window.VBA_DATA = {"generated_at": "2026-05-10T07:29:24", "total_folders": 17, "total_files": 259, "modules": [{"folder": "AutomaticallyCleanData", "path": "模組/AutomaticallyCleanData", "files": [{"name": "CleanAddressData.bas", "path": "模組/AutomaticallyCleanData/CleanAddressData.bas", "content": "Attribute VB_Name = \"CleanAddressData\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: CleanAddressData\n'功能說明: 清理地址欄位，補全縣市簡稱（台→臺）、移除多餘空白與全形空格\n'著作權所有: Dunk\n'撰寫日期: 2026/5/9\n'*************************************************************************************\n\nSub TestCleanAddressData()\n    Dim ws As Worksheet\n    Set ws = GetOrCreateAddressSheet(ThisWorkbook, \"地址清理範例\")\n    Call FillDirtyAddressData(ws)\n    Call CleanAddressColumn(ws, 2)\n    MsgBox \"地址欄位清理完成！\", vbInformation, \"完成\"\nEnd Sub\n\n' 清理地址欄位：補全縣市名稱、移除多餘空白\nSub CleanAddressColumn(ByVal ws As Worksheet, ByVal colIndex As Long)\n    Dim lastRow As Long\n    Dim r       As Long\n    Dim strVal  As String\n\n    Application.ScreenUpdating = False\n    lastRow = ws.Cells(ws.Rows.Count, 1).End(xlUp).Row\n\n    For r = 2 To lastRow\n        strVal = Trim(CStr(ws.Cells(r, colIndex).Value))\n        If strVal <> \"\" Then\n            ' 移除全形空格（Unicode 12288）\n            strVal = Replace(strVal, Chr(12288), \"\")\n            ' 統一「台」開頭縣市名稱為「臺」\n            strVal = Replace(strVal, \"台北市\", \"臺北市\")\n            strVal = Replace(strVal, \"台中市\", \"臺中市\")\n            strVal = Replace(strVal, \"台南市\", \"臺南市\")\n            strVal = Replace(strVal, \"台東縣\", \"臺東縣\")\n            ' 移除地址內多餘空白\n            Do While InStr(strVal, \"  \") > 0\n                strVal = Replace(strVal, \"  \", \" \")\n            Loop\n            strVal = Trim(strVal)\n            ws.Cells(r, colIndex).Value = strVal\n        End If\n    Next r\n\n    Application.ScreenUpdating = True\nEnd Sub\n\nPrivate Sub FillDirtyAddressData(ByVal ws As Worksheet)\n    ws.Cells.Clear\n    ws.Range(\"A1:B1\").Value = Array(\"姓名\", \"地址\")\n    ws.Range(\"A2:B2\").Value = Array(\"王大明\", \"  台北市信義區  忠孝東路五段1號  \")\n    ws.Range(\"A3:B3\").Value = Array(\"李小花\", \"台中市西屯區文心路100號\")\n    ws.Range(\"A4:B4\").Value = Array(\"陳志強\", \"台南市東區中華東路二段50號3F\")\n    ws.Range(\"A5:B5\").Value = Array(\"林美雪\", \"高雄市三民區  九如二路200號\")\n    ws.Range(\"A6:B6\").Value = Array(\"張建國\", \"台東縣台東市中正路1段99號\")\n    ws.Columns(\"A:B\").AutoFit\nEnd Sub\n\nPrivate Function GetOrCreateAddressSheet(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add\n        ws.Name = sheetName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreateAddressSheet = ws\nEnd Function", "content_b64": ""}, {"name": "CleanDateFormat.bas", "path": "模組/AutomaticallyCleanData/CleanDateFormat.bas", "content": "Attribute VB_Name = \"CleanDateFormat\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: CleanDateFormat\n'功能說明: 統一日期格式，將民國年、各種分隔符的日期轉換為 yyyy/mm/dd 標準格式\n'著作權所有: Dunk\n'撰寫日期: 2026/5/9\n'*************************************************************************************\n\nSub TestCleanDateFormat()\n    Dim ws As Worksheet\n    Set ws = GetOrCreateDateSheet(ThisWorkbook, \"日期清理範例\")\n    Call FillDirtyDateData(ws)\n    Call StandardizeDateColumn(ws, 2)\n    MsgBox \"日期欄位格式統一完成！\", vbInformation, \"完成\"\nEnd Sub\n\n' 將指定欄位的日期統一轉換為 yyyy/mm/dd 格式\nSub StandardizeDateColumn(ByVal ws As Worksheet, ByVal colIndex As Long)\n    Dim lastRow As Long\n    Dim r       As Long\n    Dim strVal  As String\n    Dim dtVal   As Date\n    Dim parts() As String\n    Dim yearNum As Long\n\n    Application.ScreenUpdating = False\n    lastRow = ws.Cells(ws.Rows.Count, 1).End(xlUp).Row\n\n    For r = 2 To lastRow\n        strVal = Trim(CStr(ws.Cells(r, colIndex).Value))\n        If strVal <> \"\" Then\n            ' 統一分隔符為 /\n            strVal = Replace(strVal, \"-\", \"/\")\n            strVal = Replace(strVal, \".\", \"/\")\n            ' 判斷是否為民國年（3位數且 < 200）\n            parts = Split(strVal, \"/\")\n            If UBound(parts) = 2 Then\n                yearNum = 0\n                If IsNumeric(parts(0)) Then yearNum = CLng(parts(0))\n                If yearNum > 0 And yearNum < 200 Then\n                    ' 民國年加 1911 轉為西元年\n                    strVal = CStr(yearNum + 1911) & \"/\" & parts(1) & \"/\" & parts(2)\n                End If\n            End If\n            If IsDate(strVal) Then\n                dtVal = CDate(strVal)\n                ws.Cells(r, colIndex).Value = dtVal\n                ws.Cells(r, colIndex).NumberFormat = \"yyyy/mm/dd\"\n            End If\n        End If\n    Next r\n\n    Application.ScreenUpdating = True\nEnd Sub\n\nPrivate Sub FillDirtyDateData(ByVal ws As Worksheet)\n    ws.Cells.Clear\n    ws.Range(\"A1:C1\").Value = Array(\"編號\", \"日期原始值\", \"備註\")\n    ws.Range(\"A2:C2\").Value = Array(1, \"2025-01-15\", \"西元年橫線\")\n    ws.Range(\"A3:C3\").Value = Array(2, \"114/05/09\", \"民國年斜線\")\n    ws.Range(\"A4:C4\").Value = Array(3, \"2024.12.31\", \"西元年點號\")\n    ws.Range(\"A5:C5\").Value = Array(4, \"113/07/20\", \"民國年\")\n    ws.Range(\"A6:C6\").Value = Array(5, \"2026/03/01\", \"標準格式\")\n    ws.Columns(\"A:C\").AutoFit\nEnd Sub\n\nPrivate Function GetOrCreateDateSheet(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add\n        ws.Name = sheetName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreateDateSheet = ws\nEnd Function", "content_b64": ""}, {"name": "CleanDuplicateAndBlank.bas", "path": "模組/AutomaticallyCleanData/CleanDuplicateAndBlank.bas", "content": "Attribute VB_Name = \"CleanDuplicateAndBlank\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: CleanDuplicateAndBlank\n'功能說明: 自動清理資料：刪除重複列、移除空白列及修整多餘空格\n'\n'著作權所有: Dunk\n'程式設計: Dunk\n'撰寫日期: 2026/5/7\n'\n'*************************************************************************************\n\n' 測試用入口（建立含髒資料的範例後自動清理）\nSub TestCleanData()\n    Dim ws As Worksheet\n    Set ws = GetOrCreateSheet(ThisWorkbook, \"待清理資料\")\n    Call FillDirtyData(ws)\n    Call CleanAllData(ws)\nEnd Sub\n\n' 執行完整資料清理（整合所有清理步驟）\nSub CleanAllData(ByVal ws As Worksheet)\n    Application.ScreenUpdating = False\n\n    Call TrimAllStringCells(ws)\n    Call RemoveBlankRows(ws)\n    Call RemoveDuplicateRows(ws)\n\n    Application.ScreenUpdating = True\n\n    ws.Activate\n    MsgBox \"資料清理完成！已執行：修整空格 -> 刪除空白列 -> 刪除重複列\", _\n           vbInformation, \"完成\"\nEnd Sub\n\n' 修整工作表內所有字串儲存格的多餘空格\nPrivate Sub TrimAllStringCells(ByVal ws As Worksheet)\n    Dim cell As Range\n    Dim usedRng As Range\n\n    Set usedRng = ws.UsedRange\n    For Each cell In usedRng\n        If cell.Value <> \"\" And VarType(cell.Value) = vbString Then\n            cell.Value = Trim(cell.Value)\n        End If\n    Next cell\nEnd Sub\n\n' 刪除工作表內的整列空白列\nPrivate Sub RemoveBlankRows(ByVal ws As Worksheet)\n    Dim lastRow As Long\n    Dim r As Long\n\n    lastRow = ws.Cells(ws.Rows.Count, 1).End(xlUp).Row\n\n    ' 從最後一列往上刪，避免刪除後列索引偏移\n    For r = lastRow To 1 Step -1\n        If Application.WorksheetFunction.CountA(ws.Rows(r)) = 0 Then\n            ws.Rows(r).Delete\n        End If\n    Next r\nEnd Sub\n\n' 刪除工作表內的重複列（保留第一筆）\nPrivate Sub RemoveDuplicateRows(ByVal ws As Worksheet)\n    Dim lastRow As Long\n    Dim lastCol As Long\n    Dim dataRange As Range\n    Dim colArray() As Integer\n    Dim i As Integer\n\n    lastRow = ws.Cells(ws.Rows.Count, 1).End(xlUp).Row\n    lastCol = ws.Cells(1, ws.Columns.Count).End(xlToLeft).Column\n\n    If lastRow < 2 Then Exit Sub\n\n    Set dataRange = ws.Range(ws.Cells(1, 1), ws.Cells(lastRow, lastCol))\n\n    ReDim colArray(1 To lastCol)\n    For i = 1 To lastCol\n        colArray(i) = i\n    Next i\n\n    dataRange.RemoveDuplicates Columns:=colArray, Header:=xlYes\nEnd Sub\n\n' 填入含有髒資料的範例（含空白列、重複列、多餘空格）\nPrivate Sub FillDirtyData(ByVal ws As Worksheet)\n    ws.Range(\"A1\").Value = \"姓名\"\n    ws.Range(\"B1\").Value = \"部門\"\n    ws.Range(\"C1\").Value = \"電話\"\n    ws.Range(\"A2\").Value = \"  張三  \"\n    ws.Range(\"B2\").Value = \"研發部\"\n    ws.Range(\"C2\").Value = \"0912-345678\"\n    ws.Range(\"A3\").Value = \"\"\n    ws.Range(\"B3\").Value = \"\"\n    ws.Range(\"C3\").Value = \"\"\n    ws.Range(\"A4\").Value = \"李四\"\n    ws.Range(\"B4\").Value = \"  業務部  \"\n    ws.Range(\"C4\").Value = \"0923-456789\"\n    ws.Range(\"A5\").Value = \"張三\"\n    ws.Range(\"B5\").Value = \"研發部\"\n    ws.Range(\"C5\").Value = \"0912-345678\"\n    ws.Range(\"A6\").Value = \"王五\"\n    ws.Range(\"B6\").Value = \"行政部\"\n    ws.Range(\"C6\").Value = \"0934-567890\"\n    ws.Range(\"A7\").Value = \"\"\n    ws.Range(\"B7\").Value = \"\"\n    ws.Range(\"C7\").Value = \"\"\n    ws.Range(\"A8\").Value = \"李四\"\n    ws.Range(\"B8\").Value = \"業務部\"\n    ws.Range(\"C8\").Value = \"0923-456789\"\n    ws.Columns(\"A:C\").AutoFit\nEnd Sub\n\n' 取得或建立工作表，並清除內容\nPrivate Function GetOrCreateSheet(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add\n        ws.Name = sheetName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreateSheet = ws\nEnd Function\n", "content_b64": ""}, {"name": "CleanNumericData.bas", "path": "模組/AutomaticallyCleanData/CleanNumericData.bas", "content": "Attribute VB_Name = \"CleanNumericData\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: CleanNumericData\n'功能說明: 清理數值欄位，移除貨幣符號（NT$、$）、千分位逗號與多餘空白，轉換為數字格式\n'著作權所有: Dunk\n'撰寫日期: 2026/5/9\n'*************************************************************************************\n\nSub TestCleanNumericData()\n    Dim ws As Worksheet\n    Set ws = GetOrCreateNumericSheet(ThisWorkbook, \"數值清理範例\")\n    Call FillDirtyNumericData(ws)\n    Call CleanNumericColumns(ws, 2, 4)\n    MsgBox \"數值欄位清理完成！\", vbInformation, \"完成\"\nEnd Sub\n\n' 清理指定欄範圍的數值格式\nSub CleanNumericColumns(ByVal ws As Worksheet, ByVal startCol As Long, ByVal endCol As Long)\n    Dim lastRow As Long\n    Dim r       As Long\n    Dim c       As Long\n    Dim strVal  As String\n\n    Application.ScreenUpdating = False\n    lastRow = ws.Cells(ws.Rows.Count, 1).End(xlUp).Row\n\n    For c = startCol To endCol\n        For r = 2 To lastRow\n            strVal = Trim(CStr(ws.Cells(r, c).Value))\n            strVal = Replace(strVal, \"NT$\", \"\")\n            strVal = Replace(strVal, \"$\", \"\")\n            strVal = Replace(strVal, \",\", \"\")\n            strVal = Trim(strVal)\n            If IsNumeric(strVal) And strVal <> \"\" Then\n                ws.Cells(r, c).Value = CDbl(strVal)\n                ws.Cells(r, c).NumberFormat = \"#,##0.00\"\n            End If\n        Next r\n    Next c\n\n    Application.ScreenUpdating = True\nEnd Sub\n\n' 填入含污染數值的測試資料\nPrivate Sub FillDirtyNumericData(ByVal ws As Worksheet)\n    ws.Cells.Clear\n    ws.Range(\"A1:D1\").Value = Array(\"品名\", \"售價\", \"成本\", \"毛利\")\n    ws.Range(\"A2:D2\").Value = Array(\"產品A\", \"NT$1,200\", \"$800\", \"  400  \")\n    ws.Range(\"A3:D3\").Value = Array(\"產品B\", \"2,500.50\", \"NT$1,800\", \"$700.50\")\n    ws.Range(\"A4:D4\").Value = Array(\"產品C\", \" $350 \", \"200\", \"150\")\n    ws.Columns(\"A:D\").AutoFit\nEnd Sub\n\nPrivate Function GetOrCreateNumericSheet(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add\n        ws.Name = sheetName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreateNumericSheet = ws\nEnd Function", "content_b64": ""}, {"name": "CleanPercentageData.bas", "path": "模組/AutomaticallyCleanData/CleanPercentageData.bas", "content": "Attribute VB_Name = \"CleanPercentageData\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: CleanPercentageData\n'功能說明: 清理百分比欄位，移除 % 符號並轉換為小數（如 85% -> 0.85），統一儲存格格式\n'著作權所有: Dunk\n'撰寫日期: 2026/5/9\n'*************************************************************************************\n\nSub TestCleanPercentageData()\n    Dim ws As Worksheet\n    Set ws = GetOrCreatePctSheet(ThisWorkbook, \"百分比清理範例\")\n    Call FillDirtyPercentageData(ws)\n    Call CleanPercentageColumns(ws, 2, 4)\n    ws.Columns(\"A:D\").AutoFit\n    MsgBox \"百分比欄位清理完成！\", vbInformation, \"完成\"\nEnd Sub\n\n' 清理指定欄範圍的百分比資料，轉換為 Excel 百分比格式\nSub CleanPercentageColumns(ByVal ws As Worksheet, ByVal startCol As Long, ByVal endCol As Long)\n    Dim lastRow  As Long\n    Dim r        As Long\n    Dim c        As Long\n    Dim strVal   As String\n    Dim dblVal   As Double\n\n    Application.ScreenUpdating = False\n    lastRow = ws.Cells(ws.Rows.Count, 1).End(xlUp).Row\n\n    For c = startCol To endCol\n        For r = 2 To lastRow\n            strVal = Trim(CStr(ws.Cells(r, c).Value))\n            If strVal <> \"\" Then\n                ' 移除 % 符號、空白及千分位逗號\n                strVal = Replace(strVal, \"%\", \"\")\n                strVal = Replace(strVal, \",\", \"\")\n                strVal = Trim(strVal)\n                If IsNumeric(strVal) Then\n                    dblVal = CDbl(strVal)\n                    ' 若數值 > 1，視為百分比整數（如 85.5 代表 85.5%），除以 100\n                    If dblVal > 1 Then dblVal = dblVal / 100\n                    ws.Cells(r, c).Value = dblVal\n                    ws.Cells(r, c).NumberFormat = \"0.00%\"\n                End If\n            End If\n        Next r\n    Next c\n\n    Application.ScreenUpdating = True\nEnd Sub\n\nPrivate Sub FillDirtyPercentageData(ByVal ws As Worksheet)\n    ws.Cells.Clear\n    ws.Range(\"A1:D1\").Value = Array(\"姓名\", \"業績達成率\", \"客戶滿意度\", \"出席率\")\n    ws.Range(\"A2:D2\").Value = Array(\"陳大文\", \"85%\", \"92.5%\", \"100%\")\n    ws.Range(\"A3:D3\").Value = Array(\"林小美\", \" 78.3% \", \"88%\", \" 95%\")\n    ws.Range(\"A4:D4\").Value = Array(\"王志強\", \"105.2%\", \"76%\", \"90%\")\n    ws.Range(\"A5:D5\").Value = Array(\"張明宏\", \"0.92\", \"0.85\", \"1.00\")\n    ws.Columns(\"A:D\").AutoFit\nEnd Sub\n\nPrivate Function GetOrCreatePctSheet(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add\n        ws.Name = sheetName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreatePctSheet = ws\nEnd Function", "content_b64": ""}, {"name": "CleanPostalCode.bas", "path": "模組/AutomaticallyCleanData/CleanPostalCode.bas", "content": "Attribute VB_Name = \"CleanPostalCode\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: CleanPostalCode\n'功能說明: 清理郵遞區號欄位，移除非數字字元，並補足前導零至 3 位（臺灣郵遞區號格式）\n'著作權所有: Dunk\n'撰寫日期: 2026/5/9\n'*************************************************************************************\n\nSub TestCleanPostalCode()\n    Dim ws As Worksheet\n    Set ws = GetOrCreatePostalSheet(ThisWorkbook, \"郵遞區號清理範例\")\n    Call FillDirtyPostalData(ws)\n    Call CleanPostalCodeColumn(ws, 3, 3)\n    ws.Columns(\"A:C\").AutoFit\n    MsgBox \"郵遞區號清理完成！\", vbInformation, \"完成\"\nEnd Sub\n\n' 清理郵遞區號欄位，移除非數字並補足指定位數\nSub CleanPostalCodeColumn(ByVal ws As Worksheet, ByVal colIndex As Long, ByVal digitCount As Integer)\n    Dim lastRow  As Long\n    Dim r        As Long\n    Dim strVal   As String\n    Dim cleanVal As String\n    Dim i        As Integer\n    Dim c        As String\n\n    Application.ScreenUpdating = False\n    lastRow = ws.Cells(ws.Rows.Count, 1).End(xlUp).Row\n\n    For r = 2 To lastRow\n        strVal = Trim(CStr(ws.Cells(r, colIndex).Value))\n        If strVal <> \"\" Then\n            ' 移除非數字字元\n            cleanVal = \"\"\n            For i = 1 To Len(strVal)\n                c = Mid(strVal, i, 1)\n                If c >= \"0\" And c <= \"9\" Then\n                    cleanVal = cleanVal & c\n                End If\n            Next i\n            ' 補足前導零至指定位數\n            If Len(cleanVal) > 0 And Len(cleanVal) < digitCount Then\n                cleanVal = String(digitCount - Len(cleanVal), \"0\") & cleanVal\n            End If\n            If Len(cleanVal) > digitCount Then\n                ' 截取前 digitCount 位\n                cleanVal = Left(cleanVal, digitCount)\n            End If\n            ws.Cells(r, colIndex).Value = cleanVal\n            ws.Cells(r, colIndex).NumberFormat = \"@\"\n        End If\n    Next r\n\n    Application.ScreenUpdating = True\nEnd Sub\n\nPrivate Sub FillDirtyPostalData(ByVal ws As Worksheet)\n    ws.Cells.Clear\n    ws.Range(\"A1:C1\").Value = Array(\"姓名\", \"地址\", \"郵遞區號\")\n    ws.Range(\"A2:C2\").Value = Array(\"王大明\", \"臺北市信義區忠孝東路五段1號\", \"110\")\n    ws.Range(\"A3:C3\").Value = Array(\"李小花\", \"臺中市西屯區文心路100號\", \"40756\")\n    ws.Range(\"A4:C4\").Value = Array(\"陳志強\", \"高雄市三民區九如二路200號\", \" 807 \")\n    ws.Range(\"A5:C5\").Value = Array(\"林美雪\", \"臺南市東區中華東路二段50號\", \"70\")\n    ws.Range(\"A6:C6\").Value = Array(\"張建國\", \"新北市板橋區中山路一段100號\", \"22041-ABC\")\n    ws.Columns(\"A:C\").AutoFit\nEnd Sub\n\nPrivate Function GetOrCreatePostalSheet(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add\n        ws.Name = sheetName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreatePostalSheet = ws\nEnd Function", "content_b64": ""}, {"name": "CleanProductCode.bas", "path": "模組/AutomaticallyCleanData/CleanProductCode.bas", "content": "Attribute VB_Name = \"CleanProductCode\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: CleanProductCode\n'功能說明: 清理產品代碼欄位，統一轉為大寫、移除非字母數字字元、補足前導零至固定長度\n'著作權所有: Dunk\n'撰寫日期: 2026/5/9\n'*************************************************************************************\n\n' 測試入口：建立範例工作表並執行清理\nSub TestCleanProductCode()\n    Dim ws As Worksheet\n    Set ws = GetOrCreateProdCodeSheet(ThisWorkbook, \"產品代碼清理範例\")\n    Call FillDirtyProductCodeData(ws)\n    Call StandardizeProductCodeColumn(ws, 1, 8)\n    ws.Columns(\"A:C\").AutoFit\n    MsgBox \"產品代碼清理完成！\", vbInformation, \"完成\"\nEnd Sub\n\n' 清理產品代碼：統一大寫、移除非英數字元、補足固定長度\nSub StandardizeProductCodeColumn(ByVal ws As Worksheet, ByVal colIndex As Long, ByVal codeLength As Integer)\n    Dim lastRow  As Long\n    Dim r        As Long\n    Dim strVal   As String\n    Dim cleanVal As String\n    Dim i        As Integer\n    Dim c        As String\n\n    Application.ScreenUpdating = False\n    lastRow = ws.Cells(ws.Rows.Count, colIndex).End(xlUp).Row\n\n    For r = 2 To lastRow\n        strVal = Trim(UCase(CStr(ws.Cells(r, colIndex).Value)))\n        If strVal <> \"\" Then\n            ' 移除非英數字元\n            cleanVal = \"\"\n            For i = 1 To Len(strVal)\n                c = Mid(strVal, i, 1)\n                If (c >= \"A\" And c <= \"Z\") Or (c >= \"0\" And c <= \"9\") Then\n                    cleanVal = cleanVal & c\n                End If\n            Next i\n            ' 補足前導零至指定長度（如果全為數字部分）\n            If Len(cleanVal) > 0 And Len(cleanVal) < codeLength Then\n                cleanVal = String(codeLength - Len(cleanVal), \"0\") & cleanVal\n            End If\n            ws.Cells(r, colIndex).Value = cleanVal\n        End If\n    Next r\n\n    Application.ScreenUpdating = True\nEnd Sub\n\nPrivate Sub FillDirtyProductCodeData(ByVal ws As Worksheet)\n    ws.Cells.Clear\n    ws.Range(\"A1:C1\").Value = Array(\"產品代碼\", \"品名\", \"狀態\")\n    ws.Range(\"A2:C2\").Value = Array(\"prd-001\", \"鍵盤\", \"上架\")\n    ws.Range(\"A3:C3\").Value = Array(\"PRD_002 \", \"滑鼠\", \"上架\")\n    ws.Range(\"A4:C4\").Value = Array(\"prd#3\", \"耳機\", \"缺貨\")\n    ws.Range(\"A5:C5\").Value = Array(\"PRD 0004\", \"螢幕\", \"上架\")\n    ws.Range(\"A6:C6\").Value = Array(\"prd.5\", \"鏡頭\", \"預購\")\n    ws.Columns(\"A:C\").AutoFit\nEnd Sub\n\nPrivate Function GetOrCreateProdCodeSheet(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add\n        ws.Name = sheetName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreateProdCodeSheet = ws\nEnd Function", "content_b64": ""}, {"name": "CleanSpecialCharacters.bas", "path": "模組/AutomaticallyCleanData/CleanSpecialCharacters.bas", "content": "Attribute VB_Name = \"CleanSpecialCharacters\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: CleanSpecialCharacters\n'功能說明: 移除儲存格中的特殊字元，包含 @#$%^&*!~|\\ 等符號，保留中英數與空白\n'著作權所有: Dunk\n'撰寫日期: 2026/5/9\n'*************************************************************************************\n\nSub TestCleanSpecialCharacters()\n    Dim ws As Worksheet\n    Set ws = GetOrCreateSpecialCharSheet(ThisWorkbook, \"特殊字元清理範例\")\n    Call FillDirtySpecialCharData(ws)\n    Call RemoveSpecialCharsFromRange(ws.UsedRange.Offset(1))\n    ws.Columns(\"A:C\").AutoFit\n    MsgBox \"特殊字元清理完成！\", vbInformation, \"完成\"\nEnd Sub\n\n' 移除範圍內所有儲存格的特殊字元\nSub RemoveSpecialCharsFromRange(ByVal rng As Range)\n    Dim cell       As Range\n    Dim strVal     As String\n    Dim cleanVal   As String\n    Dim i          As Integer\n    Dim charCode   As Integer\n    Dim specialSet As String\n\n    ' 定義要移除的特殊字元清單\n    specialSet = \"@#$%^&*!~|\\/<>{}[]\"\n    Application.ScreenUpdating = False\n\n    For Each cell In rng\n        If Not IsEmpty(cell) And VarType(cell.Value) = vbString Then\n            strVal = cell.Value\n            cleanVal = \"\"\n            For i = 1 To Len(strVal)\n                charCode = Asc(Mid(strVal, i, 1))\n                ' 保留中文（charCode < 0 表示雙位元組）、英數及空白\n                If charCode < 0 Or (charCode >= 48 And charCode <= 57) Or _\n                   (charCode >= 65 And charCode <= 90) Or _\n                   (charCode >= 97 And charCode <= 122) Or charCode = 32 Then\n                    cleanVal = cleanVal & Mid(strVal, i, 1)\n                ElseIf InStr(specialSet, Mid(strVal, i, 1)) = 0 Then\n                    cleanVal = cleanVal & Mid(strVal, i, 1)\n                End If\n            Next i\n            If cell.Value <> cleanVal Then cell.Value = Trim(cleanVal)\n        End If\n    Next cell\n\n    Application.ScreenUpdating = True\nEnd Sub\n\nPrivate Sub FillDirtySpecialCharData(ByVal ws As Worksheet)\n    ws.Cells.Clear\n    ws.Range(\"A1:C1\").Value = Array(\"產品代碼\", \"描述\", \"備註\")\n    ws.Range(\"A2:C2\").Value = Array(\"PRD@001\", \"高品質#商品\", \"庫存@正常!\")\n    ws.Range(\"A3:C3\").Value = Array(\"PRD#002!\", \"$$特價商品$$\", \"注意&庫存\")\n    ws.Range(\"A4:C4\").Value = Array(\"PRD|003\", \"標準^商品\", \"正常|供貨\")\n    ws.Range(\"A5:C5\").Value = Array(\"PRD~004\", \"特殊*規格\", \"需確認\\\\庫存\")\n    ws.Columns(\"A:C\").AutoFit\nEnd Sub\n\nPrivate Function GetOrCreateSpecialCharSheet(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add\n        ws.Name = sheetName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreateSpecialCharSheet = ws\nEnd Function", "content_b64": ""}, {"name": "FillMissingValues.bas", "path": "模組/AutomaticallyCleanData/FillMissingValues.bas", "content": "Attribute VB_Name = \"FillMissingValues\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: FillMissingValues\n'功能說明: 向下填補空白儲存格（Fill Down），適用於合併儲存格來源或報表遺漏值填補\n'著作權所有: Dunk\n'撰寫日期: 2026/5/9\n'*************************************************************************************\n\nSub TestFillMissingValues()\n    Dim ws As Worksheet\n    Set ws = GetOrCreateFillSheet(ThisWorkbook, \"遺漏值填補範例\")\n    Call FillSparseData(ws)\n    Call FillDownColumn(ws, 1)\n    Call FillDownColumn(ws, 2)\n    ws.Columns(\"A:D\").AutoFit\n    MsgBox \"遺漏值向下填補完成！\", vbInformation, \"完成\"\nEnd Sub\n\n' 對指定欄進行向下填補（Fill Down）\nSub FillDownColumn(ByVal ws As Worksheet, ByVal colIndex As Long)\n    Dim lastRow  As Long\n    Dim r        As Long\n    Dim lastVal  As Variant\n\n    lastRow = ws.Cells(ws.Rows.Count, colIndex).End(xlUp).Row\n    lastVal = \"\"\n\n    For r = 2 To lastRow\n        If Trim(CStr(ws.Cells(r, colIndex).Value)) = \"\" Then\n            ' 空白儲存格：填入上一個非空值\n            If lastVal <> \"\" Then\n                ws.Cells(r, colIndex).Value = lastVal\n            End If\n        Else\n            ' 非空儲存格：更新記錄值\n            lastVal = ws.Cells(r, colIndex).Value\n        End If\n    Next r\nEnd Sub\n\n' 對工作表中多個欄位批次執行向下填補\nSub FillDownMultipleColumns(ByVal ws As Worksheet, ParamArray colIndexes() As Variant)\n    Dim idx As Variant\n    For Each idx In colIndexes\n        Call FillDownColumn(ws, CLng(idx))\n    Next idx\nEnd Sub\n\nPrivate Sub FillSparseData(ByVal ws As Worksheet)\n    ws.Cells.Clear\n    ws.Range(\"A1:D1\").Value = Array(\"部門\", \"組別\", \"員工姓名\", \"職稱\")\n    ws.Range(\"A2:D2\").Value = Array(\"業務部\", \"北區業務組\", \"陳大文\", \"業務員\")\n    ws.Range(\"A3:D3\").Value = Array(\"\", \"\", \"林小美\", \"資深業務\")\n    ws.Range(\"A4:D4\").Value = Array(\"\", \"南區業務組\", \"王志強\", \"業務員\")\n    ws.Range(\"A5:D5\").Value = Array(\"\", \"\", \"張明宏\", \"業務員\")\n    ws.Range(\"A6:D6\").Value = Array(\"技術部\", \"研發組\", \"李俊賢\", \"工程師\")\n    ws.Range(\"A7:D7\").Value = Array(\"\", \"\", \"劉雅婷\", \"資深工程師\")\n    ws.Range(\"A8:D8\").Value = Array(\"\", \"測試組\", \"吳建志\", \"測試工程師\")\n    ws.Columns(\"A:D\").AutoFit\nEnd Sub\n\nPrivate Function GetOrCreateFillSheet(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add\n        ws.Name = sheetName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreateFillSheet = ws\nEnd Function", "content_b64": ""}, {"name": "NormalizeContactData.bas", "path": "模組/AutomaticallyCleanData/NormalizeContactData.bas", "content": "Option Explicit\n\n' 清理電話與電子郵件欄位，移除多餘空白並統一大小寫。\nPublic Sub NormalizeContactDataExample()\n    On Error GoTo ErrHandler\n\n    Dim ws As Worksheet\n\n    Set ws = GetOrCreateCleanWorksheet(\"聯絡資料清理範例\")\n    ws.Cells.Clear\n    Call FillContactData(ws)\n    Call NormalizeContactData(ws)\n\n    ws.Columns(\"A:D\").AutoFit\n    MsgBox \"聯絡資料清理完成。\", vbInformation, \"完成\"\n    Exit Sub\n\nErrHandler:\n    MsgBox \"清理聯絡資料失敗：\" & Err.Description, vbExclamation, \"錯誤\"\nEnd Sub\n\nPrivate Sub NormalizeContactData(ByVal ws As Worksheet)\n    Dim lastRow As Long\n    Dim rowIndex As Long\n    Dim phoneText As String\n    Dim emailText As String\n\n    lastRow = ws.Cells(ws.Rows.Count, \"A\").End(xlUp).Row\n    For rowIndex = 2 To lastRow\n        phoneText = CStr(ws.Cells(rowIndex, \"B\").Value)\n        phoneText = Replace(phoneText, \" \", \"\")\n        phoneText = Replace(phoneText, \"-\", \"\")\n        ws.Cells(rowIndex, \"C\").Value = phoneText\n\n        emailText = Trim$(CStr(ws.Cells(rowIndex, \"D\").Value))\n        ws.Cells(rowIndex, \"D\").Value = LCase$(emailText)\n    Next rowIndex\nEnd Sub\n\nPrivate Sub FillContactData(ByVal ws As Worksheet)\n    ws.Range(\"A1:D1\").Value = Array(\"姓名\", \"原始電話\", \"清理後電話\", \"電子郵件\")\n    ws.Range(\"A2:D2\").Value = Array(\"王小明\", \"0912-345-678\", \"\", \" USER1@EXAMPLE.COM \")\n    ws.Range(\"A3:D3\").Value = Array(\"陳美華\", \" 02-2345-6789\", \"\", \"Sales@Example.com\")\n    ws.Range(\"A4:D4\").Value = Array(\"林志強\", \"07 2233 456\", \"\", \" SERVICE@EXAMPLE.COM\")\nEnd Sub\n\nPrivate Function GetOrCreateCleanWorksheet(ByVal sheetName As String) As Worksheet\n    On Error Resume Next\n    Set GetOrCreateCleanWorksheet = ThisWorkbook.Worksheets(sheetName)\n    On Error GoTo 0\n\n    If GetOrCreateCleanWorksheet Is Nothing Then\n        Set GetOrCreateCleanWorksheet = ThisWorkbook.Worksheets.Add\n        GetOrCreateCleanWorksheet.Name = sheetName\n    End If\nEnd Function", "content_b64": ""}, {"name": "SplitFullNameColumn.bas", "path": "模組/AutomaticallyCleanData/SplitFullNameColumn.bas", "content": "Attribute VB_Name = \"SplitFullNameColumn\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: SplitFullNameColumn\n'功能說明: 將全名欄位拆分為姓氏與名字，支援中文（單姓）與英文（空白分隔）姓名\n'著作權所有: Dunk\n'撰寫日期: 2026/5/9\n'*************************************************************************************\n\nSub TestSplitFullNameColumn()\n    Dim ws As Worksheet\n    Set ws = GetOrCreateNameSheet(ThisWorkbook, \"姓名拆分範例\")\n    Call FillFullNameData(ws)\n    Call SplitNameColumn(ws, 1, 2, 3)\n    ws.Columns(\"A:D\").AutoFit\n    MsgBox \"姓名拆分完成！\", vbInformation, \"完成\"\nEnd Sub\n\n' 拆分全名欄位，寫入姓氏欄與名字欄\nSub SplitNameColumn(ByVal ws As Worksheet, _\n                    ByVal fullNameCol As Long, _\n                    ByVal lastNameCol As Long, _\n                    ByVal firstNameCol As Long)\n    Dim lastRow  As Long\n    Dim r        As Long\n    Dim fullName As String\n    Dim spacePos As Integer\n\n    Application.ScreenUpdating = False\n    ' 設定標題\n    ws.Cells(1, lastNameCol).Value = \"姓氏\"\n    ws.Cells(1, firstNameCol).Value = \"名字\"\n    lastRow = ws.Cells(ws.Rows.Count, fullNameCol).End(xlUp).Row\n\n    For r = 2 To lastRow\n        fullName = Trim(CStr(ws.Cells(r, fullNameCol).Value))\n        If fullName <> \"\" Then\n            spacePos = InStr(fullName, \" \")\n            If spacePos > 0 Then\n                ' 英文姓名：以空白分隔（First Last 格式）\n                ws.Cells(r, lastNameCol).Value = Trim(Mid(fullName, spacePos + 1))\n                ws.Cells(r, firstNameCol).Value = Trim(Left(fullName, spacePos - 1))\n            Else\n                ' 中文姓名：第一個字為姓，其餘為名\n                ws.Cells(r, lastNameCol).Value = Left(fullName, 1)\n                ws.Cells(r, firstNameCol).Value = Mid(fullName, 2)\n            End If\n        End If\n    Next r\n\n    Application.ScreenUpdating = True\nEnd Sub\n\nPrivate Sub FillFullNameData(ByVal ws As Worksheet)\n    ws.Cells.Clear\n    ws.Range(\"A1\").Value = \"全名\"\n    ws.Range(\"A2\").Value = \"陳志強\"\n    ws.Range(\"A3\").Value = \"王大明\"\n    ws.Range(\"A4\").Value = \"John Smith\"\n    ws.Range(\"A5\").Value = \"歐陽美玲\"\n    ws.Range(\"A6\").Value = \"Mary Johnson\"\n    ws.Range(\"A7\").Value = \"林雅婷\"\n    ws.Columns(\"A\").AutoFit\nEnd Sub\n\nPrivate Function GetOrCreateNameSheet(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add\n        ws.Name = sheetName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreateNameSheet = ws\nEnd Function", "content_b64": ""}, {"name": "StandardizeTextData.bas", "path": "模組/AutomaticallyCleanData/StandardizeTextData.bas", "content": "Attribute VB_Name = \"StandardizeTextData\"\n\nOption Explicit\n\n\n\n' ============================================================\n\n' 範例：自動標準化文字資料（去空白、統一大小寫、全半形轉換）\n\n' 功能：對選取範圍套用 Trim、大小寫標準化，並移除全形空白\n\n' ============================================================\n\nSub StandardizeSelectedTextData()\n\n    Dim rng     As Range\n\n    Dim cell    As Range\n\n    Dim strVal  As String\n\n    Dim intCnt  As Integer\n\n\n\n    On Error GoTo ErrHandler\n\n\n\n    If TypeName(Selection) <> \"Range\" Then\n\n        MsgBox \"請先選取要標準化的儲存格範圍。\", vbExclamation\n\n        Exit Sub\n\n    End If\n\n\n\n    Set rng = Selection\n\n    Application.ScreenUpdating = False\n\n    intCnt = 0\n\n\n\n    For Each cell In rng\n\n        If Not IsEmpty(cell) And Not IsNumeric(cell.Value) Then\n\n            strVal = cell.Value\n\n            ' 去除前後空白\n\n            strVal = Trim(strVal)\n\n            ' 移除全形空白（Unicode 12288）\n\n            strVal = Replace(strVal, Chr(12288), \"\")\n\n            ' 移除多餘半形空白\n\n            Do While InStr(strVal, \"  \") > 0\n\n                strVal = Replace(strVal, \"  \", \" \")\n\n            Loop\n\n            If cell.Value <> strVal Then\n\n                cell.Value = strVal\n\n                intCnt = intCnt + 1\n\n            End If\n\n        End If\n\n    Next cell\n\n\n\n    Application.ScreenUpdating = True\n\n    MsgBox \"文字標準化完成，共修正 \" & intCnt & \" 個儲存格。\", vbInformation\n\n    Exit Sub\n\n\n\nErrHandler:\n\n    Application.ScreenUpdating = True\n\n    MsgBox \"發生錯誤：\" & Err.Description, vbCritical\n\nEnd Sub\n\n", "content_b64": ""}, {"name": "ValidateAndCleanEmail.bas", "path": "模組/AutomaticallyCleanData/ValidateAndCleanEmail.bas", "content": "Attribute VB_Name = \"ValidateAndCleanEmail\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: ValidateAndCleanEmail\n'功能說明: 驗證並清理 Email 欄位，統一轉小寫、移除多餘空白，並標記格式不符的資料\n'著作權所有: Dunk\n'撰寫日期: 2026/5/9\n'*************************************************************************************\n\nSub TestValidateAndCleanEmail()\n    Dim ws As Worksheet\n    Set ws = GetOrCreateEmailSheet(ThisWorkbook, \"Email清理範例\")\n    Call FillDirtyEmailData(ws)\n    Call CleanAndValidateEmailColumn(ws, 2, 3)\n    ws.Columns(\"A:C\").AutoFit\n    MsgBox \"Email 驗證與清理完成！\", vbInformation, \"完成\"\nEnd Sub\n\n' 清理並驗證 Email 欄位，結果寫入狀態欄\nSub CleanAndValidateEmailColumn(ByVal ws As Worksheet, ByVal emailCol As Long, ByVal statusCol As Long)\n    Dim lastRow  As Long\n    Dim r        As Long\n    Dim strVal   As String\n\n    Application.ScreenUpdating = False\n    ws.Cells(1, statusCol).Value = \"驗證狀態\"\n    lastRow = ws.Cells(ws.Rows.Count, 1).End(xlUp).Row\n\n    For r = 2 To lastRow\n        strVal = Trim(LCase(CStr(ws.Cells(r, emailCol).Value)))\n        ' 移除全形空格\n        strVal = Replace(strVal, Chr(12288), \"\")\n        ws.Cells(r, emailCol).Value = strVal\n\n        ' 基本格式驗證：包含 @ 且 @ 後有 .\n        If IsValidEmailFormat(strVal) Then\n            ws.Cells(r, statusCol).Value = \"格式正確\"\n            ws.Cells(r, statusCol).Interior.Color = RGB(198, 239, 206)\n        Else\n            ws.Cells(r, statusCol).Value = \"格式錯誤\"\n            ws.Cells(r, statusCol).Interior.Color = RGB(255, 199, 206)\n        End If\n    Next r\n\n    Application.ScreenUpdating = True\nEnd Sub\n\n' 基本 Email 格式驗證（含 @，且 @ 後段含 .）\nPrivate Function IsValidEmailFormat(ByVal emailStr As String) As Boolean\n    Dim atPos  As Integer\n    Dim dotPos As Integer\n\n    atPos = InStr(emailStr, \"@\")\n    If atPos < 2 Then\n        IsValidEmailFormat = False\n        Exit Function\n    End If\n    dotPos = InStr(atPos + 1, emailStr, \".\")\n    If dotPos = 0 Or dotPos = Len(emailStr) Then\n        IsValidEmailFormat = False\n        Exit Function\n    End If\n    IsValidEmailFormat = True\nEnd Function\n\nPrivate Sub FillDirtyEmailData(ByVal ws As Worksheet)\n    ws.Cells.Clear\n    ws.Range(\"A1:B1\").Value = Array(\"姓名\", \"Email\")\n    ws.Range(\"A2:B2\").Value = Array(\"王大明\", \" WANG@EXAMPLE.COM \")\n    ws.Range(\"A3:B3\").Value = Array(\"李小花\", \"Lee@Test.com.tw\")\n    ws.Range(\"A4:B4\").Value = Array(\"陳志強\", \"chen.email.com\")\n    ws.Range(\"A5:B5\").Value = Array(\"林美雪\", \" LIN@Company.ORG \")\n    ws.Range(\"A6:B6\").Value = Array(\"張建國\", \"chang@\")\n    ws.Columns(\"A:B\").AutoFit\nEnd Sub\n\nPrivate Function GetOrCreateEmailSheet(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add\n        ws.Name = sheetName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreateEmailSheet = ws\nEnd Function", "content_b64": ""}]}, {"folder": "AutomaticallyCompareDataDifferences", "path": "模組/AutomaticallyCompareDataDifferences", "files": [{"name": "CompareAndMerge.bas", "path": "模組/AutomaticallyCompareDataDifferences/CompareAndMerge.bas", "content": "Attribute VB_Name = \"CompareAndMerge\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: CompareAndMerge\n'功能說明: 比對新舊兩張工作表資料，將新版有異動的欄位更新至主表，\n'          並標記異動儲存格便於覆核\n'\n'著作權所有: Dunk\n'程式設計: Dunk\n'撰寫日期: 2026/5/9\n'\n'*************************************************************************************\n\n' 測試用入口\nSub TestCompareAndMerge()\n    Call CreateMergeData\n    Call CompareAndMerge(\"舊版資料\", \"新版資料\", \"合併後主表\", 1, 1)\nEnd Sub\n\n' 建立合併測試範例資料\nPrivate Sub CreateMergeData()\n    Dim wsOld As Worksheet\n    Dim wsNew As Worksheet\n\n    Set wsOld = GetOrCreateSheetCAM(\"舊版資料\")\n    Set wsNew = GetOrCreateSheetCAM(\"新版資料\")\n\n    wsOld.Range(\"A1\").Value = \"產品代碼\"\n    wsOld.Range(\"B1\").Value = \"產品名稱\"\n    wsOld.Range(\"C1\").Value = \"單價\"\n    wsOld.Range(\"D1\").Value = \"庫存量\"\n    wsOld.Range(\"A2\").Value = \"P001\" : wsOld.Range(\"B2\").Value = \"筆記型電腦\" : wsOld.Range(\"C2\").Value = 35000 : wsOld.Range(\"D2\").Value = 50\n    wsOld.Range(\"A3\").Value = \"P002\" : wsOld.Range(\"B3\").Value = \"無線滑鼠\"   : wsOld.Range(\"C3\").Value = 800   : wsOld.Range(\"D3\").Value = 200\n    wsOld.Range(\"A4\").Value = \"P003\" : wsOld.Range(\"B4\").Value = \"機械鍵盤\"   : wsOld.Range(\"C4\").Value = 2500  : wsOld.Range(\"D4\").Value = 80\n    wsOld.Columns(\"A:D\").AutoFit\n\n    wsNew.Range(\"A1\").Value = \"產品代碼\"\n    wsNew.Range(\"B1\").Value = \"產品名稱\"\n    wsNew.Range(\"C1\").Value = \"單價\"\n    wsNew.Range(\"D1\").Value = \"庫存量\"\n    wsNew.Range(\"A2\").Value = \"P001\" : wsNew.Range(\"B2\").Value = \"筆記型電腦\" : wsNew.Range(\"C2\").Value = 38000 : wsNew.Range(\"D2\").Value = 45\n    wsNew.Range(\"A3\").Value = \"P002\" : wsNew.Range(\"B3\").Value = \"無線滑鼠\"   : wsNew.Range(\"C3\").Value = 800   : wsNew.Range(\"D3\").Value = 180\n    wsNew.Range(\"A4\").Value = \"P003\" : wsNew.Range(\"B4\").Value = \"機械鍵盤\"   : wsNew.Range(\"C4\").Value = 2800  : wsNew.Range(\"D4\").Value = 80\n    wsNew.Range(\"A5\").Value = \"P004\" : wsNew.Range(\"B5\").Value = \"USB集線器\"  : wsNew.Range(\"C5\").Value = 450   : wsNew.Range(\"D5\").Value = 300\n    wsNew.Columns(\"A:D\").AutoFit\nEnd Sub\n\n' 依鍵值欄合併新版資料至主表，並標記變更欄位\nPublic Sub CompareAndMerge(ByVal oldSheet As String, ByVal newSheet As String, _\n                            ByVal masterSheet As String, ByVal keyColNum As Long, _\n                            ByVal headerRows As Long)\n    Dim wsOld        As Worksheet\n    Dim wsNew        As Worksheet\n    Dim wsMaster     As Worksheet\n    Dim oldLastRow   As Long\n    Dim newLastRow   As Long\n    Dim lastCol      As Long\n    Dim masterLastRow As Long\n    Dim i            As Long\n    Dim j            As Long\n    Dim c            As Long\n    Dim oldKey       As String\n    Dim newKey       As String\n    Dim foundMatch   As Boolean\n    Dim updateCount  As Long\n    Dim addCount     As Long\n\n    On Error GoTo ErrHandler\n\n    Set wsOld = ThisWorkbook.Worksheets(oldSheet)\n    Set wsNew = ThisWorkbook.Worksheets(newSheet)\n    Set wsMaster = GetOrCreateSheetCAM(masterSheet)\n\n    ' 先複製舊版資料至主表\n    wsOld.UsedRange.Copy wsMaster.Range(\"A1\")\n\n    oldLastRow = wsOld.Cells(wsOld.Rows.Count, keyColNum).End(xlUp).Row\n    newLastRow = wsNew.Cells(wsNew.Rows.Count, keyColNum).End(xlUp).Row\n    lastCol = wsOld.Cells(1, wsOld.Columns.Count).End(xlToLeft).Column\n\n    updateCount = 0\n    addCount = 0\n\n    For i = headerRows + 1 To newLastRow\n        newKey = CStr(wsNew.Cells(i, keyColNum).Value)\n        If newKey <> \"\" Then\n            foundMatch = False\n            For j = headerRows + 1 To oldLastRow\n                oldKey = CStr(wsOld.Cells(j, keyColNum).Value)\n                If newKey = oldKey Then\n                    foundMatch = True\n                    ' 更新主表中有差異的欄位並加入批注\n                    For c = 1 To lastCol\n                        If CStr(wsNew.Cells(i, c).Value) <> CStr(wsOld.Cells(j, c).Value) Then\n                            wsMaster.Cells(j, c).Value = wsNew.Cells(i, c).Value\n                            wsMaster.Cells(j, c).Interior.Color = RGB(146, 208, 80)\n                            On Error Resume Next\n                            wsMaster.Cells(j, c).AddComment \"原值: \" & CStr(wsOld.Cells(j, c).Value)\n                            On Error GoTo ErrHandler\n                            updateCount = updateCount + 1\n                        End If\n                    Next c\n                    Exit For\n                End If\n            Next j\n            If Not foundMatch Then\n                ' 新增列加入主表底部\n                masterLastRow = wsMaster.Cells(wsMaster.Rows.Count, keyColNum).End(xlUp).Row + 1\n                For c = 1 To lastCol\n                    wsMaster.Cells(masterLastRow, c).Value = wsNew.Cells(i, c).Value\n                Next c\n                wsMaster.Rows(masterLastRow).Interior.Color = RGB(198, 239, 206)\n                addCount = addCount + 1\n            End If\n        End If\n    Next i\n\n    wsMaster.Columns(\"A:D\").AutoFit\n    wsMaster.Activate\n    MsgBox \"合併完成！\" & vbCrLf & _\n           \"更新欄位: \" & updateCount & \" 格\" & vbCrLf & _\n           \"新增記錄: \" & addCount & \" 筆\", vbInformation, \"合併結果\"\n    Exit Sub\n\nErrHandler:\n    MsgBox \"發生錯誤: \" & Err.Description, vbCritical, \"錯誤\"\nEnd Sub\n\nPrivate Function GetOrCreateSheetCAM(ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = ThisWorkbook.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = ThisWorkbook.Worksheets.Add\n        ws.Name = sheetName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreateSheetCAM = ws\nEnd Function\n", "content_b64": ""}, {"name": "CompareByKeyColumn.bas", "path": "模組/AutomaticallyCompareDataDifferences/CompareByKeyColumn.bas", "content": "Attribute VB_Name = \"CompareByKeyColumn\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: CompareByKeyColumn\n'功能說明: 依指定鍵值欄位比對兩張工作表，輸出新增、刪除、修改三類差異\n'\n'著作權所有: Dunk\n'程式設計: Dunk\n'撰寫日期: 2026/5/9\n'\n'*************************************************************************************\n\n' 測試用入口\nSub TestCompareByKeyColumn()\n    Call CreateKeyCompareData\n    Call CompareByKeyColumn(\"來源清單\", \"目標清單\", 1, \"鍵值差異報告\", 1)\nEnd Sub\n\n' 建立鍵值比對範例資料\nPrivate Sub CreateKeyCompareData()\n    Dim wsA As Worksheet\n    Dim wsB As Worksheet\n\n    Set wsA = GetOrCreateSheetCBK(\"來源清單\")\n    Set wsB = GetOrCreateSheetCBK(\"目標清單\")\n\n    wsA.Range(\"A1\").Value = \"訂單編號\"\n    wsA.Range(\"B1\").Value = \"客戶\"\n    wsA.Range(\"C1\").Value = \"金額\"\n    wsA.Range(\"A2\").Value = \"ORD001\" : wsA.Range(\"B2\").Value = \"台積電\" : wsA.Range(\"C2\").Value = 50000\n    wsA.Range(\"A3\").Value = \"ORD002\" : wsA.Range(\"B3\").Value = \"聯發科\" : wsA.Range(\"C3\").Value = 32000\n    wsA.Range(\"A4\").Value = \"ORD003\" : wsA.Range(\"B4\").Value = \"鴻海\"   : wsA.Range(\"C4\").Value = 18000\n    wsA.Columns(\"A:C\").AutoFit\n\n    wsB.Range(\"A1\").Value = \"訂單編號\"\n    wsB.Range(\"B1\").Value = \"客戶\"\n    wsB.Range(\"C1\").Value = \"金額\"\n    wsB.Range(\"A2\").Value = \"ORD001\" : wsB.Range(\"B2\").Value = \"台積電\" : wsB.Range(\"C2\").Value = 55000\n    wsB.Range(\"A3\").Value = \"ORD002\" : wsB.Range(\"B3\").Value = \"聯發科\" : wsB.Range(\"C3\").Value = 32000\n    wsB.Range(\"A4\").Value = \"ORD004\" : wsB.Range(\"B4\").Value = \"華碩\"   : wsB.Range(\"C4\").Value = 41000\n    wsB.Columns(\"A:C\").AutoFit\nEnd Sub\n\n' 依鍵值欄比對，輸出新增/刪除/修改清單\nPublic Sub CompareByKeyColumn(ByVal srcSheet As String, ByVal tgtSheet As String, _\n                               ByVal keyColNum As Long, ByVal reportSheet As String, _\n                               ByVal headerRows As Long)\n    Dim wsS         As Worksheet\n    Dim wsT         As Worksheet\n    Dim wsR         As Worksheet\n    Dim srcLastRow  As Long\n    Dim tgtLastRow  As Long\n    Dim srcLastCol  As Long\n    Dim rptRow      As Long\n    Dim i           As Long\n    Dim j           As Long\n    Dim c           As Long\n    Dim srcKey      As String\n    Dim tgtKey      As String\n    Dim foundInTarget As Boolean\n    Dim foundInSource As Boolean\n    Dim addedCount  As Long\n    Dim deletedCount As Long\n    Dim modifiedCount As Long\n\n    On Error GoTo ErrHandler\n\n    Set wsS = ThisWorkbook.Worksheets(srcSheet)\n    Set wsT = ThisWorkbook.Worksheets(tgtSheet)\n    Set wsR = GetOrCreateSheetCBK(reportSheet)\n\n    srcLastRow = wsS.Cells(wsS.Rows.Count, keyColNum).End(xlUp).Row\n    tgtLastRow = wsT.Cells(wsT.Rows.Count, keyColNum).End(xlUp).Row\n    srcLastCol = wsS.Cells(1, wsS.Columns.Count).End(xlToLeft).Column\n\n    wsR.Range(\"A1\").Value = \"差異類型\"\n    wsR.Range(\"B1\").Value = \"鍵值\"\n    wsR.Range(\"C1\").Value = \"欄位\"\n    wsR.Range(\"D1\").Value = \"來源值\"\n    wsR.Range(\"E1\").Value = \"目標值\"\n    With wsR.Range(\"A1:E1\")\n        .Font.Bold = True\n        .Interior.Color = RGB(68, 114, 196)\n        .Font.Color = RGB(255, 255, 255)\n    End With\n\n    rptRow = 2\n    addedCount = 0\n    deletedCount = 0\n    modifiedCount = 0\n\n    ' 掃描來源，找出修改與刪除\n    For i = headerRows + 1 To srcLastRow\n        srcKey = CStr(wsS.Cells(i, keyColNum).Value)\n        If srcKey <> \"\" Then\n            foundInTarget = False\n            For j = headerRows + 1 To tgtLastRow\n                tgtKey = CStr(wsT.Cells(j, keyColNum).Value)\n                If srcKey = tgtKey Then\n                    foundInTarget = True\n                    For c = 1 To srcLastCol\n                        If CStr(wsS.Cells(i, c).Value) <> CStr(wsT.Cells(j, c).Value) Then\n                            wsR.Cells(rptRow, 1).Value = \"修改\"\n                            wsR.Cells(rptRow, 2).Value = srcKey\n                            wsR.Cells(rptRow, 3).Value = CStr(wsS.Cells(1, c).Value)\n                            wsR.Cells(rptRow, 4).Value = CStr(wsS.Cells(i, c).Value)\n                            wsR.Cells(rptRow, 5).Value = CStr(wsT.Cells(j, c).Value)\n                            wsR.Cells(rptRow, 1).Interior.Color = RGB(255, 255, 153)\n                            rptRow = rptRow + 1\n                            modifiedCount = modifiedCount + 1\n                        End If\n                    Next c\n                    Exit For\n                End If\n            Next j\n            If Not foundInTarget Then\n                wsR.Cells(rptRow, 1).Value = \"刪除\"\n                wsR.Cells(rptRow, 2).Value = srcKey\n                wsR.Cells(rptRow, 3).Value = \"(不存在於目標)\"\n                wsR.Cells(rptRow, 1).Interior.Color = RGB(255, 199, 206)\n                rptRow = rptRow + 1\n                deletedCount = deletedCount + 1\n            End If\n        End If\n    Next i\n\n    ' 掃描目標，找出新增\n    For j = headerRows + 1 To tgtLastRow\n        tgtKey = CStr(wsT.Cells(j, keyColNum).Value)\n        If tgtKey <> \"\" Then\n            foundInSource = False\n            For i = headerRows + 1 To srcLastRow\n                If tgtKey = CStr(wsS.Cells(i, keyColNum).Value) Then\n                    foundInSource = True\n                    Exit For\n                End If\n            Next i\n            If Not foundInSource Then\n                wsR.Cells(rptRow, 1).Value = \"新增\"\n                wsR.Cells(rptRow, 2).Value = tgtKey\n                wsR.Cells(rptRow, 3).Value = \"(僅存在於目標)\"\n                wsR.Cells(rptRow, 1).Interior.Color = RGB(198, 239, 206)\n                rptRow = rptRow + 1\n                addedCount = addedCount + 1\n            End If\n        End If\n    Next j\n\n    wsR.Columns(\"A:E\").AutoFit\n    wsR.Activate\n    MsgBox \"鍵值比對完成！\" & vbCrLf & _\n           \"新增: \" & addedCount & \" 筆\" & vbCrLf & _\n           \"刪除: \" & deletedCount & \" 筆\" & vbCrLf & _\n           \"修改: \" & modifiedCount & \" 筆\", vbInformation, \"比對結果\"\n    Exit Sub\n\nErrHandler:\n    MsgBox \"發生錯誤: \" & Err.Description, vbCritical, \"錯誤\"\nEnd Sub\n\nPrivate Function GetOrCreateSheetCBK(ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = ThisWorkbook.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = ThisWorkbook.Worksheets.Add\n        ws.Name = sheetName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreateSheetCBK = ws\nEnd Function\n", "content_b64": ""}, {"name": "CompareColumnHeaders.bas", "path": "模組/AutomaticallyCompareDataDifferences/CompareColumnHeaders.bas", "content": "Attribute VB_Name = \"CompareColumnHeaders\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: CompareColumnHeaders\n'功能說明: 比對兩張工作表的欄位標題結構是否一致，\n'          找出缺少、多餘、順序不符的欄位\n'\n'著作權所有: Dunk\n'程式設計: Dunk\n'撰寫日期: 2026/5/9\n'\n'*************************************************************************************\n\n' 測試用入口\nSub TestCompareColumnHeaders()\n    Call CreateHeaderData\n    Call CompareColumnHeaders(\"標準格式\", \"上傳格式\", \"欄位結構差異\")\nEnd Sub\n\n' 建立欄位標題比對範例資料\nPrivate Sub CreateHeaderData()\n    Dim wsA As Worksheet\n    Dim wsB As Worksheet\n\n    Set wsA = GetOrCreateSheetCCH(\"標準格式\")\n    Set wsB = GetOrCreateSheetCCH(\"上傳格式\")\n\n    wsA.Range(\"A1\").Value = \"員工編號\"\n    wsA.Range(\"B1\").Value = \"姓名\"\n    wsA.Range(\"C1\").Value = \"部門\"\n    wsA.Range(\"D1\").Value = \"職稱\"\n    wsA.Range(\"E1\").Value = \"到職日\"\n    wsA.Range(\"F1\").Value = \"薪資\"\n    wsA.Range(\"A2\").Value = \"（標準格式範例資料列）\"\n\n    wsB.Range(\"A1\").Value = \"員工編號\"\n    wsB.Range(\"B1\").Value = \"姓名\"\n    wsB.Range(\"C1\").Value = \"職稱\"\n    wsB.Range(\"D1\").Value = \"部門\"\n    wsB.Range(\"E1\").Value = \"薪資\"\n    wsB.Range(\"F1\").Value = \"備註\"\n    wsB.Range(\"A2\").Value = \"（上傳格式範例資料列）\"\nEnd Sub\n\n' 比對兩張工作表的欄位標題\nPublic Sub CompareColumnHeaders(ByVal standardSheet As String, ByVal uploadSheet As String, _\n                                 ByVal reportSheet As String)\n    Dim wsStd        As Worksheet\n    Dim wsUpd        As Worksheet\n    Dim wsR          As Worksheet\n    Dim stdLastCol   As Long\n    Dim updLastCol   As Long\n    Dim i            As Long\n    Dim j            As Long\n    Dim rptRow       As Long\n    Dim stdHeader    As String\n    Dim updHeader    As String\n    Dim foundInUpload As Boolean\n    Dim foundInStd   As Boolean\n    Dim missingCount As Long\n    Dim extraCount   As Long\n    Dim orderMismatch As Long\n\n    On Error GoTo ErrHandler\n\n    Set wsStd = ThisWorkbook.Worksheets(standardSheet)\n    Set wsUpd = ThisWorkbook.Worksheets(uploadSheet)\n    Set wsR = GetOrCreateSheetCCH(reportSheet)\n\n    stdLastCol = wsStd.Cells(1, wsStd.Columns.Count).End(xlToLeft).Column\n    updLastCol = wsUpd.Cells(1, wsUpd.Columns.Count).End(xlToLeft).Column\n\n    wsR.Range(\"A1\").Value = \"標準格式欄位\"\n    wsR.Range(\"B1\").Value = \"上傳格式欄位\"\n    wsR.Range(\"C1\").Value = \"比對結果\"\n    With wsR.Range(\"A1:C1\")\n        .Font.Bold = True\n        .Interior.Color = RGB(84, 130, 53)\n        .Font.Color = RGB(255, 255, 255)\n    End With\n\n    rptRow = 2\n    missingCount = 0\n    extraCount = 0\n    orderMismatch = 0\n\n    ' 以標準格式為基準，逐欄比對\n    For i = 1 To stdLastCol\n        stdHeader = CStr(wsStd.Cells(1, i).Value)\n        foundInUpload = False\n        For j = 1 To updLastCol\n            updHeader = CStr(wsUpd.Cells(1, j).Value)\n            If stdHeader = updHeader Then\n                foundInUpload = True\n                wsR.Cells(rptRow, 1).Value = stdHeader & \" (第\" & i & \"欄)\"\n                wsR.Cells(rptRow, 2).Value = updHeader & \" (第\" & j & \"欄)\"\n                If i = j Then\n                    wsR.Cells(rptRow, 3).Value = \"位置相符\"\n                Else\n                    wsR.Cells(rptRow, 3).Value = \"位置不同\"\n                    wsR.Cells(rptRow, 1).Resize(1, 3).Interior.Color = RGB(255, 235, 156)\n                    orderMismatch = orderMismatch + 1\n                End If\n                rptRow = rptRow + 1\n                Exit For\n            End If\n        Next j\n        If Not foundInUpload Then\n            wsR.Cells(rptRow, 1).Value = stdHeader & \" (第\" & i & \"欄)\"\n            wsR.Cells(rptRow, 2).Value = \"(缺少)\"\n            wsR.Cells(rptRow, 3).Value = \"上傳格式缺少此欄\"\n            wsR.Cells(rptRow, 1).Resize(1, 3).Interior.Color = RGB(255, 199, 206)\n            rptRow = rptRow + 1\n            missingCount = missingCount + 1\n        End If\n    Next i\n\n    ' 找出上傳格式多出的欄位\n    For j = 1 To updLastCol\n        updHeader = CStr(wsUpd.Cells(1, j).Value)\n        foundInStd = False\n        For i = 1 To stdLastCol\n            If updHeader = CStr(wsStd.Cells(1, i).Value) Then\n                foundInStd = True\n                Exit For\n            End If\n        Next i\n        If Not foundInStd Then\n            wsR.Cells(rptRow, 1).Value = \"(不在標準格式)\"\n            wsR.Cells(rptRow, 2).Value = updHeader & \" (第\" & j & \"欄)\"\n            wsR.Cells(rptRow, 3).Value = \"上傳格式多出此欄\"\n            wsR.Cells(rptRow, 1).Resize(1, 3).Interior.Color = RGB(198, 239, 206)\n            rptRow = rptRow + 1\n            extraCount = extraCount + 1\n        End If\n    Next j\n\n    wsR.Columns(\"A:C\").AutoFit\n    wsR.Activate\n    MsgBox \"欄位結構比對完成！\" & vbCrLf & _\n           \"缺少欄位: \" & missingCount & \" 個\" & vbCrLf & _\n           \"多餘欄位: \" & extraCount & \" 個\" & vbCrLf & _\n           \"位置不符: \" & orderMismatch & \" 個\", vbInformation, \"欄位比對結果\"\n    Exit Sub\n\nErrHandler:\n    MsgBox \"發生錯誤: \" & Err.Description, vbCritical, \"錯誤\"\nEnd Sub\n\nPrivate Function GetOrCreateSheetCCH(ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = ThisWorkbook.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = ThisWorkbook.Worksheets.Add\n        ws.Name = sheetName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreateSheetCCH = ws\nEnd Function\n", "content_b64": ""}, {"name": "CompareFormulas.bas", "path": "模組/AutomaticallyCompareDataDifferences/CompareFormulas.bas", "content": "Attribute VB_Name = \"CompareFormulas\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: CompareFormulas\n'功能說明: 比對兩張工作表中的公式內容（非儲存格值），\n'          找出公式不一致的位置並輸出報告\n'\n'著作權所有: Dunk\n'程式設計: Dunk\n'撰寫日期: 2026/5/9\n'\n'*************************************************************************************\n\n' 測試用入口\nSub TestCompareFormulas()\n    Call CreateFormulaData\n    Call CompareFormulas(\"公式版A\", \"公式版B\", \"公式差異報告\")\nEnd Sub\n\n' 建立含有公式的範例工作表\nPrivate Sub CreateFormulaData()\n    Dim wsA As Worksheet\n    Dim wsB As Worksheet\n\n    Set wsA = GetOrCreateSheetCF(\"公式版A\")\n    Set wsB = GetOrCreateSheetCF(\"公式版B\")\n\n    wsA.Range(\"A1\").Value = \"月份\"\n    wsA.Range(\"B1\").Value = \"收入\"\n    wsA.Range(\"C1\").Value = \"支出\"\n    wsA.Range(\"D1\").Value = \"淨利\"\n    wsA.Range(\"A2\").Value = \"一月\" : wsA.Range(\"B2\").Value = 100000 : wsA.Range(\"C2\").Value = 60000\n    wsA.Range(\"A3\").Value = \"二月\" : wsA.Range(\"B3\").Value = 120000 : wsA.Range(\"C3\").Value = 70000\n    wsA.Range(\"D2\").Formula = \"=B2-C2\"\n    wsA.Range(\"D3\").Formula = \"=B3-C3\"\n    wsA.Columns(\"A:D\").AutoFit\n\n    wsB.Range(\"A1\").Value = \"月份\"\n    wsB.Range(\"B1\").Value = \"收入\"\n    wsB.Range(\"C1\").Value = \"支出\"\n    wsB.Range(\"D1\").Value = \"淨利\"\n    wsB.Range(\"A2\").Value = \"一月\" : wsB.Range(\"B2\").Value = 100000 : wsB.Range(\"C2\").Value = 60000\n    wsB.Range(\"A3\").Value = \"二月\" : wsB.Range(\"B3\").Value = 120000 : wsB.Range(\"C3\").Value = 70000\n    ' 故意放入不同公式以產生差異\n    wsB.Range(\"D2\").Formula = \"=B2-C2\"\n    wsB.Range(\"D3\").Formula = \"=B3+C3\"\n    wsB.Columns(\"A:D\").AutoFit\nEnd Sub\n\n' 比對兩張工作表中的公式，差異輸出至報告工作表\nPublic Sub CompareFormulas(ByVal sheetA As String, ByVal sheetB As String, _\n                            ByVal reportSheet As String)\n    Dim wsA      As Worksheet\n    Dim wsB      As Worksheet\n    Dim wsR      As Worksheet\n    Dim lastRow  As Long\n    Dim lastCol  As Long\n    Dim r        As Long\n    Dim c        As Long\n    Dim rptRow   As Long\n    Dim fmlA     As String\n    Dim fmlB     As String\n    Dim diffCount As Long\n\n    On Error GoTo ErrHandler\n\n    Set wsA = ThisWorkbook.Worksheets(sheetA)\n    Set wsB = ThisWorkbook.Worksheets(sheetB)\n    Set wsR = GetOrCreateSheetCF(reportSheet)\n\n    lastRow = Application.WorksheetFunction.Max( _\n        wsA.Cells(wsA.Rows.Count, 1).End(xlUp).Row, _\n        wsB.Cells(wsB.Rows.Count, 1).End(xlUp).Row)\n    lastCol = Application.WorksheetFunction.Max( _\n        wsA.Cells(1, wsA.Columns.Count).End(xlToLeft).Column, _\n        wsB.Cells(1, wsB.Columns.Count).End(xlToLeft).Column)\n\n    wsR.Range(\"A1\").Value = \"儲存格\"\n    wsR.Range(\"B1\").Value = \"差異類型\"\n    wsR.Range(\"C1\").Value = sheetA & \" 公式\"\n    wsR.Range(\"D1\").Value = sheetB & \" 公式\"\n    With wsR.Range(\"A1:D1\")\n        .Font.Bold = True\n        .Interior.Color = RGB(112, 48, 160)\n        .Font.Color = RGB(255, 255, 255)\n    End With\n\n    rptRow = 2\n    diffCount = 0\n\n    For r = 1 To lastRow\n        For c = 1 To lastCol\n            If wsA.Cells(r, c).HasFormula Then\n                fmlA = wsA.Cells(r, c).Formula\n            Else\n                fmlA = \"\"\n            End If\n            If wsB.Cells(r, c).HasFormula Then\n                fmlB = wsB.Cells(r, c).Formula\n            Else\n                fmlB = \"\"\n            End If\n            If fmlA <> fmlB Then\n                wsR.Cells(rptRow, 1).Value = wsA.Cells(r, c).Address(False, False)\n                If fmlA <> \"\" And fmlB = \"\" Then\n                    wsR.Cells(rptRow, 2).Value = \"B缺少公式\"\n                ElseIf fmlA = \"\" And fmlB <> \"\" Then\n                    wsR.Cells(rptRow, 2).Value = \"A缺少公式\"\n                Else\n                    wsR.Cells(rptRow, 2).Value = \"公式不同\"\n                End If\n                wsR.Cells(rptRow, 3).Value = fmlA\n                wsR.Cells(rptRow, 4).Value = fmlB\n                wsR.Cells(rptRow, 1).Resize(1, 4).Interior.Color = RGB(255, 235, 156)\n                rptRow = rptRow + 1\n                diffCount = diffCount + 1\n            End If\n        Next c\n    Next r\n\n    wsR.Columns(\"A:D\").AutoFit\n    wsR.Activate\n    If diffCount = 0 Then\n        MsgBox \"兩張工作表公式完全相符！\", vbInformation, \"公式比對\"\n    Else\n        MsgBox \"公式比對完成！共發現 \" & diffCount & \" 處公式差異。\", vbInformation, \"公式比對\"\n    End If\n    Exit Sub\n\nErrHandler:\n    MsgBox \"發生錯誤: \" & Err.Description, vbCritical, \"錯誤\"\nEnd Sub\n\nPrivate Function GetOrCreateSheetCF(ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = ThisWorkbook.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = ThisWorkbook.Worksheets.Add\n        ws.Name = sheetName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreateSheetCF = ws\nEnd Function\n", "content_b64": ""}, {"name": "CompareIgnoreCase.bas", "path": "模組/AutomaticallyCompareDataDifferences/CompareIgnoreCase.bas", "content": "Attribute VB_Name = \"CompareIgnoreCase\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: CompareIgnoreCase\n'功能說明: 不區分英文大小寫比對兩張工作表，\n'          區分「僅大小寫差異」與「實質內容差異」兩類\n'\n'著作權所有: Dunk\n'程式設計: Dunk\n'撰寫日期: 2026/5/9\n'\n'*************************************************************************************\n\n' 測試用入口\nSub TestCompareIgnoreCase()\n    Call CreateIgnoreCaseData\n    Call CompareIgnoreCase(\"系統匯出\", \"手動輸入\", \"大小寫差異報告\")\nEnd Sub\n\n' 建立大小寫比對範例資料\nPrivate Sub CreateIgnoreCaseData()\n    Dim wsA As Worksheet\n    Dim wsB As Worksheet\n\n    Set wsA = GetOrCreateSheetCIC(\"系統匯出\")\n    Set wsB = GetOrCreateSheetCIC(\"手動輸入\")\n\n    wsA.Range(\"A1\").Value = \"料號\"\n    wsA.Range(\"B1\").Value = \"型號\"\n    wsA.Range(\"C1\").Value = \"顏色代碼\"\n    wsA.Range(\"D1\").Value = \"規格\"\n    wsA.Range(\"A2\").Value = \"SKU001\" : wsA.Range(\"B2\").Value = \"MODEL-A100\" : wsA.Range(\"C2\").Value = \"RED\"   : wsA.Range(\"D2\").Value = \"XL\"\n    wsA.Range(\"A3\").Value = \"SKU002\" : wsA.Range(\"B3\").Value = \"MODEL-B200\" : wsA.Range(\"C3\").Value = \"BLUE\"  : wsA.Range(\"D3\").Value = \"M\"\n    wsA.Range(\"A4\").Value = \"SKU003\" : wsA.Range(\"B4\").Value = \"MODEL-C300\" : wsA.Range(\"C4\").Value = \"GREEN\" : wsA.Range(\"D4\").Value = \"S\"\n    wsA.Columns(\"A:D\").AutoFit\n\n    wsB.Range(\"A1\").Value = \"料號\"\n    wsB.Range(\"B1\").Value = \"型號\"\n    wsB.Range(\"C1\").Value = \"顏色代碼\"\n    wsB.Range(\"D1\").Value = \"規格\"\n    wsB.Range(\"A2\").Value = \"SKU001\" : wsB.Range(\"B2\").Value = \"model-a100\" : wsB.Range(\"C2\").Value = \"Red\"   : wsB.Range(\"D2\").Value = \"XL\"\n    wsB.Range(\"A3\").Value = \"SKU002\" : wsB.Range(\"B3\").Value = \"MODEL-B200\" : wsB.Range(\"C3\").Value = \"BLUE\"  : wsB.Range(\"D3\").Value = \"m\"\n    wsB.Range(\"A4\").Value = \"SKU003\" : wsB.Range(\"B4\").Value = \"Model-C999\" : wsB.Range(\"C4\").Value = \"GREEN\" : wsB.Range(\"D4\").Value = \"S\"\n    wsB.Columns(\"A:D\").AutoFit\nEnd Sub\n\n' 不區分大小寫比對，區分「大小寫差異」與「實質差異」\nPublic Sub CompareIgnoreCase(ByVal sheetA As String, ByVal sheetB As String, _\n                              ByVal reportSheet As String)\n    Dim wsA           As Worksheet\n    Dim wsB           As Worksheet\n    Dim wsR           As Worksheet\n    Dim lastRow       As Long\n    Dim lastCol       As Long\n    Dim r             As Long\n    Dim c             As Long\n    Dim rptRow        As Long\n    Dim valA          As String\n    Dim valB          As String\n    Dim caseOnlyCount As Long\n    Dim realDiffCount As Long\n\n    On Error GoTo ErrHandler\n\n    Set wsA = ThisWorkbook.Worksheets(sheetA)\n    Set wsB = ThisWorkbook.Worksheets(sheetB)\n    Set wsR = GetOrCreateSheetCIC(reportSheet)\n\n    lastRow = Application.WorksheetFunction.Max( _\n        wsA.Cells(wsA.Rows.Count, 1).End(xlUp).Row, _\n        wsB.Cells(wsB.Rows.Count, 1).End(xlUp).Row)\n    lastCol = Application.WorksheetFunction.Max( _\n        wsA.Cells(1, wsA.Columns.Count).End(xlToLeft).Column, _\n        wsB.Cells(1, wsB.Columns.Count).End(xlToLeft).Column)\n\n    wsR.Range(\"A1\").Value = \"儲存格\"\n    wsR.Range(\"B1\").Value = \"差異類型\"\n    wsR.Range(\"C1\").Value = sheetA & \" 值\"\n    wsR.Range(\"D1\").Value = sheetB & \" 值\"\n    With wsR.Range(\"A1:D1\")\n        .Font.Bold = True\n        .Interior.Color = RGB(192, 0, 0)\n        .Font.Color = RGB(255, 255, 255)\n    End With\n\n    rptRow = 2\n    caseOnlyCount = 0\n    realDiffCount = 0\n\n    For r = 1 To lastRow\n        For c = 1 To lastCol\n            valA = CStr(wsA.Cells(r, c).Value)\n            valB = CStr(wsB.Cells(r, c).Value)\n            If valA <> valB Then\n                wsR.Cells(rptRow, 1).Value = wsA.Cells(r, c).Address(False, False)\n                wsR.Cells(rptRow, 3).Value = valA\n                wsR.Cells(rptRow, 4).Value = valB\n                If UCase(valA) = UCase(valB) Then\n                    ' 僅大小寫不同\n                    wsR.Cells(rptRow, 2).Value = \"大小寫差異\"\n                    wsR.Cells(rptRow, 1).Resize(1, 4).Interior.Color = RGB(255, 235, 156)\n                    caseOnlyCount = caseOnlyCount + 1\n                Else\n                    ' 實質內容不同\n                    wsR.Cells(rptRow, 2).Value = \"實質差異\"\n                    wsR.Cells(rptRow, 1).Resize(1, 4).Interior.Color = RGB(255, 199, 206)\n                    realDiffCount = realDiffCount + 1\n                End If\n                rptRow = rptRow + 1\n            End If\n        Next c\n    Next r\n\n    wsR.Columns(\"A:D\").AutoFit\n    wsR.Activate\n    MsgBox \"不區分大小寫比對完成！\" & vbCrLf & _\n           \"僅大小寫差異: \" & caseOnlyCount & \" 筆\" & vbCrLf & _\n           \"實質內容差異: \" & realDiffCount & \" 筆\", vbInformation, \"比對結果\"\n    Exit Sub\n\nErrHandler:\n    MsgBox \"發生錯誤: \" & Err.Description, vbCritical, \"錯誤\"\nEnd Sub\n\nPrivate Function GetOrCreateSheetCIC(ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = ThisWorkbook.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = ThisWorkbook.Worksheets.Add\n        ws.Name = sheetName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreateSheetCIC = ws\nEnd Function\n", "content_b64": ""}, {"name": "CompareMultipleSheets.bas", "path": "模組/AutomaticallyCompareDataDifferences/CompareMultipleSheets.bas", "content": "Attribute VB_Name = \"CompareMultipleSheets\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: CompareMultipleSheets\n'功能說明: 批次比對活頁簿中多對工作表，一次產生所有比對結果整合報告，\n'          適用於多月份或多部門同時比對的情境\n'\n'著作權所有: Dunk\n'程式設計: Dunk\n'撰寫日期: 2026/5/9\n'\n'*************************************************************************************\n\n' 測試用入口，批次比對三組工作表\nSub TestCompareMultipleSheets()\n    Call CreateMultiSheetsData\n\n    Dim pairs(1 To 3, 1 To 2) As String\n    pairs(1, 1) = \"Jan_舊版\" : pairs(1, 2) = \"Jan_新版\"\n    pairs(2, 1) = \"Feb_舊版\" : pairs(2, 2) = \"Feb_新版\"\n    pairs(3, 1) = \"Mar_舊版\" : pairs(3, 2) = \"Mar_新版\"\n\n    Call CompareMultipleSheets(pairs, \"批次比對總表\")\nEnd Sub\n\n' 建立多工作表批次比對範例資料\nPrivate Sub CreateMultiSheetsData()\n    Dim ws         As Worksheet\n    Dim sheetNames(1 To 6) As String\n    Dim i          As Integer\n\n    sheetNames(1) = \"Jan_舊版\" : sheetNames(2) = \"Jan_新版\"\n    sheetNames(3) = \"Feb_舊版\" : sheetNames(4) = \"Feb_新版\"\n    sheetNames(5) = \"Mar_舊版\" : sheetNames(6) = \"Mar_新版\"\n\n    For i = 1 To 6\n        Set ws = GetOrCreateSheetCMS(sheetNames(i))\n        ws.Range(\"A1\").Value = \"項目\"\n        ws.Range(\"B1\").Value = \"數量\"\n        ws.Range(\"C1\").Value = \"金額\"\n        ws.Range(\"A2\").Value = \"項目A\"\n        ws.Range(\"A3\").Value = \"項目B\"\n        ws.Range(\"A4\").Value = \"項目C\"\n        ' 舊版與新版填入不同數值以產生差異\n        If InStr(sheetNames(i), \"舊版\") > 0 Then\n            ws.Range(\"B2\").Value = 100 : ws.Range(\"C2\").Value = 5000\n            ws.Range(\"B3\").Value = 200 : ws.Range(\"C3\").Value = 8000\n            ws.Range(\"B4\").Value = 150 : ws.Range(\"C4\").Value = 6000\n        Else\n            ws.Range(\"B2\").Value = 110 : ws.Range(\"C2\").Value = 5000\n            ws.Range(\"B3\").Value = 200 : ws.Range(\"C3\").Value = 8500\n            ws.Range(\"B4\").Value = 145 : ws.Range(\"C4\").Value = 6000\n        End If\n        ws.Columns(\"A:C\").AutoFit\n    Next i\nEnd Sub\n\n' 批次比對多對工作表，輸出整合報告\nPublic Sub CompareMultipleSheets(ByRef pairList() As String, ByVal summarySheet As String)\n    Dim wsR        As Worksheet\n    Dim wsA        As Worksheet\n    Dim wsB        As Worksheet\n    Dim totalPairs As Long\n    Dim p          As Long\n    Dim r          As Long\n    Dim c          As Long\n    Dim lastRow    As Long\n    Dim lastCol    As Long\n    Dim rptRow     As Long\n    Dim valA       As String\n    Dim valB       As String\n    Dim pairDiff   As Long\n    Dim grandTotal As Long\n    Dim sheetA     As String\n    Dim sheetB     As String\n\n    On Error GoTo ErrHandler\n\n    Set wsR = GetOrCreateSheetCMS(summarySheet)\n\n    wsR.Range(\"A1\").Value = \"批次工作表比對總覽\"\n    With wsR.Range(\"A1\")\n        .Font.Bold = True\n        .Font.Size = 14\n    End With\n    wsR.Range(\"A2\").Value = \"執行時間: \" & Format(Now, \"yyyy/mm/dd hh:mm:ss\")\n\n    wsR.Range(\"A4\").Value = \"組別\"\n    wsR.Range(\"B4\").Value = \"工作表A\"\n    wsR.Range(\"C4\").Value = \"工作表B\"\n    wsR.Range(\"D4\").Value = \"儲存格\"\n    wsR.Range(\"E4\").Value = \"A值\"\n    wsR.Range(\"F4\").Value = \"B值\"\n    With wsR.Range(\"A4:F4\")\n        .Font.Bold = True\n        .Interior.Color = RGB(0, 70, 127)\n        .Font.Color = RGB(255, 255, 255)\n    End With\n\n    rptRow = 5\n    grandTotal = 0\n    totalPairs = UBound(pairList, 1)\n\n    For p = 1 To totalPairs\n        sheetA = pairList(p, 1)\n        sheetB = pairList(p, 2)\n        pairDiff = 0\n\n        Set wsA = Nothing\n        Set wsB = Nothing\n        On Error Resume Next\n        Set wsA = ThisWorkbook.Worksheets(sheetA)\n        Set wsB = ThisWorkbook.Worksheets(sheetB)\n        On Error GoTo ErrHandler\n\n        If wsA Is Nothing Or wsB Is Nothing Then\n            wsR.Cells(rptRow, 1).Value = \"第\" & p & \"組\"\n            wsR.Cells(rptRow, 2).Value = sheetA\n            wsR.Cells(rptRow, 3).Value = sheetB\n            wsR.Cells(rptRow, 4).Value = \"(找不到工作表)\"\n            wsR.Cells(rptRow, 1).Resize(1, 6).Interior.Color = RGB(255, 199, 206)\n            rptRow = rptRow + 1\n        Else\n            lastRow = Application.WorksheetFunction.Max( _\n                wsA.Cells(wsA.Rows.Count, 1).End(xlUp).Row, _\n                wsB.Cells(wsB.Rows.Count, 1).End(xlUp).Row)\n            lastCol = Application.WorksheetFunction.Max( _\n                wsA.Cells(1, wsA.Columns.Count).End(xlToLeft).Column, _\n                wsB.Cells(1, wsB.Columns.Count).End(xlToLeft).Column)\n\n            For r = 1 To lastRow\n                For c = 1 To lastCol\n                    valA = CStr(wsA.Cells(r, c).Value)\n                    valB = CStr(wsB.Cells(r, c).Value)\n                    If valA <> valB Then\n                        wsR.Cells(rptRow, 1).Value = \"第\" & p & \"組\"\n                        wsR.Cells(rptRow, 2).Value = sheetA\n                        wsR.Cells(rptRow, 3).Value = sheetB\n                        wsR.Cells(rptRow, 4).Value = wsA.Cells(r, c).Address(False, False)\n                        wsR.Cells(rptRow, 5).Value = valA\n                        wsR.Cells(rptRow, 6).Value = valB\n                        wsR.Cells(rptRow, 1).Resize(1, 6).Interior.Color = RGB(255, 255, 153)\n                        rptRow = rptRow + 1\n                        pairDiff = pairDiff + 1\n                        grandTotal = grandTotal + 1\n                    End If\n                Next c\n            Next r\n\n            If pairDiff = 0 Then\n                wsR.Cells(rptRow, 1).Value = \"第\" & p & \"組\"\n                wsR.Cells(rptRow, 2).Value = sheetA\n                wsR.Cells(rptRow, 3).Value = sheetB\n                wsR.Cells(rptRow, 4).Value = \"(無差異)\"\n                wsR.Cells(rptRow, 1).Resize(1, 6).Interior.Color = RGB(198, 239, 206)\n                rptRow = rptRow + 1\n            End If\n        End If\n    Next p\n\n    ' 總計列\n    wsR.Cells(rptRow + 1, 1).Value = \"總計差異數\"\n    wsR.Cells(rptRow + 1, 2).Value = grandTotal & \" 處\"\n    With wsR.Cells(rptRow + 1, 1).Resize(1, 6)\n        .Font.Bold = True\n        .Interior.Color = RGB(155, 194, 230)\n    End With\n\n    wsR.Columns(\"A:F\").AutoFit\n    wsR.Activate\n    MsgBox \"批次比對完成！共比對 \" & totalPairs & \" 組工作表，\" & _\n           \"合計發現 \" & grandTotal & \" 處差異。\", vbInformation, \"批次比對結果\"\n    Exit Sub\n\nErrHandler:\n    MsgBox \"發生錯誤: \" & Err.Description, vbCritical, \"錯誤\"\nEnd Sub\n\nPrivate Function GetOrCreateSheetCMS(ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = ThisWorkbook.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = ThisWorkbook.Worksheets.Add\n        ws.Name = sheetName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreateSheetCMS = ws\nEnd Function\n", "content_b64": ""}, {"name": "CompareSheetData.bas", "path": "模組/AutomaticallyCompareDataDifferences/CompareSheetData.bas", "content": "Attribute VB_Name = \"CompareSheetData\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: CompareSheetData\n'功能說明: 自動比較兩個工作表的資料差異，並以顏色標示不同之處\n'\n'著作權所有: Dunk\n'程式設計: Dunk\n'撰寫日期: 2026/5/7\n'\n'*************************************************************************************\n\n' 測試用入口（建立範例資料後進行比較）\nSub TestCompareSheetData()\n    Call CreateSampleDataForCompare\n    Call CompareSheetData(\"資料版本A\", \"資料版本B\", \"差異報告\")\nEnd Sub\n\n' 建立兩個版本的範例資料\nPrivate Sub CreateSampleDataForCompare()\n    Dim wsA As Worksheet\n    Dim wsB As Worksheet\n\n    Set wsA = GetOrCreateSheet(ThisWorkbook, \"資料版本A\")\n    Set wsB = GetOrCreateSheet(ThisWorkbook, \"資料版本B\")\n\n    wsA.Range(\"A1\").Value = \"員工編號\"\n    wsA.Range(\"B1\").Value = \"姓名\"\n    wsA.Range(\"C1\").Value = \"部門\"\n    wsA.Range(\"D1\").Value = \"薪資\"\n    wsA.Range(\"A2\").Value = \"E001\" : wsA.Range(\"B2\").Value = \"張三\"\n    wsA.Range(\"C2\").Value = \"研發部\" : wsA.Range(\"D2\").Value = 60000\n    wsA.Range(\"A3\").Value = \"E002\" : wsA.Range(\"B3\").Value = \"李四\"\n    wsA.Range(\"C3\").Value = \"業務部\" : wsA.Range(\"D3\").Value = 55000\n    wsA.Range(\"A4\").Value = \"E003\" : wsA.Range(\"B4\").Value = \"王五\"\n    wsA.Range(\"C4\").Value = \"行政部\" : wsA.Range(\"D4\").Value = 45000\n    wsA.Range(\"A5\").Value = \"E004\" : wsA.Range(\"B5\").Value = \"趙六\"\n    wsA.Range(\"C5\").Value = \"財務部\" : wsA.Range(\"D5\").Value = 52000\n    wsA.Columns(\"A:D\").AutoFit\n\n    wsB.Range(\"A1\").Value = \"員工編號\"\n    wsB.Range(\"B1\").Value = \"姓名\"\n    wsB.Range(\"C1\").Value = \"部門\"\n    wsB.Range(\"D1\").Value = \"薪資\"\n    wsB.Range(\"A2\").Value = \"E001\" : wsB.Range(\"B2\").Value = \"張三\"\n    wsB.Range(\"C2\").Value = \"研發部\" : wsB.Range(\"D2\").Value = 65000\n    wsB.Range(\"A3\").Value = \"E002\" : wsB.Range(\"B3\").Value = \"李四\"\n    wsB.Range(\"C3\").Value = \"行銷部\" : wsB.Range(\"D3\").Value = 55000\n    wsB.Range(\"A4\").Value = \"E003\" : wsB.Range(\"B4\").Value = \"王五\"\n    wsB.Range(\"C4\").Value = \"行政部\" : wsB.Range(\"D4\").Value = 45000\n    wsB.Range(\"A5\").Value = \"E004\" : wsB.Range(\"B5\").Value = \"趙六\"\n    wsB.Range(\"C5\").Value = \"財務部\" : wsB.Range(\"D5\").Value = 52000\n    wsB.Columns(\"A:D\").AutoFit\nEnd Sub\n\n' 比較兩張工作表的差異並輸出報告\nSub CompareSheetData(ByVal sheetNameA As String, ByVal sheetNameB As String, _\n                     ByVal reportSheetName As String)\n    Dim wsA As Worksheet\n    Dim wsB As Worksheet\n    Dim wsReport As Worksheet\n    Dim lastRowA As Long\n    Dim lastColA As Long\n    Dim r As Long\n    Dim c As Long\n    Dim diffCount As Long\n    Dim reportRow As Long\n    Dim valA As String\n    Dim valB As String\n\n    On Error Resume Next\n    Set wsA = ThisWorkbook.Worksheets(sheetNameA)\n    Set wsB = ThisWorkbook.Worksheets(sheetNameB)\n    On Error GoTo 0\n\n    If wsA Is Nothing Or wsB Is Nothing Then\n        MsgBox \"找不到指定的工作表，請確認工作表名稱！\", vbExclamation, \"錯誤\"\n        Exit Sub\n    End If\n\n    Set wsReport = GetOrCreateSheet(ThisWorkbook, reportSheetName)\n\n    wsReport.Range(\"A1\").Value = \"工作表A\"\n    wsReport.Range(\"B1\").Value = sheetNameA\n    wsReport.Range(\"A2\").Value = \"工作表B\"\n    wsReport.Range(\"B2\").Value = sheetNameB\n    wsReport.Range(\"A3\").Value = \"差異儲存格\"\n    wsReport.Range(\"B3\").Value = \"版本A值\"\n    wsReport.Range(\"C3\").Value = \"版本B值\"\n\n    With wsReport.Range(\"A3:C3\")\n        .Font.Bold = True\n        .Interior.Color = RGB(200, 200, 200)\n    End With\n\n    reportRow = 4\n    diffCount = 0\n\n    lastRowA = wsA.Cells(wsA.Rows.Count, 1).End(xlUp).Row\n    lastColA = wsA.Cells(1, wsA.Columns.Count).End(xlToLeft).Column\n\n    For r = 1 To lastRowA\n        For c = 1 To lastColA\n            valA = CStr(wsA.Cells(r, c).Value)\n            valB = CStr(wsB.Cells(r, c).Value)\n            If valA <> valB Then\n                wsReport.Cells(reportRow, 1).Value = wsA.Cells(r, c).Address(False, False)\n                wsReport.Cells(reportRow, 2).Value = valA\n                wsReport.Cells(reportRow, 3).Value = valB\n                wsA.Cells(r, c).Interior.Color = RGB(255, 255, 0)\n                wsB.Cells(r, c).Interior.Color = RGB(255, 200, 0)\n                reportRow = reportRow + 1\n                diffCount = diffCount + 1\n            End If\n        Next c\n    Next r\n\n    wsReport.Columns(\"A:C\").AutoFit\n    wsReport.Activate\n\n    If diffCount = 0 Then\n        MsgBox \"兩個工作表資料完全相同！\", vbInformation, \"比較結果\"\n    Else\n        MsgBox \"比較完成！共發現 \" & diffCount & \" 處差異。\", vbInformation, \"比較結果\"\n    End If\nEnd Sub\n\n' 取得或建立工作表，並清除內容\nPrivate Function GetOrCreateSheet(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add\n        ws.Name = sheetName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreateSheet = ws\nEnd Function\n", "content_b64": ""}, {"name": "CompareTwoWorkbooks.bas", "path": "模組/AutomaticallyCompareDataDifferences/CompareTwoWorkbooks.bas", "content": "Attribute VB_Name = \"CompareTwoWorkbooks\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: CompareTwoWorkbooks\n'功能說明: 讓使用者選取兩個 Excel 活頁簿，比對指定工作表的差異，\n'          結果輸出至目前活頁簿的新工作表\n'\n'著作權所有: Dunk\n'程式設計: Dunk\n'撰寫日期: 2026/5/9\n'\n'*************************************************************************************\n\n' 選取兩個活頁簿後進行比對\nSub CompareTwoWorkbooks()\n    Dim pathA     As String\n    Dim pathB     As String\n    Dim sheetName As String\n    Dim wbA       As Workbook\n    Dim wbB       As Workbook\n    Dim wsA       As Worksheet\n    Dim wsB       As Worksheet\n    Dim wsR       As Worksheet\n    Dim lastRow   As Long\n    Dim lastCol   As Long\n    Dim r         As Long\n    Dim c         As Long\n    Dim rptRow    As Long\n    Dim valA      As String\n    Dim valB      As String\n    Dim diffCount As Long\n\n    On Error GoTo ErrHandler\n\n    ' 選取第一個活頁簿（基準）\n    pathA = Application.GetOpenFilename( _\n        \"Excel 檔案 (*.xls;*.xlsx;*.xlsm),*.xls;*.xlsx;*.xlsm\", _\n        1, \"選取第一個活頁簿（基準）\", , False)\n    If pathA = \"False\" Then Exit Sub\n\n    ' 選取第二個活頁簿（比對對象）\n    pathB = Application.GetOpenFilename( _\n        \"Excel 檔案 (*.xls;*.xlsx;*.xlsm),*.xls;*.xlsx;*.xlsm\", _\n        1, \"選取第二個活頁簿（比對對象）\", , False)\n    If pathB = \"False\" Then Exit Sub\n\n    ' 詢問要比對的工作表名稱\n    sheetName = InputBox(\"請輸入要比對的工作表名稱：\", \"工作表名稱\", \"Sheet1\")\n    If sheetName = \"\" Then Exit Sub\n\n    Application.ScreenUpdating = False\n\n    Set wbA = Workbooks.Open(pathA, ReadOnly:=True)\n    Set wbB = Workbooks.Open(pathB, ReadOnly:=True)\n\n    On Error Resume Next\n    Set wsA = wbA.Worksheets(sheetName)\n    Set wsB = wbB.Worksheets(sheetName)\n    On Error GoTo ErrHandler\n\n    If wsA Is Nothing Or wsB Is Nothing Then\n        MsgBox \"找不到工作表「\" & sheetName & \"」，請確認名稱是否正確。\", vbExclamation, \"錯誤\"\n        GoTo Cleanup\n    End If\n\n    ' 在目前活頁簿建立差異報告\n    Set wsR = GetOrCreateSheetCTW(ThisWorkbook, \"跨檔差異報告\")\n\n    wsR.Range(\"A1\").Value = \"檔案A\"\n    wsR.Range(\"B1\").Value = pathA\n    wsR.Range(\"A2\").Value = \"檔案B\"\n    wsR.Range(\"B2\").Value = pathB\n    wsR.Range(\"A3\").Value = \"工作表\"\n    wsR.Range(\"B3\").Value = sheetName\n    wsR.Range(\"A5\").Value = \"儲存格\"\n    wsR.Range(\"B5\").Value = \"檔案A 值\"\n    wsR.Range(\"C5\").Value = \"檔案B 值\"\n    With wsR.Range(\"A5:C5\")\n        .Font.Bold = True\n        .Interior.Color = RGB(0, 112, 192)\n        .Font.Color = RGB(255, 255, 255)\n    End With\n\n    lastRow = Application.WorksheetFunction.Max( _\n        wsA.Cells(wsA.Rows.Count, 1).End(xlUp).Row, _\n        wsB.Cells(wsB.Rows.Count, 1).End(xlUp).Row)\n    lastCol = Application.WorksheetFunction.Max( _\n        wsA.Cells(1, wsA.Columns.Count).End(xlToLeft).Column, _\n        wsB.Cells(1, wsB.Columns.Count).End(xlToLeft).Column)\n\n    rptRow = 6\n    diffCount = 0\n\n    For r = 1 To lastRow\n        For c = 1 To lastCol\n            valA = CStr(wsA.Cells(r, c).Value)\n            valB = CStr(wsB.Cells(r, c).Value)\n            If valA <> valB Then\n                wsR.Cells(rptRow, 1).Value = wsA.Cells(r, c).Address(False, False)\n                wsR.Cells(rptRow, 2).Value = valA\n                wsR.Cells(rptRow, 3).Value = valB\n                wsR.Cells(rptRow, 1).Resize(1, 3).Interior.Color = RGB(255, 255, 153)\n                rptRow = rptRow + 1\n                diffCount = diffCount + 1\n            End If\n        Next c\n    Next r\n\n    wsR.Columns(\"A:C\").AutoFit\n    wsR.Activate\n\nCleanup:\n    wbA.Close SaveChanges:=False\n    wbB.Close SaveChanges:=False\n    Application.ScreenUpdating = True\n    MsgBox \"跨檔比對完成！共發現 \" & diffCount & \" 處差異。\", vbInformation, \"比對結果\"\n    Exit Sub\n\nErrHandler:\n    Application.ScreenUpdating = True\n    MsgBox \"發生錯誤: \" & Err.Description, vbCritical, \"錯誤\"\n    On Error Resume Next\n    If Not wbA Is Nothing Then wbA.Close SaveChanges:=False\n    If Not wbB Is Nothing Then wbB.Close SaveChanges:=False\nEnd Sub\n\nPrivate Function GetOrCreateSheetCTW(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add\n        ws.Name = sheetName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreateSheetCTW = ws\nEnd Function\n", "content_b64": ""}, {"name": "CompareWithTolerance.bas", "path": "模組/AutomaticallyCompareDataDifferences/CompareWithTolerance.bas", "content": "Attribute VB_Name = \"CompareWithTolerance\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: CompareWithTolerance\n'功能說明: 數值欄位容差比對，允許設定可接受誤差百分比，\n'          超出容差範圍才標記為差異\n'\n'著作權所有: Dunk\n'程式設計: Dunk\n'撰寫日期: 2026/5/9\n'\n'*************************************************************************************\n\n' 測試用入口，容差設定為 5%\nSub TestCompareWithTolerance()\n    Call CreateToleranceData\n    Call CompareWithTolerance(\"預算表\", \"實績表\", \"容差比對報告\", 0.05)\nEnd Sub\n\n' 建立容差比對範例資料\nPrivate Sub CreateToleranceData()\n    Dim wsA As Worksheet\n    Dim wsB As Worksheet\n\n    Set wsA = GetOrCreateSheetCWT(\"預算表\")\n    Set wsB = GetOrCreateSheetCWT(\"實績表\")\n\n    wsA.Range(\"A1\").Value = \"部門\"\n    wsA.Range(\"B1\").Value = \"Q1預算\"\n    wsA.Range(\"C1\").Value = \"Q2預算\"\n    wsA.Range(\"D1\").Value = \"Q3預算\"\n    wsA.Range(\"A2\").Value = \"業務部\" : wsA.Range(\"B2\").Value = 100000 : wsA.Range(\"C2\").Value = 120000 : wsA.Range(\"D2\").Value = 110000\n    wsA.Range(\"A3\").Value = \"研發部\" : wsA.Range(\"B3\").Value = 200000 : wsA.Range(\"C3\").Value = 210000 : wsA.Range(\"D3\").Value = 205000\n    wsA.Range(\"A4\").Value = \"行銷部\" : wsA.Range(\"B4\").Value = 80000  : wsA.Range(\"C4\").Value = 90000  : wsA.Range(\"D4\").Value = 85000\n    wsA.Columns(\"A:D\").AutoFit\n\n    wsB.Range(\"A1\").Value = \"部門\"\n    wsB.Range(\"B1\").Value = \"Q1預算\"\n    wsB.Range(\"C1\").Value = \"Q2預算\"\n    wsB.Range(\"D1\").Value = \"Q3預算\"\n    wsB.Range(\"A2\").Value = \"業務部\" : wsB.Range(\"B2\").Value = 103000 : wsB.Range(\"C2\").Value = 125000 : wsB.Range(\"D2\").Value = 110000\n    wsB.Range(\"A3\").Value = \"研發部\" : wsB.Range(\"B3\").Value = 218000 : wsB.Range(\"C3\").Value = 209000 : wsB.Range(\"D3\").Value = 205000\n    wsB.Range(\"A4\").Value = \"行銷部\" : wsB.Range(\"B4\").Value = 80000  : wsB.Range(\"C4\").Value = 100000 : wsB.Range(\"D4\").Value = 85500\n    wsB.Columns(\"A:D\").AutoFit\nEnd Sub\n\n' 進行容差比對，tolerancePct 為允許誤差比率（如 0.05 代表 5%）\nPublic Sub CompareWithTolerance(ByVal sheetA As String, ByVal sheetB As String, _\n                                 ByVal reportSheet As String, ByVal tolerancePct As Double)\n    Dim wsA      As Worksheet\n    Dim wsB      As Worksheet\n    Dim wsR      As Worksheet\n    Dim lastRow  As Long\n    Dim lastCol  As Long\n    Dim r        As Long\n    Dim c        As Long\n    Dim rptRow   As Long\n    Dim valA     As Double\n    Dim valB     As Double\n    Dim diffPct  As Double\n    Dim diffCount As Long\n    Dim isNumA   As Boolean\n    Dim isNumB   As Boolean\n\n    On Error GoTo ErrHandler\n\n    Set wsA = ThisWorkbook.Worksheets(sheetA)\n    Set wsB = ThisWorkbook.Worksheets(sheetB)\n    Set wsR = GetOrCreateSheetCWT(reportSheet)\n\n    lastRow = wsA.Cells(wsA.Rows.Count, 1).End(xlUp).Row\n    lastCol = wsA.Cells(1, wsA.Columns.Count).End(xlToLeft).Column\n\n    wsR.Range(\"A1\").Value = \"儲存格位址\"\n    wsR.Range(\"B1\").Value = \"欄位/列說明\"\n    wsR.Range(\"C1\").Value = sheetA & \" 值\"\n    wsR.Range(\"D1\").Value = sheetB & \" 值\"\n    wsR.Range(\"E1\").Value = \"差異百分比\"\n    wsR.Range(\"F1\").Value = \"是否超出容差\"\n    With wsR.Range(\"A1:F1\")\n        .Font.Bold = True\n        .Interior.Color = RGB(255, 165, 0)\n        .Font.Color = RGB(255, 255, 255)\n    End With\n\n    rptRow = 2\n    diffCount = 0\n\n    For r = 2 To lastRow\n        For c = 2 To lastCol\n            isNumA = IsNumeric(wsA.Cells(r, c).Value)\n            isNumB = IsNumeric(wsB.Cells(r, c).Value)\n            If isNumA And isNumB Then\n                valA = CDbl(wsA.Cells(r, c).Value)\n                valB = CDbl(wsB.Cells(r, c).Value)\n                If valA <> 0 Then\n                    diffPct = Abs((valB - valA) / valA)\n                ElseIf valB <> 0 Then\n                    diffPct = 1\n                Else\n                    diffPct = 0\n                End If\n                wsR.Cells(rptRow, 1).Value = wsA.Cells(r, c).Address(False, False)\n                wsR.Cells(rptRow, 2).Value = CStr(wsA.Cells(1, c).Value) & \" / \" & CStr(wsA.Cells(r, 1).Value)\n                wsR.Cells(rptRow, 3).Value = valA\n                wsR.Cells(rptRow, 4).Value = valB\n                wsR.Cells(rptRow, 5).Value = Format(diffPct, \"0.00%\")\n                If diffPct > tolerancePct Then\n                    wsR.Cells(rptRow, 6).Value = \"超出\"\n                    wsR.Cells(rptRow, 1).Resize(1, 6).Interior.Color = RGB(255, 199, 206)\n                    diffCount = diffCount + 1\n                Else\n                    wsR.Cells(rptRow, 6).Value = \"正常\"\n                End If\n                rptRow = rptRow + 1\n            End If\n        Next c\n    Next r\n\n    wsR.Columns(\"A:F\").AutoFit\n    wsR.Activate\n    MsgBox \"容差比對完成！\" & vbCrLf & _\n           \"容差設定: \" & Format(tolerancePct, \"0%\") & vbCrLf & _\n           \"超出容差: \" & diffCount & \" 筆\", vbInformation, \"比對結果\"\n    Exit Sub\n\nErrHandler:\n    MsgBox \"發生錯誤: \" & Err.Description, vbCritical, \"錯誤\"\nEnd Sub\n\nPrivate Function GetOrCreateSheetCWT(ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = ThisWorkbook.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = ThisWorkbook.Worksheets.Add\n        ws.Name = sheetName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreateSheetCWT = ws\nEnd Function\n", "content_b64": ""}, {"name": "GenerateDiffSummary.bas", "path": "模組/AutomaticallyCompareDataDifferences/GenerateDiffSummary.bas", "content": "Attribute VB_Name = \"GenerateDiffSummary\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: GenerateDiffSummary\n'功能說明: 比對兩張工作表並產生差異統計摘要，包含各欄差異數量、\n'          差異比率、最大差異值等統計指標\n'\n'著作權所有: Dunk\n'程式設計: Dunk\n'撰寫日期: 2026/5/9\n'\n'*************************************************************************************\n\n' 測試用入口\nSub TestGenerateDiffSummary()\n    Call CreateSummaryData\n    Call GenerateDiffSummary(\"月報A版\", \"月報B版\", \"差異統計摘要\")\nEnd Sub\n\n' 建立統計摘要範例資料\nPrivate Sub CreateSummaryData()\n    Dim wsA As Worksheet\n    Dim wsB As Worksheet\n\n    Set wsA = GetOrCreateSheetGDS(\"月報A版\")\n    Set wsB = GetOrCreateSheetGDS(\"月報B版\")\n\n    wsA.Range(\"A1\").Value = \"產品\"  : wsA.Range(\"B1\").Value = \"一月\" : wsA.Range(\"C1\").Value = \"二月\" : wsA.Range(\"D1\").Value = \"三月\"\n    wsA.Range(\"A2\").Value = \"產品A\" : wsA.Range(\"B2\").Value = 100 : wsA.Range(\"C2\").Value = 200 : wsA.Range(\"D2\").Value = 150\n    wsA.Range(\"A3\").Value = \"產品B\" : wsA.Range(\"B3\").Value = 300 : wsA.Range(\"C3\").Value = 280 : wsA.Range(\"D3\").Value = 310\n    wsA.Range(\"A4\").Value = \"產品C\" : wsA.Range(\"B4\").Value = 50  : wsA.Range(\"C4\").Value = 60  : wsA.Range(\"D4\").Value = 55\n    wsA.Range(\"A5\").Value = \"產品D\" : wsA.Range(\"B5\").Value = 400 : wsA.Range(\"C5\").Value = 420 : wsA.Range(\"D5\").Value = 390\n    wsA.Columns(\"A:D\").AutoFit\n\n    wsB.Range(\"A1\").Value = \"產品\"  : wsB.Range(\"B1\").Value = \"一月\" : wsB.Range(\"C1\").Value = \"二月\" : wsB.Range(\"D1\").Value = \"三月\"\n    wsB.Range(\"A2\").Value = \"產品A\" : wsB.Range(\"B2\").Value = 105 : wsB.Range(\"C2\").Value = 200 : wsB.Range(\"D2\").Value = 160\n    wsB.Range(\"A3\").Value = \"產品B\" : wsB.Range(\"B3\").Value = 300 : wsB.Range(\"C3\").Value = 295 : wsB.Range(\"D3\").Value = 310\n    wsB.Range(\"A4\").Value = \"產品C\" : wsB.Range(\"B4\").Value = 48  : wsB.Range(\"C4\").Value = 60  : wsB.Range(\"D4\").Value = 55\n    wsB.Range(\"A5\").Value = \"產品D\" : wsB.Range(\"B5\").Value = 400 : wsB.Range(\"C5\").Value = 420 : wsB.Range(\"D5\").Value = 400\n    wsB.Columns(\"A:D\").AutoFit\nEnd Sub\n\n' 產生差異統計摘要報表\nPublic Sub GenerateDiffSummary(ByVal sheetA As String, ByVal sheetB As String, _\n                                ByVal reportSheet As String)\n    Dim wsA          As Worksheet\n    Dim wsB          As Worksheet\n    Dim wsR          As Worksheet\n    Dim lastRow      As Long\n    Dim lastCol      As Long\n    Dim r            As Long\n    Dim c            As Long\n    Dim rptRow       As Long\n    Dim valA         As Double\n    Dim valB         As Double\n    Dim colDiffCount As Long\n    Dim totalDiff    As Long\n    Dim maxDiff      As Double\n    Dim curDiff      As Double\n    Dim colHeader    As String\n\n    On Error GoTo ErrHandler\n\n    Set wsA = ThisWorkbook.Worksheets(sheetA)\n    Set wsB = ThisWorkbook.Worksheets(sheetB)\n    Set wsR = GetOrCreateSheetGDS(reportSheet)\n\n    lastRow = wsA.Cells(wsA.Rows.Count, 1).End(xlUp).Row\n    lastCol = wsA.Cells(1, wsA.Columns.Count).End(xlToLeft).Column\n\n    ' 報表標頭\n    wsR.Range(\"A1\").Value = \"差異統計摘要報表\"\n    With wsR.Range(\"A1\")\n        .Font.Bold = True\n        .Font.Size = 14\n    End With\n    wsR.Range(\"A2\").Value = \"比對來源: \" & sheetA & \" vs \" & sheetB\n    wsR.Range(\"A3\").Value = \"產生日期: \" & Format(Now, \"yyyy/mm/dd hh:mm:ss\")\n\n    wsR.Range(\"A5\").Value = \"欄位名稱\"\n    wsR.Range(\"B5\").Value = \"差異筆數\"\n    wsR.Range(\"C5\").Value = \"差異比率\"\n    wsR.Range(\"D5\").Value = \"最大差異值\"\n    wsR.Range(\"E5\").Value = \"差異方向\"\n    With wsR.Range(\"A5:E5\")\n        .Font.Bold = True\n        .Interior.Color = RGB(47, 117, 181)\n        .Font.Color = RGB(255, 255, 255)\n    End With\n\n    rptRow = 6\n    totalDiff = 0\n\n    For c = 2 To lastCol\n        colHeader = CStr(wsA.Cells(1, c).Value)\n        colDiffCount = 0\n        maxDiff = 0\n\n        For r = 2 To lastRow\n            If IsNumeric(wsA.Cells(r, c).Value) And IsNumeric(wsB.Cells(r, c).Value) Then\n                valA = CDbl(wsA.Cells(r, c).Value)\n                valB = CDbl(wsB.Cells(r, c).Value)\n                If valA <> valB Then\n                    colDiffCount = colDiffCount + 1\n                    curDiff = Abs(valB - valA)\n                    If curDiff > maxDiff Then maxDiff = curDiff\n                End If\n            ElseIf CStr(wsA.Cells(r, c).Value) <> CStr(wsB.Cells(r, c).Value) Then\n                colDiffCount = colDiffCount + 1\n            End If\n        Next r\n\n        wsR.Cells(rptRow, 1).Value = colHeader\n        wsR.Cells(rptRow, 2).Value = colDiffCount\n        wsR.Cells(rptRow, 3).Value = Format(colDiffCount / (lastRow - 1), \"0.0%\")\n        If maxDiff > 0 Then\n            wsR.Cells(rptRow, 4).Value = maxDiff\n            wsR.Cells(rptRow, 5).Value = \"數值差異\"\n        Else\n            wsR.Cells(rptRow, 4).Value = \"-\"\n            If colDiffCount > 0 Then\n                wsR.Cells(rptRow, 5).Value = \"文字差異\"\n            Else\n                wsR.Cells(rptRow, 5).Value = \"無差異\"\n            End If\n        End If\n        If colDiffCount > 0 Then\n            wsR.Cells(rptRow, 1).Resize(1, 5).Interior.Color = RGB(255, 235, 156)\n        End If\n        totalDiff = totalDiff + colDiffCount\n        rptRow = rptRow + 1\n    Next c\n\n    ' 總計列\n    wsR.Cells(rptRow, 1).Value = \"合計\"\n    wsR.Cells(rptRow, 2).Value = totalDiff\n    With wsR.Cells(rptRow, 1).Resize(1, 5)\n        .Font.Bold = True\n        .Interior.Color = RGB(155, 194, 230)\n    End With\n\n    wsR.Columns(\"A:E\").AutoFit\n    wsR.Activate\n    MsgBox \"差異統計摘要產生完成！總差異筆數: \" & totalDiff, vbInformation, \"統計結果\"\n    Exit Sub\n\nErrHandler:\n    MsgBox \"發生錯誤: \" & Err.Description, vbCritical, \"錯誤\"\nEnd Sub\n\nPrivate Function GetOrCreateSheetGDS(ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = ThisWorkbook.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = ThisWorkbook.Worksheets.Add\n        ws.Name = sheetName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreateSheetGDS = ws\nEnd Function\n", "content_b64": ""}, {"name": "HighlightDifferences.bas", "path": "模組/AutomaticallyCompareDataDifferences/HighlightDifferences.bas", "content": "Attribute VB_Name = \"HighlightDifferences\"\nOption Explicit\n\n' ============================================================\n' 範例：比較兩個工作表的相同位置資料，並以顏色標示差異儲存格\n' 功能：在第二個工作表中，將與第一個工作表不同的儲存格標為黃色\n' ============================================================\nSub HighlightSheetDifferences()\n    Dim ws1         As Worksheet\n    Dim ws2         As Worksheet\n    Dim strName1    As String\n    Dim strName2    As String\n    Dim lngRow      As Long\n    Dim lngCol      As Long\n    Dim lngMaxRow   As Long\n    Dim lngMaxCol   As Long\n    Dim intDiffCnt  As Integer\n    Dim strLeftValue As String\n    Dim strRightValue As String\n\n    On Error GoTo ErrHandler\n\n    ' --- 詢問工作表名稱 ---\n    strName1 = InputBox(\"請輸入第一個工作表名稱（基準）：\", \"比較工作表\", \"Sheet1\")\n    If strName1 = \"\" Then Exit Sub\n\n    strName2 = InputBox(\"請輸入第二個工作表名稱（比較對象）：\", \"比較工作表\", \"Sheet2\")\n    If strName2 = \"\" Then Exit Sub\n\n    Set ws1 = ThisWorkbook.Worksheets(strName1)\n    Set ws2 = ThisWorkbook.Worksheets(strName2)\n\n    ' --- 決定比較範圍 ---\n    lngMaxRow = Application.WorksheetFunction.Max( _\n        ws1.Cells(ws1.Rows.Count, 1).End(xlUp).Row, _\n        ws2.Cells(ws2.Rows.Count, 1).End(xlUp).Row)\n    lngMaxCol = Application.WorksheetFunction.Max( _\n        ws1.Cells(1, ws1.Columns.Count).End(xlToLeft).Column, _\n        ws2.Cells(1, ws2.Columns.Count).End(xlToLeft).Column)\n\n    ' --- 清除第二個工作表既有標色 ---\n    ws2.Cells.Interior.ColorIndex = xlNone\n\n    Application.ScreenUpdating = False\n    intDiffCnt = 0\n\n    ' --- 逐格比較並標色 ---\n    For lngRow = 1 To lngMaxRow\n        For lngCol = 1 To lngMaxCol\n            strLeftValue = CStr(ws1.Cells(lngRow, lngCol).Value)\n            strRightValue = CStr(ws2.Cells(lngRow, lngCol).Value)\n            If strLeftValue <> strRightValue Then\n                ws2.Cells(lngRow, lngCol).Interior.Color = RGB(255, 255, 0)\n                intDiffCnt = intDiffCnt + 1\n            End If\n        Next lngCol\n    Next lngRow\n\n    Application.ScreenUpdating = True\n    MsgBox \"比較完成，共發現 \" & intDiffCnt & \" 個差異儲存格（已在「\" & _\n        strName2 & \"」工作表中以黃色標示）。\", vbInformation\n    Exit Sub\n\nErrHandler:\n    Application.ScreenUpdating = True\n    MsgBox \"發生錯誤：\" & Err.Description, vbCritical\nEnd Sub\n", "content_b64": ""}, {"name": "ReconcileTwoLists.bas", "path": "模組/AutomaticallyCompareDataDifferences/ReconcileTwoLists.bas", "content": "Option Explicit\n\n' 比對兩份清單的鍵值，標示只存在於左表或右表的資料。\nPublic Sub ReconcileTwoListsExample()\n    On Error GoTo ErrHandler\n\n    Dim ws As Worksheet\n\n    Set ws = GetOrCreateReconcileWorksheet(\"雙清單比對範例\")\n    ws.Cells.Clear\n    Call FillReconcileData(ws)\n    Call ReconcileTwoLists(ws)\n\n    ws.Columns(\"A:G\").AutoFit\n    MsgBox \"雙清單比對完成。\", vbInformation, \"完成\"\n    Exit Sub\n\nErrHandler:\n    MsgBox \"比對清單失敗：\" & Err.Description, vbExclamation, \"錯誤\"\nEnd Sub\n\nPrivate Sub ReconcileTwoLists(ByVal ws As Worksheet)\n    Dim leftLastRow As Long\n    Dim rightLastRow As Long\n    Dim resultRow As Long\n    Dim rowIndex As Long\n    Dim foundCell As Range\n\n    leftLastRow = ws.Cells(ws.Rows.Count, \"A\").End(xlUp).Row\n    rightLastRow = ws.Cells(ws.Rows.Count, \"D\").End(xlUp).Row\n    ws.Range(\"G1\").Value = \"差異說明\"\n    resultRow = 2\n\n    For rowIndex = 2 To leftLastRow\n        Set foundCell = ws.Range(\"D2:D\" & rightLastRow).Find(What:=ws.Cells(rowIndex, \"A\").Value, LookIn:=xlValues, LookAt:=xlWhole)\n        If foundCell Is Nothing Then\n            ws.Cells(resultRow, \"G\").Value = \"左表有，右表沒有：\" & ws.Cells(rowIndex, \"A\").Value\n            resultRow = resultRow + 1\n        End If\n    Next rowIndex\n\n    For rowIndex = 2 To rightLastRow\n        Set foundCell = ws.Range(\"A2:A\" & leftLastRow).Find(What:=ws.Cells(rowIndex, \"D\").Value, LookIn:=xlValues, LookAt:=xlWhole)\n        If foundCell Is Nothing Then\n            ws.Cells(resultRow, \"G\").Value = \"右表有，左表沒有：\" & ws.Cells(rowIndex, \"D\").Value\n            resultRow = resultRow + 1\n        End If\n    Next rowIndex\nEnd Sub\n\nPrivate Sub FillReconcileData(ByVal ws As Worksheet)\n    ws.Range(\"A1:B1\").Value = Array(\"左表編號\", \"左表金額\")\n    ws.Range(\"A2:B2\").Value = Array(\"A001\", 1200)\n    ws.Range(\"A3:B3\").Value = Array(\"A002\", 1800)\n    ws.Range(\"A4:B4\").Value = Array(\"A003\", 1500)\n    ws.Range(\"A5:B5\").Value = Array(\"A004\", 2100)\n    ws.Range(\"D1:E1\").Value = Array(\"右表編號\", \"右表金額\")\n    ws.Range(\"D2:E2\").Value = Array(\"A001\", 1200)\n    ws.Range(\"D3:E3\").Value = Array(\"A003\", 1500)\n    ws.Range(\"D4:E4\").Value = Array(\"A004\", 2100)\n    ws.Range(\"D5:E5\").Value = Array(\"A005\", 990)\nEnd Sub\n\nPrivate Function GetOrCreateReconcileWorksheet(ByVal sheetName As String) As Worksheet\n    On Error Resume Next\n    Set GetOrCreateReconcileWorksheet = ThisWorkbook.Worksheets(sheetName)\n    On Error GoTo 0\n\n    If GetOrCreateReconcileWorksheet Is Nothing Then\n        Set GetOrCreateReconcileWorksheet = ThisWorkbook.Worksheets.Add\n        GetOrCreateReconcileWorksheet.Name = sheetName\n    End If\nEnd Function", "content_b64": ""}, {"name": "TrackDataChanges.bas", "path": "模組/AutomaticallyCompareDataDifferences/TrackDataChanges.bas", "content": "Attribute VB_Name = \"TrackDataChanges\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: TrackDataChanges\n'功能說明: 比對兩版資料，將差異記錄至變更歷程工作表，\n'          包含變更時間、變更前後值、變更類型\n'\n'著作權所有: Dunk\n'程式設計: Dunk\n'撰寫日期: 2026/5/9\n'\n'*************************************************************************************\n\n' 測試用入口\nSub TestTrackDataChanges()\n    Call CreateTrackData\n    Call TrackDataChanges(\"v1.0資料\", \"v2.0資料\", \"變更歷程\", 1, 1)\nEnd Sub\n\n' 建立版本追蹤範例資料\nPrivate Sub CreateTrackData()\n    Dim wsV1 As Worksheet\n    Dim wsV2 As Worksheet\n\n    Set wsV1 = GetOrCreateSheetTDC(\"v1.0資料\")\n    Set wsV2 = GetOrCreateSheetTDC(\"v2.0資料\")\n\n    wsV1.Range(\"A1\").Value = \"客戶編號\"\n    wsV1.Range(\"B1\").Value = \"公司名稱\"\n    wsV1.Range(\"C1\").Value = \"聯絡人\"\n    wsV1.Range(\"D1\").Value = \"信用等級\"\n    wsV1.Range(\"A2\").Value = \"C001\" : wsV1.Range(\"B2\").Value = \"宏碁股份有限公司\"   : wsV1.Range(\"C2\").Value = \"陳小明\" : wsV1.Range(\"D2\").Value = \"A\"\n    wsV1.Range(\"A3\").Value = \"C002\" : wsV1.Range(\"B3\").Value = \"微星科技股份有限公司\" : wsV1.Range(\"C3\").Value = \"李大華\" : wsV1.Range(\"D3\").Value = \"B\"\n    wsV1.Range(\"A4\").Value = \"C003\" : wsV1.Range(\"B4\").Value = \"技嘉科技股份有限公司\" : wsV1.Range(\"C4\").Value = \"王雅惠\" : wsV1.Range(\"D4\").Value = \"A\"\n    wsV1.Columns(\"A:D\").AutoFit\n\n    wsV2.Range(\"A1\").Value = \"客戶編號\"\n    wsV2.Range(\"B1\").Value = \"公司名稱\"\n    wsV2.Range(\"C1\").Value = \"聯絡人\"\n    wsV2.Range(\"D1\").Value = \"信用等級\"\n    wsV2.Range(\"A2\").Value = \"C001\" : wsV2.Range(\"B2\").Value = \"宏碁股份有限公司\"   : wsV2.Range(\"C2\").Value = \"陳小明\" : wsV2.Range(\"D2\").Value = \"A+\"\n    wsV2.Range(\"A3\").Value = \"C002\" : wsV2.Range(\"B3\").Value = \"微星科技股份有限公司\" : wsV2.Range(\"C3\").Value = \"林淑芬\" : wsV2.Range(\"D3\").Value = \"B\"\n    wsV2.Range(\"A4\").Value = \"C003\" : wsV2.Range(\"B4\").Value = \"技嘉科技股份有限公司\" : wsV2.Range(\"C4\").Value = \"王雅惠\" : wsV2.Range(\"D4\").Value = \"A+\"\n    wsV2.Range(\"A5\").Value = \"C004\" : wsV2.Range(\"B5\").Value = \"仁寶電腦工業股份有限公司\" : wsV2.Range(\"C5\").Value = \"黃志偉\" : wsV2.Range(\"D5\").Value = \"B+\"\n    wsV2.Columns(\"A:D\").AutoFit\nEnd Sub\n\n' 追蹤並記錄兩版資料間的變更歷程\nPublic Sub TrackDataChanges(ByVal oldVersion As String, ByVal newVersion As String, _\n                             ByVal logSheet As String, ByVal keyColNum As Long, _\n                             ByVal headerRows As Long)\n    Dim wsOld      As Worksheet\n    Dim wsNew      As Worksheet\n    Dim wsLog      As Worksheet\n    Dim oldLastRow As Long\n    Dim newLastRow As Long\n    Dim lastCol    As Long\n    Dim i          As Long\n    Dim j          As Long\n    Dim c          As Long\n    Dim oldKey     As String\n    Dim newKey     As String\n    Dim foundMatch As Boolean\n    Dim logRow     As Long\n    Dim changeTime As String\n\n    On Error GoTo ErrHandler\n\n    Set wsOld = ThisWorkbook.Worksheets(oldVersion)\n    Set wsNew = ThisWorkbook.Worksheets(newVersion)\n    Set wsLog = GetOrCreateSheetTDC(logSheet)\n\n    changeTime = Format(Now, \"yyyy/mm/dd hh:mm:ss\")\n\n    oldLastRow = wsOld.Cells(wsOld.Rows.Count, keyColNum).End(xlUp).Row\n    newLastRow = wsNew.Cells(wsNew.Rows.Count, keyColNum).End(xlUp).Row\n    lastCol = wsOld.Cells(1, wsOld.Columns.Count).End(xlToLeft).Column\n\n    ' 設定歷程標頭\n    wsLog.Range(\"A1\").Value = \"記錄時間\"\n    wsLog.Range(\"B1\").Value = \"變更類型\"\n    wsLog.Range(\"C1\").Value = \"鍵值\"\n    wsLog.Range(\"D1\").Value = \"欄位名稱\"\n    wsLog.Range(\"E1\").Value = \"舊版值\"\n    wsLog.Range(\"F1\").Value = \"新版值\"\n    wsLog.Range(\"G1\").Value = \"版本對照\"\n    With wsLog.Range(\"A1:G1\")\n        .Font.Bold = True\n        .Interior.Color = RGB(31, 73, 125)\n        .Font.Color = RGB(255, 255, 255)\n    End With\n\n    logRow = 2\n\n    ' 比對舊版 vs 新版（修改 / 刪除）\n    For i = headerRows + 1 To oldLastRow\n        oldKey = CStr(wsOld.Cells(i, keyColNum).Value)\n        If oldKey <> \"\" Then\n            foundMatch = False\n            For j = headerRows + 1 To newLastRow\n                newKey = CStr(wsNew.Cells(j, keyColNum).Value)\n                If oldKey = newKey Then\n                    foundMatch = True\n                    For c = 1 To lastCol\n                        If CStr(wsOld.Cells(i, c).Value) <> CStr(wsNew.Cells(j, c).Value) Then\n                            wsLog.Cells(logRow, 1).Value = changeTime\n                            wsLog.Cells(logRow, 2).Value = \"修改\"\n                            wsLog.Cells(logRow, 3).Value = oldKey\n                            wsLog.Cells(logRow, 4).Value = CStr(wsOld.Cells(1, c).Value)\n                            wsLog.Cells(logRow, 5).Value = CStr(wsOld.Cells(i, c).Value)\n                            wsLog.Cells(logRow, 6).Value = CStr(wsNew.Cells(j, c).Value)\n                            wsLog.Cells(logRow, 7).Value = oldVersion & \" -> \" & newVersion\n                            wsLog.Cells(logRow, 2).Interior.Color = RGB(255, 255, 153)\n                            logRow = logRow + 1\n                        End If\n                    Next c\n                    Exit For\n                End If\n            Next j\n            If Not foundMatch Then\n                wsLog.Cells(logRow, 1).Value = changeTime\n                wsLog.Cells(logRow, 2).Value = \"刪除\"\n                wsLog.Cells(logRow, 3).Value = oldKey\n                wsLog.Cells(logRow, 4).Value = \"(整筆記錄)\"\n                wsLog.Cells(logRow, 5).Value = \"(存在)\"\n                wsLog.Cells(logRow, 6).Value = \"(已刪除)\"\n                wsLog.Cells(logRow, 7).Value = oldVersion & \" -> \" & newVersion\n                wsLog.Cells(logRow, 2).Interior.Color = RGB(255, 199, 206)\n                logRow = logRow + 1\n            End If\n        End If\n    Next i\n\n    ' 找出新增記錄\n    For j = headerRows + 1 To newLastRow\n        newKey = CStr(wsNew.Cells(j, keyColNum).Value)\n        If newKey <> \"\" Then\n            foundMatch = False\n            For i = headerRows + 1 To oldLastRow\n                If newKey = CStr(wsOld.Cells(i, keyColNum).Value) Then\n                    foundMatch = True\n                    Exit For\n                End If\n            Next i\n            If Not foundMatch Then\n                wsLog.Cells(logRow, 1).Value = changeTime\n                wsLog.Cells(logRow, 2).Value = \"新增\"\n                wsLog.Cells(logRow, 3).Value = newKey\n                wsLog.Cells(logRow, 4).Value = \"(整筆記錄)\"\n                wsLog.Cells(logRow, 5).Value = \"(不存在)\"\n                wsLog.Cells(logRow, 6).Value = \"(已新增)\"\n                wsLog.Cells(logRow, 7).Value = oldVersion & \" -> \" & newVersion\n                wsLog.Cells(logRow, 2).Interior.Color = RGB(198, 239, 206)\n                logRow = logRow + 1\n            End If\n        End If\n    Next j\n\n    wsLog.Columns(\"A:G\").AutoFit\n    wsLog.Activate\n    MsgBox \"變更歷程記錄完成！共記錄 \" & (logRow - 2) & \" 筆變更。\", vbInformation, \"追蹤結果\"\n    Exit Sub\n\nErrHandler:\n    MsgBox \"發生錯誤: \" & Err.Description, vbCritical, \"錯誤\"\nEnd Sub\n\nPrivate Function GetOrCreateSheetTDC(ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = ThisWorkbook.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = ThisWorkbook.Worksheets.Add\n        ws.Name = sheetName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreateSheetTDC = ws\nEnd Function\n", "content_b64": ""}]}, {"folder": "BatchEnterFormulas", "path": "模組/BatchEnterFormulas", "files": [{"name": "BatchAverageFormulas.bas", "path": "模組/BatchEnterFormulas/BatchAverageFormulas.bas", "content": "Attribute VB_Name = \"BatchAverageFormulas\"\n\nOption Explicit\n\n\n\n' ============================================================\n\n' 範例：批次在每列的最後一欄插入 AVERAGE 平均值公式\n\n' 功能：自動偵測資料範圍，在每列末尾插入平均公式\n\n' ============================================================\n\nSub BatchInsertAverageFormulas()\n\n    Dim ws          As Worksheet\n\n    Dim lngLastRow  As Long\n\n    Dim lngLastCol  As Long\n\n    Dim lngRow      As Long\n\n    Dim strColLetter As String\n\n\n\n    On Error GoTo ErrHandler\n\n    Set ws = ActiveSheet\n\n\n\n    lngLastRow = ws.Cells(ws.Rows.Count, 1).End(xlUp).Row\n\n    lngLastCol = ws.Cells(1, ws.Columns.Count).End(xlToLeft).Column\n\n\n\n    If lngLastRow < 2 Or lngLastCol < 2 Then\n\n        MsgBox \"資料不足，請確認工作表至少有兩列兩欄資料。\", vbExclamation\n\n        Exit Sub\n\n    End If\n\n\n\n    ' --- 在每列資料末欄+1插入 AVERAGE 公式 ---\n\n    strColLetter = Split(ws.Cells(1, lngLastCol + 1).Address, \"$\")(1)\n\n\n\n    ' 第一列寫標題\n\n    ws.Cells(1, lngLastCol + 1).Value = \"平均值\"\n\n\n\n    Application.ScreenUpdating = False\n\n    For lngRow = 2 To lngLastRow\n\n        Dim strStartCell As String\n\n        Dim strEndCell   As String\n\n        strStartCell = ws.Cells(lngRow, 2).Address(False, False)\n\n        strEndCell = ws.Cells(lngRow, lngLastCol).Address(False, False)\n\n        ws.Cells(lngRow, lngLastCol + 1).Formula = _\n\n            \"=AVERAGE(\" & strStartCell & \":\" & strEndCell & \")\"\n\n    Next lngRow\n\n    Application.ScreenUpdating = True\n\n\n\n    MsgBox \"已在第 \" & lngLastCol + 1 & \" 欄批次插入 AVERAGE 公式，共 \" & _\n\n        lngLastRow - 1 & \" 列。\", vbInformation\n\n    Exit Sub\n\n\n\nErrHandler:\n\n    Application.ScreenUpdating = True\n\n    MsgBox \"發生錯誤：\" & Err.Description, vbCritical\n\nEnd Sub\n\n", "content_b64": ""}, {"name": "BatchCountFormulas.bas", "path": "模組/BatchEnterFormulas/BatchCountFormulas.bas", "content": "Attribute VB_Name = \"BatchCountFormulas\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: BatchCountFormulas\n'功能說明: 批次在多欄工作表中自動填入 COUNT、COUNTA、COUNTIF、COUNTIFS 統計公式\n'\n'作者版權: Dunk\n'原始設計: Dunk\n'撰寫日期: 2026/5/9\n'\n'*************************************************************************************\n\n' 測試用入口\nSub TestBatchCountFormulas()\n    Call CreateCountFormulaExample\nEnd Sub\n\n' 建立計數公式批次填入示範\nSub CreateCountFormulaExample()\n    Dim ws As Worksheet\n    On Error GoTo ErrHandler\n\n    Set ws = GetOrCreateSheet(ThisWorkbook, \"計數公式示範\")\n    Call FillStudentScoreData(ws)\n    Call BatchEnterCountFormulas(ws)\n\n    ws.Columns(\"A:H\").AutoFit\n    ws.Activate\n    MsgBox \"計數公式已批次填入完成！\", vbInformation, \"完成\"\n    Exit Sub\n\nErrHandler:\n    MsgBox \"發生錯誤：\" & Err.Description, vbCritical, \"錯誤\"\nEnd Sub\n\n' 批次填入 COUNT / COUNTA / COUNTIF / COUNTIFS 公式\nPrivate Sub BatchEnterCountFormulas(ByVal ws As Worksheet)\n    Dim i As Integer\n\n    ' 科目欄位：B~E (4科)\n    For i = 2 To 5\n        ' COUNT：計算數值筆數\n        ws.Cells(12, i).Formula = \"=COUNT(\" & _\n            ws.Cells(2, i).Address(False, False) & \":\" & _\n            ws.Cells(11, i).Address(False, False) & \")\"\n        ' COUNTA：含文字計算非空筆數\n        ws.Cells(13, i).Formula = \"=COUNTA(\" & _\n            ws.Cells(2, i).Address(False, False) & \":\" & _\n            ws.Cells(11, i).Address(False, False) & \")\"\n        ' COUNTIF：計算 >= 60 (及格人數)\n        ws.Cells(14, i).Formula = \"=COUNTIF(\" & _\n            ws.Cells(2, i).Address(False, False) & \":\" & _\n            ws.Cells(11, i).Address(False, False) & \",\"\">=60\"\")\"\n        ' COUNTIF：計算 < 60 (不及格人數)\n        ws.Cells(15, i).Formula = \"=COUNTIF(\" & _\n            ws.Cells(2, i).Address(False, False) & \":\" & _\n            ws.Cells(11, i).Address(False, False) & \",\"\"<60\"\")\"\n    Next i\n\n    ' 標籤\n    ws.Range(\"A12\").Value = \"數值筆數(COUNT)\"\n    ws.Range(\"A13\").Value = \"非空筆數(COUNTA)\"\n    ws.Range(\"A14\").Value = \"及格人數(>=60)\"\n    ws.Range(\"A15\").Value = \"不及格人數(<60)\"\n    ws.Range(\"A12:A15\").Font.Bold = True\n    ws.Range(\"B12:E15\").Font.Bold = True\nEnd Sub\n\n' 填入學生成績示範資料\nPrivate Sub FillStudentScoreData(ByVal ws As Worksheet)\n    Dim i As Integer\n    Dim names(1 To 10) As String\n    Dim scores(1 To 10, 1 To 4) As Variant\n\n    names(1) = \"王小明\" : names(2) = \"李美玲\" : names(3) = \"陳大偉\" : names(4) = \"林志豪\"\n    names(5) = \"張雅惠\" : names(6) = \"黃建宏\" : names(7) = \"蔡佳慧\" : names(8) = \"吳宗翰\"\n    names(9) = \"鄭麗娟\" : names(10) = \"許志遠\"\n\n    scores(1, 1) = 85 : scores(1, 2) = 72 : scores(1, 3) = 91 : scores(1, 4) = 68\n    scores(2, 1) = 90 : scores(2, 2) = 88 : scores(2, 3) = 75 : scores(2, 4) = 82\n    scores(3, 1) = 55 : scores(3, 2) = 61 : scores(3, 3) = 48 : scores(3, 4) = 70\n    scores(4, 1) = 78 : scores(4, 2) = 83 : scores(4, 3) = 89 : scores(4, 4) = 77\n    scores(5, 1) = 45 : scores(5, 2) = 52 : scores(5, 3) = 60 : scores(5, 4) = 55\n    scores(6, 1) = 92 : scores(6, 2) = 95 : scores(6, 3) = 88 : scores(6, 4) = 90\n    scores(7, 1) = 67 : scores(7, 2) = 74 : scores(7, 3) = 70 : scores(7, 4) = 63\n    scores(8, 1) = 38 : scores(8, 2) = 42 : scores(8, 3) = 50 : scores(8, 4) = 45\n    scores(9, 1) = 80 : scores(9, 2) = 78 : scores(9, 3) = 82 : scores(9, 4) = 85\n    scores(10, 1) = 73 : scores(10, 2) = 69 : scores(10, 3) = 76 : scores(10, 4) = 71\n\n    ws.Range(\"A1\").Value = \"姓名\"\n    ws.Range(\"B1\").Value = \"國文\"\n    ws.Range(\"C1\").Value = \"英文\"\n    ws.Range(\"D1\").Value = \"數學\"\n    ws.Range(\"E1\").Value = \"自然\"\n    ws.Range(\"A1:E1\").Font.Bold = True\n\n    For i = 1 To 10\n        ws.Cells(i + 1, 1).Value = names(i)\n        ws.Cells(i + 1, 2).Value = scores(i, 1)\n        ws.Cells(i + 1, 3).Value = scores(i, 2)\n        ws.Cells(i + 1, 4).Value = scores(i, 3)\n        ws.Cells(i + 1, 5).Value = scores(i, 4)\n    Next i\nEnd Sub\n\n' 取得或建立工作表，並清除內容\nPrivate Function GetOrCreateSheet(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add\n        ws.Name = sheetName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreateSheet = ws\nEnd Function", "content_b64": ""}, {"name": "BatchDateFormulas.bas", "path": "模組/BatchEnterFormulas/BatchDateFormulas.bas", "content": "Attribute VB_Name = \"BatchDateFormulas\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: BatchDateFormulas\n'功能說明: 批次填入日期公式，包含 YEAR、MONTH、DAY、DATEDIF、EDATE、EOMONTH\n'\n'作者版權: Dunk\n'原始設計: Dunk\n'撰寫日期: 2026/5/9\n'\n'*************************************************************************************\n\n' 測試用入口\nSub TestBatchDateFormulas()\n    Call CreateDateFormulaExample\nEnd Sub\n\n' 建立日期公式批次填入示範\nSub CreateDateFormulaExample()\n    Dim ws As Worksheet\n    On Error GoTo ErrHandler\n\n    Set ws = GetOrCreateDateSheet(ThisWorkbook, \"日期公式示範\")\n    Call FillEmployeeHireDates(ws)\n    Call BatchEnterDateExtractFormulas(ws)\n    Call BatchEnterDateCalcFormulas(ws)\n\n    ws.Columns(\"A:J\").AutoFit\n    ws.Activate\n    MsgBox \"日期公式已批次填入完成！\", vbInformation, \"完成\"\n    Exit Sub\n\nErrHandler:\n    MsgBox \"發生錯誤：\" & Err.Description, vbCritical, \"錯誤\"\nEnd Sub\n\n' 批次填入 YEAR / MONTH / DAY 拆解公式\nPrivate Sub BatchEnterDateExtractFormulas(ByVal ws As Worksheet)\n    Dim i As Integer\n    Dim lastRow As Long\n    lastRow = ws.Cells(ws.Rows.Count, \"A\").End(xlUp).Row\n\n    ws.Range(\"C1\").Value = \"年份(YEAR)\"\n    ws.Range(\"D1\").Value = \"月份(MONTH)\"\n    ws.Range(\"E1\").Value = \"日期(DAY)\"\n    ws.Range(\"C1:E1\").Font.Bold = True\n\n    For i = 2 To lastRow\n        ws.Cells(i, 3).Formula = \"=YEAR(B\" & i & \")\"\n        ws.Cells(i, 4).Formula = \"=MONTH(B\" & i & \")\"\n        ws.Cells(i, 5).Formula = \"=DAY(B\" & i & \")\"\n    Next i\nEnd Sub\n\n' 批次填入 DATEDIF / EDATE / EOMONTH 計算公式\nPrivate Sub BatchEnterDateCalcFormulas(ByVal ws As Worksheet)\n    Dim i As Integer\n    Dim lastRow As Long\n    lastRow = ws.Cells(ws.Rows.Count, \"A\").End(xlUp).Row\n\n    ws.Range(\"F1\").Value = \"年資(年)\"\n    ws.Range(\"G1\").Value = \"年資(月)\"\n    ws.Range(\"H1\").Value = \"到職6個月日\"\n    ws.Range(\"I1\").Value = \"當月最後一天\"\n    ws.Range(\"J1\").Value = \"試用期結束(90天)\"\n    ws.Range(\"F1:J1\").Font.Bold = True\n\n    For i = 2 To lastRow\n        ' DATEDIF 計算年資（年/月）\n        ws.Cells(i, 6).Formula = \"=DATEDIF(B\" & i & \",TODAY(),\"\"Y\"\")\"\n        ws.Cells(i, 7).Formula = \"=DATEDIF(B\" & i & \",TODAY(),\"\"M\"\")\"\n        ' EDATE：到職後6個月\n        ws.Cells(i, 8).Formula = \"=EDATE(B\" & i & \",6)\"\n        ws.Cells(i, 8).NumberFormat = \"yyyy/mm/dd\"\n        ' EOMONTH：到職月份最後一天\n        ws.Cells(i, 9).Formula = \"=EOMONTH(B\" & i & \",0)\"\n        ws.Cells(i, 9).NumberFormat = \"yyyy/mm/dd\"\n        ' 到職日 + 90 天\n        ws.Cells(i, 10).Formula = \"=B\" & i & \"+90\"\n        ws.Cells(i, 10).NumberFormat = \"yyyy/mm/dd\"\n    Next i\nEnd Sub\n\n' 填入員工到職日資料\nPrivate Sub FillEmployeeHireDates(ByVal ws As Worksheet)\n    Dim i As Integer\n    Dim names(1 To 8) As String\n    Dim hireDates(1 To 8) As Date\n\n    names(1) = \"王小明\" : hireDates(1) = CDate(\"2020/03/15\")\n    names(2) = \"李美玲\" : hireDates(2) = CDate(\"2019/07/01\")\n    names(3) = \"陳大偉\" : hireDates(3) = CDate(\"2022/11/20\")\n    names(4) = \"林志豪\" : hireDates(4) = CDate(\"2018/01/10\")\n    names(5) = \"張雅惠\" : hireDates(5) = CDate(\"2023/04/05\")\n    names(6) = \"黃建宏\" : hireDates(6) = CDate(\"2021/09/30\")\n    names(7) = \"蔡佳慧\" : hireDates(7) = CDate(\"2024/02/14\")\n    names(8) = \"吳宗翰\" : hireDates(8) = CDate(\"2017/06/25\")\n\n    ws.Range(\"A1\").Value = \"員工姓名\"\n    ws.Range(\"B1\").Value = \"到職日期\"\n    ws.Range(\"A1:B1\").Font.Bold = True\n\n    For i = 1 To 8\n        ws.Cells(i + 1, 1).Value = names(i)\n        ws.Cells(i + 1, 2).Value = hireDates(i)\n        ws.Cells(i + 1, 2).NumberFormat = \"yyyy/mm/dd\"\n    Next i\nEnd Sub\n\n' 取得或建立工作表，並清除內容\nPrivate Function GetOrCreateDateSheet(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add\n        ws.Name = sheetName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreateDateSheet = ws\nEnd Function", "content_b64": ""}, {"name": "BatchFinancialFormulas.bas", "path": "模組/BatchEnterFormulas/BatchFinancialFormulas.bas", "content": "Attribute VB_Name = \"BatchFinancialFormulas\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: BatchFinancialFormulas\n'功能說明: 批次填入財務公式，包含 PMT 月繳、PV 現值、FV 終值、NPV 淨現值\n'\n'作者版權: Dunk\n'原始設計: Dunk\n'撰寫日期: 2026/5/9\n'\n'*************************************************************************************\n\n' 測試用入口\nSub TestBatchFinancialFormulas()\n    Call CreateFinancialFormulaExample\nEnd Sub\n\n' 建立財務公式批次填入示範\nSub CreateFinancialFormulaExample()\n    Dim ws As Worksheet\n    On Error GoTo ErrHandler\n\n    Set ws = GetOrCreateFinSheet(ThisWorkbook, \"財務公式示範\")\n    Call BuildLoanPMTTable(ws)\n    Call BuildPVFVTable(ws)\n\n    ws.Columns(\"A:H\").AutoFit\n    ws.Activate\n    MsgBox \"財務公式已批次填入完成！\", vbInformation, \"完成\"\n    Exit Sub\n\nErrHandler:\n    MsgBox \"發生錯誤：\" & Err.Description, vbCritical, \"錯誤\"\nEnd Sub\n\n' 建立貸款月繳金額 (PMT) 計算表\nPrivate Sub BuildLoanPMTTable(ByVal ws As Worksheet)\n    ' 標題區\n    ws.Range(\"A1\").Value = \"=== 貸款月繳試算 (PMT) ===\"\n    ws.Range(\"A1\").Font.Bold = True\n\n    ws.Range(\"A2\").Value = \"貸款金額\"\n    ws.Range(\"B2\").Value = \"年利率\"\n    ws.Range(\"C2\").Value = \"年數\"\n    ws.Range(\"D2\").Value = \"月繳金額(PMT)\"\n    ws.Range(\"E2\").Value = \"總繳金額\"\n    ws.Range(\"F2\").Value = \"利息總額\"\n    ws.Range(\"A2:F2\").Font.Bold = True\n\n    ' 不同貸款條件資料\n    Dim loanData As Variant\n    loanData = Array( _\n        Array(500000, 0.02, 5), _\n        Array(1000000, 0.025, 10), _\n        Array(2000000, 0.03, 20), _\n        Array(3000000, 0.035, 30), _\n        Array(500000, 0.015, 3) _\n    )\n\n    Dim i As Integer\n    For i = 0 To UBound(loanData)\n        Dim r As Integer\n        r = i + 3\n        ws.Cells(r, 1).Value = loanData(i)(0)   ' 貸款金額\n        ws.Cells(r, 2).Value = loanData(i)(1)   ' 年利率\n        ws.Cells(r, 3).Value = loanData(i)(2)   ' 年數\n        ws.Cells(r, 1).NumberFormat = \"#,##0\"\n        ws.Cells(r, 2).NumberFormat = \"0.00%\"\n\n        ' PMT 公式：=PMT(年利率/12, 年數*12, -貸款金額)\n        ws.Cells(r, 4).Formula = \"=PMT(B\" & r & \"/12,C\" & r & \"*12,-A\" & r & \")\"\n        ws.Cells(r, 4).NumberFormat = \"#,##0\"\n\n        ' 總繳金額 = 月繳 * 月數\n        ws.Cells(r, 5).Formula = \"=D\" & r & \"*C\" & r & \"*12\"\n        ws.Cells(r, 5).NumberFormat = \"#,##0\"\n\n        ' 利息總額 = 總繳 - 貸款金額\n        ws.Cells(r, 6).Formula = \"=E\" & r & \"-A\" & r\n        ws.Cells(r, 6).NumberFormat = \"#,##0\"\n    Next i\nEnd Sub\n\n' 建立 PV (現值) / FV (終值) 計算表\nPrivate Sub BuildPVFVTable(ByVal ws As Worksheet)\n    Dim startRow As Integer\n    startRow = 10\n\n    ws.Cells(startRow, 1).Value = \"=== 投資現值(PV)與終值(FV)試算 ===\"\n    ws.Cells(startRow, 1).Font.Bold = True\n\n    ws.Cells(startRow + 1, 1).Value = \"每期金額\"\n    ws.Cells(startRow + 1, 2).Value = \"年利率\"\n    ws.Cells(startRow + 1, 3).Value = \"期數(年)\"\n    ws.Cells(startRow + 1, 4).Value = \"現值(PV)\"\n    ws.Cells(startRow + 1, 5).Value = \"終值(FV)\"\n    ws.Range(ws.Cells(startRow + 1, 1), ws.Cells(startRow + 1, 5)).Font.Bold = True\n\n    ' 不同投資方案\n    Dim pvData As Variant\n    pvData = Array( _\n        Array(10000, 0.05, 10), _\n        Array(20000, 0.04, 15), _\n        Array(5000, 0.06, 20), _\n        Array(15000, 0.03, 5), _\n        Array(8000, 0.055, 12) _\n    )\n\n    Dim i As Integer\n    For i = 0 To UBound(pvData)\n        Dim r As Integer\n        r = startRow + 2 + i\n        ws.Cells(r, 1).Value = pvData(i)(0)\n        ws.Cells(r, 2).Value = pvData(i)(1)\n        ws.Cells(r, 3).Value = pvData(i)(2)\n        ws.Cells(r, 1).NumberFormat = \"#,##0\"\n        ws.Cells(r, 2).NumberFormat = \"0.00%\"\n\n        ' PV 公式：每年領回固定金額的現值\n        ws.Cells(r, 4).Formula = \"=PV(B\" & r & \",C\" & r & \",-A\" & r & \")\"\n        ws.Cells(r, 4).NumberFormat = \"#,##0\"\n\n        ' FV 公式：每年存入固定金額的終值\n        ws.Cells(r, 5).Formula = \"=FV(B\" & r & \",C\" & r & \",-A\" & r & \")\"\n        ws.Cells(r, 5).NumberFormat = \"#,##0\"\n    Next i\nEnd Sub\n\n' 取得或建立工作表，並清除內容\nPrivate Function GetOrCreateFinSheet(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add\n        ws.Name = sheetName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreateFinSheet = ws\nEnd Function", "content_b64": ""}, {"name": "BatchIFFormulas.bas", "path": "模組/BatchEnterFormulas/BatchIFFormulas.bas", "content": "Attribute VB_Name = \"BatchIFFormulas\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: BatchIFFormulas\n'功能說明: 批次在工作表中填入 IF、巢狀 IF 判斷公式，依成績自動標示等第\n'\n'作者版權: Dunk\n'原始設計: Dunk\n'撰寫日期: 2026/5/9\n'\n'*************************************************************************************\n\n' 測試用入口\nSub TestBatchIFFormulas()\n    Call CreateIFFormulaExample\nEnd Sub\n\n' 建立 IF 公式批次填入示範\nSub CreateIFFormulaExample()\n    Dim ws As Worksheet\n    On Error GoTo ErrHandler\n\n    Set ws = GetOrCreateIFSheet(ThisWorkbook, \"IF公式示範\")\n    Call FillScoreBaseData(ws)\n    Call BatchEnterGradeFormulas(ws)\n    Call BatchEnterPassFailFormulas(ws)\n\n    ws.Columns(\"A:G\").AutoFit\n    ws.Activate\n    MsgBox \"IF 判斷公式已批次填入完成！\", vbInformation, \"完成\"\n    Exit Sub\n\nErrHandler:\n    MsgBox \"發生錯誤：\" & Err.Description, vbCritical, \"錯誤\"\nEnd Sub\n\n' 批次填入巢狀 IF 等第公式 (A/B/C/D/F)\nPrivate Sub BatchEnterGradeFormulas(ByVal ws As Worksheet)\n    Dim i As Integer\n    ' 平均分數在 F 欄，等第放 G 欄\n    ws.Range(\"F1\").Value = \"平均\"\n    ws.Range(\"G1\").Value = \"等第\"\n    ws.Range(\"F1:G1\").Font.Bold = True\n\n    For i = 2 To 11\n        ' 先計算平均\n        ws.Cells(i, 6).Formula = \"=AVERAGE(\" & _\n            ws.Cells(i, 2).Address(False, False) & \":\" & _\n            ws.Cells(i, 5).Address(False, False) & \")\"\n        ws.Cells(i, 6).NumberFormat = \"0.0\"\n\n        ' 巢狀 IF：90+ A / 80+ B / 70+ C / 60+ D / 不及格 F\n        ws.Cells(i, 7).Formula = \"=IF(\" & ws.Cells(i, 6).Address(False, False) & _\n            \">=90,\"\"A\"\",IF(\" & ws.Cells(i, 6).Address(False, False) & _\n            \">=80,\"\"B\"\",IF(\" & ws.Cells(i, 6).Address(False, False) & _\n            \">=70,\"\"C\"\",IF(\" & ws.Cells(i, 6).Address(False, False) & _\n            \">=60,\"\"D\"\",\"\"F\"\"))))\"\n    Next i\nEnd Sub\n\n' 批次填入及格/不及格判斷公式\nPrivate Sub BatchEnterPassFailFormulas(ByVal ws As Worksheet)\n    Dim i As Integer\n    Dim j As Integer\n    ' 在每科後面（H~K欄）加上通過/未通過\n    ws.Range(\"H1\").Value = \"國文狀態\"\n    ws.Range(\"I1\").Value = \"英文狀態\"\n    ws.Range(\"J1\").Value = \"數學狀態\"\n    ws.Range(\"K1\").Value = \"自然狀態\"\n    ws.Range(\"H1:K1\").Font.Bold = True\n\n    For i = 2 To 11\n        For j = 0 To 3\n            ws.Cells(i, 8 + j).Formula = \"=IF(\" & _\n                ws.Cells(i, 2 + j).Address(False, False) & _\n                \">=60,\"\"通過\"\",\"\"未通過\"\")\"\n        Next j\n    Next i\n    ws.Columns(\"A:K\").AutoFit\nEnd Sub\n\n' 填入基礎成績資料\nPrivate Sub FillScoreBaseData(ByVal ws As Worksheet)\n    Dim i As Integer\n    Dim names(1 To 10) As String\n    Dim scores(1 To 10, 1 To 4) As Integer\n\n    names(1) = \"王小明\" : names(2) = \"李美玲\" : names(3) = \"陳大偉\" : names(4) = \"林志豪\"\n    names(5) = \"張雅惠\" : names(6) = \"黃建宏\" : names(7) = \"蔡佳慧\" : names(8) = \"吳宗翰\"\n    names(9) = \"鄭麗娟\" : names(10) = \"許志遠\"\n\n    scores(1, 1) = 92 : scores(1, 2) = 88 : scores(1, 3) = 95 : scores(1, 4) = 91\n    scores(2, 1) = 75 : scores(2, 2) = 70 : scores(2, 3) = 68 : scores(2, 4) = 73\n    scores(3, 1) = 55 : scores(3, 2) = 60 : scores(3, 3) = 45 : scores(3, 4) = 58\n    scores(4, 1) = 83 : scores(4, 2) = 87 : scores(4, 3) = 80 : scores(4, 4) = 85\n    scores(5, 1) = 40 : scores(5, 2) = 35 : scores(5, 3) = 50 : scores(5, 4) = 42\n    scores(6, 1) = 98 : scores(6, 2) = 95 : scores(6, 3) = 92 : scores(6, 4) = 97\n    scores(7, 1) = 62 : scores(7, 2) = 68 : scores(7, 3) = 65 : scores(7, 4) = 60\n    scores(8, 1) = 30 : scores(8, 2) = 28 : scores(8, 3) = 35 : scores(8, 4) = 32\n    scores(9, 1) = 78 : scores(9, 2) = 82 : scores(9, 3) = 75 : scores(9, 4) = 80\n    scores(10, 1) = 68 : scores(10, 2) = 72 : scores(10, 3) = 70 : scores(10, 4) = 65\n\n    ws.Range(\"A1\").Value = \"姓名\"\n    ws.Range(\"B1\").Value = \"國文\"\n    ws.Range(\"C1\").Value = \"英文\"\n    ws.Range(\"D1\").Value = \"數學\"\n    ws.Range(\"E1\").Value = \"自然\"\n    ws.Range(\"A1:E1\").Font.Bold = True\n\n    For i = 1 To 10\n        ws.Cells(i + 1, 1).Value = names(i)\n        ws.Cells(i + 1, 2).Value = scores(i, 1)\n        ws.Cells(i + 1, 3).Value = scores(i, 2)\n        ws.Cells(i + 1, 4).Value = scores(i, 3)\n        ws.Cells(i + 1, 5).Value = scores(i, 4)\n    Next i\nEnd Sub\n\n' 取得或建立工作表，並清除內容\nPrivate Function GetOrCreateIFSheet(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add\n        ws.Name = sheetName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreateIFSheet = ws\nEnd Function", "content_b64": ""}, {"name": "BatchIndexMatchFormulas.bas", "path": "模組/BatchEnterFormulas/BatchIndexMatchFormulas.bas", "content": "Attribute VB_Name = \"BatchIndexMatchFormulas\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: BatchIndexMatchFormulas\n'功能說明: 批次填入 INDEX+MATCH 雙向查找公式，取代 VLOOKUP 實現更靈活的資料查詢\n'\n'作者版權: Dunk\n'原始設計: Dunk\n'撰寫日期: 2026/5/9\n'\n'*************************************************************************************\n\n' 測試用入口\nSub TestBatchIndexMatchFormulas()\n    Call CreateIndexMatchFormulaExample\nEnd Sub\n\n' 建立 INDEX/MATCH 公式批次填入示範\nSub CreateIndexMatchFormulaExample()\n    Dim wsRef As Worksheet\n    Dim wsQuery As Worksheet\n    On Error GoTo ErrHandler\n\n    Set wsRef = GetOrCreateIMSheet(ThisWorkbook, \"商品主檔\")\n    Set wsQuery = GetOrCreateIMSheet(ThisWorkbook, \"INDEX查詢\")\n\n    Call FillProductMasterData(wsRef)\n    Call BuildIndexMatchQuery(wsQuery, wsRef)\n\n    wsQuery.Columns(\"A:F\").AutoFit\n    wsQuery.Activate\n    MsgBox \"INDEX + MATCH 公式已批次填入完成！\", vbInformation, \"完成\"\n    Exit Sub\n\nErrHandler:\n    MsgBox \"發生錯誤：\" & Err.Description, vbCritical, \"錯誤\"\nEnd Sub\n\n' 批次填入 INDEX+MATCH 查詢公式\nPrivate Sub BuildIndexMatchQuery(ByVal wsQuery As Worksheet, ByVal wsRef As Worksheet)\n    Dim refName As String\n    Dim i As Integer\n    refName = wsRef.Name\n\n    ' 查詢標頭\n    wsQuery.Range(\"A1\").Value = \"查詢商品ID\"\n    wsQuery.Range(\"B1\").Value = \"商品名稱\"\n    wsQuery.Range(\"C1\").Value = \"類別\"\n    wsQuery.Range(\"D1\").Value = \"單價\"\n    wsQuery.Range(\"E1\").Value = \"庫存量\"\n    wsQuery.Range(\"F1\").Value = \"供應商\"\n    wsQuery.Range(\"A1:F1\").Font.Bold = True\n\n    ' 填入待查詢的商品 ID\n    wsQuery.Range(\"A2\").Value = \"P003\"\n    wsQuery.Range(\"A3\").Value = \"P007\"\n    wsQuery.Range(\"A4\").Value = \"P001\"\n    wsQuery.Range(\"A5\").Value = \"P005\"\n    wsQuery.Range(\"A6\").Value = \"P009\"\n\n    ' 批次填入 INDEX+MATCH 公式（查不到則顯示「查無資料」）\n    For i = 2 To 6\n        ' 商品名稱（第2欄）\n        wsQuery.Cells(i, 2).Formula = \"=IFERROR(INDEX('\" & refName & \"'!$B:$B,\" & _\n            \"MATCH(A\" & i & \",'\" & refName & \"'!$A:$A,0)),\"\"查無資料\"\")\"\n        ' 類別（第3欄）\n        wsQuery.Cells(i, 3).Formula = \"=IFERROR(INDEX('\" & refName & \"'!$C:$C,\" & _\n            \"MATCH(A\" & i & \",'\" & refName & \"'!$A:$A,0)),\"\"查無資料\"\")\"\n        ' 單價（第4欄）\n        wsQuery.Cells(i, 4).Formula = \"=IFERROR(INDEX('\" & refName & \"'!$D:$D,\" & _\n            \"MATCH(A\" & i & \",'\" & refName & \"'!$A:$A,0)),0)\"\n        wsQuery.Cells(i, 4).NumberFormat = \"#,##0\"\n        ' 庫存量（第5欄）\n        wsQuery.Cells(i, 5).Formula = \"=IFERROR(INDEX('\" & refName & \"'!$E:$E,\" & _\n            \"MATCH(A\" & i & \",'\" & refName & \"'!$A:$A,0)),0)\"\n        ' 供應商（第6欄）\n        wsQuery.Cells(i, 6).Formula = \"=IFERROR(INDEX('\" & refName & \"'!$F:$F,\" & _\n            \"MATCH(A\" & i & \",'\" & refName & \"'!$A:$A,0)),\"\"查無資料\"\")\"\n    Next i\nEnd Sub\n\n' 填入商品主檔參考資料\nPrivate Sub FillProductMasterData(ByVal ws As Worksheet)\n    ws.Range(\"A1:F1\").Value = Array(\"商品ID\", \"商品名稱\", \"類別\", \"單價\", \"庫存量\", \"供應商\")\n    ws.Range(\"A1:F1\").Font.Bold = True\n\n    Dim data As Variant\n    data = Array( _\n        Array(\"P001\", \"無線滑鼠\", \"電腦周邊\", 590, 120, \"科技公司A\"), _\n        Array(\"P002\", \"機械鍵盤\", \"電腦周邊\", 2800, 45, \"科技公司B\"), _\n        Array(\"P003\", \"27吋螢幕\", \"顯示設備\", 8500, 30, \"顯示公司C\"), _\n        Array(\"P004\", \"USB集線器\", \"電腦周邊\", 450, 200, \"科技公司A\"), _\n        Array(\"P005\", \"筆記型電腦\", \"電腦主機\", 35000, 15, \"電腦公司D\"), _\n        Array(\"P006\", \"行動硬碟\", \"儲存設備\", 1800, 80, \"儲存公司E\"), _\n        Array(\"P007\", \"網路攝影機\", \"影音設備\", 1200, 60, \"影音公司F\"), _\n        Array(\"P008\", \"藍芽耳機\", \"音訊設備\", 2200, 90, \"音訊公司G\"), _\n        Array(\"P009\", \"桌上型電腦\", \"電腦主機\", 28000, 10, \"電腦公司D\"), _\n        Array(\"P010\", \"平板電腦\", \"行動裝置\", 15000, 25, \"行動公司H\") _\n    )\n\n    Dim i As Integer\n    For i = 0 To UBound(data)\n        ws.Cells(i + 2, 1).Value = data(i)(0)\n        ws.Cells(i + 2, 2).Value = data(i)(1)\n        ws.Cells(i + 2, 3).Value = data(i)(2)\n        ws.Cells(i + 2, 4).Value = data(i)(3)\n        ws.Cells(i + 2, 5).Value = data(i)(4)\n        ws.Cells(i + 2, 6).Value = data(i)(5)\n    Next i\n\n    ws.Range(\"D2:D11\").NumberFormat = \"#,##0\"\n    ws.Columns(\"A:F\").AutoFit\nEnd Sub\n\n' 取得或建立工作表，並清除內容\nPrivate Function GetOrCreateIMSheet(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add\n        ws.Name = sheetName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreateIMSheet = ws\nEnd Function", "content_b64": ""}, {"name": "BatchLookupFormulas.bas", "path": "模組/BatchEnterFormulas/BatchLookupFormulas.bas", "content": "Option Explicit\n\n' 批次輸入查找公式，依產品代碼帶出產品名稱與單價。\nPublic Sub BatchEnterLookupFormulasExample()\n    On Error GoTo ErrHandler\n\n    Dim ws As Worksheet\n    Dim lastRow As Long\n\n    Set ws = GetOrCreateLookupWorksheet(\"批次查找公式範例\")\n    ws.Cells.Clear\n    Call FillLookupFormulaData(ws)\n\n    lastRow = ws.Cells(ws.Rows.Count, \"A\").End(xlUp).Row\n    ws.Range(\"B2:B\" & lastRow).Formula = \"=IFERROR(VLOOKUP(A2,$F$2:$H$5,2,FALSE),\"\"查無資料\"\")\"\n    ws.Range(\"C2:C\" & lastRow).Formula = \"=IFERROR(VLOOKUP(A2,$F$2:$H$5,3,FALSE),0)\"\n    ws.Range(\"D2:D\" & lastRow).Formula = \"=C2*E2\"\n    ws.Range(\"C2:D\" & lastRow).NumberFormat = \"#,##0\"\n    ws.Columns(\"A:H\").AutoFit\n\n    MsgBox \"查找公式已批次輸入完成。\", vbInformation, \"完成\"\n    Exit Sub\n\nErrHandler:\n    MsgBox \"批次輸入公式失敗：\" & Err.Description, vbExclamation, \"錯誤\"\nEnd Sub\n\nPrivate Sub FillLookupFormulaData(ByVal ws As Worksheet)\n    ws.Range(\"A1:E1\").Value = Array(\"產品代碼\", \"產品名稱\", \"單價\", \"小計\", \"數量\")\n    ws.Range(\"A2:E2\").Value = Array(\"P001\", \"\", \"\", \"\", 3)\n    ws.Range(\"A3:E3\").Value = Array(\"P003\", \"\", \"\", \"\", 5)\n    ws.Range(\"A4:E4\").Value = Array(\"P002\", \"\", \"\", \"\", 2)\n    ws.Range(\"A5:E5\").Value = Array(\"P004\", \"\", \"\", \"\", 4)\n    ws.Range(\"F1:H1\").Value = Array(\"產品代碼\", \"產品名稱\", \"單價\")\n    ws.Range(\"F2:H2\").Value = Array(\"P001\", \"鍵盤\", 900)\n    ws.Range(\"F3:H3\").Value = Array(\"P002\", \"滑鼠\", 450)\n    ws.Range(\"F4:H4\").Value = Array(\"P003\", \"螢幕\", 5200)\n    ws.Range(\"F5:H5\").Value = Array(\"P004\", \"耳機\", 1300)\nEnd Sub\n\nPrivate Function GetOrCreateLookupWorksheet(ByVal sheetName As String) As Worksheet\n    On Error Resume Next\n    Set GetOrCreateLookupWorksheet = ThisWorkbook.Worksheets(sheetName)\n    On Error GoTo 0\n\n    If GetOrCreateLookupWorksheet Is Nothing Then\n        Set GetOrCreateLookupWorksheet = ThisWorkbook.Worksheets.Add\n        GetOrCreateLookupWorksheet.Name = sheetName\n    End If\nEnd Function", "content_b64": ""}, {"name": "BatchPercentFormulas.bas", "path": "模組/BatchEnterFormulas/BatchPercentFormulas.bas", "content": "Attribute VB_Name = \"BatchPercentFormulas\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: BatchPercentFormulas\n'功能說明: 批次填入百分比計算公式，包含佔比、成長率、達成率、毛利率等\n'\n'作者版權: Dunk\n'原始設計: Dunk\n'撰寫日期: 2026/5/9\n'\n'*************************************************************************************\n\n' 測試用入口\nSub TestBatchPercentFormulas()\n    Call CreatePercentFormulaExample\nEnd Sub\n\n' 建立百分比公式批次填入示範\nSub CreatePercentFormulaExample()\n    Dim ws As Worksheet\n    On Error GoTo ErrHandler\n\n    Set ws = GetOrCreatePctSheet(ThisWorkbook, \"百分比公式示範\")\n    Call FillSalesTargetData(ws)\n    Call BatchEnterPercentFormulas(ws)\n\n    ws.Columns(\"A:I\").AutoFit\n    ws.Activate\n    MsgBox \"百分比計算公式已批次填入完成！\", vbInformation, \"完成\"\n    Exit Sub\n\nErrHandler:\n    MsgBox \"發生錯誤：\" & Err.Description, vbCritical, \"錯誤\"\nEnd Sub\n\n' 批次填入各種百分比計算公式\nPrivate Sub BatchEnterPercentFormulas(ByVal ws As Worksheet)\n    Dim i As Integer\n    Dim lastRow As Long\n    lastRow = ws.Cells(ws.Rows.Count, \"A\").End(xlUp).Row\n\n    ' 欄位標頭\n    ws.Range(\"F1\").Value = \"佔總業績%\"\n    ws.Range(\"G1\").Value = \"目標達成率%\"\n    ws.Range(\"H1\").Value = \"與去年成長率%\"\n    ws.Range(\"I1\").Value = \"毛利率%\"\n    ws.Range(\"F1:I1\").Font.Bold = True\n\n    ' 計算總業績（用於佔比）\n    Dim totalFormula As String\n    totalFormula = \"SUM($B$2:$B$\" & lastRow & \")\"\n\n    For i = 2 To lastRow\n        ' 佔總業績比例\n        ws.Cells(i, 6).Formula = \"=IFERROR(B\" & i & \"/\" & totalFormula & \",0)\"\n        ws.Cells(i, 6).NumberFormat = \"0.00%\"\n\n        ' 目標達成率 = 實際 / 目標\n        ws.Cells(i, 7).Formula = \"=IFERROR(B\" & i & \"/C\" & i & \",0)\"\n        ws.Cells(i, 7).NumberFormat = \"0.00%\"\n\n        ' 與去年成長率 = (今年 - 去年) / 去年\n        ws.Cells(i, 8).Formula = \"=IFERROR((B\" & i & \"-D\" & i & \")/D\" & i & \",0)\"\n        ws.Cells(i, 8).NumberFormat = \"0.00%\"\n\n        ' 毛利率 = (業績 - 成本) / 業績\n        ws.Cells(i, 9).Formula = \"=IFERROR((B\" & i & \"-E\" & i & \")/B\" & i & \",0)\"\n        ws.Cells(i, 9).NumberFormat = \"0.00%\"\n    Next i\n\n    ' 合計列\n    Dim sumRow As Long\n    sumRow = lastRow + 1\n    ws.Cells(sumRow, 1).Value = \"合計\"\n    ws.Cells(sumRow, 1).Font.Bold = True\n\n    ws.Cells(sumRow, 2).Formula = \"=SUM(B2:B\" & lastRow & \")\"\n    ws.Cells(sumRow, 2).NumberFormat = \"#,##0\"\n    ws.Cells(sumRow, 3).Formula = \"=SUM(C2:C\" & lastRow & \")\"\n    ws.Cells(sumRow, 3).NumberFormat = \"#,##0\"\n    ws.Cells(sumRow, 4).Formula = \"=SUM(D2:D\" & lastRow & \")\"\n    ws.Cells(sumRow, 4).NumberFormat = \"#,##0\"\n    ws.Cells(sumRow, 5).Formula = \"=SUM(E2:E\" & lastRow & \")\"\n    ws.Cells(sumRow, 5).NumberFormat = \"#,##0\"\n\n    ' 合計列達成率與毛利率\n    ws.Cells(sumRow, 7).Formula = \"=IFERROR(B\" & sumRow & \"/C\" & sumRow & \",0)\"\n    ws.Cells(sumRow, 7).NumberFormat = \"0.00%\"\n    ws.Cells(sumRow, 9).Formula = \"=IFERROR((B\" & sumRow & \"-E\" & sumRow & \")/B\" & sumRow & \",0)\"\n    ws.Cells(sumRow, 9).NumberFormat = \"0.00%\"\n    ws.Range(ws.Cells(sumRow, 1), ws.Cells(sumRow, 9)).Font.Bold = True\nEnd Sub\n\n' 填入各部門業績、目標、去年業績、成本資料\nPrivate Sub FillSalesTargetData(ByVal ws As Worksheet)\n    ws.Range(\"A1:E1\").Value = Array(\"部門\", \"今年業績\", \"目標金額\", \"去年業績\", \"成本\")\n    ws.Range(\"A1:E1\").Font.Bold = True\n\n    Dim data As Variant\n    data = Array( _\n        Array(\"業務一組\", 3850000, 3500000, 3200000, 2310000), _\n        Array(\"業務二組\", 2980000, 3200000, 2750000, 1788000), _\n        Array(\"行銷部門\", 1560000, 1500000, 1320000, 936000), _\n        Array(\"電商部門\", 4200000, 4000000, 3600000, 2520000), _\n        Array(\"通路部門\", 2750000, 2800000, 2500000, 1650000), _\n        Array(\"直銷團隊\", 1980000, 2000000, 1800000, 1188000) _\n    )\n\n    Dim i As Integer\n    For i = 0 To UBound(data)\n        Dim r As Integer\n        r = i + 2\n        ws.Cells(r, 1).Value = data(i)(0)\n        ws.Cells(r, 2).Value = data(i)(1)\n        ws.Cells(r, 3).Value = data(i)(2)\n        ws.Cells(r, 4).Value = data(i)(3)\n        ws.Cells(r, 5).Value = data(i)(4)\n    Next i\n\n    ws.Range(\"B2:E7\").NumberFormat = \"#,##0\"\nEnd Sub\n\n' 取得或建立工作表，並清除內容\nPrivate Function GetOrCreatePctSheet(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add\n        ws.Name = sheetName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreatePctSheet = ws\nEnd Function", "content_b64": ""}, {"name": "BatchRankFormulas.bas", "path": "模組/BatchEnterFormulas/BatchRankFormulas.bas", "content": "Attribute VB_Name = \"BatchRankFormulas\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: BatchRankFormulas\n'功能說明: 批次填入 RANK 排名公式，對多欄成績自動產生名次與百分比排名\n'\n'作者版權: Dunk\n'原始設計: Dunk\n'撰寫日期: 2026/5/9\n'\n'*************************************************************************************\n\n' 測試用入口\nSub TestBatchRankFormulas()\n    Call CreateRankFormulaExample\nEnd Sub\n\n' 建立排名公式批次填入示範\nSub CreateRankFormulaExample()\n    Dim ws As Worksheet\n    On Error GoTo ErrHandler\n\n    Set ws = GetOrCreateRankSheet(ThisWorkbook, \"排名公式示範\")\n    Call FillSalesPerformanceData(ws)\n    Call BatchEnterRankFormulas(ws)\n    Call BatchEnterPercentRankFormulas(ws)\n\n    ws.Columns(\"A:H\").AutoFit\n    ws.Activate\n    MsgBox \"排名公式已批次填入完成！\", vbInformation, \"完成\"\n    Exit Sub\n\nErrHandler:\n    MsgBox \"發生錯誤：\" & Err.Description, vbCritical, \"錯誤\"\nEnd Sub\n\n' 批次填入 RANK 名次公式（由大到小）\nPrivate Sub BatchEnterRankFormulas(ByVal ws As Worksheet)\n    Dim i As Integer\n    Dim lastRow As Long\n    lastRow = ws.Cells(ws.Rows.Count, \"A\").End(xlUp).Row\n\n    ws.Range(\"D1\").Value = \"業績名次(RANK)\"\n    ws.Range(\"E1\").Value = \"客戶數名次(RANK)\"\n    ws.Range(\"D1:E1\").Font.Bold = True\n\n    ' 固定範圍參考（加上 $ 絕對參照）\n    Dim salesRange As String\n    Dim custRange As String\n    salesRange = \"$B$2:$B$\" & lastRow\n    custRange = \"$C$2:$C$\" & lastRow\n\n    For i = 2 To lastRow\n        ' RANK 第3參數 0 = 由大到小\n        ws.Cells(i, 4).Formula = \"=RANK(B\" & i & \",\" & salesRange & \",0)\"\n        ws.Cells(i, 5).Formula = \"=RANK(C\" & i & \",\" & custRange & \",0)\"\n    Next i\nEnd Sub\n\n' 批次填入百分比排名與超過平均標記\nPrivate Sub BatchEnterPercentRankFormulas(ByVal ws As Worksheet)\n    Dim i As Integer\n    Dim lastRow As Long\n    lastRow = ws.Cells(ws.Rows.Count, \"A\").End(xlUp).Row\n\n    ws.Range(\"F1\").Value = \"業績%排名\"\n    ws.Range(\"G1\").Value = \"超過平均?\"\n    ws.Range(\"H1\").Value = \"排名標籤\"\n    ws.Range(\"F1:H1\").Font.Bold = True\n\n    Dim salesRange As String\n    salesRange = \"$B$2:$B$\" & lastRow\n\n    For i = 2 To lastRow\n        ' PERCENTRANK.INC 百分比排名\n        ws.Cells(i, 6).Formula = \"=PERCENTRANK.INC(\" & salesRange & \",B\" & i & \")\"\n        ws.Cells(i, 6).NumberFormat = \"0.0%\"\n        ' IF：超過平均則標示是\n        ws.Cells(i, 7).Formula = \"=IF(B\" & i & \">AVERAGE(\" & salesRange & \"),\"\"是\"\",\"\"否\"\")\"\n        ' 排名標籤文字\n        ws.Cells(i, 8).Formula = \"=\"\"第\"\"&D\" & i & \"&\"\"名\"\"\"\n    Next i\nEnd Sub\n\n' 填入業務績效資料\nPrivate Sub FillSalesPerformanceData(ByVal ws As Worksheet)\n    Dim i As Integer\n    Dim names(1 To 8) As String\n    Dim sales(1 To 8) As Long\n    Dim customers(1 To 8) As Integer\n\n    names(1) = \"業務一\" : sales(1) = 1250000 : customers(1) = 35\n    names(2) = \"業務二\" : sales(2) = 980000  : customers(2) = 28\n    names(3) = \"業務三\" : sales(3) = 1580000 : customers(3) = 42\n    names(4) = \"業務四\" : sales(4) = 760000  : customers(4) = 22\n    names(5) = \"業務五\" : sales(5) = 2100000 : customers(5) = 55\n    names(6) = \"業務六\" : sales(6) = 1380000 : customers(6) = 38\n    names(7) = \"業務七\" : sales(7) = 890000  : customers(7) = 25\n    names(8) = \"業務八\" : sales(8) = 1720000 : customers(8) = 47\n\n    ws.Range(\"A1\").Value = \"業務姓名\"\n    ws.Range(\"B1\").Value = \"業績金額\"\n    ws.Range(\"C1\").Value = \"客戶數\"\n    ws.Range(\"A1:C1\").Font.Bold = True\n\n    For i = 1 To 8\n        ws.Cells(i + 1, 1).Value = names(i)\n        ws.Cells(i + 1, 2).Value = sales(i)\n        ws.Cells(i + 1, 2).NumberFormat = \"#,##0\"\n        ws.Cells(i + 1, 3).Value = customers(i)\n    Next i\nEnd Sub\n\n' 取得或建立工作表，並清除內容\nPrivate Function GetOrCreateRankSheet(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add\n        ws.Name = sheetName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreateRankSheet = ws\nEnd Function", "content_b64": ""}, {"name": "BatchStatisticsFormulas.bas", "path": "模組/BatchEnterFormulas/BatchStatisticsFormulas.bas", "content": "Attribute VB_Name = \"BatchStatisticsFormulas\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: BatchStatisticsFormulas\n'功能說明: 批次填入統計公式，包含 STDEV、VAR、MEDIAN、MODE、QUARTILE 等描述性統計\n'\n'作者版權: Dunk\n'原始設計: Dunk\n'撰寫日期: 2026/5/9\n'\n'*************************************************************************************\n\n' 測試用入口\nSub TestBatchStatisticsFormulas()\n    Call CreateStatisticsFormulaExample\nEnd Sub\n\n' 建立統計公式批次填入示範\nSub CreateStatisticsFormulaExample()\n    Dim ws As Worksheet\n    On Error GoTo ErrHandler\n\n    Set ws = GetOrCreateStatSheet(ThisWorkbook, \"統計公式示範\")\n    Call FillProductSalesData(ws)\n    Call BatchEnterDescriptiveStats(ws)\n\n    ws.Columns(\"A:H\").AutoFit\n    ws.Activate\n    MsgBox \"統計公式已批次填入完成！\", vbInformation, \"完成\"\n    Exit Sub\n\nErrHandler:\n    MsgBox \"發生錯誤：\" & Err.Description, vbCritical, \"錯誤\"\nEnd Sub\n\n' 批次填入描述性統計公式（每欄資料分別計算）\nPrivate Sub BatchEnterDescriptiveStats(ByVal ws As Worksheet)\n    Dim col As Integer\n    Dim lastRow As Long\n    lastRow = ws.Cells(ws.Rows.Count, \"B\").End(xlUp).Row\n\n    ' 統計標籤行（第14列之後，假設資料12筆）\n    Dim statsRow As Long\n    statsRow = lastRow + 2\n\n    ws.Cells(statsRow, 1).Value = \"統計項目\"\n    ws.Cells(statsRow, 1).Font.Bold = True\n\n    ' 標籤清單\n    Dim labels(1 To 9) As String\n    labels(1) = \"平均值 (AVERAGE)\"\n    labels(2) = \"中位數 (MEDIAN)\"\n    labels(3) = \"眾數 (MODE)\"\n    labels(4) = \"標準差 (STDEV)\"\n    labels(5) = \"變異數 (VAR)\"\n    labels(6) = \"第1四分位 (Q1)\"\n    labels(7) = \"第3四分位 (Q3)\"\n    labels(8) = \"四分位距 (IQR)\"\n    labels(9) = \"變異係數 (CV%)\"\n\n    Dim k As Integer\n    For k = 1 To 9\n        ws.Cells(statsRow + k, 1).Value = labels(k)\n        ws.Cells(statsRow + k, 1).Font.Bold = True\n    Next k\n\n    ' 對每個商品欄（B~D）批次填入統計公式\n    For col = 2 To 4\n        Dim rngAddr As String\n        rngAddr = ws.Cells(2, col).Address(False, False) & \":\" & ws.Cells(lastRow, col).Address(False, False)\n\n        ws.Cells(statsRow + 1, col).Formula = \"=AVERAGE(\" & rngAddr & \")\"\n        ws.Cells(statsRow + 2, col).Formula = \"=MEDIAN(\" & rngAddr & \")\"\n        ws.Cells(statsRow + 3, col).Formula = \"=MODE(\" & rngAddr & \")\"\n        ws.Cells(statsRow + 4, col).Formula = \"=STDEV(\" & rngAddr & \")\"\n        ws.Cells(statsRow + 5, col).Formula = \"=VAR(\" & rngAddr & \")\"\n        ws.Cells(statsRow + 6, col).Formula = \"=QUARTILE(\" & rngAddr & \",1)\"\n        ws.Cells(statsRow + 7, col).Formula = \"=QUARTILE(\" & rngAddr & \",3)\"\n        ' IQR = Q3 - Q1\n        ws.Cells(statsRow + 8, col).Formula = \"=\" & _\n            ws.Cells(statsRow + 7, col).Address(False, False) & \"-\" & _\n            ws.Cells(statsRow + 6, col).Address(False, False)\n        ' CV = 標準差 / 平均值\n        ws.Cells(statsRow + 9, col).Formula = \"=\" & _\n            ws.Cells(statsRow + 4, col).Address(False, False) & \"/\" & _\n            ws.Cells(statsRow + 1, col).Address(False, False)\n        ws.Cells(statsRow + 9, col).NumberFormat = \"0.00%\"\n\n        ' 格式：小數2位\n        ws.Range(ws.Cells(statsRow + 1, col), ws.Cells(statsRow + 8, col)).NumberFormat = \"0.00\"\n    Next col\nEnd Sub\n\n' 填入商品月銷售量資料（12個月 x 3個商品）\nPrivate Sub FillProductSalesData(ByVal ws As Worksheet)\n    Dim months(1 To 12) As String\n    Dim salesA(1 To 12) As Integer\n    Dim salesB(1 To 12) As Integer\n    Dim salesC(1 To 12) As Integer\n    Dim i As Integer\n\n    months(1) = \"1月\" : months(2) = \"2月\" : months(3) = \"3月\"\n    months(4) = \"4月\" : months(5) = \"5月\" : months(6) = \"6月\"\n    months(7) = \"7月\" : months(8) = \"8月\" : months(9) = \"9月\"\n    months(10) = \"10月\" : months(11) = \"11月\" : months(12) = \"12月\"\n\n    salesA(1) = 85  : salesA(2) = 92  : salesA(3) = 78\n    salesA(4) = 95  : salesA(5) = 88  : salesA(6) = 102\n    salesA(7) = 115 : salesA(8) = 120 : salesA(9) = 98\n    salesA(10) = 88 : salesA(11) = 105 : salesA(12) = 130\n\n    salesB(1) = 210 : salesB(2) = 195 : salesB(3) = 230\n    salesB(4) = 185 : salesB(5) = 220 : salesB(6) = 215\n    salesB(7) = 198 : salesB(8) = 210 : salesB(9) = 240\n    salesB(10) = 225 : salesB(11) = 195 : salesB(12) = 260\n\n    salesC(1) = 50  : salesC(2) = 55  : salesC(3) = 48\n    salesC(4) = 62  : salesC(5) = 58  : salesC(6) = 70\n    salesC(7) = 45  : salesC(8) = 52  : salesC(9) = 65\n    salesC(10) = 72 : salesC(11) = 68 : salesC(12) = 80\n\n    ws.Range(\"A1\").Value = \"月份\"\n    ws.Range(\"B1\").Value = \"商品A銷量\"\n    ws.Range(\"C1\").Value = \"商品B銷量\"\n    ws.Range(\"D1\").Value = \"商品C銷量\"\n    ws.Range(\"A1:D1\").Font.Bold = True\n\n    For i = 1 To 12\n        ws.Cells(i + 1, 1).Value = months(i)\n        ws.Cells(i + 1, 2).Value = salesA(i)\n        ws.Cells(i + 1, 3).Value = salesB(i)\n        ws.Cells(i + 1, 4).Value = salesC(i)\n    Next i\nEnd Sub\n\n' 取得或建立工作表，並清除內容\nPrivate Function GetOrCreateStatSheet(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add\n        ws.Name = sheetName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreateStatSheet = ws\nEnd Function", "content_b64": ""}, {"name": "BatchSumFormulas.bas", "path": "模組/BatchEnterFormulas/BatchSumFormulas.bas", "content": "Attribute VB_Name = \"BatchSumFormulas\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: BatchSumFormulas\n'功能說明: 批次在多個儲存格中自動輸入加總、平均、最大最小值公式\n'\n'著作權所有: Dunk\n'程式設計: Dunk\n'撰寫日期: 2026/5/7\n'\n'*************************************************************************************\n\n' 測試用入口\nSub TestBatchSumFormulas()\n    Call CreateBatchFormulaExample\nEnd Sub\n\n' 建立批次公式輸入範例\nSub CreateBatchFormulaExample()\n    Dim ws As Worksheet\n    Set ws = GetOrCreateSheet(ThisWorkbook, \"批次公式範例\")\n\n    Call FillMonthlySalesData(ws)\n    Call BatchEnterSumFormulas(ws)\n    Call BatchEnterAverageFormulas(ws)\n    Call BatchEnterMaxMinFormulas(ws)\n\n    ws.Activate\n    MsgBox \"批次公式輸入完成！\", vbInformation, \"完成\"\nEnd Sub\n\n' 批次輸入每月小計（SUM）公式\nPrivate Sub BatchEnterSumFormulas(ByVal ws As Worksheet)\n    Dim i As Integer\n    For i = 2 To 7\n        ws.Cells(8, i).Formula = \"=SUM(\" & _\n            ws.Cells(2, i).Address(False, False) & \":\" & _\n            ws.Cells(7, i).Address(False, False) & \")\"\n    Next i\n    ws.Range(\"A8\").Value = \"月合計\"\n    ws.Range(\"A8\").Font.Bold = True\n    ws.Range(\"B8:G8\").Font.Bold = True\nEnd Sub\n\n' 批次輸入每月平均（AVERAGE）公式\nPrivate Sub BatchEnterAverageFormulas(ByVal ws As Worksheet)\n    Dim i As Integer\n    For i = 2 To 7\n        ws.Cells(9, i).Formula = \"=AVERAGE(\" & _\n            ws.Cells(2, i).Address(False, False) & \":\" & _\n            ws.Cells(7, i).Address(False, False) & \")\"\n    Next i\n    ws.Range(\"A9\").Value = \"月平均\"\n    ws.Range(\"A9\").Font.Bold = True\nEnd Sub\n\n' 批次輸入每月最大最小值公式\nPrivate Sub BatchEnterMaxMinFormulas(ByVal ws As Worksheet)\n    Dim i As Integer\n    For i = 2 To 7\n        ws.Cells(10, i).Formula = \"=MAX(\" & _\n            ws.Cells(2, i).Address(False, False) & \":\" & _\n            ws.Cells(7, i).Address(False, False) & \")\"\n        ws.Cells(11, i).Formula = \"=MIN(\" & _\n            ws.Cells(2, i).Address(False, False) & \":\" & _\n            ws.Cells(7, i).Address(False, False) & \")\"\n    Next i\n    ws.Range(\"A10\").Value = \"月最大值\"\n    ws.Range(\"A11\").Value = \"月最小值\"\n    ws.Range(\"A10:A11\").Font.Bold = True\nEnd Sub\n\n' 填入月度銷售資料（6個業務員 x 6個月）\nPrivate Sub FillMonthlySalesData(ByVal ws As Worksheet)\n    Dim salesData(1 To 6, 1 To 6) As Integer\n    Dim r As Integer\n    Dim c As Integer\n\n    ws.Range(\"A1\").Value = \"業務員\\月份\"\n    ws.Range(\"B1\").Value = \"1月\"\n    ws.Range(\"C1\").Value = \"2月\"\n    ws.Range(\"D1\").Value = \"3月\"\n    ws.Range(\"E1\").Value = \"4月\"\n    ws.Range(\"F1\").Value = \"5月\"\n    ws.Range(\"G1\").Value = \"6月\"\n\n    ws.Range(\"A2\").Value = \"張一\"\n    ws.Range(\"A3\").Value = \"李二\"\n    ws.Range(\"A4\").Value = \"王三\"\n    ws.Range(\"A5\").Value = \"趙四\"\n    ws.Range(\"A6\").Value = \"孫五\"\n    ws.Range(\"A7\").Value = \"周六\"\n\n    salesData(1, 1) = 120 : salesData(1, 2) = 135 : salesData(1, 3) = 98\n    salesData(1, 4) = 145 : salesData(1, 5) = 160 : salesData(1, 6) = 130\n    salesData(2, 1) = 95 : salesData(2, 2) = 110 : salesData(2, 3) = 125\n    salesData(2, 4) = 100 : salesData(2, 5) = 88 : salesData(2, 6) = 115\n    salesData(3, 1) = 200 : salesData(3, 2) = 185 : salesData(3, 3) = 220\n    salesData(3, 4) = 195 : salesData(3, 5) = 210 : salesData(3, 6) = 230\n    salesData(4, 1) = 75 : salesData(4, 2) = 80 : salesData(4, 3) = 70\n    salesData(4, 4) = 90 : salesData(4, 5) = 85 : salesData(4, 6) = 78\n    salesData(5, 1) = 155 : salesData(5, 2) = 160 : salesData(5, 3) = 148\n    salesData(5, 4) = 170 : salesData(5, 5) = 165 : salesData(5, 6) = 175\n    salesData(6, 1) = 110 : salesData(6, 2) = 105 : salesData(6, 3) = 118\n    salesData(6, 4) = 122 : salesData(6, 5) = 130 : salesData(6, 6) = 115\n\n    For r = 1 To 6\n        For c = 1 To 6\n            ws.Cells(r + 1, c + 1).Value = salesData(r, c)\n        Next c\n    Next r\n\n    ws.Columns(\"A:G\").AutoFit\nEnd Sub\n\n' 取得或建立工作表，並清除內容\nPrivate Function GetOrCreateSheet(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add\n        ws.Name = sheetName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreateSheet = ws\nEnd Function\n", "content_b64": ""}, {"name": "BatchSumIfFormulas.bas", "path": "模組/BatchEnterFormulas/BatchSumIfFormulas.bas", "content": "Attribute VB_Name = \"BatchSumIfFormulas\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: BatchSumIfFormulas\n'功能說明: 批次填入 SUMIF / SUMIFS 條件加總公式，依部門/月份彙整銷售數據\n'\n'作者版權: Dunk\n'原始設計: Dunk\n'撰寫日期: 2026/5/9\n'\n'*************************************************************************************\n\n' 測試用入口\nSub TestBatchSumIfFormulas()\n    Call CreateSumIfFormulaExample\nEnd Sub\n\n' 建立 SUMIF / SUMIFS 公式批次填入示範\nSub CreateSumIfFormulaExample()\n    Dim wsData As Worksheet\n    Dim wsSummary As Worksheet\n    On Error GoTo ErrHandler\n\n    Set wsData = GetOrCreateSumIfSheet(ThisWorkbook, \"銷售明細\")\n    Set wsSummary = GetOrCreateSumIfSheet(ThisWorkbook, \"SUMIF彙整\")\n\n    Call FillSalesDetailData(wsData)\n    Call BuildSumIfSummary(wsSummary, wsData)\n\n    wsSummary.Columns(\"A:F\").AutoFit\n    wsSummary.Activate\n    MsgBox \"SUMIF / SUMIFS 公式已批次填入完成！\", vbInformation, \"完成\"\n    Exit Sub\n\nErrHandler:\n    MsgBox \"發生錯誤：\" & Err.Description, vbCritical, \"錯誤\"\nEnd Sub\n\n' 在彙整表中批次填入 SUMIF / SUMIFS 公式\nPrivate Sub BuildSumIfSummary(ByVal wsSummary As Worksheet, ByVal wsData As Worksheet)\n    Dim deptNames(1 To 4) As String\n    Dim i As Integer\n    Dim dataSheetName As String\n    dataSheetName = wsData.Name\n\n    deptNames(1) = \"業務部\" : deptNames(2) = \"行銷部\"\n    deptNames(3) = \"電商部\" : deptNames(4) = \"通路部\"\n\n    ' 標頭\n    wsSummary.Range(\"A1\").Value = \"部門\"\n    wsSummary.Range(\"B1\").Value = \"總業績(SUMIF)\"\n    wsSummary.Range(\"C1\").Value = \"Q1業績(SUMIFS)\"\n    wsSummary.Range(\"D1\").Value = \"Q2業績(SUMIFS)\"\n    wsSummary.Range(\"E1\").Value = \"線上通路(SUMIFS)\"\n    wsSummary.Range(\"F1\").Value = \"線下通路(SUMIFS)\"\n    wsSummary.Range(\"A1:F1\").Font.Bold = True\n\n    ' 批次填入各部門公式\n    For i = 1 To 4\n        wsSummary.Cells(i + 1, 1).Value = deptNames(i)\n\n        ' SUMIF：依部門加總業績\n        wsSummary.Cells(i + 1, 2).Formula = \"=SUMIF('\" & dataSheetName & \"'!$B:$B,A\" & _\n            (i + 1) & \",'\" & dataSheetName & \"'!$D:$D)\"\n\n        ' SUMIFS：部門 + Q1 (1~3月)\n        wsSummary.Cells(i + 1, 3).Formula = \"=SUMIFS('\" & dataSheetName & \"'!$D:$D,'\" & _\n            dataSheetName & \"'!$B:$B,A\" & (i + 1) & \",'\" & dataSheetName & \"'!$C:$C,\"\"Q1\"\")\"\n\n        ' SUMIFS：部門 + Q2 (4~6月)\n        wsSummary.Cells(i + 1, 4).Formula = \"=SUMIFS('\" & dataSheetName & \"'!$D:$D,'\" & _\n            dataSheetName & \"'!$B:$B,A\" & (i + 1) & \",'\" & dataSheetName & \"'!$C:$C,\"\"Q2\"\")\"\n\n        ' SUMIFS：部門 + 線上通路\n        wsSummary.Cells(i + 1, 5).Formula = \"=SUMIFS('\" & dataSheetName & \"'!$D:$D,'\" & _\n            dataSheetName & \"'!$B:$B,A\" & (i + 1) & \",'\" & dataSheetName & \"'!$E:$E,\"\"線上\"\")\"\n\n        ' SUMIFS：部門 + 線下通路\n        wsSummary.Cells(i + 1, 6).Formula = \"=SUMIFS('\" & dataSheetName & \"'!$D:$D,'\" & _\n            dataSheetName & \"'!$B:$B,A\" & (i + 1) & \",'\" & dataSheetName & \"'!$E:$E,\"\"線下\"\")\"\n    Next i\n\n    ' 格式設定\n    wsSummary.Range(\"B2:F5\").NumberFormat = \"#,##0\"\nEnd Sub\n\n' 填入銷售明細資料\nPrivate Sub FillSalesDetailData(ByVal ws As Worksheet)\n    ws.Range(\"A1:E1\").Value = Array(\"月份\", \"部門\", \"季度\", \"業績\", \"通路\")\n    ws.Range(\"A1:E1\").Font.Bold = True\n\n    Dim data As Variant\n    data = Array( _\n        Array(\"1月\", \"業務部\", \"Q1\", 320000, \"線下\"), _\n        Array(\"1月\", \"行銷部\", \"Q1\", 180000, \"線上\"), _\n        Array(\"2月\", \"業務部\", \"Q1\", 295000, \"線下\"), _\n        Array(\"2月\", \"電商部\", \"Q1\", 420000, \"線上\"), _\n        Array(\"3月\", \"行銷部\", \"Q1\", 210000, \"線上\"), _\n        Array(\"3月\", \"通路部\", \"Q1\", 155000, \"線下\"), _\n        Array(\"4月\", \"業務部\", \"Q2\", 380000, \"線下\"), _\n        Array(\"4月\", \"電商部\", \"Q2\", 510000, \"線上\"), _\n        Array(\"5月\", \"行銷部\", \"Q2\", 260000, \"線上\"), _\n        Array(\"5月\", \"通路部\", \"Q2\", 190000, \"線下\"), _\n        Array(\"6月\", \"業務部\", \"Q2\", 430000, \"線下\"), _\n        Array(\"6月\", \"電商部\", \"Q2\", 580000, \"線上\") _\n    )\n\n    Dim i As Integer\n    For i = 0 To UBound(data)\n        ws.Cells(i + 2, 1).Value = data(i)(0)\n        ws.Cells(i + 2, 2).Value = data(i)(1)\n        ws.Cells(i + 2, 3).Value = data(i)(2)\n        ws.Cells(i + 2, 4).Value = data(i)(3)\n        ws.Cells(i + 2, 5).Value = data(i)(4)\n    Next i\n\n    ws.Range(\"D2:D13\").NumberFormat = \"#,##0\"\n    ws.Columns(\"A:E\").AutoFit\nEnd Sub\n\n' 取得或建立工作表，並清除內容\nPrivate Function GetOrCreateSumIfSheet(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add\n        ws.Name = sheetName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreateSumIfSheet = ws\nEnd Function", "content_b64": ""}, {"name": "BatchTextFormulas.bas", "path": "模組/BatchEnterFormulas/BatchTextFormulas.bas", "content": "Attribute VB_Name = \"BatchTextFormulas\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: BatchTextFormulas\n'功能說明: 批次填入文字處理公式，包含 LEFT、RIGHT、MID、LEN、TRIM、UPPER、LOWER\n'\n'作者版權: Dunk\n'原始設計: Dunk\n'撰寫日期: 2026/5/9\n'\n'*************************************************************************************\n\n' 測試用入口\nSub TestBatchTextFormulas()\n    Call CreateTextFormulaExample\nEnd Sub\n\n' 建立文字公式批次填入示範\nSub CreateTextFormulaExample()\n    Dim ws As Worksheet\n    On Error GoTo ErrHandler\n\n    Set ws = GetOrCreateTextSheet(ThisWorkbook, \"文字公式示範\")\n    Call FillRawTextData(ws)\n    Call BatchEnterTextExtractFormulas(ws)\n    Call BatchEnterTextTransformFormulas(ws)\n\n    ws.Columns(\"A:I\").AutoFit\n    ws.Activate\n    MsgBox \"文字處理公式已批次填入完成！\", vbInformation, \"完成\"\n    Exit Sub\n\nErrHandler:\n    MsgBox \"發生錯誤：\" & Err.Description, vbCritical, \"錯誤\"\nEnd Sub\n\n' 批次填入 LEFT / RIGHT / MID / LEN 擷取公式\nPrivate Sub BatchEnterTextExtractFormulas(ByVal ws As Worksheet)\n    Dim i As Integer\n    Dim lastRow As Long\n    lastRow = ws.Cells(ws.Rows.Count, \"A\").End(xlUp).Row\n\n    ws.Range(\"B1\").Value = \"前3字(LEFT)\"\n    ws.Range(\"C1\").Value = \"後3字(RIGHT)\"\n    ws.Range(\"D1\").Value = \"中間4字(MID)\"\n    ws.Range(\"E1\").Value = \"字元長度(LEN)\"\n    ws.Range(\"B1:E1\").Font.Bold = True\n\n    For i = 2 To lastRow\n        ws.Cells(i, 2).Formula = \"=LEFT(A\" & i & \",3)\"\n        ws.Cells(i, 3).Formula = \"=RIGHT(A\" & i & \",3)\"\n        ws.Cells(i, 4).Formula = \"=MID(A\" & i & \",2,4)\"\n        ws.Cells(i, 5).Formula = \"=LEN(A\" & i & \")\"\n    Next i\nEnd Sub\n\n' 批次填入 TRIM / UPPER / LOWER 轉換公式\nPrivate Sub BatchEnterTextTransformFormulas(ByVal ws As Worksheet)\n    Dim i As Integer\n    Dim lastRow As Long\n    lastRow = ws.Cells(ws.Rows.Count, \"A\").End(xlUp).Row\n\n    ws.Range(\"F1\").Value = \"去除空白(TRIM)\"\n    ws.Range(\"G1\").Value = \"大寫(UPPER)\"\n    ws.Range(\"H1\").Value = \"小寫(LOWER)\"\n    ws.Range(\"I1\").Value = \"合併姓名\"\n    ws.Range(\"F1:I1\").Font.Bold = True\n\n    For i = 2 To lastRow\n        ws.Cells(i, 6).Formula = \"=TRIM(A\" & i & \")\"\n        ws.Cells(i, 7).Formula = \"=UPPER(A\" & i & \")\"\n        ws.Cells(i, 8).Formula = \"=LOWER(A\" & i & \")\"\n        ' CONCATENATE 模擬：將前3字與後3字合併\n        ws.Cells(i, 9).Formula = \"=LEFT(A\" & i & \",3)&\"\"-\"\"&RIGHT(A\" & i & \",3)\"\n    Next i\nEnd Sub\n\n' 填入原始文字資料（英文員工代號）\nPrivate Sub FillRawTextData(ByVal ws As Worksheet)\n    ws.Range(\"A1\").Value = \"員工代號\"\n    ws.Range(\"A1\").Font.Bold = True\n\n    ws.Range(\"A2\").Value = \"EMP-Alice-2023\"\n    ws.Range(\"A3\").Value = \"EMP-Bob-2022\"\n    ws.Range(\"A4\").Value = \"EMP-Carol-2024\"\n    ws.Range(\"A5\").Value = \"EMP-David-2021\"\n    ws.Range(\"A6\").Value = \"EMP-Eve-2023\"\n    ws.Range(\"A7\").Value = \"EMP-Frank-2020\"\n    ws.Range(\"A8\").Value = \"EMP-Grace-2022\"\n    ws.Range(\"A9\").Value = \"EMP-Henry-2024\"\n    ws.Range(\"A10\").Value = \"EMP-Ivy-2023\"\n    ws.Range(\"A11\").Value = \"EMP-Jack-2021\"\nEnd Sub\n\n' 取得或建立工作表，並清除內容\nPrivate Function GetOrCreateTextSheet(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add\n        ws.Name = sheetName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreateTextSheet = ws\nEnd Function", "content_b64": ""}]}, {"folder": "ChartsNormal", "path": "模組/ChartsNormal", "files": [{"name": "AreaChartExample.bas", "path": "模組/ChartsNormal/AreaChartExample.bas", "content": "Option Explicit\nAttribute VB_Name = \"AreaChartExample\"\n'*************************************************************************************\n'模組名稱: 區域圖範例\n'功能描述: 在 Excel 中建立區域圖的範例程式\n'\n'版權所有: Dunk\n'程式設計: Dunk\n'撰寫日期: 2026/5/4\n'\n'傳入參數:\n'傳回值:\n'\n'*************************************************************************************\n\n' 測試用入口\nSub TestAreaChart()\n    Call CreateAreaChart(\"區域圖範例\")\nEnd Sub\n\n' 建立區域圖\n' sheetName: 要建立圖表的工作表名稱\nSub CreateAreaChart(ByVal sheetName As String)\n    On Error GoTo ErrorHandler\n\n    Dim ws As Worksheet\n    Dim chartObj As ChartObject\n    Dim cht As Chart\n    Dim dataRange As Range\n\n    Set ws = GetOrCreateWorksheet(sheetName)\n    ws.Cells.Clear\n\n    Call FillAreaChartData(ws)\n    Set dataRange = ws.Range(\"A1:D7\")\n\n    Set chartObj = ws.ChartObjects.Add( _\n        Left:=ws.Range(\"F1\").Left, _\n        Top:=ws.Range(\"F1\").Top, _\n        Width:=480, _\n        Height:=320)\n\n    Set cht = chartObj.Chart\n    cht.SetSourceData Source:=dataRange\n    cht.ChartType = xlAreaStacked\n\n    cht.HasTitle = True\n    cht.ChartTitle.Text = \"各產品每月累積營收\"\n\n    With cht.Axes(xlCategory)\n        .HasTitle = True\n        .AxisTitle.Text = \"月份\"\n    End With\n\n    With cht.Axes(xlValue)\n        .HasTitle = True\n        .AxisTitle.Text = \"營收（萬元）\"\n    End With\n\n    cht.HasLegend = True\n    cht.Legend.Position = xlLegendPositionBottom\n    cht.ChartStyle = 13\n\n    MsgBox \"區域圖已建立完成！\", vbInformation, \"完成\"\n    Exit Sub\n\nErrorHandler:\n    MsgBox \"建立區域圖時發生錯誤：\" & Err.Description, vbExclamation, \"錯誤\"\nEnd Sub\n\n' 取得或建立工作表\nPrivate Function GetOrCreateWorksheet(ByVal sheetName As String) As Worksheet\n    On Error Resume Next\n    Set GetOrCreateWorksheet = ThisWorkbook.Worksheets(sheetName)\n    On Error GoTo 0\n\n    If GetOrCreateWorksheet Is Nothing Then\n        Set GetOrCreateWorksheet = ThisWorkbook.Worksheets.Add\n        GetOrCreateWorksheet.Name = sheetName\n    End If\nEnd Function\n\n' 輸入區域圖範例資料\nPrivate Sub FillAreaChartData(ByVal ws As Worksheet)\n    ws.Range(\"A1\").Value = \"月份\"\n    ws.Range(\"B1\").Value = \"產品A\"\n    ws.Range(\"C1\").Value = \"產品B\"\n    ws.Range(\"D1\").Value = \"產品C\"\n\n    ws.Range(\"A2\").Value = \"一月\"\n    ws.Range(\"B2\").Value = 120\n    ws.Range(\"C2\").Value = 90\n    ws.Range(\"D2\").Value = 60\n\n    ws.Range(\"A3\").Value = \"二月\"\n    ws.Range(\"B3\").Value = 135\n    ws.Range(\"C3\").Value = 98\n    ws.Range(\"D3\").Value = 72\n\n    ws.Range(\"A4\").Value = \"三月\"\n    ws.Range(\"B4\").Value = 150\n    ws.Range(\"C4\").Value = 110\n    ws.Range(\"D4\").Value = 80\n\n    ws.Range(\"A5\").Value = \"四月\"\n    ws.Range(\"B5\").Value = 170\n    ws.Range(\"C5\").Value = 128\n    ws.Range(\"D5\").Value = 96\n\n    ws.Range(\"A6\").Value = \"五月\"\n    ws.Range(\"B6\").Value = 188\n    ws.Range(\"C6\").Value = 142\n    ws.Range(\"D6\").Value = 105\n\n    ws.Range(\"A7\").Value = \"六月\"\n    ws.Range(\"B7\").Value = 205\n    ws.Range(\"C7\").Value = 160\n    ws.Range(\"D7\").Value = 118\n\n    ws.Columns(\"A:D\").AutoFit\nEnd Sub", "content_b64": ""}, {"name": "BarChartExample.bas", "path": "模組/ChartsNormal/BarChartExample.bas", "content": "Attribute VB_Name = \"BarChartExample\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: 長條圖範例\n'功能描述: 在Excel中建立長條圖的範例程式\n'\n'版權所有: Dunk\n'程式設計: Dunk\n'撰寫日期: 2026/5/3\n'\n'傳入參數:\n'傳回數值:\n'\n'*************************************************************************************\n\n' 測試用入口\nSub TestBarChart()\n    Call CreateBarChart(\"長條圖範例\")\nEnd Sub\n\n' 建立長條圖\n' sheetName: 要建立圖表的工作表名稱\nSub CreateBarChart(ByVal sheetName As String)\n    Dim ws As Worksheet\n    Dim chartObj As ChartObject\n    Dim cht As Chart\n    Dim dataRange As Range\n\n    ' 取得或建立工作表\n    On Error Resume Next\n    Set ws = ThisWorkbook.Worksheets(sheetName)\n    On Error GoTo 0\n\n    If ws Is Nothing Then\n        Set ws = ThisWorkbook.Worksheets.Add\n        ws.Name = sheetName\n    End If\n\n    ' 清除工作表\n    ws.Cells.Clear\n\n    ' 建立範例資料\n    Call FillSampleData(ws)\n\n    ' 設定資料範圍 (A1:B6)\n    Set dataRange = ws.Range(\"A1:B6\")\n\n    ' 在工作表中新增圖表物件\n    Set chartObj = ws.ChartObjects.Add( _\n        Left:=ws.Range(\"D1\").Left, _\n        Top:=ws.Range(\"D1\").Top, _\n        Width:=400, _\n        Height:=300)\n\n    Set cht = chartObj.Chart\n\n    ' 設定圖表資料來源\n    cht.SetSourceData Source:=dataRange\n\n    ' 設定圖表類型為群組直條圖\n    cht.ChartType = xlColumnClustered\n\n    ' 設定圖表標題\n    cht.HasTitle = True\n    cht.ChartTitle.Text = \"月份銷售量統計\"\n\n    ' 設定 X 軸標題\n    With cht.Axes(xlCategory)\n        .HasTitle = True\n        .AxisTitle.Text = \"月份\"\n    End With\n\n    ' 設定 Y 軸標題\n    With cht.Axes(xlValue)\n        .HasTitle = True\n        .AxisTitle.Text = \"銷售量\"\n    End With\n\n    ' 設定圖表樣式\n    cht.ChartStyle = 2\n\n    ' 顯示資料標籤\n    cht.SeriesCollection(1).HasDataLabels = True\n\n    MsgBox \"長條圖已建立完成！\", vbInformation, \"完成\"\nEnd Sub\n\n' 填入範例資料\nPrivate Sub FillSampleData(ByVal ws As Worksheet)\n    ' 標題列\n    ws.Range(\"A1\").Value = \"月份\"\n    ws.Range(\"B1\").Value = \"銷售量\"\n\n    ' 資料列\n    ws.Range(\"A2\").Value = \"一月\"\n    ws.Range(\"B2\").Value = 1200\n\n    ws.Range(\"A3\").Value = \"二月\"\n    ws.Range(\"B3\").Value = 850\n\n    ws.Range(\"A4\").Value = \"三月\"\n    ws.Range(\"B4\").Value = 1560\n\n    ws.Range(\"A5\").Value = \"四月\"\n    ws.Range(\"B5\").Value = 970\n\n    ws.Range(\"A6\").Value = \"五月\"\n    ws.Range(\"B6\").Value = 1380\n\n    ' 自動調整欄寬\n    ws.Columns(\"A:B\").AutoFit\nEnd Sub\n\n' 建立多系列長條圖範例\nSub CreateMultiSeriesBarChart()\n    Dim ws As Worksheet\n    Dim chartObj As ChartObject\n    Dim cht As Chart\n    Dim dataRange As Range\n    Dim sheetName As String\n\n    sheetName = \"多系列長條圖\"\n\n    ' 取得或建立工作表\n    On Error Resume Next\n    Set ws = ThisWorkbook.Worksheets(sheetName)\n    On Error GoTo 0\n\n    If ws Is Nothing Then\n        Set ws = ThisWorkbook.Worksheets.Add\n        ws.Name = sheetName\n    End If\n\n    ' 清除工作表\n    ws.Cells.Clear\n\n    ' 建立多系列範例資料\n    Call FillMultiSeriesData(ws)\n\n    ' 設定資料範圍\n    Set dataRange = ws.Range(\"A1:C6\")\n\n    ' 新增圖表物件\n    Set chartObj = ws.ChartObjects.Add( _\n        Left:=ws.Range(\"E1\").Left, _\n        Top:=ws.Range(\"E1\").Top, _\n        Width:=480, _\n        Height:=320)\n\n    Set cht = chartObj.Chart\n\n    ' 設定圖表資料來源\n    cht.SetSourceData Source:=dataRange\n\n    ' 設定圖表類型為群組直條圖\n    cht.ChartType = xlColumnClustered\n\n    ' 設定圖表標題\n    cht.HasTitle = True\n    cht.ChartTitle.Text = \"各季度產品銷售比較\"\n\n    ' 設定 X 軸標題\n    With cht.Axes(xlCategory)\n        .HasTitle = True\n        .AxisTitle.Text = \"季度\"\n    End With\n\n    ' 設定 Y 軸標題\n    With cht.Axes(xlValue)\n        .HasTitle = True\n        .AxisTitle.Text = \"銷售額（萬元）\"\n    End With\n\n    ' 設定圖表樣式\n    cht.ChartStyle = 10\n\n    ' 顯示圖例\n    cht.HasLegend = True\n\n    MsgBox \"多系列長條圖已建立完成！\", vbInformation, \"完成\"\nEnd Sub\n\n' 填入多系列範例資料\nPrivate Sub FillMultiSeriesData(ByVal ws As Worksheet)\n    ' 標題列\n    ws.Range(\"A1\").Value = \"季度\"\n    ws.Range(\"B1\").Value = \"產品A\"\n    ws.Range(\"C1\").Value = \"產品B\"\n\n    ' 資料列\n    ws.Range(\"A2\").Value = \"第一季\"\n    ws.Range(\"B2\").Value = 320\n    ws.Range(\"C2\").Value = 280\n\n    ws.Range(\"A3\").Value = \"第二季\"\n    ws.Range(\"B3\").Value = 450\n    ws.Range(\"C3\").Value = 390\n\n    ws.Range(\"A4\").Value = \"第三季\"\n    ws.Range(\"B4\").Value = 380\n    ws.Range(\"C4\").Value = 420\n\n    ws.Range(\"A5\").Value = \"第四季\"\n    ws.Range(\"B5\").Value = 510\n    ws.Range(\"C5\").Value = 480\n\n    ws.Range(\"A6\").Value = \"全年合計\"\n    ws.Range(\"B6\").Value = 1660\n    ws.Range(\"C6\").Value = 1570\n\n    ' 自動調整欄寬\n    ws.Columns(\"A:C\").AutoFit\nEnd Sub", "content_b64": ""}, {"name": "BubbleChartExample.bas", "path": "模組/ChartsNormal/BubbleChartExample.bas", "content": "Option Explicit\nAttribute VB_Name = \"BubbleChartExample\"\n'*************************************************************************************\n'模組名稱: 泡泡圖範例\n'功能描述: 在 Excel 中建立泡泡圖的範例程式\n'\n'版權所有: Dunk\n'程式設計: Dunk\n'撰寫日期: 2026/5/4\n'\n'傳入參數:\n'傳回值:\n'\n'*************************************************************************************\n\n' 測試用入口\nSub TestBubbleChart()\n    Call CreateBubbleChart(\"泡泡圖範例\")\nEnd Sub\n\n' 建立泡泡圖\n' sheetName: 要建立圖表的工作表名稱\nSub CreateBubbleChart(ByVal sheetName As String)\n    On Error GoTo ErrorHandler\n\n    Dim ws As Worksheet\n    Dim chartObj As ChartObject\n    Dim cht As Chart\n    Dim seriesItem As Series\n\n    Set ws = GetOrCreateWorksheet(sheetName)\n    ws.Cells.Clear\n\n    Call FillBubbleChartData(ws)\n\n    Set chartObj = ws.ChartObjects.Add( _\n        Left:=ws.Range(\"F1\").Left, _\n        Top:=ws.Range(\"F1\").Top, _\n        Width:=480, _\n        Height:=340)\n\n    Set cht = chartObj.Chart\n    cht.ChartType = xlBubble\n    cht.HasTitle = True\n    cht.ChartTitle.Text = \"廣告支出、銷售額與客戶數分析\"\n    cht.HasLegend = False\n\n    Set seriesItem = cht.SeriesCollection.NewSeries\n    With seriesItem\n        .Name = \"市場資料\"\n        .XValues = ws.Range(\"B2:B8\")\n        .Values = ws.Range(\"C2:C8\")\n        .BubbleSizes = ws.Range(\"D2:D8\")\n        .HasDataLabels = True\n        .DataLabels.ShowSeriesName = False\n        .DataLabels.ShowCategoryName = False\n        .DataLabels.ShowValue = False\n    End With\n\n    With cht.Axes(xlCategory)\n        .HasTitle = True\n        .AxisTitle.Text = \"廣告支出（萬元）\"\n    End With\n\n    With cht.Axes(xlValue)\n        .HasTitle = True\n        .AxisTitle.Text = \"銷售額（萬元）\"\n    End With\n\n    cht.ChartStyle = 18\n\n    MsgBox \"泡泡圖已建立完成！\", vbInformation, \"完成\"\n    Exit Sub\n\nErrorHandler:\n    MsgBox \"建立泡泡圖時發生錯誤：\" & Err.Description, vbExclamation, \"錯誤\"\nEnd Sub\n\n' 取得或建立工作表\nPrivate Function GetOrCreateWorksheet(ByVal sheetName As String) As Worksheet\n    On Error Resume Next\n    Set GetOrCreateWorksheet = ThisWorkbook.Worksheets(sheetName)\n    On Error GoTo 0\n\n    If GetOrCreateWorksheet Is Nothing Then\n        Set GetOrCreateWorksheet = ThisWorkbook.Worksheets.Add\n        GetOrCreateWorksheet.Name = sheetName\n    End If\nEnd Function\n\n' 輸入泡泡圖範例資料\nPrivate Sub FillBubbleChartData(ByVal ws As Worksheet)\n    ws.Range(\"A1\").Value = \"區域\"\n    ws.Range(\"B1\").Value = \"廣告支出\"\n    ws.Range(\"C1\").Value = \"銷售額\"\n    ws.Range(\"D1\").Value = \"客戶數\"\n\n    ws.Range(\"A2\").Value = \"北區\"\n    ws.Range(\"B2\").Value = 35\n    ws.Range(\"C2\").Value = 260\n    ws.Range(\"D2\").Value = 120\n\n    ws.Range(\"A3\").Value = \"中區\"\n    ws.Range(\"B3\").Value = 28\n    ws.Range(\"C3\").Value = 210\n    ws.Range(\"D3\").Value = 95\n\n    ws.Range(\"A4\").Value = \"南區\"\n    ws.Range(\"B4\").Value = 32\n    ws.Range(\"C4\").Value = 235\n    ws.Range(\"D4\").Value = 110\n\n    ws.Range(\"A5\").Value = \"東區\"\n    ws.Range(\"B5\").Value = 18\n    ws.Range(\"C5\").Value = 130\n    ws.Range(\"D5\").Value = 65\n\n    ws.Range(\"A6\").Value = \"海外A\"\n    ws.Range(\"B6\").Value = 45\n    ws.Range(\"C6\").Value = 340\n    ws.Range(\"D6\").Value = 150\n\n    ws.Range(\"A7\").Value = \"海外B\"\n    ws.Range(\"B7\").Value = 22\n    ws.Range(\"C7\").Value = 170\n    ws.Range(\"D7\").Value = 80\n\n    ws.Range(\"A8\").Value = \"電商\"\n    ws.Range(\"B8\").Value = 50\n    ws.Range(\"C8\").Value = 390\n    ws.Range(\"D8\").Value = 180\n\n    ws.Columns(\"A:D\").AutoFit\nEnd Sub", "content_b64": ""}, {"name": "ComboChartExample.bas", "path": "模組/ChartsNormal/ComboChartExample.bas", "content": "Option Explicit\nAttribute VB_Name = \"ComboChartExample\"\n'*************************************************************************************\n'模組名稱: 組合圖範例\n'功能描述: 在 Excel 中建立直條圖與折線圖組合圖的範例程式\n'\n'版權所有: Dunk\n'程式設計: Dunk\n'撰寫日期: 2026/5/4\n'\n'傳入參數:\n'傳回值:\n'\n'*************************************************************************************\n\n' 測試用入口\nSub TestComboChart()\n    Call CreateComboChart(\"組合圖範例\")\nEnd Sub\n\n' 建立組合圖\n' sheetName: 要建立圖表的工作表名稱\nSub CreateComboChart(ByVal sheetName As String)\n    On Error GoTo ErrorHandler\n\n    Dim ws As Worksheet\n    Dim chartObj As ChartObject\n    Dim cht As Chart\n    Dim dataRange As Range\n\n    Set ws = GetOrCreateWorksheet(sheetName)\n    ws.Cells.Clear\n\n    Call FillComboChartData(ws)\n    Set dataRange = ws.Range(\"A1:C7\")\n\n    Set chartObj = ws.ChartObjects.Add( _\n        Left:=ws.Range(\"E1\").Left, _\n        Top:=ws.Range(\"E1\").Top, _\n        Width:=500, _\n        Height:=340)\n\n    Set cht = chartObj.Chart\n    cht.SetSourceData Source:=dataRange\n    cht.ChartType = xlColumnClustered\n\n    With cht.SeriesCollection(2)\n        .ChartType = xlLineMarkers\n        .AxisGroup = xlSecondary\n        .HasDataLabels = True\n    End With\n\n    cht.HasTitle = True\n    cht.ChartTitle.Text = \"營收與毛利率組合圖\"\n    cht.HasLegend = True\n    cht.Legend.Position = xlLegendPositionBottom\n\n    With cht.Axes(xlCategory)\n        .HasTitle = True\n        .AxisTitle.Text = \"月份\"\n    End With\n\n    With cht.Axes(xlValue, xlPrimary)\n        .HasTitle = True\n        .AxisTitle.Text = \"營收（萬元）\"\n    End With\n\n    With cht.Axes(xlValue, xlSecondary)\n        .HasTitle = True\n        .AxisTitle.Text = \"毛利率\"\n        .TickLabels.NumberFormat = \"0%\"\n    End With\n\n    cht.ChartStyle = 5\n\n    MsgBox \"組合圖已建立完成！\", vbInformation, \"完成\"\n    Exit Sub\n\nErrorHandler:\n    MsgBox \"建立組合圖時發生錯誤：\" & Err.Description, vbExclamation, \"錯誤\"\nEnd Sub\n\n' 取得或建立工作表\nPrivate Function GetOrCreateWorksheet(ByVal sheetName As String) As Worksheet\n    On Error Resume Next\n    Set GetOrCreateWorksheet = ThisWorkbook.Worksheets(sheetName)\n    On Error GoTo 0\n\n    If GetOrCreateWorksheet Is Nothing Then\n        Set GetOrCreateWorksheet = ThisWorkbook.Worksheets.Add\n        GetOrCreateWorksheet.Name = sheetName\n    End If\nEnd Function\n\n' 輸入組合圖範例資料\nPrivate Sub FillComboChartData(ByVal ws As Worksheet)\n    ws.Range(\"A1\").Value = \"月份\"\n    ws.Range(\"B1\").Value = \"營收\"\n    ws.Range(\"C1\").Value = \"毛利率\"\n\n    ws.Range(\"A2\").Value = \"一月\"\n    ws.Range(\"B2\").Value = 420\n    ws.Range(\"C2\").Value = 0.31\n\n    ws.Range(\"A3\").Value = \"二月\"\n    ws.Range(\"B3\").Value = 455\n    ws.Range(\"C3\").Value = 0.33\n\n    ws.Range(\"A4\").Value = \"三月\"\n    ws.Range(\"B4\").Value = 510\n    ws.Range(\"C4\").Value = 0.35\n\n    ws.Range(\"A5\").Value = \"四月\"\n    ws.Range(\"B5\").Value = 498\n    ws.Range(\"C5\").Value = 0.34\n\n    ws.Range(\"A6\").Value = \"五月\"\n    ws.Range(\"B6\").Value = 560\n    ws.Range(\"C6\").Value = 0.37\n\n    ws.Range(\"A7\").Value = \"六月\"\n    ws.Range(\"B7\").Value = 610\n    ws.Range(\"C7\").Value = 0.39\n\n    ws.Range(\"C2:C7\").NumberFormat = \"0%\"\n    ws.Columns(\"A:C\").AutoFit\nEnd Sub", "content_b64": ""}, {"name": "DoughnutChartExample.bas", "path": "模組/ChartsNormal/DoughnutChartExample.bas", "content": "Attribute VB_Name = \"DoughnutChartExample\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: DoughnutChartExample\n'功能說明: 在Excel中建立圓環圖的範例程式\n'\n'著作權所有: Dunk\n'程式設計: Dunk\n'撰寫日期: 2026/5/7\n'\n'*************************************************************************************\n\n' 測試用入口\nSub TestDoughnutChart()\n    Call CreateDoughnutChart(\"圓環圖範例\")\nEnd Sub\n\n' 建立圓環圖\n' sheetName: 要建立圖表的工作表名稱\nSub CreateDoughnutChart(ByVal sheetName As String)\n    Dim ws As Worksheet\n    Dim chartObj As ChartObject\n    Dim cht As Chart\n    Dim dataRange As Range\n\n    On Error Resume Next\n    Set ws = ThisWorkbook.Worksheets(sheetName)\n    On Error GoTo 0\n\n    If ws Is Nothing Then\n        Set ws = ThisWorkbook.Worksheets.Add\n        ws.Name = sheetName\n    End If\n\n    ws.Cells.Clear\n    Call FillDepartmentData(ws)\n\n    Set dataRange = ws.Range(\"A1:B6\")\n\n    Set chartObj = ws.ChartObjects.Add( _\n        Left:=ws.Range(\"D1\").Left, _\n        Top:=ws.Range(\"D1\").Top, _\n        Width:=400, _\n        Height:=300)\n\n    Set cht = chartObj.Chart\n    cht.SetSourceData Source:=dataRange\n    cht.ChartType = xlDoughnut\n    cht.HasTitle = True\n    cht.ChartTitle.Text = \"各部門費用佔比\"\n    cht.HasLegend = True\n    cht.Legend.Position = xlLegendPositionRight\n\n    With cht.SeriesCollection(1)\n        .HasDataLabels = True\n        .DataLabels.ShowPercentage = True\n        .DataLabels.ShowValue = False\n        .DataLabels.Position = xlLabelPositionCenter\n    End With\n\n    cht.SeriesCollection(1).DoughnutHoleSize = 50\n\n    MsgBox \"圓環圖已建立完成！\", vbInformation, \"完成\"\nEnd Sub\n\n' 填入部門費用範例資料\nPrivate Sub FillDepartmentData(ByVal ws As Worksheet)\n    ws.Range(\"A1\").Value = \"部門\"\n    ws.Range(\"B1\").Value = \"費用\"\n    ws.Range(\"A2\").Value = \"研發部\"\n    ws.Range(\"B2\").Value = 350000\n    ws.Range(\"A3\").Value = \"業務部\"\n    ws.Range(\"B3\").Value = 280000\n    ws.Range(\"A4\").Value = \"行政部\"\n    ws.Range(\"B4\").Value = 120000\n    ws.Range(\"A5\").Value = \"人資部\"\n    ws.Range(\"B5\").Value = 90000\n    ws.Range(\"A6\").Value = \"財務部\"\n    ws.Range(\"B6\").Value = 160000\n    ws.Columns(\"A:B\").AutoFit\nEnd Sub\n", "content_b64": ""}, {"name": "HistogramChartExample.bas", "path": "模組/ChartsNormal/HistogramChartExample.bas", "content": "Attribute VB_Name = \"HistogramChartExample\"\n\nOption Explicit\n\n\n\n' ============================================================\n\n' 範例：建立長條圖（直方圖）並設定格式\n\n' 功能：在新工作表上建立頻率分布直方圖\n\n' ============================================================\n\nSub CreateHistogramChartExample()\n\n    Dim ws      As Worksheet\n\n    Dim chObj   As ChartObject\n\n    Dim ch      As Chart\n\n    Dim rngData As Range\n\n\n\n    ' --- 準備示範資料 ---\n\n    On Error GoTo ErrHandler\n\n    Set ws = ThisWorkbook.Worksheets.Add\n\n    ws.Name = \"HistogramDemo\"\n\n\n\n    ws.Cells(1, 1).Value = \"區間\"\n\n    ws.Cells(1, 2).Value = \"頻率\"\n\n    ws.Cells(2, 1).Value = \"0-10\"\n\n    ws.Cells(2, 2).Value = 5\n\n    ws.Cells(3, 1).Value = \"11-20\"\n\n    ws.Cells(3, 2).Value = 12\n\n    ws.Cells(4, 1).Value = \"21-30\"\n\n    ws.Cells(4, 2).Value = 20\n\n    ws.Cells(5, 1).Value = \"31-40\"\n\n    ws.Cells(5, 2).Value = 18\n\n    ws.Cells(6, 1).Value = \"41-50\"\n\n    ws.Cells(6, 2).Value = 8\n\n\n\n    Set rngData = ws.Range(\"A1:B6\")\n\n\n\n    ' --- 建立圖表物件 ---\n\n    Set chObj = ws.ChartObjects.Add(Left:=20, Top:=80, Width:=400, Height:=260)\n\n    Set ch = chObj.Chart\n\n\n\n    ch.SetSourceData Source:=rngData, PlotBy:=xlColumns\n\n    ch.ChartType = xlColumnClustered\n\n\n\n    ' --- 設定標題與軸標籤 ---\n\n    ch.HasTitle = True\n\n    ch.ChartTitle.Text = \"頻率分布直方圖\"\n\n\n\n    ch.Axes(xlCategory, xlPrimary).HasTitle = True\n\n    ch.Axes(xlCategory, xlPrimary).AxisTitle.Text = \"區間\"\n\n\n\n    ch.Axes(xlValue, xlPrimary).HasTitle = True\n\n    ch.Axes(xlValue, xlPrimary).AxisTitle.Text = \"頻率\"\n\n\n\n    ' --- 移除數列間隙，使直方圖外觀更貼近 ---\n\n    ch.SeriesCollection(1).GapWidth = 0\n\n    ch.SeriesCollection(1).Interior.Color = RGB(70, 130, 180)\n\n\n\n    MsgBox \"直方圖已建立於工作表：\" & ws.Name, vbInformation\n\n    Exit Sub\n\n\n\nErrHandler:\n\n    MsgBox \"發生錯誤：\" & Err.Description, vbCritical\n\nEnd Sub\n\n", "content_b64": ""}, {"name": "LineChartExample.bas", "path": "模組/ChartsNormal/LineChartExample.bas", "content": "Attribute VB_Name = \"LineChartExample\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: 折線圖範例\n'功能描述: 在Excel中建立折線圖的範例程式\n'\n'版權所有: Dunk\n'程式設計: Dunk\n'撰寫日期: 2026/5/3\n'\n'傳入參數:\n'傳回資料:\n'\n'*************************************************************************************\n\n' 簡化測試入口\nSub TestLineChart()\n    Call CreateLineChart(\"折線圖範例\")\nEnd Sub\n\n' 建立單系列折線圖\n' sheetName: 要建立圖表的工作表名稱\nSub CreateLineChart(ByVal sheetName As String)\n    Dim ws As Worksheet\n    Dim chartObj As ChartObject\n    Dim cht As Chart\n    Dim dataRange As Range\n\n    ' 取得或建立工作表\n    On Error Resume Next\n    Set ws = ThisWorkbook.Worksheets(sheetName)\n    On Error GoTo 0\n\n    If ws Is Nothing Then\n        Set ws = ThisWorkbook.Worksheets.Add\n        ws.Name = sheetName\n    End If\n\n    ' 清除工作表\n    ws.Cells.Clear\n\n    ' 建立範例資料\n    Call FillLineChartData(ws)\n\n    ' 設定資料範圍 (A1:B13)\n    Set dataRange = ws.Range(\"A1:B13\")\n\n    ' 在工作表中新增圖表物件\n    Set chartObj = ws.ChartObjects.Add( _\n        Left:=ws.Range(\"D1\").Left, _\n        Top:=ws.Range(\"D1\").Top, _\n        Width:=420, _\n        Height:=300)\n\n    Set cht = chartObj.Chart\n\n    ' 設定圖表資料來源\n    cht.SetSourceData Source:=dataRange\n\n    ' 設定圖表類型為含資料標記的折線圖\n    cht.ChartType = xlLineMarkers\n\n    ' 設定圖表標題\n    cht.HasTitle = True\n    cht.ChartTitle.Text = \"全年每月氣溫趨勢\"\n\n    ' 設定 X 軸標題\n    With cht.Axes(xlCategory)\n        .HasTitle = True\n        .AxisTitle.Text = \"月份\"\n    End With\n\n    ' 設定 Y 軸標題\n    With cht.Axes(xlValue)\n        .HasTitle = True\n        .AxisTitle.Text = \"平均氣溫 (°C)\"\n        .MinimumScale = 0\n        .MaximumScale = 40\n    End With\n\n    ' 設定圖表樣式\n    cht.ChartStyle = 4\n\n    ' 顯示資料標籤\n    cht.SeriesCollection(1).HasDataLabels = True\n\n    ' 設定折線平滑化\n    cht.SeriesCollection(1).Smooth = True\n\n    MsgBox \"折線圖已建立完成！\", vbInformation, \"完成\"\nEnd Sub\n\n' 建立雙系列折線圖（年度比較）\nSub CreateCompareLineChart()\n    Dim ws As Worksheet\n    Dim chartObj As ChartObject\n    Dim cht As Chart\n    Dim dataRange As Range\n    Dim sheetName As String\n\n    sheetName = \"折線圖年度比較\"\n\n    ' 取得或建立工作表\n    On Error Resume Next\n    Set ws = ThisWorkbook.Worksheets(sheetName)\n    On Error GoTo 0\n\n    If ws Is Nothing Then\n        Set ws = ThisWorkbook.Worksheets.Add\n        ws.Name = sheetName\n    End If\n\n    ' 清除工作表\n    ws.Cells.Clear\n\n    ' 建立雙系列範例資料\n    Call FillCompareLineData(ws)\n\n    ' 設定資料範圍\n    Set dataRange = ws.Range(\"A1:C7\")\n\n    ' 新增圖表物件\n    Set chartObj = ws.ChartObjects.Add( _\n        Left:=ws.Range(\"E1\").Left, _\n        Top:=ws.Range(\"E1\").Top, _\n        Width:=480, _\n        Height:=320)\n\n    Set cht = chartObj.Chart\n\n    ' 設定圖表資料來源\n    cht.SetSourceData Source:=dataRange\n\n    ' 設定圖表類型\n    cht.ChartType = xlLineMarkers\n\n    ' 設定圖表標題\n    cht.HasTitle = True\n    cht.ChartTitle.Text = \"上下半年業績趨勢比較\"\n\n    ' 設定 X 軸標題\n    With cht.Axes(xlCategory)\n        .HasTitle = True\n        .AxisTitle.Text = \"季度\"\n    End With\n\n    ' 設定 Y 軸標題\n    With cht.Axes(xlValue)\n        .HasTitle = True\n        .AxisTitle.Text = \"業績（萬元）\"\n    End With\n\n    ' 設定圖表樣式\n    cht.ChartStyle = 12\n\n    ' 顯示圖例\n    cht.HasLegend = True\n\n    MsgBox \"雙系列折線圖已建立完成！\", vbInformation, \"完成\"\nEnd Sub\n\n' 填入折線圖範例資料（月份氣溫）\nPrivate Sub FillLineChartData(ByVal ws As Worksheet)\n    ' 標題列\n    ws.Range(\"A1\").Value = \"月份\"\n    ws.Range(\"B1\").Value = \"平均氣溫\"\n\n    ' 資料列\n    ws.Range(\"A2\").Value = \"1月\"\n    ws.Range(\"B2\").Value = 16\n\n    ws.Range(\"A3\").Value = \"2月\"\n    ws.Range(\"B3\").Value = 17\n\n    ws.Range(\"A4\").Value = \"3月\"\n    ws.Range(\"B4\").Value = 20\n\n    ws.Range(\"A5\").Value = \"4月\"\n    ws.Range(\"B5\").Value = 24\n\n    ws.Range(\"A6\").Value = \"5月\"\n    ws.Range(\"B6\").Value = 28\n\n    ws.Range(\"A7\").Value = \"6月\"\n    ws.Range(\"B7\").Value = 32\n\n    ws.Range(\"A8\").Value = \"7月\"\n    ws.Range(\"B8\").Value = 34\n\n    ws.Range(\"A9\").Value = \"8月\"\n    ws.Range(\"B9\").Value = 34\n\n    ws.Range(\"A10\").Value = \"9月\"\n    ws.Range(\"B10\").Value = 30\n\n    ws.Range(\"A11\").Value = \"10月\"\n    ws.Range(\"B11\").Value = 26\n\n    ws.Range(\"A12\").Value = \"11月\"\n    ws.Range(\"B12\").Value = 22\n\n    ws.Range(\"A13\").Value = \"12月\"\n    ws.Range(\"B13\").Value = 18\n\n    ' 自動調整欄寬\n    ws.Columns(\"A:B\").AutoFit\nEnd Sub\n\n' 填入雙系列折線圖範例資料\nPrivate Sub FillCompareLineData(ByVal ws As Worksheet)\n    ' 標題列\n    ws.Range(\"A1\").Value = \"季度\"\n    ws.Range(\"B1\").Value = \"上半年\"\n    ws.Range(\"C1\").Value = \"下半年\"\n\n    ' 資料列\n    ws.Range(\"A2\").Value = \"第一季\"\n    ws.Range(\"B2\").Value = 280\n    ws.Range(\"C2\").Value = 310\n\n    ws.Range(\"A3\").Value = \"第二季\"\n    ws.Range(\"B3\").Value = 350\n    ws.Range(\"C3\").Value = 420\n\n    ws.Range(\"A4\").Value = \"第三季\"\n    ws.Range(\"B4\").Value = 410\n    ws.Range(\"C4\").Value = 390\n\n    ws.Range(\"A5\").Value = \"第四季\"\n    ws.Range(\"B5\").Value = 380\n    ws.Range(\"C5\").Value = 450\n\n    ws.Range(\"A6\").Value = \"第五季\"\n    ws.Range(\"B6\").Value = 460\n    ws.Range(\"C6\").Value = 500\n\n    ws.Range(\"A7\").Value = \"第六季\"\n    ws.Range(\"B7\").Value = 520\n    ws.Range(\"C7\").Value = 480\n\n    ' 自動調整欄寬\n    ws.Columns(\"A:C\").AutoFit\nEnd Sub", "content_b64": ""}, {"name": "PieChartExample.bas", "path": "模組/ChartsNormal/PieChartExample.bas", "content": "Attribute VB_Name = \"PieChartExample\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: 圓餅圖範例\n'功能描述: 在Excel中建立圓餅圖的範例程式\n'\n'版權所有: Dunk\n'程式設計: Dunk\n'撰寫日期: 2026/5/3\n'\n'傳入參數:\n'傳回資料:\n'\n'*************************************************************************************\n\n' 簡化測試入口\nSub TestPieChart()\n    Call CreatePieChart(\"圓餅圖範例\")\nEnd Sub\n\n' 建立圓餅圖\n' sheetName: 要建立圖表的工作表名稱\nSub CreatePieChart(ByVal sheetName As String)\n    Dim ws As Worksheet\n    Dim chartObj As ChartObject\n    Dim cht As Chart\n    Dim dataRange As Range\n\n    ' 取得或建立工作表\n    On Error Resume Next\n    Set ws = ThisWorkbook.Worksheets(sheetName)\n    On Error GoTo 0\n\n    If ws Is Nothing Then\n        Set ws = ThisWorkbook.Worksheets.Add\n        ws.Name = sheetName\n    End If\n\n    ' 清除工作表\n    ws.Cells.Clear\n\n    ' 建立範例資料\n    Call FillPieChartData(ws)\n\n    ' 設定資料範圍 (A1:B6)\n    Set dataRange = ws.Range(\"A1:B6\")\n\n    ' 在工作表中新增圖表物件\n    Set chartObj = ws.ChartObjects.Add( _\n        Left:=ws.Range(\"D1\").Left, _\n        Top:=ws.Range(\"D1\").Top, _\n        Width:=400, _\n        Height:=320)\n\n    Set cht = chartObj.Chart\n\n    ' 設定圖表資料來源\n    cht.SetSourceData Source:=dataRange\n\n    ' 設定圖表類型為圓餅圖\n    cht.ChartType = xlPie\n\n    ' 設定圖表標題\n    cht.HasTitle = True\n    cht.ChartTitle.Text = \"產品市場佔有率分析\"\n\n    ' 顯示圖例\n    cht.HasLegend = True\n    cht.Legend.Position = xlLegendPositionRight\n\n    ' 顯示資料標籤（含百分比）\n    With cht.SeriesCollection(1)\n        .HasDataLabels = True\n        With .DataLabels\n            .ShowPercentage = True\n            .ShowCategoryName = True\n            .ShowValue = False\n            .Separator = Chr(10)\n        End With\n    End With\n\n    ' 設定圖表樣式\n    cht.ChartStyle = 26\n\n    MsgBox \"圓餅圖已建立完成！\", vbInformation, \"完成\"\nEnd Sub\n\n' 建立環圈圖（圓餅圖變體）\nSub CreateDonutChart()\n    Dim ws As Worksheet\n    Dim chartObj As ChartObject\n    Dim cht As Chart\n    Dim dataRange As Range\n    Dim sheetName As String\n\n    sheetName = \"環圈圖範例\"\n\n    ' 取得或建立工作表\n    On Error Resume Next\n    Set ws = ThisWorkbook.Worksheets(sheetName)\n    On Error GoTo 0\n\n    If ws Is Nothing Then\n        Set ws = ThisWorkbook.Worksheets.Add\n        ws.Name = sheetName\n    End If\n\n    ' 清除工作表\n    ws.Cells.Clear\n\n    ' 建立範例資料\n    Call FillDonutChartData(ws)\n\n    ' 設定資料範圍\n    Set dataRange = ws.Range(\"A1:B7\")\n\n    ' 新增圖表物件\n    Set chartObj = ws.ChartObjects.Add( _\n        Left:=ws.Range(\"D1\").Left, _\n        Top:=ws.Range(\"D1\").Top, _\n        Width:=420, _\n        Height:=340)\n\n    Set cht = chartObj.Chart\n\n    ' 設定圖表資料來源\n    cht.SetSourceData Source:=dataRange\n\n    ' 設定圖表類型為環圈圖\n    cht.ChartType = xlDoughnut\n\n    ' 設定圖表標題\n    cht.HasTitle = True\n    cht.ChartTitle.Text = \"部門預算分配比例\"\n\n    ' 顯示圖例\n    cht.HasLegend = True\n    cht.Legend.Position = xlLegendPositionBottom\n\n    ' 顯示資料標籤\n    With cht.SeriesCollection(1)\n        .HasDataLabels = True\n        With .DataLabels\n            .ShowPercentage = True\n            .ShowCategoryName = True\n            .ShowValue = False\n        End With\n    End With\n\n    ' 設定圖表樣式\n    cht.ChartStyle = 26\n\n    MsgBox \"環圈圖已建立完成！\", vbInformation, \"完成\"\nEnd Sub\n\n' 填入圓餅圖範例資料（產品市佔率）\nPrivate Sub FillPieChartData(ByVal ws As Worksheet)\n    ' 標題列\n    ws.Range(\"A1\").Value = \"產品\"\n    ws.Range(\"B1\").Value = \"市占率\"\n\n    ' 資料列\n    ws.Range(\"A2\").Value = \"產品A\"\n    ws.Range(\"B2\").Value = 35\n\n    ws.Range(\"A3\").Value = \"產品B\"\n    ws.Range(\"B3\").Value = 25\n\n    ws.Range(\"A4\").Value = \"產品C\"\n    ws.Range(\"B4\").Value = 20\n\n    ws.Range(\"A5\").Value = \"產品D\"\n    ws.Range(\"B5\").Value = 12\n\n    ws.Range(\"A6\").Value = \"其他\"\n    ws.Range(\"B6\").Value = 8\n\n    ' 自動調整欄寬\n    ws.Columns(\"A:B\").AutoFit\nEnd Sub\n\n' 填入環圈圖範例資料（部門預算）\nPrivate Sub FillDonutChartData(ByVal ws As Worksheet)\n    ' 標題列\n    ws.Range(\"A1\").Value = \"部門\"\n    ws.Range(\"B1\").Value = \"預算（萬元）\"\n\n    ' 資料列\n    ws.Range(\"A2\").Value = \"業務部\"\n    ws.Range(\"B2\").Value = 500\n\n    ws.Range(\"A3\").Value = \"研發部\"\n    ws.Range(\"B3\").Value = 800\n\n    ws.Range(\"A4\").Value = \"行銷部\"\n    ws.Range(\"B4\").Value = 350\n\n    ws.Range(\"A5\").Value = \"人資部\"\n    ws.Range(\"B5\").Value = 200\n\n    ws.Range(\"A6\").Value = \"財務部\"\n    ws.Range(\"B6\").Value = 150\n\n    ws.Range(\"A7\").Value = \"資訊部\"\n    ws.Range(\"B7\").Value = 300\n\n    ' 自動調整欄寬\n    ws.Columns(\"A:B\").AutoFit\nEnd Sub", "content_b64": ""}, {"name": "RadarChartExample.bas", "path": "模組/ChartsNormal/RadarChartExample.bas", "content": "Option Explicit\nAttribute VB_Name = \"RadarChartExample\"\n'*************************************************************************************\n'模組名稱: 雷達圖範例\n'功能描述: 在 Excel 中建立雷達圖的範例程式\n'\n'版權所有: Dunk\n'程式設計: Dunk\n'撰寫日期: 2026/5/4\n'\n'傳入參數:\n'傳回值:\n'\n'*************************************************************************************\n\n' 測試用入口\nSub TestRadarChart()\n    Call CreateRadarChart(\"雷達圖範例\")\nEnd Sub\n\n' 建立雷達圖\n' sheetName: 要建立圖表的工作表名稱\nSub CreateRadarChart(ByVal sheetName As String)\n    On Error GoTo ErrorHandler\n\n    Dim ws As Worksheet\n    Dim chartObj As ChartObject\n    Dim cht As Chart\n    Dim dataRange As Range\n\n    Set ws = GetOrCreateWorksheet(sheetName)\n    ws.Cells.Clear\n\n    Call FillRadarChartData(ws)\n    Set dataRange = ws.Range(\"A1:C7\")\n\n    Set chartObj = ws.ChartObjects.Add( _\n        Left:=ws.Range(\"E1\").Left, _\n        Top:=ws.Range(\"E1\").Top, _\n        Width:=440, _\n        Height:=340)\n\n    Set cht = chartObj.Chart\n    cht.SetSourceData Source:=dataRange\n    cht.ChartType = xlRadarMarkers\n\n    cht.HasTitle = True\n    cht.ChartTitle.Text = \"部門能力評估雷達圖\"\n    cht.HasLegend = True\n    cht.Legend.Position = xlLegendPositionBottom\n    cht.ChartStyle = 27\n\n    MsgBox \"雷達圖已建立完成！\", vbInformation, \"完成\"\n    Exit Sub\n\nErrorHandler:\n    MsgBox \"建立雷達圖時發生錯誤：\" & Err.Description, vbExclamation, \"錯誤\"\nEnd Sub\n\n' 取得或建立工作表\nPrivate Function GetOrCreateWorksheet(ByVal sheetName As String) As Worksheet\n    On Error Resume Next\n    Set GetOrCreateWorksheet = ThisWorkbook.Worksheets(sheetName)\n    On Error GoTo 0\n\n    If GetOrCreateWorksheet Is Nothing Then\n        Set GetOrCreateWorksheet = ThisWorkbook.Worksheets.Add\n        GetOrCreateWorksheet.Name = sheetName\n    End If\nEnd Function\n\n' 輸入雷達圖範例資料\nPrivate Sub FillRadarChartData(ByVal ws As Worksheet)\n    ws.Range(\"A1\").Value = \"指標\"\n    ws.Range(\"B1\").Value = \"業務部\"\n    ws.Range(\"C1\").Value = \"客服部\"\n\n    ws.Range(\"A2\").Value = \"效率\"\n    ws.Range(\"B2\").Value = 85\n    ws.Range(\"C2\").Value = 78\n\n    ws.Range(\"A3\").Value = \"品質\"\n    ws.Range(\"B3\").Value = 80\n    ws.Range(\"C3\").Value = 92\n\n    ws.Range(\"A4\").Value = \"成本\"\n    ws.Range(\"B4\").Value = 76\n    ws.Range(\"C4\").Value = 83\n\n    ws.Range(\"A5\").Value = \"創新\"\n    ws.Range(\"B5\").Value = 88\n    ws.Range(\"C5\").Value = 70\n\n    ws.Range(\"A6\").Value = \"協作\"\n    ws.Range(\"B6\").Value = 82\n    ws.Range(\"C6\").Value = 90\n\n    ws.Range(\"A7\").Value = \"穩定\"\n    ws.Range(\"B7\").Value = 79\n    ws.Range(\"C7\").Value = 86\n\n    ws.Columns(\"A:C\").AutoFit\nEnd Sub", "content_b64": ""}, {"name": "ScatterChartExample.bas", "path": "模組/ChartsNormal/ScatterChartExample.bas", "content": "Attribute VB_Name = \"ScatterChartExample\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: 散佈圖範例\n'功能描述: 在Excel中建立XY散佈圖的範例程式\n'\n'版權所有: Dunk\n'程式設計: Dunk\n'撰寫日期: 2026/5/3\n'\n'傳入參數:\n'傳回資料:\n'\n'*************************************************************************************\n\n' 簡化測試入口\nSub TestScatterChart()\n    Call CreateScatterChart(\"散佈圖範例\")\nEnd Sub\n\n' 建立XY散佈圖\n' sheetName: 要建立圖表的工作表名稱\nSub CreateScatterChart(ByVal sheetName As String)\n    Dim ws As Worksheet\n    Dim chartObj As ChartObject\n    Dim cht As Chart\n    Dim dataRange As Range\n\n    ' 取得或建立工作表\n    On Error Resume Next\n    Set ws = ThisWorkbook.Worksheets(sheetName)\n    On Error GoTo 0\n\n    If ws Is Nothing Then\n        Set ws = ThisWorkbook.Worksheets.Add\n        ws.Name = sheetName\n    End If\n\n    ' 清除工作表\n    ws.Cells.Clear\n\n    ' 建立範例資料\n    Call FillScatterData(ws)\n\n    ' 設定資料範圍 (A1:B11)\n    Set dataRange = ws.Range(\"A1:B11\")\n\n    ' 在工作表中新增圖表物件\n    Set chartObj = ws.ChartObjects.Add( _\n        Left:=ws.Range(\"D1\").Left, _\n        Top:=ws.Range(\"D1\").Top, _\n        Width:=420, _\n        Height:=320)\n\n    Set cht = chartObj.Chart\n\n    ' 設定圖表資料來源\n    cht.SetSourceData Source:=dataRange\n\n    ' 設定圖表類型為XY散佈圖（含資料標記）\n    cht.ChartType = xlXYScatter\n\n    ' 設定圖表標題\n    cht.HasTitle = True\n    cht.ChartTitle.Text = \"廣告費用與銷售額相關分析\"\n\n    ' 設定 X 軸標題\n    With cht.Axes(xlCategory)\n        .HasTitle = True\n        .AxisTitle.Text = \"廣告費用（萬元）\"\n    End With\n\n    ' 設定 Y 軸標題\n    With cht.Axes(xlValue)\n        .HasTitle = True\n        .AxisTitle.Text = \"銷售額（萬元）\"\n    End With\n\n    ' 設定圖表樣式\n    cht.ChartStyle = 15\n\n    ' 不顯示圖例（單系列不需要）\n    cht.HasLegend = False\n\n    MsgBox \"散佈圖已建立完成！\", vbInformation, \"完成\"\nEnd Sub\n\n' 建立含趨勢線的散佈圖\nSub CreateScatterWithTrendline()\n    Dim ws As Worksheet\n    Dim chartObj As ChartObject\n    Dim cht As Chart\n    Dim dataRange As Range\n    Dim ser As Series\n    Dim tl As Trendline\n    Dim sheetName As String\n\n    sheetName = \"散佈圖含趨勢線\"\n\n    ' 取得或建立工作表\n    On Error Resume Next\n    Set ws = ThisWorkbook.Worksheets(sheetName)\n    On Error GoTo 0\n\n    If ws Is Nothing Then\n        Set ws = ThisWorkbook.Worksheets.Add\n        ws.Name = sheetName\n    End If\n\n    ' 清除工作表\n    ws.Cells.Clear\n\n    ' 建立範例資料\n    Call FillScatterData(ws)\n\n    ' 設定資料範圍\n    Set dataRange = ws.Range(\"A1:B11\")\n\n    ' 新增圖表物件\n    Set chartObj = ws.ChartObjects.Add( _\n        Left:=ws.Range(\"D1\").Left, _\n        Top:=ws.Range(\"D1\").Top, _\n        Width:=480, _\n        Height:=360)\n\n    Set cht = chartObj.Chart\n\n    ' 設定圖表資料來源\n    cht.SetSourceData Source:=dataRange\n\n    ' 設定圖表類型為XY散佈圖（含資料標記）\n    cht.ChartType = xlXYScatter\n\n    ' 設定圖表標題\n    cht.HasTitle = True\n    cht.ChartTitle.Text = \"廣告費用與銷售額相關分析（含趨勢線）\"\n\n    ' 設定 X 軸標題\n    With cht.Axes(xlCategory)\n        .HasTitle = True\n        .AxisTitle.Text = \"廣告費用（萬元）\"\n    End With\n\n    ' 設定 Y 軸標題\n    With cht.Axes(xlValue)\n        .HasTitle = True\n        .AxisTitle.Text = \"銷售額（萬元）\"\n    End With\n\n    ' 取得第一個數列\n    Set ser = cht.SeriesCollection(1)\n\n    ' 新增線性趨勢線\n    Set tl = ser.Trendlines.Add( _\n        Type:=xlLinear, _\n        Forward:=0, _\n        Backward:=0, _\n        DisplayEquation:=True, _\n        DisplayRSquared:=True, _\n        Name:=\"線性趨勢\")\n\n    ' 設定趨勢線格式\n    With tl.Border\n        .Color = RGB(255, 0, 0)\n        .Weight = xlThin\n    End With\n\n    ' 設定圖表樣式\n    cht.ChartStyle = 15\n    cht.HasLegend = False\n\n    MsgBox \"含趨勢線的散佈圖已建立完成！\", vbInformation, \"完成\"\nEnd Sub\n\n' 填入散佈圖範例資料（廣告費用 vs 銷售額）\nPrivate Sub FillScatterData(ByVal ws As Worksheet)\n    ' 標題列\n    ws.Range(\"A1\").Value = \"廣告費用\"\n    ws.Range(\"B1\").Value = \"銷售額\"\n\n    ' 資料列（X值, Y值）\n    ws.Range(\"A2\").Value = 10\n    ws.Range(\"B2\").Value = 85\n\n    ws.Range(\"A3\").Value = 15\n    ws.Range(\"B3\").Value = 120\n\n    ws.Range(\"A4\").Value = 20\n    ws.Range(\"B4\").Value = 165\n\n    ws.Range(\"A5\").Value = 25\n    ws.Range(\"B5\").Value = 190\n\n    ws.Range(\"A6\").Value = 30\n    ws.Range(\"B6\").Value = 230\n\n    ws.Range(\"A7\").Value = 38\n    ws.Range(\"B7\").Value = 275\n\n    ws.Range(\"A8\").Value = 45\n    ws.Range(\"B8\").Value = 320\n\n    ws.Range(\"A9\").Value = 50\n    ws.Range(\"B9\").Value = 360\n\n    ws.Range(\"A10\").Value = 60\n    ws.Range(\"B10\").Value = 410\n\n    ws.Range(\"A11\").Value = 70\n    ws.Range(\"B11\").Value = 480\n\n    ' 自動調整欄寬\n    ws.Columns(\"A:B\").AutoFit\nEnd Sub", "content_b64": ""}, {"name": "StackedColumnChartExample.bas", "path": "模組/ChartsNormal/StackedColumnChartExample.bas", "content": "Option Explicit\n\n' 建立堆疊直條圖範例，呈現各月份不同區域的銷售占比。\nPublic Sub CreateStackedColumnChartExample()\n    On Error GoTo ErrHandler\n\n    Dim ws As Worksheet\n    Dim chartObj As ChartObject\n    Dim dataRange As Range\n    Dim sheetName As String\n\n    sheetName = \"堆疊直條圖範例\"\n    Set ws = GetOrCreateWorksheet(sheetName)\n    ws.Cells.Clear\n\n    Call FillStackedColumnSampleData(ws)\n    Set dataRange = ws.Range(\"A1:D7\")\n\n    Set chartObj = ws.ChartObjects.Add(Left:=ws.Range(\"F2\").Left, Top:=ws.Range(\"F2\").Top, Width:=480, Height:=320)\n    With chartObj.Chart\n        .SetSourceData Source:=dataRange\n        .ChartType = xlColumnStacked\n        .HasTitle = True\n        .ChartTitle.Text = \"各區每月銷售堆疊圖\"\n        .HasLegend = True\n        .Axes(xlCategory).HasTitle = True\n        .Axes(xlCategory).AxisTitle.Text = \"月份\"\n        .Axes(xlValue).HasTitle = True\n        .Axes(xlValue).AxisTitle.Text = \"銷售金額\"\n    End With\n\n    ws.Columns(\"A:D\").AutoFit\n    MsgBox \"堆疊直條圖已建立完成。\", vbInformation, \"完成\"\n    Exit Sub\n\nErrHandler:\n    MsgBox \"建立堆疊直條圖失敗：\" & Err.Description, vbExclamation, \"錯誤\"\nEnd Sub\n\nPrivate Sub FillStackedColumnSampleData(ByVal ws As Worksheet)\n    ws.Range(\"A1:D1\").Value = Array(\"月份\", \"北區\", \"中區\", \"南區\")\n    ws.Range(\"A2:D2\").Value = Array(\"一月\", 120, 95, 88)\n    ws.Range(\"A3:D3\").Value = Array(\"二月\", 135, 110, 92)\n    ws.Range(\"A4:D4\").Value = Array(\"三月\", 148, 125, 105)\n    ws.Range(\"A5:D5\").Value = Array(\"四月\", 142, 132, 118)\n    ws.Range(\"A6:D6\").Value = Array(\"五月\", 160, 140, 126)\n    ws.Range(\"A7:D7\").Value = Array(\"六月\", 175, 152, 139)\nEnd Sub\n\nPrivate Function GetOrCreateWorksheet(ByVal sheetName As String) As Worksheet\n    On Error Resume Next\n    Set GetOrCreateWorksheet = ThisWorkbook.Worksheets(sheetName)\n    On Error GoTo 0\n\n    If GetOrCreateWorksheet Is Nothing Then\n        Set GetOrCreateWorksheet = ThisWorkbook.Worksheets.Add\n        GetOrCreateWorksheet.Name = sheetName\n    End If\nEnd Function", "content_b64": ""}, {"name": "StockChartExample.bas", "path": "模組/ChartsNormal/StockChartExample.bas", "content": "Option Explicit\nAttribute VB_Name = \"StockChartExample\"\n'*************************************************************************************\n'模組名稱: 股價圖範例\n'功能描述: 在 Excel 中建立開高低收股價圖的範例程式\n'\n'版權所有: Dunk\n'程式設計: Dunk\n'撰寫日期: 2026/5/4\n'\n'傳入參數:\n'傳回值:\n'\n'*************************************************************************************\n\n' 測試用入口\nSub TestStockChart()\n    Call CreateStockChart(\"股價圖範例\")\nEnd Sub\n\n' 建立股價圖\n' sheetName: 要建立圖表的工作表名稱\nSub CreateStockChart(ByVal sheetName As String)\n    On Error GoTo ErrorHandler\n\n    Dim ws As Worksheet\n    Dim chartObj As ChartObject\n    Dim cht As Chart\n    Dim dataRange As Range\n\n    Set ws = GetOrCreateWorksheet(sheetName)\n    ws.Cells.Clear\n\n    Call FillStockChartData(ws)\n    Set dataRange = ws.Range(\"A1:E11\")\n\n    Set chartObj = ws.ChartObjects.Add( _\n        Left:=ws.Range(\"G1\").Left, _\n        Top:=ws.Range(\"G1\").Top, _\n        Width:=520, _\n        Height:=340)\n\n    Set cht = chartObj.Chart\n    cht.SetSourceData Source:=dataRange\n    cht.ChartType = xlStockOHLC\n\n    cht.HasTitle = True\n    cht.ChartTitle.Text = \"開高低收股價走勢\"\n    cht.HasLegend = True\n    cht.Legend.Position = xlLegendPositionBottom\n\n    With cht.Axes(xlCategory)\n        .HasTitle = True\n        .AxisTitle.Text = \"日期\"\n    End With\n\n    With cht.Axes(xlValue)\n        .HasTitle = True\n        .AxisTitle.Text = \"價格\"\n    End With\n\n    cht.ChartStyle = 2\n\n    MsgBox \"股價圖已建立完成！\", vbInformation, \"完成\"\n    Exit Sub\n\nErrorHandler:\n    MsgBox \"建立股價圖時發生錯誤：\" & Err.Description, vbExclamation, \"錯誤\"\nEnd Sub\n\n' 取得或建立工作表\nPrivate Function GetOrCreateWorksheet(ByVal sheetName As String) As Worksheet\n    On Error Resume Next\n    Set GetOrCreateWorksheet = ThisWorkbook.Worksheets(sheetName)\n    On Error GoTo 0\n\n    If GetOrCreateWorksheet Is Nothing Then\n        Set GetOrCreateWorksheet = ThisWorkbook.Worksheets.Add\n        GetOrCreateWorksheet.Name = sheetName\n    End If\nEnd Function\n\n' 輸入股價圖範例資料\nPrivate Sub FillStockChartData(ByVal ws As Worksheet)\n    ws.Range(\"A1\").Value = \"日期\"\n    ws.Range(\"B1\").Value = \"開盤\"\n    ws.Range(\"C1\").Value = \"最高\"\n    ws.Range(\"D1\").Value = \"最低\"\n    ws.Range(\"E1\").Value = \"收盤\"\n\n    ws.Range(\"A2\").Value = DateSerial(2026, 4, 1)\n    ws.Range(\"B2\").Value = 101\n    ws.Range(\"C2\").Value = 108\n    ws.Range(\"D2\").Value = 99\n    ws.Range(\"E2\").Value = 106\n\n    ws.Range(\"A3\").Value = DateSerial(2026, 4, 2)\n    ws.Range(\"B3\").Value = 106\n    ws.Range(\"C3\").Value = 110\n    ws.Range(\"D3\").Value = 103\n    ws.Range(\"E3\").Value = 104\n\n    ws.Range(\"A4\").Value = DateSerial(2026, 4, 3)\n    ws.Range(\"B4\").Value = 104\n    ws.Range(\"C4\").Value = 112\n    ws.Range(\"D4\").Value = 102\n    ws.Range(\"E4\").Value = 111\n\n    ws.Range(\"A5\").Value = DateSerial(2026, 4, 6)\n    ws.Range(\"B5\").Value = 111\n    ws.Range(\"C5\").Value = 116\n    ws.Range(\"D5\").Value = 109\n    ws.Range(\"E5\").Value = 114\n\n    ws.Range(\"A6\").Value = DateSerial(2026, 4, 7)\n    ws.Range(\"B6\").Value = 114\n    ws.Range(\"C6\").Value = 118\n    ws.Range(\"D6\").Value = 112\n    ws.Range(\"E6\").Value = 117\n\n    ws.Range(\"A7\").Value = DateSerial(2026, 4, 8)\n    ws.Range(\"B7\").Value = 117\n    ws.Range(\"C7\").Value = 120\n    ws.Range(\"D7\").Value = 113\n    ws.Range(\"E7\").Value = 115\n\n    ws.Range(\"A8\").Value = DateSerial(2026, 4, 9)\n    ws.Range(\"B8\").Value = 115\n    ws.Range(\"C8\").Value = 121\n    ws.Range(\"D8\").Value = 114\n    ws.Range(\"E8\").Value = 119\n\n    ws.Range(\"A9\").Value = DateSerial(2026, 4, 10)\n    ws.Range(\"B9\").Value = 119\n    ws.Range(\"C9\").Value = 124\n    ws.Range(\"D9\").Value = 118\n    ws.Range(\"E9\").Value = 123\n\n    ws.Range(\"A10\").Value = DateSerial(2026, 4, 13)\n    ws.Range(\"B10\").Value = 123\n    ws.Range(\"C10\").Value = 126\n    ws.Range(\"D10\").Value = 120\n    ws.Range(\"E10\").Value = 121\n\n    ws.Range(\"A11\").Value = DateSerial(2026, 4, 14)\n    ws.Range(\"B11\").Value = 121\n    ws.Range(\"C11\").Value = 128\n    ws.Range(\"D11\").Value = 119\n    ws.Range(\"E11\").Value = 126\n\n    ws.Range(\"A2:A11\").NumberFormat = \"yyyy/mm/dd\"\n    ws.Columns(\"A:E\").AutoFit\nEnd Sub", "content_b64": ""}, {"name": "SurfaceChartExample.bas", "path": "模組/ChartsNormal/SurfaceChartExample.bas", "content": "Option Explicit\nAttribute VB_Name = \"SurfaceChartExample\"\n'*************************************************************************************\n'模組名稱: 曲面圖範例\n'功能描述: 在 Excel 中建立三維曲面圖的範例程式\n'\n'版權所有: Dunk\n'程式設計: Dunk\n'撰寫日期: 2026/5/4\n'\n'傳入參數:\n'傳回值:\n'\n'*************************************************************************************\n\n' 測試用入口\nSub TestSurfaceChart()\n    Call CreateSurfaceChart(\"曲面圖範例\")\nEnd Sub\n\n' 建立曲面圖\n' sheetName: 要建立圖表的工作表名稱\nSub CreateSurfaceChart(ByVal sheetName As String)\n    On Error GoTo ErrorHandler\n\n    Dim ws As Worksheet\n    Dim chartObj As ChartObject\n    Dim cht As Chart\n    Dim dataRange As Range\n\n    Set ws = GetOrCreateWorksheet(sheetName)\n    ws.Cells.Clear\n\n    Call FillSurfaceChartData(ws)\n    Set dataRange = ws.Range(\"A1:F6\")\n\n    Set chartObj = ws.ChartObjects.Add( _\n        Left:=ws.Range(\"H1\").Left, _\n        Top:=ws.Range(\"H1\").Top, _\n        Width:=520, _\n        Height:=360)\n\n    Set cht = chartObj.Chart\n    cht.SetSourceData Source:=dataRange\n    cht.ChartType = xlSurface\n\n    cht.HasTitle = True\n    cht.ChartTitle.Text = \"價格與數量對利潤的影響\"\n    cht.HasLegend = True\n    cht.Legend.Position = xlLegendPositionRight\n    cht.ChartStyle = 14\n\n    MsgBox \"曲面圖已建立完成！\", vbInformation, \"完成\"\n    Exit Sub\n\nErrorHandler:\n    MsgBox \"建立曲面圖時發生錯誤：\" & Err.Description, vbExclamation, \"錯誤\"\nEnd Sub\n\n' 取得或建立工作表\nPrivate Function GetOrCreateWorksheet(ByVal sheetName As String) As Worksheet\n    On Error Resume Next\n    Set GetOrCreateWorksheet = ThisWorkbook.Worksheets(sheetName)\n    On Error GoTo 0\n\n    If GetOrCreateWorksheet Is Nothing Then\n        Set GetOrCreateWorksheet = ThisWorkbook.Worksheets.Add\n        GetOrCreateWorksheet.Name = sheetName\n    End If\nEnd Function\n\n' 輸入曲面圖範例資料\nPrivate Sub FillSurfaceChartData(ByVal ws As Worksheet)\n    ws.Range(\"A1\").Value = \"數量\\價格\"\n    ws.Range(\"B1\").Value = 80\n    ws.Range(\"C1\").Value = 90\n    ws.Range(\"D1\").Value = 100\n    ws.Range(\"E1\").Value = 110\n    ws.Range(\"F1\").Value = 120\n\n    ws.Range(\"A2\").Value = 100\n    ws.Range(\"B2\").Value = 120\n    ws.Range(\"C2\").Value = 180\n    ws.Range(\"D2\").Value = 230\n    ws.Range(\"E2\").Value = 260\n    ws.Range(\"F2\").Value = 280\n\n    ws.Range(\"A3\").Value = 200\n    ws.Range(\"B3\").Value = 260\n    ws.Range(\"C3\").Value = 340\n    ws.Range(\"D3\").Value = 420\n    ws.Range(\"E3\").Value = 470\n    ws.Range(\"F3\").Value = 500\n\n    ws.Range(\"A4\").Value = 300\n    ws.Range(\"B4\").Value = 330\n    ws.Range(\"C4\").Value = 455\n    ws.Range(\"D4\").Value = 570\n    ws.Range(\"E4\").Value = 640\n    ws.Range(\"F4\").Value = 690\n\n    ws.Range(\"A5\").Value = 400\n    ws.Range(\"B5\").Value = 360\n    ws.Range(\"C5\").Value = 540\n    ws.Range(\"D5\").Value = 700\n    ws.Range(\"E5\").Value = 820\n    ws.Range(\"F5\").Value = 900\n\n    ws.Range(\"A6\").Value = 500\n    ws.Range(\"B6\").Value = 340\n    ws.Range(\"C6\").Value = 590\n    ws.Range(\"D6\").Value = 790\n    ws.Range(\"E6\").Value = 960\n    ws.Range(\"F6\").Value = 1080\n\n    ws.Columns(\"A:F\").AutoFit\nEnd Sub", "content_b64": ""}]}, {"folder": "ClearCellFormatting", "path": "模組/ClearCellFormatting", "files": [{"name": "ClearAllSheetsFormatting.bas", "path": "模組/ClearCellFormatting/ClearAllSheetsFormatting.bas", "content": "Attribute VB_Name = \"ClearAllSheetsFormatting\"\n\nOption Explicit\n\n\n\n' ============================================================\n\n' 範例：一次清除活頁簿所有工作表的儲存格格式\n\n' 功能：保留資料內容，僅清除字型、色彩、框線等格式設定\n\n' ============================================================\n\nSub ClearAllSheetsFormatting()\n\n    Dim ws      As Worksheet\n\n    Dim intCnt  As Integer\n\n\n\n    On Error GoTo ErrHandler\n\n\n\n    Dim blnConfirm As Boolean\n\n    blnConfirm = (MsgBox( _\n\n        \"確定要清除活頁簿所有工作表的儲存格格式？\" & Chr(10) & _\n\n        \"（此操作將清除字型、色彩、框線等，但保留資料內容）\", _\n\n        vbYesNo + vbQuestion, \"確認清除格式\") = vbYes)\n\n\n\n    If Not blnConfirm Then\n\n        MsgBox \"操作已取消。\", vbInformation\n\n        Exit Sub\n\n    End If\n\n\n\n    Application.ScreenUpdating = False\n\n    intCnt = 0\n\n\n\n    For Each ws In ThisWorkbook.Worksheets\n\n        ws.Cells.ClearFormats\n\n        intCnt = intCnt + 1\n\n    Next ws\n\n\n\n    Application.ScreenUpdating = True\n\n    MsgBox \"已清除 \" & intCnt & \" 個工作表的所有儲存格格式。\", vbInformation\n\n    Exit Sub\n\n\n\nErrHandler:\n\n    Application.ScreenUpdating = True\n\n    MsgBox \"發生錯誤：\" & Err.Description, vbCritical\n\nEnd Sub\n\n", "content_b64": ""}, {"name": "ClearBorderFormattingOnly.bas", "path": "模組/ClearCellFormatting/ClearBorderFormattingOnly.bas", "content": "Attribute VB_Name = \"ClearBorderFormattingOnly\"\nOption Explicit\n\n'*************************************************************************************\n'模組名稱: ClearBorderFormattingOnly\n'功能說明: 只清除儲存格框線格式，保留字型/填色/數字格式不變\n'\n'作者版權所有: Dunk\n'程式設計: Dunk\n'撰寫日期: 2026/5/9\n'\n'*************************************************************************************\n\n' 清除選取範圍的所有框線\nSub ClearBorderFormattingOnly()\n    Dim targetRange As Range\n\n    If TypeName(Selection) <> \"Range\" Then\n        MsgBox \"請先選取要清除框線的儲存格範圍。\", vbExclamation, \"警告\"\n        Exit Sub\n    End If\n\n    Set targetRange = Selection\n\n    On Error GoTo ErrHandler\n\n    targetRange.Borders(xlEdgeLeft).LineStyle   = xlNone\n    targetRange.Borders(xlEdgeRight).LineStyle  = xlNone\n    targetRange.Borders(xlEdgeTop).LineStyle    = xlNone\n    targetRange.Borders(xlEdgeBottom).LineStyle = xlNone\n    targetRange.Borders(xlInsideHorizontal).LineStyle = xlNone\n    targetRange.Borders(xlInsideVertical).LineStyle   = xlNone\n\n    MsgBox \"已清除選取範圍的框線格式。\", vbInformation, \"完成\"\n    Exit Sub\n\nErrHandler:\n    MsgBox \"清除框線時發生錯誤：\" & Err.Description, vbCritical, \"錯誤\"\nEnd Sub\n\n' 清除整張工作表所有框線\nSub ClearAllBordersInSheet()\n    Dim ws As Worksheet\n    Set ws = ActiveSheet\n\n    On Error GoTo ErrHandler\n\n    ws.Cells.Borders(xlEdgeLeft).LineStyle         = xlNone\n    ws.Cells.Borders(xlEdgeRight).LineStyle        = xlNone\n    ws.Cells.Borders(xlEdgeTop).LineStyle          = xlNone\n    ws.Cells.Borders(xlEdgeBottom).LineStyle       = xlNone\n    ws.Cells.Borders(xlInsideHorizontal).LineStyle = xlNone\n    ws.Cells.Borders(xlInsideVertical).LineStyle   = xlNone\n\n    MsgBox \"已清除工作表「\" & ws.Name & \"」的所有框線。\", vbInformation, \"完成\"\n    Exit Sub\n\nErrHandler:\n    MsgBox \"清除工作表框線時發生錯誤：\" & Err.Description, vbCritical, \"錯誤\"\nEnd Sub", "content_b64": ""}, {"name": "ClearCommentAndFormatting.bas", "path": "模組/ClearCellFormatting/ClearCommentAndFormatting.bas", "content": "Attribute VB_Name = \"ClearCommentAndFormatting\"\nOption Explicit\n\n'*************************************************************************************\n'模組名稱: ClearCommentAndFormatting\n'功能說明: 同時清除儲存格的註解（批註）與格式設定\n'\n'作者版權所有: Dunk\n'程式設計: Dunk\n'撰寫日期: 2026/5/9\n'\n'*************************************************************************************\n\n' 清除選取範圍的註解與格式\nSub ClearCommentAndFormatting()\n    Dim targetRange As Range\n    Dim intComments As Integer\n\n    If TypeName(Selection) <> \"Range\" Then\n        MsgBox \"請先選取要清除的儲存格範圍。\", vbExclamation, \"警告\"\n        Exit Sub\n    End If\n\n    Set targetRange = Selection\n    intComments = targetRange.SpecialCells(xlCellTypeComments).Count\n\n    On Error GoTo ErrHandler\n\n    targetRange.ClearFormats\n    targetRange.ClearComments\n\n    MsgBox \"已清除選取範圍的格式與 \" & intComments & \" 個註解。\", vbInformation, \"完成\"\n    Exit Sub\n\nErrHandler:\n    ' 若無註解仍繼續清除格式\n    targetRange.ClearFormats\n    MsgBox \"已清除選取範圍的格式（無找到可清除的註解）。\", vbInformation, \"完成\"\nEnd Sub\n\n' 清除整張工作表所有註解與使用範圍格式\nSub ClearAllCommentsAndFormatsInSheet()\n    Dim ws As Worksheet\n    Set ws = ActiveSheet\n\n    On Error GoTo ErrHandler\n\n    Application.ScreenUpdating = False\n    ws.UsedRange.ClearFormats\n    ws.UsedRange.ClearComments\n\n    Application.ScreenUpdating = True\n    MsgBox \"已清除工作表「\" & ws.Name & \"」使用範圍的所有格式與註解。\", vbInformation, \"完成\"\n    Exit Sub\n\nErrHandler:\n    Application.ScreenUpdating = True\n    MsgBox \"清除時發生錯誤：\" & Err.Description, vbCritical, \"錯誤\"\nEnd Sub", "content_b64": ""}, {"name": "ClearConditionalFormatsOnly.bas", "path": "模組/ClearCellFormatting/ClearConditionalFormatsOnly.bas", "content": "Option Explicit\n\n' 只清除選取範圍的條件式格式，保留字型、框線、底色與數值。\nPublic Sub ClearConditionalFormatsOnlyExample()\n    On Error GoTo ErrHandler\n\n    Dim targetRange As Range\n\n    If TypeName(Selection) <> \"Range\" Then\n        MsgBox \"請先選取要清除條件式格式的範圍。\", vbExclamation, \"提醒\"\n        Exit Sub\n    End If\n\n    Set targetRange = Selection\n    targetRange.FormatConditions.Delete\n\n    MsgBox \"已清除選取範圍的條件式格式。\", vbInformation, \"完成\"\n    Exit Sub\n\nErrHandler:\n    MsgBox \"清除條件式格式失敗：\" & Err.Description, vbExclamation, \"錯誤\"\nEnd Sub", "content_b64": ""}, {"name": "ClearFillColorOnly.bas", "path": "模組/ClearCellFormatting/ClearFillColorOnly.bas", "content": "Attribute VB_Name = \"ClearFillColorOnly\"\nOption Explicit\n\n'*************************************************************************************\n'模組名稱: ClearFillColorOnly\n'功能說明: 只清除儲存格填滿色彩（背景色），保留其他格式不變\n'\n'作者版權所有: Dunk\n'程式設計: Dunk\n'撰寫日期: 2026/5/9\n'\n'*************************************************************************************\n\n' 清除選取範圍的填滿色彩\nSub ClearFillColorOnly()\n    Dim targetRange As Range\n\n    If TypeName(Selection) <> \"Range\" Then\n        MsgBox \"請先選取要清除填滿色彩的儲存格範圍。\", vbExclamation, \"警告\"\n        Exit Sub\n    End If\n\n    Set targetRange = Selection\n\n    On Error GoTo ErrHandler\n\n    targetRange.Interior.ColorIndex = xlNone\n\n    MsgBox \"已清除選取範圍的填滿色彩（共 \" & targetRange.Cells.Count & \" 個儲存格）。\", _\n           vbInformation, \"完成\"\n    Exit Sub\n\nErrHandler:\n    MsgBox \"清除填滿色彩時發生錯誤：\" & Err.Description, vbCritical, \"錯誤\"\nEnd Sub\n\n' 清除整張工作表的填滿色彩\nSub ClearAllFillColorsInSheet()\n    Dim ws As Worksheet\n    Set ws = ActiveSheet\n\n    On Error GoTo ErrHandler\n\n    ws.UsedRange.Interior.ColorIndex = xlNone\n\n    MsgBox \"已清除工作表「\" & ws.Name & \"」所有使用範圍的填滿色彩。\", vbInformation, \"完成\"\n    Exit Sub\n\nErrHandler:\n    MsgBox \"清除填滿色彩時發生錯誤：\" & Err.Description, vbCritical, \"錯誤\"\nEnd Sub\n\n' 清除特定顏色的儲存格填滿（跳過其他顏色）\nSub ClearSpecificFillColor()\n    Dim ws         As Worksheet\n    Dim cell       As Range\n    Dim targetColor As Long\n    Dim intCleaned As Integer\n\n    Set ws = ActiveSheet\n    ' 以黃色 (RGB 255,255,0) 為目標\n    targetColor = RGB(255, 255, 0)\n    intCleaned = 0\n\n    On Error GoTo ErrHandler\n\n    For Each cell In ws.UsedRange\n        If cell.Interior.Color = targetColor Then\n            cell.Interior.ColorIndex = xlNone\n            intCleaned = intCleaned + 1\n        End If\n    Next cell\n\n    MsgBox \"已清除 \" & intCleaned & \" 個黃色填滿儲存格的背景色。\", vbInformation, \"完成\"\n    Exit Sub\n\nErrHandler:\n    MsgBox \"清除特定色彩時發生錯誤：\" & Err.Description, vbCritical, \"錯誤\"\nEnd Sub", "content_b64": ""}, {"name": "ClearFontFormattingOnly.bas", "path": "模組/ClearCellFormatting/ClearFontFormattingOnly.bas", "content": "Attribute VB_Name = \"ClearFontFormattingOnly\"\nOption Explicit\n\n'*************************************************************************************\n'模組名稱: ClearFontFormattingOnly\n'功能說明: 只清除字型格式（粗體、斜體、顏色、大小），保留框線/填色/數字格式\n'\n'作者版權所有: Dunk\n'程式設計: Dunk\n'撰寫日期: 2026/5/9\n'\n'*************************************************************************************\n\n' 清除目前選取範圍的字型格式\nSub ClearFontFormattingOnly()\n    Dim targetRange As Range\n\n    If TypeName(Selection) <> \"Range\" Then\n        MsgBox \"請先選取要清除字型格式的儲存格範圍。\", vbExclamation, \"警告\"\n        Exit Sub\n    End If\n\n    Set targetRange = Selection\n\n    On Error GoTo ErrHandler\n\n    With targetRange.Font\n        .Name       = \"新細明體\"\n        .Size       = 12\n        .Bold       = False\n        .Italic     = False\n        .Underline  = xlUnderlineStyleNone\n        .Strikethrough = False\n        .Color      = RGB(0, 0, 0)\n        .TintAndShade = 0\n    End With\n\n    MsgBox \"已清除選取範圍的字型格式（共 \" & targetRange.Cells.Count & \" 個儲存格）。\", _\n           vbInformation, \"完成\"\n    Exit Sub\n\nErrHandler:\n    MsgBox \"清除字型格式時發生錯誤：\" & Err.Description, vbCritical, \"錯誤\"\nEnd Sub\n\n' 示範：建立含字型格式的資料再清除\nSub DemoClearFontFormatting()\n    Dim ws As Worksheet\n    Set ws = ActiveSheet\n\n    With ws.Range(\"A1:C3\")\n        .Value = \"示範文字\"\n        .Font.Bold = True\n        .Font.Italic = True\n        .Font.Color = RGB(255, 0, 0)\n        .Font.Size = 16\n        .Font.Underline = xlUnderlineStyleSingle\n    End With\n\n    MsgBox \"已建立帶有字型格式的資料，請選取 A1:C3 後執行 ClearFontFormattingOnly。\", _\n           vbInformation, \"提示\"\nEnd Sub", "content_b64": ""}, {"name": "ClearFormattingInRange.bas", "path": "模組/ClearCellFormatting/ClearFormattingInRange.bas", "content": "Attribute VB_Name = \"ClearFormattingInRange\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: ClearFormattingInRange\n'功能說明: 清除指定範圍或整個工作表的儲存格格式設定\n'\n'著作權所有: Dunk\n'程式設計: Dunk\n'撰寫日期: 2026/5/7\n'\n'*************************************************************************************\n\n' 測試用入口（建立含格式的範例資料）\nSub TestClearFormatting()\n    Dim ws As Worksheet\n    Set ws = GetOrCreateSheet(ThisWorkbook, \"清除格式範例\")\n    Call FillFormattedData(ws)\n    MsgBox \"已建立含格式的範例資料。\" & vbCrLf & _\n           \"可執行以下程序進行測試：\" & vbCrLf & _\n           \"  ClearAllFormatsInSheet     - 清除整張工作表格式\" & vbCrLf & _\n           \"  ClearConditionalFormatsInSheet - 清除條件式格式\" & vbCrLf & _\n           \"  ClearFormatInRange         - 清除指定範圍格式\" & vbCrLf & _\n           \"  ResetRangeToDefault        - 重設選取範圍為預設格式\", _\n           vbInformation, \"提示\"\nEnd Sub\n\n' 清除整張工作表所有儲存格格式（保留資料內容）\nSub ClearAllFormatsInSheet()\n    Dim ws As Worksheet\n    Set ws = ActiveSheet\n    ws.UsedRange.ClearFormats\n    MsgBox \"已清除工作表「\" & ws.Name & \"」的所有格式！\", vbInformation, \"完成\"\nEnd Sub\n\n' 清除整張工作表的條件式格式\nSub ClearConditionalFormatsInSheet()\n    Dim ws As Worksheet\n    Set ws = ActiveSheet\n    ws.Cells.FormatConditions.Delete\n    MsgBox \"已清除工作表「\" & ws.Name & \"」的所有條件式格式！\", vbInformation, \"完成\"\nEnd Sub\n\n' 清除指定範圍的儲存格格式（保留資料）\nSub ClearFormatInRange()\n    Dim ws As Worksheet\n    Dim targetRange As Range\n    Dim rangeAddress As String\n\n    Set ws = ActiveSheet\n    rangeAddress = InputBox(\"請輸入要清除格式的儲存格範圍（例如：A1:D10）：\", \"輸入範圍\")\n\n    If rangeAddress = \"\" Then\n        MsgBox \"已取消操作\", vbInformation, \"取消\"\n        Exit Sub\n    End If\n\n    On Error Resume Next\n    Set targetRange = ws.Range(rangeAddress)\n    On Error GoTo 0\n\n    If targetRange Is Nothing Then\n        MsgBox \"範圍格式不正確，請重新輸入！\", vbExclamation, \"錯誤\"\n        Exit Sub\n    End If\n\n    targetRange.ClearFormats\n    targetRange.FormatConditions.Delete\n    MsgBox \"已清除範圍 \" & rangeAddress & \" 的格式！\", vbInformation, \"完成\"\nEnd Sub\n\n' 重設選取範圍為預設格式\nSub ResetRangeToDefault()\n    Dim targetRange As Range\n    Set targetRange = Selection\n\n    If targetRange Is Nothing Then\n        MsgBox \"請先選取要重設的儲存格範圍！\", vbExclamation, \"警告\"\n        Exit Sub\n    End If\n\n    With targetRange\n        .ClearFormats\n        .Font.Name = \"新細明體\"\n        .Font.Size = 12\n        .Font.Bold = False\n        .Font.Italic = False\n        .Font.Color = RGB(0, 0, 0)\n        .Interior.ColorIndex = xlNone\n        .Borders.LineStyle = xlNone\n        .HorizontalAlignment = xlGeneral\n        .VerticalAlignment = xlBottom\n        .NumberFormat = \"General\"\n    End With\n\n    MsgBox \"選取範圍已重設為預設格式！\", vbInformation, \"完成\"\nEnd Sub\n\n' 填入含格式的範例資料\nPrivate Sub FillFormattedData(ByVal ws As Worksheet)\n    With ws.Range(\"A1:D1\")\n        .Value = Array(\"編號\", \"姓名\", \"部門\", \"薪資\")\n        .Font.Bold = True\n        .Interior.Color = RGB(70, 130, 180)\n        .Font.Color = RGB(255, 255, 255)\n        .HorizontalAlignment = xlCenter\n    End With\n\n    ws.Range(\"A2\").Value = 1\n    ws.Range(\"B2\").Value = \"張三\"\n    ws.Range(\"C2\").Value = \"研發部\"\n    ws.Range(\"D2\").Value = 60000\n\n    ws.Range(\"A3\").Value = 2\n    ws.Range(\"B3\").Value = \"李四\"\n    ws.Range(\"C3\").Value = \"業務部\"\n    ws.Range(\"D3\").Value = 55000\n    ws.Range(\"A3:D3\").Interior.Color = RGB(230, 240, 250)\n\n    ws.Range(\"A4\").Value = 3\n    ws.Range(\"B4\").Value = \"王五\"\n    ws.Range(\"C4\").Value = \"行政部\"\n    ws.Range(\"D4\").Value = 45000\n\n    ws.Range(\"D2:D4\").NumberFormat = \"#,##0\"\n    ws.Range(\"A1:D4\").Borders.LineStyle = xlContinuous\n    ws.Columns(\"A:D\").AutoFit\nEnd Sub\n\n' 取得或建立工作表，並清除內容\nPrivate Function GetOrCreateSheet(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add\n        ws.Name = sheetName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreateSheet = ws\nEnd Function\n", "content_b64": ""}, {"name": "ClearHyperlinkFormatting.bas", "path": "模組/ClearCellFormatting/ClearHyperlinkFormatting.bas", "content": "Attribute VB_Name = \"ClearHyperlinkFormatting\"\nOption Explicit\n\n'*************************************************************************************\n'模組名稱: ClearHyperlinkFormatting\n'功能說明: 清除儲存格中的超連結及其藍色底線字型格式\n'\n'作者版權所有: Dunk\n'程式設計: Dunk\n'撰寫日期: 2026/5/9\n'\n'*************************************************************************************\n\n' 清除選取範圍的超連結與其格式\nSub ClearHyperlinkFormatting()\n    Dim targetRange As Range\n    Dim hl          As Hyperlink\n    Dim intCount    As Integer\n\n    If TypeName(Selection) <> \"Range\" Then\n        MsgBox \"請先選取要清除超連結的儲存格範圍。\", vbExclamation, \"警告\"\n        Exit Sub\n    End If\n\n    Set targetRange = Selection\n    intCount = targetRange.Hyperlinks.Count\n\n    If intCount = 0 Then\n        MsgBox \"選取範圍內沒有超連結。\", vbInformation, \"提示\"\n        Exit Sub\n    End If\n\n    On Error GoTo ErrHandler\n\n    ' 刪除所有超連結\n    targetRange.Hyperlinks.Delete\n\n    ' 重設字型（移除藍色底線）\n    With targetRange.Font\n        .Color     = RGB(0, 0, 0)\n        .Underline = xlUnderlineStyleNone\n    End With\n\n    MsgBox \"已清除 \" & intCount & \" 個超連結及其字型格式。\", vbInformation, \"完成\"\n    Exit Sub\n\nErrHandler:\n    MsgBox \"清除超連結時發生錯誤：\" & Err.Description, vbCritical, \"錯誤\"\nEnd Sub\n\n' 清除整張工作表所有超連結\nSub ClearAllHyperlinksInSheet()\n    Dim ws       As Worksheet\n    Dim intCount As Integer\n\n    Set ws = ActiveSheet\n    intCount = ws.Hyperlinks.Count\n\n    If intCount = 0 Then\n        MsgBox \"工作表「\" & ws.Name & \"」內沒有超連結。\", vbInformation, \"提示\"\n        Exit Sub\n    End If\n\n    On Error GoTo ErrHandler\n\n    ws.Hyperlinks.Delete\n\n    MsgBox \"已清除工作表「\" & ws.Name & \"」的 \" & intCount & \" 個超連結。\", _\n           vbInformation, \"完成\"\n    Exit Sub\n\nErrHandler:\n    MsgBox \"清除工作表超連結時發生錯誤：\" & Err.Description, vbCritical, \"錯誤\"\nEnd Sub", "content_b64": ""}, {"name": "ClearMergedCellFormatting.bas", "path": "模組/ClearCellFormatting/ClearMergedCellFormatting.bas", "content": "Attribute VB_Name = \"ClearMergedCellFormatting\"\nOption Explicit\n\n'*************************************************************************************\n'模組名稱: ClearMergedCellFormatting\n'功能說明: 取消合併儲存格並清除其格式設定\n'\n'作者版權所有: Dunk\n'程式設計: Dunk\n'撰寫日期: 2026/5/9\n'\n'*************************************************************************************\n\n' 取消選取範圍的合併並清除格式\nSub UnmergeAndClearFormatting()\n    Dim targetRange As Range\n\n    If TypeName(Selection) <> \"Range\" Then\n        MsgBox \"請先選取要取消合併並清除格式的儲存格範圍。\", vbExclamation, \"警告\"\n        Exit Sub\n    End If\n\n    Set targetRange = Selection\n\n    On Error GoTo ErrHandler\n\n    targetRange.UnMerge\n    targetRange.ClearFormats\n\n    MsgBox \"已取消合併並清除格式（範圍：\" & targetRange.Address & \"）。\", _\n           vbInformation, \"完成\"\n    Exit Sub\n\nErrHandler:\n    MsgBox \"取消合併或清除格式時發生錯誤：\" & Err.Description, vbCritical, \"錯誤\"\nEnd Sub\n\n' 掃描整張工作表，找出所有合併儲存格並取消合併後清除格式\nSub ClearAllMergedCellFormatsInSheet()\n    Dim ws        As Worksheet\n    Dim cell      As Range\n    Dim intCount  As Integer\n    Dim mergedArea As Range\n\n    Set ws = ActiveSheet\n    intCount = 0\n\n    On Error GoTo ErrHandler\n\n    Application.ScreenUpdating = False\n\n    For Each cell In ws.UsedRange\n        If cell.MergeCells Then\n            If cell.Address = cell.MergeArea.Cells(1, 1).Address Then\n                Set mergedArea = cell.MergeArea\n                mergedArea.UnMerge\n                mergedArea.ClearFormats\n                intCount = intCount + 1\n            End If\n        End If\n    Next cell\n\n    Application.ScreenUpdating = True\n    MsgBox \"已取消並清除 \" & intCount & \" 個合併儲存格區域的格式。\", vbInformation, \"完成\"\n    Exit Sub\n\nErrHandler:\n    Application.ScreenUpdating = True\n    MsgBox \"處理合併儲存格時發生錯誤：\" & Err.Description, vbCritical, \"錯誤\"\nEnd Sub", "content_b64": ""}, {"name": "ClearNamedStyleFormatting.bas", "path": "模組/ClearCellFormatting/ClearNamedStyleFormatting.bas", "content": "Attribute VB_Name = \"ClearNamedStyleFormatting\"\nOption Explicit\n\n'*************************************************************************************\n'模組名稱: ClearNamedStyleFormatting\n'功能說明: 將套用命名樣式的儲存格重設回 Normal 樣式，並清除多餘格式\n'\n'作者版權所有: Dunk\n'程式設計: Dunk\n'撰寫日期: 2026/5/9\n'\n'*************************************************************************************\n\n' 將選取範圍的樣式重設為 Normal\nSub ClearNamedStyleToNormal()\n    Dim targetRange As Range\n\n    If TypeName(Selection) <> \"Range\" Then\n        MsgBox \"請先選取要重設樣式的儲存格範圍。\", vbExclamation, \"警告\"\n        Exit Sub\n    End If\n\n    Set targetRange = Selection\n\n    On Error GoTo ErrHandler\n\n    targetRange.Style = \"Normal\"\n    targetRange.ClearFormats\n\n    MsgBox \"已將選取範圍重設為 Normal 樣式並清除格式（共 \" & _\n           targetRange.Cells.Count & \" 個儲存格）。\", vbInformation, \"完成\"\n    Exit Sub\n\nErrHandler:\n    MsgBox \"重設樣式時發生錯誤：\" & Err.Description, vbCritical, \"錯誤\"\nEnd Sub\n\n' 掃描整張工作表，將所有非 Normal 樣式的儲存格重設\nSub ResetAllNonNormalStyles()\n    Dim ws       As Worksheet\n    Dim cell     As Range\n    Dim intCount As Integer\n\n    Set ws = ActiveSheet\n    intCount = 0\n\n    On Error GoTo ErrHandler\n\n    Application.ScreenUpdating = False\n\n    For Each cell In ws.UsedRange\n        If cell.Style <> \"Normal\" Then\n            cell.Style = \"Normal\"\n            cell.ClearFormats\n            intCount = intCount + 1\n        End If\n    Next cell\n\n    Application.ScreenUpdating = True\n    MsgBox \"已將 \" & intCount & \" 個非 Normal 樣式的儲存格重設。\", vbInformation, \"完成\"\n    Exit Sub\n\nErrHandler:\n    Application.ScreenUpdating = True\n    MsgBox \"重設樣式時發生錯誤：\" & Err.Description, vbCritical, \"錯誤\"\nEnd Sub\n\n' 列出目前工作簿中所有自訂樣式名稱\nSub ListAllStyles()\n    Dim sty     As Style\n    Dim strList As String\n\n    strList = \"目前活頁簿樣式清單：\" & vbCrLf\n\n    For Each sty In ThisWorkbook.Styles\n        If Not sty.BuiltIn Then\n            strList = strList & \"  [自訂] \" & sty.Name & vbCrLf\n        End If\n    Next sty\n\n    If strList = \"目前活頁簿樣式清單：\" & vbCrLf Then\n        strList = strList & \"  （無自訂樣式）\"\n    End If\n\n    MsgBox strList, vbInformation, \"樣式清單\"\nEnd Sub", "content_b64": ""}, {"name": "ClearNumberFormatOnly.bas", "path": "模組/ClearCellFormatting/ClearNumberFormatOnly.bas", "content": "Attribute VB_Name = \"ClearNumberFormatOnly\"\nOption Explicit\n\n'*************************************************************************************\n'模組名稱: ClearNumberFormatOnly\n'功能說明: 只清除數字格式，將選取範圍重設為 General，保留其他格式\n'\n'作者版權所有: Dunk\n'程式設計: Dunk\n'撰寫日期: 2026/5/9\n'\n'*************************************************************************************\n\n' 清除選取範圍的數字格式\nSub ClearNumberFormatOnly()\n    Dim targetRange As Range\n\n    If TypeName(Selection) <> \"Range\" Then\n        MsgBox \"請先選取要清除數字格式的儲存格範圍。\", vbExclamation, \"警告\"\n        Exit Sub\n    End If\n\n    Set targetRange = Selection\n\n    On Error GoTo ErrHandler\n\n    targetRange.NumberFormat = \"General\"\n\n    MsgBox \"已將選取範圍的數字格式重設為 General（共 \" & _\n           targetRange.Cells.Count & \" 個儲存格）。\", vbInformation, \"完成\"\n    Exit Sub\n\nErrHandler:\n    MsgBox \"清除數字格式時發生錯誤：\" & Err.Description, vbCritical, \"錯誤\"\nEnd Sub\n\n' 清除整張工作表使用範圍的數字格式\nSub ClearNumberFormatInSheet()\n    Dim ws As Worksheet\n    Set ws = ActiveSheet\n\n    On Error GoTo ErrHandler\n\n    ws.UsedRange.NumberFormat = \"General\"\n\n    MsgBox \"已清除工作表「\" & ws.Name & \"」所有使用範圍的數字格式。\", vbInformation, \"完成\"\n    Exit Sub\n\nErrHandler:\n    MsgBox \"清除數字格式時發生錯誤：\" & Err.Description, vbCritical, \"錯誤\"\nEnd Sub\n\n' 示範各種數字格式的套用與清除\nSub DemoNumberFormatClear()\n    Dim ws As Worksheet\n    Set ws = ActiveSheet\n\n    ws.Range(\"A1\").Value = 1234567.89\n    ws.Range(\"A2\").Value = 0.75\n    ws.Range(\"A3\").Value = 45000\n    ws.Range(\"A4\").Value = -500\n\n    ws.Range(\"A1\").NumberFormat = \"#,##0.00\"\n    ws.Range(\"A2\").NumberFormat = \"0.00%\"\n    ws.Range(\"A3\").NumberFormat = \"yyyy/mm/dd\"\n    ws.Range(\"A4\").NumberFormat = \"$#,##0.00;[Red]($#,##0.00)\"\n\n    MsgBox \"已套用各種數字格式於 A1:A4，請選取後執行 ClearNumberFormatOnly。\", _\n           vbInformation, \"提示\"\nEnd Sub", "content_b64": ""}, {"name": "ClearProtectionFormatting.bas", "path": "模組/ClearCellFormatting/ClearProtectionFormatting.bas", "content": "Attribute VB_Name = \"ClearProtectionFormatting\"\nOption Explicit\n\n'*************************************************************************************\n'模組名稱: ClearProtectionFormatting\n'功能說明: 清除儲存格的鎖定與隱藏保護設定，並同時清除格式\n'\n'作者版權所有: Dunk\n'程式設計: Dunk\n'撰寫日期: 2026/5/9\n'\n'*************************************************************************************\n\n' 清除選取範圍的保護設定（鎖定+隱藏）並清除格式\nSub ClearProtectionAndFormatting()\n    Dim targetRange As Range\n\n    If TypeName(Selection) <> \"Range\" Then\n        MsgBox \"請先選取要清除保護設定的儲存格範圍。\", vbExclamation, \"警告\"\n        Exit Sub\n    End If\n\n    Set targetRange = Selection\n\n    On Error GoTo ErrHandler\n\n    ' 先解除工作表保護（若已保護）\n    If ActiveSheet.ProtectContents Then\n        MsgBox \"工作表目前已保護，請先解除保護再執行此操作。\", vbExclamation, \"警告\"\n        Exit Sub\n    End If\n\n    With targetRange\n        .Locked = False\n        .FormulaHidden = False\n        .ClearFormats\n    End With\n\n    MsgBox \"已清除選取範圍的鎖定、隱藏保護設定與格式。\", vbInformation, \"完成\"\n    Exit Sub\n\nErrHandler:\n    MsgBox \"清除保護設定時發生錯誤：\" & Err.Description, vbCritical, \"錯誤\"\nEnd Sub\n\n' 批次解鎖整張工作表所有儲存格並清除格式\nSub UnlockAllCellsAndClearFormats()\n    Dim ws As Worksheet\n    Set ws = ActiveSheet\n\n    If ws.ProtectContents Then\n        MsgBox \"工作表目前已保護，請先解除保護再執行此操作。\", vbExclamation, \"警告\"\n        Exit Sub\n    End If\n\n    On Error GoTo ErrHandler\n\n    Application.ScreenUpdating = False\n    ws.Cells.Locked = False\n    ws.Cells.FormulaHidden = False\n    ws.UsedRange.ClearFormats\n\n    Application.ScreenUpdating = True\n    MsgBox \"已解鎖工作表「\" & ws.Name & \"」所有儲存格並清除使用範圍格式。\", _\n           vbInformation, \"完成\"\n    Exit Sub\n\nErrHandler:\n    Application.ScreenUpdating = True\n    MsgBox \"操作時發生錯誤：\" & Err.Description, vbCritical, \"錯誤\"\nEnd Sub", "content_b64": ""}, {"name": "ClearRowColumnFormatting.bas", "path": "模組/ClearCellFormatting/ClearRowColumnFormatting.bas", "content": "Attribute VB_Name = \"ClearRowColumnFormatting\"\nOption Explicit\n\n'*************************************************************************************\n'模組名稱: ClearRowColumnFormatting\n'功能說明: 清除整列或整欄的格式設定（字型/填色/框線/數字格式）\n'\n'作者版權所有: Dunk\n'程式設計: Dunk\n'撰寫日期: 2026/5/9\n'\n'*************************************************************************************\n\n' 清除目前所在列的格式\nSub ClearCurrentRowFormatting()\n    Dim ws  As Worksheet\n    Dim lngRow As Long\n\n    Set ws = ActiveSheet\n    lngRow = ActiveCell.Row\n\n    On Error GoTo ErrHandler\n\n    ws.Rows(lngRow).ClearFormats\n    ws.Rows(lngRow).FormatConditions.Delete\n\n    MsgBox \"已清除第 \" & lngRow & \" 列的所有格式。\", vbInformation, \"完成\"\n    Exit Sub\n\nErrHandler:\n    MsgBox \"清除列格式時發生錯誤：\" & Err.Description, vbCritical, \"錯誤\"\nEnd Sub\n\n' 清除目前所在欄的格式\nSub ClearCurrentColumnFormatting()\n    Dim ws     As Worksheet\n    Dim lngCol As Long\n\n    Set ws = ActiveSheet\n    lngCol = ActiveCell.Column\n\n    On Error GoTo ErrHandler\n\n    ws.Columns(lngCol).ClearFormats\n    ws.Columns(lngCol).FormatConditions.Delete\n\n    MsgBox \"已清除第 \" & lngCol & \" 欄的所有格式。\", vbInformation, \"完成\"\n    Exit Sub\n\nErrHandler:\n    MsgBox \"清除欄格式時發生錯誤：\" & Err.Description, vbCritical, \"錯誤\"\nEnd Sub\n\n' 依使用者輸入列號範圍批次清除格式\nSub ClearRowRangeFormatting()\n    Dim ws         As Worksheet\n    Dim strInput   As String\n    Dim lngStart   As Long\n    Dim lngEnd     As Long\n\n    Set ws = ActiveSheet\n\n    strInput = InputBox(\"請輸入要清除格式的列號範圍（例如：3:8）：\", \"輸入列範圍\")\n    If strInput = \"\" Then\n        MsgBox \"已取消操作。\", vbInformation, \"提示\"\n        Exit Sub\n    End If\n\n    On Error GoTo ErrHandler\n\n    ws.Rows(strInput).ClearFormats\n    ws.Rows(strInput).FormatConditions.Delete\n\n    MsgBox \"已清除第 \" & strInput & \" 列的格式。\", vbInformation, \"完成\"\n    Exit Sub\n\nErrHandler:\n    MsgBox \"清除列範圍格式時發生錯誤：\" & Err.Description, vbCritical, \"錯誤\"\nEnd Sub", "content_b64": ""}]}, {"folder": "ConditionalFormatting", "path": "模組/ConditionalFormatting", "files": [{"name": "ColorScaleFormatting.bas", "path": "模組/ConditionalFormatting/ColorScaleFormatting.bas", "content": "Attribute VB_Name = \"ColorScaleFormatting\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: ColorScaleFormatting\n'功能說明: 使用VBA對指定範圍套用色階條件式格式設定\n'\n'著作權所有: Dunk\n'程式設計: Dunk\n'撰寫日期: 2026/5/7\n'\n'*************************************************************************************\n\n' 測試用入口\nSub TestColorScaleFormatting()\n    Call ApplyColorScaleFormatting\nEnd Sub\n\n' 對資料範圍套用三色色階條件式格式\nSub ApplyColorScaleFormatting()\n    Dim ws As Worksheet\n    Dim dataRange As Range\n    Dim cf As ColorScale\n    Dim barRange As Range\n\n    Set ws = GetOrCreateSheet(ThisWorkbook, \"色階格式範例\")\n    Call FillGradeData(ws)\n\n    Set dataRange = ws.Range(\"B2:D6\")\n    dataRange.FormatConditions.Delete\n\n    ' 新增三色色階格式（低=紅, 中=黃, 高=綠）\n    Set cf = dataRange.FormatConditions.AddColorScale(ColorScaleType:=3)\n\n    With cf.ColorScaleCriteria(1)\n        .Type = xlConditionValueLowestValue\n        .FormatColor.Color = RGB(255, 0, 0)\n    End With\n\n    With cf.ColorScaleCriteria(2)\n        .Type = xlConditionValuePercentile\n        .Value = 50\n        .FormatColor.Color = RGB(255, 255, 0)\n    End With\n\n    With cf.ColorScaleCriteria(3)\n        .Type = xlConditionValueHighestValue\n        .FormatColor.Color = RGB(0, 255, 0)\n    End With\n\n    ' 示範資料橫條格式\n    Set barRange = ws.Range(\"E2:E6\")\n    ws.Range(\"E1\").Value = \"業績達成率(%)\"\n    ws.Range(\"E2\").Value = 45\n    ws.Range(\"E3\").Value = 78\n    ws.Range(\"E4\").Value = 92\n    ws.Range(\"E5\").Value = 60\n    ws.Range(\"E6\").Value = 85\n    barRange.FormatConditions.Delete\n    barRange.FormatConditions.AddDatabar\n\n    ws.Columns(\"A:E\").AutoFit\n    ws.Activate\n    MsgBox \"色階條件式格式已套用完成！\", vbInformation, \"完成\"\nEnd Sub\n\n' 填入成績範例資料\nPrivate Sub FillGradeData(ByVal ws As Worksheet)\n    ws.Range(\"A1\").Value = \"學生\"\n    ws.Range(\"B1\").Value = \"國文\"\n    ws.Range(\"C1\").Value = \"英文\"\n    ws.Range(\"D1\").Value = \"數學\"\n    ws.Range(\"A2\").Value = \"陳小明\"\n    ws.Range(\"B2\").Value = 78\n    ws.Range(\"C2\").Value = 85\n    ws.Range(\"D2\").Value = 92\n    ws.Range(\"A3\").Value = \"李小華\"\n    ws.Range(\"B3\").Value = 55\n    ws.Range(\"C3\").Value = 60\n    ws.Range(\"D3\").Value = 48\n    ws.Range(\"A4\").Value = \"王小美\"\n    ws.Range(\"B4\").Value = 90\n    ws.Range(\"C4\").Value = 88\n    ws.Range(\"D4\").Value = 95\n    ws.Range(\"A5\").Value = \"張小強\"\n    ws.Range(\"B5\").Value = 65\n    ws.Range(\"C5\").Value = 72\n    ws.Range(\"D5\").Value = 68\n    ws.Range(\"A6\").Value = \"林小芬\"\n    ws.Range(\"B6\").Value = 82\n    ws.Range(\"C6\").Value = 77\n    ws.Range(\"D6\").Value = 80\n    ws.Columns(\"A:D\").AutoFit\nEnd Sub\n\n' 取得或建立工作表，並清除內容\nPrivate Function GetOrCreateSheet(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add\n        ws.Name = sheetName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreateSheet = ws\nEnd Function\n", "content_b64": ""}, {"name": "DataBarFormatting.bas", "path": "模組/ConditionalFormatting/DataBarFormatting.bas", "content": "Attribute VB_Name = \"DataBarFormatting\"\n\nOption Explicit\n\n\n\n' ============================================================\n\n' 範例：以 VBA 設定資料橫條（Data Bar）條件式格式\n\n' 功能：對選取範圍套用資料橫條，並自訂顏色與最大值設定\n\n' ============================================================\n\nSub ApplyDataBarFormatting()\n\n    Dim ws      As Worksheet\n\n    Dim rng     As Range\n\n    Dim db      As Databar\n\n\n\n    On Error GoTo ErrHandler\n\n\n\n    ' --- 準備示範資料 ---\n\n    Set ws = ThisWorkbook.Worksheets.Add\n\n    ws.Name = \"DataBarDemo\"\n\n\n\n    ws.Cells(1, 1).Value = \"產品\"\n\n    ws.Cells(1, 2).Value = \"銷售量\"\n\n    ws.Cells(2, 1).Value = \"產品A\"\n\n    ws.Cells(2, 2).Value = 320\n\n    ws.Cells(3, 1).Value = \"產品B\"\n\n    ws.Cells(3, 2).Value = 150\n\n    ws.Cells(4, 1).Value = \"產品C\"\n\n    ws.Cells(4, 2).Value = 480\n\n    ws.Cells(5, 1).Value = \"產品D\"\n\n    ws.Cells(5, 2).Value = 210\n\n    ws.Cells(6, 1).Value = \"產品E\"\n\n    ws.Cells(6, 2).Value = 390\n\n\n\n    Set rng = ws.Range(\"B2:B6\")\n\n\n\n    ' --- 清除既有條件式格式 ---\n\n    rng.FormatConditions.Delete\n\n\n\n    ' --- 新增資料橫條格式 ---\n\n    Set db = rng.FormatConditions.AddDatabar\n\n\n\n    ' --- 設定最小值為 0，最大值自動 ---\n\n    db.MinPoint.Modify newtype:=xlConditionValueNumber, newvalue:=0\n\n    db.MaxPoint.Modify newtype:=xlConditionValueAutomaticMax\n\n\n\n    ' --- 設定橫條顏色（藍色）---\n\n    db.BarColor.Color = RGB(0, 112, 192)\n\n    db.BarFillType = xlDataBarFillGradient\n\n\n\n    ' --- 顯示數值 ---\n\n    db.ShowValue = True\n\n\n\n    ws.Columns.AutoFit\n\n    MsgBox \"資料橫條條件式格式已套用至範圍：\" & rng.Address, vbInformation\n\n    Exit Sub\n\n\n\nErrHandler:\n\n    MsgBox \"發生錯誤：\" & Err.Description, vbCritical\n\nEnd Sub\n\n", "content_b64": ""}, {"name": "IconSetFormatting.bas", "path": "模組/ConditionalFormatting/IconSetFormatting.bas", "content": "Option Explicit\n\n' 使用圖示集建立條件式格式，標示績效高低。\nPublic Sub ApplyIconSetFormattingExample()\n    On Error GoTo ErrHandler\n\n    Dim ws As Worksheet\n    Dim targetRange As Range\n    Dim iconCondition As IconSetCondition\n\n    Set ws = GetOrCreateConditionWorksheet(\"圖示集格式範例\")\n    ws.Cells.Clear\n    Call FillIconSetData(ws)\n\n    Set targetRange = ws.Range(\"C2:C8\")\n    targetRange.FormatConditions.Delete\n    Set iconCondition = targetRange.FormatConditions.AddIconSetCondition\n\n    With iconCondition\n        .IconSet = ActiveWorkbook.IconSets(xl3TrafficLights1)\n        .ShowIconOnly = False\n        .IconCriteria(2).Type = xlConditionValueNumber\n        .IconCriteria(2).Value = 70\n        .IconCriteria(3).Type = xlConditionValueNumber\n        .IconCriteria(3).Value = 90\n    End With\n\n    ws.Columns(\"A:C\").AutoFit\n    MsgBox \"圖示集條件式格式已套用完成。\", vbInformation, \"完成\"\n    Exit Sub\n\nErrHandler:\n    MsgBox \"套用條件式格式失敗：\" & Err.Description, vbExclamation, \"錯誤\"\nEnd Sub\n\nPrivate Sub FillIconSetData(ByVal ws As Worksheet)\n    ws.Range(\"A1:C1\").Value = Array(\"員工\", \"部門\", \"達成率\")\n    ws.Range(\"A2:C2\").Value = Array(\"王小明\", \"業務\", 95)\n    ws.Range(\"A3:C3\").Value = Array(\"陳美華\", \"業務\", 82)\n    ws.Range(\"A4:C4\").Value = Array(\"林志強\", \"業務\", 68)\n    ws.Range(\"A5:C5\").Value = Array(\"張雅婷\", \"客服\", 91)\n    ws.Range(\"A6:C6\").Value = Array(\"黃建國\", \"客服\", 74)\n    ws.Range(\"A7:C7\").Value = Array(\"李佳玲\", \"客服\", 63)\n    ws.Range(\"A8:C8\").Value = Array(\"周信宏\", \"管理\", 88)\n    ws.Range(\"C2:C8\").NumberFormat = \"0\"\nEnd Sub\n\nPrivate Function GetOrCreateConditionWorksheet(ByVal sheetName As String) As Worksheet\n    On Error Resume Next\n    Set GetOrCreateConditionWorksheet = ThisWorkbook.Worksheets(sheetName)\n    On Error GoTo 0\n\n    If GetOrCreateConditionWorksheet Is Nothing Then\n        Set GetOrCreateConditionWorksheet = ThisWorkbook.Worksheets.Add\n        GetOrCreateConditionWorksheet.Name = sheetName\n    End If\nEnd Function", "content_b64": ""}]}, {"folder": "ExporttoPDF", "path": "模組/ExporttoPDF", "files": [{"name": "ExportAllSheetsToPDF.bas", "path": "模組/ExporttoPDF/ExportAllSheetsToPDF.bas", "content": "Attribute VB_Name = \"ExportAllSheetsToPDF\"\n\nOption Explicit\n\n\n\n' ============================================================\n\n' 範例：將活頁簿所有工作表合併匯出為單一 PDF 檔案\n\n' 功能：選擇輸出路徑後，將所有工作表一次列印為 PDF\n\n' ============================================================\n\nSub ExportAllSheetsToPDF()\n\n    Dim strPath     As String\n\n    Dim wsArr()     As String\n\n    Dim i           As Integer\n\n\n\n    ' --- 選擇儲存路徑 ---\n\n    With Application.FileDialog(msoFileDialogSaveAs)\n\n        .Title = \"請選擇 PDF 儲存路徑\"\n\n        .FilterIndex = 2\n\n        If .Show <> -1 Then\n\n            MsgBox \"已取消操作。\", vbInformation\n\n            Exit Sub\n\n        End If\n\n        strPath = .SelectedItems(1)\n\n    End With\n\n\n\n    If Right(LCase(strPath), 4) <> \".pdf\" Then strPath = strPath & \".pdf\"\n\n\n\n    On Error GoTo ErrHandler\n\n\n\n    ' --- 收集所有工作表名稱 ---\n\n    ReDim wsArr(1 To ThisWorkbook.Sheets.Count)\n\n    For i = 1 To ThisWorkbook.Sheets.Count\n\n        wsArr(i) = ThisWorkbook.Sheets(i).Name\n\n    Next i\n\n\n\n    ' --- 選取所有工作表並匯出 ---\n\n    ThisWorkbook.Sheets(wsArr).Select\n\n    ActiveSheet.ExportAsFixedFormat _\n\n        Type:=xlTypePDF, _\n\n        Filename:=strPath, _\n\n        Quality:=xlQualityStandard, _\n\n        IncludeDocProperties:=True, _\n\n        IgnorePrintAreas:=False\n\n\n\n    ' --- 取消多工作表選取 ---\n\n    ThisWorkbook.Sheets(1).Select\n\n\n\n    MsgBox \"所有工作表已匯出為 PDF：\" & Chr(10) & strPath, vbInformation\n\n    Exit Sub\n\n\n\nErrHandler:\n\n    MsgBox \"發生錯誤：\" & Err.Description, vbCritical\n\nEnd Sub\n\n", "content_b64": ""}, {"name": "ExportChartToPDF.bas", "path": "模組/ExporttoPDF/ExportChartToPDF.bas", "content": "Attribute VB_Name = \"ExportChartToPDF\"\n\nOption Explicit\n\n\n\n' ============================================================\n\n' 範例：將工作表中的圖表匯出為 PDF\n\n' 功能：支援匯出目前選取圖表、第一個圖表，或逐一匯出全部圖表\n\n' ============================================================\n\n\n\n' 匯出目前已選取的圖表為 PDF\n\nSub ExportSelectedChartToPDF()\n\n    Dim pdfPath As String\n\n    Dim cht     As Chart\n\n\n\n    If TypeName(ActiveChart) = \"Chart\" Then\n\n        Set cht = ActiveChart\n\n    ElseIf TypeName(Selection) = \"ChartObject\" Then\n\n        Set cht = Selection.Chart\n\n    Else\n\n        MsgBox \"請先點選要匯出的圖表。\", vbExclamation, \"提示\"\n\n        Exit Sub\n\n    End If\n\n\n\n    With Application.FileDialog(msoFileDialogSaveAs)\n\n        .Title = \"請選擇圖表 PDF 儲存位置\"\n\n        .InitialFileName = \"Chart.pdf\"\n\n        If .Show <> -1 Then\n\n            MsgBox \"已取消操作。\", vbInformation, \"提示\"\n\n            Exit Sub\n\n        End If\n\n        pdfPath = .SelectedItems(1)\n\n    End With\n\n\n\n    If LCase(Right(pdfPath, 4)) <> \".pdf\" Then pdfPath = pdfPath & \".pdf\"\n\n\n\n    On Error GoTo ErrHandler\n\n    cht.ExportAsFixedFormat _\n\n        Type:=xlTypePDF, _\n\n        Filename:=pdfPath, _\n\n        Quality:=xlQualityStandard, _\n\n        IncludeDocProperties:=False, _\n\n        IgnorePrintAreas:=False, _\n\n        OpenAfterPublish:=False\n\n\n\n    MsgBox \"圖表已成功匯出為 PDF：\" & vbCrLf & pdfPath, vbInformation, \"完成\"\n\n    Exit Sub\n\n\n\nErrHandler:\n\n    MsgBox \"圖表匯出失敗：\" & Err.Description, vbCritical, \"錯誤\"\n\nEnd Sub\n\n\n\n' 匯出工作表中第一個圖表為 PDF（不需手動選取）\n\nSub ExportFirstChartToPDF()\n\n    Dim ws          As Worksheet\n\n    Dim folderPath  As String\n\n    Dim pdfPath     As String\n\n\n\n    Set ws = ActiveSheet\n\n\n\n    If ws.ChartObjects.Count = 0 Then\n\n        MsgBox \"目前工作表沒有任何圖表。\", vbExclamation, \"提示\"\n\n        Exit Sub\n\n    End If\n\n\n\n    With Application.FileDialog(msoFileDialogFolderPicker)\n\n        .Title = \"請選擇 PDF 輸出資料夾\"\n\n        If .Show <> -1 Then\n\n            MsgBox \"已取消操作。\", vbInformation, \"提示\"\n\n            Exit Sub\n\n        End If\n\n        folderPath = .SelectedItems(1)\n\n    End With\n\n\n\n    pdfPath = folderPath & \"\\\" & ws.ChartObjects(1).Name & \".pdf\"\n\n\n\n    On Error GoTo ErrHandler\n\n    ws.ChartObjects(1).Chart.ExportAsFixedFormat _\n\n        Type:=xlTypePDF, _\n\n        Filename:=pdfPath, _\n\n        Quality:=xlQualityStandard, _\n\n        IncludeDocProperties:=False, _\n\n        IgnorePrintAreas:=False, _\n\n        OpenAfterPublish:=False\n\n\n\n    MsgBox \"圖表已匯出為 PDF：\" & vbCrLf & pdfPath, vbInformation, \"完成\"\n\n    Exit Sub\n\n\n\nErrHandler:\n\n    MsgBox \"匯出失敗：\" & Err.Description, vbCritical, \"錯誤\"\n\nEnd Sub\n\n\n\n' 逐一匯出工作表中所有圖表為個別 PDF\n\nSub ExportAllChartsToPDF()\n\n    Dim ws          As Worksheet\n\n    Dim folderPath  As String\n\n    Dim pdfPath     As String\n\n    Dim i           As Integer\n\n    Dim totalCount  As Integer\n\n\n\n    Set ws = ActiveSheet\n\n\n\n    If ws.ChartObjects.Count = 0 Then\n\n        MsgBox \"目前工作表沒有任何圖表。\", vbExclamation, \"提示\"\n\n        Exit Sub\n\n    End If\n\n\n\n    With Application.FileDialog(msoFileDialogFolderPicker)\n\n        .Title = \"請選擇 PDF 輸出資料夾\"\n\n        If .Show <> -1 Then\n\n            MsgBox \"已取消操作。\", vbInformation, \"提示\"\n\n            Exit Sub\n\n        End If\n\n        folderPath = .SelectedItems(1)\n\n    End With\n\n\n\n    totalCount = 0\n\n    For i = 1 To ws.ChartObjects.Count\n\n        pdfPath = folderPath & \"\\\" & ws.ChartObjects(i).Name & \".pdf\"\n\n        On Error Resume Next\n\n        ws.ChartObjects(i).Chart.ExportAsFixedFormat _\n\n            Type:=xlTypePDF, _\n\n            Filename:=pdfPath, _\n\n            Quality:=xlQualityStandard, _\n\n            IncludeDocProperties:=False, _\n\n            IgnorePrintAreas:=False, _\n\n            OpenAfterPublish:=False\n\n        If Err.Number = 0 Then totalCount = totalCount + 1\n\n        Err.Clear\n\n        On Error GoTo 0\n\n    Next i\n\n\n\n    MsgBox \"已匯出 \" & totalCount & \" 個圖表為 PDF。\", vbInformation, \"完成\"\n\nEnd Sub\n\n", "content_b64": ""}, {"name": "ExportPDFAndSendEmail.bas", "path": "模組/ExporttoPDF/ExportPDFAndSendEmail.bas", "content": "Attribute VB_Name = \"ExportPDFAndSendEmail\"\n\nOption Explicit\n\n\n\n' ============================================================\n\n' 範例：將工作表匯出為 PDF 後，自動以 Outlook 寄送\n\n' 功能：匯出 PDF 至暫存路徑，並建立含附件的 Outlook 郵件草稿\n\n' ============================================================\n\n\n\nSub ExportPDFAndSendEmail()\n\n    Dim ws          As Worksheet\n\n    Dim pdfPath     As String\n\n    Dim recipient   As String\n\n    Dim mailSubject As String\n\n    Dim mailBody    As String\n\n    Dim olApp       As Object\n\n    Dim olMail      As Object\n\n\n\n    Set ws = ActiveSheet\n\n\n\n    recipient = InputBox(\"請輸入收件人 Email：\", \"設定寄送資訊\")\n\n    If Trim(recipient) = \"\" Then\n\n        MsgBox \"未輸入收件人，操作取消。\", vbInformation, \"提示\"\n\n        Exit Sub\n\n    End If\n\n\n\n    mailSubject = InputBox(\"請輸入郵件主旨：\", \"設定寄送資訊\", ws.Name & \" PDF 報表\")\n\n    mailBody = \"您好，\" & vbCrLf & vbCrLf & _\n\n               \"請參閱附件 PDF 報表。\" & vbCrLf & vbCrLf & _\n\n               \"此郵件由系統自動產生。\"\n\n\n\n    ' 儲存至系統暫存資料夾\n\n    pdfPath = Environ(\"TEMP\") & \"\\\" & ws.Name & \"_\" & Format(Now, \"yyyymmdd_hhnnss\") & \".pdf\"\n\n\n\n    On Error GoTo ErrHandler\n\n\n\n    ws.ExportAsFixedFormat _\n\n        Type:=xlTypePDF, _\n\n        Filename:=pdfPath, _\n\n        Quality:=xlQualityStandard, _\n\n        IncludeDocProperties:=True, _\n\n        IgnorePrintAreas:=False, _\n\n        OpenAfterPublish:=False\n\n\n\n    ' 建立 Outlook 郵件草稿並附加 PDF\n\n    Set olApp  = CreateObject(\"Outlook.Application\")\n\n    Set olMail = olApp.CreateItem(0)\n\n\n\n    With olMail\n\n        .To      = recipient\n\n        .Subject = mailSubject\n\n        .Body    = mailBody\n\n        .Attachments.Add pdfPath\n\n        .Display  ' 顯示草稿視窗；改為 .Send 可直接寄出\n\n    End With\n\n\n\n    MsgBox \"PDF 已產生並附加至郵件草稿，請確認後手動寄出。\", vbInformation, \"完成\"\n\n    Exit Sub\n\n\n\nErrHandler:\n\n    MsgBox \"操作失敗：\" & Err.Description, vbCritical, \"錯誤\"\n\nEnd Sub\n\n", "content_b64": ""}, {"name": "ExportPDFBatchWorkbooks.bas", "path": "模組/ExporttoPDF/ExportPDFBatchWorkbooks.bas", "content": "Attribute VB_Name = \"ExportPDFBatchWorkbooks\"\n\nOption Explicit\n\n\n\n' ============================================================\n\n' 範例：批次開啟資料夾中的 Excel 檔案，逐一將第一個工作表匯出為 PDF\n\n' 功能：自動處理來源資料夾中所有 .xlsx / .xls 檔案\n\n' ============================================================\n\n\n\nSub ExportPDFBatchWorkbooks()\n\n    Dim srcFolder   As String\n\n    Dim outFolder   As String\n\n    Dim fileName    As String\n\n    Dim wbPath      As String\n\n    Dim pdfPath     As String\n\n    Dim wb          As Workbook\n\n    Dim totalCount  As Integer\n\n    Dim e           As Integer\n\n    Dim extensions(1) As String\n\n\n\n    ' 選擇來源資料夾\n\n    With Application.FileDialog(msoFileDialogFolderPicker)\n\n        .Title = \"請選擇包含 Excel 檔案的來源資料夾\"\n\n        If .Show <> -1 Then\n\n            MsgBox \"已取消操作。\", vbInformation, \"提示\"\n\n            Exit Sub\n\n        End If\n\n        srcFolder = .SelectedItems(1)\n\n    End With\n\n\n\n    ' 選擇輸出資料夾\n\n    With Application.FileDialog(msoFileDialogFolderPicker)\n\n        .Title = \"請選擇 PDF 輸出資料夾\"\n\n        If .Show <> -1 Then\n\n            MsgBox \"已取消操作。\", vbInformation, \"提示\"\n\n            Exit Sub\n\n        End If\n\n        outFolder = .SelectedItems(1)\n\n    End With\n\n\n\n    Application.ScreenUpdating = False\n\n    Application.DisplayAlerts  = False\n\n    totalCount = 0\n\n\n\n    extensions(0) = \"*.xlsx\"\n\n    extensions(1) = \"*.xls\"\n\n\n\n    For e = 0 To 1\n\n        fileName = Dir(srcFolder & \"\\\" & extensions(e))\n\n        Do While fileName <> \"\"\n\n            ' 略過 Excel 暫存檔（~ 開頭）\n\n            If Left(fileName, 1) <> \"~\" Then\n\n                wbPath  = srcFolder & \"\\\" & fileName\n\n                pdfPath = outFolder & \"\\\" & Left(fileName, InStrRev(fileName, \".\") - 1) & \".pdf\"\n\n                On Error Resume Next\n\n                Set wb = Workbooks.Open(Filename:=wbPath, ReadOnly:=True)\n\n                If Err.Number = 0 Then\n\n                    wb.Sheets(1).ExportAsFixedFormat _\n\n                        Type:=xlTypePDF, _\n\n                        Filename:=pdfPath, _\n\n                        Quality:=xlQualityStandard, _\n\n                        IncludeDocProperties:=True, _\n\n                        IgnorePrintAreas:=False, _\n\n                        OpenAfterPublish:=False\n\n                    wb.Close SaveChanges:=False\n\n                    totalCount = totalCount + 1\n\n                End If\n\n                Err.Clear\n\n                On Error GoTo 0\n\n            End If\n\n            fileName = Dir\n\n        Loop\n\n    Next e\n\n\n\n    Application.ScreenUpdating = True\n\n    Application.DisplayAlerts  = True\n\n\n\n    MsgBox \"批次匯出完成！共匯出 \" & totalCount & \" 個 PDF 檔案。\", vbInformation, \"完成\"\n\nEnd Sub\n\n", "content_b64": ""}, {"name": "ExportPDFBySheetCondition.bas", "path": "模組/ExporttoPDF/ExportPDFBySheetCondition.bas", "content": "Attribute VB_Name = \"ExportPDFBySheetCondition\"\n\nOption Explicit\n\n\n\n' ============================================================\n\n' 範例：依條件篩選工作表後批次匯出 PDF\n\n' 功能：支援只匯出可見工作表，或依名稱關鍵字篩選後匯出\n\n' ============================================================\n\n\n\n' 只匯出所有可見（非隱藏）的工作表為個別 PDF\n\nSub ExportVisibleSheetsToPDF()\n\n    Dim folderPath  As String\n\n    Dim ws          As Worksheet\n\n    Dim pdfPath     As String\n\n    Dim totalCount  As Integer\n\n\n\n    With Application.FileDialog(msoFileDialogFolderPicker)\n\n        .Title = \"請選擇 PDF 輸出資料夾\"\n\n        If .Show <> -1 Then\n\n            MsgBox \"已取消操作。\", vbInformation, \"提示\"\n\n            Exit Sub\n\n        End If\n\n        folderPath = .SelectedItems(1)\n\n    End With\n\n\n\n    Application.ScreenUpdating = False\n\n    totalCount = 0\n\n\n\n    For Each ws In ThisWorkbook.Worksheets\n\n        If ws.Visible = xlSheetVisible Then\n\n            pdfPath = folderPath & \"\\\" & ws.Name & \".pdf\"\n\n            On Error Resume Next\n\n            ws.ExportAsFixedFormat _\n\n                Type:=xlTypePDF, _\n\n                Filename:=pdfPath, _\n\n                Quality:=xlQualityStandard, _\n\n                IncludeDocProperties:=True, _\n\n                IgnorePrintAreas:=False, _\n\n                OpenAfterPublish:=False\n\n            If Err.Number = 0 Then totalCount = totalCount + 1\n\n            Err.Clear\n\n            On Error GoTo 0\n\n        End If\n\n    Next ws\n\n\n\n    Application.ScreenUpdating = True\n\n    MsgBox \"已匯出所有可見工作表為 PDF，共 \" & totalCount & \" 個。\", vbInformation, \"完成\"\n\nEnd Sub\n\n\n\n' 依工作表名稱關鍵字篩選，符合者匯出為 PDF\n\nSub ExportSheetsByKeywordToPDF()\n\n    Dim folderPath  As String\n\n    Dim ws          As Worksheet\n\n    Dim pdfPath     As String\n\n    Dim keyword     As String\n\n    Dim totalCount  As Integer\n\n\n\n    keyword = InputBox(\"請輸入工作表名稱關鍵字（模糊比對）：\", \"關鍵字篩選匯出\")\n\n    If Trim(keyword) = \"\" Then\n\n        MsgBox \"未輸入關鍵字，操作取消。\", vbInformation, \"提示\"\n\n        Exit Sub\n\n    End If\n\n\n\n    With Application.FileDialog(msoFileDialogFolderPicker)\n\n        .Title = \"請選擇 PDF 輸出資料夾\"\n\n        If .Show <> -1 Then\n\n            MsgBox \"已取消操作。\", vbInformation, \"提示\"\n\n            Exit Sub\n\n        End If\n\n        folderPath = .SelectedItems(1)\n\n    End With\n\n\n\n    Application.ScreenUpdating = False\n\n    totalCount = 0\n\n\n\n    For Each ws In ThisWorkbook.Worksheets\n\n        If InStr(1, ws.Name, keyword, vbTextCompare) > 0 Then\n\n            pdfPath = folderPath & \"\\\" & ws.Name & \".pdf\"\n\n            On Error Resume Next\n\n            ws.ExportAsFixedFormat _\n\n                Type:=xlTypePDF, _\n\n                Filename:=pdfPath, _\n\n                Quality:=xlQualityStandard, _\n\n                IncludeDocProperties:=True, _\n\n                IgnorePrintAreas:=False, _\n\n                OpenAfterPublish:=False\n\n            If Err.Number = 0 Then totalCount = totalCount + 1\n\n            Err.Clear\n\n            On Error GoTo 0\n\n        End If\n\n    Next ws\n\n\n\n    Application.ScreenUpdating = True\n\n\n\n    If totalCount = 0 Then\n\n        MsgBox \"沒有符合關鍵字「\" & keyword & \"」的工作表。\", vbExclamation, \"提示\"\n\n    Else\n\n        MsgBox \"已匯出名稱含「\" & keyword & \"」的工作表，共 \" & totalCount & \" 個 PDF。\", vbInformation, \"完成\"\n\n    End If\n\nEnd Sub\n\n", "content_b64": ""}, {"name": "ExportPDFWithAutoFileName.bas", "path": "模組/ExporttoPDF/ExportPDFWithAutoFileName.bas", "content": "Attribute VB_Name = \"ExportPDFWithAutoFileName\"\n\nOption Explicit\n\n\n\n' ============================================================\n\n' 範例：自動以儲存格值與時間戳記產生 PDF 檔名後匯出\n\n' 功能：讀取 A1 儲存格的文字作為檔名前綴，自動加上日期時間後存檔\n\n' ============================================================\n\n\n\nSub ExportPDFWithAutoFileName()\n\n    Dim ws          As Worksheet\n\n    Dim folderPath  As String\n\n    Dim cellValue   As String\n\n    Dim pdfPath     As String\n\n\n\n    Set ws = ActiveSheet\n\n\n\n    ' 取得 A1 儲存格內容作為檔名前綴\n\n    cellValue = Trim(ws.Range(\"A1\").Value)\n\n    If Len(cellValue) = 0 Then cellValue = ws.Name\n\n\n\n    ' 選擇輸出資料夾\n\n    With Application.FileDialog(msoFileDialogFolderPicker)\n\n        .Title = \"請選擇 PDF 輸出資料夾\"\n\n        .AllowMultiSelect = False\n\n        If .Show <> -1 Then\n\n            MsgBox \"已取消操作。\", vbInformation, \"提示\"\n\n            Exit Sub\n\n        End If\n\n        folderPath = .SelectedItems(1)\n\n    End With\n\n\n\n    ' 組合完整路徑：資料夾 + A1內容 + 時間戳記\n\n    pdfPath = folderPath & \"\\\" & cellValue & \"_\" & Format(Now, \"yyyymmdd_hhnnss\") & \".pdf\"\n\n\n\n    On Error GoTo ErrHandler\n\n    ws.ExportAsFixedFormat _\n\n        Type:=xlTypePDF, _\n\n        Filename:=pdfPath, _\n\n        Quality:=xlQualityStandard, _\n\n        IncludeDocProperties:=True, _\n\n        IgnorePrintAreas:=False, _\n\n        OpenAfterPublish:=False\n\n\n\n    MsgBox \"PDF 已成功匯出！\" & vbCrLf & \"儲存路徑：\" & pdfPath, vbInformation, \"完成\"\n\n    Exit Sub\n\n\n\nErrHandler:\n\n    MsgBox \"匯出失敗！\" & vbCrLf & \"錯誤：\" & Err.Description, vbCritical, \"錯誤\"\n\nEnd Sub\n\n", "content_b64": ""}, {"name": "ExportPDFWithCustomPageSetup.bas", "path": "模組/ExporttoPDF/ExportPDFWithCustomPageSetup.bas", "content": "Attribute VB_Name = \"ExportPDFWithCustomPageSetup\"\n\nOption Explicit\n\n\n\n' ============================================================\n\n' 範例：套用自訂頁面設定後再匯出 PDF\n\n' 功能：設定 A4 橫向、四邊 1cm 邊界、自動縮放，完成後還原\n\n' ============================================================\n\n\n\nSub ExportPDFWithCustomPageSetup()\n\n    Dim ws               As Worksheet\n\n    Dim pdfPath          As String\n\n    Dim origOrientation  As XlPageOrientation\n\n    Dim origPaperSize    As XlPaperSize\n\n    Dim origTopMargin    As Double\n\n    Dim origBottomMargin As Double\n\n    Dim origLeftMargin   As Double\n\n    Dim origRightMargin  As Double\n\n    Dim hadError         As Boolean\n\n\n\n    Set ws = ActiveSheet\n\n\n\n    ' 備份原始頁面設定\n\n    With ws.PageSetup\n\n        origOrientation  = .Orientation\n\n        origPaperSize    = .PaperSize\n\n        origTopMargin    = .TopMargin\n\n        origBottomMargin = .BottomMargin\n\n        origLeftMargin   = .LeftMargin\n\n        origRightMargin  = .RightMargin\n\n    End With\n\n\n\n    With Application.FileDialog(msoFileDialogSaveAs)\n\n        .Title = \"請選擇 PDF 儲存位置\"\n\n        .InitialFileName = ws.Name & \"_Custom.pdf\"\n\n        If .Show <> -1 Then\n\n            MsgBox \"已取消操作。\", vbInformation, \"提示\"\n\n            Exit Sub\n\n        End If\n\n        pdfPath = .SelectedItems(1)\n\n    End With\n\n\n\n    If LCase(Right(pdfPath, 4)) <> \".pdf\" Then pdfPath = pdfPath & \".pdf\"\n\n\n\n    hadError = False\n\n    On Error GoTo RestoreSettings\n\n\n\n    ' 套用自訂頁面設定（A4 橫向，四邊 1 公分，自動縮放至單頁寬）\n\n    With ws.PageSetup\n\n        .Orientation     = xlLandscape\n\n        .PaperSize       = xlPaperA4\n\n        .TopMargin       = Application.CentimetersToPoints(1)\n\n        .BottomMargin    = Application.CentimetersToPoints(1)\n\n        .LeftMargin      = Application.CentimetersToPoints(1)\n\n        .RightMargin     = Application.CentimetersToPoints(1)\n\n        .Zoom            = False\n\n        .FitToPagesWide  = 1\n\n        .FitToPagesTall  = False\n\n    End With\n\n\n\n    ws.ExportAsFixedFormat _\n\n        Type:=xlTypePDF, _\n\n        Filename:=pdfPath, _\n\n        Quality:=xlQualityStandard, _\n\n        IncludeDocProperties:=True, _\n\n        IgnorePrintAreas:=False, _\n\n        OpenAfterPublish:=False\n\n\n\n    MsgBox \"已套用自訂頁面設定並匯出 PDF：\" & vbCrLf & pdfPath, vbInformation, \"完成\"\n\n\n\nRestoreSettings:\n\n    hadError = (Err.Number <> 0)\n\n    If hadError Then\n\n        MsgBox \"匯出失敗：\" & Err.Description, vbCritical, \"錯誤\"\n\n    End If\n\n    ' 還原原始頁面設定\n\n    On Error Resume Next\n\n    With ws.PageSetup\n\n        .Orientation     = origOrientation\n\n        .PaperSize       = origPaperSize\n\n        .TopMargin       = origTopMargin\n\n        .BottomMargin    = origBottomMargin\n\n        .LeftMargin      = origLeftMargin\n\n        .RightMargin     = origRightMargin\n\n        .Zoom            = 100\n\n        .FitToPagesWide  = False\n\n        .FitToPagesTall  = False\n\n    End With\n\n    On Error GoTo 0\n\nEnd Sub\n\n", "content_b64": ""}, {"name": "ExportPDFWithProgress.bas", "path": "模組/ExporttoPDF/ExportPDFWithProgress.bas", "content": "Attribute VB_Name = \"ExportPDFWithProgress\"\n\nOption Explicit\n\n\n\n' ============================================================\n\n' 範例：逐一匯出工作表為 PDF，並在狀態列即時顯示進度文字\n\n' 功能：每匯出一張工作表即更新 Excel 狀態列，完成後自動還原\n\n' ============================================================\n\n\n\nSub ExportPDFWithProgress()\n\n    Dim folderPath  As String\n\n    Dim ws          As Worksheet\n\n    Dim pdfPath     As String\n\n    Dim total       As Integer\n\n    Dim current     As Integer\n\n    Dim errCount    As Integer\n\n\n\n    With Application.FileDialog(msoFileDialogFolderPicker)\n\n        .Title = \"請選擇 PDF 輸出資料夾\"\n\n        If .Show <> -1 Then\n\n            MsgBox \"已取消操作。\", vbInformation, \"提示\"\n\n            Exit Sub\n\n        End If\n\n        folderPath = .SelectedItems(1)\n\n    End With\n\n\n\n    total    = ThisWorkbook.Worksheets.Count\n\n    current  = 0\n\n    errCount = 0\n\n\n\n    Application.ScreenUpdating = False\n\n\n\n    For Each ws In ThisWorkbook.Worksheets\n\n        current = current + 1\n\n        ' 更新狀態列顯示目前進度\n\n        Application.StatusBar = \"正在匯出第 \" & current & \" / \" & total & _\n\n                                \" 張：\" & ws.Name & \"　請稍候...\"\n\n\n\n        pdfPath = folderPath & \"\\\" & ws.Name & \".pdf\"\n\n\n\n        On Error Resume Next\n\n        ws.ExportAsFixedFormat _\n\n            Type:=xlTypePDF, _\n\n            Filename:=pdfPath, _\n\n            Quality:=xlQualityStandard, _\n\n            IncludeDocProperties:=True, _\n\n            IgnorePrintAreas:=False, _\n\n            OpenAfterPublish:=False\n\n        If Err.Number <> 0 Then errCount = errCount + 1\n\n        Err.Clear\n\n        On Error GoTo 0\n\n    Next ws\n\n\n\n    Application.ScreenUpdating = True\n\n    Application.StatusBar = False  ' 還原狀態列為預設文字\n\n\n\n    MsgBox \"匯出完成！\" & vbCrLf & _\n\n           \"成功：\" & (total - errCount) & \" 張\" & vbCrLf & _\n\n           \"失敗：\" & errCount & \" 張\", vbInformation, \"完成\"\n\nEnd Sub\n\n", "content_b64": ""}, {"name": "ExportPDFWithWatermark.bas", "path": "模組/ExporttoPDF/ExportPDFWithWatermark.bas", "content": "Attribute VB_Name = \"ExportPDFWithWatermark\"\n\nOption Explicit\n\n\n\n' ============================================================\n\n' 範例：加入文字浮水印後匯出 PDF，完成後自動移除浮水印\n\n' 功能：在工作表中加入半透明文字方塊作為浮水印，匯出後刪除\n\n' ============================================================\n\n\n\nPrivate Const WATERMARK_NAME As String = \"WatermarkShape_Temp\"\n\n\n\nSub ExportPDFWithWatermark()\n\n    Dim ws          As Worksheet\n\n    Dim pdfPath     As String\n\n    Dim waterText   As String\n\n    Dim shp         As Shape\n\n    Dim centerLeft  As Double\n\n    Dim centerTop   As Double\n\n\n\n    Set ws = ActiveSheet\n\n\n\n    waterText = InputBox(\"請輸入浮水印文字：\", \"設定浮水印\", \"機密文件\")\n\n    If Trim(waterText) = \"\" Then\n\n        MsgBox \"未輸入浮水印文字，操作取消。\", vbInformation, \"提示\"\n\n        Exit Sub\n\n    End If\n\n\n\n    With Application.FileDialog(msoFileDialogSaveAs)\n\n        .Title = \"請選擇 PDF 儲存位置\"\n\n        .InitialFileName = ws.Name & \"_Watermark.pdf\"\n\n        If .Show <> -1 Then\n\n            MsgBox \"已取消操作。\", vbInformation, \"提示\"\n\n            Exit Sub\n\n        End If\n\n        pdfPath = .SelectedItems(1)\n\n    End With\n\n\n\n    If LCase(Right(pdfPath, 4)) <> \".pdf\" Then pdfPath = pdfPath & \".pdf\"\n\n\n\n    ' 以前 15 列的中間位置估算浮水印位置\n\n    centerLeft = ws.Range(\"A1\").Left + 150\n\n    centerTop  = ws.Range(\"A15\").Top\n\n\n\n    On Error GoTo ErrHandler\n\n\n\n    ' 新增浮水印文字方塊\n\n    Set shp = ws.Shapes.AddTextbox(msoTextOrientationHorizontal, _\n\n                                   centerLeft, centerTop, 350, 80)\n\n    With shp\n\n        .Name = WATERMARK_NAME\n\n        .Line.Visible = msoFalse\n\n        .Fill.Visible = msoFalse\n\n        .Rotation = 315\n\n        With .TextFrame2.TextRange\n\n            .Text = waterText\n\n            With .Font\n\n                .Size = 54\n\n                .Bold = msoTrue\n\n                .Fill.Visible = msoTrue\n\n                .Fill.ForeColor.RGB = RGB(210, 210, 210)\n\n                .Fill.Transparency = 0.3\n\n            End With\n\n        End With\n\n    End With\n\n\n\n    ws.ExportAsFixedFormat _\n\n        Type:=xlTypePDF, _\n\n        Filename:=pdfPath, _\n\n        Quality:=xlQualityStandard, _\n\n        IncludeDocProperties:=True, _\n\n        IgnorePrintAreas:=False, _\n\n        OpenAfterPublish:=False\n\n\n\n    MsgBox \"含浮水印的 PDF 已匯出：\" & vbCrLf & pdfPath, vbInformation, \"完成\"\n\n\n\nErrHandler:\n\n    If Err.Number <> 0 Then\n\n        MsgBox \"操作失敗：\" & Err.Description, vbCritical, \"錯誤\"\n\n    End If\n\n    RemoveWatermark ws\n\nEnd Sub\n\n\n\nPrivate Sub RemoveWatermark(ByVal ws As Worksheet)\n\n    Dim shp As Shape\n\n    For Each shp In ws.Shapes\n\n        If shp.Name = WATERMARK_NAME Then\n\n            shp.Delete\n\n            Exit For\n\n        End If\n\n    Next shp\n\nEnd Sub\n\n", "content_b64": ""}, {"name": "ExportPrintAreaToPDF.bas", "path": "模組/ExporttoPDF/ExportPrintAreaToPDF.bas", "content": "Attribute VB_Name = \"ExportPrintAreaToPDF\"\n\nOption Explicit\n\n\n\n' ============================================================\n\n' 範例：僅匯出工作表設定的列印範圍為 PDF\n\n' 功能：讀取現有列印範圍設定，或由使用者選取後設定並匯出\n\n' ============================================================\n\n\n\n' 匯出已設定好的列印範圍為 PDF\n\nSub ExportPrintAreaToPDF()\n\n    Dim ws      As Worksheet\n\n    Dim pdfPath As String\n\n\n\n    Set ws = ActiveSheet\n\n\n\n    If ws.PageSetup.PrintArea = \"\" Then\n\n        MsgBox \"目前工作表尚未設定列印範圍。\" & vbCrLf & _\n\n               \"請先選取範圍，再到「版面配置 > 列印範圍 > 設定列印範圍」。\", _\n\n               vbExclamation, \"提示\"\n\n        Exit Sub\n\n    End If\n\n\n\n    With Application.FileDialog(msoFileDialogSaveAs)\n\n        .Title = \"請選擇列印範圍 PDF 儲存位置\"\n\n        .InitialFileName = ws.Name & \"_PrintArea.pdf\"\n\n        If .Show <> -1 Then\n\n            MsgBox \"已取消操作。\", vbInformation, \"提示\"\n\n            Exit Sub\n\n        End If\n\n        pdfPath = .SelectedItems(1)\n\n    End With\n\n\n\n    If LCase(Right(pdfPath, 4)) <> \".pdf\" Then pdfPath = pdfPath & \".pdf\"\n\n\n\n    On Error GoTo ErrHandler\n\n    ' IgnorePrintAreas = False 確保只輸出已設定的列印範圍\n\n    ws.ExportAsFixedFormat _\n\n        Type:=xlTypePDF, _\n\n        Filename:=pdfPath, _\n\n        Quality:=xlQualityStandard, _\n\n        IncludeDocProperties:=True, _\n\n        IgnorePrintAreas:=False, _\n\n        OpenAfterPublish:=False\n\n\n\n    MsgBox \"列印範圍已匯出為 PDF：\" & vbCrLf & pdfPath, vbInformation, \"完成\"\n\n    Exit Sub\n\n\n\nErrHandler:\n\n    MsgBox \"匯出失敗：\" & Err.Description, vbCritical, \"錯誤\"\n\nEnd Sub\n\n\n\n' 由使用者選取範圍，臨時設定列印範圍後匯出，完成後清除設定\n\nSub SetPrintAreaAndExportToPDF()\n\n    Dim ws          As Worksheet\n\n    Dim rng         As Range\n\n    Dim folderPath  As String\n\n    Dim pdfPath     As String\n\n    Dim origArea    As String\n\n\n\n    Set ws = ActiveSheet\n\n\n\n    If TypeName(Selection) <> \"Range\" Then\n\n        MsgBox \"請先選取要設定為列印範圍的儲存格區域。\", vbExclamation, \"提示\"\n\n        Exit Sub\n\n    End If\n\n\n\n    Set rng = Selection\n\n\n\n    With Application.FileDialog(msoFileDialogFolderPicker)\n\n        .Title = \"請選擇 PDF 輸出資料夾\"\n\n        If .Show <> -1 Then\n\n            MsgBox \"已取消操作。\", vbInformation, \"提示\"\n\n            Exit Sub\n\n        End If\n\n        folderPath = .SelectedItems(1)\n\n    End With\n\n\n\n    pdfPath  = folderPath & \"\\\" & ws.Name & \"_CustomPrintArea.pdf\"\n\n    origArea = ws.PageSetup.PrintArea\n\n\n\n    ' 臨時套用列印範圍\n\n    ws.PageSetup.PrintArea = rng.Address\n\n\n\n    On Error GoTo RestoreArea\n\n    ws.ExportAsFixedFormat _\n\n        Type:=xlTypePDF, _\n\n        Filename:=pdfPath, _\n\n        Quality:=xlQualityStandard, _\n\n        IncludeDocProperties:=True, _\n\n        IgnorePrintAreas:=False, _\n\n        OpenAfterPublish:=False\n\n\n\n    MsgBox \"選取範圍已匯出為 PDF：\" & vbCrLf & pdfPath, vbInformation, \"完成\"\n\n\n\nRestoreArea:\n\n    If Err.Number <> 0 Then\n\n        MsgBox \"匯出失敗：\" & Err.Description, vbCritical, \"錯誤\"\n\n    End If\n\n    ' 還原原始列印範圍設定\n\n    ws.PageSetup.PrintArea = origArea\n\nEnd Sub\n\n", "content_b64": ""}, {"name": "ExportSelectedRangeToPDF.bas", "path": "模組/ExporttoPDF/ExportSelectedRangeToPDF.bas", "content": "Option Explicit\n\nPrivate Const MsoFileDialogFolderPicker As Long = 4\n\n' 將目前選取範圍轉存成 PDF。\nPublic Sub ExportSelectedRangeToPDFExample()\n    On Error GoTo ErrHandler\n\n    Dim selectedRange As Range\n    Dim folderPath As String\n    Dim pdfPath As String\n\n    If TypeName(Selection) <> \"Range\" Then\n        MsgBox \"請先選取要轉存的儲存格範圍。\", vbExclamation, \"提醒\"\n        Exit Sub\n    End If\n\n    Set selectedRange = Selection\n    folderPath = PickPdfFolder()\n    If Len(folderPath) = 0 Then Exit Sub\n\n    pdfPath = folderPath & \"\\SelectedRange_\" & Format(Now, \"yyyymmdd_hhnnss\") & \".pdf\"\n    selectedRange.ExportAsFixedFormat Type:=xlTypePDF, Filename:=pdfPath, Quality:=xlQualityStandard, IncludeDocProperties:=True, IgnorePrintAreas:=False, OpenAfterPublish:=False\n\n    MsgBox \"PDF 已轉存完成：\" & pdfPath, vbInformation, \"完成\"\n    Exit Sub\n\nErrHandler:\n    MsgBox \"轉存 PDF 失敗：\" & Err.Description, vbExclamation, \"錯誤\"\nEnd Sub\n\nPrivate Function PickPdfFolder() As String\n    With Application.FileDialog(MsoFileDialogFolderPicker)\n        .Title = \"請選擇 PDF 輸出資料夾\"\n        .AllowMultiSelect = False\n        If .Show = -1 Then\n            PickPdfFolder = .SelectedItems(1)\n        End If\n    End With\nEnd Function", "content_b64": ""}, {"name": "ExportSheetToPDF.bas", "path": "模組/ExporttoPDF/ExportSheetToPDF.bas", "content": "Attribute VB_Name = \"ExportSheetToPDF\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: ExportSheetToPDF\n'功能說明: 將指定工作表或整個活頁簿匯出為 PDF 檔案\n'\n'著作權所有: Dunk\n'程式設計: Dunk\n'撰寫日期: 2026/5/7\n'\n'*************************************************************************************\n\n' 測試用入口\nSub TestExportSheetToPDF()\n    Call ExportActiveSheetToPDF\nEnd Sub\n\n' 將目前使用中的工作表匯出為 PDF\nSub ExportActiveSheetToPDF()\n    Dim ws As Worksheet\n    Dim pdfPath As String\n    Dim defaultName As String\n\n    Set ws = ActiveSheet\n    defaultName = ws.Name & \".pdf\"\n\n    With Application.FileDialog(msoFileDialogSaveAs)\n        .Title = \"請選擇 PDF 儲存路徑\"\n        .InitialFileName = defaultName\n        .FilterIndex = 1\n        If .Show <> -1 Then\n            MsgBox \"已取消操作\", vbInformation, \"取消\"\n            Exit Sub\n        End If\n        pdfPath = .SelectedItems(1)\n    End With\n\n    If LCase(Right(pdfPath, 4)) <> \".pdf\" Then\n        pdfPath = pdfPath & \".pdf\"\n    End If\n\n    On Error GoTo ErrorHandler\n    ws.ExportAsFixedFormat _\n        Type:=xlTypePDF, _\n        Filename:=pdfPath, _\n        Quality:=xlQualityStandard, _\n        IncludeDocProperties:=True, _\n        IgnorePrintAreas:=False, _\n        OpenAfterPublish:=False\n\n    MsgBox \"PDF 匯出完成！\" & vbCrLf & \"儲存路徑：\" & pdfPath, vbInformation, \"完成\"\n    Exit Sub\n\nErrorHandler:\n    MsgBox \"匯出失敗！\" & vbCrLf & \"錯誤：\" & Err.Description, vbCritical, \"錯誤\"\nEnd Sub\n\n' 將整個活頁簿匯出為單一 PDF\nSub ExportWorkbookToPDF()\n    Dim pdfPath As String\n    Dim defaultName As String\n\n    defaultName = ThisWorkbook.Name\n    If InStr(defaultName, \".\") > 0 Then\n        defaultName = Left(defaultName, InStrRev(defaultName, \".\") - 1) & \".pdf\"\n    End If\n\n    With Application.FileDialog(msoFileDialogSaveAs)\n        .Title = \"請選擇整本活頁簿 PDF 儲存路徑\"\n        .InitialFileName = defaultName\n        If .Show <> -1 Then\n            MsgBox \"已取消操作\", vbInformation, \"取消\"\n            Exit Sub\n        End If\n        pdfPath = .SelectedItems(1)\n    End With\n\n    If LCase(Right(pdfPath, 4)) <> \".pdf\" Then\n        pdfPath = pdfPath & \".pdf\"\n    End If\n\n    On Error GoTo ErrorHandler\n    ThisWorkbook.ExportAsFixedFormat _\n        Type:=xlTypePDF, _\n        Filename:=pdfPath, _\n        Quality:=xlQualityStandard, _\n        IncludeDocProperties:=True, _\n        IgnorePrintAreas:=False, _\n        OpenAfterPublish:=False\n\n    MsgBox \"整本活頁簿 PDF 匯出完成！\" & vbCrLf & \"儲存路徑：\" & pdfPath, vbInformation, \"完成\"\n    Exit Sub\n\nErrorHandler:\n    MsgBox \"匯出失敗！\" & vbCrLf & \"錯誤：\" & Err.Description, vbCritical, \"錯誤\"\nEnd Sub\n\n' 批次將所有工作表分別匯出為獨立 PDF\nSub ExportEachSheetToPDF()\n    Dim ws As Worksheet\n    Dim folderPath As String\n    Dim pdfPath As String\n    Dim count As Integer\n\n    With Application.FileDialog(msoFileDialogFolderPicker)\n        .Title = \"請選擇 PDF 輸出資料夾\"\n        If .Show <> -1 Then\n            MsgBox \"已取消操作\", vbInformation, \"取消\"\n            Exit Sub\n        End If\n        folderPath = .SelectedItems(1)\n    End With\n\n    Application.ScreenUpdating = False\n    count = 0\n\n    For Each ws In ThisWorkbook.Worksheets\n        pdfPath = folderPath & \"\" & ws.Name & \".pdf\"\n        On Error Resume Next\n        ws.ExportAsFixedFormat _\n            Type:=xlTypePDF, _\n            Filename:=pdfPath, _\n            Quality:=xlQualityStandard, _\n            IncludeDocProperties:=True, _\n            IgnorePrintAreas:=False, _\n            OpenAfterPublish:=False\n        If Err.Number = 0 Then count = count + 1\n        On Error GoTo 0\n    Next ws\n\n    Application.ScreenUpdating = True\n    MsgBox \"批次匯出完成！共匯出 \" & count & \" 個 PDF 檔案。\", vbInformation, \"完成\"\nEnd Sub\n", "content_b64": ""}, {"name": "ExportSpecificSheetsToPDF.bas", "path": "模組/ExporttoPDF/ExportSpecificSheetsToPDF.bas", "content": "Attribute VB_Name = \"ExportSpecificSheetsToPDF\"\n\nOption Explicit\n\n\n\n' ============================================================\n\n' 範例：將使用者指定的工作表名稱清單合併匯出成一份 PDF\n\n' 功能：以逗號分隔輸入工作表名稱，合併列印為單一 PDF 檔\n\n' ============================================================\n\n\n\nSub ExportSpecificSheetsToPDF()\n\n    Dim inputNames  As String\n\n    Dim nameArr()   As String\n\n    Dim wsNames()   As String\n\n    Dim pdfPath     As String\n\n    Dim i           As Integer\n\n    Dim validCount  As Integer\n\n    Dim sheetName   As String\n\n\n\n    inputNames = InputBox(\"請輸入要匯出的工作表名稱（以逗號分隔）：\", \"指定工作表匯出 PDF\")\n\n    If Trim(inputNames) = \"\" Then\n\n        MsgBox \"未輸入任何工作表名稱，操作取消。\", vbInformation, \"提示\"\n\n        Exit Sub\n\n    End If\n\n\n\n    nameArr = Split(inputNames, \",\")\n\n    ReDim wsNames(0 To UBound(nameArr))\n\n    validCount = 0\n\n\n\n    For i = 0 To UBound(nameArr)\n\n        sheetName = Trim(nameArr(i))\n\n        If SheetExists(sheetName) Then\n\n            wsNames(validCount) = sheetName\n\n            validCount = validCount + 1\n\n        Else\n\n            MsgBox \"找不到工作表：\" & sheetName & \"，將略過。\", vbExclamation, \"警告\"\n\n        End If\n\n    Next i\n\n\n\n    If validCount = 0 Then\n\n        MsgBox \"沒有有效的工作表可匯出。\", vbExclamation, \"警告\"\n\n        Exit Sub\n\n    End If\n\n\n\n    ReDim Preserve wsNames(0 To validCount - 1)\n\n\n\n    With Application.FileDialog(msoFileDialogSaveAs)\n\n        .Title = \"請選擇 PDF 儲存位置\"\n\n        .InitialFileName = \"SpecificSheets.pdf\"\n\n        If .Show <> -1 Then\n\n            MsgBox \"已取消操作。\", vbInformation, \"提示\"\n\n            Exit Sub\n\n        End If\n\n        pdfPath = .SelectedItems(1)\n\n    End With\n\n\n\n    If LCase(Right(pdfPath, 4)) <> \".pdf\" Then pdfPath = pdfPath & \".pdf\"\n\n\n\n    On Error GoTo ErrHandler\n\n    ThisWorkbook.Sheets(wsNames).Select\n\n    ActiveSheet.ExportAsFixedFormat _\n\n        Type:=xlTypePDF, _\n\n        Filename:=pdfPath, _\n\n        Quality:=xlQualityStandard, _\n\n        IncludeDocProperties:=True, _\n\n        IgnorePrintAreas:=False, _\n\n        OpenAfterPublish:=False\n\n\n\n    ThisWorkbook.Sheets(1).Select\n\n    MsgBox \"指定工作表已匯出為 PDF：\" & vbCrLf & pdfPath, vbInformation, \"完成\"\n\n    Exit Sub\n\n\n\nErrHandler:\n\n    MsgBox \"匯出失敗：\" & Err.Description, vbCritical, \"錯誤\"\n\nEnd Sub\n\n\n\nPrivate Function SheetExists(ByVal sheetName As String) As Boolean\n\n    Dim ws As Object\n\n    On Error Resume Next\n\n    Set ws = ThisWorkbook.Sheets(sheetName)\n\n    SheetExists = (Not ws Is Nothing)\n\n    On Error GoTo 0\n\nEnd Function\n\n", "content_b64": ""}]}, {"folder": "FileMerge", "path": "模組/FileMerge", "files": [{"name": "MergeAllSheetsToWorkbook.bas", "path": "模組/FileMerge/MergeAllSheetsToWorkbook.bas", "content": "Attribute VB_Name = \"MergeAllSheetsToWorkbook\"\nOption Explicit\n\n' ============================================================\n' 範例：將多個活頁簿的所有工作表複製至單一新活頁簿\n' 功能：搜尋指定資料夾的所有 .xlsx 活頁簿，\n'       將每個活頁簿的所有工作表各別複製成獨立工作表，\n'       工作表命名格式：來源檔名_工作表名\n' ============================================================\n\nSub MergeAllSheetsIntoOneWorkbook()\n    On Error GoTo ErrHandler\n\n    Dim strFolder   As String\n    Dim strFile     As String\n    Dim wbSrc       As Workbook\n    Dim wbDest      As Workbook\n    Dim wsSrc       As Worksheet\n    Dim strNewName  As String\n    Dim lngSheetsCount As Long\n    Dim lngFilesCount  As Long\n\n    ' --- 選擇資料夾 ---\n    With Application.FileDialog(msoFileDialogFolderPicker)\n        .Title = \"請選擇包含 Excel 活頁簿的資料夾\"\n        If .Show <> -1 Then\n            MsgBox \"已取消操作。\", vbInformation, \"提示\"\n            Exit Sub\n        End If\n        strFolder = .SelectedItems(1)\n    End With\n\n    If Right(strFolder, 1) <> \"\\\" Then strFolder = strFolder & \"\\\"\n\n    strFile = Dir(strFolder & \"*.xlsx\")\n    If strFile = \"\" Then\n        MsgBox \"找不到任何 .xlsx 活頁簿。\", vbExclamation, \"警告\"\n        Exit Sub\n    End If\n\n    Application.ScreenUpdating = False\n    Application.DisplayAlerts = False\n\n    ' --- 建立新目標活頁簿 ---\n    Set wbDest = Workbooks.Add\n    ' 刪除預設工作表（保留最後一個以防出錯）\n    Do While wbDest.Sheets.Count > 1\n        wbDest.Sheets(1).Delete\n    Loop\n\n    lngSheetsCount = 0\n    lngFilesCount = 0\n\n    Do While strFile <> \"\"\n        If StrComp(strFile, ThisWorkbook.Name, vbTextCompare) <> 0 Then\n            Set wbSrc = Nothing\n            On Error Resume Next\n            Set wbSrc = Workbooks.Open(Filename:=strFolder & strFile, ReadOnly:=True)\n            On Error GoTo ErrHandler\n\n            If Not wbSrc Is Nothing Then\n                Dim i As Long\n                For i = 1 To wbSrc.Sheets.Count\n                    Set wsSrc = wbSrc.Sheets(i)\n                    ' 命名：前 15 字元的檔名 + _ + 工作表名\n                    Dim strBaseName As String\n                    strBaseName = Left(Replace(strFile, \".xlsx\", \"\"), 15)\n                    strNewName = strBaseName & \"_\" & Left(wsSrc.Name, 15)\n                    ' 確保名稱不重複\n                    Dim lngSuffix As Long\n                    lngSuffix = 0\n                    Dim strFinalName As String\n                    strFinalName = strNewName\n                    On Error Resume Next\n                    Do While wbDest.Sheets(strFinalName) Is Nothing = False\n                        lngSuffix = lngSuffix + 1\n                        strFinalName = Left(strNewName, 28) & \"_\" & lngSuffix\n                    Loop\n                    On Error GoTo ErrHandler\n                    wsSrc.Copy After:=wbDest.Sheets(wbDest.Sheets.Count)\n                    wbDest.Sheets(wbDest.Sheets.Count).Name = strFinalName\n                    lngSheetsCount = lngSheetsCount + 1\n                Next i\n                wbSrc.Close SaveChanges:=False\n                lngFilesCount = lngFilesCount + 1\n            End If\n        End If\n        strFile = Dir()\n    Loop\n\n    ' 刪除初始預留的空白工作表（Sheet1）\n    On Error Resume Next\n    wbDest.Sheets(\"Sheet1\").Delete\n    On Error GoTo ErrHandler\n\n    Application.ScreenUpdating = True\n    Application.DisplayAlerts = True\n\n    MsgBox \"工作表合併至新活頁簿完成！\" & vbCrLf & _\n           \"共處理 \" & lngFilesCount & \" 個檔案，\" & _\n           \"複製 \" & lngSheetsCount & \" 個工作表。\", vbInformation, \"完成\"\n    Exit Sub\n\nErrHandler:\n    Application.ScreenUpdating = True\n    Application.DisplayAlerts = True\n    MsgBox \"合併過程發生錯誤：\" & Err.Description, vbCritical, \"錯誤\"\nEnd Sub", "content_b64": ""}, {"name": "MergeCSVFiles.bas", "path": "模組/FileMerge/MergeCSVFiles.bas", "content": "Attribute VB_Name = \"MergeCSVFiles\"\n\nOption Explicit\n\n\n\n' ============================================================\n\n' 範例：合併同一資料夾下所有 CSV 檔案至單一工作表\n\n' 功能：讀取目標資料夾內所有 .csv 並逐列合併，第一個檔案保留標題\n\n' ============================================================\n\nSub MergeAllCSVFiles()\n\n    Dim strFolder   As String\n\n    Dim strFile     As String\n\n    Dim wsDest      As Worksheet\n\n    Dim wbSrc       As Workbook\n\n    Dim wsSrc       As Worksheet\n\n    Dim lngLastRow  As Long\n\n    Dim lngDestRow  As Long\n\n    Dim lngStartRow As Long\n\n    Dim blnFirst    As Boolean\n\n\n\n    ' --- 選擇資料夾 ---\n\n    With Application.FileDialog(msoFileDialogFolderPicker)\n\n        .Title = \"請選擇包含 CSV 檔案的資料夾\"\n\n        If .Show <> -1 Then\n\n            MsgBox \"已取消操作。\", vbInformation\n\n            Exit Sub\n\n        End If\n\n        strFolder = .SelectedItems(1)\n\n    End With\n\n\n\n    If Right(strFolder, 1) <> \"\\\" Then strFolder = strFolder & \"\\\"\n\n\n\n    ' --- 建立目標工作表 ---\n\n    On Error GoTo ErrHandler\n\n    Set wsDest = ThisWorkbook.Worksheets.Add\n\n    wsDest.Name = \"MergedCSV_\" & Format(Now(), \"mmddHHmm\")\n\n    lngDestRow = 1\n\n    blnFirst = True\n\n\n\n    Application.ScreenUpdating = False\n\n    Application.DisplayAlerts = False\n\n\n\n    strFile = Dir(strFolder & \"*.csv\")\n\n    If strFile = \"\" Then\n\n        MsgBox \"找不到任何 CSV 檔案。\", vbExclamation\n\n        GoTo CleanUp\n\n    End If\n\n\n\n    Do While strFile <> \"\"\n\n        Set wbSrc = Workbooks.Open(Filename:=strFolder & strFile, ReadOnly:=True)\n\n        Set wsSrc = wbSrc.Sheets(1)\n\n        lngLastRow = wsSrc.Cells(wsSrc.Rows.Count, 1).End(xlUp).Row\n\n\n\n        If blnFirst Then\n\n            lngStartRow = 1  ' 第一個檔案含標題\n\n            blnFirst = False\n\n        Else\n\n            lngStartRow = 2  ' 後續檔案跳過標題\n\n        End If\n\n\n\n        wsSrc.Rows(lngStartRow & \":\" & lngLastRow).Copy _\n\n            Destination:=wsDest.Cells(lngDestRow, 1)\n\n        lngDestRow = lngDestRow + (lngLastRow - lngStartRow + 1)\n\n\n\n        wbSrc.Close SaveChanges:=False\n\n        strFile = Dir()\n\n    Loop\n\n\n\n    wsDest.Columns.AutoFit\n\n    MsgBox \"CSV 合併完成！資料已寫入工作表：\" & wsDest.Name, vbInformation\n\n\n\nCleanUp:\n\n    Application.ScreenUpdating = True\n\n    Application.DisplayAlerts = True\n\n    Exit Sub\n\n\n\nErrHandler:\n\n    Application.ScreenUpdating = True\n\n    Application.DisplayAlerts = True\n\n    MsgBox \"發生錯誤：\" & Err.Description, vbCritical\n\nEnd Sub\n\n", "content_b64": ""}, {"name": "MergeCSVToOutputFile.bas", "path": "模組/FileMerge/MergeCSVToOutputFile.bas", "content": "Attribute VB_Name = \"MergeCSVToOutputFile\"\nOption Explicit\n\n' ============================================================\n' 範例：將資料夾內所有 CSV 檔案合併輸出為單一 CSV 檔案\n' 功能：不匯入 Excel，直接以文字串流方式讀取並輸出\n'       第一個檔案保留標題列，後續檔案跳過標題\n' ============================================================\n\nSub MergeCSVFilesToSingleFile()\n    On Error GoTo ErrHandler\n\n    Dim strFolder   As String\n    Dim strOutFile  As String\n    Dim strFile     As String\n    Dim intIn       As Integer\n    Dim intOut      As Integer\n    Dim strLine     As String\n    Dim blnFirst    As Boolean\n    Dim lngFiles    As Long\n    Dim lngLines    As Long\n\n    ' --- 選擇資料夾 ---\n    With Application.FileDialog(msoFileDialogFolderPicker)\n        .Title = \"請選擇包含 CSV 檔案的資料夾\"\n        If .Show <> -1 Then\n            MsgBox \"已取消操作。\", vbInformation, \"提示\"\n            Exit Sub\n        End If\n        strFolder = .SelectedItems(1)\n    End With\n\n    If Right(strFolder, 1) <> \"\\\" Then strFolder = strFolder & \"\\\"\n    strOutFile = strFolder & \"MergedOutput.csv\"\n\n    ' 防止輸出檔已存在時重複處理\n    If Dir(strOutFile) <> \"\" Then\n        Dim intResp As Integer\n        intResp = MsgBox(\"輸出檔案已存在：\" & strOutFile & vbCrLf & \"是否覆寫？\", _\n                         vbYesNo + vbQuestion, \"確認覆寫\")\n        If intResp = vbNo Then Exit Sub\n    End If\n\n    intOut = FreeFile\n    Open strOutFile For Output As #intOut\n\n    blnFirst = True\n    lngFiles = 0\n    lngLines = 0\n\n    strFile = Dir(strFolder & \"*.csv\")\n    If strFile = \"\" Then\n        MsgBox \"找不到任何 CSV 檔案。\", vbExclamation, \"警告\"\n        Close #intOut\n        Kill strOutFile\n        Exit Sub\n    End If\n\n    Do While strFile <> \"\"\n        ' 略過輸出檔本身\n        If StrComp(strFile, \"MergedOutput.csv\", vbTextCompare) <> 0 Then\n            intIn = FreeFile\n            Open strFolder & strFile For Input As #intIn\n\n            Dim blnIsFirstLine As Boolean\n            blnIsFirstLine = True\n\n            Do While Not EOF(intIn)\n                Line Input #intIn, strLine\n                If blnIsFirstLine Then\n                    If blnFirst Then\n                        ' 第一個檔案的標題列直接寫入\n                        Print #intOut, strLine\n                        lngLines = lngLines + 1\n                        blnFirst = False\n                    End If\n                    ' 後續檔案跳過標題列\n                    blnIsFirstLine = False\n                Else\n                    Print #intOut, strLine\n                    lngLines = lngLines + 1\n                End If\n            Loop\n\n            Close #intIn\n            lngFiles = lngFiles + 1\n        End If\n        strFile = Dir()\n    Loop\n\n    Close #intOut\n\n    MsgBox \"CSV 合併完成！\" & vbCrLf & _\n           \"共合併 \" & lngFiles & \" 個檔案，輸出 \" & lngLines & \" 列。\" & vbCrLf & _\n           \"輸出路徑：\" & strOutFile, vbInformation, \"完成\"\n    Exit Sub\n\nErrHandler:\n    On Error Resume Next\n    Close #intIn\n    Close #intOut\n    On Error GoTo 0\n    MsgBox \"合併 CSV 時發生錯誤：\" & Err.Description, vbCritical, \"錯誤\"\nEnd Sub", "content_b64": ""}, {"name": "MergeExcelByKeyColumn.bas", "path": "模組/FileMerge/MergeExcelByKeyColumn.bas", "content": "Attribute VB_Name = \"MergeExcelByKeyColumn\"\nOption Explicit\n\n' ============================================================\n' 範例：以關鍵欄位（Key Column）水平合併兩個 Excel 檔案\n' 功能：選擇主檔與副檔，指定兩者的關鍵欄位欄號，\n'       依關鍵值比對後，將副檔的資料欄位附加至主檔右側\n' ============================================================\n\nSub MergeExcelByKeyColumn()\n    On Error GoTo ErrHandler\n\n    Dim strMainFile As String\n    Dim strSubFile  As String\n    Dim wbMain      As Workbook\n    Dim wbSub       As Workbook\n    Dim wsMain      As Worksheet\n    Dim wsSub       As Worksheet\n    Dim wsDest      As Worksheet\n    Dim lngKeyColMain   As Long\n    Dim lngKeyColSub    As Long\n    Dim lngMainLastRow  As Long\n    Dim lngSubLastRow   As Long\n    Dim lngMainLastCol  As Long\n    Dim lngSubLastCol   As Long\n    Dim lngRow      As Long\n    Dim lngSubRow   As Long\n    Dim strKeyVal   As String\n    Dim strInput    As String\n\n    ' --- 選擇主檔 ---\n    With Application.FileDialog(msoFileDialogFilePicker)\n        .Title = \"請選擇主檔（Main File）\"\n        .Filters.Clear\n        .Filters.Add \"Excel 檔案\", \"*.xlsx;*.xls;*.xlsm\"\n        If .Show <> -1 Then\n            MsgBox \"已取消操作。\", vbInformation, \"提示\"\n            Exit Sub\n        End If\n        strMainFile = .SelectedItems(1)\n    End With\n\n    ' --- 選擇副檔 ---\n    With Application.FileDialog(msoFileDialogFilePicker)\n        .Title = \"請選擇副檔（Sub File）\"\n        .Filters.Clear\n        .Filters.Add \"Excel 檔案\", \"*.xlsx;*.xls;*.xlsm\"\n        If .Show <> -1 Then\n            MsgBox \"已取消操作。\", vbInformation, \"提示\"\n            Exit Sub\n        End If\n        strSubFile = .SelectedItems(1)\n    End With\n\n    ' --- 取得關鍵欄位欄號 ---\n    strInput = InputBox(\"請輸入主檔的關鍵欄位欄號（如：1 代表 A 欄）：\", \"主檔關鍵欄\", \"1\")\n    If Not IsNumeric(strInput) Or CLng(strInput) < 1 Then\n        MsgBox \"欄號輸入無效，已取消。\", vbExclamation, \"警告\"\n        Exit Sub\n    End If\n    lngKeyColMain = CLng(strInput)\n\n    strInput = InputBox(\"請輸入副檔的關鍵欄位欄號（如：1 代表 A 欄）：\", \"副檔關鍵欄\", \"1\")\n    If Not IsNumeric(strInput) Or CLng(strInput) < 1 Then\n        MsgBox \"欄號輸入無效，已取消。\", vbExclamation, \"警告\"\n        Exit Sub\n    End If\n    lngKeyColSub = CLng(strInput)\n\n    Application.ScreenUpdating = False\n    Application.DisplayAlerts = False\n\n    Set wbMain = Workbooks.Open(Filename:=strMainFile, ReadOnly:=True)\n    Set wsMain = wbMain.Sheets(1)\n    Set wbSub = Workbooks.Open(Filename:=strSubFile, ReadOnly:=True)\n    Set wsSub = wbSub.Sheets(1)\n\n    lngMainLastRow = wsMain.Cells(wsMain.Rows.Count, lngKeyColMain).End(xlUp).Row\n    lngSubLastRow = wsSub.Cells(wsSub.Rows.Count, lngKeyColSub).End(xlUp).Row\n    lngMainLastCol = wsMain.Cells(1, wsMain.Columns.Count).End(xlToLeft).Column\n    lngSubLastCol = wsSub.Cells(1, wsSub.Columns.Count).End(xlToLeft).Column\n\n    ' --- 建立目標工作表 ---\n    Set wsDest = ThisWorkbook.Worksheets.Add\n    wsDest.Name = \"KeyMerged_\" & Format(Now(), \"mmddHHmm\")\n\n    ' 複製主檔全部資料\n    wsMain.Cells(1, 1).Resize(lngMainLastRow, lngMainLastCol).Copy _\n        Destination:=wsDest.Cells(1, 1)\n\n    ' 寫入副檔標題（排除 Key 欄）至目標表右側\n    Dim lngDestStartCol As Long\n    lngDestStartCol = lngMainLastCol + 1\n    Dim lngSubCol As Long\n    Dim lngWriteCol As Long\n    lngWriteCol = lngDestStartCol\n    For lngSubCol = 1 To lngSubLastCol\n        If lngSubCol <> lngKeyColSub Then\n            wsDest.Cells(1, lngWriteCol).Value = wsSub.Cells(1, lngSubCol).Value\n            lngWriteCol = lngWriteCol + 1\n        End If\n    Next lngSubCol\n\n    ' 逐列比對主檔 Key，查找副檔對應資料\n    For lngRow = 2 To lngMainLastRow\n        strKeyVal = CStr(wsDest.Cells(lngRow, lngKeyColMain).Value)\n        For lngSubRow = 2 To lngSubLastRow\n            If CStr(wsSub.Cells(lngSubRow, lngKeyColSub).Value) = strKeyVal Then\n                lngWriteCol = lngDestStartCol\n                For lngSubCol = 1 To lngSubLastCol\n                    If lngSubCol <> lngKeyColSub Then\n                        wsDest.Cells(lngRow, lngWriteCol).Value = wsSub.Cells(lngSubRow, lngSubCol).Value\n                        lngWriteCol = lngWriteCol + 1\n                    End If\n                Next lngSubCol\n                Exit For\n            End If\n        Next lngSubRow\n    Next lngRow\n\n    wbMain.Close SaveChanges:=False\n    wbSub.Close SaveChanges:=False\n\n    wsDest.Columns.AutoFit\n    Application.ScreenUpdating = True\n    Application.DisplayAlerts = True\n\n    MsgBox \"關鍵欄位合併完成！結果在工作表：\" & wsDest.Name, vbInformation, \"完成\"\n    Exit Sub\n\nErrHandler:\n    Application.ScreenUpdating = True\n    Application.DisplayAlerts = True\n    MsgBox \"合併過程發生錯誤：\" & Err.Description, vbCritical, \"錯誤\"\nEnd Sub", "content_b64": ""}, {"name": "MergeExcelFiles.bas", "path": "模組/FileMerge/MergeExcelFiles.bas", "content": "Attribute VB_Name = \"MergeExcelFiles\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: MergeExcelFiles\n'功能說明: 將指定資料夾內所有Excel檔案的第一個工作表合併至一個彙總工作表\n'\n'著作權所有: Dunk\n'程式設計: Dunk\n'撰寫日期: 2026/5/7\n'\n'*************************************************************************************\n\n' 測試用入口\nSub TestMergeExcelFiles()\n    Call MergeExcelFilesFromFolder\nEnd Sub\n\n' 合併指定資料夾內所有 Excel 檔案\nSub MergeExcelFilesFromFolder()\n    Dim folderPath As String\n    Dim fileName As String\n    Dim wbSource As Workbook\n    Dim wsSource As Worksheet\n    Dim wsTarget As Worksheet\n    Dim lastRow As Long\n    Dim targetRow As Long\n    Dim isFirstFile As Boolean\n\n    With Application.FileDialog(msoFileDialogFolderPicker)\n        .Title = \"請選擇要合併的 Excel 檔案所在資料夾\"\n        If .Show <> -1 Then\n            MsgBox \"已取消操作\", vbInformation, \"取消\"\n            Exit Sub\n        End If\n        folderPath = .SelectedItems(1)\n    End With\n\n    Application.ScreenUpdating = False\n    Application.DisplayAlerts = False\n\n    On Error Resume Next\n    Set wsTarget = ThisWorkbook.Worksheets(\"合併彙總\")\n    On Error GoTo 0\n\n    If wsTarget Is Nothing Then\n        Set wsTarget = ThisWorkbook.Worksheets.Add\n        wsTarget.Name = \"合併彙總\"\n    Else\n        wsTarget.Cells.Clear\n    End If\n\n    targetRow = 1\n    isFirstFile = True\n\n    fileName = Dir(folderPath & \"\\*.xlsx\")\n\n    Do While fileName <> \"\"\n        If fileName <> ThisWorkbook.Name Then\n            Set wbSource = Workbooks.Open(folderPath & \"\" & fileName)\n            Set wsSource = wbSource.Worksheets(1)\n            lastRow = wsSource.Cells(wsSource.Rows.Count, 1).End(xlUp).Row\n\n            If lastRow >= 1 Then\n                If isFirstFile Then\n                    wsSource.Range(\"A1\").Resize(lastRow, wsSource.UsedRange.Columns.Count).Copy _\n                        Destination:=wsTarget.Cells(targetRow, 1)\n                    targetRow = targetRow + lastRow\n                    isFirstFile = False\n                Else\n                    If lastRow >= 2 Then\n                        wsSource.Range(\"A2\").Resize(lastRow - 1, wsSource.UsedRange.Columns.Count).Copy _\n                            Destination:=wsTarget.Cells(targetRow, 1)\n                        targetRow = targetRow + lastRow - 1\n                    End If\n                End If\n            End If\n\n            wbSource.Close SaveChanges:=False\n        End If\n        fileName = Dir()\n    Loop\n\n    wsTarget.UsedRange.Columns.AutoFit\n    Application.ScreenUpdating = True\n    Application.DisplayAlerts = True\n    wsTarget.Activate\n    MsgBox \"Excel 檔案合併完成！共合併至第 \" & targetRow - 1 & \" 列。\", vbInformation, \"完成\"\nEnd Sub\n", "content_b64": ""}, {"name": "MergeExcelWithSourceTag.bas", "path": "模組/FileMerge/MergeExcelWithSourceTag.bas", "content": "Attribute VB_Name = \"MergeExcelWithSourceTag\"\nOption Explicit\n\n' ============================================================\n' 範例：合併多個 Excel 檔案，並在每列前加入來源檔案名稱標記\n' 功能：搜尋資料夾內所有 .xlsx，合併第一個工作表資料，\n'       同時在最左側自動插入「來源檔案」欄，記錄資料出處\n' ============================================================\n\nSub MergeExcelWithSourceTag()\n    On Error GoTo ErrHandler\n\n    Dim strFolder       As String\n    Dim strFile         As String\n    Dim wbSrc           As Workbook\n    Dim wsSrc           As Worksheet\n    Dim wsDest          As Worksheet\n    Dim lngLastRow      As Long\n    Dim lngLastCol      As Long\n    Dim lngDestRow      As Long\n    Dim blnFirst        As Boolean\n    Dim lngFilesCount   As Long\n    Dim lngRow          As Long\n\n    ' --- 選擇資料夾 ---\n    With Application.FileDialog(msoFileDialogFolderPicker)\n        .Title = \"請選擇包含 Excel 檔案的資料夾\"\n        If .Show <> -1 Then\n            MsgBox \"已取消操作。\", vbInformation, \"提示\"\n            Exit Sub\n        End If\n        strFolder = .SelectedItems(1)\n    End With\n\n    If Right(strFolder, 1) <> \"\\\" Then strFolder = strFolder & \"\\\"\n\n    ' --- 建立目標工作表 ---\n    Set wsDest = ThisWorkbook.Worksheets.Add\n    wsDest.Name = \"TaggedMerge_\" & Format(Now(), \"mmddHHmm\")\n    lngDestRow = 1\n    blnFirst = True\n    lngFilesCount = 0\n\n    Application.ScreenUpdating = False\n    Application.DisplayAlerts = False\n\n    strFile = Dir(strFolder & \"*.xlsx\")\n    If strFile = \"\" Then\n        MsgBox \"找不到任何 .xlsx 檔案。\", vbExclamation, \"警告\"\n        GoTo CleanUp\n    End If\n\n    Do While strFile <> \"\"\n        If StrComp(strFile, ThisWorkbook.Name, vbTextCompare) <> 0 Then\n            Set wbSrc = Nothing\n            On Error Resume Next\n            Set wbSrc = Workbooks.Open(Filename:=strFolder & strFile, ReadOnly:=True)\n            On Error GoTo ErrHandler\n\n            If Not wbSrc Is Nothing Then\n                Set wsSrc = wbSrc.Sheets(1)\n                lngLastRow = wsSrc.Cells(wsSrc.Rows.Count, 1).End(xlUp).Row\n                lngLastCol = wsSrc.Cells(1, wsSrc.Columns.Count).End(xlToLeft).Column\n\n                If lngLastRow >= 1 Then\n                    If blnFirst Then\n                        ' 第一個檔案：先寫入標題列，B 欄起為原始標題\n                        wsDest.Cells(lngDestRow, 1).Value = \"來源檔案\"\n                        wsSrc.Cells(1, 1).Resize(1, lngLastCol).Copy _\n                            Destination:=wsDest.Cells(lngDestRow, 2)\n                        lngDestRow = lngDestRow + 1\n                        blnFirst = False\n                    End If\n\n                    ' 從第 2 列（跳過標題）開始複製資料\n                    Dim lngSrcRow As Long\n                    For lngSrcRow = 2 To lngLastRow\n                        wsDest.Cells(lngDestRow, 1).Value = strFile  ' 來源標記\n                        wsSrc.Cells(lngSrcRow, 1).Resize(1, lngLastCol).Copy _\n                            Destination:=wsDest.Cells(lngDestRow, 2)\n                        lngDestRow = lngDestRow + 1\n                    Next lngSrcRow\n                    lngFilesCount = lngFilesCount + 1\n                End If\n\n                wbSrc.Close SaveChanges:=False\n            End If\n        End If\n        strFile = Dir()\n    Loop\n\n    wsDest.Columns.AutoFit\n\nCleanUp:\n    Application.ScreenUpdating = True\n    Application.DisplayAlerts = True\n\n    If lngFilesCount > 0 Then\n        MsgBox \"含來源標記合併完成！\" & vbCrLf & _\n               \"共合併 \" & lngFilesCount & \" 個檔案，\" & _\n               \"合計 \" & lngDestRow - 2 & \" 列資料。\", vbInformation, \"完成\"\n    End If\n    Exit Sub\n\nErrHandler:\n    Application.ScreenUpdating = True\n    Application.DisplayAlerts = True\n    MsgBox \"合併過程發生錯誤：\" & Err.Description, vbCritical, \"錯誤\"\nEnd Sub", "content_b64": ""}, {"name": "MergeFilesByDateRange.bas", "path": "模組/FileMerge/MergeFilesByDateRange.bas", "content": "Attribute VB_Name = \"MergeFilesByDateRange\"\nOption Explicit\n\n' ============================================================\n' 範例：依檔案修改日期範圍篩選，合併符合條件的 Excel 檔案\n' 功能：使用者輸入起始與結束日期，程式僅合併在此日期範圍\n'       內被修改的 .xlsx 檔案之第一個工作表資料\n' ============================================================\n\nSub MergeExcelFilesByDateRange()\n    On Error GoTo ErrHandler\n\n    Dim strFolder       As String\n    Dim strFile         As String\n    Dim strStartDate    As String\n    Dim strEndDate      As String\n    Dim dtStart         As Date\n    Dim dtEnd           As Date\n    Dim dtFileDate      As Date\n    Dim wbSrc           As Workbook\n    Dim wsSrc           As Worksheet\n    Dim wsDest          As Worksheet\n    Dim lngLastRow      As Long\n    Dim lngLastCol      As Long\n    Dim lngDestRow      As Long\n    Dim blnFirst        As Boolean\n    Dim lngFilesCount   As Long\n\n    ' --- 取得日期範圍 ---\n    strStartDate = InputBox(\"請輸入起始日期（格式：YYYY/MM/DD）：\", \"起始日期\", Format(Date - 30, \"YYYY/MM/DD\"))\n    If Not IsDate(strStartDate) Then\n        MsgBox \"起始日期格式錯誤，已取消。\", vbExclamation, \"警告\"\n        Exit Sub\n    End If\n    dtStart = CDate(strStartDate)\n\n    strEndDate = InputBox(\"請輸入結束日期（格式：YYYY/MM/DD）：\", \"結束日期\", Format(Date, \"YYYY/MM/DD\"))\n    If Not IsDate(strEndDate) Then\n        MsgBox \"結束日期格式錯誤，已取消。\", vbExclamation, \"警告\"\n        Exit Sub\n    End If\n    dtEnd = CDate(strEndDate)\n\n    If dtStart > dtEnd Then\n        MsgBox \"起始日期不可晚於結束日期，已取消。\", vbExclamation, \"警告\"\n        Exit Sub\n    End If\n\n    ' --- 選擇資料夾 ---\n    With Application.FileDialog(msoFileDialogFolderPicker)\n        .Title = \"請選擇包含 Excel 檔案的資料夾\"\n        If .Show <> -1 Then\n            MsgBox \"已取消操作。\", vbInformation, \"提示\"\n            Exit Sub\n        End If\n        strFolder = .SelectedItems(1)\n    End With\n\n    If Right(strFolder, 1) <> \"\\\" Then strFolder = strFolder & \"\\\"\n\n    ' --- 建立目標工作表 ---\n    Set wsDest = ThisWorkbook.Worksheets.Add\n    wsDest.Name = \"DateFiltered_\" & Format(Now(), \"mmddHHmm\")\n    lngDestRow = 1\n    blnFirst = True\n    lngFilesCount = 0\n\n    Application.ScreenUpdating = False\n    Application.DisplayAlerts = False\n\n    strFile = Dir(strFolder & \"*.xlsx\")\n    Do While strFile <> \"\"\n        If StrComp(strFile, ThisWorkbook.Name, vbTextCompare) <> 0 Then\n            ' 取得檔案修改日期\n            On Error Resume Next\n            dtFileDate = CDate(FileDateTime(strFolder & strFile))\n            On Error GoTo ErrHandler\n\n            ' 判斷是否在日期範圍內\n            If dtFileDate >= dtStart And dtFileDate <= dtEnd + 1 Then\n                Set wbSrc = Nothing\n                On Error Resume Next\n                Set wbSrc = Workbooks.Open(Filename:=strFolder & strFile, ReadOnly:=True)\n                On Error GoTo ErrHandler\n\n                If Not wbSrc Is Nothing Then\n                    Set wsSrc = wbSrc.Sheets(1)\n                    lngLastRow = wsSrc.Cells(wsSrc.Rows.Count, 1).End(xlUp).Row\n                    lngLastCol = wsSrc.Cells(1, wsSrc.Columns.Count).End(xlToLeft).Column\n\n                    If lngLastRow >= 1 Then\n                        Dim lngStartRow As Long\n                        If blnFirst Then\n                            lngStartRow = 1\n                            blnFirst = False\n                        Else\n                            lngStartRow = 2\n                        End If\n                        If lngLastRow >= lngStartRow Then\n                            wsSrc.Cells(lngStartRow, 1).Resize(lngLastRow - lngStartRow + 1, lngLastCol).Copy _\n                                Destination:=wsDest.Cells(lngDestRow, 1)\n                            lngDestRow = lngDestRow + (lngLastRow - lngStartRow + 1)\n                        End If\n                        lngFilesCount = lngFilesCount + 1\n                    End If\n                    wbSrc.Close SaveChanges:=False\n                End If\n            End If\n        End If\n        strFile = Dir()\n    Loop\n\n    wsDest.Columns.AutoFit\n    Application.ScreenUpdating = True\n    Application.DisplayAlerts = True\n\n    MsgBox \"依日期範圍合併完成！\" & vbCrLf & _\n           \"日期範圍：\" & Format(dtStart, \"YYYY/MM/DD\") & \" ~ \" & Format(dtEnd, \"YYYY/MM/DD\") & vbCrLf & _\n           \"共合併 \" & lngFilesCount & \" 個檔案，\" & _\n           \"合計 \" & lngDestRow - 1 & \" 列資料。\", vbInformation, \"完成\"\n    Exit Sub\n\nErrHandler:\n    Application.ScreenUpdating = True\n    Application.DisplayAlerts = True\n    MsgBox \"合併過程發生錯誤：\" & Err.Description, vbCritical, \"錯誤\"\nEnd Sub", "content_b64": ""}, {"name": "MergeFilteredRows.bas", "path": "模組/FileMerge/MergeFilteredRows.bas", "content": "Attribute VB_Name = \"MergeFilteredRows\"\nOption Explicit\n\n' ============================================================\n' 範例：從多個 Excel 檔案中，僅合併符合特定條件的資料列\n' 功能：使用者指定要篩選的欄號與關鍵字，程式自動找出\n'       資料夾內所有 .xlsx 活頁簿符合條件的列並合併\n' ============================================================\n\nSub MergeFilteredRowsFromFolder()\n    On Error GoTo ErrHandler\n\n    Dim strFolder       As String\n    Dim strFile         As String\n    Dim strKeyword      As String\n    Dim strInput        As String\n    Dim lngFilterCol    As Long\n    Dim wbSrc           As Workbook\n    Dim wsSrc           As Worksheet\n    Dim wsDest          As Worksheet\n    Dim lngSrcLastRow   As Long\n    Dim lngSrcLastCol   As Long\n    Dim lngDestRow      As Long\n    Dim lngRow          As Long\n    Dim blnFirst        As Boolean\n    Dim lngMatchCount   As Long\n\n    ' --- 取得篩選欄號 ---\n    strInput = InputBox(\"請輸入要篩選的欄號（如：2 代表 B 欄）：\", \"篩選欄號\", \"2\")\n    If Not IsNumeric(strInput) Or CLng(strInput) < 1 Then\n        MsgBox \"欄號輸入無效，已取消。\", vbExclamation, \"警告\"\n        Exit Sub\n    End If\n    lngFilterCol = CLng(strInput)\n\n    ' --- 取得篩選關鍵字 ---\n    strKeyword = InputBox(\"請輸入篩選關鍵字（完全符合）：\", \"篩選條件\", \"\")\n    If Len(Trim(strKeyword)) = 0 Then\n        MsgBox \"未輸入關鍵字，已取消。\", vbInformation, \"提示\"\n        Exit Sub\n    End If\n\n    ' --- 選擇資料夾 ---\n    With Application.FileDialog(msoFileDialogFolderPicker)\n        .Title = \"請選擇包含 Excel 檔案的資料夾\"\n        If .Show <> -1 Then\n            MsgBox \"已取消操作。\", vbInformation, \"提示\"\n            Exit Sub\n        End If\n        strFolder = .SelectedItems(1)\n    End With\n\n    If Right(strFolder, 1) <> \"\\\" Then strFolder = strFolder & \"\\\"\n\n    ' --- 建立目標工作表 ---\n    Set wsDest = ThisWorkbook.Worksheets.Add\n    wsDest.Name = \"Filtered_\" & Format(Now(), \"mmddHHmm\")\n    lngDestRow = 1\n    blnFirst = True\n    lngMatchCount = 0\n\n    Application.ScreenUpdating = False\n    Application.DisplayAlerts = False\n\n    strFile = Dir(strFolder & \"*.xlsx\")\n    Do While strFile <> \"\"\n        If StrComp(strFile, ThisWorkbook.Name, vbTextCompare) <> 0 Then\n            Set wbSrc = Nothing\n            On Error Resume Next\n            Set wbSrc = Workbooks.Open(Filename:=strFolder & strFile, ReadOnly:=True)\n            On Error GoTo ErrHandler\n\n            If Not wbSrc Is Nothing Then\n                Set wsSrc = wbSrc.Sheets(1)\n                lngSrcLastRow = wsSrc.Cells(wsSrc.Rows.Count, 1).End(xlUp).Row\n                lngSrcLastCol = wsSrc.Cells(1, wsSrc.Columns.Count).End(xlToLeft).Column\n\n                ' 若第一個檔案，先複製標題列\n                If blnFirst And lngSrcLastRow >= 1 Then\n                    wsSrc.Rows(1).Copy Destination:=wsDest.Cells(1, 1)\n                    lngDestRow = 2\n                    blnFirst = False\n                End If\n\n                ' 逐列檢查篩選條件（從第 2 列開始，跳過標題）\n                For lngRow = 2 To lngSrcLastRow\n                    If CStr(wsSrc.Cells(lngRow, lngFilterCol).Value) = strKeyword Then\n                        wsSrc.Rows(lngRow).Copy Destination:=wsDest.Cells(lngDestRow, 1)\n                        lngDestRow = lngDestRow + 1\n                        lngMatchCount = lngMatchCount + 1\n                    End If\n                Next lngRow\n\n                wbSrc.Close SaveChanges:=False\n            End If\n        End If\n        strFile = Dir()\n    Loop\n\n    wsDest.Columns.AutoFit\n    Application.ScreenUpdating = True\n    Application.DisplayAlerts = True\n\n    MsgBox \"條件篩選合併完成！\" & vbCrLf & _\n           \"關鍵字：\" & strKeyword & vbCrLf & _\n           \"共篩選出 \" & lngMatchCount & \" 列資料。\", vbInformation, \"完成\"\n    Exit Sub\n\nErrHandler:\n    Application.ScreenUpdating = True\n    Application.DisplayAlerts = True\n    MsgBox \"合併過程發生錯誤：\" & Err.Description, vbCritical, \"錯誤\"\nEnd Sub", "content_b64": ""}, {"name": "MergeFixedWidthTextFiles.bas", "path": "模組/FileMerge/MergeFixedWidthTextFiles.bas", "content": "Attribute VB_Name = \"MergeFixedWidthTextFiles\"\nOption Explicit\n\n' ============================================================\n' 範例：合併同一資料夾下所有固定寬度格式 (.txt) 文字檔\n' 功能：使用者定義各欄位的起始位置與寬度，程式讀取每一列，\n'       依定義拆解欄位後，寫入目標工作表的對應儲存格\n' 說明：固定寬度格式例如：\n'         姓名(1-10)  部門(11-20)  金額(21-28)\n' ============================================================\n\n' 固定寬度欄位定義型別\nPrivate Type FieldDef\n    FieldName   As String   ' 欄位名稱\n    StartPos    As Long     ' 起始字元位置（1 起算）\n    FieldWidth  As Long     ' 欄位寬度（字元數）\nEnd Type\n\nSub MergeFixedWidthTextFiles()\n    On Error GoTo ErrHandler\n\n    Dim strFolder   As String\n    Dim strFile     As String\n    Dim intIn       As Integer\n    Dim strLine     As String\n    Dim wsDest      As Worksheet\n    Dim lngDestRow  As Long\n    Dim blnFirst    As Boolean\n    Dim lngFilesCount As Long\n\n    ' --- 定義固定寬度欄位（依實際格式修改）---\n    Dim nFields     As Long\n    nFields = 3\n    Dim fields(1 To 3) As FieldDef\n    fields(1).FieldName = \"姓名\"\n    fields(1).StartPos = 1\n    fields(1).FieldWidth = 10\n\n    fields(2).FieldName = \"部門\"\n    fields(2).StartPos = 11\n    fields(2).FieldWidth = 10\n\n    fields(3).FieldName = \"金額\"\n    fields(3).StartPos = 21\n    fields(3).FieldWidth = 8\n\n    ' --- 選擇資料夾 ---\n    With Application.FileDialog(msoFileDialogFolderPicker)\n        .Title = \"請選擇包含固定寬度 TXT 檔案的資料夾\"\n        If .Show <> -1 Then\n            MsgBox \"已取消操作。\", vbInformation, \"提示\"\n            Exit Sub\n        End If\n        strFolder = .SelectedItems(1)\n    End With\n\n    If Right(strFolder, 1) <> \"\\\" Then strFolder = strFolder & \"\\\"\n\n    ' --- 建立目標工作表 ---\n    Set wsDest = ThisWorkbook.Worksheets.Add\n    wsDest.Name = \"FixedWidth_\" & Format(Now(), \"mmddHHmm\")\n    lngDestRow = 1\n    blnFirst = True\n    lngFilesCount = 0\n\n    Application.ScreenUpdating = False\n\n    strFile = Dir(strFolder & \"*.txt\")\n    If strFile = \"\" Then\n        MsgBox \"找不到任何 TXT 檔案。\", vbExclamation, \"警告\"\n        GoTo CleanUp\n    End If\n\n    Do While strFile <> \"\"\n        intIn = FreeFile\n        Open strFolder & strFile For Input As #intIn\n\n        ' 第一個檔案寫入標題列\n        If blnFirst Then\n            Dim lngCol As Long\n            For lngCol = 1 To nFields\n                wsDest.Cells(lngDestRow, lngCol).Value = fields(lngCol).FieldName\n            Next lngCol\n            lngDestRow = lngDestRow + 1\n            blnFirst = False\n        End If\n\n        ' 逐列讀取並依欄位定義拆解\n        Dim blnIsHeader As Boolean\n        blnIsHeader = True\n        Do While Not EOF(intIn)\n            Line Input #intIn, strLine\n            ' 跳過每個檔案的第一列（假設為標題列）\n            If blnIsHeader Then\n                blnIsHeader = False\n            Else\n                If Len(strLine) > 0 Then\n                    For lngCol = 1 To nFields\n                        Dim lngStart As Long\n                        Dim lngWidth As Long\n                        lngStart = fields(lngCol).StartPos\n                        lngWidth = fields(lngCol).FieldWidth\n                        If lngStart <= Len(strLine) Then\n                            Dim strVal As String\n                            strVal = Mid(strLine, lngStart, lngWidth)\n                            wsDest.Cells(lngDestRow, lngCol).Value = Trim(strVal)\n                        End If\n                    Next lngCol\n                    lngDestRow = lngDestRow + 1\n                End If\n            End If\n        Loop\n\n        Close #intIn\n        lngFilesCount = lngFilesCount + 1\n        strFile = Dir()\n    Loop\n\n    wsDest.Columns.AutoFit\n\nCleanUp:\n    Application.ScreenUpdating = True\n\n    If lngFilesCount > 0 Then\n        MsgBox \"固定寬度文字檔合併完成！\" & vbCrLf & _\n               \"共合併 \" & lngFilesCount & \" 個檔案，\" & _\n               \"合計 \" & lngDestRow - 2 & \" 列資料。\", vbInformation, \"完成\"\n    End If\n    Exit Sub\n\nErrHandler:\n    On Error Resume Next\n    Close #intIn\n    On Error GoTo 0\n    Application.ScreenUpdating = True\n    MsgBox \"合併過程發生錯誤：\" & Err.Description, vbCritical, \"錯誤\"\nEnd Sub", "content_b64": ""}, {"name": "MergeJSONFiles.bas", "path": "模組/FileMerge/MergeJSONFiles.bas", "content": "Attribute VB_Name = \"MergeJSONFiles\"\nOption Explicit\n\n' ============================================================\n' 範例：合併同一資料夾下所有 .json 文字檔\n' 功能：逐一讀取每個 JSON 檔案（假設為 JSON array），\n'       去除首尾的 [ ] 後，合併成一個大型 JSON array 輸出\n' ============================================================\n\nSub MergeJSONFilesInFolder()\n    On Error GoTo ErrHandler\n\n    Dim strFolder   As String\n    Dim strFile     As String\n    Dim strOutFile  As String\n    Dim intIn       As Integer\n    Dim intOut      As Integer\n    Dim strLine     As String\n    Dim strContent  As String\n    Dim blnFirst    As Boolean\n    Dim lngCount    As Long\n\n    ' --- 選擇資料夾 ---\n    With Application.FileDialog(msoFileDialogFolderPicker)\n        .Title = \"請選擇包含 JSON 檔案的資料夾\"\n        If .Show <> -1 Then\n            MsgBox \"已取消操作。\", vbInformation, \"提示\"\n            Exit Sub\n        End If\n        strFolder = .SelectedItems(1)\n    End With\n\n    If Right(strFolder, 1) <> \"\\\" Then strFolder = strFolder & \"\\\"\n\n    strOutFile = strFolder & \"MergedOutput.json\"\n    intOut = FreeFile\n    Open strOutFile For Output As #intOut\n    Print #intOut, \"[\"\n\n    blnFirst = True\n    lngCount = 0\n    strFile = Dir(strFolder & \"*.json\")\n\n    If strFile = \"\" Then\n        MsgBox \"找不到任何 JSON 檔案。\", vbExclamation, \"警告\"\n        Close #intOut\n        Kill strOutFile\n        Exit Sub\n    End If\n\n    Do While strFile <> \"\"\n        ' 略過輸出檔本身\n        If StrComp(strFile, \"MergedOutput.json\", vbTextCompare) <> 0 Then\n            strContent = \"\"\n            intIn = FreeFile\n            Open strFolder & strFile For Input As #intIn\n            Do While Not EOF(intIn)\n                Line Input #intIn, strLine\n                strContent = strContent & strLine & vbCrLf\n            Loop\n            Close #intIn\n\n            ' 去除最外層 [ ] (假設為合法 JSON array)\n            strContent = Trim(strContent)\n            If Left(strContent, 1) = \"[\" Then\n                strContent = Mid(strContent, 2)\n            End If\n            If Right(strContent, 1) = \"]\" Then\n                strContent = Left(strContent, Len(strContent) - 1)\n            End If\n            strContent = Trim(strContent)\n\n            If Len(strContent) > 0 Then\n                If Not blnFirst Then\n                    Print #intOut, \",\"\n                End If\n                Print #intOut, strContent\n                blnFirst = False\n                lngCount = lngCount + 1\n            End If\n        End If\n        strFile = Dir()\n    Loop\n\n    Print #intOut, \"]\"\n    Close #intOut\n\n    MsgBox \"JSON 合併完成！共合併 \" & lngCount & \" 個檔案。\" & vbCrLf & _\n           \"輸出路徑：\" & strOutFile, vbInformation, \"完成\"\n    Exit Sub\n\nErrHandler:\n    On Error Resume Next\n    Close #intOut\n    On Error GoTo 0\n    MsgBox \"合併 JSON 時發生錯誤：\" & Err.Description, vbCritical, \"錯誤\"\nEnd Sub", "content_b64": ""}, {"name": "MergeSheetsByName.bas", "path": "模組/FileMerge/MergeSheetsByName.bas", "content": "Attribute VB_Name = \"MergeSheetsByName\"\nOption Explicit\n\n' ============================================================\n' 範例：從多個活頁簿中，找出相同名稱的工作表並合併其資料\n' 功能：使用者指定工作表名稱，程式自動搜尋資料夾內所有\n'       .xlsx 活頁簿，找到同名工作表後逐一貼入目標工作表\n' ============================================================\n\nSub MergeSheetsBySheetName()\n    On Error GoTo ErrHandler\n\n    Dim strFolder       As String\n    Dim strSheetName    As String\n    Dim strFile         As String\n    Dim wbSrc           As Workbook\n    Dim wsSrc           As Worksheet\n    Dim wsDest          As Worksheet\n    Dim lngLastRow      As Long\n    Dim lngDestRow      As Long\n    Dim blnFirst        As Boolean\n    Dim lngFilesFound   As Long\n\n    ' --- 取得工作表名稱 ---\n    strSheetName = InputBox(\"請輸入要合併的工作表名稱：\", \"指定工作表名稱\", \"Sheet1\")\n    If Len(Trim(strSheetName)) = 0 Then\n        MsgBox \"未輸入工作表名稱，已取消。\", vbInformation, \"提示\"\n        Exit Sub\n    End If\n\n    ' --- 選擇資料夾 ---\n    With Application.FileDialog(msoFileDialogFolderPicker)\n        .Title = \"請選擇包含 Excel 檔案的資料夾\"\n        If .Show <> -1 Then\n            MsgBox \"已取消操作。\", vbInformation, \"提示\"\n            Exit Sub\n        End If\n        strFolder = .SelectedItems(1)\n    End With\n\n    If Right(strFolder, 1) <> \"\\\" Then strFolder = strFolder & \"\\\"\n\n    ' --- 建立目標工作表 ---\n    Set wsDest = ThisWorkbook.Worksheets.Add\n    wsDest.Name = \"Merged_\" & Left(strSheetName, 20) & \"_\" & Format(Now(), \"mmddHHmm\")\n    lngDestRow = 1\n    blnFirst = True\n    lngFilesFound = 0\n\n    Application.ScreenUpdating = False\n    Application.DisplayAlerts = False\n\n    strFile = Dir(strFolder & \"*.xlsx\")\n    Do While strFile <> \"\"\n        If StrComp(strFile, ThisWorkbook.Name, vbTextCompare) <> 0 Then\n            Set wbSrc = Nothing\n            On Error Resume Next\n            Set wbSrc = Workbooks.Open(Filename:=strFolder & strFile, ReadOnly:=True)\n            On Error GoTo ErrHandler\n            If Not wbSrc Is Nothing Then\n                Set wsSrc = Nothing\n                On Error Resume Next\n                Set wsSrc = wbSrc.Worksheets(strSheetName)\n                On Error GoTo ErrHandler\n\n                If Not wsSrc Is Nothing Then\n                    lngLastRow = wsSrc.Cells(wsSrc.Rows.Count, 1).End(xlUp).Row\n                    If lngLastRow >= 1 Then\n                        Dim lngStartRow As Long\n                        If blnFirst Then\n                            lngStartRow = 1\n                            blnFirst = False\n                        Else\n                            lngStartRow = 2  ' 跳過標題\n                        End If\n                        If lngLastRow >= lngStartRow Then\n                            wsSrc.Rows(lngStartRow & \":\" & lngLastRow).Copy _\n                                Destination:=wsDest.Cells(lngDestRow, 1)\n                            lngDestRow = lngDestRow + (lngLastRow - lngStartRow + 1)\n                        End If\n                        lngFilesFound = lngFilesFound + 1\n                    End If\n                End If\n                wbSrc.Close SaveChanges:=False\n            End If\n        End If\n        strFile = Dir()\n    Loop\n\n    wsDest.Columns.AutoFit\n    Application.ScreenUpdating = True\n    Application.DisplayAlerts = True\n\n    If lngFilesFound = 0 Then\n        MsgBox \"找不到任何包含工作表「\" & strSheetName & \"」的活頁簿。\", vbExclamation, \"警告\"\n    Else\n        MsgBox \"依工作表名稱合併完成！\" & vbCrLf & _\n               \"共找到 \" & lngFilesFound & \" 個檔案，\" & _\n               \"合計 \" & lngDestRow - 1 & \" 列資料。\", vbInformation, \"完成\"\n    End If\n    Exit Sub\n\nErrHandler:\n    Application.ScreenUpdating = True\n    Application.DisplayAlerts = True\n    MsgBox \"合併過程發生錯誤：\" & Err.Description, vbCritical, \"錯誤\"\nEnd Sub", "content_b64": ""}, {"name": "MergeTextFilesWithHeader.bas", "path": "模組/FileMerge/MergeTextFilesWithHeader.bas", "content": "Option Explicit\n\nPrivate Const MsoFileDialogFolderPicker As Long = 4\n\n' 合併資料夾內所有 TXT 檔，並只保留第一個檔案的標題列。\nPublic Sub MergeTextFilesWithHeaderExample()\n    On Error GoTo ErrHandler\n\n    Dim folderPath As String\n    Dim outputPath As String\n\n    folderPath = PickMergeFolder()\n    If Len(folderPath) = 0 Then Exit Sub\n\n    outputPath = folderPath & \"\\MergedTextWithHeader.txt\"\n    Call MergeTextFilesWithHeader(folderPath, outputPath)\n\n    MsgBox \"文字檔合併完成：\" & outputPath, vbInformation, \"完成\"\n    Exit Sub\n\nErrHandler:\n    MsgBox \"合併文字檔失敗：\" & Err.Description, vbExclamation, \"錯誤\"\nEnd Sub\n\nPrivate Sub MergeTextFilesWithHeader(ByVal folderPath As String, ByVal outputPath As String)\n    Dim fileName As String\n    Dim inputFile As Integer\n    Dim outputFile As Integer\n    Dim lineText As String\n    Dim isFirstFile As Boolean\n    Dim isFirstLine As Boolean\n\n    outputFile = FreeFile\n    Open outputPath For Output As #outputFile\n\n    isFirstFile = True\n    fileName = Dir(folderPath & \"\\*.txt\")\n    Do While Len(fileName) > 0\n        If StrComp(fileName, \"MergedTextWithHeader.txt\", vbTextCompare) <> 0 Then\n            inputFile = FreeFile\n            Open folderPath & \"\\\" & fileName For Input As #inputFile\n            isFirstLine = True\n\n            Do While Not EOF(inputFile)\n                Line Input #inputFile, lineText\n                If isFirstFile Or Not isFirstLine Then\n                    Print #outputFile, lineText\n                End If\n                isFirstLine = False\n            Loop\n\n            Close #inputFile\n            isFirstFile = False\n        End If\n        fileName = Dir()\n    Loop\n\n    Close #outputFile\nEnd Sub\n\nPrivate Function PickMergeFolder() As String\n    With Application.FileDialog(MsoFileDialogFolderPicker)\n        .Title = \"請選擇要合併 TXT 檔的資料夾\"\n        .AllowMultiSelect = False\n        If .Show = -1 Then\n            PickMergeFolder = .SelectedItems(1)\n        End If\n    End With\nEnd Function", "content_b64": ""}, {"name": "MergeXMLFiles.bas", "path": "模組/FileMerge/MergeXMLFiles.bas", "content": "Attribute VB_Name = \"MergeXMLFiles\"\nOption Explicit\n\n' ============================================================\n' 範例：合併同一資料夾下所有 .xml 檔案的第一層子元素\n' 功能：建立一個共同根節點，將每個 XML 檔案的根節點子元素\n'       全部收集至新 XML 的根節點下，輸出為單一 XML 檔案\n' 需求：需啟用 Microsoft XML, v6.0 參考 (MSXML2)\n' ============================================================\n\nSub MergeXMLFilesInFolder()\n    On Error GoTo ErrHandler\n\n    Dim strFolder   As String\n    Dim strFile     As String\n    Dim strOutFile  As String\n    Dim xmlMerged   As Object   ' MSXML2.DOMDocument60\n    Dim xmlSrc      As Object   ' MSXML2.DOMDocument60\n    Dim xmlRoot     As Object\n    Dim xmlSrcRoot  As Object\n    Dim xmlChild    As Object\n    Dim xmlImported As Object\n    Dim lngCount    As Long\n\n    ' --- 選擇資料夾 ---\n    With Application.FileDialog(msoFileDialogFolderPicker)\n        .Title = \"請選擇包含 XML 檔案的資料夾\"\n        If .Show <> -1 Then\n            MsgBox \"已取消操作。\", vbInformation, \"提示\"\n            Exit Sub\n        End If\n        strFolder = .SelectedItems(1)\n    End With\n\n    If Right(strFolder, 1) <> \"\\\" Then strFolder = strFolder & \"\\\"\n\n    ' --- 建立合併用 DOM ---\n    Set xmlMerged = CreateObject(\"MSXML2.DOMDocument.6.0\")\n    xmlMerged.async = False\n    xmlMerged.loadXML \"<?xml version=\"\"1.0\"\" encoding=\"\"UTF-8\"\"?><MergedRoot/>\"\n    Set xmlRoot = xmlMerged.documentElement\n\n    lngCount = 0\n    strFile = Dir(strFolder & \"*.xml\")\n\n    If strFile = \"\" Then\n        MsgBox \"找不到任何 XML 檔案。\", vbExclamation, \"警告\"\n        Exit Sub\n    End If\n\n    Do While strFile <> \"\"\n        Set xmlSrc = CreateObject(\"MSXML2.DOMDocument.6.0\")\n        xmlSrc.async = False\n        xmlSrc.Load strFolder & strFile\n\n        If xmlSrc.parseError.errorCode = 0 Then\n            Set xmlSrcRoot = xmlSrc.documentElement\n            Dim i As Long\n            For i = 0 To xmlSrcRoot.childNodes.Length - 1\n                Set xmlChild = xmlSrcRoot.childNodes(i)\n                ' 以字串方式轉移節點（避免跨 Document 節點問題）\n                xmlRoot.appendChild xmlMerged.createTextNode(vbCrLf & \"  \")\n                xmlRoot.appendChild xmlMerged.createNode(1, xmlChild.nodeName, \"\")\n                ' 直接以原始 XML 插入子節點\n                xmlRoot.lastChild.setAttribute \"src\", strFile\n            Next i\n            lngCount = lngCount + 1\n        Else\n            MsgBox \"解析 \" & strFile & \" 時發生錯誤：\" & xmlSrc.parseError.reason, _\n                   vbExclamation, \"XML 解析錯誤\"\n        End If\n\n        strFile = Dir()\n    Loop\n\n    strOutFile = strFolder & \"MergedOutput.xml\"\n    xmlMerged.Save strOutFile\n\n    MsgBox \"XML 合併完成！共處理 \" & lngCount & \" 個檔案。\" & vbCrLf & _\n           \"輸出路徑：\" & strOutFile, vbInformation, \"完成\"\n    Exit Sub\n\nErrHandler:\n    MsgBox \"合併 XML 時發生錯誤：\" & Err.Description, vbCritical, \"錯誤\"\nEnd Sub", "content_b64": ""}]}, {"folder": "FileSplit", "path": "模組/FileSplit", "files": [{"name": "SplitByCustomList.bas", "path": "模組/FileSplit/SplitByCustomList.bas", "content": "Attribute VB_Name = \"SplitByCustomList\"\n\nOption Explicit\n\n'*************************************************************************************\n\n'模組名稱: SplitByCustomList\n\n'功能說明: 依另一工作表定義的自訂清單分組，將來源工作表拆分為多個 Excel 檔案\n\n'          清單工作表：A 欄為群組名稱，B 欄起為該群組包含的欄位值（可多個）\n\n'          不符合任何群組的列存入 Others.xlsx\n\n'\n\n'作者版權: Dunk\n\n'程式設計: Dunk\n\n'最後修改: 2026/5/9\n\n'\n\n'*************************************************************************************\n\n\n\n' 測試用入口：建立範例資料與自訂清單後執行分割\n\nSub TestSplitByCustomList()\n\n    Dim wsSrc As Worksheet\n\n    Dim wsMap As Worksheet\n\n    Set wsSrc = GetOrCreateSheetCustom(ThisWorkbook, \"自訂清單來源\")\n\n    Set wsMap = GetOrCreateSheetCustom(ThisWorkbook, \"分組清單定義\")\n\n    Call FillSampleCustomData(wsSrc)\n\n    Call FillSampleCustomList(wsMap)\n\n    Call SplitSheetByCustomGroupList(wsSrc, wsMap, 2)\n\nEnd Sub\n\n\n\n' 依自訂群組清單拆分工作表\n\n' wsSrc: 來源工作表  wsMap: 群組定義工作表  splitColIndex: 比對欄號\n\nSub SplitSheetByCustomGroupList(ByVal wsSrc As Worksheet, _\n\n                                 ByVal wsMap As Worksheet, _\n\n                                 ByVal splitColIndex As Integer)\n\n    Dim folderPath As String\n\n    Dim lastRowSrc As Long\n\n    Dim lastRowMap As Long\n\n    Dim lastColMap As Long\n\n    Dim i As Long\n\n    Dim j As Long\n\n    Dim k As Long\n\n    Dim colCount As Long\n\n    Dim groupName As String\n\n    Dim groupValue As String\n\n    Dim cellValue As String\n\n    Dim groupFound As String\n\n    Dim wbNew As Workbook\n\n    Dim wsNew As Worksheet\n\n    Dim newRow As Long\n\n    Dim groupCount As Long\n\n\n\n    lastRowSrc = wsSrc.Cells(wsSrc.Rows.Count, splitColIndex).End(xlUp).Row\n\n    If lastRowSrc <= 1 Then\n\n        MsgBox \"來源工作表無資料！\", vbExclamation, \"警告\"\n\n        Exit Sub\n\n    End If\n\n\n\n    lastRowMap = wsMap.Cells(wsMap.Rows.Count, 1).End(xlUp).Row\n\n    If lastRowMap < 1 Then\n\n        MsgBox \"群組定義工作表無資料！\", vbExclamation, \"警告\"\n\n        Exit Sub\n\n    End If\n\n\n\n    With Application.FileDialog(msoFileDialogFolderPicker)\n\n        .Title = \"請選擇輸出資料夾\"\n\n        If .Show <> -1 Then\n\n            MsgBox \"已取消操作\", vbInformation, \"取消\"\n\n            Exit Sub\n\n        End If\n\n        folderPath = .SelectedItems(1)\n\n    End With\n\n    If Right(folderPath, 1) <> \"\\\" Then folderPath = folderPath & \"\\\"\n\n\n\n    colCount = wsSrc.Cells(1, wsSrc.Columns.Count).End(xlToLeft).Column\n\n\n\n    Application.ScreenUpdating = False\n\n    Application.DisplayAlerts = False\n\n    groupCount = 0\n\n\n\n    ' 逐一處理每個群組\n\n    For i = 1 To lastRowMap\n\n        groupName = CStr(wsMap.Cells(i, 1).Value)\n\n        If Len(Trim(groupName)) = 0 Then GoTo NextGroup\n\n\n\n        Set wbNew = Workbooks.Add\n\n        Set wsNew = wbNew.Worksheets(1)\n\n        wsNew.Name = Left(groupName, 31)\n\n        wsSrc.Range(wsSrc.Cells(1, 1), wsSrc.Cells(1, colCount)).Copy _\n\n            Destination:=wsNew.Cells(1, 1)\n\n        newRow = 2\n\n        lastColMap = wsMap.Cells(i, wsMap.Columns.Count).End(xlToLeft).Column\n\n\n\n        For k = 2 To lastRowSrc\n\n            cellValue = CStr(wsSrc.Cells(k, splitColIndex).Value)\n\n            For j = 2 To lastColMap\n\n                groupValue = CStr(wsMap.Cells(i, j).Value)\n\n                If cellValue = groupValue Then\n\n                    wsSrc.Range(wsSrc.Cells(k, 1), wsSrc.Cells(k, colCount)).Copy _\n\n                        Destination:=wsNew.Cells(newRow, 1)\n\n                    newRow = newRow + 1\n\n                    Exit For\n\n                End If\n\n            Next j\n\n        Next k\n\n\n\n        wsNew.Columns.AutoFit\n\n        wbNew.SaveAs folderPath & groupName & \".xlsx\", xlOpenXMLWorkbook\n\n        wbNew.Close SaveChanges:=False\n\n        groupCount = groupCount + 1\n\nNextGroup:\n\n    Next i\n\n\n\n    ' 找出不屬於任何群組的列，存入 Others\n\n    Set wbNew = Workbooks.Add\n\n    Set wsNew = wbNew.Worksheets(1)\n\n    wsNew.Name = \"Others\"\n\n    wsSrc.Range(wsSrc.Cells(1, 1), wsSrc.Cells(1, colCount)).Copy _\n\n        Destination:=wsNew.Cells(1, 1)\n\n    newRow = 2\n\n\n\n    For k = 2 To lastRowSrc\n\n        cellValue = CStr(wsSrc.Cells(k, splitColIndex).Value)\n\n        groupFound = \"\"\n\n        For i = 1 To lastRowMap\n\n            lastColMap = wsMap.Cells(i, wsMap.Columns.Count).End(xlToLeft).Column\n\n            For j = 2 To lastColMap\n\n                If cellValue = CStr(wsMap.Cells(i, j).Value) Then\n\n                    groupFound = CStr(wsMap.Cells(i, 1).Value)\n\n                    Exit For\n\n                End If\n\n            Next j\n\n            If Len(groupFound) > 0 Then Exit For\n\n        Next i\n\n        If Len(groupFound) = 0 Then\n\n            wsSrc.Range(wsSrc.Cells(k, 1), wsSrc.Cells(k, colCount)).Copy _\n\n                Destination:=wsNew.Cells(newRow, 1)\n\n            newRow = newRow + 1\n\n        End If\n\n    Next k\n\n\n\n    If newRow > 2 Then\n\n        wsNew.Columns.AutoFit\n\n        wbNew.SaveAs folderPath & \"Others.xlsx\", xlOpenXMLWorkbook\n\n        groupCount = groupCount + 1\n\n    End If\n\n    wbNew.Close SaveChanges:=False\n\n\n\n    Application.ScreenUpdating = True\n\n    Application.DisplayAlerts = True\n\n    MsgBox \"自訂清單分割完成！共建立 \" & groupCount & \" 個檔案。\", vbInformation, \"完成\"\n\nEnd Sub\n\n\n\n' 建立來源範例資料\n\nPrivate Sub FillSampleCustomData(ByVal ws As Worksheet)\n\n    ws.Cells.Clear\n\n    ws.Range(\"A1\").Value = \"商品\"\n\n    ws.Range(\"B1\").Value = \"類別\"\n\n    ws.Range(\"C1\").Value = \"售價\"\n\n    ws.Range(\"A2\").Value = \"蘋果\": ws.Range(\"B2\").Value = \"水果\": ws.Range(\"C2\").Value = 50\n\n    ws.Range(\"A3\").Value = \"筆記本\": ws.Range(\"B3\").Value = \"文具\": ws.Range(\"C3\").Value = 35\n\n    ws.Range(\"A4\").Value = \"香蕉\": ws.Range(\"B4\").Value = \"水果\": ws.Range(\"C4\").Value = 30\n\n    ws.Range(\"A5\").Value = \"原子筆\": ws.Range(\"B5\").Value = \"文具\": ws.Range(\"C5\").Value = 15\n\n    ws.Range(\"A6\").Value = \"手機\": ws.Range(\"B6\").Value = \"電子\": ws.Range(\"C6\").Value = 15000\n\n    ws.Range(\"A7\").Value = \"橘子\": ws.Range(\"B7\").Value = \"水果\": ws.Range(\"C7\").Value = 40\n\n    ws.Range(\"A8\").Value = \"平板\": ws.Range(\"B8\").Value = \"電子\": ws.Range(\"C8\").Value = 20000\n\n    ws.Range(\"A9\").Value = \"雨傘\": ws.Range(\"B9\").Value = \"雜貨\": ws.Range(\"C9\").Value = 280\n\n    ws.Range(\"A1:C1\").Font.Bold = True\n\n    ws.Columns(\"A:C\").AutoFit\n\nEnd Sub\n\n\n\n' 建立自訂群組清單定義（A欄=群組名，B欄起=所含類別值）\n\nPrivate Sub FillSampleCustomList(ByVal ws As Worksheet)\n\n    ws.Cells.Clear\n\n    ws.Range(\"A1\").Value = \"鮮果類\"\n\n    ws.Range(\"B1\").Value = \"水果\"\n\n    ws.Range(\"A2\").Value = \"辦公用品\"\n\n    ws.Range(\"B2\").Value = \"文具\"\n\n    ws.Range(\"A3\").Value = \"3C商品\"\n\n    ws.Range(\"B3\").Value = \"電子\"\n\n    ws.Columns(\"A:B\").AutoFit\n\nEnd Sub\n\n\n\n' 取得或建立工作表\n\nPrivate Function GetOrCreateSheetCustom(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n\n    Dim ws As Worksheet\n\n    On Error Resume Next\n\n    Set ws = wb.Worksheets(sheetName)\n\n    On Error GoTo 0\n\n    If ws Is Nothing Then\n\n        Set ws = wb.Worksheets.Add\n\n        ws.Name = sheetName\n\n    End If\n\n    ws.Cells.Clear\n\n    Set GetOrCreateSheetCustom = ws\n\nEnd Function\n\n", "content_b64": ""}, {"name": "SplitByDateColumn.bas", "path": "模組/FileSplit/SplitByDateColumn.bas", "content": "Attribute VB_Name = \"SplitByDateColumn\"\n\nOption Explicit\n\n'*************************************************************************************\n\n'模組名稱: SplitByDateColumn\n\n'功能說明: 依指定日期欄位的年月，將工作表拆分為多個 Excel 檔案\n\n'\n\n'作者版權: Dunk\n\n'程式設計: Dunk\n\n'最後修改: 2026/5/9\n\n'\n\n'*************************************************************************************\n\n\n\n' 測試用入口：建立範例資料後執行拆分\n\nSub TestSplitByDate()\n\n    Dim ws As Worksheet\n\n    Set ws = GetOrCreateSheetByDate(ThisWorkbook, \"日期來源資料\")\n\n    Call FillSampleDateData(ws)\n\n    Call SplitSheetByDateColumn(ws, 1)\n\nEnd Sub\n\n\n\n' 依日期欄（年月）拆分工作表，每個年月存成獨立 Excel 檔案\n\n' ws: 來源工作表  dateColIndex: 日期所在欄號\n\nSub SplitSheetByDateColumn(ByVal ws As Worksheet, ByVal dateColIndex As Integer)\n\n    Dim folderPath As String\n\n    Dim lastRow As Long\n\n    Dim i As Long\n\n    Dim colCount As Long\n\n    Dim yearMonth As String\n\n    Dim uniqueKeys As Collection\n\n    Dim alreadyAdded As Boolean\n\n    Dim key As Variant\n\n    Dim wbNew As Workbook\n\n    Dim wsNew As Worksheet\n\n    Dim newRow As Long\n\n    Dim copyRow As Long\n\n\n\n    lastRow = ws.Cells(ws.Rows.Count, dateColIndex).End(xlUp).Row\n\n    If lastRow <= 1 Then\n\n        MsgBox \"工作表無資料可分割！\", vbExclamation, \"警告\"\n\n        Exit Sub\n\n    End If\n\n\n\n    With Application.FileDialog(msoFileDialogFolderPicker)\n\n        .Title = \"請選擇輸出資料夾\"\n\n        If .Show <> -1 Then\n\n            MsgBox \"已取消操作\", vbInformation, \"取消\"\n\n            Exit Sub\n\n        End If\n\n        folderPath = .SelectedItems(1)\n\n    End With\n\n    If Right(folderPath, 1) <> \"\\\" Then folderPath = folderPath & \"\\\"\n\n\n\n    colCount = ws.Cells(1, ws.Columns.Count).End(xlToLeft).Column\n\n\n\n    Set uniqueKeys = New Collection\n\n    For i = 2 To lastRow\n\n        If IsDate(ws.Cells(i, dateColIndex).Value) Then\n\n            yearMonth = Format(CDate(ws.Cells(i, dateColIndex).Value), \"YYYY-MM\")\n\n            alreadyAdded = False\n\n            For Each key In uniqueKeys\n\n                If key = yearMonth Then\n\n                    alreadyAdded = True\n\n                    Exit For\n\n                End If\n\n            Next key\n\n            If Not alreadyAdded Then uniqueKeys.Add yearMonth\n\n        End If\n\n    Next i\n\n\n\n    If uniqueKeys.Count = 0 Then\n\n        MsgBox \"找不到有效的日期資料！\", vbExclamation, \"警告\"\n\n        Exit Sub\n\n    End If\n\n\n\n    Application.ScreenUpdating = False\n\n    Application.DisplayAlerts = False\n\n\n\n    For Each key In uniqueKeys\n\n        Set wbNew = Workbooks.Add\n\n        Set wsNew = wbNew.Worksheets(1)\n\n        wsNew.Name = Left(CStr(key), 31)\n\n        ws.Range(ws.Cells(1, 1), ws.Cells(1, colCount)).Copy _\n\n            Destination:=wsNew.Cells(1, 1)\n\n        newRow = 2\n\n        For copyRow = 2 To lastRow\n\n            If IsDate(ws.Cells(copyRow, dateColIndex).Value) Then\n\n                If Format(CDate(ws.Cells(copyRow, dateColIndex).Value), \"YYYY-MM\") = CStr(key) Then\n\n                    ws.Range(ws.Cells(copyRow, 1), ws.Cells(copyRow, colCount)).Copy _\n\n                        Destination:=wsNew.Cells(newRow, 1)\n\n                    newRow = newRow + 1\n\n                End If\n\n            End If\n\n        Next copyRow\n\n        wsNew.Columns.AutoFit\n\n        wbNew.SaveAs folderPath & CStr(key) & \".xlsx\", xlOpenXMLWorkbook\n\n        wbNew.Close SaveChanges:=False\n\n    Next key\n\n\n\n    Application.ScreenUpdating = True\n\n    Application.DisplayAlerts = True\n\n    MsgBox \"拆分完成！共建立 \" & uniqueKeys.Count & \" 個年月檔案。\", vbInformation, \"完成\"\n\nEnd Sub\n\n\n\n' 建立範例日期資料\n\nPrivate Sub FillSampleDateData(ByVal ws As Worksheet)\n\n    ws.Cells.Clear\n\n    ws.Range(\"A1\").Value = \"日期\"\n\n    ws.Range(\"B1\").Value = \"品名\"\n\n    ws.Range(\"C1\").Value = \"金額\"\n\n    ws.Range(\"A2\").Value = CDate(\"2026/01/05\")\n\n    ws.Range(\"B2\").Value = \"商品A\"\n\n    ws.Range(\"C2\").Value = 3000\n\n    ws.Range(\"A3\").Value = CDate(\"2026/01/12\")\n\n    ws.Range(\"B3\").Value = \"商品B\"\n\n    ws.Range(\"C3\").Value = 1500\n\n    ws.Range(\"A4\").Value = CDate(\"2026/02/03\")\n\n    ws.Range(\"B4\").Value = \"商品C\"\n\n    ws.Range(\"C4\").Value = 4200\n\n    ws.Range(\"A5\").Value = CDate(\"2026/02/18\")\n\n    ws.Range(\"B5\").Value = \"商品D\"\n\n    ws.Range(\"C5\").Value = 2100\n\n    ws.Range(\"A6\").Value = CDate(\"2026/03/07\")\n\n    ws.Range(\"B6\").Value = \"商品E\"\n\n    ws.Range(\"C6\").Value = 5500\n\n    ws.Range(\"A1:C1\").Font.Bold = True\n\n    ws.Columns(\"A:C\").AutoFit\n\nEnd Sub\n\n\n\n' 取得或建立工作表\n\nPrivate Function GetOrCreateSheetByDate(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n\n    Dim ws As Worksheet\n\n    On Error Resume Next\n\n    Set ws = wb.Worksheets(sheetName)\n\n    On Error GoTo 0\n\n    If ws Is Nothing Then\n\n        Set ws = wb.Worksheets.Add\n\n        ws.Name = sheetName\n\n    End If\n\n    ws.Cells.Clear\n\n    Set GetOrCreateSheetByDate = ws\n\nEnd Function\n\n", "content_b64": ""}, {"name": "SplitByMultipleColumns.bas", "path": "模組/FileSplit/SplitByMultipleColumns.bas", "content": "Attribute VB_Name = \"SplitByMultipleColumns\"\n\nOption Explicit\n\n'*************************************************************************************\n\n'模組名稱: SplitByMultipleColumns\n\n'功能說明: 依兩個欄位的組合鍵拆分工作表，每種組合存成一個 Excel 檔案\n\n'\n\n'作者版權: Dunk\n\n'程式設計: Dunk\n\n'最後修改: 2026/5/9\n\n'\n\n'*************************************************************************************\n\n\n\n' 測試用入口：建立範例資料後依「地區+部門」組合分割\n\nSub TestSplitByMultipleColumns()\n\n    Dim ws As Worksheet\n\n    Set ws = GetOrCreateSheetMulti(ThisWorkbook, \"組合鍵來源\")\n\n    Call FillSampleMultiData(ws)\n\n    Call SplitSheetByTwoColumns(ws, 1, 2)\n\nEnd Sub\n\n\n\n' 依兩個欄位的組合鍵拆分工作表\n\n' ws: 來源工作表  col1: 第一欄號  col2: 第二欄號\n\nSub SplitSheetByTwoColumns(ByVal ws As Worksheet, _\n\n                            ByVal col1 As Integer, _\n\n                            ByVal col2 As Integer)\n\n    Dim folderPath As String\n\n    Dim lastRow As Long\n\n    Dim i As Long\n\n    Dim colCount As Long\n\n    Dim comboKey As String\n\n    Dim uniqueKeys As Collection\n\n    Dim alreadyAdded As Boolean\n\n    Dim key As Variant\n\n    Dim wbNew As Workbook\n\n    Dim wsNew As Worksheet\n\n    Dim newRow As Long\n\n    Dim copyRow As Long\n\n    Dim safeName As String\n\n\n\n    lastRow = ws.Cells(ws.Rows.Count, col1).End(xlUp).Row\n\n    If lastRow <= 1 Then\n\n        MsgBox \"工作表無資料可分割！\", vbExclamation, \"警告\"\n\n        Exit Sub\n\n    End If\n\n\n\n    With Application.FileDialog(msoFileDialogFolderPicker)\n\n        .Title = \"請選擇輸出資料夾\"\n\n        If .Show <> -1 Then\n\n            MsgBox \"已取消操作\", vbInformation, \"取消\"\n\n            Exit Sub\n\n        End If\n\n        folderPath = .SelectedItems(1)\n\n    End With\n\n    If Right(folderPath, 1) <> \"\\\" Then folderPath = folderPath & \"\\\"\n\n\n\n    colCount = ws.Cells(1, ws.Columns.Count).End(xlToLeft).Column\n\n\n\n    Set uniqueKeys = New Collection\n\n    For i = 2 To lastRow\n\n        comboKey = CStr(ws.Cells(i, col1).Value) & \"_\" & CStr(ws.Cells(i, col2).Value)\n\n        alreadyAdded = False\n\n        For Each key In uniqueKeys\n\n            If key = comboKey Then\n\n                alreadyAdded = True\n\n                Exit For\n\n            End If\n\n        Next key\n\n        If Not alreadyAdded Then uniqueKeys.Add comboKey\n\n    Next i\n\n\n\n    Application.ScreenUpdating = False\n\n    Application.DisplayAlerts = False\n\n\n\n    For Each key In uniqueKeys\n\n        Set wbNew = Workbooks.Add\n\n        Set wsNew = wbNew.Worksheets(1)\n\n        safeName = CStr(key)\n\n        safeName = Replace(safeName, \"/\", \"-\")\n\n        safeName = Replace(safeName, \":\", \"-\")\n\n        wsNew.Name = Left(safeName, 31)\n\n        ws.Range(ws.Cells(1, 1), ws.Cells(1, colCount)).Copy _\n\n            Destination:=wsNew.Cells(1, 1)\n\n        newRow = 2\n\n        For copyRow = 2 To lastRow\n\n            comboKey = CStr(ws.Cells(copyRow, col1).Value) & \"_\" & CStr(ws.Cells(copyRow, col2).Value)\n\n            If comboKey = CStr(key) Then\n\n                ws.Range(ws.Cells(copyRow, 1), ws.Cells(copyRow, colCount)).Copy _\n\n                    Destination:=wsNew.Cells(newRow, 1)\n\n                newRow = newRow + 1\n\n            End If\n\n        Next copyRow\n\n        wsNew.Columns.AutoFit\n\n        wbNew.SaveAs folderPath & safeName & \".xlsx\", xlOpenXMLWorkbook\n\n        wbNew.Close SaveChanges:=False\n\n    Next key\n\n\n\n    Application.ScreenUpdating = True\n\n    Application.DisplayAlerts = True\n\n    MsgBox \"組合鍵分割完成！共建立 \" & uniqueKeys.Count & \" 個檔案。\", vbInformation, \"完成\"\n\nEnd Sub\n\n\n\n' 建立範例資料\n\nPrivate Sub FillSampleMultiData(ByVal ws As Worksheet)\n\n    ws.Cells.Clear\n\n    ws.Range(\"A1\").Value = \"地區\"\n\n    ws.Range(\"B1\").Value = \"部門\"\n\n    ws.Range(\"C1\").Value = \"姓名\"\n\n    ws.Range(\"D1\").Value = \"業績\"\n\n    ws.Range(\"A2\").Value = \"北區\": ws.Range(\"B2\").Value = \"業務部\": ws.Range(\"C2\").Value = \"王大明\": ws.Range(\"D2\").Value = 80000\n\n    ws.Range(\"A3\").Value = \"北區\": ws.Range(\"B3\").Value = \"財務部\": ws.Range(\"C3\").Value = \"李小美\": ws.Range(\"D3\").Value = 60000\n\n    ws.Range(\"A4\").Value = \"南區\": ws.Range(\"B4\").Value = \"業務部\": ws.Range(\"C4\").Value = \"張志偉\": ws.Range(\"D4\").Value = 75000\n\n    ws.Range(\"A5\").Value = \"北區\": ws.Range(\"B5\").Value = \"業務部\": ws.Range(\"C5\").Value = \"陳美如\": ws.Range(\"D5\").Value = 92000\n\n    ws.Range(\"A6\").Value = \"南區\": ws.Range(\"B6\").Value = \"財務部\": ws.Range(\"C6\").Value = \"林正雄\": ws.Range(\"D6\").Value = 58000\n\n    ws.Range(\"A1:D1\").Font.Bold = True\n\n    ws.Columns(\"A:D\").AutoFit\n\nEnd Sub\n\n\n\n' 取得或建立工作表\n\nPrivate Function GetOrCreateSheetMulti(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n\n    Dim ws As Worksheet\n\n    On Error Resume Next\n\n    Set ws = wb.Worksheets(sheetName)\n\n    On Error GoTo 0\n\n    If ws Is Nothing Then\n\n        Set ws = wb.Worksheets.Add\n\n        ws.Name = sheetName\n\n    End If\n\n    ws.Cells.Clear\n\n    Set GetOrCreateSheetMulti = ws\n\nEnd Function\n\n", "content_b64": ""}, {"name": "SplitByNumericRange.bas", "path": "模組/FileSplit/SplitByNumericRange.bas", "content": "Attribute VB_Name = \"SplitByNumericRange\"\n\nOption Explicit\n\n'*************************************************************************************\n\n'模組名稱: SplitByNumericRange\n\n'功能說明: 依指定數值欄的區間（每段 rangeSize 為一組）拆分工作表，\n\n'          每個區間存成一個 Excel 檔案\n\n'\n\n'作者版權: Dunk\n\n'程式設計: Dunk\n\n'最後修改: 2026/5/9\n\n'\n\n'*************************************************************************************\n\n\n\n' 測試用入口：建立範例資料後依薪資區間（每段 10000）分割\n\nSub TestSplitByNumericRange()\n\n    Dim ws As Worksheet\n\n    Set ws = GetOrCreateSheetNumeric(ThisWorkbook, \"數值區間來源\")\n\n    Call FillSampleNumericData(ws)\n\n    Call SplitSheetByNumericRange(ws, 3, 10000)\n\nEnd Sub\n\n\n\n' 依數值欄位區間拆分工作表\n\n' ws: 來源工作表  numColIndex: 數值欄號  rangeSize: 每段區間大小\n\nSub SplitSheetByNumericRange(ByVal ws As Worksheet, _\n\n                              ByVal numColIndex As Integer, _\n\n                              ByVal rangeSize As Double)\n\n    Dim folderPath As String\n\n    Dim lastRow As Long\n\n    Dim i As Long\n\n    Dim colCount As Long\n\n    Dim cellNum As Double\n\n    Dim bucketKey As String\n\n    Dim bucketKey2 As String\n\n    Dim bucketLow As Long\n\n    Dim bucketHigh As Long\n\n    Dim uniqueBuckets As Collection\n\n    Dim alreadyAdded As Boolean\n\n    Dim key As Variant\n\n    Dim wbNew As Workbook\n\n    Dim wsNew As Worksheet\n\n    Dim newRow As Long\n\n    Dim copyRow As Long\n\n    Dim cellNum2 As Double\n\n\n\n    lastRow = ws.Cells(ws.Rows.Count, numColIndex).End(xlUp).Row\n\n    If lastRow <= 1 Then\n\n        MsgBox \"工作表無資料可分割！\", vbExclamation, \"警告\"\n\n        Exit Sub\n\n    End If\n\n\n\n    If rangeSize <= 0 Then\n\n        MsgBox \"區間大小必須大於 0！\", vbExclamation, \"警告\"\n\n        Exit Sub\n\n    End If\n\n\n\n    With Application.FileDialog(msoFileDialogFolderPicker)\n\n        .Title = \"請選擇輸出資料夾\"\n\n        If .Show <> -1 Then\n\n            MsgBox \"已取消操作\", vbInformation, \"取消\"\n\n            Exit Sub\n\n        End If\n\n        folderPath = .SelectedItems(1)\n\n    End With\n\n    If Right(folderPath, 1) <> \"\\\" Then folderPath = folderPath & \"\\\"\n\n\n\n    colCount = ws.Cells(1, ws.Columns.Count).End(xlToLeft).Column\n\n\n\n    Set uniqueBuckets = New Collection\n\n    For i = 2 To lastRow\n\n        If IsNumeric(ws.Cells(i, numColIndex).Value) Then\n\n            cellNum = CDbl(ws.Cells(i, numColIndex).Value)\n\n            bucketLow = Int(cellNum / rangeSize) * CLng(rangeSize)\n\n            bucketHigh = bucketLow + CLng(rangeSize) - 1\n\n            bucketKey = CStr(bucketLow) & \"-\" & CStr(bucketHigh)\n\n            alreadyAdded = False\n\n            For Each key In uniqueBuckets\n\n                If key = bucketKey Then\n\n                    alreadyAdded = True\n\n                    Exit For\n\n                End If\n\n            Next key\n\n            If Not alreadyAdded Then uniqueBuckets.Add bucketKey\n\n        End If\n\n    Next i\n\n\n\n    If uniqueBuckets.Count = 0 Then\n\n        MsgBox \"找不到有效的數值資料！\", vbExclamation, \"警告\"\n\n        Exit Sub\n\n    End If\n\n\n\n    Application.ScreenUpdating = False\n\n    Application.DisplayAlerts = False\n\n\n\n    For Each key In uniqueBuckets\n\n        Set wbNew = Workbooks.Add\n\n        Set wsNew = wbNew.Worksheets(1)\n\n        wsNew.Name = Left(CStr(key), 31)\n\n        ws.Range(ws.Cells(1, 1), ws.Cells(1, colCount)).Copy _\n\n            Destination:=wsNew.Cells(1, 1)\n\n        newRow = 2\n\n        For copyRow = 2 To lastRow\n\n            If IsNumeric(ws.Cells(copyRow, numColIndex).Value) Then\n\n                cellNum2 = CDbl(ws.Cells(copyRow, numColIndex).Value)\n\n                bucketLow = Int(cellNum2 / rangeSize) * CLng(rangeSize)\n\n                bucketHigh = bucketLow + CLng(rangeSize) - 1\n\n                bucketKey2 = CStr(bucketLow) & \"-\" & CStr(bucketHigh)\n\n                If bucketKey2 = CStr(key) Then\n\n                    ws.Range(ws.Cells(copyRow, 1), ws.Cells(copyRow, colCount)).Copy _\n\n                        Destination:=wsNew.Cells(newRow, 1)\n\n                    newRow = newRow + 1\n\n                End If\n\n            End If\n\n        Next copyRow\n\n        wsNew.Columns.AutoFit\n\n        wbNew.SaveAs folderPath & CStr(key) & \".xlsx\", xlOpenXMLWorkbook\n\n        wbNew.Close SaveChanges:=False\n\n    Next key\n\n\n\n    Application.ScreenUpdating = True\n\n    Application.DisplayAlerts = True\n\n    MsgBox \"數值區間分割完成！共建立 \" & uniqueBuckets.Count & \" 個檔案。\", vbInformation, \"完成\"\n\nEnd Sub\n\n\n\n' 建立範例資料\n\nPrivate Sub FillSampleNumericData(ByVal ws As Worksheet)\n\n    ws.Cells.Clear\n\n    ws.Range(\"A1\").Value = \"員工\"\n\n    ws.Range(\"B1\").Value = \"部門\"\n\n    ws.Range(\"C1\").Value = \"薪資\"\n\n    ws.Range(\"A2\").Value = \"甲\": ws.Range(\"B2\").Value = \"研發\": ws.Range(\"C2\").Value = 35000\n\n    ws.Range(\"A3\").Value = \"乙\": ws.Range(\"B3\").Value = \"業務\": ws.Range(\"C3\").Value = 28000\n\n    ws.Range(\"A4\").Value = \"丙\": ws.Range(\"B4\").Value = \"研發\": ws.Range(\"C4\").Value = 52000\n\n    ws.Range(\"A5\").Value = \"丁\": ws.Range(\"B5\").Value = \"行政\": ws.Range(\"C5\").Value = 42000\n\n    ws.Range(\"A6\").Value = \"戊\": ws.Range(\"B6\").Value = \"業務\": ws.Range(\"C6\").Value = 31000\n\n    ws.Range(\"A7\").Value = \"己\": ws.Range(\"B7\").Value = \"研發\": ws.Range(\"C7\").Value = 65000\n\n    ws.Range(\"A1:C1\").Font.Bold = True\n\n    ws.Columns(\"A:C\").AutoFit\n\nEnd Sub\n\n\n\n' 取得或建立工作表\n\nPrivate Function GetOrCreateSheetNumeric(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n\n    Dim ws As Worksheet\n\n    On Error Resume Next\n\n    Set ws = wb.Worksheets(sheetName)\n\n    On Error GoTo 0\n\n    If ws Is Nothing Then\n\n        Set ws = wb.Worksheets.Add\n\n        ws.Name = sheetName\n\n    End If\n\n    ws.Cells.Clear\n\n    Set GetOrCreateSheetNumeric = ws\n\nEnd Function\n\n", "content_b64": ""}, {"name": "SplitByOddEvenRow.bas", "path": "模組/FileSplit/SplitByOddEvenRow.bas", "content": "Attribute VB_Name = \"SplitByOddEvenRow\"\n\nOption Explicit\n\n'*************************************************************************************\n\n'模組名稱: SplitByOddEvenRow\n\n'功能說明: 將工作表依資料列的奇偶性拆分為兩個 Excel 檔案\n\n'          奇數資料列與偶數資料列各存一個檔案，均保留標題列\n\n'          適用於交錯式資料或輪替分組場景\n\n'\n\n'作者版權: Dunk\n\n'程式設計: Dunk\n\n'最後修改: 2026/5/9\n\n'\n\n'*************************************************************************************\n\n\n\n' 測試用入口：建立範例資料後執行奇偶分割\n\nSub TestSplitByOddEven()\n\n    Dim ws As Worksheet\n\n    Set ws = GetOrCreateSheetOddEven(ThisWorkbook, \"奇偶列來源\")\n\n    Call FillSampleOddEvenData(ws)\n\n    Call SplitSheetByOddEvenRow(ws)\n\nEnd Sub\n\n\n\n' 將工作表資料依奇偶行拆分為兩個 Excel 檔案\n\n' ws: 來源工作表（第 1 列為標題，資料從第 2 列開始）\n\nSub SplitSheetByOddEvenRow(ByVal ws As Worksheet)\n\n    Dim folderPath As String\n\n    Dim lastRow As Long\n\n    Dim colCount As Long\n\n    Dim wbOdd As Workbook\n\n    Dim wbEven As Workbook\n\n    Dim wsOdd As Worksheet\n\n    Dim wsEven As Worksheet\n\n    Dim rowOdd As Long\n\n    Dim rowEven As Long\n\n    Dim i As Long\n\n    Dim dataIndex As Long\n\n\n\n    lastRow = ws.Cells(ws.Rows.Count, 1).End(xlUp).Row\n\n    If lastRow <= 1 Then\n\n        MsgBox \"工作表無資料可分割！\", vbExclamation, \"警告\"\n\n        Exit Sub\n\n    End If\n\n\n\n    With Application.FileDialog(msoFileDialogFolderPicker)\n\n        .Title = \"請選擇輸出資料夾\"\n\n        If .Show <> -1 Then\n\n            MsgBox \"已取消操作\", vbInformation, \"取消\"\n\n            Exit Sub\n\n        End If\n\n        folderPath = .SelectedItems(1)\n\n    End With\n\n    If Right(folderPath, 1) <> \"\\\" Then folderPath = folderPath & \"\\\"\n\n\n\n    colCount = ws.Cells(1, ws.Columns.Count).End(xlToLeft).Column\n\n\n\n    Application.ScreenUpdating = False\n\n    Application.DisplayAlerts = False\n\n\n\n    Set wbOdd = Workbooks.Add\n\n    Set wsOdd = wbOdd.Worksheets(1)\n\n    wsOdd.Name = \"奇數列\"\n\n    ws.Range(ws.Cells(1, 1), ws.Cells(1, colCount)).Copy Destination:=wsOdd.Cells(1, 1)\n\n\n\n    Set wbEven = Workbooks.Add\n\n    Set wsEven = wbEven.Worksheets(1)\n\n    wsEven.Name = \"偶數列\"\n\n    ws.Range(ws.Cells(1, 1), ws.Cells(1, colCount)).Copy Destination:=wsEven.Cells(1, 1)\n\n\n\n    rowOdd = 2\n\n    rowEven = 2\n\n    dataIndex = 0\n\n\n\n    For i = 2 To lastRow\n\n        dataIndex = dataIndex + 1\n\n        If dataIndex Mod 2 = 1 Then\n\n            ws.Range(ws.Cells(i, 1), ws.Cells(i, colCount)).Copy _\n\n                Destination:=wsOdd.Cells(rowOdd, 1)\n\n            rowOdd = rowOdd + 1\n\n        Else\n\n            ws.Range(ws.Cells(i, 1), ws.Cells(i, colCount)).Copy _\n\n                Destination:=wsEven.Cells(rowEven, 1)\n\n            rowEven = rowEven + 1\n\n        End If\n\n    Next i\n\n\n\n    wsOdd.Columns.AutoFit\n\n    wbOdd.SaveAs folderPath & \"OddRows.xlsx\", xlOpenXMLWorkbook\n\n    wbOdd.Close SaveChanges:=False\n\n\n\n    wsEven.Columns.AutoFit\n\n    wbEven.SaveAs folderPath & \"EvenRows.xlsx\", xlOpenXMLWorkbook\n\n    wbEven.Close SaveChanges:=False\n\n\n\n    Application.ScreenUpdating = True\n\n    Application.DisplayAlerts = True\n\n    MsgBox \"奇偶列分割完成！已輸出 OddRows.xlsx 與 EvenRows.xlsx。\", vbInformation, \"完成\"\n\nEnd Sub\n\n\n\n' 建立範例資料\n\nPrivate Sub FillSampleOddEvenData(ByVal ws As Worksheet)\n\n    Dim i As Integer\n\n    Dim names(1 To 8) As String\n\n    ws.Cells.Clear\n\n    ws.Range(\"A1\").Value = \"編號\"\n\n    ws.Range(\"B1\").Value = \"姓名\"\n\n    ws.Range(\"C1\").Value = \"分數\"\n\n    names(1) = \"甲\": names(2) = \"乙\": names(3) = \"丙\": names(4) = \"丁\"\n\n    names(5) = \"戊\": names(6) = \"己\": names(7) = \"庚\": names(8) = \"辛\"\n\n    For i = 1 To 8\n\n        ws.Cells(i + 1, 1).Value = i\n\n        ws.Cells(i + 1, 2).Value = names(i)\n\n        ws.Cells(i + 1, 3).Value = 60 + i * 4\n\n    Next i\n\n    ws.Range(\"A1:C1\").Font.Bold = True\n\n    ws.Columns(\"A:C\").AutoFit\n\nEnd Sub\n\n\n\n' 取得或建立工作表\n\nPrivate Function GetOrCreateSheetOddEven(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n\n    Dim ws As Worksheet\n\n    On Error Resume Next\n\n    Set ws = wb.Worksheets(sheetName)\n\n    On Error GoTo 0\n\n    If ws Is Nothing Then\n\n        Set ws = wb.Worksheets.Add\n\n        ws.Name = sheetName\n\n    End If\n\n    ws.Cells.Clear\n\n    Set GetOrCreateSheetOddEven = ws\n\nEnd Function\n\n", "content_b64": ""}, {"name": "SplitSheetByAlphabet.bas", "path": "模組/FileSplit/SplitSheetByAlphabet.bas", "content": "Attribute VB_Name = \"SplitSheetByAlphabet\"\n\nOption Explicit\n\n'*************************************************************************************\n\n'模組名稱: SplitSheetByAlphabet\n\n'功能說明: 依指定欄位的首字母（A-Z）分組，將工作表拆分為多個 Excel 檔案\n\n'          非英文字母的值統一歸入 Others 群組\n\n'\n\n'作者版權: Dunk\n\n'程式設計: Dunk\n\n'最後修改: 2026/5/9\n\n'\n\n'*************************************************************************************\n\n\n\n' 測試用入口：建立範例資料後依首字母分割\n\nSub TestSplitByAlphabet()\n\n    Dim ws As Worksheet\n\n    Set ws = GetOrCreateSheetAlpha(ThisWorkbook, \"字母分組來源\")\n\n    Call FillSampleAlphaData(ws)\n\n    Call SplitSheetByFirstLetter(ws, 1)\n\nEnd Sub\n\n\n\n' 依指定欄位的首字母分割工作表\n\n' ws: 來源工作表  keyColIndex: 鍵值欄號\n\nSub SplitSheetByFirstLetter(ByVal ws As Worksheet, ByVal keyColIndex As Integer)\n\n    Dim folderPath As String\n\n    Dim lastRow As Long\n\n    Dim i As Long\n\n    Dim colCount As Long\n\n    Dim firstLetter As String\n\n    Dim uniqueLetters As Collection\n\n    Dim alreadyAdded As Boolean\n\n    Dim key As Variant\n\n    Dim wbNew As Workbook\n\n    Dim wsNew As Worksheet\n\n    Dim newRow As Long\n\n    Dim copyRow As Long\n\n    Dim cellVal As String\n\n\n\n    lastRow = ws.Cells(ws.Rows.Count, keyColIndex).End(xlUp).Row\n\n    If lastRow <= 1 Then\n\n        MsgBox \"工作表無資料可分割！\", vbExclamation, \"警告\"\n\n        Exit Sub\n\n    End If\n\n\n\n    With Application.FileDialog(msoFileDialogFolderPicker)\n\n        .Title = \"請選擇輸出資料夾\"\n\n        If .Show <> -1 Then\n\n            MsgBox \"已取消操作\", vbInformation, \"取消\"\n\n            Exit Sub\n\n        End If\n\n        folderPath = .SelectedItems(1)\n\n    End With\n\n    If Right(folderPath, 1) <> \"\\\" Then folderPath = folderPath & \"\\\"\n\n\n\n    colCount = ws.Cells(1, ws.Columns.Count).End(xlToLeft).Column\n\n\n\n    Set uniqueLetters = New Collection\n\n    For i = 2 To lastRow\n\n        cellVal = CStr(ws.Cells(i, keyColIndex).Value)\n\n        If Len(cellVal) > 0 Then\n\n            firstLetter = UCase(Left(cellVal, 1))\n\n            If firstLetter < \"A\" Or firstLetter > \"Z\" Then firstLetter = \"Others\"\n\n            alreadyAdded = False\n\n            For Each key In uniqueLetters\n\n                If key = firstLetter Then\n\n                    alreadyAdded = True\n\n                    Exit For\n\n                End If\n\n            Next key\n\n            If Not alreadyAdded Then uniqueLetters.Add firstLetter\n\n        End If\n\n    Next i\n\n\n\n    Application.ScreenUpdating = False\n\n    Application.DisplayAlerts = False\n\n\n\n    For Each key In uniqueLetters\n\n        Set wbNew = Workbooks.Add\n\n        Set wsNew = wbNew.Worksheets(1)\n\n        wsNew.Name = Left(CStr(key), 31)\n\n        ws.Range(ws.Cells(1, 1), ws.Cells(1, colCount)).Copy _\n\n            Destination:=wsNew.Cells(1, 1)\n\n        newRow = 2\n\n        For copyRow = 2 To lastRow\n\n            cellVal = CStr(ws.Cells(copyRow, keyColIndex).Value)\n\n            If Len(cellVal) > 0 Then\n\n                firstLetter = UCase(Left(cellVal, 1))\n\n                If firstLetter < \"A\" Or firstLetter > \"Z\" Then firstLetter = \"Others\"\n\n                If firstLetter = CStr(key) Then\n\n                    ws.Range(ws.Cells(copyRow, 1), ws.Cells(copyRow, colCount)).Copy _\n\n                        Destination:=wsNew.Cells(newRow, 1)\n\n                    newRow = newRow + 1\n\n                End If\n\n            End If\n\n        Next copyRow\n\n        wsNew.Columns.AutoFit\n\n        wbNew.SaveAs folderPath & CStr(key) & \".xlsx\", xlOpenXMLWorkbook\n\n        wbNew.Close SaveChanges:=False\n\n    Next key\n\n\n\n    Application.ScreenUpdating = True\n\n    Application.DisplayAlerts = True\n\n    MsgBox \"首字母分割完成！共建立 \" & uniqueLetters.Count & \" 個檔案。\", vbInformation, \"完成\"\n\nEnd Sub\n\n\n\n' 建立範例資料\n\nPrivate Sub FillSampleAlphaData(ByVal ws As Worksheet)\n\n    ws.Cells.Clear\n\n    ws.Range(\"A1\").Value = \"公司名稱\"\n\n    ws.Range(\"B1\").Value = \"聯絡人\"\n\n    ws.Range(\"C1\").Value = \"電話\"\n\n    ws.Range(\"A2\").Value = \"Apple Corp\": ws.Range(\"B2\").Value = \"John\": ws.Range(\"C2\").Value = \"02-1234-5678\"\n\n    ws.Range(\"A3\").Value = \"Beta Solutions\": ws.Range(\"B3\").Value = \"Mary\": ws.Range(\"C3\").Value = \"02-2345-6789\"\n\n    ws.Range(\"A4\").Value = \"Ace Trading\": ws.Range(\"B4\").Value = \"David\": ws.Range(\"C4\").Value = \"02-3456-7890\"\n\n    ws.Range(\"A5\").Value = \"Cherry Design\": ws.Range(\"B5\").Value = \"Susan\": ws.Range(\"C5\").Value = \"02-4567-8901\"\n\n    ws.Range(\"A6\").Value = \"Big Data Inc\": ws.Range(\"B6\").Value = \"Kevin\": ws.Range(\"C6\").Value = \"02-5678-9012\"\n\n    ws.Range(\"A7\").Value = \"協大工業\": ws.Range(\"B7\").Value = \"陳大偉\": ws.Range(\"C7\").Value = \"04-6789-0123\"\n\n    ws.Range(\"A1:C1\").Font.Bold = True\n\n    ws.Columns(\"A:C\").AutoFit\n\nEnd Sub\n\n\n\n' 取得或建立工作表\n\nPrivate Function GetOrCreateSheetAlpha(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n\n    Dim ws As Worksheet\n\n    On Error Resume Next\n\n    Set ws = wb.Worksheets(sheetName)\n\n    On Error GoTo 0\n\n    If ws Is Nothing Then\n\n        Set ws = wb.Worksheets.Add\n\n        ws.Name = sheetName\n\n    End If\n\n    ws.Cells.Clear\n\n    Set GetOrCreateSheetAlpha = ws\n\nEnd Function\n\n", "content_b64": ""}, {"name": "SplitSheetByColorTag.bas", "path": "模組/FileSplit/SplitSheetByColorTag.bas", "content": "Attribute VB_Name = \"SplitSheetByColorTag\"\n\nOption Explicit\n\n'*************************************************************************************\n\n'模組名稱: SplitSheetByColorTag\n\n'功能說明: 依指定欄位的儲存格背景色分割工作表，每種顏色存成一個 Excel 檔案\n\n'          常用於以顏色標記的優先等級或分類資料\n\n'\n\n'作者版權: Dunk\n\n'程式設計: Dunk\n\n'最後修改: 2026/5/9\n\n'\n\n'*************************************************************************************\n\n\n\n' 測試用入口：建立範例顏色標記資料後執行分割\n\nSub TestSplitByColor()\n\n    Dim ws As Worksheet\n\n    Set ws = GetOrCreateSheetColor(ThisWorkbook, \"顏色標記來源\")\n\n    Call FillSampleColorData(ws)\n\n    Call SplitSheetByInteriorColor(ws, 1)\n\nEnd Sub\n\n\n\n' 依儲存格背景色拆分工作表\n\n' ws: 來源工作表  colorColIndex: 判斷顏色的欄號\n\nSub SplitSheetByInteriorColor(ByVal ws As Worksheet, ByVal colorColIndex As Integer)\n\n    Dim folderPath As String\n\n    Dim lastRow As Long\n\n    Dim i As Long\n\n    Dim colCount As Long\n\n    Dim cellColor As Long\n\n    Dim cellColor2 As Long\n\n    Dim colorKey As String\n\n    Dim uniqueColors As Collection\n\n    Dim alreadyAdded As Boolean\n\n    Dim key As Variant\n\n    Dim wbNew As Workbook\n\n    Dim wsNew As Worksheet\n\n    Dim newRow As Long\n\n    Dim copyRow As Long\n\n\n\n    lastRow = ws.Cells(ws.Rows.Count, colorColIndex).End(xlUp).Row\n\n    If lastRow <= 1 Then\n\n        MsgBox \"工作表無資料可分割！\", vbExclamation, \"警告\"\n\n        Exit Sub\n\n    End If\n\n\n\n    With Application.FileDialog(msoFileDialogFolderPicker)\n\n        .Title = \"請選擇輸出資料夾\"\n\n        If .Show <> -1 Then\n\n            MsgBox \"已取消操作\", vbInformation, \"取消\"\n\n            Exit Sub\n\n        End If\n\n        folderPath = .SelectedItems(1)\n\n    End With\n\n    If Right(folderPath, 1) <> \"\\\" Then folderPath = folderPath & \"\\\"\n\n\n\n    colCount = ws.Cells(1, ws.Columns.Count).End(xlToLeft).Column\n\n\n\n    Set uniqueColors = New Collection\n\n    For i = 2 To lastRow\n\n        cellColor = ws.Cells(i, colorColIndex).Interior.Color\n\n        colorKey = CStr(cellColor)\n\n        alreadyAdded = False\n\n        For Each key In uniqueColors\n\n            If key = colorKey Then\n\n                alreadyAdded = True\n\n                Exit For\n\n            End If\n\n        Next key\n\n        If Not alreadyAdded Then uniqueColors.Add colorKey\n\n    Next i\n\n\n\n    Application.ScreenUpdating = False\n\n    Application.DisplayAlerts = False\n\n\n\n    For Each key In uniqueColors\n\n        Set wbNew = Workbooks.Add\n\n        Set wsNew = wbNew.Worksheets(1)\n\n        wsNew.Name = Left(\"Color_\" & Hex(CLng(CStr(key))), 31)\n\n        ws.Range(ws.Cells(1, 1), ws.Cells(1, colCount)).Copy _\n\n            Destination:=wsNew.Cells(1, 1)\n\n        newRow = 2\n\n        For copyRow = 2 To lastRow\n\n            cellColor2 = ws.Cells(copyRow, colorColIndex).Interior.Color\n\n            If CStr(cellColor2) = CStr(key) Then\n\n                ws.Range(ws.Cells(copyRow, 1), ws.Cells(copyRow, colCount)).Copy _\n\n                    Destination:=wsNew.Cells(newRow, 1)\n\n                newRow = newRow + 1\n\n            End If\n\n        Next copyRow\n\n        wsNew.Columns.AutoFit\n\n        wbNew.SaveAs folderPath & \"Color_\" & Hex(CLng(CStr(key))) & \".xlsx\", xlOpenXMLWorkbook\n\n        wbNew.Close SaveChanges:=False\n\n    Next key\n\n\n\n    Application.ScreenUpdating = True\n\n    Application.DisplayAlerts = True\n\n    MsgBox \"顏色分割完成！共建立 \" & uniqueColors.Count & \" 個檔案。\", vbInformation, \"完成\"\n\nEnd Sub\n\n\n\n' 建立範例顏色標記資料（高=紅、中=黃、低=綠）\n\nPrivate Sub FillSampleColorData(ByVal ws As Worksheet)\n\n    ws.Cells.Clear\n\n    ws.Range(\"A1\").Value = \"任務\"\n\n    ws.Range(\"B1\").Value = \"負責人\"\n\n    ws.Range(\"C1\").Value = \"優先度\"\n\n    ws.Range(\"A2\").Value = \"簽約審核\": ws.Range(\"B2\").Value = \"王大明\": ws.Range(\"C2\").Value = \"高\"\n\n    ws.Range(\"A3\").Value = \"報告撰寫\": ws.Range(\"B3\").Value = \"李小美\": ws.Range(\"C3\").Value = \"低\"\n\n    ws.Range(\"A4\").Value = \"客戶拜訪\": ws.Range(\"B4\").Value = \"張志偉\": ws.Range(\"C4\").Value = \"高\"\n\n    ws.Range(\"A5\").Value = \"會議準備\": ws.Range(\"B5\").Value = \"陳美如\": ws.Range(\"C5\").Value = \"中\"\n\n    ws.Range(\"A6\").Value = \"系統測試\": ws.Range(\"B6\").Value = \"林正雄\": ws.Range(\"C6\").Value = \"中\"\n\n    ws.Range(\"A7\").Value = \"資料備份\": ws.Range(\"B7\").Value = \"吳淑芬\": ws.Range(\"C7\").Value = \"低\"\n\n    ws.Range(\"A2:C2\").Interior.Color = RGB(255, 153, 153)\n\n    ws.Range(\"A3:C3\").Interior.Color = RGB(153, 255, 153)\n\n    ws.Range(\"A4:C4\").Interior.Color = RGB(255, 153, 153)\n\n    ws.Range(\"A5:C5\").Interior.Color = RGB(255, 255, 153)\n\n    ws.Range(\"A6:C6\").Interior.Color = RGB(255, 255, 153)\n\n    ws.Range(\"A7:C7\").Interior.Color = RGB(153, 255, 153)\n\n    ws.Range(\"A1:C1\").Font.Bold = True\n\n    ws.Columns(\"A:C\").AutoFit\n\nEnd Sub\n\n\n\n' 取得或建立工作表\n\nPrivate Function GetOrCreateSheetColor(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n\n    Dim ws As Worksheet\n\n    On Error Resume Next\n\n    Set ws = wb.Worksheets(sheetName)\n\n    On Error GoTo 0\n\n    If ws Is Nothing Then\n\n        Set ws = wb.Worksheets.Add\n\n        ws.Name = sheetName\n\n    End If\n\n    ws.Cells.Clear\n\n    Set GetOrCreateSheetColor = ws\n\nEnd Function\n\n", "content_b64": ""}, {"name": "SplitSheetByColumn.bas", "path": "模組/FileSplit/SplitSheetByColumn.bas", "content": "Attribute VB_Name = \"SplitSheetByColumn\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: SplitSheetByColumn\n'功能說明: 將工作表依據指定欄的值分割，每個唯一值另存為獨立的Excel檔案\n'\n'著作權所有: Dunk\n'程式設計: Dunk\n'撰寫日期: 2026/5/7\n'\n'*************************************************************************************\n\n' 測試用入口（先建立範例資料再分割）\nSub TestSplitSheet()\n    Dim ws As Worksheet\n    Set ws = GetOrCreateSheet(ThisWorkbook, \"切割來源資料\")\n    Call FillSampleSplitData(ws)\n    Call SplitSheetByColumnValue(ws, 2)\nEnd Sub\n\n' 依據指定欄位的唯一值分割工作表，輸出為獨立 Excel 檔案\n' ws: 來源工作表  splitColIndex: 分割欄位索引\nSub SplitSheetByColumnValue(ByVal ws As Worksheet, ByVal splitColIndex As Integer)\n    Dim folderPath As String\n    Dim lastRow As Long\n    Dim headerRow As Long\n    Dim i As Long\n    Dim uniqueValues As Collection\n    Dim cellValue As String\n    Dim alreadyAdded As Boolean\n    Dim key As Variant\n    Dim wbNew As Workbook\n    Dim wsNew As Worksheet\n    Dim copyRow As Long\n    Dim newRow As Long\n    Dim colCount As Long\n\n    headerRow = 1\n    lastRow = ws.Cells(ws.Rows.Count, splitColIndex).End(xlUp).Row\n\n    If lastRow <= headerRow Then\n        MsgBox \"資料列數不足，無法分割！\", vbExclamation, \"警告\"\n        Exit Sub\n    End If\n\n    With Application.FileDialog(msoFileDialogFolderPicker)\n        .Title = \"請選擇分割後檔案的儲存資料夾\"\n        If .Show <> -1 Then\n            MsgBox \"已取消操作\", vbInformation, \"取消\"\n            Exit Sub\n        End If\n        folderPath = .SelectedItems(1)\n    End With\n\n    Set uniqueValues = New Collection\n    For i = headerRow + 1 To lastRow\n        cellValue = CStr(ws.Cells(i, splitColIndex).Value)\n        alreadyAdded = False\n        For Each key In uniqueValues\n            If key = cellValue Then\n                alreadyAdded = True\n                Exit For\n            End If\n        Next key\n        If Not alreadyAdded Then\n            uniqueValues.Add cellValue\n        End If\n    Next i\n\n    colCount = ws.Cells(headerRow, ws.Columns.Count).End(xlToLeft).Column\n\n    Application.ScreenUpdating = False\n    Application.DisplayAlerts = False\n\n    For Each key In uniqueValues\n        Set wbNew = Workbooks.Add\n        Set wsNew = wbNew.Worksheets(1)\n        wsNew.Name = Left(CStr(key), 31)\n\n        ws.Range(ws.Cells(headerRow, 1), ws.Cells(headerRow, colCount)).Copy _\n            Destination:=wsNew.Cells(1, 1)\n\n        newRow = 2\n        For copyRow = headerRow + 1 To lastRow\n            If CStr(ws.Cells(copyRow, splitColIndex).Value) = CStr(key) Then\n                ws.Range(ws.Cells(copyRow, 1), ws.Cells(copyRow, colCount)).Copy _\n                    Destination:=wsNew.Cells(newRow, 1)\n                newRow = newRow + 1\n            End If\n        Next copyRow\n\n        wsNew.Columns.AutoFit\n        wbNew.SaveAs folderPath & \"\" & CStr(key) & \".xlsx\", xlOpenXMLWorkbook\n        wbNew.Close SaveChanges:=False\n    Next key\n\n    Application.ScreenUpdating = True\n    Application.DisplayAlerts = True\n\n    MsgBox \"分割完成！共建立 \" & uniqueValues.Count & \" 個檔案。\", vbInformation, \"完成\"\nEnd Sub\n\n' 填入切割範例資料\nPrivate Sub FillSampleSplitData(ByVal ws As Worksheet)\n    ws.Cells.Clear\n    ws.Range(\"A1\").Value = \"姓名\"\n    ws.Range(\"B1\").Value = \"部門\"\n    ws.Range(\"C1\").Value = \"薪資\"\n    ws.Range(\"A2\").Value = \"張三\"\n    ws.Range(\"B2\").Value = \"研發部\"\n    ws.Range(\"C2\").Value = 60000\n    ws.Range(\"A3\").Value = \"李四\"\n    ws.Range(\"B3\").Value = \"業務部\"\n    ws.Range(\"C3\").Value = 55000\n    ws.Range(\"A4\").Value = \"王五\"\n    ws.Range(\"B4\").Value = \"研發部\"\n    ws.Range(\"C4\").Value = 65000\n    ws.Range(\"A5\").Value = \"趙六\"\n    ws.Range(\"B5\").Value = \"行政部\"\n    ws.Range(\"C5\").Value = 45000\n    ws.Range(\"A6\").Value = \"孫七\"\n    ws.Range(\"B6\").Value = \"業務部\"\n    ws.Range(\"C6\").Value = 58000\n    ws.Range(\"A7\").Value = \"周八\"\n    ws.Range(\"B7\").Value = \"行政部\"\n    ws.Range(\"C7\").Value = 47000\n    ws.Columns(\"A:C\").AutoFit\nEnd Sub\n\n' 取得或建立工作表，並清除內容\nPrivate Function GetOrCreateSheet(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add\n        ws.Name = sheetName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreateSheet = ws\nEnd Function\n", "content_b64": ""}, {"name": "SplitSheetByRowCount.bas", "path": "模組/FileSplit/SplitSheetByRowCount.bas", "content": "Option Explicit\n\n' 依指定資料列數切割目前工作表，每個區塊另存為新活頁簿。\nPublic Sub SplitSheetByRowCountExample()\n    On Error GoTo ErrHandler\n\n    Dim rowsPerFile As Long\n    Dim outputFolder As String\n\n    rowsPerFile = CLng(Application.InputBox(\"請輸入每個檔案的資料列數\", \"切割列數\", 100, Type:=1))\n    If rowsPerFile <= 0 Then Exit Sub\n\n    outputFolder = ThisWorkbook.Path\n    If Len(outputFolder) = 0 Then\n        MsgBox \"請先儲存目前活頁簿，再執行切割。\", vbExclamation, \"提醒\"\n        Exit Sub\n    End If\n\n    Call SplitActiveSheetByRowCount(rowsPerFile, outputFolder)\n    MsgBox \"工作表切割完成。\", vbInformation, \"完成\"\n    Exit Sub\n\nErrHandler:\n    MsgBox \"切割工作表失敗：\" & Err.Description, vbExclamation, \"錯誤\"\nEnd Sub\n\nPrivate Sub SplitActiveSheetByRowCount(ByVal rowsPerFile As Long, ByVal outputFolder As String)\n    Dim srcWs As Worksheet\n    Dim newWb As Workbook\n    Dim newWs As Worksheet\n    Dim lastRow As Long\n    Dim lastCol As Long\n    Dim startRow As Long\n    Dim endRow As Long\n    Dim fileIndex As Long\n    Dim targetRowCount As Long\n\n    Set srcWs = ActiveSheet\n    lastRow = srcWs.Cells(srcWs.Rows.Count, 1).End(xlUp).Row\n    lastCol = srcWs.Cells(1, srcWs.Columns.Count).End(xlToLeft).Column\n\n    If lastRow < 2 Then Err.Raise vbObjectError + 510, , \"目前工作表沒有可切割的資料列。\"\n\n    fileIndex = 1\n    For startRow = 2 To lastRow Step rowsPerFile\n        endRow = startRow + rowsPerFile - 1\n        If endRow > lastRow Then endRow = lastRow\n\n        Set newWb = Workbooks.Add(xlWBATWorksheet)\n        Set newWs = newWb.Worksheets(1)\n        srcWs.Range(srcWs.Cells(1, 1), srcWs.Cells(1, lastCol)).Copy Destination:=newWs.Range(\"A1\")\n        targetRowCount = endRow - startRow + 1\n        srcWs.Range(srcWs.Cells(startRow, 1), srcWs.Cells(endRow, lastCol)).Copy Destination:=newWs.Range(\"A2\")\n        newWs.Columns.AutoFit\n        newWb.SaveAs outputFolder & \"\\SplitRows_\" & Format(fileIndex, \"000\") & \".xlsx\", xlOpenXMLWorkbook\n        newWb.Close SaveChanges:=False\n        fileIndex = fileIndex + 1\n    Next startRow\nEnd Sub", "content_b64": ""}, {"name": "SplitSheetToCSV.bas", "path": "模組/FileSplit/SplitSheetToCSV.bas", "content": "Attribute VB_Name = \"SplitSheetToCSV\"\n\nOption Explicit\n\n'*************************************************************************************\n\n'模組名稱: SplitSheetToCSV\n\n'功能說明: 依指定欄位的唯一值拆分工作表，每組資料另存為 CSV 格式檔案\n\n'\n\n'作者版權: Dunk\n\n'程式設計: Dunk\n\n'最後修改: 2026/5/9\n\n'\n\n'*************************************************************************************\n\n\n\n' 測試用入口：建立範例資料後執行 CSV 分割\n\nSub TestSplitToCSV()\n\n    Dim ws As Worksheet\n\n    Set ws = GetOrCreateSheetCSV(ThisWorkbook, \"CSV來源資料\")\n\n    Call FillSampleCSVData(ws)\n\n    Call SplitSheetByColumnToCSV(ws, 2)\n\nEnd Sub\n\n\n\n' 依欄位唯一值拆分工作表，各組存為 CSV 檔\n\n' ws: 來源工作表  splitColIndex: 分割依據欄號\n\nSub SplitSheetByColumnToCSV(ByVal ws As Worksheet, ByVal splitColIndex As Integer)\n\n    Dim folderPath As String\n\n    Dim lastRow As Long\n\n    Dim i As Long\n\n    Dim colCount As Long\n\n    Dim cellValue As String\n\n    Dim uniqueValues As Collection\n\n    Dim alreadyAdded As Boolean\n\n    Dim key As Variant\n\n    Dim wbNew As Workbook\n\n    Dim wsNew As Worksheet\n\n    Dim newRow As Long\n\n    Dim copyRow As Long\n\n\n\n    lastRow = ws.Cells(ws.Rows.Count, splitColIndex).End(xlUp).Row\n\n    If lastRow <= 1 Then\n\n        MsgBox \"工作表無資料可分割！\", vbExclamation, \"警告\"\n\n        Exit Sub\n\n    End If\n\n\n\n    With Application.FileDialog(msoFileDialogFolderPicker)\n\n        .Title = \"請選擇 CSV 輸出資料夾\"\n\n        If .Show <> -1 Then\n\n            MsgBox \"已取消操作\", vbInformation, \"取消\"\n\n            Exit Sub\n\n        End If\n\n        folderPath = .SelectedItems(1)\n\n    End With\n\n    If Right(folderPath, 1) <> \"\\\" Then folderPath = folderPath & \"\\\"\n\n\n\n    colCount = ws.Cells(1, ws.Columns.Count).End(xlToLeft).Column\n\n\n\n    Set uniqueValues = New Collection\n\n    For i = 2 To lastRow\n\n        cellValue = CStr(ws.Cells(i, splitColIndex).Value)\n\n        alreadyAdded = False\n\n        For Each key In uniqueValues\n\n            If key = cellValue Then\n\n                alreadyAdded = True\n\n                Exit For\n\n            End If\n\n        Next key\n\n        If Not alreadyAdded Then uniqueValues.Add cellValue\n\n    Next i\n\n\n\n    Application.ScreenUpdating = False\n\n    Application.DisplayAlerts = False\n\n\n\n    For Each key In uniqueValues\n\n        Set wbNew = Workbooks.Add\n\n        Set wsNew = wbNew.Worksheets(1)\n\n        ws.Range(ws.Cells(1, 1), ws.Cells(1, colCount)).Copy _\n\n            Destination:=wsNew.Cells(1, 1)\n\n        newRow = 2\n\n        For copyRow = 2 To lastRow\n\n            If CStr(ws.Cells(copyRow, splitColIndex).Value) = CStr(key) Then\n\n                ws.Range(ws.Cells(copyRow, 1), ws.Cells(copyRow, colCount)).Copy _\n\n                    Destination:=wsNew.Cells(newRow, 1)\n\n                newRow = newRow + 1\n\n            End If\n\n        Next copyRow\n\n        wbNew.SaveAs folderPath & CStr(key) & \".csv\", xlCSV\n\n        wbNew.Close SaveChanges:=False\n\n    Next key\n\n\n\n    Application.ScreenUpdating = True\n\n    Application.DisplayAlerts = True\n\n    MsgBox \"CSV 分割完成！共建立 \" & uniqueValues.Count & \" 個 CSV 檔案。\", vbInformation, \"完成\"\n\nEnd Sub\n\n\n\n' 建立範例資料\n\nPrivate Sub FillSampleCSVData(ByVal ws As Worksheet)\n\n    ws.Cells.Clear\n\n    ws.Range(\"A1\").Value = \"客戶\"\n\n    ws.Range(\"B1\").Value = \"地區\"\n\n    ws.Range(\"C1\").Value = \"訂單金額\"\n\n    ws.Range(\"A2\").Value = \"客戶甲\": ws.Range(\"B2\").Value = \"北區\": ws.Range(\"C2\").Value = 12000\n\n    ws.Range(\"A3\").Value = \"客戶乙\": ws.Range(\"B3\").Value = \"南區\": ws.Range(\"C3\").Value = 8500\n\n    ws.Range(\"A4\").Value = \"客戶丙\": ws.Range(\"B4\").Value = \"北區\": ws.Range(\"C4\").Value = 15000\n\n    ws.Range(\"A5\").Value = \"客戶丁\": ws.Range(\"B5\").Value = \"中區\": ws.Range(\"C5\").Value = 9300\n\n    ws.Range(\"A6\").Value = \"客戶戊\": ws.Range(\"B6\").Value = \"南區\": ws.Range(\"C6\").Value = 11200\n\n    ws.Range(\"A1:C1\").Font.Bold = True\n\n    ws.Columns(\"A:C\").AutoFit\n\nEnd Sub\n\n\n\n' 取得或建立工作表\n\nPrivate Function GetOrCreateSheetCSV(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n\n    Dim ws As Worksheet\n\n    On Error Resume Next\n\n    Set ws = wb.Worksheets(sheetName)\n\n    On Error GoTo 0\n\n    If ws Is Nothing Then\n\n        Set ws = wb.Worksheets.Add\n\n        ws.Name = sheetName\n\n    End If\n\n    ws.Cells.Clear\n\n    Set GetOrCreateSheetCSV = ws\n\nEnd Function\n\n", "content_b64": ""}, {"name": "SplitSheetToNewSheets.bas", "path": "模組/FileSplit/SplitSheetToNewSheets.bas", "content": "Attribute VB_Name = \"SplitSheetToNewSheets\"\n\nOption Explicit\n\n'*************************************************************************************\n\n'模組名稱: SplitSheetToNewSheets\n\n'功能說明: 依指定欄位的唯一值，將工作表資料拆分為同一活頁簿中的多個工作表\n\n'          （不另存新檔，直接在目前活頁簿新增分頁）\n\n'\n\n'作者版權: Dunk\n\n'程式設計: Dunk\n\n'最後修改: 2026/5/9\n\n'\n\n'*************************************************************************************\n\n\n\n' 測試用入口：建立範例資料後依部門拆分為多個工作表\n\nSub TestSplitToSheets()\n\n    Dim ws As Worksheet\n\n    Set ws = GetOrCreateSheetInBook(ThisWorkbook, \"待分割來源\")\n\n    Call FillSampleSheetData(ws)\n\n    Call SplitSheetIntoNewSheets(ws, 2)\n\nEnd Sub\n\n\n\n' 依欄位唯一值將資料拆分至同活頁簿的新工作表\n\n' ws: 來源工作表  splitColIndex: 分割依據欄號\n\nSub SplitSheetIntoNewSheets(ByVal ws As Worksheet, ByVal splitColIndex As Integer)\n\n    Dim lastRow As Long\n\n    Dim i As Long\n\n    Dim colCount As Long\n\n    Dim cellValue As String\n\n    Dim uniqueValues As Collection\n\n    Dim alreadyAdded As Boolean\n\n    Dim key As Variant\n\n    Dim wsNew As Worksheet\n\n    Dim newRow As Long\n\n    Dim copyRow As Long\n\n\n\n    lastRow = ws.Cells(ws.Rows.Count, splitColIndex).End(xlUp).Row\n\n    If lastRow <= 1 Then\n\n        MsgBox \"工作表無資料可分割！\", vbExclamation, \"警告\"\n\n        Exit Sub\n\n    End If\n\n\n\n    colCount = ws.Cells(1, ws.Columns.Count).End(xlToLeft).Column\n\n\n\n    Set uniqueValues = New Collection\n\n    For i = 2 To lastRow\n\n        cellValue = CStr(ws.Cells(i, splitColIndex).Value)\n\n        alreadyAdded = False\n\n        For Each key In uniqueValues\n\n            If key = cellValue Then\n\n                alreadyAdded = True\n\n                Exit For\n\n            End If\n\n        Next key\n\n        If Not alreadyAdded Then uniqueValues.Add cellValue\n\n    Next i\n\n\n\n    Application.ScreenUpdating = False\n\n\n\n    For Each key In uniqueValues\n\n        On Error Resume Next\n\n        Application.DisplayAlerts = False\n\n        ws.Parent.Worksheets(CStr(key)).Delete\n\n        Application.DisplayAlerts = True\n\n        On Error GoTo 0\n\n\n\n        Set wsNew = ws.Parent.Worksheets.Add( _\n\n            After:=ws.Parent.Worksheets(ws.Parent.Worksheets.Count))\n\n        wsNew.Name = Left(CStr(key), 31)\n\n        ws.Range(ws.Cells(1, 1), ws.Cells(1, colCount)).Copy _\n\n            Destination:=wsNew.Cells(1, 1)\n\n        newRow = 2\n\n        For copyRow = 2 To lastRow\n\n            If CStr(ws.Cells(copyRow, splitColIndex).Value) = CStr(key) Then\n\n                ws.Range(ws.Cells(copyRow, 1), ws.Cells(copyRow, colCount)).Copy _\n\n                    Destination:=wsNew.Cells(newRow, 1)\n\n                newRow = newRow + 1\n\n            End If\n\n        Next copyRow\n\n        wsNew.Columns.AutoFit\n\n    Next key\n\n\n\n    Application.ScreenUpdating = True\n\n    MsgBox \"已在目前活頁簿建立 \" & uniqueValues.Count & \" 個新工作表！\", vbInformation, \"完成\"\n\nEnd Sub\n\n\n\n' 建立範例資料\n\nPrivate Sub FillSampleSheetData(ByVal ws As Worksheet)\n\n    ws.Cells.Clear\n\n    ws.Range(\"A1\").Value = \"姓名\"\n\n    ws.Range(\"B1\").Value = \"部門\"\n\n    ws.Range(\"C1\").Value = \"職稱\"\n\n    ws.Range(\"A2\").Value = \"王大明\": ws.Range(\"B2\").Value = \"業務部\": ws.Range(\"C2\").Value = \"業務專員\"\n\n    ws.Range(\"A3\").Value = \"李小美\": ws.Range(\"B3\").Value = \"研發部\": ws.Range(\"C3\").Value = \"工程師\"\n\n    ws.Range(\"A4\").Value = \"張志偉\": ws.Range(\"B4\").Value = \"業務部\": ws.Range(\"C4\").Value = \"業務主任\"\n\n    ws.Range(\"A5\").Value = \"陳美如\": ws.Range(\"B5\").Value = \"行政部\": ws.Range(\"C5\").Value = \"行政助理\"\n\n    ws.Range(\"A6\").Value = \"林正雄\": ws.Range(\"B6\").Value = \"研發部\": ws.Range(\"C6\").Value = \"研發主任\"\n\n    ws.Range(\"A7\").Value = \"吳淑芬\": ws.Range(\"B7\").Value = \"行政部\": ws.Range(\"C7\").Value = \"人事專員\"\n\n    ws.Range(\"A1:C1\").Font.Bold = True\n\n    ws.Columns(\"A:C\").AutoFit\n\nEnd Sub\n\n\n\n' 取得或建立工作表\n\nPrivate Function GetOrCreateSheetInBook(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n\n    Dim ws As Worksheet\n\n    On Error Resume Next\n\n    Set ws = wb.Worksheets(sheetName)\n\n    On Error GoTo 0\n\n    If ws Is Nothing Then\n\n        Set ws = wb.Worksheets.Add\n\n        ws.Name = sheetName\n\n    End If\n\n    ws.Cells.Clear\n\n    Set GetOrCreateSheetInBook = ws\n\nEnd Function\n\n", "content_b64": ""}, {"name": "SplitSheetWithPassword.bas", "path": "模組/FileSplit/SplitSheetWithPassword.bas", "content": "Attribute VB_Name = \"SplitSheetWithPassword\"\n\nOption Explicit\n\n'*************************************************************************************\n\n'模組名稱: SplitSheetWithPassword\n\n'功能說明: 依欄位唯一值拆分工作表，並對每個輸出的 Excel 檔案設定開啟密碼保護\n\n'          適合需要分發給不同收件人且要求保密的情境\n\n'\n\n'作者版權: Dunk\n\n'程式設計: Dunk\n\n'最後修改: 2026/5/9\n\n'\n\n'*************************************************************************************\n\n\n\n' 測試用入口：建立範例資料後執行加密分割\n\nSub TestSplitWithPassword()\n\n    Dim ws As Worksheet\n\n    Dim pwd As String\n\n    Set ws = GetOrCreateSheetPwd(ThisWorkbook, \"加密分割來源\")\n\n    Call FillSamplePwdData(ws)\n\n    pwd = InputBox(\"請輸入每個分割檔案的開啟密碼：\", \"設定密碼\", \"P@ssw0rd\")\n\n    If Len(Trim(pwd)) = 0 Then\n\n        MsgBox \"密碼不可為空白，操作取消。\", vbExclamation, \"取消\"\n\n        Exit Sub\n\n    End If\n\n    Call SplitSheetByColumnWithPassword(ws, 2, pwd)\n\nEnd Sub\n\n\n\n' 依欄位唯一值拆分工作表並以密碼保護輸出檔\n\n' ws: 來源工作表  splitColIndex: 分割欄號  filePassword: 檔案開啟密碼\n\nSub SplitSheetByColumnWithPassword(ByVal ws As Worksheet, _\n\n                                    ByVal splitColIndex As Integer, _\n\n                                    ByVal filePassword As String)\n\n    Dim folderPath As String\n\n    Dim lastRow As Long\n\n    Dim i As Long\n\n    Dim colCount As Long\n\n    Dim cellValue As String\n\n    Dim uniqueValues As Collection\n\n    Dim alreadyAdded As Boolean\n\n    Dim key As Variant\n\n    Dim wbNew As Workbook\n\n    Dim wsNew As Worksheet\n\n    Dim newRow As Long\n\n    Dim copyRow As Long\n\n\n\n    lastRow = ws.Cells(ws.Rows.Count, splitColIndex).End(xlUp).Row\n\n    If lastRow <= 1 Then\n\n        MsgBox \"工作表無資料可分割！\", vbExclamation, \"警告\"\n\n        Exit Sub\n\n    End If\n\n\n\n    With Application.FileDialog(msoFileDialogFolderPicker)\n\n        .Title = \"請選擇加密檔案輸出資料夾\"\n\n        If .Show <> -1 Then\n\n            MsgBox \"已取消操作\", vbInformation, \"取消\"\n\n            Exit Sub\n\n        End If\n\n        folderPath = .SelectedItems(1)\n\n    End With\n\n    If Right(folderPath, 1) <> \"\\\" Then folderPath = folderPath & \"\\\"\n\n\n\n    colCount = ws.Cells(1, ws.Columns.Count).End(xlToLeft).Column\n\n\n\n    Set uniqueValues = New Collection\n\n    For i = 2 To lastRow\n\n        cellValue = CStr(ws.Cells(i, splitColIndex).Value)\n\n        alreadyAdded = False\n\n        For Each key In uniqueValues\n\n            If key = cellValue Then\n\n                alreadyAdded = True\n\n                Exit For\n\n            End If\n\n        Next key\n\n        If Not alreadyAdded Then uniqueValues.Add cellValue\n\n    Next i\n\n\n\n    Application.ScreenUpdating = False\n\n    Application.DisplayAlerts = False\n\n\n\n    For Each key In uniqueValues\n\n        Set wbNew = Workbooks.Add\n\n        Set wsNew = wbNew.Worksheets(1)\n\n        wsNew.Name = Left(CStr(key), 31)\n\n        ws.Range(ws.Cells(1, 1), ws.Cells(1, colCount)).Copy _\n\n            Destination:=wsNew.Cells(1, 1)\n\n        newRow = 2\n\n        For copyRow = 2 To lastRow\n\n            If CStr(ws.Cells(copyRow, splitColIndex).Value) = CStr(key) Then\n\n                ws.Range(ws.Cells(copyRow, 1), ws.Cells(copyRow, colCount)).Copy _\n\n                    Destination:=wsNew.Cells(newRow, 1)\n\n                newRow = newRow + 1\n\n            End If\n\n        Next copyRow\n\n        wsNew.Columns.AutoFit\n\n        ' 以密碼保護儲存 Excel 檔案\n\n        wbNew.SaveAs folderPath & CStr(key) & \".xlsx\", _\n\n            FileFormat:=xlOpenXMLWorkbook, _\n\n            Password:=filePassword\n\n        wbNew.Close SaveChanges:=False\n\n    Next key\n\n\n\n    Application.ScreenUpdating = True\n\n    Application.DisplayAlerts = True\n\n    MsgBox \"加密分割完成！共建立 \" & uniqueValues.Count & \" 個加密檔案。\", vbInformation, \"完成\"\n\nEnd Sub\n\n\n\n' 建立範例資料\n\nPrivate Sub FillSamplePwdData(ByVal ws As Worksheet)\n\n    ws.Cells.Clear\n\n    ws.Range(\"A1\").Value = \"員工編號\"\n\n    ws.Range(\"B1\").Value = \"部門\"\n\n    ws.Range(\"C1\").Value = \"薪資\"\n\n    ws.Range(\"D1\").Value = \"考績\"\n\n    ws.Range(\"A2\").Value = \"E001\": ws.Range(\"B2\").Value = \"財務部\": ws.Range(\"C2\").Value = 55000: ws.Range(\"D2\").Value = \"A\"\n\n    ws.Range(\"A3\").Value = \"E002\": ws.Range(\"B3\").Value = \"研發部\": ws.Range(\"C3\").Value = 72000: ws.Range(\"D3\").Value = \"B\"\n\n    ws.Range(\"A4\").Value = \"E003\": ws.Range(\"B4\").Value = \"財務部\": ws.Range(\"C4\").Value = 48000: ws.Range(\"D4\").Value = \"A\"\n\n    ws.Range(\"A5\").Value = \"E004\": ws.Range(\"B5\").Value = \"業務部\": ws.Range(\"C5\").Value = 61000: ws.Range(\"D5\").Value = \"C\"\n\n    ws.Range(\"A6\").Value = \"E005\": ws.Range(\"B6\").Value = \"研發部\": ws.Range(\"C6\").Value = 83000: ws.Range(\"D6\").Value = \"A\"\n\n    ws.Range(\"A1:D1\").Font.Bold = True\n\n    ws.Columns(\"A:D\").AutoFit\n\nEnd Sub\n\n\n\n' 取得或建立工作表\n\nPrivate Function GetOrCreateSheetPwd(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n\n    Dim ws As Worksheet\n\n    On Error Resume Next\n\n    Set ws = wb.Worksheets(sheetName)\n\n    On Error GoTo 0\n\n    If ws Is Nothing Then\n\n        Set ws = wb.Worksheets.Add\n\n        ws.Name = sheetName\n\n    End If\n\n    ws.Cells.Clear\n\n    Set GetOrCreateSheetPwd = ws\n\nEnd Function\n\n", "content_b64": ""}, {"name": "SplitWorkbookBySheet.bas", "path": "模組/FileSplit/SplitWorkbookBySheet.bas", "content": "Attribute VB_Name = \"SplitWorkbookBySheet\"\n\nOption Explicit\n\n\n\n' ============================================================\n\n' 範例：將活頁簿每個工作表分別存成獨立的 Excel 檔案\n\n' 功能：依工作表名稱逐一另存新檔至指定資料夾\n\n' ============================================================\n\nSub SplitWorkbookBySheet()\n\n    Dim strFolder   As String\n\n    Dim ws          As Worksheet\n\n    Dim wbNew       As Workbook\n\n    Dim strPath     As String\n\n    Dim intCount    As Integer\n\n\n\n    ' --- 選擇儲存資料夾 ---\n\n    With Application.FileDialog(msoFileDialogFolderPicker)\n\n        .Title = \"請選擇輸出資料夾\"\n\n        If .Show <> -1 Then\n\n            MsgBox \"已取消操作。\", vbInformation\n\n            Exit Sub\n\n        End If\n\n        strFolder = .SelectedItems(1)\n\n    End With\n\n\n\n    If Right(strFolder, 1) <> \"\\\" Then strFolder = strFolder & \"\\\"\n\n\n\n    On Error GoTo ErrHandler\n\n    Application.ScreenUpdating = False\n\n    Application.DisplayAlerts = False\n\n    intCount = 0\n\n\n\n    ' --- 逐一複製工作表並另存 ---\n\n    For Each ws In ThisWorkbook.Worksheets\n\n        ws.Copy\n\n        Set wbNew = ActiveWorkbook\n\n        strPath = strFolder & ws.Name & \".xlsx\"\n\n        wbNew.SaveAs Filename:=strPath, FileFormat:=xlOpenXMLWorkbook\n\n        wbNew.Close SaveChanges:=False\n\n        intCount = intCount + 1\n\n    Next ws\n\n\n\n    Application.ScreenUpdating = True\n\n    Application.DisplayAlerts = True\n\n    MsgBox \"已成功切割 \" & intCount & \" 個工作表，輸出至：\" & strFolder, vbInformation\n\n    Exit Sub\n\n\n\nErrHandler:\n\n    Application.ScreenUpdating = True\n\n    Application.DisplayAlerts = True\n\n    MsgBox \"發生錯誤：\" & Err.Description, vbCritical\n\nEnd Sub\n\n", "content_b64": ""}]}, {"folder": "FilterDataBasedonMultipleConditions", "path": "模組/FilterDataBasedonMultipleConditions", "files": [{"name": "AdvancedFilterExample.bas", "path": "模組/FilterDataBasedonMultipleConditions/AdvancedFilterExample.bas", "content": "Attribute VB_Name = \"AdvancedFilterExample\"\n\nOption Explicit\n\n\n\n' ============================================================\n\n' 範例：使用 VBA 進階篩選（AdvancedFilter）篩選資料至新位置\n\n' 功能：設定條件範圍後，將篩選結果複製到同工作表指定區域\n\n' ============================================================\n\nSub RunAdvancedFilterExample()\n\n    Dim ws          As Worksheet\n\n    Dim rngData     As Range\n\n    Dim rngCriteria As Range\n\n    Dim rngOutput   As Range\n\n\n\n    On Error GoTo ErrHandler\n\n\n\n    ' --- 建立示範資料 ---\n\n    Set ws = ThisWorkbook.Worksheets.Add\n\n    ws.Name = \"AdvFilterDemo\"\n\n\n\n    ws.Range(\"A1\").Value = \"部門\"\n\n    ws.Range(\"B1\").Value = \"員工\"\n\n    ws.Range(\"C1\").Value = \"薪資\"\n\n\n\n    Dim arrData As Variant\n\n    arrData = Array( _\n\n        Array(\"業務\", \"王小明\", 45000), _\n\n        Array(\"業務\", \"林美華\", 42000), _\n\n        Array(\"工程\", \"張大同\", 60000), _\n\n        Array(\"工程\", \"陳雅婷\", 58000), _\n\n        Array(\"人事\", \"劉建國\", 40000), _\n\n        Array(\"業務\", \"吳志明\", 48000))\n\n    Dim i As Integer\n\n    For i = 0 To 5\n\n        ws.Cells(2 + i, 1).Value = arrData(i)(0)\n\n        ws.Cells(2 + i, 2).Value = arrData(i)(1)\n\n        ws.Cells(2 + i, 3).Value = arrData(i)(2)\n\n    Next i\n\n\n\n    ' --- 設定條件範圍（部門=業務，薪資>42000）---\n\n    ws.Range(\"E1\").Value = \"部門\"\n\n    ws.Range(\"E2\").Value = \"業務\"\n\n    ws.Range(\"F1\").Value = \"薪資\"\n\n    ws.Range(\"F2\").Value = \">42000\"\n\n\n\n    ' --- 設定輸出標題 ---\n\n    ws.Range(\"A10\").Value = \"篩選結果：\"\n\n\n\n    Set rngData = ws.Range(\"A1:C7\")\n\n    Set rngCriteria = ws.Range(\"E1:F2\")\n\n    Set rngOutput = ws.Range(\"A11\")\n\n\n\n    ' --- 執行進階篩選 ---\n\n    rngData.AdvancedFilter _\n\n        Action:=xlFilterCopy, _\n\n        CriteriaRange:=rngCriteria, _\n\n        CopyToRange:=rngOutput, _\n\n        Unique:=False\n\n\n\n    ws.Columns.AutoFit\n\n    MsgBox \"進階篩選完成！結果已複製至 A11 起始範圍。\", vbInformation\n\n    Exit Sub\n\n\n\nErrHandler:\n\n    MsgBox \"發生錯誤：\" & Err.Description, vbCritical\n\nEnd Sub\n\n", "content_b64": ""}, {"name": "AutoFilterMultiConditions.bas", "path": "模組/FilterDataBasedonMultipleConditions/AutoFilterMultiConditions.bas", "content": "Attribute VB_Name = \"AutoFilterMultiConditions\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: AutoFilterMultiConditions\n'功能說明: 示範依據多重條件篩選資料，包含自動篩選及進階篩選\n'\n'著作權所有: Dunk\n'程式設計: Dunk\n'撰寫日期: 2026/5/7\n'\n'*************************************************************************************\n\n' 測試用入口\nSub TestAutoFilterMultiConditions()\n    Dim ws As Worksheet\n    Set ws = GetOrCreateSheet(ThisWorkbook, \"篩選資料範例\")\n    Call FillEmployeeData(ws)\n    Call FilterByMultipleConditions(ws, \"研發部\", 55000)\nEnd Sub\n\n' 依多重條件篩選（部門 + 薪資下限）\nSub FilterByMultipleConditions(ByVal ws As Worksheet, ByVal department As String, _\n                                ByVal minSalary As Long)\n    If ws.AutoFilterMode Then\n        ws.AutoFilterMode = False\n    End If\n\n    ' 套用自動篩選：A欄=姓名, B欄=部門, C欄=薪資\n    ws.Range(\"A1\").AutoFilter\n    ws.Range(\"A1\").AutoFilter Field:=2, Criteria1:=department\n    ws.Range(\"A1\").AutoFilter Field:=3, Criteria1:=\">\" & minSalary\n\n    MsgBox \"已套用篩選條件：\" & vbCrLf & _\n           \"部門 = \" & department & vbCrLf & _\n           \"薪資 > \" & minSalary, _\n           vbInformation, \"篩選完成\"\nEnd Sub\n\n' 清除所有篩選條件並顯示全部資料\nSub ClearAllFilters()\n    Dim ws As Worksheet\n    Set ws = ActiveSheet\n    If ws.AutoFilterMode Then\n        ws.AutoFilterMode = False\n    End If\n    MsgBox \"已清除所有篩選條件！\", vbInformation, \"完成\"\nEnd Sub\n\n' 將篩選結果複製到新工作表\nSub CopyFilteredResultToSheet()\n    Dim wsSource As Worksheet\n    Dim wsResult As Worksheet\n    Dim visibleRange As Range\n    Dim lastRow As Long\n    Dim lastCol As Long\n\n    Set wsSource = ActiveSheet\n\n    If Not wsSource.AutoFilterMode Then\n        MsgBox \"目前未套用篩選，請先執行篩選！\", vbExclamation, \"警告\"\n        Exit Sub\n    End If\n\n    Set wsResult = GetOrCreateSheet(ThisWorkbook, \"篩選結果\")\n\n    lastRow = wsSource.Cells(wsSource.Rows.Count, 1).End(xlUp).Row\n    lastCol = wsSource.Cells(1, wsSource.Columns.Count).End(xlToLeft).Column\n\n    Set visibleRange = wsSource.Range( _\n        wsSource.Cells(1, 1), _\n        wsSource.Cells(lastRow, lastCol)).SpecialCells(xlCellTypeVisible)\n\n    visibleRange.Copy Destination:=wsResult.Cells(1, 1)\n    wsResult.Columns.AutoFit\n    wsResult.Activate\n    MsgBox \"篩選結果已複製到工作表「篩選結果」！\", vbInformation, \"完成\"\nEnd Sub\n\n' 進階篩選：依條件範圍篩選並輸出到指定位置\nSub AdvancedFilterExample()\n    Dim wsData As Worksheet\n    Dim wsCriteria As Worksheet\n    Dim wsOutput As Worksheet\n\n    Set wsData = GetOrCreateSheet(ThisWorkbook, \"進階篩選資料\")\n    Call FillEmployeeData(wsData)\n\n    Set wsCriteria = GetOrCreateSheet(ThisWorkbook, \"篩選條件\")\n    ' 條件：部門=業務部 OR 薪資>=60000（OR關係需在不同列）\n    wsCriteria.Range(\"A1\").Value = \"部門\"\n    wsCriteria.Range(\"B1\").Value = \"薪資\"\n    wsCriteria.Range(\"A2\").Value = \"業務部\"\n    wsCriteria.Range(\"B3\").Value = \">=60000\"\n\n    Set wsOutput = GetOrCreateSheet(ThisWorkbook, \"進階篩選結果\")\n\n    wsData.Range(\"A1\").CurrentRegion.AdvancedFilter _\n        Action:=xlFilterCopy, _\n        CriteriaRange:=wsCriteria.Range(\"A1:B3\"), _\n        CopyToRange:=wsOutput.Range(\"A1\"), _\n        Unique:=False\n\n    wsOutput.Columns.AutoFit\n    wsOutput.Activate\n    MsgBox \"進階篩選完成！結果已輸出至「進階篩選結果」工作表。\", vbInformation, \"完成\"\nEnd Sub\n\n' 填入員工資料\nPrivate Sub FillEmployeeData(ByVal ws As Worksheet)\n    ws.Range(\"A1\").Value = \"姓名\"\n    ws.Range(\"B1\").Value = \"部門\"\n    ws.Range(\"C1\").Value = \"薪資\"\n    ws.Range(\"D1\").Value = \"年資\"\n    ws.Range(\"A2\").Value = \"張三\"\n    ws.Range(\"B2\").Value = \"研發部\"\n    ws.Range(\"C2\").Value = 70000\n    ws.Range(\"D2\").Value = 5\n    ws.Range(\"A3\").Value = \"李四\"\n    ws.Range(\"B3\").Value = \"業務部\"\n    ws.Range(\"C3\").Value = 55000\n    ws.Range(\"D3\").Value = 3\n    ws.Range(\"A4\").Value = \"王五\"\n    ws.Range(\"B4\").Value = \"研發部\"\n    ws.Range(\"C4\").Value = 80000\n    ws.Range(\"D4\").Value = 8\n    ws.Range(\"A5\").Value = \"趙六\"\n    ws.Range(\"B5\").Value = \"行政部\"\n    ws.Range(\"C5\").Value = 45000\n    ws.Range(\"D5\").Value = 2\n    ws.Range(\"A6\").Value = \"孫七\"\n    ws.Range(\"B6\").Value = \"業務部\"\n    ws.Range(\"C6\").Value = 62000\n    ws.Range(\"D6\").Value = 6\n    ws.Range(\"A7\").Value = \"周八\"\n    ws.Range(\"B7\").Value = \"研發部\"\n    ws.Range(\"C7\").Value = 50000\n    ws.Range(\"D7\").Value = 1\n    ws.Columns(\"A:D\").AutoFit\nEnd Sub\n\n' 取得或建立工作表，並清除內容\nPrivate Function GetOrCreateSheet(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add\n        ws.Name = sheetName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreateSheet = ws\nEnd Function\n", "content_b64": ""}, {"name": "FilterAndSummarize.bas", "path": "模組/FilterDataBasedonMultipleConditions/FilterAndSummarize.bas", "content": "Attribute VB_Name = \"FilterAndSummarize\"\nOption Explicit\n\n'************************************************************************************\n' 模組名稱: FilterAndSummarize\n' 功能說明: 篩選後使用 SUBTOTAL 函數對可見儲存格加總，並輸出分類彙總表\n'           同時示範 SpecialCells(xlCellTypeVisible) 取得篩選後可見範圍\n'\n' 作者版權: Dunk\n' 現任設計: Dunk\n' 最後修改: 2026/5/9\n'************************************************************************************\n\n' 入口：對各區域套用篩選並產生彙總結果\nPublic Sub FilterAndSummarizeByRegion()\n    On Error GoTo ErrHandler\n\n    Dim wsData   As Worksheet\n    Dim wsResult As Worksheet\n    Dim regions  As Variant\n    Dim i        As Integer\n\n    Set wsData = GetOrCreateWsSum(ThisWorkbook, \"銷售資料\")\n    Call FillSalesRegionData(wsData)\n\n    Set wsResult = GetOrCreateWsSum(ThisWorkbook, \"區域彙總\")\n    wsResult.Range(\"A1:C1\").Value = Array(\"區域\", \"篩選筆數\", \"合計銷售額\")\n\n    regions = Array(\"北區\", \"中區\", \"南區\", \"東區\")\n    Dim resultRow As Integer\n    resultRow = 2\n\n    For i = 0 To UBound(regions)\n        Dim regionName  As String\n        Dim filteredCnt As Long\n        Dim filteredSum As Double\n\n        regionName = regions(i)\n        Call GetFilteredStats(wsData, regionName, filteredCnt, filteredSum)\n\n        wsResult.Cells(resultRow, 1).Value = regionName\n        wsResult.Cells(resultRow, 2).Value = filteredCnt\n        wsResult.Cells(resultRow, 3).Value = filteredSum\n        resultRow = resultRow + 1\n    Next i\n\n    ' 清除篩選狀態\n    If wsData.AutoFilterMode Then wsData.AutoFilterMode = False\n\n    wsResult.Range(\"C2:C5\").NumberFormat = \"#,##0\"\n    wsResult.Columns(\"A:C\").AutoFit\n    wsResult.Activate\n    MsgBox \"各區域彙總完成，結果在「區域彙總」工作表。\", vbInformation, \"完成\"\n    Exit Sub\n\nErrHandler:\n    If wsData.AutoFilterMode Then wsData.AutoFilterMode = False\n    MsgBox \"發生錯誤：\" & Err.Description, vbCritical, \"錯誤\"\nEnd Sub\n\n' 對指定區域篩選，取得可見列數與合計\nPrivate Sub GetFilteredStats(ByVal ws As Worksheet, ByVal region As String, _\n                              ByRef outCount As Long, ByRef outSum As Double)\n    Dim rng         As Range\n    Dim visibleRng  As Range\n    Dim lastRow     As Long\n\n    If ws.AutoFilterMode Then ws.AutoFilterMode = False\n\n    Set rng = ws.Range(\"A1\").CurrentRegion\n    rng.AutoFilter Field:=2, Criteria1:=region\n\n    lastRow = ws.Cells(ws.Rows.Count, 1).End(xlUp).Row\n\n    On Error Resume Next\n    Set visibleRng = ws.Range(\"A2:A\" & lastRow).SpecialCells(xlCellTypeVisible)\n    On Error GoTo 0\n\n    If visibleRng Is Nothing Then\n        outCount = 0\n        outSum = 0\n    Else\n        outCount = visibleRng.Count\n        ' SUBTOTAL(9,...) 僅加總可見儲存格\n        outSum = Application.WorksheetFunction.Subtotal(9, ws.Range(\"C2:C\" & lastRow))\n    End If\nEnd Sub\n\n' 填入多區域銷售測試資料\nPrivate Sub FillSalesRegionData(ByVal ws As Worksheet)\n    ws.Range(\"A1:C1\").Value = Array(\"月份\", \"區域\", \"銷售額\")\n    ws.Range(\"A2:C2\").Value = Array(\"2026/01\", \"北區\", 580000)\n    ws.Range(\"A3:C3\").Value = Array(\"2026/01\", \"中區\", 420000)\n    ws.Range(\"A4:C4\").Value = Array(\"2026/01\", \"南區\", 650000)\n    ws.Range(\"A5:C5\").Value = Array(\"2026/01\", \"東區\", 310000)\n    ws.Range(\"A6:C6\").Value = Array(\"2026/02\", \"北區\", 720000)\n    ws.Range(\"A7:C7\").Value = Array(\"2026/02\", \"中區\", 390000)\n    ws.Range(\"A8:C8\").Value = Array(\"2026/02\", \"南區\", 480000)\n    ws.Range(\"A9:C9\").Value = Array(\"2026/02\", \"東區\", 260000)\n    ws.Range(\"C2:C9\").NumberFormat = \"#,##0\"\n    ws.Columns(\"A:C\").AutoFit\nEnd Sub\n\n' 取得或建立工作表並清空\nPrivate Function GetOrCreateWsSum(ByVal wb As Workbook, ByVal shName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(shName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add\n        ws.Name = shName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreateWsSum = ws\nEnd Function", "content_b64": ""}, {"name": "FilterBlankNonBlank.bas", "path": "模組/FilterDataBasedonMultipleConditions/FilterBlankNonBlank.bas", "content": "Attribute VB_Name = \"FilterBlankNonBlank\"\nOption Explicit\n\n'************************************************************************************\n' 模組名稱: FilterBlankNonBlank\n' 功能說明: 使用 AutoFilter 篩選空白列或非空白列\n'           示範找出備註未填寫與已填寫的記錄\n'\n' 作者版權: Dunk\n' 現任設計: Dunk\n' 最後修改: 2026/5/9\n'************************************************************************************\n\n' 入口：篩選備註欄空白的列（待跟進記錄）\nPublic Sub FilterBlankRemarkExample()\n    On Error GoTo ErrHandler\n\n    Dim ws As Worksheet\n    Set ws = GetOrCreateWsBlank(ThisWorkbook, \"空白篩選範例\")\n    Call FillRemarkData(ws)\n    Call ApplyBlankFilter(ws, 4, True)\n\n    MsgBox \"已篩選出「備註」欄空白的記錄（待跟進）。\", vbInformation, \"完成\"\n    Exit Sub\n\nErrHandler:\n    MsgBox \"發生錯誤：\" & Err.Description, vbCritical, \"錯誤\"\nEnd Sub\n\n' 入口：篩選備註欄非空白的列（已處理記錄）\nPublic Sub FilterNonBlankRemarkExample()\n    On Error GoTo ErrHandler\n\n    Dim ws As Worksheet\n    Set ws = GetOrCreateWsBlank(ThisWorkbook, \"空白篩選範例\")\n    Call FillRemarkData(ws)\n    Call ApplyBlankFilter(ws, 4, False)\n\n    MsgBox \"已篩選出「備註」欄有填寫的記錄（已處理）。\", vbInformation, \"完成\"\n    Exit Sub\n\nErrHandler:\n    MsgBox \"發生錯誤：\" & Err.Description, vbCritical, \"錯誤\"\nEnd Sub\n\n' 清除篩選\nPublic Sub ClearBlankFilter()\n    Dim ws As Worksheet\n    Set ws = ActiveSheet\n    If ws.AutoFilterMode Then ws.AutoFilterMode = False\n    MsgBox \"已清除篩選條件。\", vbInformation, \"完成\"\nEnd Sub\n\n' 套用空白/非空白篩選\n' filterField: 欄位編號（1-based）\n' blankOnly: True=只顯示空白，False=只顯示非空白\nPrivate Sub ApplyBlankFilter(ByVal ws As Worksheet, _\n                              ByVal filterField As Integer, _\n                              ByVal blankOnly As Boolean)\n    Dim rng As Range\n    Set rng = ws.Range(\"A1\").CurrentRegion\n    If ws.AutoFilterMode Then ws.AutoFilterMode = False\n\n    If blankOnly Then\n        rng.AutoFilter Field:=filterField, Criteria1:=\"=\"\n    Else\n        rng.AutoFilter Field:=filterField, Criteria1:=\"<>\"\n    End If\n    ws.Columns(\"A:D\").AutoFit\nEnd Sub\n\n' 填入含空白備註的測試資料\nPrivate Sub FillRemarkData(ByVal ws As Worksheet)\n    ws.Range(\"A1:D1\").Value = Array(\"案件編號\", \"客戶\", \"金額\", \"備註\")\n    ws.Range(\"A2:D2\").Value = Array(\"C001\", \"甲公司\", 15000, \"已確認\")\n    ws.Range(\"A3:D3\").Value = Array(\"C002\", \"乙公司\", 8500, \"\")\n    ws.Range(\"A4:D4\").Value = Array(\"C003\", \"丙公司\", 22000, \"待簽約\")\n    ws.Range(\"A5:D5\").Value = Array(\"C004\", \"丁公司\", 3200, \"\")\n    ws.Range(\"A6:D6\").Value = Array(\"C005\", \"戊公司\", 67000, \"已付款\")\n    ws.Range(\"A7:D7\").Value = Array(\"C006\", \"己公司\", 4800, \"\")\n    ws.Range(\"C2:C7\").NumberFormat = \"#,##0\"\n    ws.Columns(\"A:D\").AutoFit\nEnd Sub\n\n' 取得或建立工作表並清空\nPrivate Function GetOrCreateWsBlank(ByVal wb As Workbook, ByVal shName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(shName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add\n        ws.Name = shName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreateWsBlank = ws\nEnd Function", "content_b64": ""}, {"name": "FilterByCellColor.bas", "path": "模組/FilterDataBasedonMultipleConditions/FilterByCellColor.bas", "content": "Attribute VB_Name = \"FilterByCellColor\"\nOption Explicit\n\n'************************************************************************************\n' 模組名稱: FilterByCellColor\n' 功能說明: 依儲存格背景色篩選資料（AutoFilter FilterByColor）\n'           同時示範手動以 Interior.Color 逐列比對並複製到新工作表\n'\n' 作者版權: Dunk\n' 現任設計: Dunk\n' 最後修改: 2026/5/9\n'************************************************************************************\n\n' 定義標記色彩常數\nPrivate Const COLOR_RED    As Long = RGB(255, 199, 206)  ' 紅色警示（庫存不足）\nPrivate Const COLOR_YELLOW As Long = RGB(255, 235, 156)  ' 黃色提醒（即將不足）\nPrivate Const COLOR_GREEN  As Long = RGB(198, 239, 206)  ' 綠色正常\n\n' 入口：以 AutoFilter FilterByColor 篩選紅色警示列\nPublic Sub FilterByRedColorExample()\n    On Error GoTo ErrHandler\n\n    Dim ws As Worksheet\n    Set ws = GetOrCreateWsColor(ThisWorkbook, \"色彩篩選範例\")\n    Call FillColorCodedData(ws)\n\n    If ws.AutoFilterMode Then ws.AutoFilterMode = False\n\n    ' AutoFilter 依背景色篩選（xlFilterCellColor：背景色）\n    ws.Range(\"A1\").CurrentRegion.AutoFilter _\n        Field:=4, _\n        Criteria1:=COLOR_RED, _\n        Operator:=xlFilterCellColor\n\n    ws.Columns(\"A:D\").AutoFit\n    MsgBox \"已篩選庫存不足（紅色警示）的商品。\", vbInformation, \"完成\"\n    Exit Sub\n\nErrHandler:\n    MsgBox \"發生錯誤：\" & Err.Description, vbCritical, \"錯誤\"\nEnd Sub\n\n' 入口：手動逐列比對顏色，將紅色列複製到新工作表\nPublic Sub CopyRedRowsToNewSheet()\n    On Error GoTo ErrHandler\n\n    Dim wsSource As Worksheet\n    Dim wsResult As Worksheet\n    Dim lastRow  As Long\n    Dim i        As Long\n    Dim resultRow As Long\n\n    Set wsSource = GetOrCreateWsColor(ThisWorkbook, \"色彩篩選範例\")\n    Call FillColorCodedData(wsSource)\n\n    Set wsResult = GetOrCreateWsColor(ThisWorkbook, \"紅色警示清單\")\n    lastRow = wsSource.Cells(wsSource.Rows.Count, 1).End(xlUp).Row\n\n    ' 複製標題列\n    wsSource.Rows(1).Copy Destination:=wsResult.Rows(1)\n    resultRow = 2\n\n    For i = 2 To lastRow\n        ' 判斷 D 欄（庫存量）儲存格的背景色\n        If wsSource.Cells(i, 4).Interior.Color = COLOR_RED Then\n            wsSource.Rows(i).Copy Destination:=wsResult.Rows(resultRow)\n            resultRow = resultRow + 1\n        End If\n    Next i\n\n    wsResult.Columns.AutoFit\n    wsResult.Activate\n    MsgBox \"已將紅色警示列複製到「紅色警示清單」工作表。共 \" & _\n           (resultRow - 2) & \" 筆。\", vbInformation, \"完成\"\n    Exit Sub\n\nErrHandler:\n    MsgBox \"發生錯誤：\" & Err.Description, vbCritical, \"錯誤\"\nEnd Sub\n\n' 清除色彩篩選\nPublic Sub ClearColorFilter()\n    Dim ws As Worksheet\n    Set ws = ActiveSheet\n    If ws.AutoFilterMode Then ws.AutoFilterMode = False\n    MsgBox \"已清除色彩篩選。\", vbInformation, \"完成\"\nEnd Sub\n\n' 填入帶有色彩標記的庫存資料\nPrivate Sub FillColorCodedData(ByVal ws As Worksheet)\n    ws.Range(\"A1:D1\").Value = Array(\"商品代碼\", \"品名\", \"安全庫存\", \"現有庫存\")\n\n    Dim rowData As Variant\n    rowData = Array( _\n        Array(\"G001\", \"電阻 10K\", 100, 250), _\n        Array(\"G002\", \"電容 100uF\", 200, 45), _\n        Array(\"G003\", \"二極體 1N4007\", 300, 320), _\n        Array(\"G004\", \"電感 10uH\", 150, 80), _\n        Array(\"G005\", \"IC NE555\", 50, 10), _\n        Array(\"G006\", \"LED 紅色\", 500, 620), _\n        Array(\"G007\", \"繼電器 5V\", 80, 60), _\n        Array(\"G008\", \"光耦合器\", 120, 5))\n\n    Dim i As Integer\n    For i = 0 To 7\n        Dim safeQty   As Long\n        Dim currentQty As Long\n        safeQty = CLng(rowData(i)(2))\n        currentQty = CLng(rowData(i)(3))\n\n        ws.Cells(i + 2, 1).Value = rowData(i)(0)\n        ws.Cells(i + 2, 2).Value = rowData(i)(1)\n        ws.Cells(i + 2, 3).Value = safeQty\n        ws.Cells(i + 2, 4).Value = currentQty\n\n        ' 依庫存量套用色彩標記\n        If currentQty < safeQty * 0.3 Then\n            ws.Cells(i + 2, 4).Interior.Color = COLOR_RED     ' 嚴重不足\n        ElseIf currentQty < safeQty Then\n            ws.Cells(i + 2, 4).Interior.Color = COLOR_YELLOW  ' 低於安全量\n        Else\n            ws.Cells(i + 2, 4).Interior.Color = COLOR_GREEN   ' 正常\n        End If\n    Next i\n\n    ws.Columns(\"A:D\").AutoFit\nEnd Sub\n\n' 取得或建立工作表並清空\nPrivate Function GetOrCreateWsColor(ByVal wb As Workbook, ByVal shName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(shName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add\n        ws.Name = shName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreateWsColor = ws\nEnd Function", "content_b64": ""}, {"name": "FilterByDateAndAmount.bas", "path": "模組/FilterDataBasedonMultipleConditions/FilterByDateAndAmount.bas", "content": "Option Explicit\n\n' 依日期區間與最低金額篩選資料。\nPublic Sub FilterByDateAndAmountExample()\n    On Error GoTo ErrHandler\n\n    Dim ws As Worksheet\n    Dim startDate As Date\n    Dim endDate As Date\n    Dim minAmount As Double\n\n    Set ws = GetOrCreateFilterWorksheet(\"日期金額篩選範例\")\n    ws.Cells.Clear\n    Call FillDateAmountData(ws)\n\n    startDate = DateSerial(2026, 1, 1)\n    endDate = DateSerial(2026, 1, 31)\n    minAmount = 3000\n    Call ApplyDateAmountFilter(ws, startDate, endDate, minAmount)\n\n    MsgBox \"多重條件篩選已套用完成。\", vbInformation, \"完成\"\n    Exit Sub\n\nErrHandler:\n    MsgBox \"篩選資料失敗：\" & Err.Description, vbExclamation, \"錯誤\"\nEnd Sub\n\nPrivate Sub ApplyDateAmountFilter(ByVal ws As Worksheet, ByVal startDate As Date, ByVal endDate As Date, ByVal minAmount As Double)\n    Dim dataRange As Range\n\n    Set dataRange = ws.Range(\"A1\").CurrentRegion\n    If ws.AutoFilterMode Then ws.AutoFilterMode = False\n\n    dataRange.AutoFilter Field:=1, Criteria1:=\">=\" & CLng(startDate), Operator:=xlAnd, Criteria2:=\"<=\" & CLng(endDate)\n    dataRange.AutoFilter Field:=4, Criteria1:=\">=\" & minAmount\n    ws.Columns(\"A:D\").AutoFit\nEnd Sub\n\nPrivate Sub FillDateAmountData(ByVal ws As Worksheet)\n    ws.Range(\"A1:D1\").Value = Array(\"日期\", \"客戶\", \"產品\", \"金額\")\n    ws.Range(\"A2:D2\").Value = Array(DateSerial(2026, 1, 3), \"甲公司\", \"A\", 2800)\n    ws.Range(\"A3:D3\").Value = Array(DateSerial(2026, 1, 8), \"乙公司\", \"B\", 5200)\n    ws.Range(\"A4:D4\").Value = Array(DateSerial(2026, 1, 20), \"丙公司\", \"A\", 3600)\n    ws.Range(\"A5:D5\").Value = Array(DateSerial(2026, 2, 5), \"丁公司\", \"C\", 4100)\n    ws.Range(\"A6:D6\").Value = Array(DateSerial(2026, 1, 26), \"戊公司\", \"B\", 1900)\n    ws.Range(\"A2:A6\").NumberFormat = \"yyyy/mm/dd\"\n    ws.Range(\"D2:D6\").NumberFormat = \"#,##0\"\nEnd Sub\n\nPrivate Function GetOrCreateFilterWorksheet(ByVal sheetName As String) As Worksheet\n    On Error Resume Next\n    Set GetOrCreateFilterWorksheet = ThisWorkbook.Worksheets(sheetName)\n    On Error GoTo 0\n\n    If GetOrCreateFilterWorksheet Is Nothing Then\n        Set GetOrCreateFilterWorksheet = ThisWorkbook.Worksheets.Add\n        GetOrCreateFilterWorksheet.Name = sheetName\n    End If\nEnd Function", "content_b64": ""}, {"name": "FilterByDateRangeWithDropdown.bas", "path": "模組/FilterDataBasedonMultipleConditions/FilterByDateRangeWithDropdown.bas", "content": "Attribute VB_Name = \"FilterByDateRangeWithDropdown\"\nOption Explicit\n\n'************************************************************************************\n' 模組名稱: FilterByDateRangeWithDropdown\n' 功能說明: 使用 AutoFilter 依「月份」或「季度」下拉選項篩選日期欄位\n'           提供快速按月／按季篩選的工具函式\n'\n' 作者版權: Dunk\n' 現任設計: Dunk\n' 最後修改: 2026/5/9\n'************************************************************************************\n\n' 入口：依月份篩選（只保留指定年月的資料列）\nPublic Sub FilterByMonthExample()\n    On Error GoTo ErrHandler\n\n    Dim ws          As Worksheet\n    Dim targetYear  As Integer\n    Dim targetMonth As Integer\n\n    Set ws = GetOrCreateWsDate(ThisWorkbook, \"月份篩選範例\")\n    Call FillMonthlyData(ws)\n\n    targetYear  = 2026\n    targetMonth = 3  ' 3月\n\n    Call ApplyMonthFilter(ws, 1, targetYear, targetMonth)\n\n    MsgBox \"已篩選 \" & targetYear & \" 年 \" & targetMonth & \" 月的資料。\", vbInformation, \"完成\"\n    Exit Sub\n\nErrHandler:\n    MsgBox \"發生錯誤：\" & Err.Description, vbCritical, \"錯誤\"\nEnd Sub\n\n' 入口：依季度篩選（Q1=1~3月, Q2=4~6月, ...）\nPublic Sub FilterByQuarterExample()\n    On Error GoTo ErrHandler\n\n    Dim ws        As Worksheet\n    Dim targetQtr As Integer\n\n    Set ws = GetOrCreateWsDate(ThisWorkbook, \"季度篩選範例\")\n    Call FillMonthlyData(ws)\n\n    targetQtr = 1  ' 第一季 (1~3月)\n\n    Call ApplyQuarterFilter(ws, 1, 2026, targetQtr)\n\n    MsgBox \"已篩選 2026 年第 \" & targetQtr & \" 季資料。\", vbInformation, \"完成\"\n    Exit Sub\n\nErrHandler:\n    MsgBox \"發生錯誤：\" & Err.Description, vbCritical, \"錯誤\"\nEnd Sub\n\n' 依年月篩選（在 Field 欄套用開始與結束日期範圍）\nPrivate Sub ApplyMonthFilter(ByVal ws As Worksheet, ByVal dateField As Integer, _\n                              ByVal yr As Integer, ByVal mo As Integer)\n    Dim dtStart As Date\n    Dim dtEnd   As Date\n\n    dtStart = DateSerial(yr, mo, 1)\n    dtEnd   = DateSerial(yr, mo + 1, 1) - 1\n\n    If ws.AutoFilterMode Then ws.AutoFilterMode = False\n\n    ws.Range(\"A1\").CurrentRegion.AutoFilter _\n        Field:=dateField, _\n        Criteria1:=\">=\" & CLng(dtStart), _\n        Operator:=xlAnd, _\n        Criteria2:=\"<=\" & CLng(dtEnd)\n\n    ws.Columns(\"A:C\").AutoFit\nEnd Sub\n\n' 依季度篩選\nPrivate Sub ApplyQuarterFilter(ByVal ws As Worksheet, ByVal dateField As Integer, _\n                                ByVal yr As Integer, ByVal qtr As Integer)\n    Dim startMonth As Integer\n    Dim dtStart    As Date\n    Dim dtEnd      As Date\n\n    startMonth = (qtr - 1) * 3 + 1\n    dtStart = DateSerial(yr, startMonth, 1)\n    dtEnd   = DateSerial(yr, startMonth + 3, 1) - 1\n\n    If ws.AutoFilterMode Then ws.AutoFilterMode = False\n\n    ws.Range(\"A1\").CurrentRegion.AutoFilter _\n        Field:=dateField, _\n        Criteria1:=\">=\" & CLng(dtStart), _\n        Operator:=xlAnd, _\n        Criteria2:=\"<=\" & CLng(dtEnd)\n\n    ws.Columns(\"A:C\").AutoFit\nEnd Sub\n\n' 填入逐月銷售測試資料\nPrivate Sub FillMonthlyData(ByVal ws As Worksheet)\n    ws.Range(\"A1:C1\").Value = Array(\"日期\", \"品項\", \"銷售額\")\n    ws.Range(\"A2:C2\").Value  = Array(DateSerial(2026, 1, 5),  \"商品A\", 32000)\n    ws.Range(\"A3:C3\").Value  = Array(DateSerial(2026, 1, 20), \"商品B\", 18000)\n    ws.Range(\"A4:C4\").Value  = Array(DateSerial(2026, 2, 10), \"商品A\", 41000)\n    ws.Range(\"A5:C5\").Value  = Array(DateSerial(2026, 2, 25), \"商品C\", 27000)\n    ws.Range(\"A6:C6\").Value  = Array(DateSerial(2026, 3, 8),  \"商品B\", 55000)\n    ws.Range(\"A7:C7\").Value  = Array(DateSerial(2026, 3, 22), \"商品A\", 38000)\n    ws.Range(\"A8:C8\").Value  = Array(DateSerial(2026, 4, 3),  \"商品C\", 62000)\n    ws.Range(\"A9:C9\").Value  = Array(DateSerial(2026, 4, 18), \"商品A\", 29000)\n    ws.Range(\"A2:A9\").NumberFormat = \"yyyy/mm/dd\"\n    ws.Range(\"C2:C9\").NumberFormat = \"#,##0\"\n    ws.Columns(\"A:C\").AutoFit\nEnd Sub\n\n' 取得或建立工作表並清空\nPrivate Function GetOrCreateWsDate(ByVal wb As Workbook, ByVal shName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(shName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add\n        ws.Name = shName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreateWsDate = ws\nEnd Function", "content_b64": ""}, {"name": "FilterByDynamicInputBox.bas", "path": "模組/FilterDataBasedonMultipleConditions/FilterByDynamicInputBox.bas", "content": "Attribute VB_Name = \"FilterByDynamicInputBox\"\nOption Explicit\n\n'************************************************************************************\n' 模組名稱: FilterByDynamicInputBox\n' 功能說明: 透過 InputBox 讓使用者即時輸入篩選條件（欄位名稱＋條件值）\n'           動態決定要篩選哪一欄與比較值，實現互動式篩選\n'\n' 作者版權: Dunk\n' 現任設計: Dunk\n' 最後修改: 2026/5/9\n'************************************************************************************\n\n' 入口：提示使用者輸入條件後執行篩選\nPublic Sub FilterByDynamicInputBoxExample()\n    On Error GoTo ErrHandler\n\n    Dim ws         As Worksheet\n    Dim colName    As String\n    Dim criteria   As String\n    Dim fieldIndex As Integer\n\n    Set ws = GetOrCreateWsDyn(ThisWorkbook, \"動態篩選範例\")\n    Call FillInventoryData(ws)\n\n    ' 詢問要篩選的欄位名稱\n    colName = InputBox(\"請輸入篩選欄位名稱（倉庫 / 類別 / 數量）：\", \"動態篩選 - 欄位\", \"倉庫\")\n    If colName = \"\" Then Exit Sub\n\n    ' 詢問條件值\n    criteria = InputBox(\"請輸入篩選條件（可加比較符號如 >100）：\", \"動態篩選 - 條件\", \"A倉\")\n    If criteria = \"\" Then Exit Sub\n\n    ' 查找欄位編號\n    fieldIndex = FindColumnIndex(ws, colName)\n    If fieldIndex = 0 Then\n        MsgBox \"找不到欄位「\" & colName & \"」，請確認欄名正確。\", vbExclamation, \"欄位錯誤\"\n        Exit Sub\n    End If\n\n    ' 套用篩選\n    If ws.AutoFilterMode Then ws.AutoFilterMode = False\n    ws.Range(\"A1\").CurrentRegion.AutoFilter Field:=fieldIndex, Criteria1:=criteria\n    ws.Columns(\"A:D\").AutoFit\n\n    MsgBox \"已篩選「\" & colName & \"」\" & criteria & \" 的資料。\", vbInformation, \"完成\"\n    Exit Sub\n\nErrHandler:\n    MsgBox \"發生錯誤：\" & Err.Description, vbCritical, \"錯誤\"\nEnd Sub\n\n' 清除動態篩選\nPublic Sub ClearDynamicFilter()\n    Dim ws As Worksheet\n    Set ws = ActiveSheet\n    If ws.AutoFilterMode Then ws.AutoFilterMode = False\n    MsgBox \"已清除篩選。\", vbInformation, \"完成\"\nEnd Sub\n\n' 依標題名稱找欄位編號（1-based）\nPrivate Function FindColumnIndex(ByVal ws As Worksheet, ByVal colName As String) As Integer\n    Dim lastCol As Integer\n    Dim j       As Integer\n\n    lastCol = ws.Cells(1, ws.Columns.Count).End(xlToLeft).Column\n    FindColumnIndex = 0\n\n    For j = 1 To lastCol\n        If ws.Cells(1, j).Value = colName Then\n            FindColumnIndex = j\n            Exit Function\n        End If\n    Next j\nEnd Function\n\n' 填入倉庫庫存測試資料\nPrivate Sub FillInventoryData(ByVal ws As Worksheet)\n    ws.Range(\"A1:D1\").Value = Array(\"料號\", \"類別\", \"倉庫\", \"數量\")\n    ws.Range(\"A2:D2\").Value = Array(\"P001\", \"零件\", \"A倉\", 250)\n    ws.Range(\"A3:D3\").Value = Array(\"P002\", \"成品\", \"B倉\", 80)\n    ws.Range(\"A4:D4\").Value = Array(\"P003\", \"零件\", \"A倉\", 420)\n    ws.Range(\"A5:D5\").Value = Array(\"P004\", \"原料\", \"C倉\", 1500)\n    ws.Range(\"A6:D6\").Value = Array(\"P005\", \"成品\", \"A倉\", 35)\n    ws.Range(\"A7:D7\").Value = Array(\"P006\", \"原料\", \"B倉\", 200)\n    ws.Range(\"A8:D8\").Value = Array(\"P007\", \"零件\", \"C倉\", 90)\n    ws.Columns(\"A:D\").AutoFit\nEnd Sub\n\n' 取得或建立工作表並清空\nPrivate Function GetOrCreateWsDyn(ByVal wb As Workbook, ByVal shName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(shName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add\n        ws.Name = shName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreateWsDyn = ws\nEnd Function", "content_b64": ""}, {"name": "FilterByMultipleKeywordsOR.bas", "path": "模組/FilterDataBasedonMultipleConditions/FilterByMultipleKeywordsOR.bas", "content": "Attribute VB_Name = \"FilterByMultipleKeywordsOR\"\nOption Explicit\n\n'************************************************************************************\n' 模組名稱: FilterByMultipleKeywordsOR\n' 功能說明: 使用 AdvancedFilter OR 邏輯，篩選某欄符合多個關鍵字之任一的資料\n'           每個關鍵字條件分列在條件區的不同列（OR 關係）\n'\n' 作者版權: Dunk\n' 現任設計: Dunk\n' 最後修改: 2026/5/9\n'************************************************************************************\n\n' 入口：篩選「城市」欄中包含台北、台中或高雄的客戶\nPublic Sub FilterByMultipleKeywordsORExample()\n    On Error GoTo ErrHandler\n\n    Dim wsData     As Worksheet\n    Dim wsCriteria As Worksheet\n    Dim wsResult   As Worksheet\n\n    Set wsData = GetOrCreateWsKw(ThisWorkbook, \"多關鍵字來源\")\n    Call FillCityData(wsData)\n\n    ' 建立條件區（OR：各關鍵字分行）\n    Set wsCriteria = GetOrCreateWsKw(ThisWorkbook, \"多關鍵字條件\")\n    wsCriteria.Range(\"A1\").Value = \"城市\"\n    wsCriteria.Range(\"A2\").Value = \"台北*\"\n    wsCriteria.Range(\"A3\").Value = \"台中*\"\n    wsCriteria.Range(\"A4\").Value = \"高雄*\"\n\n    Set wsResult = GetOrCreateWsKw(ThisWorkbook, \"多關鍵字結果\")\n\n    wsData.Range(\"A1\").CurrentRegion.AdvancedFilter _\n        Action:=xlFilterCopy, _\n        CriteriaRange:=wsCriteria.Range(\"A1:A4\"), _\n        CopyToRange:=wsResult.Range(\"A1\"), _\n        Unique:=False\n\n    wsResult.Columns.AutoFit\n    wsResult.Activate\n    MsgBox \"已篩選台北/台中/高雄客戶，結果在「多關鍵字結果」工作表。\", vbInformation, \"完成\"\n    Exit Sub\n\nErrHandler:\n    MsgBox \"發生錯誤：\" & Err.Description, vbCritical, \"錯誤\"\nEnd Sub\n\n' 填入客戶城市測試資料\nPrivate Sub FillCityData(ByVal ws As Worksheet)\n    ws.Range(\"A1:C1\").Value = Array(\"客戶名稱\", \"城市\", \"消費金額\")\n    ws.Range(\"A2:C2\").Value = Array(\"甲公司\", \"台北市信義區\", 85000)\n    ws.Range(\"A3:C3\").Value = Array(\"乙公司\", \"新竹市東區\", 42000)\n    ws.Range(\"A4:C4\").Value = Array(\"丙公司\", \"台中市西屯區\", 67000)\n    ws.Range(\"A5:C5\").Value = Array(\"丁公司\", \"高雄市前鎮區\", 91000)\n    ws.Range(\"A6:C6\").Value = Array(\"戊公司\", \"桃園市中壢區\", 35000)\n    ws.Range(\"A7:C7\").Value = Array(\"己公司\", \"台北市大安區\", 120000)\n    ws.Range(\"A8:C8\").Value = Array(\"庚公司\", \"台南市永康區\", 58000)\n    ws.Range(\"A9:C9\").Value = Array(\"辛公司\", \"高雄市鹽埕區\", 47000)\n    ws.Range(\"C2:C9\").NumberFormat = \"#,##0\"\n    ws.Columns(\"A:C\").AutoFit\nEnd Sub\n\n' 取得或建立工作表並清空\nPrivate Function GetOrCreateWsKw(ByVal wb As Workbook, ByVal shName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(shName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add\n        ws.Name = shName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreateWsKw = ws\nEnd Function", "content_b64": ""}, {"name": "FilterByPercentile.bas", "path": "模組/FilterDataBasedonMultipleConditions/FilterByPercentile.bas", "content": "Attribute VB_Name = \"FilterByPercentile\"\nOption Explicit\n\n'************************************************************************************\n' 模組名稱: FilterByPercentile\n' 功能說明: 計算指定欄位的百分位數門檻值，再用 AutoFilter 篩選超過門檻的記錄\n'           示範自訂百分位數動態篩選（如：業績高於第75百分位）\n'\n' 作者版權: Dunk\n' 現任設計: Dunk\n' 最後修改: 2026/5/9\n'************************************************************************************\n\n' 入口：篩選業績高於第 75 百分位的業務員\nPublic Sub FilterAbovePercentileExample()\n    On Error GoTo ErrHandler\n\n    Dim ws          As Worksheet\n    Dim percentile  As Double\n    Dim threshold   As Double\n\n    Set ws = GetOrCreateWsPct(ThisWorkbook, \"百分位篩選範例\")\n    Call FillPerformanceData(ws)\n\n    percentile = 75   ' 第 75 百分位\n    threshold = CalcPercentile(ws, 3, percentile)\n\n    If ws.AutoFilterMode Then ws.AutoFilterMode = False\n    ws.Range(\"A1\").CurrentRegion.AutoFilter Field:=3, Criteria1:=\">\" & threshold\n    ws.Columns(\"A:D\").AutoFit\n\n    MsgBox \"已篩選業績高於第 \" & percentile & \" 百分位（門檻：\" & _\n           Format(threshold, \"#,##0\") & \" 元）的業務員。\", vbInformation, \"完成\"\n    Exit Sub\n\nErrHandler:\n    MsgBox \"發生錯誤：\" & Err.Description, vbCritical, \"錯誤\"\nEnd Sub\n\n' 清除百分位篩選\nPublic Sub ClearPercentileFilter()\n    Dim ws As Worksheet\n    Set ws = ActiveSheet\n    If ws.AutoFilterMode Then ws.AutoFilterMode = False\n    MsgBox \"已清除篩選。\", vbInformation, \"完成\"\nEnd Sub\n\n' 計算指定欄的第 N 百分位值（使用 Percentile 工作表函數）\nPrivate Function CalcPercentile(ByVal ws As Worksheet, _\n                                 ByVal col As Integer, _\n                                 ByVal pct As Double) As Double\n    Dim lastRow As Long\n    Dim rng     As Range\n\n    lastRow = ws.Cells(ws.Rows.Count, col).End(xlUp).Row\n    Set rng = ws.Range(ws.Cells(2, col), ws.Cells(lastRow, col))\n\n    CalcPercentile = Application.WorksheetFunction.Percentile(rng, pct / 100)\nEnd Function\n\n' 填入業績測試資料\nPrivate Sub FillPerformanceData(ByVal ws As Worksheet)\n    ws.Range(\"A1:D1\").Value = Array(\"業務員\", \"部門\", \"季業績\", \"客戶數\")\n    ws.Range(\"A2:D2\").Value = Array(\"王大明\", \"北區業務\", 820000, 12)\n    ws.Range(\"A3:D3\").Value = Array(\"陳美珠\", \"南區業務\", 1350000, 18)\n    ws.Range(\"A4:D4\").Value = Array(\"林志偉\", \"中區業務\", 560000, 8)\n    ws.Range(\"A5:D5\").Value = Array(\"黃麗娟\", \"北區業務\", 940000, 14)\n    ws.Range(\"A6:D6\").Value = Array(\"張建國\", \"東區業務\", 430000, 6)\n    ws.Range(\"A7:D7\").Value = Array(\"蔡雅芳\", \"南區業務\", 1120000, 16)\n    ws.Range(\"A8:D8\").Value = Array(\"吳俊仁\", \"中區業務\", 670000, 10)\n    ws.Range(\"A9:D9\").Value = Array(\"李淑君\", \"東區業務\", 780000, 11)\n    ws.Range(\"C2:C9\").NumberFormat = \"#,##0\"\n    ws.Columns(\"A:D\").AutoFit\nEnd Sub\n\n' 取得或建立工作表並清空\nPrivate Function GetOrCreateWsPct(ByVal wb As Workbook, ByVal shName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(shName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add\n        ws.Name = shName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreateWsPct = ws\nEnd Function", "content_b64": ""}, {"name": "FilterByRegExp.bas", "path": "模組/FilterDataBasedonMultipleConditions/FilterByRegExp.bas", "content": "Attribute VB_Name = \"FilterByRegExp\"\nOption Explicit\n\n'************************************************************************************\n' 模組名稱: FilterByRegExp\n' 功能說明: 使用 VBScript.RegExp 對每列進行正則比對，手動控制列可見性\n'           適合 AutoFilter 無法表達的複雜文字條件（如：開頭為數字+英文）\n'\n' 作者版權: Dunk\n' 現任設計: Dunk\n' 最後修改: 2026/5/9\n'************************************************************************************\n\n' 入口：只顯示料號格式符合 \"^\\d{3}-[A-Z]{2}\" 的資料列（如 001-AB）\nPublic Sub FilterByRegExpPatternExample()\n    On Error GoTo ErrHandler\n\n    Dim ws As Worksheet\n    Set ws = GetOrCreateWsReg(ThisWorkbook, \"RegExp篩選範例\")\n    Call FillPartNumberData(ws)\n    Call ApplyRegExpFilter(ws, 1, \"^\\d{3}-[A-Z]{2}\")\n\n    MsgBox \"RegExp 篩選完成！僅顯示符合「3位數字-2位大寫英文」格式的料號。\", vbInformation, \"完成\"\n    Exit Sub\n\nErrHandler:\n    MsgBox \"發生錯誤：\" & Err.Description, vbCritical, \"錯誤\"\nEnd Sub\n\n' 清除手動隱藏（顯示所有列）\nPublic Sub ShowAllRows()\n    Dim ws As Worksheet\n    Set ws = ActiveSheet\n    ws.Rows.Hidden = False\n    MsgBox \"已取消所有列隱藏。\", vbInformation, \"完成\"\nEnd Sub\n\n' 對指定欄套用 RegExp 篩選，隱藏不符合的列\nPrivate Sub ApplyRegExpFilter(ByVal ws As Worksheet, _\n                               ByVal targetCol As Integer, _\n                               ByVal pattern As String)\n    Dim re       As Object\n    Dim lastRow  As Long\n    Dim i        As Long\n    Dim cellVal  As String\n\n    Set re = CreateObject(\"VBScript.RegExp\")\n    re.Pattern = pattern\n    re.IgnoreCase = False\n    re.Global = False\n\n    lastRow = ws.Cells(ws.Rows.Count, targetCol).End(xlUp).Row\n\n    ' 先顯示所有列\n    ws.Rows.Hidden = False\n\n    ' 從第2列開始逐列比對\n    For i = 2 To lastRow\n        cellVal = CStr(ws.Cells(i, targetCol).Value)\n        If Not re.Test(cellVal) Then\n            ws.Rows(i).Hidden = True\n        End If\n    Next i\nEnd Sub\n\n' 填入料號測試資料\nPrivate Sub FillPartNumberData(ByVal ws As Worksheet)\n    ws.Range(\"A1:C1\").Value = Array(\"料號\", \"品名\", \"庫存量\")\n    ws.Range(\"A2:C2\").Value = Array(\"001-AB\", \"螺絲 M3\", 500)\n    ws.Range(\"A3:C3\").Value = Array(\"X12-cd\", \"螺帽 M4\", 300)  ' 小寫不符\n    ws.Range(\"A4:C4\").Value = Array(\"045-ZK\", \"墊片 10mm\", 800)\n    ws.Range(\"A5:C5\").Value = Array(\"AB-123\", \"彈簧 5cm\", 120)  ' 格式不符\n    ws.Range(\"A6:C6\").Value = Array(\"078-TW\", \"銅管 6分\", 200)\n    ws.Range(\"A7:C7\").Value = Array(\"99-ABC\", \"鋁板 1mm\", 150)  ' 格式不符\n    ws.Range(\"A8:C8\").Value = Array(\"123-QR\", \"不鏽鋼棒\", 90)\n    ws.Columns(\"A:C\").AutoFit\nEnd Sub\n\n' 取得或建立工作表並清空\nPrivate Function GetOrCreateWsReg(ByVal wb As Workbook, ByVal shName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(shName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add\n        ws.Name = shName\n    End If\n    ws.Rows.Hidden = False\n    ws.Cells.Clear\n    Set GetOrCreateWsReg = ws\nEnd Function", "content_b64": ""}, {"name": "FilterByTextContains.bas", "path": "模組/FilterDataBasedonMultipleConditions/FilterByTextContains.bas", "content": "Attribute VB_Name = \"FilterByTextContains\"\nOption Explicit\n\n'************************************************************************************\n' 模組名稱: FilterByTextContains\n' 功能說明: 使用 AutoFilter 萬用字元篩選包含特定文字的資料列\n'           示範 * 萬用字元搭配多欄條件篩選\n'\n' 作者版權: Dunk\n' 現任設計: Dunk\n' 最後修改: 2026/5/9\n'************************************************************************************\n\n' 主要入口：篩選品名含「電」且供應商含「科技」的資料\nPublic Sub FilterByTextContainsExample()\n    On Error GoTo ErrHandler\n\n    Dim ws As Worksheet\n    Set ws = GetOrCreateWs(ThisWorkbook, \"文字篩選範例\")\n    Call FillProductData(ws)\n    Call ApplyTextContainsFilter(ws, \"電\", \"科技\")\n\n    MsgBox \"篩選完成！已保留品名含「電」且供應商含「科技」的列。\", vbInformation, \"完成\"\n    Exit Sub\n\nErrHandler:\n    MsgBox \"發生錯誤：\" & Err.Description, vbCritical, \"錯誤\"\nEnd Sub\n\n' 套用文字包含篩選\nPrivate Sub ApplyTextContainsFilter(ByVal ws As Worksheet, _\n                                     ByVal productKeyword As String, _\n                                     ByVal supplierKeyword As String)\n    Dim rng As Range\n    Set rng = ws.Range(\"A1\").CurrentRegion\n\n    If ws.AutoFilterMode Then ws.AutoFilterMode = False\n\n    ' Field:=1 品名含 productKeyword，Field:=3 供應商含 supplierKeyword\n    rng.AutoFilter Field:=1, Criteria1:=\"*\" & productKeyword & \"*\"\n    rng.AutoFilter Field:=3, Criteria1:=\"*\" & supplierKeyword & \"*\"\n    ws.Columns(\"A:D\").AutoFit\nEnd Sub\n\n' 填入商品測試資料\nPrivate Sub FillProductData(ByVal ws As Worksheet)\n    ws.Range(\"A1:D1\").Value = Array(\"品名\", \"單價\", \"供應商\", \"庫存\")\n    ws.Range(\"A2:D2\").Value = Array(\"液晶電視 55吋\", 18000, \"新光科技\", 30)\n    ws.Range(\"A3:D3\").Value = Array(\"冷氣機 1.5噸\", 25000, \"東元電器\", 20)\n    ws.Range(\"A4:D4\").Value = Array(\"電磁爐 IH\", 3200, \"品佳科技\", 80)\n    ws.Range(\"A5:D5\").Value = Array(\"掃地機器人\", 8900, \"小米科技\", 50)\n    ws.Range(\"A6:D6\").Value = Array(\"電風扇 DC\", 2200, \"大同電器\", 120)\n    ws.Range(\"A7:D7\").Value = Array(\"投影機 4K\", 35000, \"優派科技\", 10)\n    ws.Range(\"A8:D8\").Value = Array(\"洗衣機 滾筒\", 22000, \"日立電器\", 15)\n    ws.Columns(\"A:D\").AutoFit\nEnd Sub\n\n' 取得或建立工作表並清空\nPrivate Function GetOrCreateWs(ByVal wb As Workbook, ByVal shName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(shName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add\n        ws.Name = shName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreateWs = ws\nEnd Function", "content_b64": ""}, {"name": "FilterTopNRecords.bas", "path": "模組/FilterDataBasedonMultipleConditions/FilterTopNRecords.bas", "content": "Attribute VB_Name = \"FilterTopNRecords\"\nOption Explicit\n\n'************************************************************************************\n' 模組名稱: FilterTopNRecords\n' 功能說明: 使用 AutoFilter xlTop10Items / xlTop10Percent 篩選前 N 筆或前 N%\n'           示範依業績欄位篩選頂尖業務員\n'\n' 作者版權: Dunk\n' 現任設計: Dunk\n' 最後修改: 2026/5/9\n'************************************************************************************\n\n' 入口：篩選業績前 3 名\nPublic Sub FilterTop3SalesExample()\n    On Error GoTo ErrHandler\n\n    Dim ws As Worksheet\n    Set ws = GetOrCreateWsClean(ThisWorkbook, \"前N名篩選範例\")\n    Call FillSalesData(ws)\n    Call ApplyTopNFilter(ws, 3, False)\n\n    MsgBox \"已篩選出業績前 3 名業務員。\", vbInformation, \"完成\"\n    Exit Sub\n\nErrHandler:\n    MsgBox \"發生錯誤：\" & Err.Description, vbCritical, \"錯誤\"\nEnd Sub\n\n' 入口：篩選業績前 20%\nPublic Sub FilterTop20PercentSalesExample()\n    On Error GoTo ErrHandler\n\n    Dim ws As Worksheet\n    Set ws = GetOrCreateWsClean(ThisWorkbook, \"前20%篩選範例\")\n    Call FillSalesData(ws)\n    Call ApplyTopNFilter(ws, 20, True)\n\n    MsgBox \"已篩選出業績前 20% 業務員。\", vbInformation, \"完成\"\n    Exit Sub\n\nErrHandler:\n    MsgBox \"發生錯誤：\" & Err.Description, vbCritical, \"錯誤\"\nEnd Sub\n\n' 套用前 N 名或前 N% 篩選\n' isPercent=True 代表百分比，False 代表固定筆數\nPrivate Sub ApplyTopNFilter(ByVal ws As Worksheet, _\n                             ByVal topN As Integer, _\n                             ByVal isPercent As Boolean)\n    Dim rng As Range\n    Dim op As XlAutoFilterOperator\n\n    Set rng = ws.Range(\"A1\").CurrentRegion\n    If ws.AutoFilterMode Then ws.AutoFilterMode = False\n\n    If isPercent Then\n        op = xlTop10Percent\n    Else\n        op = xlTop10Items\n    End If\n\n    ' Field:=3 業績欄（C欄）取前 topN\n    rng.AutoFilter Field:=3, Criteria1:=topN, Operator:=op\n    ws.Columns(\"A:D\").AutoFit\nEnd Sub\n\n' 填入業務測試資料\nPrivate Sub FillSalesData(ByVal ws As Worksheet)\n    ws.Range(\"A1:D1\").Value = Array(\"業務員\", \"區域\", \"業績(元)\", \"達成率(%)\")\n    ws.Range(\"A2:D2\").Value = Array(\"王小明\", \"北區\", 980000, 112)\n    ws.Range(\"A3:D3\").Value = Array(\"李美玲\", \"中區\", 760000, 95)\n    ws.Range(\"A4:D4\").Value = Array(\"張志豪\", \"南區\", 1250000, 130)\n    ws.Range(\"A5:D5\").Value = Array(\"陳雅婷\", \"東區\", 540000, 78)\n    ws.Range(\"A6:D6\").Value = Array(\"林建宏\", \"北區\", 870000, 105)\n    ws.Range(\"A7:D7\").Value = Array(\"吳惠君\", \"中區\", 430000, 65)\n    ws.Range(\"A8:D8\").Value = Array(\"黃志偉\", \"南區\", 1100000, 120)\n    ws.Range(\"A9:D9\").Value = Array(\"蔡佳蓉\", \"東區\", 690000, 88)\n    ws.Range(\"C2:C9\").NumberFormat = \"#,##0\"\n    ws.Columns(\"A:D\").AutoFit\nEnd Sub\n\n' 取得或建立工作表並清空\nPrivate Function GetOrCreateWsClean(ByVal wb As Workbook, ByVal shName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(shName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add\n        ws.Name = shName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreateWsClean = ws\nEnd Function", "content_b64": ""}, {"name": "FilterUniqueRecords.bas", "path": "模組/FilterDataBasedonMultipleConditions/FilterUniqueRecords.bas", "content": "Attribute VB_Name = \"FilterUniqueRecords\"\nOption Explicit\n\n'************************************************************************************\n' 模組名稱: FilterUniqueRecords\n' 功能說明: 使用 AdvancedFilter Unique:=True 提取不重複記錄\n'           可選擇提取整列唯一值或指定欄位唯一清單\n'\n' 作者版權: Dunk\n' 現任設計: Dunk\n' 最後修改: 2026/5/9\n'************************************************************************************\n\n' 入口：提取整列不重複記錄\nPublic Sub ExtractUniqueRowsExample()\n    On Error GoTo ErrHandler\n\n    Dim wsData   As Worksheet\n    Dim wsResult As Worksheet\n\n    Set wsData = GetOrCreateWsUnique(ThisWorkbook, \"去重來源資料\")\n    Call FillDuplicateData(wsData)\n\n    Set wsResult = GetOrCreateWsUnique(ThisWorkbook, \"唯一記錄結果\")\n\n    ' AdvancedFilter 去重複並複製到結果工作表\n    wsData.Range(\"A1\").CurrentRegion.AdvancedFilter _\n        Action:=xlFilterCopy, _\n        CopyToRange:=wsResult.Range(\"A1\"), _\n        Unique:=True\n\n    wsResult.Columns.AutoFit\n    wsResult.Activate\n    MsgBox \"已提取不重複記錄，結果在「唯一記錄結果」工作表。\", vbInformation, \"完成\"\n    Exit Sub\n\nErrHandler:\n    MsgBox \"發生錯誤：\" & Err.Description, vbCritical, \"錯誤\"\nEnd Sub\n\n' 入口：提取單一欄位的唯一值清單\nPublic Sub ExtractUniqueColumnValuesExample()\n    On Error GoTo ErrHandler\n\n    Dim wsData   As Worksheet\n    Dim wsResult As Worksheet\n\n    Set wsData = GetOrCreateWsUnique(ThisWorkbook, \"去重來源資料\")\n    Call FillDuplicateData(wsData)\n\n    Set wsResult = GetOrCreateWsUnique(ThisWorkbook, \"部門唯一清單\")\n\n    ' 只針對 B 欄（部門）提取唯一值\n    wsData.Range(\"B1:B9\").AdvancedFilter _\n        Action:=xlFilterCopy, _\n        CopyToRange:=wsResult.Range(\"A1\"), _\n        Unique:=True\n\n    wsResult.Columns.AutoFit\n    wsResult.Activate\n    MsgBox \"已提取部門唯一清單，結果在「部門唯一清單」工作表。\", vbInformation, \"完成\"\n    Exit Sub\n\nErrHandler:\n    MsgBox \"發生錯誤：\" & Err.Description, vbCritical, \"錯誤\"\nEnd Sub\n\n' 填入含重複列的測試資料\nPrivate Sub FillDuplicateData(ByVal ws As Worksheet)\n    ws.Range(\"A1:C1\").Value = Array(\"姓名\", \"部門\", \"年資\")\n    ws.Range(\"A2:C2\").Value = Array(\"王小明\", \"業務部\", 3)\n    ws.Range(\"A3:C3\").Value = Array(\"李美玲\", \"工程部\", 5)\n    ws.Range(\"A4:C4\").Value = Array(\"王小明\", \"業務部\", 3)   ' 重複\n    ws.Range(\"A5:C5\").Value = Array(\"張志豪\", \"業務部\", 7)\n    ws.Range(\"A6:C6\").Value = Array(\"陳雅婷\", \"工程部\", 2)\n    ws.Range(\"A7:C7\").Value = Array(\"李美玲\", \"工程部\", 5)   ' 重複\n    ws.Range(\"A8:C8\").Value = Array(\"林建宏\", \"人資部\", 4)\n    ws.Range(\"A9:C9\").Value = Array(\"林建宏\", \"人資部\", 4)   ' 重複\n    ws.Columns(\"A:C\").AutoFit\nEnd Sub\n\n' 取得或建立工作表並清空\nPrivate Function GetOrCreateWsUnique(ByVal wb As Workbook, ByVal shName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(shName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add\n        ws.Name = shName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreateWsUnique = ws\nEnd Function", "content_b64": ""}]}, {"folder": "FormulaCreate", "path": "模組/FormulaCreate", "files": [{"name": "ArrayFormulaExample.bas", "path": "模組/FormulaCreate/ArrayFormulaExample.bas", "content": "Attribute VB_Name = \"ArrayFormulaExample\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: ArrayFormulaExample\n'功能說明: 示範在Excel中透過VBA輸入陣列公式的範例程式\n'\n'著作權所有: Dunk\n'程式設計: Dunk\n'撰寫日期: 2026/5/7\n'\n'*************************************************************************************\n\n' 測試用入口\nSub TestArrayFormula()\n    Call CreateArrayFormulaExample\nEnd Sub\n\n' 建立陣列公式範例\nSub CreateArrayFormulaExample()\n    Dim ws As Worksheet\n    Dim sheetName As String\n\n    sheetName = \"陣列公式範例\"\n\n    On Error Resume Next\n    Set ws = ThisWorkbook.Worksheets(sheetName)\n    On Error GoTo 0\n\n    If ws Is Nothing Then\n        Set ws = ThisWorkbook.Worksheets.Add\n        ws.Name = sheetName\n    End If\n\n    ws.Cells.Clear\n    Call FillProductData(ws)\n    Call EnterArrayFormulas(ws)\n\n    ws.Activate\n    MsgBox \"陣列公式範例已建立完成！\", vbInformation, \"完成\"\nEnd Sub\n\n' 填入產品銷售資料\nPrivate Sub FillProductData(ByVal ws As Worksheet)\n    ws.Range(\"A1\").Value = \"產品\"\n    ws.Range(\"B1\").Value = \"單價\"\n    ws.Range(\"C1\").Value = \"數量\"\n    ws.Range(\"D1\").Value = \"類別\"\n    ws.Range(\"A2\").Value = \"產品A\"\n    ws.Range(\"B2\").Value = 100\n    ws.Range(\"C2\").Value = 50\n    ws.Range(\"D2\").Value = \"電子\"\n    ws.Range(\"A3\").Value = \"產品B\"\n    ws.Range(\"B3\").Value = 200\n    ws.Range(\"C3\").Value = 30\n    ws.Range(\"D3\").Value = \"家電\"\n    ws.Range(\"A4\").Value = \"產品C\"\n    ws.Range(\"B4\").Value = 150\n    ws.Range(\"C4\").Value = 80\n    ws.Range(\"D4\").Value = \"電子\"\n    ws.Range(\"A5\").Value = \"產品D\"\n    ws.Range(\"B5\").Value = 300\n    ws.Range(\"C5\").Value = 20\n    ws.Range(\"D5\").Value = \"家電\"\n    ws.Range(\"A6\").Value = \"產品E\"\n    ws.Range(\"B6\").Value = 80\n    ws.Range(\"C6\").Value = 100\n    ws.Range(\"D6\").Value = \"電子\"\n    ws.Columns(\"A:D\").AutoFit\nEnd Sub\n\n' 輸入陣列公式\nPrivate Sub EnterArrayFormulas(ByVal ws As Worksheet)\n    ws.Range(\"F1\").Value = \"公式說明\"\n    ws.Range(\"G1\").Value = \"結果\"\n\n    ' 陣列公式：所有產品銷售總額\n    ws.Range(\"F2\").Value = \"銷售總額(陣列公式)\"\n    ws.Range(\"G2\").FormulaArray = \"=SUM(B2:B6*C2:C6)\"\n\n    ' 陣列公式：電子類別銷售額\n    ws.Range(\"F3\").Value = \"電子類銷售額(陣列公式)\"\n    ws.Range(\"G3\").FormulaArray = \"=SUM((D2:D6=\"\"電子\"\")*B2:B6*C2:C6)\"\n\n    ' 陣列公式：單價超過100的產品數\n    ws.Range(\"F4\").Value = \"單價>100的品項數\"\n    ws.Range(\"G4\").FormulaArray = \"=SUM((B2:B6>100)*1)\"\n\n    ' 陣列公式：最大銷售額\n    ws.Range(\"F5\").Value = \"最高單品銷售額\"\n    ws.Range(\"G5\").FormulaArray = \"=MAX(B2:B6*C2:C6)\"\n\n    ws.Columns(\"F:G\").AutoFit\nEnd Sub\n", "content_b64": ""}, {"name": "DashboardFormulaExample.bas", "path": "模組/FormulaCreate/DashboardFormulaExample.bas", "content": "Option Explicit\n\n' 建立常見儀表板公式範例，包含 SUMIFS、COUNTIFS、AVERAGEIFS 與 IFERROR。\nPublic Sub CreateDashboardFormulaExample()\n    On Error GoTo ErrHandler\n\n    Dim ws As Worksheet\n    Dim sheetName As String\n\n    sheetName = \"儀表板公式範例\"\n    Set ws = GetOrCreateFormulaWorksheet(sheetName)\n    ws.Cells.Clear\n\n    Call FillFormulaSourceData(ws)\n    Call FillFormulaSummaryArea(ws)\n    ws.Columns(\"A:H\").AutoFit\n\n    MsgBox \"儀表板公式已建立完成。\", vbInformation, \"完成\"\n    Exit Sub\n\nErrHandler:\n    MsgBox \"建立公式範例失敗：\" & Err.Description, vbExclamation, \"錯誤\"\nEnd Sub\n\nPrivate Sub FillFormulaSourceData(ByVal ws As Worksheet)\n    ws.Range(\"A1:E1\").Value = Array(\"日期\", \"區域\", \"產品\", \"數量\", \"金額\")\n    ws.Range(\"A2:E2\").Value = Array(DateSerial(2026, 1, 3), \"北區\", \"A\", 12, 3600)\n    ws.Range(\"A3:E3\").Value = Array(DateSerial(2026, 1, 6), \"中區\", \"B\", 8, 2800)\n    ws.Range(\"A4:E4\").Value = Array(DateSerial(2026, 1, 10), \"北區\", \"B\", 10, 3500)\n    ws.Range(\"A5:E5\").Value = Array(DateSerial(2026, 1, 18), \"南區\", \"A\", 15, 4500)\n    ws.Range(\"A6:E6\").Value = Array(DateSerial(2026, 2, 2), \"北區\", \"A\", 9, 2700)\n    ws.Range(\"A7:E7\").Value = Array(DateSerial(2026, 2, 9), \"中區\", \"A\", 11, 3300)\n    ws.Range(\"A8:E8\").Value = Array(DateSerial(2026, 2, 14), \"南區\", \"B\", 7, 2450)\n    ws.Range(\"A2:A8\").NumberFormat = \"yyyy/mm/dd\"\nEnd Sub\n\nPrivate Sub FillFormulaSummaryArea(ByVal ws As Worksheet)\n    ws.Range(\"G1:H1\").Value = Array(\"指標\", \"公式結果\")\n    ws.Range(\"G2\").Value = \"北區總金額\"\n    ws.Range(\"H2\").Formula = \"=SUMIFS(E:E,B:B,\"\"北區\"\")\"\n    ws.Range(\"G3\").Value = \"產品A筆數\"\n    ws.Range(\"H3\").Formula = \"=COUNTIFS(C:C,\"\"A\"\")\"\n    ws.Range(\"G4\").Value = \"中區平均金額\"\n    ws.Range(\"H4\").Formula = \"=IFERROR(AVERAGEIFS(E:E,B:B,\"\"中區\"\"),0)\"\n    ws.Range(\"G5\").Value = \"一月總金額\"\n    ws.Range(\"H5\").Formula = \"=SUMIFS(E:E,A:A,\"\">=\"\"&DATE(2026,1,1),A:A,\"\"<\"\"&DATE(2026,2,1))\"\n    ws.Range(\"H2:H5\").NumberFormat = \"#,##0\"\nEnd Sub\n\nPrivate Function GetOrCreateFormulaWorksheet(ByVal sheetName As String) As Worksheet\n    On Error Resume Next\n    Set GetOrCreateFormulaWorksheet = ThisWorkbook.Worksheets(sheetName)\n    On Error GoTo 0\n\n    If GetOrCreateFormulaWorksheet Is Nothing Then\n        Set GetOrCreateFormulaWorksheet = ThisWorkbook.Worksheets.Add\n        GetOrCreateFormulaWorksheet.Name = sheetName\n    End If\nEnd Function", "content_b64": ""}, {"name": "DatabaseFormulaExample.bas", "path": "模組/FormulaCreate/DatabaseFormulaExample.bas", "content": "Attribute VB_Name = \"DatabaseFormulaExample\"\n\nOption Explicit\n\n\n\n' ============================================================\n\n' 範例：使用 VBA 建立資料庫函數公式（DSUM / DAVERAGE / DCOUNT）\n\n' 功能：示範在工作表中插入資料庫函數以進行條件彙總\n\n' ============================================================\n\nSub CreateDatabaseFormulaExample()\n\n    Dim ws      As Worksheet\n\n    Dim i       As Integer\n\n    Dim arrData As Variant\n\n\n\n    On Error GoTo ErrHandler\n\n    Set ws = ThisWorkbook.Worksheets.Add\n\n    ws.Name = \"DBFormulaDemo\"\n\n\n\n    ' --- 建立資料庫標題列 ---\n\n    ws.Range(\"A1\").Value = \"部門\"\n\n    ws.Range(\"B1\").Value = \"員工\"\n\n    ws.Range(\"C1\").Value = \"薪資\"\n\n    ws.Range(\"D1\").Value = \"年資\"\n\n\n\n    ' --- 填入示範資料 ---\n\n    arrData = Array( _\n\n        Array(\"業務\", \"王小明\", 45000, 3), _\n\n        Array(\"業務\", \"林美華\", 42000, 2), _\n\n        Array(\"工程\", \"張大同\", 60000, 5), _\n\n        Array(\"工程\", \"陳雅婷\", 58000, 4), _\n\n        Array(\"人事\", \"劉建國\", 40000, 1))\n\n    For i = 0 To 4\n\n        ws.Cells(2 + i, 1).Value = arrData(i)(0)\n\n        ws.Cells(2 + i, 2).Value = arrData(i)(1)\n\n        ws.Cells(2 + i, 3).Value = arrData(i)(2)\n\n        ws.Cells(2 + i, 4).Value = arrData(i)(3)\n\n    Next i\n\n\n\n    ' --- 建立條件區域 ---\n\n    ws.Range(\"F1\").Value = \"部門\"\n\n    ws.Range(\"F2\").Value = \"業務\"\n\n\n\n    ' --- 插入資料庫函數 ---\n\n    ws.Range(\"H1\").Value = \"業務部薪資合計\"\n\n    ws.Range(\"H2\").Formula = \"=DSUM(A1:D6,\"\"薪資\"\",F1:F2)\"\n\n\n\n    ws.Range(\"H4\").Value = \"業務部平均薪資\"\n\n    ws.Range(\"H5\").Formula = \"=DAVERAGE(A1:D6,\"\"薪資\"\",F1:F2)\"\n\n\n\n    ws.Range(\"H7\").Value = \"業務部人數\"\n\n    ws.Range(\"H8\").Formula = \"=DCOUNT(A1:D6,\"\"薪資\"\",F1:F2)\"\n\n\n\n    ws.Columns.AutoFit\n\n    MsgBox \"資料庫函數公式已建立於工作表：\" & ws.Name, vbInformation\n\n    Exit Sub\n\n\n\nErrHandler:\n\n    MsgBox \"發生錯誤：\" & Err.Description, vbCritical\n\nEnd Sub\n\n", "content_b64": ""}, {"name": "DateFormulaExample.bas", "path": "模組/FormulaCreate/DateFormulaExample.bas", "content": "Attribute VB_Name = \"DateFormulaExample\"\n\nOption Explicit\n\n'*************************************************************************************\n\n'模組名稱: DateFormulaExample\n\n'功能描述: 在 Excel 中示範日期時間公式的使用範例\n\n'          包含 TODAY、NOW、YEAR、MONTH、DAY、DATEDIF、NETWORKDAYS 等公式\n\n'\n\n'版權所有: Dunk\n\n'程式設計: Dunk\n\n'撰寫日期: 2026/5/7\n\n'\n\n'*************************************************************************************\n\n\n\nSub TestDateFormula()\n\n    Call CreateDateFormulaExample(\"日期公式範例\")\n\nEnd Sub\n\n\n\nSub CreateDateFormulaExample(ByVal sheetName As String)\n\n    Dim ws As Worksheet\n\n    On Error Resume Next\n\n    Set ws = ThisWorkbook.Worksheets(sheetName)\n\n    On Error GoTo 0\n\n    If ws Is Nothing Then\n\n        Set ws = ThisWorkbook.Worksheets.Add\n\n        ws.Name = sheetName\n\n    End If\n\n    ws.Cells.Clear\n\n    ws.Range(\"A1\").Value = \"公式說明\"\n\n    ws.Range(\"B1\").Value = \"結果\"\n\n    ws.Range(\"A1:B1\").Font.Bold = True\n\n    ws.Range(\"A2\").Value = \"TODAY() 今天日期\"\n\n    ws.Range(\"B2\").Formula = \"=TODAY()\"\n\n    ws.Range(\"B2\").NumberFormat = \"yyyy/mm/dd\"\n\n    ws.Range(\"B2\").Interior.Color = RGB(198, 239, 206)\n\n    ws.Range(\"A3\").Value = \"NOW() 現在時間\"\n\n    ws.Range(\"B3\").Formula = \"=NOW()\"\n\n    ws.Range(\"B3\").NumberFormat = \"yyyy/mm/dd hh:mm:ss\"\n\n    ws.Range(\"B3\").Interior.Color = RGB(198, 239, 206)\n\n    ws.Range(\"A5\").Value = \"起始日期\"\n\n    ws.Range(\"B5\").Value = DateSerial(2020, 1, 15)\n\n    ws.Range(\"B5\").NumberFormat = \"yyyy/mm/dd\"\n\n    ws.Range(\"A6\").Value = \"YEAR(起始日期)\"\n\n    ws.Range(\"B6\").Formula = \"=YEAR(B5)\"\n\n    ws.Range(\"B6\").Interior.Color = RGB(255, 235, 156)\n\n    ws.Range(\"A7\").Value = \"MONTH(起始日期)\"\n\n    ws.Range(\"B7\").Formula = \"=MONTH(B5)\"\n\n    ws.Range(\"B7\").Interior.Color = RGB(255, 235, 156)\n\n    ws.Range(\"A8\").Value = \"DAY(起始日期)\"\n\n    ws.Range(\"B8\").Formula = \"=DAY(B5)\"\n\n    ws.Range(\"B8\").Interior.Color = RGB(255, 235, 156)\n\n    ws.Range(\"A9\").Value = \"WEEKDAY(起始日期)\"\n\n    ws.Range(\"B9\").Formula = \"=WEEKDAY(B5,2)\"\n\n    ws.Range(\"B9\").Interior.Color = RGB(255, 235, 156)\n\n    ws.Range(\"A11\").Value = \"結束日期\"\n\n    ws.Range(\"B11\").Value = DateSerial(2026, 5, 7)\n\n    ws.Range(\"B11\").NumberFormat = \"yyyy/mm/dd\"\n\n    ws.Range(\"A12\").Value = \"DATEDIF 年差\"\n\n    ws.Range(\"B12\").Formula = \"=DATEDIF(B5,B11,\"\"Y\"\")\"\n\n    ws.Range(\"B12\").Interior.Color = RGB(198, 239, 206)\n\n    ws.Range(\"A13\").Value = \"DATEDIF 月差\"\n\n    ws.Range(\"B13\").Formula = \"=DATEDIF(B5,B11,\"\"M\"\")\"\n\n    ws.Range(\"B13\").Interior.Color = RGB(198, 239, 206)\n\n    ws.Range(\"A14\").Value = \"DATEDIF 天差\"\n\n    ws.Range(\"B14\").Formula = \"=DATEDIF(B5,B11,\"\"D\"\")\"\n\n    ws.Range(\"B14\").Interior.Color = RGB(198, 239, 206)\n\n    ws.Range(\"A16\").Value = \"NETWORKDAYS 工作天數\"\n\n    ws.Range(\"B16\").Formula = \"=NETWORKDAYS(B5,B11)\"\n\n    ws.Range(\"B16\").Interior.Color = RGB(198, 239, 206)\n\n    ws.Range(\"A18\").Value = \"EOMONTH 當月最後一天\"\n\n    ws.Range(\"B18\").Formula = \"=EOMONTH(TODAY(),0)\"\n\n    ws.Range(\"B18\").NumberFormat = \"yyyy/mm/dd\"\n\n    ws.Range(\"B18\").Interior.Color = RGB(198, 239, 206)\n\n    ws.Columns(\"A:B\").AutoFit\n\n    MsgBox \"日期公式範例已建立完成！\", vbInformation, \"完成\"\n\nEnd Sub\n\n", "content_b64": ""}, {"name": "ErrorHandleFormulaExample.bas", "path": "模組/FormulaCreate/ErrorHandleFormulaExample.bas", "content": "Attribute VB_Name = \"ErrorHandleFormulaExample\"\n\nOption Explicit\n\n'*************************************************************************************\n\n'模組名稱: ErrorHandleFormulaExample\n\n'功能描述: 在 Excel 中示範錯誤處理公式的使用範例\n\n'          包含 IFERROR、ISERROR、ISBLANK、ISNA、ISNUMBER、ISTEXT 等公式\n\n'\n\n'版權所有: Dunk\n\n'程式設計: Dunk\n\n'撰寫日期: 2026/5/7\n\n'\n\n'*************************************************************************************\n\n\n\nSub TestErrorHandleFormula()\n\n    Call CreateErrorHandleFormulaExample(\"錯誤處理公式範例\")\n\nEnd Sub\n\n\n\nSub CreateErrorHandleFormulaExample(ByVal sheetName As String)\n\n    Dim ws As Worksheet\n\n    On Error Resume Next\n\n    Set ws = ThisWorkbook.Worksheets(sheetName)\n\n    On Error GoTo 0\n\n    If ws Is Nothing Then\n\n        Set ws = ThisWorkbook.Worksheets.Add\n\n        ws.Name = sheetName\n\n    End If\n\n    ws.Cells.Clear\n\n    ws.Range(\"A1\").Value = \"原始資料\"\n\n    ws.Range(\"B1\").Value = \"查閱對象\"\n\n    ws.Range(\"C1\").Value = \"IFERROR 保護\"\n\n    ws.Range(\"D1\").Value = \"ISERROR 偵測\"\n\n    ws.Range(\"E1\").Value = \"ISBLANK\"\n\n    ws.Range(\"F1\").Value = \"ISNUMBER\"\n\n    ws.Range(\"G1\").Value = \"ISTEXT\"\n\n    ws.Range(\"A1:G1\").Font.Bold = True\n\n    ws.Range(\"H1\").Value = \"查閱表\"\n\n    ws.Range(\"H2\").Value = \"A001\"\n\n    ws.Range(\"H3\").Value = \"A002\"\n\n    ws.Range(\"H4\").Value = \"A003\"\n\n    ws.Range(\"I1\").Value = \"名稱\"\n\n    ws.Range(\"I2\").Value = \"蘋果\"\n\n    ws.Range(\"I3\").Value = \"橘子\"\n\n    ws.Range(\"I4\").Value = \"葡萄\"\n\n    ws.Range(\"A2\").Value = 123\n\n    ws.Range(\"A3\").Value = \"文字\"\n\n    ws.Range(\"A4\").Value = \"\"\n\n    ws.Range(\"A5\").Value = 0\n\n    ws.Range(\"B2\").Value = \"A001\"\n\n    ws.Range(\"B3\").Value = \"A999\"\n\n    ws.Range(\"B4\").Value = \"A002\"\n\n    ws.Range(\"B5\").Value = \"A003\"\n\n    Dim i As Integer\n\n    For i = 2 To 5\n\n        ws.Cells(i, 3).Formula = \"=IFERROR(VLOOKUP(B\" & i & \",H$2:I$4,2,FALSE),\"\"查無資料\"\")\"\n\n        ws.Cells(i, 3).Interior.Color = RGB(198, 239, 206)\n\n        ws.Cells(i, 4).Formula = \"=ISERROR(VLOOKUP(B\" & i & \",H$2:I$4,2,FALSE))\"\n\n        ws.Cells(i, 4).Interior.Color = RGB(255, 235, 156)\n\n        ws.Cells(i, 5).Formula = \"=ISBLANK(A\" & i & \")\"\n\n        ws.Cells(i, 5).Interior.Color = RGB(255, 199, 206)\n\n        ws.Cells(i, 6).Formula = \"=ISNUMBER(A\" & i & \")\"\n\n        ws.Cells(i, 6).Interior.Color = RGB(255, 199, 206)\n\n        ws.Cells(i, 7).Formula = \"=ISTEXT(A\" & i & \")\"\n\n        ws.Cells(i, 7).Interior.Color = RGB(255, 199, 206)\n\n    Next i\n\n    ws.Range(\"A7\").Value = \"ISNA 示範:\"\n\n    ws.Range(\"B7\").Value = \"A999\"\n\n    ws.Range(\"C7\").Formula = \"=ISNA(VLOOKUP(B7,H$2:I$4,2,FALSE))\"\n\n    ws.Range(\"C7\").Interior.Color = RGB(198, 239, 206)\n\n    ws.Columns(\"A:I\").AutoFit\n\n    MsgBox \"錯誤處理公式範例已建立完成！\", vbInformation, \"完成\"\n\nEnd Sub\n\n", "content_b64": ""}, {"name": "FinanceFormulaExample.bas", "path": "模組/FormulaCreate/FinanceFormulaExample.bas", "content": "Attribute VB_Name = \"FinanceFormulaExample\"\n\nOption Explicit\n\n'*************************************************************************************\n\n'模組名稱: FinanceFormulaExample\n\n'功能描述: 在 Excel 中示範財務公式的使用範例\n\n'          包含 PMT、PV、FV、RATE、NPER、IRR、NPV 等公式\n\n'\n\n'版權所有: Dunk\n\n'程式設計: Dunk\n\n'撰寫日期: 2026/5/7\n\n'\n\n'*************************************************************************************\n\n\n\nSub TestFinanceFormula()\n\n    Call CreateFinanceFormulaExample(\"財務公式範例\")\n\nEnd Sub\n\n\n\nSub CreateFinanceFormulaExample(ByVal sheetName As String)\n\n    Dim ws As Worksheet\n\n    On Error Resume Next\n\n    Set ws = ThisWorkbook.Worksheets(sheetName)\n\n    On Error GoTo 0\n\n    If ws Is Nothing Then\n\n        Set ws = ThisWorkbook.Worksheets.Add\n\n        ws.Name = sheetName\n\n    End If\n\n    ws.Cells.Clear\n\n    ws.Range(\"A1\").Value = \"===== 貸款計算 (PMT) =====\"\n\n    ws.Range(\"A1\").Font.Bold = True\n\n    ws.Range(\"A2\").Value = \"貸款金額 (元)\"\n\n    ws.Range(\"B2\").Value = 1000000\n\n    ws.Range(\"A3\").Value = \"年利率\"\n\n    ws.Range(\"B3\").Value = 0.03\n\n    ws.Range(\"B3\").NumberFormat = \"0.00%\"\n\n    ws.Range(\"A4\").Value = \"還款期數 (月)\"\n\n    ws.Range(\"B4\").Value = 240\n\n    ws.Range(\"A5\").Value = \"每月還款金額\"\n\n    ws.Range(\"B5\").Formula = \"=PMT(B3/12,B4,-B2)\"\n\n    ws.Range(\"B5\").NumberFormat = \"#,##0.00\"\n\n    ws.Range(\"B5\").Interior.Color = RGB(198, 239, 206)\n\n    ws.Range(\"A7\").Value = \"===== 現值計算 (PV) =====\"\n\n    ws.Range(\"A7\").Font.Bold = True\n\n    ws.Range(\"A8\").Value = \"年利率\"\n\n    ws.Range(\"B8\").Value = 0.05\n\n    ws.Range(\"B8\").NumberFormat = \"0.00%\"\n\n    ws.Range(\"A9\").Value = \"期數\"\n\n    ws.Range(\"B9\").Value = 10\n\n    ws.Range(\"A10\").Value = \"每期現金流\"\n\n    ws.Range(\"B10\").Value = 50000\n\n    ws.Range(\"A11\").Value = \"現值\"\n\n    ws.Range(\"B11\").Formula = \"=PV(B8,B9,-B10)\"\n\n    ws.Range(\"B11\").NumberFormat = \"#,##0.00\"\n\n    ws.Range(\"B11\").Interior.Color = RGB(198, 239, 206)\n\n    ws.Range(\"A13\").Value = \"===== 終值計算 (FV) =====\"\n\n    ws.Range(\"A13\").Font.Bold = True\n\n    ws.Range(\"A14\").Value = \"年利率\"\n\n    ws.Range(\"B14\").Value = 0.04\n\n    ws.Range(\"B14\").NumberFormat = \"0.00%\"\n\n    ws.Range(\"A15\").Value = \"期數\"\n\n    ws.Range(\"B15\").Value = 12\n\n    ws.Range(\"A16\").Value = \"每期存入\"\n\n    ws.Range(\"B16\").Value = 10000\n\n    ws.Range(\"A17\").Value = \"終值\"\n\n    ws.Range(\"B17\").Formula = \"=FV(B14/12,B15,-B16)\"\n\n    ws.Range(\"B17\").NumberFormat = \"#,##0.00\"\n\n    ws.Range(\"B17\").Interior.Color = RGB(198, 239, 206)\n\n    ws.Range(\"A19\").Value = \"===== NPV 與 IRR =====\"\n\n    ws.Range(\"A19\").Font.Bold = True\n\n    ws.Range(\"A20\").Value = \"折現率\"\n\n    ws.Range(\"B20\").Value = 0.08\n\n    ws.Range(\"B20\").NumberFormat = \"0.00%\"\n\n    ws.Range(\"A21\").Value = \"初始投資\"\n\n    ws.Range(\"B21\").Value = -100000\n\n    ws.Range(\"A22\").Value = \"第1年現金流\"\n\n    ws.Range(\"B22\").Value = 30000\n\n    ws.Range(\"A23\").Value = \"第2年現金流\"\n\n    ws.Range(\"B23\").Value = 40000\n\n    ws.Range(\"A24\").Value = \"第3年現金流\"\n\n    ws.Range(\"B24\").Value = 50000\n\n    ws.Range(\"A25\").Value = \"第4年現金流\"\n\n    ws.Range(\"B25\").Value = 30000\n\n    ws.Range(\"A26\").Value = \"NPV 淨現值\"\n\n    ws.Range(\"B26\").Formula = \"=B21+NPV(B20,B22:B25)\"\n\n    ws.Range(\"B26\").NumberFormat = \"#,##0.00\"\n\n    ws.Range(\"B26\").Interior.Color = RGB(255, 235, 156)\n\n    ws.Range(\"A27\").Value = \"IRR 內部報酬率\"\n\n    ws.Range(\"B27\").Formula = \"=IRR(B21:B25)\"\n\n    ws.Range(\"B27\").NumberFormat = \"0.00%\"\n\n    ws.Range(\"B27\").Interior.Color = RGB(255, 235, 156)\n\n    ws.Columns(\"A:B\").AutoFit\n\n    MsgBox \"財務公式範例已建立完成！\", vbInformation, \"完成\"\n\nEnd Sub\n\n", "content_b64": ""}, {"name": "LogicFormulaExample.bas", "path": "模組/FormulaCreate/LogicFormulaExample.bas", "content": "Attribute VB_Name = \"LogicFormulaExample\"\n\nOption Explicit\n\n'*************************************************************************************\n\n'模組名稱: LogicFormulaExample\n\n'功能描述: 在 Excel 中示範邏輯判斷公式的使用範例\n\n'          包含 IF、AND、OR、NOT、IFS、SWITCH 等公式\n\n'\n\n'版權所有: Dunk\n\n'程式設計: Dunk\n\n'撰寫日期: 2026/5/7\n\n'\n\n'*************************************************************************************\n\n\n\nSub TestLogicFormula()\n\n    Call CreateLogicFormulaExample(\"邏輯公式範例\")\n\nEnd Sub\n\n\n\nSub CreateLogicFormulaExample(ByVal sheetName As String)\n\n    Dim ws As Worksheet\n\n    On Error Resume Next\n\n    Set ws = ThisWorkbook.Worksheets(sheetName)\n\n    On Error GoTo 0\n\n    If ws Is Nothing Then\n\n        Set ws = ThisWorkbook.Worksheets.Add\n\n        ws.Name = sheetName\n\n    End If\n\n    ws.Cells.Clear\n\n    ws.Range(\"A1\").Value = \"學生\"\n\n    ws.Range(\"B1\").Value = \"分數\"\n\n    ws.Range(\"C1\").Value = \"IF 及格判斷\"\n\n    ws.Range(\"D1\").Value = \"IFS 等第\"\n\n    ws.Range(\"E1\").Value = \"AND 條件\"\n\n    ws.Range(\"F1\").Value = \"OR 條件\"\n\n    ws.Range(\"A1:F1\").Font.Bold = True\n\n    Dim names(4) As String\n\n    Dim scores(4) As Integer\n\n    names(0) = \"張三\" : scores(0) = 92\n\n    names(1) = \"李四\" : scores(1) = 58\n\n    names(2) = \"王五\" : scores(2) = 75\n\n    names(3) = \"趙六\" : scores(3) = 45\n\n    names(4) = \"陳七\" : scores(4) = 88\n\n    Dim i As Integer\n\n    For i = 0 To 4\n\n        Dim r As Integer\n\n        r = i + 2\n\n        ws.Cells(r, 1).Value = names(i)\n\n        ws.Cells(r, 2).Value = scores(i)\n\n        ws.Cells(r, 3).Formula = \"=IF(B\" & r & \">=60,\"\"及格\"\",\"\"不及格\"\")\"\n\n        ws.Cells(r, 3).Interior.Color = RGB(198, 239, 206)\n\n        ws.Cells(r, 4).Formula = \"=IFS(B\" & r & \">=90,\"\"A\"\",B\" & r & \">=80,\"\"B\"\",B\" & r & \">=70,\"\"C\"\",B\" & r & \">=60,\"\"D\"\",TRUE,\"\"F\"\")\"\n\n        ws.Cells(r, 4).Interior.Color = RGB(255, 235, 156)\n\n        ws.Cells(r, 5).Formula = \"=AND(B\" & r & \">=60,B\" & r & \"<=90)\"\n\n        ws.Cells(r, 5).Interior.Color = RGB(255, 199, 206)\n\n        ws.Cells(r, 6).Formula = \"=OR(B\" & r & \"<60,B\" & r & \">=90)\"\n\n        ws.Cells(r, 6).Interior.Color = RGB(255, 199, 206)\n\n    Next i\n\n    ws.Range(\"A9\").Value = \"NOT 示範:\"\n\n    ws.Range(\"B9\").Value = True\n\n    ws.Range(\"C9\").Formula = \"=NOT(B9)\"\n\n    ws.Range(\"C9\").Interior.Color = RGB(198, 239, 206)\n\n    ws.Range(\"A11\").Value = \"SWITCH 示範:\"\n\n    ws.Range(\"B11\").Value = 2\n\n    ws.Range(\"C11\").Formula = \"=SWITCH(B11,1,\"\"一月\"\",2,\"\"二月\"\",3,\"\"三月\"\",\"\"其他\"\")\"\n\n    ws.Range(\"C11\").Interior.Color = RGB(198, 239, 206)\n\n    ws.Columns(\"A:F\").AutoFit\n\n    MsgBox \"邏輯公式範例已建立完成！\", vbInformation, \"完成\"\n\nEnd Sub\n\n", "content_b64": ""}, {"name": "LookupFormulaExample.bas", "path": "模組/FormulaCreate/LookupFormulaExample.bas", "content": "Attribute VB_Name = \"LookupFormulaExample\"\n\nOption Explicit\n\n'*************************************************************************************\n\n'模組名稱: LookupFormulaExample\n\n'功能描述: 在 Excel 中示範查閱參照公式的使用範例\n\n'          包含 VLOOKUP、HLOOKUP、INDEX、MATCH 等公式\n\n'\n\n'版權所有: Dunk\n\n'程式設計: Dunk\n\n'撰寫日期: 2026/5/7\n\n'\n\n'*************************************************************************************\n\n\n\nSub TestLookupFormula()\n\n    Call CreateLookupFormulaExample(\"查閱公式範例\")\n\nEnd Sub\n\n\n\nSub CreateLookupFormulaExample(ByVal sheetName As String)\n\n    Dim ws As Worksheet\n\n    On Error Resume Next\n\n    Set ws = ThisWorkbook.Worksheets(sheetName)\n\n    On Error GoTo 0\n\n    If ws Is Nothing Then\n\n        Set ws = ThisWorkbook.Worksheets.Add\n\n        ws.Name = sheetName\n\n    End If\n\n    ws.Cells.Clear\n\n    Call FillLookupData(ws)\n\n    ws.Range(\"F2\").Formula = \"=VLOOKUP(E2,A2:C11,2,FALSE)\"\n\n    ws.Range(\"F2\").Interior.Color = RGB(198, 239, 206)\n\n    ws.Range(\"G2\").Formula = \"=VLOOKUP(E2,A2:C11,3,FALSE)\"\n\n    ws.Range(\"G2\").Interior.Color = RGB(198, 239, 206)\n\n    ws.Range(\"F4\").Formula = \"=INDEX(C2:C11,MATCH(E4,B2:B11,0))\"\n\n    ws.Range(\"F4\").Interior.Color = RGB(255, 235, 156)\n\n    ws.Range(\"E1\").Value = \"查詢條件\"\n\n    ws.Range(\"E2\").Value = \"E003\"\n\n    ws.Range(\"E4\").Value = \"王五\"\n\n    ws.Range(\"F1\").Value = \"VLOOKUP 姓名\"\n\n    ws.Range(\"G1\").Value = \"VLOOKUP 薪資\"\n\n    ws.Range(\"F3\").Value = \"INDEX+MATCH 薪資\"\n\n    ws.Range(\"E1:G1\").Font.Bold = True\n\n    ws.Columns(\"A:G\").AutoFit\n\n    MsgBox \"查閱公式範例已建立完成！\", vbInformation, \"完成\"\n\nEnd Sub\n\n\n\nPrivate Sub FillLookupData(ByVal ws As Worksheet)\n\n    ws.Range(\"A1\").Value = \"員工編號\"\n\n    ws.Range(\"B1\").Value = \"姓名\"\n\n    ws.Range(\"C1\").Value = \"薪資\"\n\n    Dim data(9, 2) As Variant\n\n    data(0, 0) = \"E001\" : data(0, 1) = \"張三\" : data(0, 2) = 45000\n\n    data(1, 0) = \"E002\" : data(1, 1) = \"李四\" : data(1, 2) = 38000\n\n    data(2, 0) = \"E003\" : data(2, 1) = \"王五\" : data(2, 2) = 52000\n\n    data(3, 0) = \"E004\" : data(3, 1) = \"趙六\" : data(3, 2) = 41000\n\n    data(4, 0) = \"E005\" : data(4, 1) = \"陳七\" : data(4, 2) = 67000\n\n    data(5, 0) = \"E006\" : data(5, 1) = \"林八\" : data(5, 2) = 35000\n\n    data(6, 0) = \"E007\" : data(6, 1) = \"吳九\" : data(6, 2) = 48000\n\n    data(7, 0) = \"E008\" : data(7, 1) = \"黃十\" : data(7, 2) = 55000\n\n    data(8, 0) = \"E009\" : data(8, 1) = \"周一\" : data(8, 2) = 43000\n\n    data(9, 0) = \"E010\" : data(9, 1) = \"馮二\" : data(9, 2) = 60000\n\n    Dim i As Integer\n\n    For i = 0 To 9\n\n        ws.Cells(i + 2, 1).Value = data(i, 0)\n\n        ws.Cells(i + 2, 2).Value = data(i, 1)\n\n        ws.Cells(i + 2, 3).Value = data(i, 2)\n\n    Next i\n\n    ws.Range(\"A1:C1\").Font.Bold = True\n\nEnd Sub\n\n", "content_b64": ""}, {"name": "MathFormulaExample.bas", "path": "模組/FormulaCreate/MathFormulaExample.bas", "content": "Attribute VB_Name = \"MathFormulaExample\"\n\nOption Explicit\n\n'*************************************************************************************\n\n'模組名稱: MathFormulaExample\n\n'功能描述: 在 Excel 中示範數學運算公式的使用範例\n\n'          包含 ROUND、ROUNDUP、ROUNDDOWN、ABS、MOD、INT、CEILING、FLOOR、POWER、SQRT 等公式\n\n'\n\n'版權所有: Dunk\n\n'程式設計: Dunk\n\n'撰寫日期: 2026/5/7\n\n'\n\n'*************************************************************************************\n\n\n\nSub TestMathFormula()\n\n    Call CreateMathFormulaExample(\"數學公式範例\")\n\nEnd Sub\n\n\n\nSub CreateMathFormulaExample(ByVal sheetName As String)\n\n    Dim ws As Worksheet\n\n    On Error Resume Next\n\n    Set ws = ThisWorkbook.Worksheets(sheetName)\n\n    On Error GoTo 0\n\n    If ws Is Nothing Then\n\n        Set ws = ThisWorkbook.Worksheets.Add\n\n        ws.Name = sheetName\n\n    End If\n\n    ws.Cells.Clear\n\n    ws.Range(\"A1\").Value = \"公式說明\"\n\n    ws.Range(\"B1\").Value = \"輸入值\"\n\n    ws.Range(\"C1\").Value = \"結果\"\n\n    ws.Range(\"A1:C1\").Font.Bold = True\n\n    ws.Range(\"A2\").Value = \"ROUND(四捨五入到2位)\"\n\n    ws.Range(\"B2\").Value = 3.14159\n\n    ws.Range(\"C2\").Formula = \"=ROUND(B2,2)\"\n\n    ws.Range(\"C2\").Interior.Color = RGB(198, 239, 206)\n\n    ws.Range(\"A3\").Value = \"ROUNDUP(無條件進位到2位)\"\n\n    ws.Range(\"B3\").Value = 3.14159\n\n    ws.Range(\"C3\").Formula = \"=ROUNDUP(B3,2)\"\n\n    ws.Range(\"C3\").Interior.Color = RGB(198, 239, 206)\n\n    ws.Range(\"A4\").Value = \"ROUNDDOWN(無條件捨去到2位)\"\n\n    ws.Range(\"B4\").Value = 3.14159\n\n    ws.Range(\"C4\").Formula = \"=ROUNDDOWN(B4,2)\"\n\n    ws.Range(\"C4\").Interior.Color = RGB(198, 239, 206)\n\n    ws.Range(\"A5\").Value = \"ABS(絕對值)\"\n\n    ws.Range(\"B5\").Value = -25.8\n\n    ws.Range(\"C5\").Formula = \"=ABS(B5)\"\n\n    ws.Range(\"C5\").Interior.Color = RGB(255, 235, 156)\n\n    ws.Range(\"A6\").Value = \"MOD(餘數: 17除以5)\"\n\n    ws.Range(\"B6\").Value = 17\n\n    ws.Range(\"C6\").Formula = \"=MOD(B6,5)\"\n\n    ws.Range(\"C6\").Interior.Color = RGB(255, 235, 156)\n\n    ws.Range(\"A7\").Value = \"INT(取整數)\"\n\n    ws.Range(\"B7\").Value = 9.87\n\n    ws.Range(\"C7\").Formula = \"=INT(B7)\"\n\n    ws.Range(\"C7\").Interior.Color = RGB(255, 235, 156)\n\n    ws.Range(\"A8\").Value = \"CEILING(進位到5的倍數)\"\n\n    ws.Range(\"B8\").Value = 23\n\n    ws.Range(\"C8\").Formula = \"=CEILING(B8,5)\"\n\n    ws.Range(\"C8\").Interior.Color = RGB(255, 199, 206)\n\n    ws.Range(\"A9\").Value = \"FLOOR(捨去到5的倍數)\"\n\n    ws.Range(\"B9\").Value = 23\n\n    ws.Range(\"C9\").Formula = \"=FLOOR(B9,5)\"\n\n    ws.Range(\"C9\").Interior.Color = RGB(255, 199, 206)\n\n    ws.Range(\"A10\").Value = \"POWER(2的10次方)\"\n\n    ws.Range(\"B10\").Value = 2\n\n    ws.Range(\"C10\").Formula = \"=POWER(B10,10)\"\n\n    ws.Range(\"C10\").Interior.Color = RGB(198, 239, 206)\n\n    ws.Range(\"A11\").Value = \"SQRT(平方根)\"\n\n    ws.Range(\"B11\").Value = 144\n\n    ws.Range(\"C11\").Formula = \"=SQRT(B11)\"\n\n    ws.Range(\"C11\").Interior.Color = RGB(198, 239, 206)\n\n    ws.Range(\"A12\").Value = \"LOG(以10為底的對數)\"\n\n    ws.Range(\"B12\").Value = 1000\n\n    ws.Range(\"C12\").Formula = \"=LOG(B12,10)\"\n\n    ws.Range(\"C12\").Interior.Color = RGB(198, 239, 206)\n\n    ws.Range(\"A13\").Value = \"RAND(0~1隨機數)\"\n\n    ws.Range(\"C13\").Formula = \"=RAND()\"\n\n    ws.Range(\"C13\").Interior.Color = RGB(198, 239, 206)\n\n    ws.Columns(\"A:C\").AutoFit\n\n    MsgBox \"數學公式範例已建立完成！\", vbInformation, \"完成\"\n\nEnd Sub\n\n", "content_b64": ""}, {"name": "RankPercentFormulaExample.bas", "path": "模組/FormulaCreate/RankPercentFormulaExample.bas", "content": "Attribute VB_Name = \"RankPercentFormulaExample\"\n\nOption Explicit\n\n'*************************************************************************************\n\n'模組名稱: RankPercentFormulaExample\n\n'功能描述: 在 Excel 中示範排名與百分比公式的使用範例\n\n'          包含 RANK、PERCENTRANK、PERCENTILE、QUARTILE 等公式\n\n'\n\n'版權所有: Dunk\n\n'程式設計: Dunk\n\n'撰寫日期: 2026/5/7\n\n'\n\n'*************************************************************************************\n\n\n\nSub TestRankPercentFormula()\n\n    Call CreateRankPercentFormulaExample(\"排名百分比公式範例\")\n\nEnd Sub\n\n\n\nSub CreateRankPercentFormulaExample(ByVal sheetName As String)\n\n    Dim ws As Worksheet\n\n    On Error Resume Next\n\n    Set ws = ThisWorkbook.Worksheets(sheetName)\n\n    On Error GoTo 0\n\n    If ws Is Nothing Then\n\n        Set ws = ThisWorkbook.Worksheets.Add\n\n        ws.Name = sheetName\n\n    End If\n\n    ws.Cells.Clear\n\n    Call FillRankData(ws)\n\n    ws.Range(\"E1\").Value = \"公式說明\"\n\n    ws.Range(\"F1\").Value = \"結果\"\n\n    ws.Range(\"E1:F1\").Font.Bold = True\n\n    ws.Range(\"E2\").Value = \"PERCENTILE 第25百分位數\"\n\n    ws.Range(\"F2\").Formula = \"=PERCENTILE(C2:C11,0.25)\"\n\n    ws.Range(\"F2\").Interior.Color = RGB(198, 239, 206)\n\n    ws.Range(\"E3\").Value = \"PERCENTILE 第50百分位數\"\n\n    ws.Range(\"F3\").Formula = \"=PERCENTILE(C2:C11,0.5)\"\n\n    ws.Range(\"F3\").Interior.Color = RGB(198, 239, 206)\n\n    ws.Range(\"E4\").Value = \"PERCENTILE 第75百分位數\"\n\n    ws.Range(\"F4\").Formula = \"=PERCENTILE(C2:C11,0.75)\"\n\n    ws.Range(\"F4\").Interior.Color = RGB(198, 239, 206)\n\n    ws.Range(\"E5\").Value = \"QUARTILE 第1四分位\"\n\n    ws.Range(\"F5\").Formula = \"=QUARTILE(C2:C11,1)\"\n\n    ws.Range(\"F5\").Interior.Color = RGB(255, 235, 156)\n\n    ws.Range(\"E6\").Value = \"QUARTILE 第3四分位\"\n\n    ws.Range(\"F6\").Formula = \"=QUARTILE(C2:C11,3)\"\n\n    ws.Range(\"F6\").Interior.Color = RGB(255, 235, 156)\n\n    ws.Range(\"D1\").Value = \"排名(DESC)\"\n\n    ws.Range(\"D1\").Font.Bold = True\n\n    Dim i As Integer\n\n    For i = 2 To 11\n\n        ws.Cells(i, 4).Formula = \"=RANK(C\" & i & \",C$2:C$11,0)\"\n\n        ws.Cells(i, 4).Interior.Color = RGB(255, 199, 206)\n\n    Next i\n\n    ws.Range(\"E8\").Value = \"PERCENTRANK 陳七的百分排名\"\n\n    ws.Range(\"F8\").Formula = \"=PERCENTRANK(C2:C11,C6)\"\n\n    ws.Range(\"F8\").NumberFormat = \"0.00%\"\n\n    ws.Range(\"F8\").Interior.Color = RGB(198, 239, 206)\n\n    ws.Columns(\"A:F\").AutoFit\n\n    MsgBox \"排名百分比公式範例已建立完成！\", vbInformation, \"完成\"\n\nEnd Sub\n\n\n\nPrivate Sub FillRankData(ByVal ws As Worksheet)\n\n    ws.Range(\"A1\").Value = \"姓名\"\n\n    ws.Range(\"B1\").Value = \"部門\"\n\n    ws.Range(\"C1\").Value = \"業績\"\n\n    Dim data(9, 2) As Variant\n\n    data(0, 0) = \"張三\" : data(0, 1) = \"業務\" : data(0, 2) = 800\n\n    data(1, 0) = \"李四\" : data(1, 1) = \"行政\" : data(1, 2) = 300\n\n    data(2, 0) = \"王五\" : data(2, 1) = \"業務\" : data(2, 2) = 650\n\n    data(3, 0) = \"趙六\" : data(3, 1) = \"研發\" : data(3, 2) = 450\n\n    data(4, 0) = \"陳七\" : data(4, 1) = \"業務\" : data(4, 2) = 920\n\n    data(5, 0) = \"林八\" : data(5, 1) = \"行政\" : data(5, 2) = 280\n\n    data(6, 0) = \"吳九\" : data(6, 1) = \"研發\" : data(6, 2) = 510\n\n    data(7, 0) = \"黃十\" : data(7, 1) = \"業務\" : data(7, 2) = 380\n\n    data(8, 0) = \"周一\" : data(8, 1) = \"業務\" : data(8, 2) = 740\n\n    data(9, 0) = \"馮二\" : data(9, 1) = \"研發\" : data(9, 2) = 600\n\n    Dim i As Integer\n\n    For i = 0 To 9\n\n        ws.Cells(i + 2, 1).Value = data(i, 0)\n\n        ws.Cells(i + 2, 2).Value = data(i, 1)\n\n        ws.Cells(i + 2, 3).Value = data(i, 2)\n\n    Next i\n\n    ws.Range(\"A1:C1\").Font.Bold = True\n\nEnd Sub\n\n", "content_b64": ""}, {"name": "StatFormulaExample.bas", "path": "模組/FormulaCreate/StatFormulaExample.bas", "content": "Attribute VB_Name = \"StatFormulaExample\"\n\nOption Explicit\n\n'*************************************************************************************\n\n'模組名稱: StatFormulaExample\n\n'功能描述: 在 Excel 中示範統計公式的使用範例\n\n'          包含 AVERAGE、MAX、MIN、COUNT、COUNTIF、COUNTIFS、LARGE、SMALL、MEDIAN、STDEV 等公式\n\n'\n\n'版權所有: Dunk\n\n'程式設計: Dunk\n\n'撰寫日期: 2026/5/7\n\n'\n\n'*************************************************************************************\n\n\n\nSub TestStatFormula()\n\n    Call CreateStatFormulaExample(\"統計公式範例\")\n\nEnd Sub\n\n\n\nSub CreateStatFormulaExample(ByVal sheetName As String)\n\n    Dim ws As Worksheet\n\n    On Error Resume Next\n\n    Set ws = ThisWorkbook.Worksheets(sheetName)\n\n    On Error GoTo 0\n\n    If ws Is Nothing Then\n\n        Set ws = ThisWorkbook.Worksheets.Add\n\n        ws.Name = sheetName\n\n    End If\n\n    ws.Cells.Clear\n\n    Call FillStatData(ws)\n\n    ws.Range(\"E1\").Value = \"公式說明\"\n\n    ws.Range(\"F1\").Value = \"結果\"\n\n    ws.Range(\"E1:F1\").Font.Bold = True\n\n    ws.Range(\"E2\").Value = \"AVERAGE 平均\"\n\n    ws.Range(\"F2\").Formula = \"=AVERAGE(C2:C11)\"\n\n    ws.Range(\"F2\").Interior.Color = RGB(198, 239, 206)\n\n    ws.Range(\"E3\").Value = \"MAX 最大值\"\n\n    ws.Range(\"F3\").Formula = \"=MAX(C2:C11)\"\n\n    ws.Range(\"F3\").Interior.Color = RGB(198, 239, 206)\n\n    ws.Range(\"E4\").Value = \"MIN 最小值\"\n\n    ws.Range(\"F4\").Formula = \"=MIN(C2:C11)\"\n\n    ws.Range(\"F4\").Interior.Color = RGB(198, 239, 206)\n\n    ws.Range(\"E5\").Value = \"COUNT 數值計數\"\n\n    ws.Range(\"F5\").Formula = \"=COUNT(C2:C11)\"\n\n    ws.Range(\"F5\").Interior.Color = RGB(198, 239, 206)\n\n    ws.Range(\"E6\").Value = \"COUNTA 非空計數\"\n\n    ws.Range(\"F6\").Formula = \"=COUNTA(A2:A11)\"\n\n    ws.Range(\"F6\").Interior.Color = RGB(198, 239, 206)\n\n    ws.Range(\"E7\").Value = \"COUNTIF 業務部門人數\"\n\n    ws.Range(\"F7\").Formula = \"=COUNTIF(B2:B11,\"\"業務\"\")\"\n\n    ws.Range(\"F7\").Interior.Color = RGB(255, 235, 156)\n\n    ws.Range(\"E8\").Value = \"COUNTIFS 業務且>500\"\n\n    ws.Range(\"F8\").Formula = \"=COUNTIFS(B2:B11,\"\"業務\"\",C2:C11,\"\">500\"\")\"\n\n    ws.Range(\"F8\").Interior.Color = RGB(255, 235, 156)\n\n    ws.Range(\"E9\").Value = \"LARGE 第1大\"\n\n    ws.Range(\"F9\").Formula = \"=LARGE(C2:C11,1)\"\n\n    ws.Range(\"F9\").Interior.Color = RGB(255, 199, 206)\n\n    ws.Range(\"E10\").Value = \"SMALL 第1小\"\n\n    ws.Range(\"F10\").Formula = \"=SMALL(C2:C11,1)\"\n\n    ws.Range(\"F10\").Interior.Color = RGB(255, 199, 206)\n\n    ws.Range(\"E11\").Value = \"MEDIAN 中位數\"\n\n    ws.Range(\"F11\").Formula = \"=MEDIAN(C2:C11)\"\n\n    ws.Range(\"F11\").Interior.Color = RGB(198, 239, 206)\n\n    ws.Range(\"E12\").Value = \"STDEV 標準差\"\n\n    ws.Range(\"F12\").Formula = \"=STDEV(C2:C11)\"\n\n    ws.Range(\"F12\").Interior.Color = RGB(198, 239, 206)\n\n    ws.Columns(\"A:F\").AutoFit\n\n    MsgBox \"統計公式範例已建立完成！\", vbInformation, \"完成\"\n\nEnd Sub\n\n\n\nPrivate Sub FillStatData(ByVal ws As Worksheet)\n\n    ws.Range(\"A1\").Value = \"姓名\"\n\n    ws.Range(\"B1\").Value = \"部門\"\n\n    ws.Range(\"C1\").Value = \"業績\"\n\n    Dim data(9, 2) As Variant\n\n    data(0, 0) = \"張三\" : data(0, 1) = \"業務\" : data(0, 2) = 800\n\n    data(1, 0) = \"李四\" : data(1, 1) = \"行政\" : data(1, 2) = 300\n\n    data(2, 0) = \"王五\" : data(2, 1) = \"業務\" : data(2, 2) = 650\n\n    data(3, 0) = \"趙六\" : data(3, 1) = \"研發\" : data(3, 2) = 450\n\n    data(4, 0) = \"陳七\" : data(4, 1) = \"業務\" : data(4, 2) = 920\n\n    data(5, 0) = \"林八\" : data(5, 1) = \"行政\" : data(5, 2) = 280\n\n    data(6, 0) = \"吳九\" : data(6, 1) = \"研發\" : data(6, 2) = 510\n\n    data(7, 0) = \"黃十\" : data(7, 1) = \"業務\" : data(7, 2) = 380\n\n    data(8, 0) = \"周一\" : data(8, 1) = \"業務\" : data(8, 2) = 740\n\n    data(9, 0) = \"馮二\" : data(9, 1) = \"研發\" : data(9, 2) = 600\n\n    Dim i As Integer\n\n    For i = 0 To 9\n\n        ws.Cells(i + 2, 1).Value = data(i, 0)\n\n        ws.Cells(i + 2, 2).Value = data(i, 1)\n\n        ws.Cells(i + 2, 3).Value = data(i, 2)\n\n    Next i\n\n    ws.Range(\"A1:C1\").Font.Bold = True\n\nEnd Sub\n\n", "content_b64": ""}, {"name": "SumFormulaExample.bas", "path": "模組/FormulaCreate/SumFormulaExample.bas", "content": "Attribute VB_Name = \"SumFormulaExample\"\n\nOption Explicit\n\n'*************************************************************************************\n\n'模組名稱: SumFormulaExample\n\n'功能描述: 在 Excel 中示範加總相關公式的使用範例\n\n'          包含 SUM、SUMIF、SUMIFS 等公式\n\n'\n\n'版權所有: Dunk\n\n'程式設計: Dunk\n\n'撰寫日期: 2026/5/7\n\n'\n\n'*************************************************************************************\n\n\n\nSub TestSumFormula()\n\n    Call CreateSumFormulaExample(\"加總公式範例\")\n\nEnd Sub\n\n\n\nSub CreateSumFormulaExample(ByVal sheetName As String)\n\n    Dim ws As Worksheet\n\n    On Error Resume Next\n\n    Set ws = ThisWorkbook.Worksheets(sheetName)\n\n    On Error GoTo 0\n\n    If ws Is Nothing Then\n\n        Set ws = ThisWorkbook.Worksheets.Add\n\n        ws.Name = sheetName\n\n    End If\n\n    ws.Cells.Clear\n\n    Call FillSumData(ws)\n\n    ws.Range(\"D2\").Formula = \"=SUM(C2:C11)\"\n\n    ws.Range(\"D2\").Interior.Color = RGB(198, 239, 206)\n\n    ws.Range(\"D4\").Formula = \"=SUMIF(B2:B11,\"\"業務\"\",C2:C11)\"\n\n    ws.Range(\"D4\").Interior.Color = RGB(198, 239, 206)\n\n    ws.Range(\"D6\").Formula = \"=SUMIFS(C2:C11,B2:B11,\"\"業務\"\",C2:C11,\"\">500\"\")\"\n\n    ws.Range(\"D6\").Interior.Color = RGB(198, 239, 206)\n\n    ws.Range(\"E2\").Value = \"SUM 全部合計\"\n\n    ws.Range(\"E4\").Value = \"SUMIF 業務部門合計\"\n\n    ws.Range(\"E6\").Value = \"SUMIFS 業務部門且>500合計\"\n\n    ws.Columns(\"A:E\").AutoFit\n\n    MsgBox \"加總公式範例已建立完成！\", vbInformation, \"完成\"\n\nEnd Sub\n\n\n\nPrivate Sub FillSumData(ByVal ws As Worksheet)\n\n    ws.Range(\"A1\").Value = \"姓名\"\n\n    ws.Range(\"B1\").Value = \"部門\"\n\n    ws.Range(\"C1\").Value = \"銷售金額\"\n\n    Dim data(9, 2) As Variant\n\n    data(0, 0) = \"張三\" : data(0, 1) = \"業務\" : data(0, 2) = 800\n\n    data(1, 0) = \"李四\" : data(1, 1) = \"行政\" : data(1, 2) = 300\n\n    data(2, 0) = \"王五\" : data(2, 1) = \"業務\" : data(2, 2) = 650\n\n    data(3, 0) = \"趙六\" : data(3, 1) = \"研發\" : data(3, 2) = 450\n\n    data(4, 0) = \"陳七\" : data(4, 1) = \"業務\" : data(4, 2) = 920\n\n    data(5, 0) = \"林八\" : data(5, 1) = \"行政\" : data(5, 2) = 280\n\n    data(6, 0) = \"吳九\" : data(6, 1) = \"研發\" : data(6, 2) = 510\n\n    data(7, 0) = \"黃十\" : data(7, 1) = \"業務\" : data(7, 2) = 380\n\n    data(8, 0) = \"周一\" : data(8, 1) = \"業務\" : data(8, 2) = 740\n\n    data(9, 0) = \"馮二\" : data(9, 1) = \"研發\" : data(9, 2) = 600\n\n    Dim i As Integer\n\n    For i = 0 To 9\n\n        ws.Cells(i + 2, 1).Value = data(i, 0)\n\n        ws.Cells(i + 2, 2).Value = data(i, 1)\n\n        ws.Cells(i + 2, 3).Value = data(i, 2)\n\n    Next i\n\n    ws.Range(\"A1:C1\").Font.Bold = True\n\nEnd Sub\n\n", "content_b64": ""}, {"name": "TextFormulaExample.bas", "path": "模組/FormulaCreate/TextFormulaExample.bas", "content": "Attribute VB_Name = \"TextFormulaExample\"\n\nOption Explicit\n\n'*************************************************************************************\n\n'模組名稱: TextFormulaExample\n\n'功能描述: 在 Excel 中示範文字處理公式的使用範例\n\n'          包含 LEFT、RIGHT、MID、LEN、CONCATENATE、TRIM、TEXT 等公式\n\n'\n\n'版權所有: Dunk\n\n'程式設計: Dunk\n\n'撰寫日期: 2026/5/7\n\n'\n\n'*************************************************************************************\n\n\n\nSub TestTextFormula()\n\n    Call CreateTextFormulaExample(\"文字公式範例\")\n\nEnd Sub\n\n\n\nSub CreateTextFormulaExample(ByVal sheetName As String)\n\n    Dim ws As Worksheet\n\n    On Error Resume Next\n\n    Set ws = ThisWorkbook.Worksheets(sheetName)\n\n    On Error GoTo 0\n\n    If ws Is Nothing Then\n\n        Set ws = ThisWorkbook.Worksheets.Add\n\n        ws.Name = sheetName\n\n    End If\n\n    ws.Cells.Clear\n\n    ws.Range(\"A1\").Value = \"原始資料\"\n\n    ws.Range(\"B1\").Value = \"LEFT(3)\"\n\n    ws.Range(\"C1\").Value = \"RIGHT(3)\"\n\n    ws.Range(\"D1\").Value = \"MID(2,4)\"\n\n    ws.Range(\"E1\").Value = \"LEN\"\n\n    ws.Range(\"F1\").Value = \"UPPER\"\n\n    ws.Range(\"G1\").Value = \"LOWER\"\n\n    ws.Range(\"A1:G1\").Font.Bold = True\n\n    Dim samples(4) As String\n\n    samples(0) = \"Hello World\"\n\n    samples(1) = \"ExcelVBA\"\n\n    samples(2) = \"  TRIM TEST  \"\n\n    samples(3) = \"2026/05/07\"\n\n    samples(4) = \"OpenAI GPT\"\n\n    Dim i As Integer\n\n    For i = 0 To 4\n\n        Dim r As Integer\n\n        r = i + 2\n\n        ws.Cells(r, 1).Value = samples(i)\n\n        ws.Cells(r, 2).Formula = \"=LEFT(A\" & r & \",3)\"\n\n        ws.Cells(r, 3).Formula = \"=RIGHT(A\" & r & \",3)\"\n\n        ws.Cells(r, 4).Formula = \"=MID(A\" & r & \",2,4)\"\n\n        ws.Cells(r, 5).Formula = \"=LEN(A\" & r & \")\"\n\n        ws.Cells(r, 6).Formula = \"=UPPER(A\" & r & \")\"\n\n        ws.Cells(r, 7).Formula = \"=LOWER(A\" & r & \")\"\n\n    Next i\n\n    ws.Range(\"A9\").Value = \"TRIM 示範:\"\n\n    ws.Range(\"B9\").Value = \"  多餘空格  \"\n\n    ws.Range(\"C9\").Formula = \"=TRIM(B9)\"\n\n    ws.Range(\"C9\").Interior.Color = RGB(198, 239, 206)\n\n    ws.Range(\"A11\").Value = \"CONCATENATE 示範:\"\n\n    ws.Range(\"B11\").Value = \"Excel\"\n\n    ws.Range(\"C11\").Value = \"VBA\"\n\n    ws.Range(\"D11\").Formula = \"=CONCATENATE(B11,\"\"-\"\",C11)\"\n\n    ws.Range(\"D11\").Interior.Color = RGB(198, 239, 206)\n\n    ws.Range(\"A13\").Value = \"TEXT 示範:\"\n\n    ws.Range(\"B13\").Value = 45388\n\n    ws.Range(\"C13\").Formula = \"=TEXT(B13,\"\"yyyy/mm/dd\"\")\"\n\n    ws.Range(\"C13\").Interior.Color = RGB(198, 239, 206)\n\n    ws.Columns(\"A:G\").AutoFit\n\n    MsgBox \"文字公式範例已建立完成！\", vbInformation, \"完成\"\n\nEnd Sub\n\n", "content_b64": ""}]}, {"folder": "MergeDataAcrossSheets", "path": "模組/MergeDataAcrossSheets", "files": [{"name": "MergeBySheetNameList.bas", "path": "模組/MergeDataAcrossSheets/MergeBySheetNameList.bas", "content": "Attribute VB_Name = \"MergeBySheetNameList\"\nOption Explicit\n\n' ============================================================\n' 範例：依使用者在儲存格範圍中填入的工作表名稱清單來合併\n' 功能：讀取指定欄位的工作表名稱清單，依序合併對應工作表\n' 使用方式：在任一工作表的 A 欄列出要合併的工作表名稱後執行\n' ============================================================\nSub MergeBySheetNameList()\n    Dim wsConfig    As Worksheet\n    Dim ws          As Worksheet\n    Dim wsSummary   As Worksheet\n    Dim lngDestRow  As Long\n    Dim lngLastRow  As Long\n    Dim lngLastCol  As Long\n    Dim lngCopyStart As Long\n    Dim lngListRow  As Long\n    Dim lngListEnd  As Long\n    Dim blnFirst    As Boolean\n    Dim strSheetName As String\n    Dim strConfigSheet As String\n    Dim intCount    As Integer\n\n    On Error GoTo ErrHandler\n\n    strConfigSheet = InputBox(\"請輸入包含工作表名稱清單的工作表名稱：\", \"名稱清單合併\", ActiveSheet.Name)\n    If strConfigSheet = \"\" Then Exit Sub\n\n    On Error Resume Next\n    Set wsConfig = ThisWorkbook.Worksheets(strConfigSheet)\n    On Error GoTo ErrHandler\n    If wsConfig Is Nothing Then\n        MsgBox \"找不到工作表：\" & strConfigSheet, vbExclamation\n        Exit Sub\n    End If\n\n    lngListEnd = wsConfig.Cells(wsConfig.Rows.Count, 1).End(xlUp).Row\n    If lngListEnd < 1 Then\n        MsgBox \"A 欄未填入任何工作表名稱。\", vbExclamation\n        Exit Sub\n    End If\n\n    Set wsSummary = GetOrCreateSheet_List(ThisWorkbook, \"名稱清單合併\")\n    lngDestRow = 1\n    blnFirst = True\n    intCount = 0\n    Application.ScreenUpdating = False\n\n    For lngListRow = 1 To lngListEnd\n        strSheetName = Trim(CStr(wsConfig.Cells(lngListRow, 1).Value))\n        If strSheetName <> \"\" And strSheetName <> wsSummary.Name Then\n            Set ws = Nothing\n            On Error Resume Next\n            Set ws = ThisWorkbook.Worksheets(strSheetName)\n            On Error GoTo ErrHandler\n            If Not ws Is Nothing Then\n                lngLastRow = ws.Cells(ws.Rows.Count, 1).End(xlUp).Row\n                lngLastCol = ws.Cells(1, ws.Columns.Count).End(xlToLeft).Column\n                If lngLastRow >= 1 And lngLastCol >= 1 Then\n                    If blnFirst Then\n                        lngCopyStart = 1\n                        blnFirst = False\n                    Else\n                        lngCopyStart = 2  ' 略過標題列\n                    End If\n                    If lngLastRow >= lngCopyStart Then\n                        ws.Range(ws.Cells(lngCopyStart, 1), ws.Cells(lngLastRow, lngLastCol)).Copy _\n                            Destination:=wsSummary.Cells(lngDestRow, 1)\n                        lngDestRow = lngDestRow + (lngLastRow - lngCopyStart + 1)\n                        intCount = intCount + 1\n                    End If\n                End If\n            End If\n        End If\n    Next lngListRow\n\n    wsSummary.Columns.AutoFit\n    Application.ScreenUpdating = True\n\n    If blnFirst Then\n        MsgBox \"名稱清單中的工作表均無資料可合併。\", vbExclamation\n    Else\n        MsgBox \"名稱清單合併完成！共合併 \" & intCount & \" 個工作表。\", vbInformation\n    End If\n    Exit Sub\n\nErrHandler:\n    Application.ScreenUpdating = True\n    MsgBox \"發生錯誤：\" & Err.Description, vbCritical\nEnd Sub\n\nPrivate Function GetOrCreateSheet_List(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add(After:=wb.Sheets(wb.Sheets.Count))\n        ws.Name = sheetName\n    Else\n        ws.Cells.Clear\n    End If\n    Set GetOrCreateSheet_List = ws\nEnd Function\n", "content_b64": ""}, {"name": "MergeDeduplicatedRows.bas", "path": "模組/MergeDataAcrossSheets/MergeDeduplicatedRows.bas", "content": "Attribute VB_Name = \"MergeDeduplicatedRows\"\nOption Explicit\n\n' ============================================================\n' 範例：合併所有工作表後，依第一欄去除完全重複的列\n' 功能：使用 Collection 追蹤已出現的第一欄值，略過重複列\n' ============================================================\nSub MergeDeduplicatedRows()\n    Dim ws          As Worksheet\n    Dim wsSummary   As Worksheet\n    Dim lngDestRow  As Long\n    Dim lngLastRow  As Long\n    Dim lngLastCol  As Long\n    Dim lngRow      As Long\n    Dim blnFirst    As Boolean\n    Dim colKeys     As Collection\n    Dim strKey      As String\n    Dim blnDup      As Boolean\n\n    On Error GoTo ErrHandler\n\n    Set colKeys = New Collection\n    Set wsSummary = GetOrCreateSheet_Dedup(ThisWorkbook, \"去重複合併\")\n    lngDestRow = 1\n    blnFirst = True\n    Application.ScreenUpdating = False\n\n    For Each ws In ThisWorkbook.Worksheets\n        If ws.Name <> wsSummary.Name Then\n            lngLastRow = ws.Cells(ws.Rows.Count, 1).End(xlUp).Row\n            lngLastCol = ws.Cells(1, ws.Columns.Count).End(xlToLeft).Column\n            If lngLastRow >= 1 And lngLastCol >= 1 Then\n                If blnFirst Then\n                    ' 複製標題列（不去重）\n                    ws.Range(ws.Cells(1, 1), ws.Cells(1, lngLastCol)).Copy _\n                        Destination:=wsSummary.Cells(1, 1)\n                    lngDestRow = 2\n                    blnFirst = False\n                End If\n                For lngRow = 2 To lngLastRow\n                    strKey = CStr(ws.Cells(lngRow, 1).Value)\n                    blnDup = False\n                    On Error Resume Next\n                    colKeys.Add strKey, strKey\n                    If Err.Number <> 0 Then blnDup = True\n                    On Error GoTo ErrHandler\n                    If Not blnDup Then\n                        ws.Range(ws.Cells(lngRow, 1), ws.Cells(lngRow, lngLastCol)).Copy _\n                            Destination:=wsSummary.Cells(lngDestRow, 1)\n                        lngDestRow = lngDestRow + 1\n                    End If\n                Next lngRow\n            End If\n        End If\n    Next ws\n\n    wsSummary.Columns.AutoFit\n    Application.ScreenUpdating = True\n\n    If blnFirst Then\n        MsgBox \"所有工作表均無資料可合併。\", vbExclamation\n    Else\n        MsgBox \"去除重複合併完成！共寫入 \" & (lngDestRow - 2) & \" 筆不重複資料。\", vbInformation\n    End If\n    Exit Sub\n\nErrHandler:\n    Application.ScreenUpdating = True\n    MsgBox \"發生錯誤：\" & Err.Description, vbCritical\nEnd Sub\n\nPrivate Function GetOrCreateSheet_Dedup(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add(After:=wb.Sheets(wb.Sheets.Count))\n        ws.Name = sheetName\n    Else\n        ws.Cells.Clear\n    End If\n    Set GetOrCreateSheet_Dedup = ws\nEnd Function\n", "content_b64": ""}, {"name": "MergeFilteredRows.bas", "path": "模組/MergeDataAcrossSheets/MergeFilteredRows.bas", "content": "Attribute VB_Name = \"MergeFilteredRows\"\nOption Explicit\n\n' ============================================================\n' 範例：合併所有工作表中，指定欄位值大於門檻值的列\n' 功能：讓使用者輸入欄號與數值門檻，只複製符合條件的列\n' ============================================================\nSub MergeFilteredRows()\n    Dim ws          As Worksheet\n    Dim wsSummary   As Worksheet\n    Dim lngDestRow  As Long\n    Dim lngLastRow  As Long\n    Dim lngLastCol  As Long\n    Dim lngRow      As Long\n    Dim lngFilterCol As Long\n    Dim dblThreshold As Double\n    Dim blnFirst    As Boolean\n    Dim strInput    As String\n    Dim lngCount    As Long\n\n    On Error GoTo ErrHandler\n\n    strInput = InputBox(\"請輸入篩選欄號（例如：3 代表第 C 欄）：\", \"條件合併\", \"3\")\n    If strInput = \"\" Then Exit Sub\n    lngFilterCol = CLng(strInput)\n\n    strInput = InputBox(\"請輸入數值門檻（大於此值的列才合併）：\", \"條件合併\", \"0\")\n    If strInput = \"\" Then Exit Sub\n    dblThreshold = CDbl(strInput)\n\n    Set wsSummary = GetOrCreateSheet_Filter(ThisWorkbook, \"條件篩選合併\")\n    lngDestRow = 1\n    blnFirst = True\n    lngCount = 0\n    Application.ScreenUpdating = False\n\n    For Each ws In ThisWorkbook.Worksheets\n        If ws.Name <> wsSummary.Name Then\n            lngLastRow = ws.Cells(ws.Rows.Count, 1).End(xlUp).Row\n            lngLastCol = ws.Cells(1, ws.Columns.Count).End(xlToLeft).Column\n            If lngLastRow >= 2 And lngLastCol >= lngFilterCol Then\n                If blnFirst Then\n                    ws.Range(ws.Cells(1, 1), ws.Cells(1, lngLastCol)).Copy _\n                        Destination:=wsSummary.Cells(1, 1)\n                    lngDestRow = 2\n                    blnFirst = False\n                End If\n                For lngRow = 2 To lngLastRow\n                    If IsNumeric(ws.Cells(lngRow, lngFilterCol).Value) Then\n                        If CDbl(ws.Cells(lngRow, lngFilterCol).Value) > dblThreshold Then\n                            ws.Range(ws.Cells(lngRow, 1), ws.Cells(lngRow, lngLastCol)).Copy _\n                                Destination:=wsSummary.Cells(lngDestRow, 1)\n                            lngDestRow = lngDestRow + 1\n                            lngCount = lngCount + 1\n                        End If\n                    End If\n                Next lngRow\n            End If\n        End If\n    Next ws\n\n    wsSummary.Columns.AutoFit\n    Application.ScreenUpdating = True\n\n    If blnFirst Then\n        MsgBox \"找不到符合條件的資料。\", vbExclamation\n    Else\n        MsgBox \"條件篩選合併完成！共合併 \" & lngCount & \" 筆資料。\", vbInformation\n    End If\n    Exit Sub\n\nErrHandler:\n    Application.ScreenUpdating = True\n    MsgBox \"發生錯誤：\" & Err.Description, vbCritical\nEnd Sub\n\nPrivate Function GetOrCreateSheet_Filter(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add(After:=wb.Sheets(wb.Sheets.Count))\n        ws.Name = sheetName\n    Else\n        ws.Cells.Clear\n    End If\n    Set GetOrCreateSheet_Filter = ws\nEnd Function\n", "content_b64": ""}, {"name": "MergeFromExternalWorkbooks.bas", "path": "模組/MergeDataAcrossSheets/MergeFromExternalWorkbooks.bas", "content": "Attribute VB_Name = \"MergeFromExternalWorkbooks\"\nOption Explicit\n\n' ============================================================\n' 範例：從指定資料夾中所有 .xlsx/.xls 活頁簿合併第一張工作表\n' 功能：開啟每個活頁簿，複製第一張工作表資料，合併後關閉\n' ============================================================\nSub MergeFromExternalWorkbooks()\n    Dim strFolder   As String\n    Dim strFile     As String\n    Dim wbSrc       As Workbook\n    Dim wsSrc       As Worksheet\n    Dim wsSummary   As Worksheet\n    Dim lngDestRow  As Long\n    Dim lngLastRow  As Long\n    Dim lngLastCol  As Long\n    Dim lngCopyStart As Long\n    Dim blnFirst    As Boolean\n    Dim intCount    As Integer\n\n    On Error GoTo ErrHandler\n\n    ' 讓使用者選取資料夾\n    With Application.FileDialog(msoFileDialogFolderPicker)\n        .Title = \"請選取包含活頁簿的資料夾\"\n        If .Show <> -1 Then Exit Sub\n        strFolder = .SelectedItems(1)\n    End With\n\n    If Right(strFolder, 1) <> \"\" Then strFolder = strFolder & \"\"\n\n    Set wsSummary = GetOrCreateSheet_Ext(ThisWorkbook, \"外部活頁簿合併\")\n    lngDestRow = 1\n    blnFirst = True\n    intCount = 0\n    Application.ScreenUpdating = False\n    Application.DisplayAlerts = False\n\n    strFile = Dir(strFolder & \"*.xls*\")\n    Do While strFile <> \"\"\n        If strFolder & strFile <> ThisWorkbook.FullName Then\n            Set wbSrc = Workbooks.Open(strFolder & strFile, ReadOnly:=True)\n            Set wsSrc = wbSrc.Worksheets(1)\n            lngLastRow = wsSrc.Cells(wsSrc.Rows.Count, 1).End(xlUp).Row\n            lngLastCol = wsSrc.Cells(1, wsSrc.Columns.Count).End(xlToLeft).Column\n            If lngLastRow >= 1 And lngLastCol >= 1 Then\n                If blnFirst Then\n                    lngCopyStart = 1\n                    blnFirst = False\n                Else\n                    lngCopyStart = 2  ' 略過標題列\n                End If\n                If lngLastRow >= lngCopyStart Then\n                    wsSrc.Range(wsSrc.Cells(lngCopyStart, 1), wsSrc.Cells(lngLastRow, lngLastCol)).Copy _\n                        Destination:=wsSummary.Cells(lngDestRow, 1)\n                    lngDestRow = lngDestRow + (lngLastRow - lngCopyStart + 1)\n                    intCount = intCount + 1\n                End If\n            End If\n            wbSrc.Close SaveChanges:=False\n        End If\n        strFile = Dir\n    Loop\n\n    wsSummary.Columns.AutoFit\n    Application.DisplayAlerts = True\n    Application.ScreenUpdating = True\n\n    If intCount = 0 Then\n        MsgBox \"資料夾內找不到可合併的活頁簿。\", vbExclamation\n    Else\n        MsgBox \"已合併 \" & intCount & \" 個活頁簿的資料！\", vbInformation\n    End If\n    Exit Sub\n\nErrHandler:\n    Application.DisplayAlerts = True\n    Application.ScreenUpdating = True\n    MsgBox \"發生錯誤：\" & Err.Description, vbCritical\nEnd Sub\n\nPrivate Function GetOrCreateSheet_Ext(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add(After:=wb.Sheets(wb.Sheets.Count))\n        ws.Name = sheetName\n    Else\n        ws.Cells.Clear\n    End If\n    Set GetOrCreateSheet_Ext = ws\nEnd Function\n", "content_b64": ""}, {"name": "MergeGroupedByCategory.bas", "path": "模組/MergeDataAcrossSheets/MergeGroupedByCategory.bas", "content": "Attribute VB_Name = \"MergeGroupedByCategory\"\nOption Explicit\n\n' ============================================================\n' 範例：依指定欄位的分類值，將各工作表資料分組寫入不同工作表\n' 功能：每個分類值對應一張目標工作表，資料分流合併\n' ============================================================\nSub MergeGroupedByCategory()\n    Dim ws          As Worksheet\n    Dim wsTarget    As Worksheet\n    Dim lngCatCol   As Long\n    Dim lngLastRow  As Long\n    Dim lngLastCol  As Long\n    Dim lngRow      As Long\n    Dim strCat      As String\n    Dim strInput    As String\n    Dim colTargets  As Collection\n    Dim blnFirst    As Boolean\n    Dim lngDestRow  As Long\n    Dim strSummaryName As String\n    Dim strTargetName As String\n\n    On Error GoTo ErrHandler\n\n    strInput = InputBox(\"請輸入分類欄號（例如：1 代表第 A 欄）：\", \"分類合併\", \"1\")\n    If strInput = \"\" Then Exit Sub\n    lngCatCol = CLng(strInput)\n    If lngCatCol < 1 Then\n        MsgBox \"欄號無效，請輸入大於 0 的數值。\", vbExclamation\n        Exit Sub\n    End If\n\n    Set colTargets = New Collection\n    blnFirst = True\n    strSummaryName = \"分類合併_\"\n    Application.ScreenUpdating = False\n\n    For Each ws In ThisWorkbook.Worksheets\n        If Left(ws.Name, Len(strSummaryName)) <> strSummaryName Then\n            lngLastRow = ws.Cells(ws.Rows.Count, 1).End(xlUp).Row\n            lngLastCol = ws.Cells(1, ws.Columns.Count).End(xlToLeft).Column\n            If lngLastRow >= 2 And lngLastCol >= lngCatCol Then\n                For lngRow = 2 To lngLastRow\n                    strCat = Trim(CStr(ws.Cells(lngRow, lngCatCol).Value))\n                    If strCat <> \"\" Then\n                        strTargetName = Left(strSummaryName & strCat, 31)\n                        Set wsTarget = Nothing\n                        On Error Resume Next\n                        Set wsTarget = colTargets(strTargetName)\n                        On Error GoTo ErrHandler\n                        If wsTarget Is Nothing Then\n                            Set wsTarget = GetOrCreateSheet_Cat(ThisWorkbook, strTargetName)\n                            ' 寫入標題列\n                            ws.Range(ws.Cells(1, 1), ws.Cells(1, lngLastCol)).Copy _\n                                Destination:=wsTarget.Cells(1, 1)\n                            colTargets.Add wsTarget, strTargetName\n                        End If\n                        lngDestRow = wsTarget.Cells(wsTarget.Rows.Count, 1).End(xlUp).Row + 1\n                        ws.Range(ws.Cells(lngRow, 1), ws.Cells(lngRow, lngLastCol)).Copy _\n                            Destination:=wsTarget.Cells(lngDestRow, 1)\n                        blnFirst = False\n                    End If\n                Next lngRow\n            End If\n        End If\n    Next ws\n\n    Application.ScreenUpdating = True\n\n    If blnFirst Then\n        MsgBox \"找不到可分類合併的資料。\", vbExclamation\n    Else\n        MsgBox \"分類合併完成！各分類資料已分別寫入對應工作表。\", vbInformation\n    End If\n    Exit Sub\n\nErrHandler:\n    Application.ScreenUpdating = True\n    MsgBox \"發生錯誤：\" & Err.Description, vbCritical\nEnd Sub\n\nPrivate Function GetOrCreateSheet_Cat(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add(After:=wb.Sheets(wb.Sheets.Count))\n        ws.Name = sheetName\n    Else\n        ws.Cells.Clear\n    End If\n    Set GetOrCreateSheet_Cat = ws\nEnd Function\n", "content_b64": ""}, {"name": "MergeSelectedSheetsWithHeader.bas", "path": "模組/MergeDataAcrossSheets/MergeSelectedSheetsWithHeader.bas", "content": "Attribute VB_Name = \"MergeSelectedSheetsWithHeader\"\n\nOption Explicit\n\n\n\n' ============================================================\n\n' 範例：合併使用者選定的工作表資料至彙總表（自動處理標題列）\n\n' 功能：僅合併名稱符合前置字串的工作表，第一個工作表保留標題\n\n' ============================================================\n\nSub MergeSelectedSheetsWithHeader()\n\n    Dim ws          As Worksheet\n\n    Dim wsSummary   As Worksheet\n\n    Dim strPrefix   As String\n\n    Dim lngDestRow  As Long\n\n    Dim lngLastRow  As Long\n\n    Dim lngStart    As Long\n\n    Dim blnFirst    As Boolean\n\n\n\n    ' --- 詢問工作表名稱前置字串 ---\n\n    strPrefix = InputBox( _\n\n        \"請輸入要合併的工作表名稱前置字串\" & Chr(10) & _\n\n        \"（例如：輸入 \"\"月報\"\" 將合併所有以月報開頭的工作表）\", _\n\n        \"合併工作表\", \"Sheet\")\n\n\n\n    If strPrefix = \"\" Then\n\n        MsgBox \"未輸入前置字串，操作取消。\", vbInformation\n\n        Exit Sub\n\n    End If\n\n\n\n    On Error GoTo ErrHandler\n\n\n\n    ' --- 建立或清除彙總工作表 ---\n\n    On Error Resume Next\n\n    Set wsSummary = ThisWorkbook.Worksheets(\"合併彙總\")\n\n    On Error GoTo ErrHandler\n\n\n\n    If wsSummary Is Nothing Then\n\n        Set wsSummary = ThisWorkbook.Worksheets.Add( _\n\n            After:=ThisWorkbook.Sheets(ThisWorkbook.Sheets.Count))\n\n        wsSummary.Name = \"合併彙總\"\n\n    Else\n\n        wsSummary.Cells.Clear\n\n    End If\n\n\n\n    lngDestRow = 1\n\n    blnFirst = True\n\n    Application.ScreenUpdating = False\n\n\n\n    ' --- 依前置字串篩選並合併 ---\n\n    For Each ws In ThisWorkbook.Worksheets\n\n        If ws.Name <> wsSummary.Name Then\n\n            If Left(ws.Name, Len(strPrefix)) = strPrefix Then\n\n                lngLastRow = ws.Cells(ws.Rows.Count, 1).End(xlUp).Row\n\n                If lngLastRow >= 1 Then\n\n                    If blnFirst Then\n\n                        lngStart = 1\n\n                        blnFirst = False\n\n                    Else\n\n                        lngStart = 2  ' 跳過標題列\n\n                    End If\n\n                    ws.Rows(lngStart & \":\" & lngLastRow).Copy _\n\n                        Destination:=wsSummary.Cells(lngDestRow, 1)\n\n                    lngDestRow = lngDestRow + (lngLastRow - lngStart + 1)\n\n                End If\n\n            End If\n\n        End If\n\n    Next ws\n\n\n\n    wsSummary.Columns.AutoFit\n\n    Application.ScreenUpdating = True\n\n\n\n    If blnFirst Then\n\n        MsgBox \"找不到符合前置字串「\" & strPrefix & \"」的工作表。\", vbExclamation\n\n    Else\n\n        MsgBox \"合併完成！資料已寫入工作表：合併彙總\", vbInformation\n\n    End If\n\n    Exit Sub\n\n\n\nErrHandler:\n\n    Application.ScreenUpdating = True\n\n    MsgBox \"發生錯誤：\" & Err.Description, vbCritical\n\nEnd Sub\n\n", "content_b64": ""}, {"name": "MergeSheetsByIndexRange.bas", "path": "模組/MergeDataAcrossSheets/MergeSheetsByIndexRange.bas", "content": "Attribute VB_Name = \"MergeSheetsByIndexRange\"\nOption Explicit\n\n' ============================================================\n' 範例：依工作表索引範圍合併資料至摘要工作表\n' 功能：讓使用者輸入起始與結束索引，合併該範圍內的工作表\n' ============================================================\nSub MergeSheetsByIndexRange()\n    Dim lngStart     As Long\n    Dim lngEnd       As Long\n    Dim lngDestRow   As Long\n    Dim lngLastRow   As Long\n    Dim lngLastCol   As Long\n    Dim lngIdx       As Long\n    Dim lngCopyStart As Long\n    Dim blnFirst     As Boolean\n    Dim ws           As Worksheet\n    Dim wsSummary    As Worksheet\n    Dim strInput     As String\n\n    On Error GoTo ErrHandler\n\n    strInput = InputBox(\"請輸入起始工作表索引（最小值為 1）：\", \"合併工作表\", \"1\")\n    If strInput = \"\" Then Exit Sub\n    lngStart = CLng(strInput)\n\n    strInput = InputBox(\"請輸入結束工作表索引（最大值為 \" & ThisWorkbook.Sheets.Count & \"）：\", \"合併工作表\", CStr(ThisWorkbook.Sheets.Count))\n    If strInput = \"\" Then Exit Sub\n    lngEnd = CLng(strInput)\n\n    If lngStart < 1 Or lngEnd > ThisWorkbook.Sheets.Count Or lngStart > lngEnd Then\n        MsgBox \"索引範圍無效，請重新輸入。\", vbExclamation\n        Exit Sub\n    End If\n\n    Set wsSummary = GetOrCreateSheet_IdxRange(ThisWorkbook, \"索引範圍合併\")\n    lngDestRow = 1\n    blnFirst = True\n    Application.ScreenUpdating = False\n\n    For lngIdx = lngStart To lngEnd\n        Set ws = ThisWorkbook.Sheets(lngIdx)\n        If ws.Name <> wsSummary.Name Then\n            lngLastRow = ws.Cells(ws.Rows.Count, 1).End(xlUp).Row\n            lngLastCol = ws.Cells(1, ws.Columns.Count).End(xlToLeft).Column\n            If lngLastRow >= 1 And lngLastCol >= 1 Then\n                If blnFirst Then\n                    lngCopyStart = 1\n                    blnFirst = False\n                Else\n                    lngCopyStart = 2  ' 略過標題列\n                End If\n                If lngLastRow >= lngCopyStart Then\n                    ws.Range(ws.Cells(lngCopyStart, 1), ws.Cells(lngLastRow, lngLastCol)).Copy _\n                        Destination:=wsSummary.Cells(lngDestRow, 1)\n                    lngDestRow = lngDestRow + (lngLastRow - lngCopyStart + 1)\n                End If\n            End If\n        End If\n    Next lngIdx\n\n    wsSummary.Columns.AutoFit\n    Application.ScreenUpdating = True\n\n    If blnFirst Then\n        MsgBox \"指定索引範圍內無資料可合併。\", vbExclamation\n    Else\n        MsgBox \"索引範圍合併完成！資料已寫入工作表：索引範圍合併\", vbInformation\n    End If\n    Exit Sub\n\nErrHandler:\n    Application.ScreenUpdating = True\n    MsgBox \"發生錯誤：\" & Err.Description, vbCritical\nEnd Sub\n\nPrivate Function GetOrCreateSheet_IdxRange(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add(After:=wb.Sheets(wb.Sheets.Count))\n        ws.Name = sheetName\n    Else\n        ws.Cells.Clear\n    End If\n    Set GetOrCreateSheet_IdxRange = ws\nEnd Function\n", "content_b64": ""}, {"name": "MergeSheetsByKeyword.bas", "path": "模組/MergeDataAcrossSheets/MergeSheetsByKeyword.bas", "content": "Option Explicit\n\n' 合併工作表名稱包含指定關鍵字的資料，適合彙整分店或月份工作表。\nPublic Sub MergeSheetsByKeywordExample()\n    On Error GoTo ErrHandler\n\n    Dim keyword As String\n    Dim targetWs As Worksheet\n\n    keyword = CStr(Application.InputBox(\"請輸入工作表名稱關鍵字\", \"跨表合併\", \"分店\", Type:=2))\n    If Len(keyword) = 0 Then Exit Sub\n\n    Set targetWs = GetOrCreateMergeWorksheet(\"關鍵字合併結果\")\n    Call MergeSheetsByKeyword(keyword, targetWs)\n\n    MsgBox \"跨表合併完成。\", vbInformation, \"完成\"\n    Exit Sub\n\nErrHandler:\n    MsgBox \"跨表合併失敗：\" & Err.Description, vbExclamation, \"錯誤\"\nEnd Sub\n\nPrivate Sub MergeSheetsByKeyword(ByVal keyword As String, ByVal targetWs As Worksheet)\n    Dim ws As Worksheet\n    Dim lastRow As Long\n    Dim lastCol As Long\n    Dim targetRow As Long\n    Dim copyStartRow As Long\n\n    targetWs.Cells.Clear\n    targetRow = 1\n\n    For Each ws In ThisWorkbook.Worksheets\n        If ws.Name <> targetWs.Name And InStr(1, ws.Name, keyword, vbTextCompare) > 0 Then\n            lastRow = ws.Cells(ws.Rows.Count, 1).End(xlUp).Row\n            lastCol = ws.Cells(1, ws.Columns.Count).End(xlToLeft).Column\n            If lastRow > 0 And lastCol > 0 Then\n                If targetRow = 1 Then\n                    ws.Range(ws.Cells(1, 1), ws.Cells(1, lastCol)).Copy Destination:=targetWs.Cells(targetRow, 1)\n                    targetWs.Cells(targetRow, lastCol + 1).Value = \"來源工作表\"\n                    targetRow = targetRow + 1\n                    copyStartRow = 2\n                Else\n                    copyStartRow = 2\n                End If\n\n                If lastRow >= copyStartRow Then\n                    ws.Range(ws.Cells(copyStartRow, 1), ws.Cells(lastRow, lastCol)).Copy Destination:=targetWs.Cells(targetRow, 1)\n                    targetWs.Range(targetWs.Cells(targetRow, lastCol + 1), targetWs.Cells(targetRow + lastRow - copyStartRow, lastCol + 1)).Value = ws.Name\n                    targetRow = targetRow + lastRow - copyStartRow + 1\n                End If\n            End If\n        End If\n    Next ws\n\n    targetWs.Columns.AutoFit\nEnd Sub\n\nPrivate Function GetOrCreateMergeWorksheet(ByVal sheetName As String) As Worksheet\n    On Error Resume Next\n    Set GetOrCreateMergeWorksheet = ThisWorkbook.Worksheets(sheetName)\n    On Error GoTo 0\n\n    If GetOrCreateMergeWorksheet Is Nothing Then\n        Set GetOrCreateMergeWorksheet = ThisWorkbook.Worksheets.Add\n        GetOrCreateMergeWorksheet.Name = sheetName\n    End If\nEnd Function", "content_b64": ""}, {"name": "MergeSheetsByTabColor.bas", "path": "模組/MergeDataAcrossSheets/MergeSheetsByTabColor.bas", "content": "Attribute VB_Name = \"MergeSheetsByTabColor\"\nOption Explicit\n\n' ============================================================\n' 範例：合併與目前使用中工作表相同標籤顏色的工作表\n' 功能：偵測目前工作表的標籤顏色，合併相同顏色的工作表\n' 使用方式：先將要合併的工作表設定相同標籤顏色，再執行\n' ============================================================\nSub MergeSheetsByTabColor()\n    Dim wsActive    As Worksheet\n    Dim ws          As Worksheet\n    Dim wsSummary   As Worksheet\n    Dim lngColor    As Long\n    Dim lngDestRow  As Long\n    Dim lngLastRow  As Long\n    Dim lngLastCol  As Long\n    Dim lngCopyStart As Long\n    Dim blnFirst    As Boolean\n\n    On Error GoTo ErrHandler\n\n    Set wsActive = ActiveSheet\n    lngColor = wsActive.Tab.Color\n\n    If wsActive.Tab.ColorIndex = xlColorIndexNone Then\n        MsgBox \"目前工作表沒有設定標籤顏色，請先設定後再執行。\", vbExclamation\n        Exit Sub\n    End If\n\n    Set wsSummary = GetOrCreateSheet_TabColor(ThisWorkbook, \"標籤顏色合併\")\n    lngDestRow = 1\n    blnFirst = True\n    Application.ScreenUpdating = False\n\n    For Each ws In ThisWorkbook.Worksheets\n        If ws.Name <> wsSummary.Name Then\n            If ws.Tab.ColorIndex <> xlColorIndexNone Then\n                If ws.Tab.Color = lngColor Then\n                    lngLastRow = ws.Cells(ws.Rows.Count, 1).End(xlUp).Row\n                    lngLastCol = ws.Cells(1, ws.Columns.Count).End(xlToLeft).Column\n                    If lngLastRow >= 1 And lngLastCol >= 1 Then\n                        If blnFirst Then\n                            lngCopyStart = 1\n                            blnFirst = False\n                        Else\n                            lngCopyStart = 2  ' 略過標題列\n                        End If\n                        If lngLastRow >= lngCopyStart Then\n                            ws.Range(ws.Cells(lngCopyStart, 1), ws.Cells(lngLastRow, lngLastCol)).Copy _\n                                Destination:=wsSummary.Cells(lngDestRow, 1)\n                            lngDestRow = lngDestRow + (lngLastRow - lngCopyStart + 1)\n                        End If\n                    End If\n                End If\n            End If\n        End If\n    Next ws\n\n    wsSummary.Columns.AutoFit\n    Application.ScreenUpdating = True\n\n    If blnFirst Then\n        MsgBox \"找不到相同標籤顏色的工作表。\", vbExclamation\n    Else\n        MsgBox \"標籤顏色合併完成！資料已寫入工作表：標籤顏色合併\", vbInformation\n    End If\n    Exit Sub\n\nErrHandler:\n    Application.ScreenUpdating = True\n    MsgBox \"發生錯誤：\" & Err.Description, vbCritical\nEnd Sub\n\nPrivate Function GetOrCreateSheet_TabColor(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add(After:=wb.Sheets(wb.Sheets.Count))\n        ws.Name = sheetName\n    Else\n        ws.Cells.Clear\n    End If\n    Set GetOrCreateSheet_TabColor = ws\nEnd Function\n", "content_b64": ""}, {"name": "MergeSheetsHorizontally.bas", "path": "模組/MergeDataAcrossSheets/MergeSheetsHorizontally.bas", "content": "Attribute VB_Name = \"MergeSheetsHorizontally\"\nOption Explicit\n\n' ============================================================\n' 範例：橫向合併工作表（每張工作表的資料並排於同一列）\n' 功能：將各工作表資料由左至右依序貼至同一工作表，以欄分隔\n' 注意：各工作表列數可不同，以最多列者為準\n' ============================================================\nSub MergeSheetsHorizontally()\n    Dim ws          As Worksheet\n    Dim wsSummary   As Worksheet\n    Dim lngDestCol  As Long\n    Dim lngLastRow  As Long\n    Dim lngLastCol  As Long\n    Dim blnFirst    As Boolean\n\n    On Error GoTo ErrHandler\n\n    Set wsSummary = GetOrCreateSheet_Horiz(ThisWorkbook, \"橫向並排合併\")\n    lngDestCol = 1\n    blnFirst = True\n    Application.ScreenUpdating = False\n\n    For Each ws In ThisWorkbook.Worksheets\n        If ws.Name <> wsSummary.Name Then\n            lngLastRow = ws.Cells(ws.Rows.Count, 1).End(xlUp).Row\n            lngLastCol = ws.Cells(1, ws.Columns.Count).End(xlToLeft).Column\n            If lngLastRow >= 1 And lngLastCol >= 1 Then\n                ws.Range(ws.Cells(1, 1), ws.Cells(lngLastRow, lngLastCol)).Copy _\n                    Destination:=wsSummary.Cells(1, lngDestCol)\n                If blnFirst Then\n                    blnFirst = False\n                Else\n                    ' 插入空白分隔欄\n                    lngDestCol = lngDestCol\n                End If\n                lngDestCol = lngDestCol + lngLastCol + 1\n            End If\n        End If\n    Next ws\n\n    wsSummary.Columns.AutoFit\n    Application.ScreenUpdating = True\n\n    If blnFirst Then\n        MsgBox \"所有工作表均無資料可合併。\", vbExclamation\n    Else\n        MsgBox \"橫向並排合併完成！各工作表資料已由左至右排列。\", vbInformation\n    End If\n    Exit Sub\n\nErrHandler:\n    Application.ScreenUpdating = True\n    MsgBox \"發生錯誤：\" & Err.Description, vbCritical\nEnd Sub\n\nPrivate Function GetOrCreateSheet_Horiz(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add(After:=wb.Sheets(wb.Sheets.Count))\n        ws.Name = sheetName\n    Else\n        ws.Cells.Clear\n    End If\n    Set GetOrCreateSheet_Horiz = ws\nEnd Function\n", "content_b64": ""}, {"name": "MergeSheetsToSummary.bas", "path": "模組/MergeDataAcrossSheets/MergeSheetsToSummary.bas", "content": "Attribute VB_Name = \"MergeSheetsToSummary\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: MergeSheetsToSummary\n'功能說明: 將活頁簿內多個工作表的資料合併至一個彙總工作表\n'\n'著作權所有: Dunk\n'程式設計: Dunk\n'撰寫日期: 2026/5/7\n'\n'*************************************************************************************\n\n' 測試用入口（先建立範例工作表再合併）\nSub TestMergeSheetsToSummary()\n    Call CreateSampleSheets\n    Call MergeAllSheetsToSummary\nEnd Sub\n\n' 建立三個季度工作表作為範例來源\nPrivate Sub CreateSampleSheets()\n    Dim sheetNames(1 To 3) As String\n    Dim i As Integer\n    Dim ws As Worksheet\n\n    sheetNames(1) = \"第一季\"\n    sheetNames(2) = \"第二季\"\n    sheetNames(3) = \"第三季\"\n\n    For i = 1 To 3\n        Set ws = GetOrCreateSheet(ThisWorkbook, sheetNames(i))\n        Call FillQuarterData(ws, sheetNames(i))\n    Next i\nEnd Sub\n\n' 合併所有非彙總工作表到「合併彙總」工作表\nSub MergeAllSheetsToSummary()\n    Dim wsTarget As Worksheet\n    Dim ws As Worksheet\n    Dim lastRow As Long\n    Dim targetRow As Long\n    Dim colCount As Long\n    Dim isFirst As Boolean\n\n    Set wsTarget = GetOrCreateSheet(ThisWorkbook, \"合併彙總\")\n    targetRow = 1\n    isFirst = True\n\n    Application.ScreenUpdating = False\n\n    For Each ws In ThisWorkbook.Worksheets\n        If ws.Name <> \"合併彙總\" Then\n            lastRow = ws.Cells(ws.Rows.Count, 1).End(xlUp).Row\n            colCount = ws.Cells(1, ws.Columns.Count).End(xlToLeft).Column\n\n            If lastRow >= 1 Then\n                If isFirst Then\n                    ws.Range(ws.Cells(1, 1), ws.Cells(lastRow, colCount)).Copy _\n                        Destination:=wsTarget.Cells(targetRow, 1)\n                    targetRow = targetRow + lastRow\n                    isFirst = False\n                Else\n                    If lastRow >= 2 Then\n                        ws.Range(ws.Cells(2, 1), ws.Cells(lastRow, colCount)).Copy _\n                            Destination:=wsTarget.Cells(targetRow, 1)\n                        targetRow = targetRow + lastRow - 1\n                    End If\n                End If\n            End If\n        End If\n    Next ws\n\n    wsTarget.Columns.AutoFit\n    Application.ScreenUpdating = True\n    wsTarget.Activate\n    MsgBox \"跨工作表資料合併完成！\", vbInformation, \"完成\"\nEnd Sub\n\n' 填入季度銷售資料\nPrivate Sub FillQuarterData(ByVal ws As Worksheet, ByVal quarterName As String)\n    Dim startRow As Integer\n    startRow = 2\n\n    ws.Range(\"A1\").Value = \"季度\"\n    ws.Range(\"B1\").Value = \"產品\"\n    ws.Range(\"C1\").Value = \"銷售額\"\n\n    ws.Cells(startRow, 1).Value = quarterName\n    ws.Cells(startRow, 2).Value = \"產品A\"\n    ws.Cells(startRow, 3).Value = 35000\n\n    ws.Cells(startRow + 1, 1).Value = quarterName\n    ws.Cells(startRow + 1, 2).Value = \"產品B\"\n    ws.Cells(startRow + 1, 3).Value = 48000\n\n    ws.Cells(startRow + 2, 1).Value = quarterName\n    ws.Cells(startRow + 2, 2).Value = \"產品C\"\n    ws.Cells(startRow + 2, 3).Value = 27000\n\n    ws.Columns(\"A:C\").AutoFit\nEnd Sub\n\n' 取得或建立工作表，並清除內容\nPrivate Function GetOrCreateSheet(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add\n        ws.Name = sheetName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreateSheet = ws\nEnd Function\n", "content_b64": ""}, {"name": "MergeSortedResult.bas", "path": "模組/MergeDataAcrossSheets/MergeSortedResult.bas", "content": "Attribute VB_Name = \"MergeSortedResult\"\nOption Explicit\n\n' ============================================================\n' 範例：合併所有工作表後，依使用者指定的欄位遞增排序\n' 功能：完成合併後，對結果工作表執行 Sort 操作\n' ============================================================\nSub MergeSortedResult()\n    Dim ws          As Worksheet\n    Dim wsSummary   As Worksheet\n    Dim lngDestRow  As Long\n    Dim lngLastRow  As Long\n    Dim lngLastCol  As Long\n    Dim lngSortCol  As Long\n    Dim blnFirst    As Boolean\n    Dim strInput    As String\n    Dim rngData     As Range\n\n    On Error GoTo ErrHandler\n\n    strInput = InputBox(\"合併後依哪一欄排序？請輸入欄號（例如：1 代表第 A 欄）：\", \"排序合併\", \"1\")\n    If strInput = \"\" Then Exit Sub\n    lngSortCol = CLng(strInput)\n    If lngSortCol < 1 Then\n        MsgBox \"欄號無效，請輸入大於 0 的數值。\", vbExclamation\n        Exit Sub\n    End If\n\n    Set wsSummary = GetOrCreateSheet_Sort(ThisWorkbook, \"排序後合併\")\n    lngDestRow = 1\n    blnFirst = True\n    Application.ScreenUpdating = False\n\n    For Each ws In ThisWorkbook.Worksheets\n        If ws.Name <> wsSummary.Name Then\n            lngLastRow = ws.Cells(ws.Rows.Count, 1).End(xlUp).Row\n            lngLastCol = ws.Cells(1, ws.Columns.Count).End(xlToLeft).Column\n            If lngLastRow >= 1 And lngLastCol >= 1 Then\n                If blnFirst Then\n                    ws.Range(ws.Cells(1, 1), ws.Cells(lngLastRow, lngLastCol)).Copy _\n                        Destination:=wsSummary.Cells(lngDestRow, 1)\n                    lngDestRow = lngDestRow + lngLastRow\n                    blnFirst = False\n                Else\n                    If lngLastRow >= 2 Then\n                        ws.Range(ws.Cells(2, 1), ws.Cells(lngLastRow, lngLastCol)).Copy _\n                            Destination:=wsSummary.Cells(lngDestRow, 1)\n                        lngDestRow = lngDestRow + lngLastRow - 1\n                    End If\n                End If\n            End If\n        End If\n    Next ws\n\n    ' 對合併結果排序（保留標題列）\n    If lngDestRow > 2 Then\n        lngLastCol = wsSummary.Cells(1, wsSummary.Columns.Count).End(xlToLeft).Column\n        Set rngData = wsSummary.Range(wsSummary.Cells(1, 1), wsSummary.Cells(lngDestRow - 1, lngLastCol))\n        rngData.Sort Key1:=wsSummary.Cells(2, lngSortCol), _\n                      Order1:=xlAscending, _\n                      Header:=xlYes\n    End If\n\n    wsSummary.Columns.AutoFit\n    Application.ScreenUpdating = True\n\n    If blnFirst Then\n        MsgBox \"所有工作表均無資料可合併。\", vbExclamation\n    Else\n        MsgBox \"合併並排序完成！結果已依第 \" & lngSortCol & \" 欄遞增排序。\", vbInformation\n    End If\n    Exit Sub\n\nErrHandler:\n    Application.ScreenUpdating = True\n    MsgBox \"發生錯誤：\" & Err.Description, vbCritical\nEnd Sub\n\nPrivate Function GetOrCreateSheet_Sort(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add(After:=wb.Sheets(wb.Sheets.Count))\n        ws.Name = sheetName\n    Else\n        ws.Cells.Clear\n    End If\n    Set GetOrCreateSheet_Sort = ws\nEnd Function\n", "content_b64": ""}, {"name": "MergeWithTimestamp.bas", "path": "模組/MergeDataAcrossSheets/MergeWithTimestamp.bas", "content": "Attribute VB_Name = \"MergeWithTimestamp\"\nOption Explicit\n\n' ============================================================\n' 範例：合併所有工作表並在每列新增來源工作表名稱與合併時間\n' 功能：每列資料附加「來源工作表」與「合併時間」兩個欄位\n' ============================================================\nSub MergeWithTimestamp()\n    Dim ws          As Worksheet\n    Dim wsSummary   As Worksheet\n    Dim lngDestRow  As Long\n    Dim lngLastRow  As Long\n    Dim lngLastCol  As Long\n    Dim lngRow      As Long\n    Dim lngHeaderCol As Long\n    Dim blnFirst    As Boolean\n    Dim dtMerge     As Date\n\n    On Error GoTo ErrHandler\n\n    dtMerge = Now\n    Set wsSummary = GetOrCreateSheet_TS(ThisWorkbook, \"時間戳記合併\")\n    lngDestRow = 1\n    blnFirst = True\n    Application.ScreenUpdating = False\n\n    For Each ws In ThisWorkbook.Worksheets\n        If ws.Name <> wsSummary.Name Then\n            lngLastRow = ws.Cells(ws.Rows.Count, 1).End(xlUp).Row\n            lngLastCol = ws.Cells(1, ws.Columns.Count).End(xlToLeft).Column\n            If lngLastRow >= 1 And lngLastCol >= 1 Then\n                If blnFirst Then\n                    ' 複製標題列並加入兩個附加欄標題\n                    ws.Range(ws.Cells(1, 1), ws.Cells(1, lngLastCol)).Copy _\n                        Destination:=wsSummary.Cells(1, 1)\n                    lngHeaderCol = lngLastCol + 1\n                    wsSummary.Cells(1, lngHeaderCol).Value = \"來源工作表\"\n                    wsSummary.Cells(1, lngHeaderCol + 1).Value = \"合併時間\"\n                    lngDestRow = 2\n                    blnFirst = False\n                End If\n                If lngLastRow >= 2 Then\n                    ws.Range(ws.Cells(2, 1), ws.Cells(lngLastRow, lngLastCol)).Copy _\n                        Destination:=wsSummary.Cells(lngDestRow, 1)\n                    For lngRow = lngDestRow To lngDestRow + lngLastRow - 2\n                        wsSummary.Cells(lngRow, lngLastCol + 1).Value = ws.Name\n                        wsSummary.Cells(lngRow, lngLastCol + 2).Value = dtMerge\n                    Next lngRow\n                    lngDestRow = lngDestRow + lngLastRow - 1\n                End If\n            End If\n        End If\n    Next ws\n\n    wsSummary.Columns.AutoFit\n    Application.ScreenUpdating = True\n\n    If blnFirst Then\n        MsgBox \"所有工作表均無資料可合併。\", vbExclamation\n    Else\n        MsgBox \"時間戳記合併完成！合併時間：\" & Format(dtMerge, \"yyyy/mm/dd hh:mm:ss\"), vbInformation\n    End If\n    Exit Sub\n\nErrHandler:\n    Application.ScreenUpdating = True\n    MsgBox \"發生錯誤：\" & Err.Description, vbCritical\nEnd Sub\n\nPrivate Function GetOrCreateSheet_TS(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add(After:=wb.Sheets(wb.Sheets.Count))\n        ws.Name = sheetName\n    Else\n        ws.Cells.Clear\n    End If\n    Set GetOrCreateSheet_TS = ws\nEnd Function\n", "content_b64": ""}]}, {"folder": "Others", "path": "模組/Others", "files": [{"name": "ADQuery.bas", "path": "模組/Others/ADQuery.bas", "content": "Attribute VB_Name = \"ADQuery\"\nOption Explicit\n'*************************************************************************************\n'專案名稱: AD帳號查詢\n'功能描述: 查詢海外分行LOCALHIRE及台幹的帳號及email\n'\n'版權所有: Dunk\n'程式撰寫: Dunk\n'撰寫日期：2016/11/11\n'\n'改版日期:\n'改版備註:\n'*************************************************************************************\n\nPublic Function StartQueryUsers()\n    '選取的分行代號\n    Dim branch As Variant\n    Dim departId As String\n    Dim departName As String\n    branch = VBA.Split(ThisWorkbook.Sheets(\"查詢功能頁面\").Range(\"B2\"), \"_\")\n    If UBound(branch) < 1 Then\n        MsgBox \"請重新選擇分行\"\n    End If\n    \n    departId = branch(1)\n    departName = branch(0)\n        \n    Application.ScreenUpdating = False\n    ThisWorkbook.Sheets(\"查詢功能頁面\").Range(\"E:K\").ClearContents\n    \n    '設定表頭\n    Dim currCell As Range\n    Set currCell = ThisWorkbook.Sheets(\"查詢功能頁面\").Range(\"E1\")\n    currCell.Value = \"分行名稱\"\n    currCell.Next.Value = \"分行代號\"\n    currCell.Next.Next.Value = \"TCB帳號\"\n    currCell.Next.Next.Next.Value = \"description\"\n    currCell.Next.Next.Next.Next.Value = \"displayName\"\n    currCell.Next.Next.Next.Next.Next.Value = \"mail\"\n    currCell.Next.Next.Next.Next.Next.Next.Value = \"是否為LOCALHIRE\"\n    \n    GetUserInfoLocal departId:=departId, departName:=departName\n    ThisWorkbook.Sheets(\"查詢功能頁面\").Columns(\"E:K\").AutoFit\n    \n    Application.ScreenUpdating = True\n    MsgBox \"查詢完畢\"\nEnd Function\n\n'查詢localhire\nPublic Function GetUserInfoLocal(ByVal departId As String, ByVal departName As String)\n       On Error Resume Next\n       \n\n       Const ADS_SCOPE_SUBTREE = 2\n       Dim objConnection As Variant\n       Dim objCommand As Variant\n       Dim objRecordSet As Variant\n       Dim ldapString As String\n       \n       ldapString = \"LDAP://OU=\" & departId & \",OU=LOCALHIRE,DC=tcb,DC=com\"\n       'ldapString = \"LDAP://OU=A01447,OU=LOCALHIRE,DC=tcb,DC=com\"\n       Set objConnection = CreateObject(\"ADODB.Connection\")\n       Set objCommand = CreateObject(\"ADODB.Command\")\n       objConnection.Provider = \"ADsDSOObject\"\n       objConnection.Open \"Active Directory Provider\"\n       Set objCommand.ActiveConnection = objConnection\n\n       objCommand.Properties(\"Page Size\") = 1000\n       objCommand.Properties(\"Searchscope\") = ADS_SCOPE_SUBTREE\n       \n       'search all users from the domn XXX\n       objCommand.CommandText = _\n               \"SELECT ou,description,department,name,displayName,mail FROM '\" & ldapString & \"' WHERE objectCategory='user'\"\n       Set objRecordSet = objCommand.Execute\n       \n       objRecordSet.MoveFirst\n\n       Dim currCell As Range\n       Set currCell = ThisWorkbook.Sheets(\"查詢功能頁面\").Range(\"E2\")\n\n       Do Until objRecordSet.EOF\n               currCell.Value = departId\n               \n               currCell.Next.Value = departName\n               currCell.Next.Next.NumberFormatLocal = \"@\"\n               currCell.Next.Next.Value = objRecordSet.Fields(\"name\").Value\n               currCell.Next.Next.Next.Value = objRecordSet.Fields(\"description\").Value\n               currCell.Next.Next.Next.Next.Value = objRecordSet.Fields(\"displayName\").Value\n               currCell.Next.Next.Next.Next.Next.Value = objRecordSet.Fields(\"mail\").Value\n               currCell.Next.Next.Next.Next.Next.Next.Value = \"Y\"\n               \n               Set currCell = currCell.Offset(1, 0)\n               objRecordSet.MoveNext\n       Loop\nEnd Function\n\n", "content_b64": ""}, {"name": "CellFunction.bas", "path": "模組/Others/CellFunction.bas", "content": "Attribute VB_Name = \"CellFunction\"\nOption Explicit\n'選取表格\nSub SelectAllTable()\n    ActiveCell.CurrentRegion.Select\nEnd Sub\n'取得最後一列的長度(row length)\nFunction NotSpaceRow(ByVal columnName As String)\n    Dim columnindex As String\n    '舊版excel最多65535\n    columnindex = columnName & \"65536\"\n    Dim myRange As Range\n    Set myRange = ThisWorkbook.Sheets(1).Range(columnindex).End(xlUp)\n    myRange.Select\n    NotSpaceRow = myRange.Row\n    Set myRange = Nothing\nEnd Function\n'取得最後一列的長度(row length)\nFunction NotSpaceRowBySheetName(ByVal columnName As String, ByVal sheetName As String)\n    Dim columnindex As String\n    '舊版excel最多65535\n    columnindex = columnName & \"65536\"\n    Dim myRange As Range\n    Set myRange = ThisWorkbook.Sheets(sheetName).Range(columnindex).End(xlUp)\n    myRange.Select\n    NotSpaceRowBySheetName = myRange.Row\n    Set myRange = Nothing\nEnd Function\n'取得最後一欄的長度(column length)\nFunction NotSpaceColumns(ByVal rowIndex As Integer)\n    Dim selectedRow As String\n    selectedRow = \"IV\" & rowIndex\n    Dim myRange As Range\n    Set myRange = ThisWorkbook.Sheets(1).Range(selectedRow).End(xlToLeft)\n    myRange.Select\n    NotSpaceColumns = myRange.Column\n    Set myRange = Nothing\nEnd Function\nFunction NotSpaceColumnsBySheetNam(ByVal rowIndex As Integer, ByVal sheetName As String)\n    Dim selectedRow As String\n    selectedRow = \"IV\" & rowIndex\n    Dim myRange As Range\n    Set myRange = ThisWorkbook.Sheets(sheetName).Range(selectedRow).End(xlToLeft)\n    myRange.Select\n    NotSpaceColumnsBySheetNam = myRange.Column\n    Set myRange = Nothing\nEnd Function\n", "content_b64": ""}, {"name": "CheckFormat.bas", "path": "模組/Others/CheckFormat.bas", "content": "Attribute VB_Name = \"CheckFormat\"\n\nOption Explicit\n\n''格式檢查模組\n\n''作者：Guan Jhih Liao\n\n\n\n'計算身分證字號檢查碼\n\n'傳回 檢查碼 檢查碼錯誤\n\n'       0  檢查碼正確\n\n'      -1  身份證檢查錯誤\n\n'      -2  檢查值不為身份證(為中文,輸入字串長度不足,第一字母不為英文字母,\n\n'                           其餘的不為數字)\n\nPublic Function ChkPID(ByVal PID As String) As Integer\n\n   Dim XX(1 To 26)   As Integer\n\n   Dim i             As Integer\n\n   Dim cc            As String\n\n   Dim First_no      As Integer\n\n   Dim X1            As Integer\n\n   Dim X2            As Integer\n\n   Dim d(1 To 9)     As Integer\n\n   Dim yy            As Integer\n\n     \n\n     XX(1) = 10: XX(2) = 11: XX(3) = 12: XX(4) = 13: XX(5) = 14: XX(6) = 15: XX(7) = 16\n\n     XX(8) = 17: XX(9) = 34: XX(10) = 18: XX(11) = 19: XX(12) = 20: XX(13) = 21: XX(14) = 22\n\n     XX(15) = 35: XX(16) = 23: XX(17) = 24: XX(18) = 25: XX(19) = 26: XX(20) = 27: XX(21) = 28\n\n     XX(22) = 29: XX(23) = 32: XX(24) = 30: XX(25) = 31: XX(26) = 33\n\n     \n\n     ChkPID = 0\n\n     \n\n     PID = Trim(PID)\n\n     \n\n     If PID = \"\" Then\n\n        ChkPID = -2\n\n        Exit Function\n\n     End If\n\n     \n\n     '檢查輸入字串是否為中文\n\n     If AscB(PID) > 128 Then\n\n        ChkPID = -2\n\n        Exit Function\n\n     End If\n\n     \n\n     '檢查輸入字串是否長度為零\n\n     If Len(PID) = 0 Or Len(PID) <> 10 Then\n\n        ChkPID = -2\n\n        Exit Function\n\n     End If\n\n         \n\n     PID = UCase(PID)  '英文為轉成大寫\n\n     \n\n     '檢查第一個字母是否為英文\n\n     cc = Left(PID, 1)\n\n     If Asc(cc) > 64 And Asc(cc) < 91 Then\n\n     Else\n\n        ChkPID = -2\n\n        Exit Function\n\n     End If\n\n     \n\n     '檢查第二個字母是否為英文\n\n     cc = Mid(PID, 2, 1)\n\n     If Asc(cc) > 64 And Asc(cc) < 91 Then\n\n       '檢查其餘八位全為數字\n\n        cc = Right(PID, 8)\n\n        If IsNumeric(cc) = False Then\n\n           ChkPID = -2\n\n           Exit Function\n\n        End If\n\n        d(1) = XX(Asc(Mid(PID, 2, 1)) - 64) Mod 10\n\n     Else\n\n        '檢查其餘九位全為數字\n\n        cc = Right(PID, 9)\n\n        If IsNumeric(cc) = False Then\n\n           ChkPID = -2\n\n           Exit Function\n\n        End If\n\n        \n\n        '檢查第二個字元, 代表性別\n\n        cc = Mid(PID, 2, 1)\n\n        If cc = \"1\" Or cc = \"2\" Then\n\n        Else\n\n           ChkPID = -1\n\n           Exit Function\n\n        End If\n\n        d(1) = Mid(PID, 2, 1)\n\n     End If\n\n     \n\n     First_no = XX(Asc(Left(PID, 1)) - 64)\n\n     X1 = First_no \\ 10\n\n     X2 = First_no Mod 10\n\n     \n\n     For i = 2 To 9\n\n        cc = Mid(PID, i + 1, 1)\n\n        d(i) = Val(cc)\n\n     Next i\n\n     \n\n'     yy = X1 + 9 * X2 + 8 * d(1) + 7 * d(2) + 6 * d(3) + 5 * d(4) + 4 * d(5) + 3 * d(6) + 2 * d(7) + d(8) + d(9)\n\n'     ChkPID = yy Mod 10\n\n\n\n     yy = X1 + 9 * X2 + 8 * d(1) + 7 * d(2) + 6 * d(3) + 5 * d(4) + 4 * d(5) + 3 * d(6) + 2 * d(7) + d(8)\n\n     ChkPID = (10 - (yy Mod 10)) Mod 10\n\n     If ChkPID = d(9) Then\n\n        ChkPID = 0\n\n     End If\n\n     \n\nEnd Function\n\n\n\n'顯示今日日期(民國年YYYMMDD)\n\nPublic Function Today() As String\n\n  Today = Format(Date, \"yyyymmdd\")\n\n  Today = Today - 19110000\n\n  TodayTw = Format(TodayTw, \"0######\")\n\nEnd Function\n\n\n\n'檢查民國年(yyy/mm/dd)輸入的合理性\n\nPublic Function ChkDate(ByVal sDate As String) As Boolean\n\n  Dim EndDate       As Date\n\n  Dim yy, mm, dd    As Integer\n\n  Dim yy1, mm1, dd1 As Integer\n\n  Dim AfterDate     As String\n\n   \n\n  If Len(sDate) <> 7 Then\n\n     ChkDate = False\n\n     Exit Function\n\n  End If\n\n  \n\n  AfterDate = Format(ChgDate(sDate), \"yyyymmdd\")\n\n  AfterDate = AfterDate - 19110000\n\n  AfterDate = Format(AfterDate, \"0######\")\n\n    \n\n  yy = Val(Mid(sDate, 1, 3))\n\n  mm = Val(Mid(sDate, 4, 2))\n\n  dd = Val(Mid(sDate, 6, 2))\n\n  yy1 = Val(Mid(AfterDate, 1, 3))\n\n  mm1 = Val(Mid(AfterDate, 4, 2))\n\n  dd1 = Val(Mid(AfterDate, 6, 2))\n\n  \n\n  If yy <> yy1 Or mm <> mm1 Or dd <> dd1 Then\n\n     ChkDate = False\n\n     Exit Function\n\n  End If\n\n \n\n  ChkDate = True\n\nEnd Function\n\n\n\n'將民國年(yyymmdd)轉成日期型態\n\nPublic Function ChgDate(ByVal sDate As String) As Date\n\n   Dim yy, mm, dd As Integer\n\n   yy = Val(Mid(sDate, 1, 3)) + 1911\n\n   mm = Val(Mid(sDate, 4, 2))\n\n   dd = Val(Mid(sDate, 6, 2))\n\n   ChgDate = DateSerial(yy, mm, dd)\n\nEnd Function\n\n\n\n'將字串轉成數字\n\nPublic Function Str2Val(ByVal sNum As String) As Double\n\n   sNum = Format(sNum, \"#\")\n\n   Str2Val = Val(sNum)\n\nEnd Function\n\n\n\n'切割字串根據字元長度(Byte Length)\n\n'長度超過時會補空白\n\n'mode=\"L\":左補空白\n\n'mode=\"M\":置中(兩側擺空白)\n\n'未指定為右補空白\n\nPublic Function FixStr(ByVal iStr As String, ByVal fixlen As Integer, ByVal mode As String) As String\n\n   Dim strlen   As Integer\n\n   Dim strTemp  As String\n\n   Dim x        As Integer\n\n   Dim i        As Integer\n\n   Dim C        As String\n\n   Dim newStr   As String\n\n   Dim nowlen   As Integer\n\n   \n\n'   iStr = Trim(iStr)\n\n   strlen = 0\n\n   strTemp = iStr\n\n   newStr = \"\"\n\n   \n\n   Do While Len(strTemp) > 0\n\n      C = Left(strTemp, 1)\n\n      If Asc(C) < 0 Then\n\n         nowlen = 2\n\n      Else\n\n         nowlen = 1\n\n      End If\n\n      \n\n      If (strlen + nowlen) > fixlen Then\n\n         Exit Do\n\n      Else\n\n         strlen = strlen + nowlen\n\n      End If\n\n      newStr = newStr + C\n\n      \n\n      strTemp = Right(strTemp, Len(strTemp) - 1)\n\n   Loop\n\n   \n\n   x = fixlen - strlen\n\n   If x > 0 Then\n\n      If mode = \"L\" Then\n\n         FixStr = Space(x) + newStr\n\n      Else\n\n         If mode = \"M\" Then\n\n            i = x Mod 2\n\n            If i = 0 Then\n\n               FixStr = Space(x / 2) + newStr + Space(x / 2)\n\n            Else\n\n               i = x / 2\n\n               FixStr = Space(i) + newStr + Space(x - i)\n\n            End If\n\n         Else\n\n            FixStr = newStr + Space(x)\n\n         End If\n\n      End If\n\n   Else\n\n      FixStr = newStr\n\n   End If\n\nEnd Function\n\n\n\n'擷取字串根據指定開始位置及字元長度(Byte Length)\n\nPublic Function MidMbcs(ByVal str As String, start As Integer, Optional length As Integer) As String\n\n   Dim strlen   As Integer\n\n   Dim strTemp  As String\n\n   Dim i        As Integer\n\n   Dim C        As String\n\n   Dim newStr   As String\n\n   Dim nowlen   As Integer\n\n   \n\n   strlen = 0\n\n   strTemp = str\n\n   newStr = \"\"\n\n   \n\n   \n\n   If start < 1 Then start = 1\n\n   i = 0\n\n   Do While i < (start - 1)\n\n      If Len(strTemp) <= 0 Then Exit Do\n\n      \n\n      C = Left(strTemp, 1)\n\n      If Asc(C) < 0 Then\n\n         nowlen = 2\n\n      Else\n\n         nowlen = 1\n\n      End If\n\n      \n\n      If (i + nowlen) >= start Then\n\n         Exit Do\n\n      Else\n\n         i = i + nowlen\n\n         strTemp = Right(strTemp, Len(strTemp) - 1)\n\n      End If\n\n      \n\n      If strTemp = \"\" Then\n\n         Exit Do\n\n      End If\n\n   Loop\n\n    \n\n   Do While Len(strTemp) > 0\n\n      C = Left(strTemp, 1)\n\n      If Asc(C) < 0 Then\n\n         nowlen = 2\n\n      Else\n\n         nowlen = 1\n\n      End If\n\n      \n\n      If (strlen + nowlen) > length And length <> 0 Then\n\n         Exit Do\n\n      Else\n\n         strlen = strlen + nowlen\n\n      End If\n\n      newStr = newStr + C\n\n      \n\n      strTemp = Right(strTemp, Len(strTemp) - 1)\n\n   Loop\n\n   MidMbcs = newStr\n\nEnd Function\n\n\n\n'擷取字串根據字元長度(Byte Length)\n\n'不足指定長度會去除最後一個byte\n\nPublic Function cutchar(dataString As String, limit As Integer) As String\n\n    Dim i As Integer\n\n    Dim s As String\n\n    Dim sql As String\n\n  \n\n    sql = \"\"\n\n    s = \"\"\n\n    i = 0\n\n    Do While Len(dataString) <> 0\n\n       s = Left(dataString, 1)\n\n       \n\n       If Asc(s) < 0 Then\n\n          i = i + 2\n\n       Else\n\n          i = i + 1\n\n       End If\n\n       \n\n       If i <= limit Then\n\n          sql = sql + s\n\n          dataString = Right(dataString, Len(dataString) - 1)\n\n          If Asc(s) = 13 Then\n\n             Exit Do\n\n          End If\n\n       Else\n\n          Exit Do\n\n       End If\n\n   Loop\n\n   cutchar = sql\n\n   \n\nEnd Function\n\n\n\n'檢查是否為大寫英文\n\n'用法\n\n'Private Sub TextBox3_KeyPress(ByVal KeyAscii As MSForms.ReturnInteger)\n\n'   KeyAscii = ChgUCase(KeyAscii)\n\n'End Sub\n\nPublic Function ChgUCase(ByVal KeyAscii As Integer) As Integer\n\n    If KeyAscii >= 97 And KeyAscii <= 122 Then\n\n       ChgUCase = KeyAscii - 32\n\n    Else\n\n       ChgUCase = KeyAscii\n\n    End If\n\nEnd Function\n\n\n\n'檢查是否為數字\n\n'用法\n\n'Private Sub TextBox3_KeyPress(ByVal KeyAscii As MSForms.ReturnInteger)\n\n'   If KeyAscii = Asc(vbBack) Then Exit Sub\n\n'\n\n'   If Not ChkValNum(KeyAscii) Then\n\n'      KeyAscii = ChgUCase(KeyAscii)\n\n'   End If\n\n'End Sub\n\n'Private Sub TextBox8_KeyPress(ByVal KeyAscii As MSForms.ReturnInteger)\n\n'   If Not ChkValNum(KeyAscii) Then\n\n'      KeyAscii = 0\n\n'   End If\n\n'End Sub\n\nPublic Function ChkValNum(ByVal KeyAscii As Integer) As Boolean\n\n   If KeyAscii >= 48 And KeyAscii <= 57 Then\n\n      ChkValNum = True\n\n   Else\n\n      ChkValNum = False\n\n   End If\n\nEnd Function\n\n\n\n'將來源字串移除指定的文字\n\nPublic Function InStrDel(ByVal strData As String, ByVal strDelStr As String) As String\n\n    Dim i As Integer\n\n    Dim s As String\n\n    Dim sql As String\n\n\n\n    sql = \"\"\n\n    s = \"\"\n\n    i = 0\n\n    strData = Trim(strData)\n\n\n\n    Do While Len(strData) <> 0\n\n       s = Left(strData, 1)\n\n       Debug.Print Asc(s)\n\n       Debug.Print Asc(strDelStr)\n\n\n\n       If Asc(s) = Asc(strDelStr) Then\n\n       Else\n\n          sql = sql + s\n\n       End If\n\n       strData = Right(strData, Len(strData) - 1)\n\n\n\n   Loop\n\n   InStrDel = sql\n\n\n\n   \n\n'   If Len(strData) = 0 Then Exit Function\n\n'   Do\n\n'      W = InStr(strData, Asc(strDelStr))\n\n'      If W = 0 Then Exit Do\n\n'      strData = Left(strData, W - 1) & Right(strData, Len(strData) - W)\n\n'   Loop\n\n'   InStrDel = strData\n\nEnd Function\n\n\n\n'檢查營利事業統一編號\n\nPublic Function BANCheck(ByVal strBAN As String, Optional ByRef strReason As String) As Boolean\n\n    Dim intMod             As Integer      ' 餘數變數\n\n    Dim intSum             As Integer      ' 合計數變數\n\n    Dim intX(1 To 8)       As Integer\n\n    Dim intY(1 To 8)       As Integer\n\n    \n\n    BANCheck = False\n\n    \n\n    If Len(strBAN) <> 8 Then\n\n       strReason = \"營利事業統一編號必須是八碼。\"\n\n       BANCheck = False\n\n       Exit Function\n\n    End If\n\n    \n\n    If IsNumeric(strBAN) = False Then\n\n         strReason = \"輸入之編號中有非數字。\"\n\n         BANCheck = False\n\n         Exit Function\n\n    End If\n\n       \n\n    intX(1) = Val(Mid(strBAN, 1, 1)) * 1     ' 第 1位數 * 1。\n\n    intX(2) = Val(Mid(strBAN, 2, 1)) * 2     ' 第 2位數 * 2。\n\n    intX(3) = Val(Mid(strBAN, 3, 1)) * 1     ' 第 3位數 * 1。\n\n    intX(4) = Val(Mid(strBAN, 4, 1)) * 2     ' 第 4位數 * 2。\n\n    intX(5) = Val(Mid(strBAN, 5, 1)) * 1     ' 第 5位數 * 1。\n\n    intX(6) = Val(Mid(strBAN, 6, 1)) * 2     ' 第 6位數 * 2。\n\n    intX(7) = Val(Mid(strBAN, 7, 1)) * 4     ' 第 7位數 * 4。\n\n    intX(8) = Val(Mid(strBAN, 8, 1)) * 1     ' 第 8位數 * 1。\n\n    \n\n    intY(1) = Int(intX(2) / 10)              ' 第 2位數的乘積可能大於10，除以10，取其整數。\n\n    intY(2) = intX(2) Mod 10                 ' 第 2位數的乘積可能大於10，除以10，取其餘數。\n\n    intY(3) = Int(intX(4) / 10)              ' 第 4位數的乘積可能大於10，除以10，取其整數。\n\n    intY(4) = intX(4) Mod 10                 ' 第 4位數的乘積可能大於10，除以10，取其餘數。\n\n    intY(5) = Int(intX(6) / 10)              ' 第 6位數的乘積可能大於10，除以10，取其整數。\n\n    intY(6) = intX(6) Mod 10                 ' 第 6位數的乘積可能大於10，除以10，取其餘數。\n\n    intY(7) = Int(intX(7) / 10)              ' 第 7位數的乘積可能大於10，除以10，取其整數。\n\n    intY(8) = intX(7) Mod 10                 ' 第 7位數的乘積可能大於10，除以10，取其餘數。\n\n  \n\n    intSum = intX(1) + intX(3) + intX(5) + intX(8) + _\n\n             intY(1) + intY(2) + intY(3) + intY(4) + intY(5) + intY(6) + intY(7) + intY(8)\n\n    \n\n    intMod = intSum Mod 10\n\n  \n\n    If Val(Mid(strBAN, 7, 1)) = 7 Then       ' 判斷 1: 第 7位數是否為 7 時，\n\n       If intMod = 0 Then                    ' 判斷 2: 餘數是否為 0。\n\n           BANCheck = True\n\n           Exit Function\n\n       Else\n\n           intSum = intSum + 1               ' 再行計算。 1999/11/19 修正。\n\n           intMod = intSum Mod 10\n\n           If intMod = 0 Then\n\n               BANCheck = True\n\n               Exit Function\n\n           Else\n\n               strReason = \"輸入錯誤，請再檢查。\"\n\n               BANCheck = False\n\n               Exit Function\n\n           End If\n\n       End If\n\n    Else\n\n       If intMod = 0 Then\n\n           BANCheck = True\n\n           Exit Function\n\n       Else\n\n           strReason = \"輸入錯誤，請再檢查。\"\n\n           BANCheck = False\n\n           Exit Function\n\n       End If\n\n    End If\n\nEnd Function\n\n\n\n\n\n", "content_b64": ""}, {"name": "CombineExeFileUtil.bas", "path": "模組/Others/CombineExeFileUtil.bas", "content": "Attribute VB_Name = \"CombineExeFileUtil\"\nOption Explicit\n'*************************************************************************************\n'專案名稱: VBA專案\n'功能描述:\n'與外部程式整合\n'版權所有: Dunk\n'程式撰寫: Dunk\n'撰寫日期：2015/11/11\n'\n'改版日期:\n'改版備註:\n'*************************************************************************************\n\n'使用notepad，將檔案調整成unicode後，另存新檔\nPublic Function SaveFileToUnicode(ByVal fileName As String)\nDim R\n    R = Shell(\"notepad.exe\", 1)\n    AppActivate R\n    SendKeys \"%FO\", True '------------->[檔案][開啟檔案]\n    SendKeys fileName, True  '--------->輸入檔名\n    SendKeys \"{ENTER}\", True '-------------->按下[確定]\n    SendKeys \"%FA\", True '------------->[檔案][另存新檔]\n    SendKeys fileName, True  '--------->輸入檔名\n    SendKeys \"%E\", True '-------------->按下[切換到編碼]\n    SendKeys \"unicode\", True '-------------->[unicode]\n    SendKeys \"%S\", True '-------------->按下[存檔]\n    SendKeys \"{TAB}\", True '-------------->切換到[確定]\n    SendKeys \"{ENTER}\", True '-------------->按下[確定]\n    SendKeys \"%{f4}\", True '----------->按下[f4]結束程式\nEnd Function\n", "content_b64": ""}, {"name": "ConnectDBF.bas", "path": "模組/Others/ConnectDBF.bas", "content": "Attribute VB_Name = \"ConnectDBF\"\nOption Explicit\nSub F_Sample027()\n   'Microsoft ActiveX Data Objects 2.X Library 設定引用項目\n   '測試資料 F_Data.mdb F_Data2003.mdb F_Data.accdb\n    Dim myCon      As New ADODB.Connection\n    Dim myRst      As ADODB.Recordset\n    Dim mySqlStr   As String\n    Dim myFileName As String\n    Dim i          As Long\n    Worksheets.Add\n    myFileName = \"F_Data.mdb\"           '讀入檔案\n    'myFileName = \"F_Data2003.mdb\"      '讀入檔案\n    'myFileName = \"F_Data.accdb\"        '讀入檔案\n    '以SQL來指定讀入資料\n    mySqlStr = \"SELECT * FROM F_Tbl01\"\n    myCon.Open \"Provider=Microsoft.Jet.OLEDB.4.0;\" & _\n    \"Data Source=\" & ThisWorkbook.Path & \"\\\" & myFileName & \";\"\n    'myCon.Open \"Provider=Microsoft.Ace.OLEDB.12.0;\" & _   'accdb檔案用\n               '\"Data Source=\" & ThisWorkbook.Path & \"\\\" & myFileName & \";\"\n    Set myRst = myCon.Execute(mySqlStr)\n    If myRst.EOF Then\n        MsgBox \"沒有符合條件的資料\"\n    Else\n        With myRst\n           '欄名\n            For i = 1 To .Fields.Count\n                Cells(1, i).Value = .Fields(i - 1).Name\n            Next\n           '記錄\n            Range(\"A2\").CopyFromRecordset myRst\n            .Close\n        End With\n    End If\n    myCon.Close\n    Set myRst = Nothing             '釋放物件\n    Set myCon = Nothing\nEnd Sub\n\n", "content_b64": ""}, {"name": "ConnectionToOutput.bas", "path": "模組/Others/ConnectionToOutput.bas", "content": "Attribute VB_Name = \"ConnectionToOutput\"\n\nOption Explicit\n\n'*************************************************************************************\n\n'專案名稱: VBA專案\n\n'功能描述: 連線到外部資料源\n\n'\n\n'版權所有: Dunk\n\n'程式撰寫: Dunk\n\n'撰寫日期：2015/7/28\n\n'\n\n'改版日期: 2015/7/30\n\n'改版備註: 加入SQL帳號驗證\n\n'*************************************************************************************\n\n\n\nSub InitTableData()\n\nApplication.ScreenUpdating = False\n\n    Call DeleteAllSheets\n\n    Dim resultArray() As String\n\n    Dim i As Integer\n\n    Dim ip As String\n\n    Dim dbname As String\n\n    Dim account As String\n\n    \n\n    ip = ThisWorkbook.Sheets(1).Range(\"$D$2\").Text\n\n    dbname = ThisWorkbook.Sheets(1).Range(\"$D$3\").Text\n\n    account = ThisWorkbook.Sheets(1).Range(\"$D$4\").Text\n\n    resultArray = ReadFirstSheetTableDefs()\n\n        \n\n    For i = LBound(resultArray) To UBound(resultArray) - 1\n\n        Call CreateTableDefinition(resultArray(i), ip, dbname, account)\n\n    Next i\n\n    Call DeleteAllConnections\n\n\n\nApplication.ScreenUpdating = True\n\nEnd Sub\n\n\n\nFunction ReadFirstSheetTableDefs() As String()\n\n\n\nDim my_name, pre_name As String\n\nDim i, j As Byte\n\nDim my_range As Range\n\nDim resultArray() As String\n\nDim arrayCount As Integer\n\n\n\narrayCount = 0\n\nReDim resultArray(65536)\n\n\n\nmy_name = \"\"\n\npre_name = \"\"\n\n\n\nSet my_range = ThisWorkbook.Sheets(1).Range(\"A2\")\n\nmy_name = my_range.Text\n\n\n\nDo While my_name <> pre_name\n\n    On Error Resume Next\n\n    resultArray(arrayCount) = my_range.Text\n\n    'Debug.Print resultArray(arrayCount)\n\n    Set my_range = my_range.Offset(1, 0)\n\n    arrayCount = arrayCount + 1\n\n    my_name = my_range.Text\n\nLoop\n\n\n\nReDim Preserve resultArray(arrayCount)\n\nReadFirstSheetTableDefs = resultArray()\n\n\n\nEnd Function\n\n\n\nFunction GetConnectionString(ByVal ip As String, ByVal dbname As String, ByVal account As String) As Variant\n\n    If account <> \"\" Then\n\n    GetConnectionString = \"OLEDB;Provider=SQLOLEDB.1;Persist Security Info=True;User ID=\" & account & \";Data Source=\" & ip & \";Use Procedure for Prepare=1;Auto Translate=Tr\" _\n\n        & \"ue;Packet Size=4096;Use Encryption for Data=False;Tag with column collation when possible=False;Initi\" _\n\n        & \"al Catalog=\" & dbname\n\n        \n\n    Else\n\n    GetConnectionString = \"OLEDB;Provider=SQLOLEDB.1;Integrated Security=SSPI;Persist Security Info=True;Data Source=\" & ip & \";Use Procedure for Prepare=1;Auto T\" _\n\n        & \"ranslate=True;Packet Size=4096;Use Encryption for Data=False;Tag with column collation when possible=\" _\n\n        & \"False;Initial Catalog=\" & dbname\n\n        \n\n    End If\n\nEnd Function\n\n\n\n\n\n\n\nFunction CreateTableDefinition(ByVal tableName As String, ByVal ip As String, ByVal dbname As String, ByVal account As String)\n\n    '建立資料sheet\n\n        ThisWorkbook.Sheets.Add After:=Sheets(Sheets.Count)\n\n        Sheets(Sheets.Count).Name = tableName\n\n        Call FetchTableData(tableName, GetConnectionString(ip, dbname, account))\n\nEnd Function\n\n\n\n\n\nFunction FetchTableData(ByVal tableName As String, ByRef connectString As Variant)\n\nAttribute FetchTableData.VB_ProcData.VB_Invoke_Func = \" \\n14\"\n\nWith ActiveSheet.ListObjects.Add(SourceType:=0, Source:=connectString, Destination:=Range(\"$A$1\")).QueryTable\n\n        .CommandType = xlCmdSql\n\n        .CommandText = SqlStatement.GetDbTableCompareFormat(tableName)\n\n        .RowNumbers = False\n\n        .FillAdjacentFormulas = False\n\n        .PreserveFormatting = True\n\n        .RefreshOnFileOpen = False\n\n        .BackgroundQuery = True\n\n        .RefreshStyle = xlInsertDeleteCells\n\n        .SavePassword = False\n\n        .SaveData = True\n\n        .AdjustColumnWidth = True\n\n        .RefreshPeriod = 0\n\n        .PreserveColumnInfo = True\n\n        .Refresh BackgroundQuery:=False\n\n    End With\n\n    ActiveSheet.ListObjects(ActiveSheet.ListObjects.Count).TableStyle = \"TableStyleMedium13\"\n\nEnd Function\n\nFunction ShowConnectionInfo()\n\nAttribute ShowConnectionInfo.VB_ProcData.VB_Invoke_Func = \" \\n14\"\n\n    Dim i As Integer\n\n    For i = 1 To ThisWorkbook.Connections.Count\n\n        MsgBox CStr(ThisWorkbook.Connections.Item(i).Name)\n\n    Next\n\nEnd Function\n\n\n\nFunction DeleteAllConnections()\n\nDo While ThisWorkbook.Connections.Count > 0\n\n        ThisWorkbook.Connections.Item(ThisWorkbook.Connections.Count).Delete\n\nLoop\n\nEnd Function\n\n\n\nFunction DeleteAllSheets()\n\nApplication.DisplayAlerts = False\n\n Dim i As Integer\n\n For i = ThisWorkbook.Sheets.Count To 2 Step -1\n\n ThisWorkbook.Sheets(i).Delete\n\n Next i\n\n\n\n Application.DisplayAlerts = True\n\nEnd Function\n\n", "content_b64": ""}, {"name": "CopyCliboardUtility.bas", "path": "模組/Others/CopyCliboardUtility.bas", "content": "Attribute VB_Name = \"CopyCliboardUtility\"\nOption Explicit\n'*************************************************************************************\n'專案名稱: 底層元件\n'功能描述: 複製文字到剪貼簿\n'\n'版權所有: Dunk\n'程式撰寫: Dunk\n'撰寫日期：2018/2/23\n'\n'改版日期:\n'改版備註: 2020/09/17 調整複製寫法\n'\n'*************************************************************************************\n\n#If Mac Then\n    ' ignore\n#Else\n    #If VBA7 Then\n        Declare PtrSafe Function GlobalUnlock Lib \"kernel32\" (ByVal hMem As LongPtr) As LongPtr\n        Declare PtrSafe Function GlobalLock Lib \"kernel32\" (ByVal hMem As LongPtr) As LongPtr\n        Declare PtrSafe Function GlobalAlloc Lib \"kernel32\" (ByVal wFlags As Long, _\n                                                             ByVal dwBytes As LongPtr) As LongPtr\n\n        Declare PtrSafe Function CloseClipboard Lib \"User32\" () As Long\n        Declare PtrSafe Function OpenClipboard Lib \"User32\" (ByVal hwnd As LongPtr) As LongPtr\n        Declare PtrSafe Function EmptyClipboard Lib \"User32\" () As Long\n\n        Declare PtrSafe Function lstrcpy Lib \"kernel32\" (ByVal lpString1 As Any, _\n                                                         ByVal lpString2 As Any) As LongPtr\n\n        Declare PtrSafe Function SetClipboardData Lib \"User32\" (ByVal wFormat _\n                                                                As Long, ByVal hMem As LongPtr) As LongPtr\n        Declare PtrSafe Function lstrlen Lib \"kernel32\" Alias \"lstrlenA\" (ByVal lpString As String) As LongPtr\n    #Else\n        Declare PtrSafe Function GlobalUnlock Lib \"kernel32\" (ByVal hMem As Long) As Long\n        Declare PtrSafe Function GlobalLock Lib \"kernel32\" (ByVal hMem As Long) As Long\n        Declare PtrSafe Function GlobalAlloc Lib \"kernel32\" (ByVal wFlags As Long, _\n                                                     ByVal dwBytes As Long) As Long\n\n        Declare PtrSafe Function CloseClipboard Lib \"User32\" () As Long\n        Declare PtrSafe Function OpenClipboard Lib \"User32\" (ByVal hwnd As Long) As Long\n        Declare PtrSafe Function EmptyClipboard Lib \"User32\" () As Long\n\n        Declare PtrSafe Function lstrcpy Lib \"kernel32\" (ByVal lpString1 As Any, _\n                                                 ByVal lpString2 As Any) As Long\n\n        Declare PtrSafe Function SetClipboardData Lib \"User32\" (ByVal wFormat _\n                                                        As Long, ByVal hMem As Long) As Long\n        Declare PtrSafe Function lstrlen Lib \"kernel32\" Alias \"lstrlenA\" (ByVal lpString As String) As LongPtr\n    #End If\n#End If\nPublic Const GHND = &H42\nPublic Const CF_TEXT = 1\nPublic Const MAXSIZE = 4096\n\nPrivate Sub ClipBoard_SetData(MyString As String)\n    #If Mac Then\n        With New MSForms.DataObject\n            .SetText MyString\n            .PutInClipboard\n        End With\n    #Else\n        #If VBA7 Then\n            Dim hGlobalMemory As LongPtr\n            Dim hClipMemory   As LongPtr\n            Dim lpGlobalMemory    As LongPtr\n        #Else\n            Dim hGlobalMemory As Long\n            Dim hClipMemory   As Long\n            Dim lpGlobalMemory    As Long\n        #End If\n\n        Dim x                 As Long\n\n        ' Allocate moveable global memory.\n        '-------------------------------------------\n        hGlobalMemory = GlobalAlloc(GHND, lstrlen(MyString) + 1)\n\n        ' Lock the block to get a far pointer\n        ' to this memory.\n        lpGlobalMemory = GlobalLock(hGlobalMemory)\n\n        ' Copy the string to this global memory.\n        lpGlobalMemory = lstrcpy(lpGlobalMemory, MyString)\n\n        ' Unlock the memory.\n        If GlobalUnlock(hGlobalMemory) <> 0 Then\n            MsgBox \"Could not unlock memory location. Copy aborted.\"\n            GoTo OutOfHere2\n        End If\n\n        ' Open the Clipboard to copy data to.\n        If OpenClipboard(0&) = 0 Then\n            MsgBox \"Could not open the Clipboard. Copy aborted.\"\n            Exit Sub\n        End If\n\n        ' Clear the Clipboard.\n        x = EmptyClipboard()\n\n        ' Copy the data to the Clipboard.\n        hClipMemory = SetClipboardData(CF_TEXT, hGlobalMemory)\n\nOutOfHere2:\n\n        If CloseClipboard() = 0 Then\n            MsgBox \"Could not close Clipboard.\"\n        End If\n    #End If\n\nEnd Sub\n\n'複製到剪貼簿\n'Microsoft Forms 2.0 Object Library 設定引用項目(C:\\WINDOWS\\system32\\FM20.DLL)\nFunction CopyToClipboard(ByVal resultFileName As String)\n\n'    Dim myDobj As New DataObject\n'\n'    '複製到剪貼簿\n'    With myDobj\n'        .SetText resultFileName\n'        .PutInClipboard\n'    End With\n'    Set myDobj = Nothing\n    ClipBoard_SetData resultFileName\n\nEnd Function\n", "content_b64": ""}, {"name": "CopyFilePath.bas", "path": "模組/Others/CopyFilePath.bas", "content": "Attribute VB_Name = \"CopyFilePath\"\n\nOption Explicit\n\n'*************************************************************************************\n\n'專案名稱: 全委帳務處理\n\n'功能描述: 7000平均餘額擷取工具_複製檔案名稱\n\n'\n\n'版權所有: Dunk\n\n'程式撰寫: Dunk\n\n'撰寫日期：2017/11/26\n\n'\n\n'改版日期:\n\n'改版備註: 2020/09/15 調整複製寫法\n\n'https://chandoo.org/forum/threads/clipboard-copy-vba-code-not-working-in-windows-10.37126/\n\n'*************************************************************************************\n\n#If Mac Then\n\n    ' ignore\n\n#Else\n\n    #If VBA7 Then\n\n        Declare PtrSafe Function GlobalUnlock Lib \"kernel32\" (ByVal hMem As LongPtr) As LongPtr\n\n        Declare PtrSafe Function GlobalLock Lib \"kernel32\" (ByVal hMem As LongPtr) As LongPtr\n\n        Declare PtrSafe Function GlobalAlloc Lib \"kernel32\" (ByVal wFlags As Long, _\n\n                                                             ByVal dwBytes As LongPtr) As LongPtr\n\n\n\n        Declare PtrSafe Function CloseClipboard Lib \"User32\" () As Long\n\n        Declare PtrSafe Function OpenClipboard Lib \"User32\" (ByVal hwnd As LongPtr) As LongPtr\n\n        Declare PtrSafe Function EmptyClipboard Lib \"User32\" () As Long\n\n\n\n        Declare PtrSafe Function lstrcpy Lib \"kernel32\" (ByVal lpString1 As Any, _\n\n                                                         ByVal lpString2 As Any) As LongPtr\n\n\n\n        Declare PtrSafe Function SetClipboardData Lib \"User32\" (ByVal wFormat _\n\n                                                                As Long, ByVal hMem As LongPtr) As LongPtr\n\n\t\tDeclare PtrSafe Function lstrlen Lib \"kernel32\" Alias \"lstrlenA\" (ByVal lpString As String) As LongPtr\t\t\t\t\t\t\t\t\t\t\t\t\t\t\t\n\n    #Else\n\n        Declare PtrSafe Function GlobalUnlock Lib \"kernel32\" (ByVal hMem As Long) As Long\n\n        Declare PtrSafe Function GlobalLock Lib \"kernel32\" (ByVal hMem As Long) As Long\n\n        Declare PtrSafe Function GlobalAlloc Lib \"kernel32\" (ByVal wFlags As Long, _\n\n                                                     ByVal dwBytes As Long) As Long\n\n\n\n        Declare PtrSafe Function CloseClipboard Lib \"User32\" () As Long\n\n        Declare PtrSafe Function OpenClipboard Lib \"User32\" (ByVal hwnd As Long) As Long\n\n        Declare PtrSafe Function EmptyClipboard Lib \"User32\" () As Long\n\n\n\n        Declare PtrSafe Function lstrcpy Lib \"kernel32\" (ByVal lpString1 As Any, _\n\n                                                 ByVal lpString2 As Any) As Long\n\n\n\n        Declare PtrSafe Function SetClipboardData Lib \"User32\" (ByVal wFormat _\n\n                                                        As Long, ByVal hMem As Long) As Long\n\n\t\tDeclare PtrSafe Function lstrlen Lib \"kernel32\" Alias \"lstrlenA\" (ByVal lpString As String) As LongPtr\n\n    #End If\n\n#End If\n\nPublic Const GHND = &H42\n\nPublic Const CF_TEXT = 1\n\nPublic Const MAXSIZE = 4096\n\n\n\nPrivate Sub ClipBoard_SetData(MyString As String)\n\n    #If Mac Then\n\n        With New MSForms.DataObject\n\n            .SetText MyString\n\n            .PutInClipboard\n\n        End With\n\n    #Else\n\n        #If VBA7 Then\n\n            Dim hGlobalMemory As LongPtr\n\n            Dim hClipMemory   As LongPtr\n\n            Dim lpGlobalMemory    As LongPtr\n\n        #Else\n\n            Dim hGlobalMemory As Long\n\n            Dim hClipMemory   As Long\n\n            Dim lpGlobalMemory    As Long\n\n        #End If\n\n\n\n        Dim x                 As Long\n\n\n\n        ' Allocate moveable global memory.\n\n        '-------------------------------------------\n\n        hGlobalMemory = GlobalAlloc(GHND, lstrlen(MyString) + 1)\n\n\n\n        ' Lock the block to get a far pointer\n\n        ' to this memory.\n\n        lpGlobalMemory = GlobalLock(hGlobalMemory)\n\n\n\n        ' Copy the string to this global memory.\n\n        lpGlobalMemory = lstrcpy(lpGlobalMemory, MyString)\n\n\n\n        ' Unlock the memory.\n\n        If GlobalUnlock(hGlobalMemory) <> 0 Then\n\n            MsgBox \"Could not unlock memory location. Copy aborted.\"\n\n            GoTo OutOfHere2\n\n        End If\n\n\n\n        ' Open the Clipboard to copy data to.\n\n        If OpenClipboard(0&) = 0 Then\n\n            MsgBox \"Could not open the Clipboard. Copy aborted.\"\n\n            Exit Sub\n\n        End If\n\n\n\n        ' Clear the Clipboard.\n\n        x = EmptyClipboard()\n\n\n\n        ' Copy the data to the Clipboard.\n\n        hClipMemory = SetClipboardData(CF_TEXT, hGlobalMemory)\n\n\n\nOutOfHere2:\n\n\n\n        If CloseClipboard() = 0 Then\n\n            MsgBox \"Could not close Clipboard.\"\n\n        End If\n\n    #End If\n\n\n\nEnd Sub\n\n\n\n'複製到剪貼簿\n\n'Microsoft Forms 2.0 Object Library 設定引用項目(C:\\WINDOWS\\system32\\FM20.DLL)\n\nFunction CopyToClipboard(ByVal resultFileName As String)\n\n\n\n'    Dim myDobj As New DataObject\n\n'\n\n'    '複製到剪貼簿\n\n'    With myDobj\n\n'        .SetText resultFileName\n\n'        .PutInClipboard\n\n'    End With\n\n'    Set myDobj = Nothing\n\n    ClipBoard_SetData resultFileName\n\n\n\nEnd Function\n\n\n\n'複製結果功能代號\n\nSub CopyResultFunctionCode_DISPLAY()\n\n    Dim functionName As String\n\n    Dim value As String\n\n    value = ActiveCell.Text\n\n    value = Replace(value, \"(\", \"\")\n\n    value = Replace(value, \")\", \"\")\n\n    value = Replace(value, \",\", \"\")\n\n    functionName = Trim(value)\n\n\n\n    CopyToClipboard (functionName)\n\nEnd Sub\n\n", "content_b64": ""}, {"name": "CustmizeForm.bas", "path": "模組/Others/CustmizeForm.bas", "content": "Attribute VB_Name = \"CustmizeForm\"\n\n\nOption Explicit\n\n\nSub CreateIssueTrackingTable()\n\n\n    Application.ScreenUpdating = False\n\n\n    \n\n\n    Dim tableName As String\n\n\n    tableName = \"問題追蹤表_\" & ActiveSheet.Name\n\n\n    \n\n\n    ActiveSheet.Name = tableName\n\n\n    ActiveCell.FormulaR1C1 = \"單號\"\n\n\n    Range(\"B1\").Select\n\n\n    ActiveCell.FormulaR1C1 = \"優先程度\"\n\n\n    Range(\"C1\").Select\n\n\n    ActiveCell.FormulaR1C1 = \"紀錄日期\"\n\n\n    Range(\"D1\").Select\n\n\n    ActiveCell.FormulaR1C1 = \"預計完成日期\"\n\n\n    Range(\"E1\").Select\n\n\n    ActiveCell.FormulaR1C1 = \"實際完成日期\"\n\n\n    Range(\"F1\").Select\n\n\n    ActiveCell.FormulaR1C1 = \"處理結果\"\n\n\n    Range(\"G1\").Select\n\n\n    ActiveCell.FormulaR1C1 = \"聯絡窗口\"\n\n\n    Range(\"H1\").Select\n\n\n    ActiveCell.FormulaR1C1 = \"結案日期\"\n\n\n    Range(\"A1\").Select\n\n\n    ActiveSheet.ListObjects.Add(xlSrcRange, Range(\"$A$1:$H$1\"), , xlYes).Name = _\n\n\n        tableName\n\n\n    Range(tableName & \"[#All]\").Select\n\n\n    ActiveSheet.ListObjects(tableName).TableStyle = \"TableStyleLight11\"\n\n\n    Range(tableName & \"[紀錄日期]\").Select\n\n\n    Range(Selection, Selection.End(xlDown)).Select\n\n\n    Selection.NumberFormatLocal = \"[$-404]e/m/d;@\"\n\n\n    ActiveWindow.SmallScroll Down:=-12\n\n\n    Range(tableName & \"[預計完成日期]\").Select\n\n\n    Range(Selection, Selection.End(xlDown)).Select\n\n\n    Selection.NumberFormatLocal = \"[$-404]e/m/d;@\"\n\n\n    ActiveWindow.SmallScroll Down:=-6\n\n\n    Range(tableName & \"[實際完成日期]\").Select\n\n\n    ActiveWindow.SmallScroll Down:=-6\n\n\n    Range(Selection, Selection.End(xlDown)).Select\n\n\n    Selection.NumberFormatLocal = \"[$-404]e/m/d;@\"\n\n\n    ActiveWindow.SmallScroll Down:=-12\n\n\n    Range(tableName & \"[結案日期]\").Select\n\n\n    ActiveWindow.SmallScroll Down:=-18\n\n\n    Range(Selection, Selection.End(xlDown)).Select\n\n\n    Selection.NumberFormatLocal = \"[$-404]e/m/d;@\"\n\n\n    ActiveWindow.SmallScroll Down:=-12\n\n\n    Range(\"A1\").Select\n\n\n    \n\n\n    DrawAllBorders (tableName)\n\n\n    \n\n\n    Application.ScreenUpdating = True\n\n\n    \n\n\n    \n\n\nEnd Sub\n\n\n\n\n\nSub CreateDbTableDefinition()\n\n\n    Application.ScreenUpdating = False\n\n\n    \n\n\n    Dim tableName As String\n\n\n    tableName = \"table_\" & ActiveSheet.Name\n\n\n    Range(\"A1\").Select\n\n\n    ActiveCell.FormulaR1C1 = \"欄位名稱\"\n\n\n    Range(\"B1\").Select\n\n\n    ActiveCell.FormulaR1C1 = \"欄位描述\"\n\n\n    Range(\"C1\").Select\n\n\n    ActiveCell.FormulaR1C1 = \"型態\"\n\n\n    Range(\"D1\").Select\n\n\n    ActiveCell.FormulaR1C1 = \"長度\"\n\n\n    Range(\"E1\").Select\n\n\n    ActiveCell.FormulaR1C1 = \"主鍵(PK)\"\n\n\n    Range(\"F1\").Select\n\n\n    ActiveCell.FormulaR1C1 = \"說明\"\n\n\n    Range(\"F1\").Select\n\n\n    ActiveSheet.ListObjects.Add(xlSrcRange, Range(\"$A$1:$F$1\"), , xlYes).Name = _\n\n\n        tableName\n\n\n    ActiveSheet.ListObjects(tableName).TableStyle = \"TableStyleLight11\"\n\n\n    \n\n\n    '建立回總表連結\n\n\n    Range(\"H1\").Select\n\n\n    ActiveCell.FormulaR1C1 = \"回總表\"\n\n\n    ActiveSheet.Hyperlinks.Add Anchor:=Selection, Address:=\"\", SubAddress:= _\n\n\n        \"總表索引!A1\", TextToDisplay:=\"回總表\"\n\n\n    \n\n\n    DrawAllBorders (tableName)\n\n\n    \n\n\n    Application.ScreenUpdating = True\n\n\n    \n\n\nEnd Sub\n\n\n\n\n\n\n\n\nSub CreateDbViewDefinition()\n\n\n    Application.ScreenUpdating = False\n\n\n\n\n\n    Dim tableName As String\n\n\n    tableName = \"view_\" & ActiveSheet.Name\n\n\n    \n\n\n    Range(\"A1\").Select\n\n\n    ActiveCell.FormulaR1C1 = \"視圖名稱\"\n\n\n    Range(\"B1\").Select\n\n\n    ActiveCell.FormulaR1C1 = \"視圖定義(create sql)\"\n\n\n    Range(\"C1\").Select\n\n\n    ActiveCell.FormulaR1C1 = \"說明\"\n\n\n    ActiveSheet.ListObjects.Add(xlSrcRange, Range(\"$A$1:$C$1\"), , xlYes).Name = _\n\n\n        tableName\n\n\n    ActiveSheet.ListObjects(tableName).TableStyle = \"TableStyleLight11\"\n\n\n    \n\n\n    '建立回總表連結\n\n\n    Range(\"H1\").Select\n\n\n    ActiveCell.FormulaR1C1 = \"回總表\"\n\n\n    ActiveSheet.Hyperlinks.Add Anchor:=Selection, Address:=\"\", SubAddress:= _\n\n\n        \"總表索引!A1\", TextToDisplay:=\"回總表\"\n\n\n        \n\n\n    DrawAllBorders (tableName)\n\n\n    \n\n\n    Application.ScreenUpdating = True\n\n\n        \n\n\nEnd Sub\n\n\n\n\n\n\n\n\nSub DrawAllBorders(ByVal objName As String)\n\n\nApplication.Goto Reference:=objName\n\n\n    Selection.Borders(xlDiagonalDown).LineStyle = xlNone\n\n\n    Selection.Borders(xlDiagonalUp).LineStyle = xlNone\n\n\n    With Selection.Borders(xlEdgeLeft)\n\n\n        .LineStyle = xlContinuous\n\n\n        .ColorIndex = 0\n\n\n        .TintAndShade = 0\n\n\n        .Weight = xlThin\n\n\n    End With\n\n\n    With Selection.Borders(xlEdgeTop)\n\n\n        .LineStyle = xlContinuous\n\n\n        .ColorIndex = 0\n\n\n        .TintAndShade = 0\n\n\n        .Weight = xlThin\n\n\n    End With\n\n\n    With Selection.Borders(xlEdgeBottom)\n\n\n        .LineStyle = xlContinuous\n\n\n        .ColorIndex = 0\n\n\n        .TintAndShade = 0\n\n\n        .Weight = xlThin\n\n\n    End With\n\n\n    With Selection.Borders(xlEdgeRight)\n\n\n        .LineStyle = xlContinuous\n\n\n        .ColorIndex = 0\n\n\n        .TintAndShade = 0\n\n\n        .Weight = xlThin\n\n\n    End With\n\n\n    With Selection.Borders(xlInsideVertical)\n\n\n        .LineStyle = xlContinuous\n\n\n        .ColorIndex = 0\n\n\n        .TintAndShade = 0\n\n\n        .Weight = xlThin\n\n\n    End With\n\n\n    With Selection.Borders(xlInsideHorizontal)\n\n\n        .LineStyle = xlContinuous\n\n\n        .ColorIndex = 0\n\n\n        .TintAndShade = 0\n\n\n        .Weight = xlThin\n\n\n    End With\n\n\nEnd Sub\n\n\n\n\n\n\n\n\n", "content_b64": ""}, {"name": "EncodingUtil.bas", "path": "模組/Others/EncodingUtil.bas", "content": "Attribute VB_Name = \"EncodingUtil\"\nOption Explicit\n'*************************************************************************************\n'專案名稱: VBA專案\n'功能描述:\n'取得檔案編碼方式\n'版權所有: Dunk\n'程式撰寫: Dunk\n'撰寫日期：2015/11/11\n'\n'改版日期:\n'改版備註:\n'*************************************************************************************\nPublic Enum Encoding\nANSI\nUnicode\nUnicodeBigEndian\nUTF8\nEnd Enum\n'取得編碼名稱\nPublic Function GetEncodingName(ByVal enc As Encoding) As String\n    Select Case enc\n        Case ANSI: GetEncodingName = \"ANSI\"\n        Case Unicode: GetEncodingName = \"Unicode\"\n        Case UnicodeBigEndian: GetEncodingName = \"UnicodeBigEndian\"\n        Case UTF8: GetEncodingName = \"UTF8\"\n    End Select\nEnd Function\n'從文字檔取得編碼方式\nPublic Function GetEncoding(FileName As String) As Encoding\nDim fBytes(1) As Byte, freeNum As Integer\n\nfreeNum = FreeFile\n\nOpen FileName For Binary Access Read As #freeNum\nGet #freeNum, , fBytes(0)\nGet #freeNum, , fBytes(1)\nClose #freeNum\n\nIf fBytes(0) = &HFF And fBytes(1) = &HFE Then\n    GetEncoding = Encoding.Unicode\nElseIf fBytes(0) = &HFE And fBytes(1) = &HFF Then\n    GetEncoding = Encoding.UnicodeBigEndian\nElseIf fBytes(0) = &HEF And fBytes(1) = &HBB Then\n    GetEncoding = Encoding.UTF8\nElse\n    GetEncoding = Encoding.ANSI\nEnd If\n\nEnd Function\n'把檔案另存成UTF8\nPublic Sub FileToUTF8(FileName As String)\nDim fBytes() As Byte, uniString As String, freeNum As Integer\nDim ADO_Stream As Object\n\nfreeNum = FreeFile\n\nReDim fBytes(FileLen(FileName))\nOpen FileName For Binary Access Read As #freeNum\nGet #freeNum, , fBytes\nClose #freeNum\n\nuniString = StrConv(fBytes, vbUnicode)\n\nSet ADO_Stream = CreateObject(\"ADODB.Stream\")\nWith ADO_Stream\n    .Type = 2\n    .Mode = 3\n    .Charset = \"utf-8\"\n    .Open\n    .WriteText uniString\n    .SaveToFileFileName , 2\n    .Close\nEnd With\nSet ADO_Stream = Nothing\nEnd Sub\n\n'把檔案另存成unicode\nPublic Sub FileToUnicode(FileName As String)\nDim fBytes() As Byte, uniString As String, freeNum As Integer\nDim ADO_Stream As Object\n\nfreeNum = FreeFile\n\nReDim fBytes(FileLen(FileName))\nOpen FileName For Binary Access Read As #freeNum\nGet #freeNum, , fBytes\nClose #freeNum\n\nuniString = StrConv(fBytes, vbUnicode)\n\nSet ADO_Stream = CreateObject(\"ADODB.Stream\")\nWith ADO_Stream\n    .Type = 2\n    .Mode = 3\n    .Charset = \"unicode\"\n    .Open\n    .WriteText uniString\n    .SaveToFile FileName, 2\n    .Close\nEnd With\nSet ADO_Stream = Nothing\nEnd Sub\n\n", "content_b64": ""}, {"name": "FileIOUtility.bas", "path": "模組/Others/FileIOUtility.bas", "content": "Attribute VB_Name = \"FileIOUtility\"\n\nOption Explicit\n\n''檔案工具模組\n\n''作者：Guan Jhih Liao\n\n''2017/4/6 增加寫入CSV功能\n\n\n\n'寫入檔案\n\nSub WriteFile(ByVal fileName As String, ByVal content As String)\n\n    Open fileName For Output As #1\n\n    Print #1, content\n\n    Close #1\n\nEnd Sub\n\n\n\nSub WriteFileByDefaultEncoding(ByVal fileName As String, ByVal content As String)\n\n'ensure reference is set to Microsoft ActiveX DataObjects library (the latest version of it).\n\n'under \"tools/references\"... references travel with the excel file, so once added, no need to worry.\n\n'if not you will get a type mismatch / library error on line below.\n\n    Dim fsT As Object\n\n    Set fsT = CreateObject(\"ADODB.Stream\")\n\n    fsT.Type = 2    'Specify stream type - we want To save text/string data.\n\n    fsT.Charset = \"_autodetect\"    'Specify charset For the source text data.\n\n    fsT.Open    'Open the stream And write binary data To the object\n\n    fsT.WriteText content\n\n    fsT.SaveToFile fileName, 2    'Save binary data To disk\n\n    Set fsT = Nothing\n\nEnd Sub\n\n'使用檔案總管開啟檔案或資料夾\n\nFunction OpenFileWithExplore(ByVal fileName As String)\n\n'Microsoft Shell Controls And Automation設定引用項目\n\n    Dim mySh As Shell32.Shell\n\n    Set mySh = CreateObject(\"Shell.Application\")\n\n    mySh.Open fileName      '任意的資料夾或檔案\n\n    Set mySh = Nothing              '釋放物件\n\nEnd Function\n\n\n\n'讀取檔案\n\n'記得設定Microsoft Scripting Runtime設定引用項目\n\nFunction ReadFile(ByVal infilename As String)\n\n\n\n    Dim myFSO As Scripting.FileSystemObject\n\n    Dim myTxt As Scripting.TextStream\n\n    Dim myStr As String\n\n    Dim resultString() As Variant\n\n    ReDim resultString(65536)\n\n    Dim rowNumber As Integer\n\n    rowNumber = 0\n\n\n\n    Set myFSO = CreateObject(\"Scripting.FileSystemObject\")\n\n    '指定檔案名稱\n\n    Set myTxt = myFSO.OpenTextFile(fileName:=infilename, _\n\n                                   IOMode:=ForReading)\n\n    With myTxt\n\n        Do Until .AtEndOfStream\n\n            resultString(rowNumber) = CStr(.ReadLine)\n\n            rowNumber = rowNumber + 1\n\n        Loop\n\n        .Close\n\n    End With\n\n    'Debug.Print rowNumber\n\n    ReDim Preserve resultString(rowNumber)\n\n    Set myTxt = Nothing                            '釋放物件\n\n    Set myFSO = Nothing\n\n    ReadFile = resultString\n\n\n\nEnd Function\n\n\n\n'列出檔案清單\n\n'depth=0\n\nFunction RetrivalFileList(ByVal strDir As String, ByRef myRange As Range, ByRef depth As Integer)\n\n    Dim thePath As String\n\n    Dim strSdir As String\n\n    Dim theDirs As Scripting.Folders\n\n    Dim theDir As Scripting.Folder\n\n    Dim theFile As Scripting.File\n\n    Dim myFSO As Scripting.FileSystemObject\n\n    Dim subFolderCount As Integer\n\n\n\n    Set myFSO = New Scripting.FileSystemObject\n\n    If Right(strDir, 1) <> \"\" Then strDir = strDir & \"\"\n\n    thePath = thePath & strDir\n\n\n\n    '列出第一層根目錄的檔案\n\n    If depth = 0 Then\n\n        For Each theFile In myFSO.getfolder(strDir).Files\n\n            myRange = theFile.path\n\n            myRange.Next = theFile.Size\n\n            myRange.Next.Next = theFile.DateLastModified\n\n            Set myRange = myRange.Offset(1, 0)\n\n        Next\n\n        depth = 1\n\n    End If\n\n\n\n    '尋找所有子目錄的檔案\n\n    Set theDirs = myFSO.getfolder(strDir).SubFolders\n\n    For Each theDir In theDirs\n\n        For Each theFile In theDir.Files\n\n            myRange = theFile.path\n\n            myRange.Next = theFile.Size\n\n            myRange.Next.Next = theFile.DateLastModified\n\n            Set myRange = myRange.Offset(1, 0)\n\n        Next\n\n        RetrivalFileList strDir:=theDir.path, myRange:=myRange, depth:=depth\n\n    Next\n\n    Set myFSO = Nothing\n\nEnd Function\n\n\n\n\n\n'列出檔案清單\n\n'depth=0\n\nFunction RetrivalFileListToArrary(ByVal strDir As String, ByRef depth As Integer)\n\n    Dim thePath As String\n\n    Dim strSdir As String\n\n    Dim theDirs As Scripting.Folders\n\n    Dim theDir As Scripting.Folder\n\n    Dim theFile As Scripting.File\n\n    Dim myFSO As Scripting.FileSystemObject\n\n    Dim subFolderCount As Integer\n\n    Dim fileList() As Variant\n\n    Dim counter As Long\n\n\n\n    ReDim fileList(65536)\n\n    counter = 0\n\n\n\n    Set myFSO = New Scripting.FileSystemObject\n\n    If Right(strDir, 1) <> \"\" Then strDir = strDir & \"\"\n\n    thePath = thePath & strDir\n\n\n\n    '列出第一層根目錄的檔案\n\n    If depth = 0 Then\n\n        For Each theFile In myFSO.getfolder(strDir).Files\n\n            fileList(counter) = theFile.path\n\n            counter = counter + 1\n\n        Next\n\n        depth = 1\n\n    End If\n\n\n\n    '尋找所有子目錄的檔案\n\n    Set theDirs = myFSO.getfolder(strDir).SubFolders\n\n    For Each theDir In theDirs\n\n        For Each theFile In theDir.Files\n\n            fileList(counter) = theFile.path\n\n            counter = counter + 1\n\n        Next\n\n        RetrivalFileListToArrary strDir:=theDir.path, depth:=depth\n\n    Next\n\n\n\n    Set myFSO = Nothing\n\n    If counter > 0 Then\n\n        counter = counter - 1\n\n    End If\n\n    ReDim Preserve fileList(counter)\n\n\n\n    RetrivalFileListToArrary = fileList\n\nEnd Function\n\n\n\n\n\n'列出所有子目錄名稱大小及最後修改日期\n\nFunction RetrivalAllSubFolderList(ByVal strDir As String, ByRef myRange As Range)\n\n    Dim thePath As String\n\n    Dim strSdir As String\n\n    Dim theDirs As Scripting.Folders\n\n    Dim theDir As Scripting.Folder\n\n    Dim theFile As Scripting.File\n\n    Dim myFSO As Scripting.FileSystemObject\n\n    Dim subFolderCount As Integer\n\n\n\n    Set myFSO = New Scripting.FileSystemObject\n\n    If Right(strDir, 1) <> \"\" Then strDir = strDir & \"\"\n\n    thePath = thePath & strDir\n\n\n\n    '尋找所有子目錄\n\n    Set theDirs = myFSO.getfolder(strDir).SubFolders\n\n    For Each theDir In theDirs\n\n        myRange = theDir.path\n\n        myRange.Next = theDir.Size\n\n        myRange.Next.Next = theDir.DateLastModified\n\n        Set myRange = myRange.Offset(1, 0)\n\n        RetrivalAllSubFolderList strDir:=theDir.path, myRange:=myRange\n\n    Next\n\n    Set myFSO = Nothing\n\nEnd Function\n\n\n\n'存檔並取得檔名\n\nFunction SaveAs(initialName As String) As String\n\n    On Error GoTo EndNow\n\n    With Application.FileDialog(msoFileDialogSaveAs)\n\n        .AllowMultiSelect = False\n\n        .ButtonName = \"&Save As\"\n\n        .InitialFileName = initialName\n\n        .Title = \"File Save As\"\n\n        .Show\n\n        SaveAs = .SelectedItems(1)\n\n    End With\n\nEndNow:\n\nEnd Function\n\n\n\n'取得磁碟機類型\n\n'用法\n\n'   strDriveType = GetDriveType(objDrive.drivetype)\n\n'   If Not objDrive.IsReady Then\n\n'      MsgBox strDriveType + \"[ \" + Mid(ComboBox2.Text, 1, 1) + \" ]尚未備妥，無法轉換\", vbOKOnly + vbExclamation, \"提示訊息\"\n\n'      Exit Function\n\n'   End If\n\nPublic Function GetDriveType(ByVal nType As Long) As String\n\n    Select Case nType\n\n    Case Unknown\n\n        GetDriveType = \"無從判斷\"\n\n    Case Removable\n\n        GetDriveType = \"磁碟機\"\n\n    Case Fixed\n\n        GetDriveType = \"硬碟\"\n\n    Case Remote\n\n        GetDriveType = \"網路磁碟機\"\n\n    Case CDRom\n\n        GetDriveType = \"光碟機\"\n\n    Case RamDisk\n\n        GetDriveType = \"RamDisk\"\n\n    End Select\n\nEnd Function\n\n\n\n'檢查磁碟機是否存在\n\n'用法\n\n'If ChkDrive(strFile) Then\n\n'      If Dir(strFile) = \"\" Then\n\n'         MsgBox \"找不到資料檔\" + strFile, vbOKOnly + vbExclamation, \"提示訊息\"\n\n'         Exit Sub\n\n'      End If\n\n'   Else\n\n'      MsgBox \"磁碟機未備妥\", vbOKOnly + vbExclamation, \"提示訊息\"\n\n'      Exit Sub\n\n'   End If\n\nPublic Function ChkDrive(ByVal drive As String) As Boolean\n\n    drive = Left(drive, 1) + \":\\\"\n\n    On Error GoTo nodisk:\n\n    Dir drive\n\n    ChkDrive = True\n\n    Exit Function\n\n\n\nnodisk:\n\n    If Err.Number = \"52\" Then\n\n        ChkDrive = False\n\n        Exit Function\n\n    End If\n\nEnd Function\n\n\n\n'存檔並取得檔名\n\n'用法\n\n'    filenameKeyIn = FileIOUtility.SaveAsOtherType(tableName)\n\n'    FileIOUtility.WriteFile filename:=filenameKeyIn, content:=createSql\n\n'    MsgBox \"建立完成!請到 \" & filenameKeyIn & \" 取檔\"\n\nFunction SaveAsOtherType(initialName As String) As String\n\n    On Error Resume Next\n\n    Dim FileSelected As String\n\n\n\n    FileSelected = Application.GetSaveAsFilename(InitialFileName:=initialName, _\n\n                                                 FileFilter:=\"sql Files (*.sql), *.sql\", _\n\n                                                 Title:=\"Save SQL as\")\n\n    If Not FileSelected <> \"False\" Then\n\n        Exit Function\n\n    End If\n\n    If FileSelected <> \"False\" Then\n\n        SaveAsOtherType = FileSelected\n\n        Exit Function\n\n    End If\n\nEnd Function\n\n\n\n'把檔案讀取到workbook\n\n'用法\n\n'讀取來源檔案\n\n'   On Error GoTo NotFindFile\n\n'   LoadTxt filename:=Application.GetOpenFilename(\"所有檔案,*.*\", , \"開啟交易明細規格(長度：130)\"), TargetSheet:=Sheets(\"來源格式檔案\")\n\nSub LoadTxt(fileName As String, TargetSheet As Worksheet)\n\n    Dim arrStr() As String, InputStr As String\n\n    Dim Fn As Variant\n\n    Dim i As Integer\n\n\n\n    Fn = FreeFile\n\n\n\n    Open fileName For Input As #Fn    '開啟檔案\n\n    Application.ScreenUpdating = False    '畫面暫停更新\n\n    i = 1\n\n    While Not EOF(Fn)\n\n        Line Input #Fn, InputStr    '從檔案讀出一列,\n\n        If Len(InputStr) > 0 Then    '略過無字串的空行\n\n\n\n            TargetSheet.Cells(i, 1) = InputStr    '把字串存到儲存格\n\n\n\n        End If\n\n        i = i + 1\n\n    Wend\n\n    Application.ScreenUpdating = True    '畫面恢復更新\n\n    Close #Fn\n\n\n\nEnd Sub\n\n\n\n'寫入CSV檔案(使用CurrentRegion)\n\nFunction WriteToCsv(ByVal fileName As String, ByVal sheetName As String, ByVal x As Integer, ByVal y As Integer)\n\n'Microsoft Forms 2.0 Object Library 設定引用項目(C:\\WINDOWS\\system32\\FM20.DLL)\n\n'Microsoft Scripting Runtime 設定引用項目\n\n    Dim myFileName As String\n\n    Dim myDataobj As DataObject\n\n    Dim myFSO As Scripting.FileSystemObject\n\n    Dim myTst As Scripting.TextStream\n\n    Dim myStr As String\n\n    Dim myDataRng As Range\n\n    myFileName = fileName                  '儲存檔案名\n\n    On Error Resume Next\n\n    Kill myFileName     '刪除同名的檔案\n\n    On Error GoTo 0\n\n    '指定儲存的表\n\n    Set myDataRng = Worksheets(sheetName).Cells(y, x).CurrentRegion\n\n    '將資料送到剪貼簿\n\n    myDataRng.Copy\n\n    '從剪貼簿送到字串變數\n\n    Set myDataobj = New DataObject\n\n    myDataobj.GetFromClipboard\n\n    myStr = myStr & Replace(myDataobj.GetText, vbTab, \",\")\n\n    Set myDataobj = Nothing                       '釋放物件\n\n    '從字串變數送到檔案\n\n    Set myFSO = New Scripting.FileSystemObject\n\n    Set myTst = myFSO.OpenTextFile( _\n\n                fileName:=myFileName, _\n\n                IOMode:=ForWriting, Create:=True)\n\n    myTst.Write myStr\n\n    myTst.Close\n\n    Set myTst = Nothing                           '釋放物件\n\n    Set myFSO = Nothing\n\nEnd Function\n\n\n\n'寫入CSV檔案(使用指定的Range)\n\nFunction WriteToCsvWithSelectRange(ByVal fileName As String, ByVal sheetName As String, ByVal selectRange As Range)\n\n'Microsoft Forms 2.0 Object Library 設定引用項目\n\n'Microsoft Scripting Runtime 設定引用項目\n\n    Dim myFileName As String\n\n    Dim myDataobj As DataObject\n\n    Dim myFSO As Scripting.FileSystemObject\n\n    Dim myTst As Scripting.TextStream\n\n    Dim myStr As String\n\n    Dim myDataRng As Range\n\n    myFileName = fileName                  '儲存檔案名\n\n    On Error Resume Next\n\n    Kill myFileName     '刪除同名的檔案\n\n    On Error GoTo 0\n\n    '指定儲存的表\n\n    Set myDataRng = selectRange\n\n    '將資料送到剪貼簿\n\n    myDataRng.Copy\n\n    '從剪貼簿送到字串變數\n\n    Set myDataobj = New DataObject\n\n    myDataobj.GetFromClipboard\n\n    myStr = myStr & Replace(myDataobj.GetText, vbTab, \",\")\n\n    Set myDataobj = Nothing                       '釋放物件\n\n    '從字串變數送到檔案\n\n    Set myFSO = New Scripting.FileSystemObject\n\n    Set myTst = myFSO.OpenTextFile( _\n\n                fileName:=myFileName, _\n\n                IOMode:=ForWriting, Create:=True)\n\n    myTst.Write myStr\n\n    myTst.Close\n\n    Set myTst = Nothing                           '釋放物件\n\n    Set myFSO = Nothing\n\nEnd Function\n\n\n\n'建立資料夾(如果已經存在會先刪除)\n\nFunction MakeDir(ByVal folderName As String)\n\n    Dim fso As Scripting.FileSystemObject\n\n    Set fso = New Scripting.FileSystemObject\n\n    If fso.FolderExists(folderName) = True Then\n\n        fso.DeleteFolder folderName, force:=True\n\n        fso.CreateFolder folderName\n\n    Else\n\n        fso.CreateFolder folderName\n\n    End If\n\n    Set fso = Nothing\n\nEnd Function\n\n\n\n'判斷檔案是否存在\n\nFunction FileExist(ByVal fileName As String)\n\n    Dim existFile As Boolean\n\n    Dim fso As Scripting.FileSystemObject\n\n    Set fso = New Scripting.FileSystemObject\n\n    existFile = fso.FileExists(fileName)\n\n    Set fso = Nothing\n\n    FileExist = existFile\n\nEnd Function\n\n\n\n'取得檔案資料夾\n\nFunction GetFileFolder(ByVal fileName As String)\n\n    Dim fName As String\n\n    Dim existFile As Boolean\n\n    Dim fso As Scripting.FileSystemObject\n\n    Dim myFile As File\n\n\n\n    Set fso = New Scripting.FileSystemObject\n\n    existFile = fso.FileExists(fileName)\n\n    If existFile = False Then\n\n        GetFileFolder = \"\"\n\n        Set myFile = Nothing\n\n        Set fso = Nothing\n\n        Exit Function\n\n    End If\n\n\n\n    Set myFile = fso.GetFile(fileName)\n\n    GetFileFolder = myFile.ParentFolder\n\n    Set myFile = Nothing\n\n    Set fso = Nothing\n\nEnd Function\n\n\n\n'取得檔案名稱(不含資料夾路徑)\n\nFunction GetFileNameWithoutFolder(ByVal fileName As String)\n\n    Dim fName As String\n\n    Dim existFile As Boolean\n\n    Dim fso As Scripting.FileSystemObject\n\n    Dim myFile As File\n\n\n\n    Set fso = New Scripting.FileSystemObject\n\n    existFile = fso.FileExists(fileName)\n\n    If existFile = False Then\n\n        GetFileNameWithoutFolder = \"\"\n\n        Set myFile = Nothing\n\n        Set fso = Nothing\n\n        Exit Function\n\n    End If\n\n\n\n    Set myFile = fso.GetFile(fileName)\n\n    GetFileNameWithoutFolder = fso.GetFileName(fileName)\n\n    Set myFile = Nothing\n\n    Set fso = Nothing\n\nEnd Function\n\n\n\n'取得檔案名稱(不含資料夾路徑及副檔名)\n\nFunction GetFileNameWithoutFolderAndExt(ByVal fileName As String)\n\n    Dim fName As String\n\n    Dim existFile As Boolean\n\n    Dim fso As Scripting.FileSystemObject\n\n    Dim myFile As File\n\n\n\n    Set fso = New Scripting.FileSystemObject\n\n    existFile = fso.FileExists(fileName)\n\n    If existFile = False Then\n\n        GetFileNameWithoutFolderAndExt = \"\"\n\n        Set myFile = Nothing\n\n        Set fso = Nothing\n\n        Exit Function\n\n    End If\n\n\n\n    Set myFile = fso.GetFile(fileName)\n\n    GetFileNameWithoutFolderAndExt = fso.GetBaseName(fileName)\n\n    Set myFile = Nothing\n\n    Set fso = Nothing\n\nEnd Function\n\n\n\n'取得檔案副檔名\n\nFunction GetFileNameExtension(ByVal fileName As String)\n\n    Dim fName As String\n\n    Dim existFile As Boolean\n\n    Dim fso As Scripting.FileSystemObject\n\n\n\n    Set fso = New Scripting.FileSystemObject\n\n    existFile = fso.FileExists(fileName)\n\n    If existFile = False Then\n\n        GetFileNameExtension = \"\"\n\n        Set fso = Nothing\n\n        Exit Function\n\n    End If\n\n\n\n    GetFileNameExtension = fso.GetExtensionName(fileName)\n\n    Set fso = Nothing\n\nEnd Function\n\n\n\n'複製檔案\n\nFunction CopyFile(ByVal fileNameSource As String, ByVal fileNameDest As String)\n\n    Dim existFile As Boolean\n\n    Dim fso As Scripting.FileSystemObject\n\n    Set fso = New Scripting.FileSystemObject\n\n\n\n\n\n    existFile = fso.FileExists(fileNameSource)\n\n    If existFile = False Then\n\n        MsgBox \"來源檔案不存在!\"\n\n        Set fso = Nothing\n\n        Exit Function\n\n    End If\n\n\n\n    fso.CopyFile fileNameSource, fileNameDest, True\n\n    Set fso = Nothing\n\nEnd Function\n\n\n\n'刪除資料夾下所有的檔案\n\nFunction DelFolder(ByVal folderName As String)\n\n    Call Shell(\"cmd.exe /C DEL /S /Q \"\"\" & folderName & \"\"\"\", vbHide)\n\nEnd Function\n\n\n\n'複製資料夾結構\n\nFunction CopyFolderStructure(ByVal sourcefolderName As String, ByVal destFolderName As String)\n\n    Call Shell(\"cmd.exe /c xcopy /T /E \"\"\" & sourcefolderName & \"\"\" \"\"\" & destFolderName & \"\"\"\", vbHide)\n\nEnd Function\n\n\n\n'開啟資料夾\n\nFunction OpenFolder(ByVal folderName As String)\n\n    Call Shell(\"cmd.exe /c start \"\"\"\" \"\"\" & folderName & \"\"\"\", vbHide)\n\nEnd Function\n\n\n\n'讀取檔案\n\n'記得設定Microsoft Scripting Runtime設定引用項目\n\nFunction ReadFileToString(ByVal infilename As String)\n\n\n\n    Dim myFSO As Scripting.FileSystemObject\n\n    Dim myTxt As Scripting.TextStream\n\n    Dim myStr As String\n\n    Dim resultString As String\n\n\n\n    Set myFSO = CreateObject(\"Scripting.FileSystemObject\")\n\n    '指定檔案名稱\n\n    Set myTxt = myFSO.OpenTextFile(fileName:=infilename, _\n\n                                   IOMode:=ForReading)\n\n    With myTxt\n\n        Do Until .AtEndOfStream\n\n            resultString = resultString + CStr(.ReadLine)\n\n        Loop\n\n        .Close\n\n    End With\n\n\n\n    Set myTxt = Nothing                            '釋放物件\n\n    Set myFSO = Nothing\n\n    ReadFileToString = resultString\n\n\n\nEnd Function\n\n", "content_b64": ""}, {"name": "FileInfo.bas", "path": "模組/Others/FileInfo.bas", "content": "Attribute VB_Name = \"FileInfo\"\n\nOption Explicit\n\n\n\nSub ListFileInfo()\n\n    Dim selectFolder As String\n\n    \n\n    selectFolder = Application.InputBox(\"請輸入資料夾路徑:\", _\n\n                \"將會列出檔案路徑、大小及時間\")\n\n    \n\n    If selectFolder = \"\" Then\n\n        MsgBox \"請輸入路徑\"\n\n        Exit Sub\n\n    End If\n\n    \n\n    Application.ScreenUpdating = False\n\n    Call ListFiles(selectFolder)\n\n    Call ListSubFolders(selectFolder)\n\n    MsgBox \"列出檔案資訊完畢!\"\n\n    Application.ScreenUpdating = True\n\nEnd Sub\n\n\n\n\n\nSub SetHeader(ByVal sheetIndex As Integer)\n\n    '清除內容並將將儲存格格式設為文字格式\n\n    Dim pt As Range\n\n    Dim myRange As Range\n\n    Dim i As Integer\n\n    Set pt = ThisWorkbook.Sheets(sheetIndex).Range(\"a2\")\n\n    For i = 1 To 3\n\n        pt.Worksheet.Columns(i).ClearContents\n\n    Next\n\n    Set myRange = ThisWorkbook.Sheets(sheetIndex).Range(\"A1:C65536\")\n\n    myRange.NumberFormatLocal = \"@\"\n\n            \n\n    'SetHeader\n\n    ThisWorkbook.Sheets(sheetIndex).Range(\"A1\").Value = \"路徑\"\n\n    ThisWorkbook.Sheets(sheetIndex).Range(\"B1\").Value = \"大小\"\n\n    ThisWorkbook.Sheets(sheetIndex).Range(\"C1\").Value = \"修改時間\"\n\nEnd Sub\n\n\n\nSub ListFiles(ByVal theDir As String)\n\n    Dim pt As Range\n\n                \n\n    Set pt = Sheet1.Range(\"a2\")\n\n    Call SetHeader(1)\n\n                \n\n    If Len(Dir(theDir, vbDirectory)) > 0 Then\n\n        If (GetAttr(theDir) And vbDirectory) = vbDirectory Then\n\n            Call FileIOUtility.RetrivalFileList(theDir, pt, 0)\n\n        End If\n\n    End If\n\n    \n\n    pt.Worksheet.Columns(\"A:B\").AutoFit\n\nEnd Sub\n\n\n\nSub ListSubFolders(ByVal theDir As String)\n\n    Dim pt As Range\n\n                    \n\n    Set pt = Sheet2.Range(\"a2\")\n\n    Call SetHeader(2)\n\n    \n\n    If Len(Dir(theDir, vbDirectory)) > 0 Then\n\n        If (GetAttr(theDir) And vbDirectory) = vbDirectory Then\n\n        Call FileIOUtility.RetrivalAllSubFolderList(theDir, pt)\n\n        End If\n\n    End If\n\n    \n\n    pt.Worksheet.Columns(\"A:B\").AutoFit\n\nEnd Sub\n\n\n\n\n\n", "content_b64": ""}, {"name": "LoadConfigFile.bas", "path": "模組/Others/LoadConfigFile.bas", "content": "Attribute VB_Name = \"LoadConfigFile\"\nOption Explicit\n'*************************************************************************************\n'專案名稱: 雪梨分行APRA報表\n'功能描述: 讀取設定檔(C:\\config\\Ors_AP.txt)\n'\n'版權所有: Dunk\n'程式撰寫: Dunk\n'撰寫日期：2015/8/26\n'\n'改版日期:\n'改版備註:\n'*************************************************************************************\n'帳號\nPublic ID As String\n'密碼\nPublic PWD As String\n\n\n\nSub LoadConfig()\n Dim arrStr() As String, InputStr As String\n Dim i As Integer, j As Integer\n Dim Fn As Variant\n Dim myConfigFile As String\n\n Fn = FreeFile\n \n '組態檔位置\n myConfigFile = \"C:\\config\\Ors_AP.txt\"\n \n On Error GoTo Err\n Open myConfigFile For Input As #Fn\nApplication.ScreenUpdating = False '畫面暫停更新\ni = 1: j = 1\n While Not EOF(Fn)\n Line Input #Fn, InputStr '從檔案讀出一列,\nIf Len(InputStr) > 0 Then '略過無字串的空行\narrStr = Split(InputStr, \"=\")\n '把讀入的文字列依逗號分成數個字串, 置於 arrStr 陣列裡\nFor j = 1 To UBound(arrStr)\n    \n  If arrStr(0) = \"ID\" Then\n    ID = arrStr(1)\n  End If\n  If arrStr(0) = \"PWD\" Then\n    PWD = arrStr(1)\n  End If\nNext j\n End If\n i = i + 1\n Wend\n Application.ScreenUpdating = True '畫面恢復更新\nClose #Fn\nGoTo Final\n\nErr:\n Debug.Print \"Config File Not Exist!\" & myConfigFile\n \nFinal:\n End Sub\n", "content_b64": ""}, {"name": "LookMutiInCell.bas", "path": "模組/Others/LookMutiInCell.bas", "content": "Attribute VB_Name = \"LookMutiInCell\"\nOption Explicit\n'*************************************************************************************\n'專案名稱: 底層元件\n'功能描述: 查詢多值在同一儲存格\n'https://www.extendoffice.com/documents/excel/2706-excel-vlookup-return-multiple-values-in-one-cell.html\n'版權所有:\n'程式撰寫: Dunk\n'撰寫日期：2023/2/17\n'\n'改版日期:\n'改版備註:\n'\n'*************************************************************************************\n'查詢多欄在同一格(全部符合)\nFunction ConcatenateIf(CriteriaRange As Range, Condition As Variant, ConcatenateRange As Range, Optional Separator As String = \",\") As Variant\n    'Updateby Extendoffice\n    Dim xResult As String\n    Dim i As Long\n    On Error Resume Next\n    If CriteriaRange.Count <> ConcatenateRange.Count Then\n        ConcatenateIf = CVErr(xlErrRef)\n        Exit Function\n    End If\n    For i = 1 To CriteriaRange.Count\n        If CriteriaRange.Cells(i).Value = Condition Then\n            xResult = xResult & Separator & ConcatenateRange.Cells(i).Value\n        End If\n    Next i\n    If xResult <> \"\" Then\n        xResult = VBA.Mid(xResult, VBA.Len(Separator) + 1)\n    End If\n    ConcatenateIf = xResult\nExit Function\nEnd Function\n\n'查詢多欄在同一格(部分符合)\nFunction ConcatenateIfPartial(CriteriaRange As Range, Condition As Variant, ConcatenateRange As Range, Optional Separator As String = \",\") As Variant\n    'Updateby Extendoffice\n    Dim xResult As String\n    Dim i As Long\n    On Error Resume Next\n    If CriteriaRange.Count <> ConcatenateRange.Count Then\n        ConcatenateIfPartial = CVErr(xlErrRef)\n        Exit Function\n    End If\n    For i = 1 To CriteriaRange.Count\n        If InStrRev(CriteriaRange.Cells(i).Value, Condition) > 0 Then\n            xResult = xResult & Separator & ConcatenateRange.Cells(i).Value\n        End If\n    Next i\n    If xResult <> \"\" Then\n        xResult = VBA.Mid(xResult, VBA.Len(Separator) + 1)\n    End If\n    ConcatenateIfPartial = xResult\nExit Function\nEnd Function\n", "content_b64": ""}, {"name": "ODBCUtility.bas", "path": "模組/Others/ODBCUtility.bas", "content": "Attribute VB_Name = \"ODBCUtility\"\nOption Explicit\n'*************************************************************************************\n'專案名稱: 雪梨分行APRA報表\n'功能描述: 讀取ODBC資料源\n'http://stackoverflow.com/questions/164967/how-can-i-enumerate-the-list-of-dsns-set-up-on-a-computer-using-vba\n'版權所有: Dunk\n'程式撰寫: Dunk\n'撰寫日期：2016/5/30\n'\n'改版日期:\n'改版備註:\n'*************************************************************************************\n  Private Declare Function RegOpenKeyEx Lib \"advapi32.dll\" _\n      Alias \"RegOpenKeyExA\" _\n      (ByVal hKey As Long, _\n      ByVal lpSubKey As String, _\n      ByVal ulOptions As Long, _\n      ByVal samDesired As Long, phkResult As Long) As Long\n\n  Private Declare Function RegEnumValue Lib \"advapi32.dll\" _\n      Alias \"RegEnumValueA\" _\n      (ByVal hKey As Long, _\n      ByVal dwIndex As Long, _\n      ByVal lpValueName As String, _\n      lpcbValueName As Long, _\n      ByVal lpReserved As Long, _\n      lpType As Long, _\n      lpData As Any, _\n      lpcbData As Long) As Long\n\n  Private Declare Function RegCloseKey Lib \"advapi32.dll\" _\n      (ByVal hKey As Long) As Long\n\n  Const HKEY_CLASSES_ROOT = &H80000000\n  Const HKEY_CURRENT_USER = &H80000001\n  Const HKEY_LOCAL_MACHINE = &H80000002\n  Const HKEY_USERS = &H80000003\n\n  Const ERROR_SUCCESS = 0&\n\n  Const SYNCHRONIZE = &H100000\n  Const STANDARD_RIGHTS_READ = &H20000\n  Const STANDARD_RIGHTS_WRITE = &H20000\n  Const STANDARD_RIGHTS_EXECUTE = &H20000\n  Const STANDARD_RIGHTS_REQUIRED = &HF0000\n  Const STANDARD_RIGHTS_ALL = &H1F0000\n  Const KEY_QUERY_VALUE = &H1\n  Const KEY_SET_VALUE = &H2\n  Const KEY_CREATE_SUB_KEY = &H4\n  Const KEY_ENUMERATE_SUB_KEYS = &H8\n  Const KEY_NOTIFY = &H10\n  Const KEY_CREATE_LINK = &H20\n  Const KEY_READ = ((STANDARD_RIGHTS_READ Or _\n                    KEY_QUERY_VALUE Or _\n                    KEY_ENUMERATE_SUB_KEYS Or _\n                    KEY_NOTIFY) And _\n                    (Not SYNCHRONIZE))\n\n  Const REG_DWORD = 4\n  Const REG_BINARY = 3\n  Const REG_SZ = 1\n  \n  '設定ODBC連線資料源\n  Public Function GetConnectedODBC()\n  Dim odbcs As String\n  Dim resultODBC As String\n  Dim arrStr() As String\n  Dim j As Integer\n  Dim pos As Integer\n  odbcs = GetSystemDSN()\n  \n  If Len(odbcs) = 0 Then\n    GetConnectedODBC = \"\"\n    Exit Function\n  End If\n  \n  If Len(odbcs) > 0 Then\n        arrStr = Split(odbcs, \"!\")\n  End If\n  \n  For j = 0 To UBound(arrStr)\n  pos = InStr(arrStr(j), \"ORSAUSY\")\n    If pos > 0 Then\n        GetConnectedODBC = arrStr(j)\n        Exit Function\n    End If\n  Next j\n  GetConnectedODBC = \"\"\n  End Function\n  \n  '列出USER DSN ODBC\n  Public Function GetUserDSN()\n     Dim lngKeyHandle As Long\n     Dim lngResult As Long\n     Dim lngCurIdx As Long\n     Dim strValue As String\n     Dim lngValueLen As Long\n     Dim lngData As Long\n     Dim lngDataLen As Long\n     Dim strResult As String\n\n     lngResult = RegOpenKeyEx(HKEY_CURRENT_USER, _\n             \"SOFTWARE\\ODBC\\ODBC.INI\\ODBC Data Sources\", _\n              0&, _\n              KEY_READ, _\n              lngKeyHandle)\n\n     If lngResult <> ERROR_SUCCESS Then\n         MsgBox \"Cannot open key\"\n         Exit Function\n     End If\n\n     lngCurIdx = 0\n     Do\n        lngValueLen = 2000\n        strValue = String(lngValueLen, 0)\n        lngDataLen = 2000\n\n        lngResult = RegEnumValue(lngKeyHandle, _\n                                 lngCurIdx, _\n                                 ByVal strValue, _\n                                 lngValueLen, _\n                                 0&, _\n                                 REG_DWORD, _\n                                 ByVal lngData, _\n                                 lngDataLen)\n        lngCurIdx = lngCurIdx + 1\n\n        If lngResult = ERROR_SUCCESS Then\n           'strResult = strResult & lngCurIdx & \": \" & Left(strValue, lngValueLen) & vbCrLf\n           strResult = strResult & Left(strValue, lngValueLen) & \"!\"\n        End If\n     Loop While lngResult = ERROR_SUCCESS\n     Call RegCloseKey(lngKeyHandle)\n     \n     GetUserDSN = strResult\n     'Call MsgBox(strResult, vbInformation)\n  End Function\n  '列出SYSTEM DSN ODBC\n  Public Function GetSystemDSN()\n     Dim lngKeyHandle As Long\n     Dim lngResult As Long\n     Dim lngCurIdx As Long\n     Dim strValue As String\n     Dim lngValueLen As Long\n     Dim lngData As Long\n     Dim lngDataLen As Long\n     Dim strResult As String\n\n     lngResult = RegOpenKeyEx(HKEY_LOCAL_MACHINE, _\n             \"SOFTWARE\\ODBC\\ODBC.INI\\ODBC Data Sources\", _\n              0&, _\n              KEY_READ, _\n              lngKeyHandle)\n\n     If lngResult <> ERROR_SUCCESS Then\n         MsgBox \"Cannot open key\"\n         Exit Function\n     End If\n\n     lngCurIdx = 0\n     Do\n        lngValueLen = 2000\n        strValue = String(lngValueLen, 0)\n        lngDataLen = 2000\n\n        lngResult = RegEnumValue(lngKeyHandle, _\n                                 lngCurIdx, _\n                                 ByVal strValue, _\n                                 lngValueLen, _\n                                 0&, _\n                                 REG_DWORD, _\n                                 ByVal lngData, _\n                                 lngDataLen)\n        lngCurIdx = lngCurIdx + 1\n\n        If lngResult = ERROR_SUCCESS Then\n           'strResult = strResult & lngCurIdx & \": \" & Left(strValue, lngValueLen) & vbCrLf\n           strResult = strResult & Left(strValue, lngValueLen) & \"!\"\n        End If\n     Loop While lngResult = ERROR_SUCCESS\n     Call RegCloseKey(lngKeyHandle)\n     \n     GetSystemDSN = strResult\n     'Call MsgBox(strResult, vbInformation)\n  End Function\n\n", "content_b64": ""}, {"name": "PasswordRemoveUtil.bas", "path": "模組/Others/PasswordRemoveUtil.bas", "content": "Attribute VB_Name = \"PasswordRemoveUtil\"\nOption Explicit\n'*************************************************************************************\n'專案名稱: 全委帳務處理\n'功能描述: 將excel檔案的密碼移除\n'\n'版權所有: Dunk\n'程式撰寫: Dunk\n'撰寫日期：2017/7/25\n'\n'改版日期:\n'改版備註:\n'\n'*************************************************************************************\n\n'將原有密碼移除後，以原檔名存檔\nFunction RemovePassord(ByVal fileName As String, ByVal pwd As String)\n    Workbooks.Open fileName:= _\n                   fileName, Password:=pwd\n    ActiveWorkbook.SaveAs fileName:= _\n                          fileName, _\n                          FileFormat:=xlExcel8, Password:=\"\", WriteResPassword:=\"\", _\n                          ReadOnlyRecommended:=False, CreateBackup:=False\n    ActiveWindow.Close\nEnd Function\n\n", "content_b64": ""}, {"name": "PdfUtility.bas", "path": "模組/Others/PdfUtility.bas", "content": "Attribute VB_Name = \"PdfUtility\"\nOption Explicit\n'*************************************************************************************\n'專案名稱: 底層元件\n'功能描述: PDF工具\n'Reference required: \"VBE - Tools - References - Acrobat\n'版權所有: Dunk\n'程式撰寫: Dunk\n'撰寫日期：2018/3/14\n'\n'改版日期:\n'改版備註: 2018/4/19 增加將pdf存成其他格式\n'\n'*************************************************************************************\n'Sub test()\n''    MergePDFs \"D:\\基金報表\\20180312\", _\n '     '                   \"Crystal Reports_ G202.pdf\", _\n '     '                   \"D:\\基金報表\\20180312\\黃金報表.pdf\"\n'    SplitPdf \"D:\\基金報表\\20180312\\MergedFile.pdf\"\n'End Sub\n\n'合併pdf檔案，檔案清單用逗號分隔\nFunction MergePDFs(ByVal sourceFolder As String, ByVal fileList As String, ByVal destFile As String)\n' ZVI:2013-08-27 http://www.vbaexpress.com/forum/showthread.php?47310-Need-code-to-merge-PDF-files-in-a-folder-using-adobe-acrobat-X\n' Reference required: \"VBE - Tools - References - Acrobat\"\n\n    Dim a As Variant, i As Long, n As Long, ni As Long, p As String\n    Dim AcroApp As New Acrobat.AcroApp, PartDocs() As Acrobat.CAcroPDDoc\n\n    If Right(sourceFolder, 1) = \"\\\" Then p = sourceFolder Else p = sourceFolder & \"\\\"\n    a = Split(fileList, \",\")\n    ReDim PartDocs(0 To UBound(a))\n\n    On Error GoTo ErrHandler\n    If Len(Dir(destFile)) Then Kill destFile\n    For i = 0 To UBound(a)\n        ' Check PDF file presence\n        If Dir(p & Trim(a(i))) = \"\" Then\n            MsgBox \"File not found\" & vbLf & p & a(i), vbExclamation, \"Canceled\"\n            Exit For\n        End If\n        ' Open PDF document\n        Set PartDocs(i) = CreateObject(\"AcroExch.PDDoc\")\n        PartDocs(i).Open p & Trim(a(i))\n        If i Then\n            ' Merge PDF to PartDocs(0) document\n            ni = PartDocs(i).GetNumPages()\n            If Not PartDocs(0).InsertPages(n - 1, PartDocs(i), 0, ni, True) Then\n                MsgBox \"Cannot insert pages of\" & vbLf & p & a(i), vbExclamation, \"Canceled\"\n            End If\n            ' Calc the number of pages in the merged document\n            n = n + ni\n            ' Release the memory\n            PartDocs(i).Close\n            Set PartDocs(i) = Nothing\n        Else\n            ' Calc the number of pages in PartDocs(0) document\n            n = PartDocs(0).GetNumPages()\n        End If\n    Next\n\n    If i > UBound(a) Then\n        ' Save the merged document to DestFile\n        If Not PartDocs(0).Save(PDSaveFull, destFile) Then\n            MsgBox \"Cannot save the resulting document\" & vbLf & destFile, vbExclamation, \"Canceled\"\n        End If\n    End If\n\nErrHandler:\n\n    ' Inform about error/success\n    If Err Then\n        MsgBox Err.Description, vbCritical, \"Error #\" & Err.Number\n    ElseIf i > UBound(a) Then\n        'MsgBox \"The resulting file is created:\" & vbLf & DestFile, vbInformation, \"Done\"\n    End If\n\n    ' Release the memory\n    If Not PartDocs(0) Is Nothing Then PartDocs(0).Close\n    Set PartDocs(0) = Nothing\n\n    ' Quit Acrobat application\n    AcroApp.Exit\n    Set AcroApp = Nothing\n\nEnd Function\n\n'合併pdf檔案，檔案清單用逗號分隔\nFunction MergePDFsWithList(ByRef fileList() As Variant, ByVal destFile As String)\n' ZVI:2013-08-27 http://www.vbaexpress.com/forum/showthread.php?47310-Need-code-to-merge-PDF-files-in-a-folder-using-adobe-acrobat-X\n' Reference required: \"VBE - Tools - References - Acrobat\"\n\n    Dim i As Long, n As Long, ni As Long\n    Dim AcroApp As New Acrobat.AcroApp, PartDocs() As Acrobat.CAcroPDDoc\n\n    ReDim PartDocs(0 To UBound(fileList))\n\n    On Error GoTo ErrHandler\n    If Len(Dir(destFile)) Then Kill destFile\n    For i = 0 To UBound(fileList)\n        ' Check PDF file presence\n        If Dir(fileList(i)) = \"\" Then\n            MsgBox \"File not found\" & vbLf & fileList(i), vbExclamation, \"Canceled\"\n            Exit For\n        End If\n        ' Open PDF document\n        Set PartDocs(i) = CreateObject(\"AcroExch.PDDoc\")\n        PartDocs(i).Open fileList(i)\n        If i Then\n            ' Merge PDF to PartDocs(0) document\n            ni = PartDocs(i).GetNumPages()\n            If Not PartDocs(0).InsertPages(n - 1, PartDocs(i), 0, ni, True) Then\n                MsgBox \"Cannot insert pages of\" & vbLf & fileList(i), vbExclamation, \"Canceled\"\n            End If\n            ' Calc the number of pages in the merged document\n            n = n + ni\n            ' Release the memory\n            PartDocs(i).Close\n            Set PartDocs(i) = Nothing\n        Else\n            ' Calc the number of pages in PartDocs(0) document\n            n = PartDocs(0).GetNumPages()\n        End If\n    Next\n\n    If i > UBound(fileList) Then\n        ' Save the merged document to DestFile\n        If Not PartDocs(0).Save(PDSaveFull, destFile) Then\n            MsgBox \"Cannot save the resulting document\" & vbLf & destFile, vbExclamation, \"Canceled\"\n        End If\n    End If\n\nErrHandler:\n\n    ' Inform about error/success\n    If Err Then\n        MsgBox Err.Description, vbCritical, \"Error #\" & Err.Number\n    ElseIf i > UBound(fileList) Then\n        'MsgBox \"The resulting file is created:\" & vbLf & DestFile, vbInformation, \"Done\"\n    End If\n\n    ' Release the memory\n    If Not PartDocs(0) Is Nothing Then PartDocs(0).Close\n    Set PartDocs(0) = Nothing\n\n    ' Quit Acrobat application\n    AcroApp.Exit\n    Set AcroApp = Nothing\n\nEnd Function\n'分割pdf檔案，一頁一個檔案\nFunction SplitPdf(ByVal sourceFileName As String)\n    Dim PDDoc As Acrobat.CAcroPDDoc, newPDF As Acrobat.CAcroPDDoc\n    Dim PDPage As Acrobat.CAcroPDPage\n    Dim thePDF As String, PNum, i As Long\n    Dim Result As Variant\n    Dim NewName, fixFormat As String\n    Dim resider As Integer\n    Set PDDoc = CreateObject(\"AcroExch.pdDoc\")\n    Result = PDDoc.Open(sourceFileName)\n    If Not Result Then\n        MsgBox \"Can't open file: \" & sourceFileName\n        Exit Function\n    End If\n\n    PNum = PDDoc.GetNumPages\n\n    resider = Len(PNum - 1)\n    fixFormat = \"\"\n    For i = 1 To resider\n        fixFormat = fixFormat & \"0\"\n    Next\n\n    For i = 0 To PNum - 1\n        Set newPDF = CreateObject(\"AcroExch.pdDoc\")\n        newPDF.Create\n        NewName = Replace(sourceFileName, \".pdf\", \"_\" & Format(CStr(i + 1), fixFormat) & \".pdf\")\n        newPDF.InsertPages -1, PDDoc, i, 1, 0\n        newPDF.Save 1, NewName\n        newPDF.Close\n        Set newPDF = Nothing\n    Next i\n\nEnd Function\n\n'將pdf存成其他格式\nFunction SavePDFAsOtherFormat(PDFPath As String, FileExtension As String)\n   \n    'Saves a PDF file as another format using Adobe Professional.\n   \n    'By Christos Samaras\n    'http://www.myengineeringworld.net\n   \n    'In order to use the macro you must enable the Acrobat library from VBA editor:\n    'Go to Tools -> References -> Adobe Acrobat xx.0 Type Library, where xx depends\n    'on your Acrobat Professional version (i.e. 9.0 or 10.0) you have installed to your PC.\n   \n    'Alternatively you can find it Tools -> References -> Browse and check for the path\n    'C:\\Program Files\\Adobe\\Acrobat xx.0\\Acrobat\\acrobat.tlb\n    'where xx is your Acrobat version (i.e. 9.0 or 10.0 etc.).\n   \n    Dim objAcroApp      As Acrobat.AcroApp\n    Dim objAcroAVDoc    As Acrobat.AcroAVDoc\n    Dim objAcroPDDoc    As Acrobat.AcroPDDoc\n    Dim objJSO          As Object\n    Dim boResult        As Boolean\n    Dim ExportFormat    As String\n    Dim NewFilePath     As String\n   \n    'Check if the file exists.\n    If Dir(PDFPath) = \"\" Then\n        MsgBox \"Cannot find the PDF file!\" & vbCrLf & \"Check the PDF path and retry.\", _\n                vbCritical, \"File Path Error\"\n        Exit Function\n    End If\n   \n    'Check if the input file is a PDF file.\n    If LCase(Right(PDFPath, 3)) <> \"pdf\" Then\n        MsgBox \"The input file is not a PDF file!\", vbCritical, \"File Type Error\"\n        Exit Function\n    End If\n   \n    'Initialize Acrobat by creating App object.\n    Set objAcroApp = CreateObject(\"AcroExch.App\")\n   \n    'Set AVDoc object.\n    Set objAcroAVDoc = CreateObject(\"AcroExch.AVDoc\")\n   \n    'Open the PDF file.\n    boResult = objAcroAVDoc.Open(PDFPath, \"\")\n       \n    'Set the PDDoc object.\n    Set objAcroPDDoc = objAcroAVDoc.GetPDDoc\n   \n    'Set the JS Object - Java Script Object.\n    Set objJSO = objAcroPDDoc.GetJSObject\n   \n    'Check the type of conversion.\n    Select Case LCase(FileExtension)\n        Case \"eps\": ExportFormat = \"com.adobe.acrobat.eps\"\n        Case \"html\", \"htm\": ExportFormat = \"com.adobe.acrobat.html\"\n        Case \"jpeg\", \"jpg\", \"jpe\": ExportFormat = \"com.adobe.acrobat.jpeg\"\n        Case \"jpf\", \"jpx\", \"jp2\", \"j2k\", \"j2c\", \"jpc\": ExportFormat = \"com.adobe.acrobat.jp2k\"\n        Case \"docx\": ExportFormat = \"com.adobe.acrobat.docx\"\n        Case \"doc\": ExportFormat = \"com.adobe.acrobat.doc\"\n        Case \"png\": ExportFormat = \"com.adobe.acrobat.png\"\n        Case \"ps\": ExportFormat = \"com.adobe.acrobat.ps\"\n        Case \"rft\": ExportFormat = \"com.adobe.acrobat.rft\"\n        Case \"xlsx\": ExportFormat = \"com.adobe.acrobat.xlsx\"\n        Case \"xls\": ExportFormat = \"com.adobe.acrobat.spreadsheet\"\n        Case \"txt\": ExportFormat = \"com.adobe.acrobat.accesstext\"\n        Case \"tiff\", \"tif\": ExportFormat = \"com.adobe.acrobat.tiff\"\n        Case \"xml\": ExportFormat = \"com.adobe.acrobat.xml-1-00\"\n        Case Else: ExportFormat = \"Wrong Input\"\n    End Select\n    \n    'Check if the format is correct and there are no errors.\n    If ExportFormat <> \"Wrong Input\" And Err.Number = 0 Then\n        \n        'Format is correct and no errors.\n        \n        'Set the path of the new file. Note that Adobe instead of xls uses xml files.\n        'That's why here the xls extension changes to xml.\n        If LCase(FileExtension) <> \"xls\" Then\n            NewFilePath = WorksheetFunction.Substitute(PDFPath, \".pdf\", \".\" & LCase(FileExtension))\n        Else\n            NewFilePath = WorksheetFunction.Substitute(PDFPath, \".pdf\", \".xml\")\n        End If\n        \n        'Save PDF file to the new format.\n        boResult = objJSO.SaveAs(NewFilePath, ExportFormat)\n        \n        'Close the PDF file without saving the changes.\n        boResult = objAcroAVDoc.Close(True)\n        \n        'Close the Acrobat application.\n        boResult = objAcroApp.Exit\n        \n        'Inform the user that conversion was successfully.\n        MsgBox \"The PDf file:\" & vbNewLine & PDFPath & vbNewLine & vbNewLine & _\n        \"Was saved as: \" & vbNewLine & NewFilePath, vbInformation, \"Conversion finished successfully\"\n         \n    Else\n       \n        'Something went wrong, so close the PDF file and the application.\n       \n        'Close the PDF file without saving the changes.\n        boResult = objAcroAVDoc.Close(True)\n       \n        'Close the Acrobat application.\n        boResult = objAcroApp.Exit\n       \n        'Inform the user that something went wrong.\n        MsgBox \"Something went wrong!\" & vbNewLine & \"The conversion of the following PDF file FAILED:\" & _\n        vbNewLine & PDFPath, vbInformation, \"Conversion failed\"\n\n    End If\n       \n    'Release the objects.\n    Set objAcroPDDoc = Nothing\n    Set objAcroAVDoc = Nothing\n    Set objAcroApp = Nothing\n       \nEnd Function\n", "content_b64": ""}, {"name": "PrintUtil.bas", "path": "模組/Others/PrintUtil.bas", "content": "Attribute VB_Name = \"PrintUtil\"\nOption Explicit\n'*************************************************************************************\n'專案名稱: 全委帳務處理\n'功能描述: 列印工具底層元件\n'\n'版權所有: Dunk\n'程式撰寫: Dunk\n'撰寫日期：2017/7/20\n'\n'改版日期:\n'改版備註: 2017/9/18 增加列印各種檔案\n'                 2017/9/20 增加列印PDF\n'*************************************************************************************\n#If VBA7 Then\n    Declare PtrSafe  Sub Sleep Lib \"kernel32\" (ByVal dwMilliseconds As Long)    'For 64 Bit Systems\n    Declare PtrSafe  Function ShellExecute Lib \"shell32.dll\" _\n            Alias \"ShellExecuteA\" (ByVal hwnd As Long, ByVal lpOperation As String, _\n                                   ByVal lpFile As String, ByVal lpParameters As String, _\n                                   ByVal lpDirectory As String, ByVal nShowCmd As Long) As Long\n#Else\n    Declare Sub Sleep Lib \"KERNEL32\" (ByVal dwMilliseconds As Long)    'For 32 Bit Systems\n    Declare Function ShellExecute Lib \"shell32.dll\" _\n                                  Alias \"ShellExecuteA\" (ByVal hwnd As Long, ByVal lpOperation As String, _\n                                                         ByVal lpFile As String, ByVal lpParameters As String, _\n                                                         ByVal lpDirectory As String, ByVal nShowCmd As Long) As Long\n#End If\n\n'列印檔案第一個頁籤(根據密碼 or 不使用密碼)\nFunction PrintFile(ByVal fileName As String, ByVal pwd As String, ByVal usePwd As Boolean)\n    Dim windowName As String\n\n    windowName = FileIOUtility.GetFileNameWithoutFolder(fileName)\n\n    If usePwd = True Then\n        Workbooks.Open fileName, Password:=pwd\n    Else\n        Workbooks.Open fileName\n    End If\n\n    Windows(windowName).Activate\n    Sheets(1).PrintOut\n    Windows(windowName).Close savechanges:=False\n    Windows(ThisWorkbook.Name).Activate\n\nEnd Function\n\n'列印excel檔案\nFunction PrintExcel(ByVal fileName As String)\n    Workbooks.Open fileName:=fileName\n    '    If InStr(1, fileName, \"代操收入費用報告書\") > 0 Or InStr(1, fileName, \"代操定存應計息表\") > 0 Then\n    '        AutoPrintIS\n    '    End If\n    ExecuteExcel4Macro \"PRINT(1,,,1,,,,,,,,2,,,TRUE,,FALSE)\"\n    ActiveWorkbook.Close savechanges:=False\nEnd Function\n\n'自動調整版面為A4橫印\nFunction AutoPrintIS()\n    AutoFitAllColumnsA\n    Dim ws As Worksheet\n    Set ws = ActiveSheet\n    With ws.PageSetup\n        .Zoom = False\n        .PaperSize = xlPaperA4\n        .FitToPagesWide = 1\n        .FitToPagesTall = 1\n        .Orientation = xlLandscape\n    End With\n    'ws.PrintOut\n    Set ws = Nothing\nEnd Function\n\n'調整欄寬\nFunction AutoFitAllColumnsA()\n    ActiveSheet.UsedRange.Columns.AutoFit\nEnd Function\n\n' 取得印表機名稱\nFunction GetDefaultPrinterName()\n    Dim Printer As String\n    Printer = Application.ActivePrinter\n    Printer = Left$(Printer, InStr(Printer, \" on\") - 1)\n\n    GetDefaultPrinterName = Printer\nEnd Function\n\n'列印檔案\nFunction PrintAllKindFile(ByVal fileName As String)\n    Dim ReturnVal As Variant\n    ReturnVal = ShellExecute(0&, \"print\", fileName, 0&, 0&, 0&)\nEnd Function\n'雙面pdf檔案\nFunction PrintPdfFile(ByVal adobeExePath As String, ByVal fileName As String)\n    Dim cmd As String\n    cmd = \"\"\"\" & adobeExePath & \"\"\"  /n /s /h /t \"\"\" & fileName & \"\"\"\"\n    Shell (cmd)\nEnd Function\n\n'雙面列印檔案\nFunction PrintAllKindFileDuplex(ByVal fileName As String, Optional ByVal second As Long)\n    Dim waitSecond, myduplex, ret As Long\n    Dim printerName As String\n\n    printerName = GetDefaultPrinterName\n\n    If second = 0 Then\n        waitSecond = 3000\n    Else\n        waitSecond = second * 1000\n    End If\n\n    myduplex = SetPrinterDuplex.Setduplex(printerName, 0)\n    ret = SetPrinterDuplex.Setduplex(printerName, 3)  'set duplex on\n    ' print your stuff here, including changing to the correct printer\n    PrintAllKindFile (fileName)\n    Sleep (waitSecond)\n    ret = SetPrinterDuplex.Setduplex(printerName, myduplex)   ' return to original duplex setting\n\nEnd Function\n\n'雙面列印pdf檔案\nFunction PrintPdfFileDuplex(ByVal adobeExePath As String, ByVal fileName As String, _\n                            Optional ByVal second As Long)\n    Dim waitSecond, myduplex, ret As Long\n    Dim printerName As String\n\n    printerName = GetDefaultPrinterName\n\n    If second = 0 Then\n        waitSecond = 3000\n    Else\n        waitSecond = second * 1000\n    End If\n\n    myduplex = SetPrinterDuplex.Setduplex(printerName, 0)\n    ret = SetPrinterDuplex.Setduplex(printerName, 3)  'set duplex on\n    ' print your stuff here, including changing to the correct printer\n    PrintPdfFile adobeExePath:=adobeExePath, fileName:=fileName\n    Sleep (waitSecond)\n    ret = SetPrinterDuplex.Setduplex(printerName, myduplex)   ' return to original duplex setting\n\nEnd Function\n\n'列印html檔案\n'記得引用Microsoft Internet Controls\nFunction PrintHtml(ByVal fileNameOrUrl As String)\n    Dim ie, TimeOutWebQuery, TimeOutTime As Variant\n    Set ie = CreateObject(\"InternetExplorer.Application\")\n    ie.Navigate fileNameOrUrl\n    ie.Visible = False\n    \n    TimeOutWebQuery = 5\n    TimeOutTime = DateAdd(\"s\", TimeOutWebQuery, Now)\n    Do Until ie.ReadyState = 4\n        DoEvents\n        If Now > TimeOutTime Then\n            ie.Stop\n            GoTo ErrorTimeOut\n        End If\n    Loop\n\n    ie.ExecWB 6, 2\n    Application.Wait (Now + TimeValue(\"0:00:03\"))\n\nErrorTimeOut:\n\n    Set ie = Nothing\nEnd Function\n", "content_b64": ""}, {"name": "RegExpTool.bas", "path": "模組/Others/RegExpTool.bas", "content": "Attribute VB_Name = \"RegExpTool\"\nOption Explicit\n'*************************************************************************************\n'專案名稱: 全權委託\n'功能描述: 正規表示式處理\n' Add VBA reference to \"Microsoft VBScript Regular Expressions 5.5\"\n'版權所有: Dunk\n'程式撰寫: Dunk\n'撰寫日期：2017/12/15\n'\n'改版日期:\n'改版備註:\n'\n'*************************************************************************************\nSub test()\nDim strTest As String\n'strTest = \"本期投資損益 -110, 341.26\"\nstrTest = \"PAGE:\"\nDebug.Print \"FindPageSep:\" & FindPageSep(strTest)\nEnd Sub\n'取得符合正規表示式的第一個值\nFunction GetRegMatchFirstValue(ByVal inputValue As String, ByVal pattern As String)\n    Dim regex As Object\n    Dim matches, Match, subMatch As Variant\n    Set regex = CreateObject(\"VBScript.RegExp\")\n\n    With regex\n        .pattern = pattern\n        .Global = True\n    End With\n\n    If regex.test(inputValue) = True Then\n        Set matches = regex.Execute(inputValue)\n        GetRegMatchFirstValue = matches(0).Value\n    Else\n        GetRegMatchFirstValue = \"\"\n    End If\nEnd Function\n\n'金額欄位\nFunction FindAmt(ByVal inputValue As String)\n    Dim pattern As String\n    pattern = \"-?[0-9]{1,3}(,[0-9]{3})*.[0-9]+\"\n    FindAmt = GetRegMatchFirstValue(inputValue, pattern)\nEnd Function\n\n'日期欄位\nFunction FindDate(ByVal inputValue As String)\n    Dim pattern As String\n    pattern = \"[0-9]{2,3}.[0-9]{1,2}.[0-9]{1,2}\"\n    FindDate = GetRegMatchFirstValue(inputValue, pattern)\nEnd Function\n\n'找尋用印欄位\nFunction FindMgr(ByVal inputValue As String)\n    Dim pattern As String\n    pattern = \"經辦覆核主管\"\n    FindMgr = GetRegMatchFirstValue(inputValue, pattern)\nEnd Function\n\n'找尋加\nFunction FindPlus(ByVal inputValue As String)\n    Dim pattern As String\n    pattern = \"加\"\n    FindPlus = GetRegMatchFirstValue(inputValue, pattern)\nEnd Function\n\n'找尋基金編號\nFunction FindFundNo(ByVal inputValue As String)\n    Dim pattern As String\n    pattern = \"[0-9]{4,4}\"\n    FindFundNo = GetRegMatchFirstValue(inputValue, pattern)\nEnd Function\n\n'找尋分頁\nFunction FindPageSep(ByVal inputValue As String)\n    Dim pattern As String\n    pattern = \"PAGE:\"\n    If GetRegMatchFirstValue(inputValue, pattern) <> \"\" Then\n        FindPageSep = True\n    Else\n        FindPageSep = False\n    End If\nEnd Function\n", "content_b64": ""}, {"name": "SaveWorkSheetTool.bas", "path": "模組/Others/SaveWorkSheetTool.bas", "content": "Attribute VB_Name = \"SaveWorkSheetTool\"\nOption Explicit\n'*************************************************************************************\n'專案名稱: 底層元件\n'功能描述: 工作頁另存成xls工具\n'\n'版權所有: Dunk\n'程式撰寫: Dunk\n'撰寫日期：2018/3/22\n'\n'改版日期:\n'改版備註: 2024/9/13 增加將檔案另存成xlsx\n'\n'*************************************************************************************\n\n'將結果另存成workbook\nFunction SaveSheetToWorkBook(ByVal sourceSheetName As String, ByVal destXlsFileName As String _\n                                                              , ByVal valueOnly As Boolean)\n    Dim wsDest As Worksheet\n\n    Set wsDest = Sheets(sourceSheetName)\n\n    Dim wb As Workbook\n    Set wb = Workbooks.Add\n\n    wsDest.Copy Before:=wb.Sheets(1)\n\n    '是否只複製值\n    If valueOnly = True Then\n        With wb.Sheets(1).UsedRange\n            .Value = .Value\n        End With\n    End If\n\n    While wb.Sheets.Count <> 1\n        wb.Sheets(wb.Sheets.Count).Delete\n    Wend\n\n\n    wb.SaveAs destXlsFileName\n    wb.Close\n\n    Set wsDest = Nothing\n    Set wb = Nothing\nEnd Function\n\n'將檔案另存成xlsx(只有值)\nFunction SaveXlSMToNewXlsxWithValueOnly(ByVal SavePath)\n    Dim SourceBook As Workbook, DestBook As Workbook, SourceSheet As Worksheet, DestSheet As Worksheet\n    Dim i As Integer\n    \n    With Application\n        .ScreenUpdating = False\n        .DisplayAlerts = False\n    End With\n    \n    Set SourceBook = ThisWorkbook\n    Set DestBook = Workbooks.Add\n        \n    For i = DestBook.Worksheets.Count To 2 Step -1\n        DestBook.Worksheets(i).Delete\n    Next i\n        \n    For i = ThisWorkbook.Sheets.Count To 1 Step -1\n       Set SourceSheet = ThisWorkbook.Sheets(i)\n        SourceSheet.Cells.Copy\n        Set DestSheet = DestBook.Worksheets.Add\n        With DestSheet.Range(\"A1\")\n            .PasteSpecial xlPasteValues\n            .PasteSpecial xlPasteFormats\n        End With\n        DestSheet.Name = SourceSheet.Name\n        \n        With DestSheet.Tab\n                On Error Resume Next\n                .Color = SourceSheet.Tab.ThemeColor\n                On Error Resume Next\n                .ColorIndex = SourceSheet.Tab.ColorIndex\n                On Error Resume Next\n                .ThemeColor = SourceSheet.Tab.ThemeColor\n                On Error Resume Next\n                .TintAndShade = SourceSheet.Tab.TintAndShade\n        End With\n    Next\n    \n    DestBook.Worksheets(DestBook.Worksheets.Count).Delete\n    On Error Resume Next\n    Kill SavePath\n    DestBook.SaveAs Filename:=SavePath\n    DestBook.Close\n    \n    Set SourceSheet = Nothing\n    Set DestSheet = Nothing\n    Set SourceBook = Nothing\n    Set DestBook = Nothing\n                \n    With Application\n        .ScreenUpdating = False\n        .DisplayAlerts = False\n    End With\n    \nEnd Function\n", "content_b64": ""}, {"name": "SavingPictureTool.bas", "path": "模組/Others/SavingPictureTool.bas", "content": "Attribute VB_Name = \"SavingPictureTool\"\nOption Explicit\n'*************************************************************************************\n'專案名稱: 底層元件\n'功能描述: 將worksheet另存成圖檔\n'\n'版權所有: Dunk\n'程式撰寫: Dunk\n'撰寫日期：2018/3/23\n'\n'改版日期:\n'改版備註:\n'\n'*************************************************************************************\n\n'Sub test()\n'    PrintScreenToPngFile \"123\", \"d:\\output\\aaa1.png\"\n'    PrintScreenToPngFile \"345\", \"d:\\output\\aaa2.png\"\n'    PrintScreenToPngFileByRange \"123\", \"A1\", \"d:\\output\\aaa3.png\"\n'    SaveChartToJpg \"789\", \"圖表 1\"\n'     SaveChartToJpgWithDestFile \"789\", \"圖表 1\", \"d:\\output\\12355.jpg\"\n'End Sub\n\n'另存圖表成PNG(指定range)\nFunction PrintScreenToPngFileByRange(ByVal sheetName As String, ByVal rangeDisplay As String _\n                                                                , ByVal destFile As String)\n    Dim Rng As range\n    Dim wsSource As Worksheet\n\n    Set wsSource = Sheets(sheetName)\n    Set Rng = wsSource.range(rangeDisplay)\n    Rng.CopyPicture\n\n    ' Excel 存圖檔的精簡程式碼。\n    With wsSource.ChartObjects.Add(1, 1, Rng.Width, Rng.Height)  '新增 圖表\n        .Chart.Paste                                                '貼上 圖片\n        .Chart.Export Filename:=destFile, Filtername:=\"png\"\n        .Delete                                                      '刪除 圖表\n    End With\n\n    Set Rng = Nothing\n    Set wsSource = Nothing\nEnd Function\n\n\nFunction PrintScreenToPngFile(ByVal sheetName As String, ByVal destFile As String)\n    Dim Rng As range\n    Dim wsSource As Worksheet\n\n    Set wsSource = Sheets(sheetName)\n    Set Rng = wsSource.UsedRange\n    Rng.CopyPicture\n\n    ' Excel 存圖檔的精簡程式碼。\n    With wsSource.ChartObjects.Add(1, 1, Rng.Width, Rng.Height)  '新增 圖表\n        .Chart.Paste                                                '貼上 圖片\n        .Chart.Export Filename:=destFile, Filtername:=\"png\"\n        .Delete                                                      '刪除 圖表\n    End With\n\n    Set Rng = Nothing\n    Set wsSource = Nothing\nEnd Function\n\n'存一般圖的程式 存在當下的資料夾\nFunction SaveChartToJpg(ByVal sheetName As String, ByVal chartName As String)\n    Dim MyFullName As String\n    MyFullName = Replace(Replace(ThisWorkbook.FullName, \".xlsm\", \"\"), \".xls\", \"\") & _\n                 \"_\" & chartName\n\n    '建立存圖路徑的程式\n    With Sheets(sheetName).ChartObjects(chartName).Chart\n        .Export Filename:=MyFullName & \".jpg\", Filtername:=\"jpg\"\n    End With\nEnd Function\n\n'存一般圖的程式 存在指定的檔案\nFunction SaveChartToJpgWithDestFile(ByVal sheetName As String, ByVal chartName As String, _\n                                    ByVal destFileName As String)\n\n'建立存圖路徑的程式\n    With Sheets(sheetName).ChartObjects(chartName).Chart\n        .Export Filename:=destFileName, Filtername:=\"jpg\"\n    End With\nEnd Function\n\n", "content_b64": ""}, {"name": "SendNews.bas", "path": "模組/Others/SendNews.bas", "content": "Attribute VB_Name = \"SendNews\"\nOption Explicit\n'*************************************************************************************\n'專案名稱: 金融資訊專區檔案下載\n'功能描述: 寄送剪報圖片檔案\n'\n'版權所有: Dunk\n'程式撰寫: Dunk\n'撰寫日期：2017/6/15\n'\n'改版日期:\n'改版備註: 2017/6/16 調整收信人清單及主旨產生方式\n'*************************************************************************************\n\n'開始寄送郵件\nFunction StartSend()\n    Dim folderName As String\n    folderName = ThisWorkbook.Sheets(\"總表\").Range(\"F2\").Text\n    SendMailWithBotNews folderName:=folderName\nEnd Function\n\n'取得附件清單\nFunction SendMailWithBotNews(ByVal folderName As String)\n'記得引用Microsoft Scripting Runtime\n    Dim fso As Scripting.FileSystemObject\n    Dim myFile As Scripting.File\n    Dim subject, attFile As String\n    Dim resultSubjectList(), cCMember As Variant\n    Dim startIndex As Integer\n\n    startIndex = 1\n    resultSubjectList = GetCcList()\n    Set fso = New Scripting.FileSystemObject\n\n    For Each myFile In fso.GetFolder(folderName).Files\n        startIndex = 1\n        For Each cCMember In resultSubjectList\n            '檔案類型為png，主旨即為檔名，一封信件只夾一個附檔\n            If InStr(1, myFile.Name, \"png\") > 0 And CStr(cCMember) <> \"\" Then\n                subject = GetSubjectTitle(Replace(myFile.Name, \".png\", \"\"), startIndex)\n                attFile = myFile.Path\n\n                SendMail subject:=subject, cC:=CStr(cCMember), attFile:=attFile\n\n                startIndex = startIndex + 1\n            End If\n        Next\n    Next\n\n    Set fso = Nothing\n\nEnd Function\n\nFunction GetCcListCombine()\n    Dim lastRowNumber, i As Integer\n    Dim cC As String\n    cC = \"\"\n    lastRowNumber = ThisWorkbook.Sheets(\"寄送名單\").Range(\"A65536\").End(xlUp).Row\n    For i = 1 To lastRowNumber\n        If i < lastRowNumber Then\n            cC = cC & ThisWorkbook.Sheets(\"寄送名單\").Range(\"A\" & CStr(i)).Value & \";\"\n        Else\n            cC = cC & ThisWorkbook.Sheets(\"寄送名單\").Range(\"A\" & CStr(i)).Value\n        End If\n    Next\n    GetCcListCombine = cC\nEnd Function\n'收信人清單\nFunction GetCcList()\n    Dim lastRowNumber, i As Integer\n    Dim cC() As Variant\n    lastRowNumber = ThisWorkbook.Sheets(\"寄送名單\").Range(\"A65536\").End(xlUp).Row\n    ReDim cC(lastRowNumber)\n    For i = 1 To lastRowNumber\n        cC(i) = ThisWorkbook.Sheets(\"寄送名單\").Range(\"A\" & CStr(i)).Text\n    Next\n    GetCcList = cC\nEnd Function\n'寄送信件函式\nFunction SendMail(ByVal subject As String, ByVal cC As String, ByVal attFile As String)\n    Dim wbStr As String\n    Dim OutlookApp As Outlook.Application\n    Dim newMail As Outlook.MailItem\n    Dim myAttachments As Outlook.Attachments\n    Set OutlookApp = New Outlook.Application\n    Set newMail = OutlookApp.CreateItem(olMailItem)\n    With newMail\n        .subject = subject\n        .To = cC\n        Set myAttachments = newMail.Attachments\n        myAttachments.Add attFile\n        .Send\n    End With\n    Set newMail = Nothing\n    Set myAttachments = Nothing\n    Set OutlookApp = Nothing\nEnd Function\n'取得主旨名稱\nFunction GetSubjectTitle(ByVal fileName As String, ByVal index As Integer)\n    Dim subject As String\n    '前字元+檔名+後字元\n    subject = ThisWorkbook.Sheets(\"寄送名單\").Range(\"B\" & CStr(index)).Text & fileName _\n              & ThisWorkbook.Sheets(\"寄送名單\").Range(\"C\" & CStr(index)).Text\n    GetSubjectTitle = subject\nEnd Function\n\n\n", "content_b64": ""}, {"name": "SendingMail.bas", "path": "模組/Others/SendingMail.bas", "content": "Attribute VB_Name = \"SendingMail\"\nOption Explicit\n'*************************************************************************************\n'專案名稱: 底層元件\n'功能描述: 寄送email\n'\n'版權所有: Dunk\n'程式撰寫: Dunk\n'撰寫日期：2017/9/29\n'\n'改版日期:\n'改版備註:\n'\n'*************************************************************************************\n\n'寄送信件函式\n'引用 Microsoft Outlook 12.0 object library\nFunction SendMail(ByVal subject As String, ByVal ccList As String, ByVal ToList As String, ByVal htmlBody As String)\n    Dim wbStr As String\n    Dim OutlookApp As Outlook.Application\n    Dim newMail As Outlook.MailItem\n    Dim myAttachments As Outlook.Attachments\n    Set OutlookApp = New Outlook.Application\n    Set newMail = OutlookApp.CreateItem(olMailItem)\n    With newMail\n        .subject = subject\n        .BodyFormat = olFormatHTML\n        .To = ToList\n        .cC = ccList\n        .htmlBody = htmlBody\n        .Send\n    End With\n    Set newMail = Nothing\n    Set myAttachments = Nothing\n    Set OutlookApp = Nothing\nEnd Function\n\n\n'寄送信件函式(密件複本)\n'引用 Microsoft Outlook 12.0 object library\nFunction SendMailWithBcc(ByVal subject As String, ByVal ccList As String, ByVal bccList As String, ByVal ToList As String _\n                                                                                                   , ByVal htmlBody As String)\n    Dim wbStr As String\n    Dim OutlookApp As Outlook.Application\n    Dim newMail As Outlook.MailItem\n    Dim myAttachments As Outlook.Attachments\n    Set OutlookApp = New Outlook.Application\n    Set newMail = OutlookApp.CreateItem(olMailItem)\n    With newMail\n        .subject = subject\n        .BodyFormat = olFormatHTML\n        .To = ToList\n        .cC = ccList\n        .BCC = bccList\n        .htmlBody = htmlBody\n        .Send\n    End With\n    Set newMail = Nothing\n    Set myAttachments = Nothing\n    Set OutlookApp = Nothing\nEnd Function\n", "content_b64": ""}, {"name": "SetPrinterDuplex.bas", "path": "模組/Others/SetPrinterDuplex.bas", "content": "Attribute VB_Name = \"SetPrinterDuplex\"\nOption Explicit\n\n'myduplex = Setduplex(\"HP Color LaserJet 2605\", 0)\n'ret = Setduplex(\"HP Color LaserJet 2605\", 3)  'set duplex on\n'' print your stuff here, including changing to the correct printer\n'ret = Setduplex(\"HP Color LaserJet 2605\", myduplex)   ' return to original duplex setting\n\n'Dim reg As Variant, oreg As Object, mystr As Variant\n' Const HKEY_CURRENT_USER = &H80000001\n'\n'Set oreg = GetObject(\"winmgmts:{impersonationLevel=impersonate}!\\\\.\\root\\default:StdRegProv\")\n'\n'oreg.enumvalues HKEY_CURRENT_USER, \"Software\\Microsoft\\Windows NT\\CurrentVersion\\Devices\", mystr, Arr\n'For Each reg In mystr\n'    oreg.getstringvalue HKEY_CURRENT_USER, \"Software\\Microsoft\\Windows NT\\CurrentVersion\\Devices\", reg, regvalue\n'    Debug.Print reg & \" on \" & Mid(regvalue, InStr(regvalue, \",\") + 1)\n'Next\n\n\n   Private Const CCHDEVICENAME = 32\n   Private Const CCHFORMNAME = 32\n   Private Const PRINTER_ACCESS_ADMINISTER = &H4\n   Private Const PRINTER_ACCESS_USE = &H8\n   Private Const STANDARD_RIGHTS_REQUIRED = &HF0000\n   Private Const PRINTER_ALL_ACCESS = (STANDARD_RIGHTS_REQUIRED Or _\n     PRINTER_ACCESS_ADMINISTER Or PRINTER_ACCESS_USE)\n\n   Private Const DM_MODIFY = 8\n   Private Const DM_COPY = 2\n   Private Const DM_IN_BUFFER = DM_MODIFY\n   Private Const DM_OUT_BUFFER = DM_COPY\n   Private Const IDOK = 1\n   Private Const GMEM_MOVEABLE = &H2\n   Private Const GMEM_ZEROINIT = &H40\n   Private Const GHND = (GMEM_MOVEABLE Or GMEM_ZEROINIT)\n   Private Const vbNullPtr = 0&\n\n   ' Add appripriate Constants for what you want to change\n   Private Const DM_DUPLEX = &H1000&\n   Private Const DM_ORIENTATION = &H1&\n   Private Const DM_COPIES = &H100&\n   Private Const DMPAPER_A4 = 9\n   Private Const DM_PAPERSIZE = &H2&\n\n   ' Constants for Duplex\n   Private Const DMDUP_SIMPLEX = 1\n   Private Const DMDUP_VERTICAL = 2\n   Private Const DMDUP_HORIZONTAL = 3\n\n   ' Constants for Orientation\n   Private Const DMORIENT_PORTRAIT = 1\n   Private Const DMORIENT_LANDSCAPE = 2\n\n   Private Type ACL\n      AclRevision As Byte\n      Sbz1 As Byte\n      AclSize As Integer\n      AceCount As Integer\n      Sbz2 As Integer\n   End Type\n\n   Private Type SECURITY_DESCRIPTOR\n      Revision As Byte\n      Sbz1 As Byte\n      Control As Long\n      Owner As Long\n      Group As Long\n      Sacl As Long   ' PACL\n      Dacl As Long   ' PACL\n   End Type\n\n   Private Type PRINTER_DEFAULTS\n      pDatatype As String\n      pDevMode As Long\n      DesiredAccess As Long\n   End Type\n\n   Private Type PRINTER_INFO_2\n      pServerName As Long    ' Pointer to a String\n      pPrinterName As Long   ' Pointer to a String\n      pShareName As Long     ' Pointer to a String\n      pPortName As Long      ' Pointer to a String\n      pDriverName As Long    ' Pointer to a String\n      pComment As Long       ' Pointer to a String\n      pLocation As Long      ' Pointer to a String\n      pDevMode As Long\n      pSepFile As Long       ' Pointer to a String\n      pPrintProcessor As Long   ' Pointer to a String\n      pDatatype As Long      ' Pointer to a String\n      pParameters As Long    ' Pointer to a String\n      pSecurityDescriptor As Long\n      Attributes As Long\n      Priority As Long\n      DefaultPriority As Long\n      StartTime As Long\n      UntilTime As Long\n      Status As Long\n      cJobs As Long\n      AveragePPM As Long\n   End Type\n\n   Private Type DEVMODE\n      dmDeviceName(1 To CCHDEVICENAME) As Byte ' As String * CCHDEVICENAME\n      dmSpecVersion As Integer\n      dmDriverVersion As Integer\n      dmSize As Integer\n      dmDriverExtra As Integer\n      dmFields As Long\n      dmOrientation As Integer\n      dmPaperSize As Integer\n      dmPaperLength As Integer\n      dmPaperWidth As Integer\n      dmScale As Integer\n      dmCopies As Integer\n      dmDefaultSource As Integer\n      dmPrintQuality As Integer\n      dmColor As Integer\n      dmDuplex As Integer\n      dmYResolution As Integer\n      dmTTOption As Integer\n      dmCollate As Integer\n      dmFormName(1 To CCHFORMNAME) As Byte ' As String * CCHFORMNAME\n      dmUnusedPadding As Integer\n      dmBitsPerPel As Integer\n      dmPelsWidth As Long\n      dmPelsHeight As Long\n      dmDisplayFlags As Long\n      dmDisplayFrequency As Long\n   End Type\n\n   Private Declare Function OpenPrinter Lib \"winspool.drv\" Alias _\n     \"OpenPrinterA\" (ByVal pPrinterName As String, phPrinter As Long, _\n     pDefault As PRINTER_DEFAULTS) As Long\n   Private Declare Function GetPrinter Lib \"winspool.drv\" Alias \"GetPrinterA\" _\n     (ByVal hPrinter As Long, ByVal Level As Long, pPrinter As Any, _\n     ByVal cbBuf As Long, pcbNeeded As Long) As Long\n   Private Declare Function SetPrinter Lib \"winspool.drv\" Alias \"SetPrinterA\" _\n     (ByVal hPrinter As Long, ByVal Level As Long, pPrinter As Any, _\n     ByVal Command As Long) As Long\n   Private Declare Function ClosePrinter Lib \"winspool.drv\" _\n     (ByVal hPrinter As Long) As Long\n   Private Declare Function DocumentProperties Lib \"winspool.drv\" Alias _\n     \"DocumentPropertiesA\" (ByVal hwnd As Long, ByVal hPrinter As Long, _\n     ByVal pDeviceName As String, pDevModeOutput As Any, _\n     pDevModeInput As Any, ByVal fMode As Long) As Long\n   Private Declare Sub CopyMemory Lib \"KERNEL32\" Alias \"RtlMoveMemory\" ( _\n     hpvDest As Any, hpvSource As Any, ByVal cbCopy As Long)\n\n   Public Function Setduplex(myprinter As String, ByVal dupval As Long) As Long\n      Dim hGlobal As Long, hPrinter As Long, dwNeeded As Long\n      Dim pi2 As PRINTER_INFO_2, i As Integer, pbuf() As Byte\n      Dim dm As DEVMODE\n      Dim pd As PRINTER_DEFAULTS\n      Dim bFlag As Long, lFlag As Long\n      Dim SD As SECURITY_DESCRIPTOR, SDbuff() As Byte\n      On Error GoTo ABORT\n      If dupval < 0 Or dupval > 3 Then MsgBox \"invalid duplex value\": Exit Function\n      hGlobal = 0: hPrinter = 0: dwNeeded = 0\n      pd.pDatatype = \"TEXT\"\n      pd.pDevMode = VarPtr(dm)\n      pd.DesiredAccess = PRINTER_ALL_ACCESS\n      ' Open printer handle (in Windows NT/2000, you need full-access\n      ' because you will eventually use SetPrinter)\n      bFlag = OpenPrinter(myprinter, hPrinter, pd)\n      If (bFlag = 0) Or (hPrinter = vbNullPtr) Then GoTo ABORT\n\n      '  The first GetPrinter() tells you how big the buffer should be in\n      '  order to hold all of PRINTER_INFO_2. Note that this usually returns\n      '  as FALSE, which only means that the buffer (the third parameter) was\n      '  not filled in. You don't want it filled in here.\n\n      Call GetPrinter(hPrinter, 2, 0, 0, dwNeeded)\n      If (dwNeeded = 0) Then GoTo ABORT\n\n      '  Allocate enough space for PRINTER_INFO_2\n\n      ReDim pbuf(dwNeeded)\n      For i = 0 To dwNeeded\n          pbuf(i) = 0\n      Next i\n\n      '  The second GetPrinter() call fills in all the current settings,\n      '  so all you need to do is modify what you're interested in.\n\n      bFlag = GetPrinter(hPrinter, 2, pbuf(0), dwNeeded, dwNeeded)\n      If bFlag = 0 Then GoTo ABORT\n      Call CopyMemory(pi2, pbuf(0), Len(pi2))\n\n      If pi2.pSecurityDescriptor <> vbNullPtr Then\n        Call CopyMemory(SD, ByVal pi2.pSecurityDescriptor, Len(SD))\n        'ReDim SDbuff(Len(SD))\n        'Call CopyMemory(SD, SDbuff(0), Len(SD))\n      End If\n\n     '  Set orientation to Landscape mode and Duplex to Horizontal\n     '  if the driver supports it.\n\n     If pi2.pDevMode <> vbNullPtr Then\n          Call CopyMemory(dm, ByVal pi2.pDevMode, Len(dm))\n          If dupval = 0 Then ' return current setting only\n                Setduplex = dm.dmDuplex\n                ClosePrinter hPrinter\n                Exit Function\n          End If\n          'If dm.dmFields And DM_PAPERSIZE Then\n          If dm.dmFields And DM_DUPLEX Then\n              ' Change the devmode by first setting dmFields to the\n              ' members that will change, using a bitwise Or\n              dm.dmFields = DM_DUPLEX 'DM_ORIENTATION Or\n              'dm.dmPaperSize = DMPAPER_A4\n'              dm.dmOrientation = DMORIENT_LANDSCAPE\n              dm.dmDuplex = dupval\n              Call CopyMemory(ByVal pi2.pDevMode, dm, Len(dm))\n\n              '  Make sure the driver-dependent part of devmode is updated as\n              '  necessary.\n              lFlag = DocumentProperties(vbNullPtr, hPrinter, _\n                       myprinter, _\n                       ByVal pi2.pDevMode, ByVal pi2.pDevMode, _\n                       DM_IN_BUFFER Or DM_OUT_BUFFER)\n              If lFlag <> IDOK Then GoTo ABORT\n\n              '  Update printer information.\n   '            Call CopyMemory(ByVal pi2.pDevMode, dm, Len(dm))\n              pi2.pSecurityDescriptor = 0\n              Call CopyMemory(pbuf(0), pi2, Len(pi2))\n\n              bFlag = SetPrinter(hPrinter, 2, pbuf(0), 0)\n              If bFlag = 0 Then GoTo ABORT\n              Setduplex = True\n              '  The driver supported the change, but it wasn't allowed due to\n              '  some other reason (probably lack of permission).\n          Else\n              MsgBox \"This printer does not support Duplexing\"\n          End If\n      Else\n          '  The driver doesn't support changing this.\n          GoTo ABORT\n      End If\n\nABORT:\n      If (hPrinter <> 0) Then Call ClosePrinter(hPrinter)\n\n     '  Clean up.\n   End Function\n\n", "content_b64": ""}, {"name": "SetSheetPureText.bas", "path": "模組/Others/SetSheetPureText.bas", "content": "Attribute VB_Name = \"SetSheetPureText\"\n\nOption Explicit\n\n'*************************************************************************************\n\n'專案名稱: 風管系統\n\n'功能描述: 設定excel報表只貼上值(for監控報表)\n\n'https://zh-tw.extendoffice.com/documents/excel/4140-excel-save-workbook-as-values.html\n\n'版權所有: Dunk\n\n'程式撰寫: Dunk\n\n'撰寫日期：2024/7/10\n\n'\n\n'改版日期:\n\n'改版備註: 2024/7/11 增加設定所有Print Rage\n\n'\n\n'*************************************************************************************\n\n\n\n'只設定值(PringRange)\n\nSub S01_SetSheetValueOnlyPrintRange()\n\n    With ActiveSheet\n\n            If .PageSetup.PrintArea <> \"\" Then\n\n                .Range(.PageSetup.PrintArea).Copy\n\n                .Range(.PageSetup.PrintArea).PasteSpecial xlPasteValues\n\n            Else\n\n                msgbox \"設定excel報表只貼上值(PringRange)無設定列印範圍!\"\n\n                Exit Sub\n\n            End If\n\n    End With\n\n     Application.CutCopyMode = False\n\n     msgbox \"設定excel報表只貼上值(PringRange)OK!\"\n\nEnd Sub\n\n'只設定值\n\nSub S02_SetSheetValueOnly()\n\n    With ActiveSheet\n\n            .Cells.Copy\n\n            .Cells.PasteSpecial xlPasteValues\n\n    End With\n\n    Application.CutCopyMode = False\n\n    msgbox \"設定excel報表只貼上值OK!\"\n\nEnd Sub\n\n\n\n'設定活頁簿所有工作頁內容只有值\n\nSub S03_SetAllSheetsValueOnly()\n\n    Dim wsh As Worksheet\n\n    For Each wsh In ActiveWorkbook.Worksheets\n\n        With wsh\n\n            .Cells.Copy\n\n            .Cells.PasteSpecial xlPasteValues\n\n        End With\n\n    Next\n\n    Set wsh = Nothing\n\n    Application.CutCopyMode = False\n\n    msgbox \"設定活頁簿所有工作頁內容只有值OK!\"\n\nEnd Sub\n\n\n\n'設定活頁簿所有工作頁內容只有值PringRange\n\nSub S03_SetAllSheetsValueOnlyPrintRange()\n\n    Dim wsh As Worksheet\n\n    For Each wsh In ActiveWorkbook.Worksheets\n\n        With wsh\n\n            If .PageSetup.PrintArea <> \"\" Then\n\n                .Range(.PageSetup.PrintArea).Copy\n\n                .Range(.PageSetup.PrintArea).PasteSpecial xlPasteValues\n\n            End If\n\n        End With\n\n    Next\n\n    Set wsh = Nothing\n\n    Application.CutCopyMode = False\n\n    msgbox \"設定活頁簿所有工作頁內容只有值PringRangeOK!\"\n\nEnd Sub\n\n", "content_b64": ""}, {"name": "SettingPrinterDuplexNew.bas", "path": "模組/Others/SettingPrinterDuplexNew.bas", "content": "Attribute VB_Name = \"SettingPrinterDuplexNew\"\nOption Explicit\n'*************************************************************************************\n'專案名稱: 底層元件\n'功能描述: 設定印表機雙面列印\n'\n'版權所有: Dunk\n'程式撰寫: Dunk\n'撰寫日期：2017/7/25\n'\n'改版日期:\n'改版備註:\n'\n'*************************************************************************************\n\n#If VBA7 Then\nPublic Type PRINTER_INFO_9\n    pDevmode As LongPtr    '''' POINTER TO DEVMODE\nEnd Type\n#Else\nPublic Type PRINTER_INFO_9\n    pDevmode As Long    '''' POINTER TO DEVMODE\nEnd Type\n#End If\n\nPublic Type DEVMODE\n    dmDeviceName As String * 32\n    dmSpecVersion As Integer: dmDriverVersion As Integer\n    dmSize As Integer\n    dmDriverExtra As Integer\n    dmFields As Long\n    dmOrientation As Integer\n    dmPaperSize As Integer\n    dmPaperLength As Integer\n    dmPaperWidth As Integer\n    dmScale As Integer\n    dmCopies As Integer\n    dmDefaultSource As Integer\n    dmPrintQuality As Integer\n    dmColor As Integer\n    dmDuplex As Integer\n    dmYResolution As Integer\n    dmTTOption As Integer\n    dmCollate As Integer\n    dmFormName As String * 32\n    dmUnusedPadding As Integer\n    dmBitsPerPel As Integer\n    dmPelsWidth As Long\n    dmPelsHeight As Long\n    dmDisplayFlags As Long\n    dmDisplayFrequency As Long\n    dmICMMethod As Long\n    dmICMIntent As Long\n    dmMediaType As Long\n    dmDitherType As Long\n    dmReserved1 As Long\n    dmReserved2 As Long\nEnd Type\n#If VBA7 Then\n    Public Declare PtrSafe Function GetProfileStringA Lib \"kernel32\" (ByVal lpAppName As String, ByVal lpKeyName As String, ByVal lpDefault As String, ByVal lpReturnedString As String, ByVal nSize As LongPtr) As Long\n\n    Public Declare PtrSafe Function OpenPrinter Lib \"winspool.drv\" Alias \"OpenPrinterA\" (ByVal pPrinterName As String, phPrinter As LongPtr, pDefault As Any) As Long\n    Public Declare PtrSafe Function GetPrinter Lib \"winspool.drv\" Alias \"GetPrinterA\" (ByVal hPrinter As LongPtr, ByVal Level As LongPtr, buffer As LongPtr, ByVal pbSize As LongPtr, pbSizeNeeded As LongPtr) As Long\n    Public Declare PtrSafe Function SetPrinter Lib \"winspool.drv\" Alias \"SetPrinterA\" (ByVal hPrinter As LongPtr, ByVal Level As LongPtr, pPrinter As Any, ByVal Command As LongPtr) As Long\n    Public Declare PtrSafe Function DocumentProperties Lib \"winspool.drv\" Alias \"DocumentPropertiesA\" (ByVal hWnd As LongPtr, ByVal hPrinter As LongPtr, ByVal pDeviceName As String, _\n                                                                                                       ByVal pDevModeOutput As LongPtr, ByVal pDevModeInput As LongPtr, _\n                                                                                                       ByVal fMode As LongPtr) As Long\n    Public Declare PtrSafe Function ClosePrinter Lib \"winspool.drv\" (ByVal hPrinter As LongPtr) As Long\n    Public Declare PtrSafe Sub CopyMemory Lib \"kernel32\" Alias \"RtlMoveMemory\" (pDest As Any, pSource As Any, ByVal cbLength As LongPtr)\n\n#Else\n    Public Declare Function GetProfileStringA Lib \"kernel32\" (ByVal lpAppName As String, ByVal lpKeyName As String, ByVal lpDefault As String, ByVal lpReturnedString As String, ByVal nSize As Long) As Long\n\n    Public Declare Function OpenPrinter Lib \"winspool.drv\" Alias \"OpenPrinterA\" (ByVal pPrinterName As String, phPrinter As Long, pDefault As Any) As Long\n    Public Declare Function GetPrinter Lib \"winspool.drv\" Alias \"GetPrinterA\" (ByVal hPrinter As Long, ByVal Level As Long, buffer As Long, ByVal pbSize As Long, pbSizeNeeded As Long) As Long\n    Public Declare Function SetPrinter Lib \"winspool.drv\" Alias \"SetPrinterA\" (ByVal hPrinter As Long, ByVal Level As Long, pPrinter As Any, ByVal Command As Long) As Long\n    Public Declare Function DocumentProperties Lib \"winspool.drv\" Alias \"DocumentPropertiesA\" (ByVal hWnd As Long, ByVal hPrinter As Long, ByVal pDeviceName As String, _\n                                                                                               ByVal pDevModeOutput As Long, ByVal pDevModeInput As Long, _\n                                                                                               ByVal fMode As Long) As Long\n    Public Declare Function ClosePrinter Lib \"winspool.drv\" (ByVal hPrinter As Long) As Long\n    Public Declare Sub CopyMemory Lib \"kernel32\" Alias \"RtlMoveMemory\" (pDest As Any, pSource As Any, ByVal cbLength As Long)\n#End If\nPublic Const DM_IN_BUFFER = 8\nPublic Const DM_OUT_BUFFER = 2\n\nPublic Sub SetPrinterProperty(ByVal sPrinterName As String, ByVal iPropertyType As Long)\n    Dim PrinterName, sPrinter, sDefaultPrinter As String\n    Dim Pinfo9 As PRINTER_INFO_9\n    Dim hPrinter, nRet As Long\n    Dim yDevModeData() As Byte\n    Dim dm As DEVMODE\n\n    '''' STROE THE CURRENT DEFAULT PRINTER\n    sDefaultPrinter = sPrinterName\n\n    '''' USE THE FULL PRINTER ADDRESS TO GET THE ADDRESS AND NAME MINUS THE PORT NAME\n    PrinterName = Left(sDefaultPrinter, InStr(sDefaultPrinter, \" on \") - 1)\n\n    '''' OPEN THE PRINTER\n    nRet = OpenPrinter(PrinterName, hPrinter, ByVal 0&)\n\n    '''' GET THE SIZE OF THE CURRENT DEVMODE STRUCTURE\n    nRet = DocumentProperties(0, hPrinter, PrinterName, 0, 0, 0)\n    If (nRet < 0) Then MsgBox \"Cannot get the size of the DEVMODE structure.\": Exit Sub\n\n    '''' GET THE CURRENT DEVMODE STRUCTURE\n    ReDim yDevModeData(nRet + 100) As Byte\n    nRet = DocumentProperties(0, hPrinter, PrinterName, VarPtr(yDevModeData(0)), 0, DM_OUT_BUFFER)\n    If (nRet < 0) Then MsgBox \"Cannot get the DEVMODE structure.\": Exit Sub\n\n    '''' COPY THE CURRENT DEVMODE STRUCTURE\n    Call CopyMemory(dm, yDevModeData(0), Len(dm))\n\n    '''' CHANGE THE DEVMODE STRUCTURE TO REQUIRED\n    dm.dmDuplex = iPropertyType    ' 1 = simplex, 2 = duplex\n\n    '''' REPLACE THE CURRENT DEVMODE STRUCTURE WITH THE NEWLEY EDITED\n    Call CopyMemory(yDevModeData(0), dm, Len(dm))\n\n    '''' VERIFY THE NEW DEVMODE STRUCTURE\n    nRet = DocumentProperties(0, hPrinter, PrinterName, VarPtr(yDevModeData(0)), VarPtr(yDevModeData(0)), DM_IN_BUFFER Or DM_OUT_BUFFER)\n\n    Pinfo9.pDevmode = VarPtr(yDevModeData(0))\n\n    '''' SET THE DEMODE STRUCTURE WITH ANY CHANGES MADE\n    nRet = SetPrinter(hPrinter, 9, Pinfo9, 0)\n    If (nRet <= 0) Then MsgBox \"Cannot set the DEVMODE structure.\": Exit Sub\n\n    '''' CLOSE THE PRINTER\n    nRet = ClosePrinter(hPrinter)\n\nEnd Sub\n'設定預設印表機雙面長邊\nPublic Function SetPrinterDuplexLongSide()\n    Dim sPrinterName As String\n    sPrinterName = GetDefaultPrinter\n    SetPrinterProperty sPrinterName, 2\nEnd Function\n'設定預設印表機雙面短邊\nPublic Function SetPrinterDuplexShortSide()\n    Dim sPrinterName As String\n    sPrinterName = GetDefaultPrinter\n    SetPrinterProperty sPrinterName, 3\nEnd Function\n'設定預設印表機單面\nPublic Function SetPrinterSimplex()\n    Dim sPrinterName As String\n    sPrinterName = GetDefaultPrinter\n    SetPrinterProperty sPrinterName, 1\nEnd Function\n\n'取得預設印表機\nFunction GetDefaultPrinter()\n    Dim Printer As String\n    Printer = Application.ActivePrinter\n    GetDefaultPrinter = Printer\nEnd Function\n\n'取得印表機資訊\nFunction DefaultPrinterInfo(ByVal itemName As String)\n    Dim strLPT As String * 255\n    Dim Result, Printer, Driver, Port As String\n    Dim ResultLength As Long\n    Dim Comma1, Comma2 As Variant\n    Call GetProfileStringA(\"Windows\", \"Device\", \"\", strLPT, 254)\n\n    Result = Application.Trim(strLPT)\n    ResultLength = Len(Result)\n\n    Comma1 = Application.Find(\",\", Result, 1)\n    Comma2 = Application.Find(\",\", Result, Comma1 + 1)\n\n    '   Gets printer's name\n    Printer = Left(Result, Comma1 - 1)\n\n    '   Gets driver\n    Driver = Mid(Result, Comma1 + 1, Comma2 - Comma1 - 1)\n\n    '   Gets last part of device line\n    Port = Right(Result, ResultLength - Comma2)\n\n    Select Case itemName\n    Case \"Printer\":\n        DefaultPrinterInfo = Printer\n        Exit Function\n    Case \"Driver\":\n        DefaultPrinterInfo = Driver\n        Exit Function\n    Case \"Port\":\n        DefaultPrinterInfo = Port\n        Exit Function\n    End Select\nEnd Function\n\n\n\n", "content_b64": ""}, {"name": "ShapUtil.bas", "path": "模組/Others/ShapUtil.bas", "content": "Attribute VB_Name = \"ShapUtil\"\nOption Explicit\n'*************************************************************************************\n'專案名稱: 風管系統\n'功能描述: 報表標示紅框工具\n'\n'版權所有: Dunk\n'程式撰寫: Dunk\n'撰寫日期：2024/7/11\n'\n'改版日期:\n'改版備註:\n'\n'*************************************************************************************\n'清除所有紅框\nFunction ClearAllOval()\n    Dim Object As Object\n    \n    For Each Object In ActiveSheet.Shapes\n        If InStrRev(Object.Name, \"Oval\") > 0 Then\n            Object.Delete\n        End If\n    Next\n    \n    Set Object = Nothing\nEnd Function\n\n'設定紅框(實線)\nFunction MarkRedMarkWithSelection()\n        ActiveSheet.Shapes.AddShape(msoShapeOval, Selection.Left, Selection.Top, Selection.Width, Selection.Height).Select\n        Selection.ShapeRange.Fill.Visible = msoFalse\n        \n        With Selection.ShapeRange.Line\n            .Visible = msoTrue\n            .ForeColor.RGB = RGB(255, 0, 0)\n            .Transparency = 0\n        End With\nEnd Function\n\n'設定紅框(虛線)\nFunction MarkRedMarkWithSelectionLineDash()\n        ActiveSheet.Shapes.AddShape(msoShapeOval, Selection.Left, Selection.Top, Selection.Width, Selection.Height).Select\n        Selection.ShapeRange.Fill.Visible = msoFalse\n        \n        With Selection.ShapeRange.Line\n            .Visible = msoTrue\n            .DashStyle = msoLineDash\n            .ForeColor.RGB = RGB(255, 0, 0)\n            .Transparency = 0\n        End With\nEnd Function\n", "content_b64": ""}, {"name": "SheetToolUtil.bas", "path": "模組/Others/SheetToolUtil.bas", "content": "Attribute VB_Name = \"SheetToolUtil\"\nOption Explicit\n'*************************************************************************************\n' 模組名稱：SheetToolUtil（工作表工具模組）\n' 功能說明：提供工作表常用操作的公用函式，包含：\n'           - 取得最後一列 / 最後一欄的位置\n'           - 跨工作表 / 跨活頁簿的範圍複製\n'           - 範圍內的搜尋、清除與取代\n'           - 外部連結管理\n'\n' 版權所有：台灣版權\n' 程式作者：Dunk\n' 建立日期：2017/8/14\n'\n' 修改紀錄：\n'   2017/8/16  新增清除指定範圍內容（僅清文字數值）\n'   2018/10/31 新增取代指定字元\n'   2023/6/15  新增複製 UsedRange\n'   2025/05/03 全面重構：移除 Select/Selection 反模式、修正型別宣告、補上中文說明\n'*************************************************************************************\nOption Explicit\n\n' ══════════════════════════════════════════════════════════════════════\n' 【區段一】取得最後列 / 欄位置\n' ══════════════════════════════════════════════════════════════════════\n\n'--------------------------------------------------\n' 函式：GetLastRowNum\n' 用途：依工作表名稱與欄位英文代號，取得該欄最後一列的列號\n' 參數：sheetName   - 工作表名稱\n'       columnAlpha - 欄位英文代號（例如 \"A\"、\"B\"）\n' 回傳：最後一列列號（Long）；若工作表不存在則觸發錯誤\n' 備註：自動判斷 xlsx（1048576 列）或舊版 xls（65536 列）格式\n'--------------------------------------------------\nFunction GetLastRowNum(ByVal sheetName As String, ByVal columnAlpha As String) As Long\n    Dim lastRowNum As Long\n    On Error GoTo xlsFormat\n    ' xlsx 格式：最大列數 1,048,576\n    lastRowNum = ThisWorkbook.Sheets(sheetName).Range(columnAlpha & \"1048576\").End(xlUp).Row\n    GetLastRowNum = lastRowNum\n    Exit Function\nxlsFormat:\n    ' 舊版 xls 格式：最大列數 65,536\n    lastRowNum = ThisWorkbook.Sheets(sheetName).Range(columnAlpha & \"65536\").End(xlUp).Row\n    GetLastRowNum = lastRowNum\nEnd Function\n\n'--------------------------------------------------\n' 函式：GetLastRowNumBySheet\n' 用途：依工作表物件與欄位英文代號，取得該欄最後一列的列號\n' 參數：mySheet     - 工作表物件（Worksheet）\n'       columnAlpha - 欄位英文代號（例如 \"A\"、\"B\"）\n' 回傳：最後一列列號（Long）\n' 備註：自動判斷 xlsx / xls 格式\n'--------------------------------------------------\nFunction GetLastRowNumBySheet(ByVal mySheet As Worksheet, ByVal columnAlpha As String) As Long\n    Dim lastRowNum As Long\n    On Error GoTo xlsFormat\n    ' xlsx 格式：最大列數 1,048,576\n    lastRowNum = mySheet.Range(columnAlpha & \"1048576\").End(xlUp).Row\n    GetLastRowNumBySheet = lastRowNum\n    Exit Function\nxlsFormat:\n    ' 舊版 xls 格式：最大列數 65,536\n    lastRowNum = mySheet.Range(columnAlpha & \"65536\").End(xlUp).Row\n    GetLastRowNumBySheet = lastRowNum\nEnd Function\n\n'--------------------------------------------------\n' 函式：GetLastColumnBySheet\n' 用途：依工作表物件與指定列號，取得該列最後一欄的欄號\n' 參數：ws     - 工作表物件（Worksheet）\n'       rowNum - 要查詢的列號\n' 回傳：最後一欄欄號（Long）\n'--------------------------------------------------\nFunction GetLastColumnBySheet(ByVal ws As Worksheet, ByVal rowNum As Variant) As Long\n    Dim lastColumnNum As Long\n    With ws\n        lastColumnNum = .Cells(rowNum, .Columns.Count).End(xlToLeft).Column\n    End With\n    GetLastColumnBySheet = lastColumnNum\nEnd Function\n\n'--------------------------------------------------\n' 函式：GetLastColumn\n' 用途：依工作表名稱與指定列號，取得該列最後一欄的欄號\n' 參數：sheetName - 工作表名稱\n'       rowNum    - 要查詢的列號\n' 回傳：最後一欄欄號（Long）\n'--------------------------------------------------\nFunction GetLastColumn(ByVal sheetName As String, ByVal rowNum As Variant) As Long\n    Dim ws As Worksheet\n    Dim lastColumnNum As Long\n    Set ws = ThisWorkbook.Sheets(sheetName)\n    With ws\n        lastColumnNum = .Cells(rowNum, .Columns.Count).End(xlToLeft).Column\n    End With\n    Set ws = Nothing\n    GetLastColumn = lastColumnNum\nEnd Function\n\n'--------------------------------------------------\n' 函式：GetLastColumnAddressBySheet\n' 用途：依工作表物件與指定列號，取得該列最後一欄的儲存格位址（無 $ 號）\n' 參數：ws     - 工作表物件（Worksheet）\n'       rowNum - 要查詢的列號\n' 回傳：儲存格位址字串，例如 \"D5\"（String）\n'--------------------------------------------------\nFunction GetLastColumnAddressBySheet(ByVal ws As Worksheet, ByVal rowNum As Variant) As String\n    Dim lastColumnNum As Long\n    Dim addr As String\n    With ws\n        lastColumnNum = .Cells(rowNum, .Columns.Count).End(xlToLeft).Column\n        addr = .Cells(rowNum, lastColumnNum).Address(False, False)\n    End With\n    GetLastColumnAddressBySheet = addr\nEnd Function\n\n'--------------------------------------------------\n' 函式：GetColumnNameBySheet\n' 用途：依工作表物件與欄號，取得對應的欄位英文代號\n' 參數：ws        - 工作表物件（Worksheet）\n'       columnNum - 欄號（數字）\n' 回傳：欄位英文代號，例如 \"A\"、\"AB\"（String）\n'--------------------------------------------------\nFunction GetColumnNameBySheet(ByVal ws As Worksheet, ByVal columnNum As Variant) As String\n    Dim addr As String\n    With ws\n        ' 取得第 1 列指定欄的位址，再移除列號 \"1\" 得到欄名\n        addr = Replace(.Cells(1, columnNum).Address(False, False), \"1\", \"\")\n    End With\n    GetColumnNameBySheet = addr\nEnd Function\n\n\n' ══════════════════════════════════════════════════════════════════════\n' 【區段二】範圍複製\n' ══════════════════════════════════════════════════════════════════════\n\n'--------------------------------------------------\n' 函式：CopyRange\n' 用途：將來源工作表（依名稱）指定欄的某範圍列，以「僅貼值」方式\n'       複製到目的工作表（依名稱）的指定起始位置\n' 參數：sourceSheetName - 來源工作表名稱\n'       sourceColumnName - 來源欄位英文代號（例如 \"A\"）\n'       sourceRowStart  - 來源起始列號\n'       sourceRowEnd    - 來源結束列號\n'       destSheetName   - 目的工作表名稱\n'       destColumnName  - 目的欄位英文代號\n'       destRowStart    - 目的起始列號\n'--------------------------------------------------\nFunction CopyRange(ByVal sourceSheetName As String, ByVal sourceColumnName As String _\n                 , ByVal sourceRowStart As Long, ByVal sourceRowEnd As Long _\n                 , ByVal destSheetName As String, ByVal destColumnName As String _\n                 , ByVal destRowStart As Long)\n\n    Dim srcRange As Range\n    Dim dstRange As Range\n    Set srcRange = ThisWorkbook.Sheets(sourceSheetName).Range( _\n        sourceColumnName & sourceRowStart & \":\" & sourceColumnName & sourceRowEnd)\n    Set dstRange = ThisWorkbook.Sheets(destSheetName).Range(destColumnName & destRowStart)\n\n    srcRange.Copy\n    dstRange.PasteSpecial Paste:=xlPasteValues, Operation:=xlNone, _\n                          SkipBlanks:=False, Transpose:=False\n    Application.CutCopyMode = False\n\n    Set srcRange = Nothing\n    Set dstRange = Nothing\nEnd Function\n\n'--------------------------------------------------\n' 函式：CopyRangeWithPlace\n' 用途：將來源工作表（依名稱）指定矩形範圍，以「僅貼值」方式\n'       複製到目的工作表（依名稱）的指定起始位置\n'       （與 CopyRange 的差異在於：本函式可指定起始欄與結束欄兩個欄位）\n' 參數：sourceSheetName      - 來源工作表名稱\n'       sourceColumnNameStart - 來源起始欄位英文代號（例如 \"A\"）\n'       sourceRowStart        - 來源起始列號\n'       sourceColumnNameEnd   - 來源結束欄位英文代號（例如 \"C\"）\n'       sourceRowEnd          - 來源結束列號\n'       destSheetName         - 目的工作表名稱\n'       destColumnName        - 目的起始欄位英文代號\n'       destRowStart          - 目的起始列號\n'--------------------------------------------------\nFunction CopyRangeWithPlace(ByVal sourceSheetName As String _\n                           , ByVal sourceColumnNameStart As String, ByVal sourceRowStart As Long _\n                           , ByVal sourceColumnNameEnd As String, ByVal sourceRowEnd As Long _\n                           , ByVal destSheetName As String _\n                           , ByVal destColumnName As String, ByVal destRowStart As Long)\n\n    Dim srcRange As Range\n    Dim dstRange As Range\n    Set srcRange = ThisWorkbook.Sheets(sourceSheetName).Range( _\n        sourceColumnNameStart & sourceRowStart & \":\" & sourceColumnNameEnd & sourceRowEnd)\n    Set dstRange = ThisWorkbook.Sheets(destSheetName).Range(destColumnName & destRowStart)\n\n    srcRange.Copy\n    dstRange.PasteSpecial Paste:=xlPasteValues, Operation:=xlNone, _\n                          SkipBlanks:=False, Transpose:=False\n    Application.CutCopyMode = False\n\n    Set srcRange = Nothing\n    Set dstRange = Nothing\nEnd Function\n\n'--------------------------------------------------\n' 函式：CopyRangeBySheet\n' 用途：將來源工作表物件指定欄的某範圍列，以「僅貼值」方式\n'       複製到目的工作表物件的指定起始位置\n' 參數：sourceSheet      - 來源工作表物件（Worksheet）\n'       sourceColumnName - 來源欄位英文代號\n'       sourceRowStart   - 來源起始列號\n'       sourceRowEnd     - 來源結束列號\n'       destSheet        - 目的工作表物件（Worksheet）\n'       destColumnName   - 目的欄位英文代號\n'       destRowStart     - 目的起始列號\n'--------------------------------------------------\nFunction CopyRangeBySheet(ByVal sourceSheet As Worksheet, ByVal sourceColumnName As String _\n                         , ByVal sourceRowStart As Long, ByVal sourceRowEnd As Long _\n                         , ByVal destSheet As Worksheet, ByVal destColumnName As String _\n                         , ByVal destRowStart As Long)\n\n    Dim srcRange As Range\n    Dim dstRange As Range\n    Set srcRange = sourceSheet.Range( _\n        sourceColumnName & sourceRowStart & \":\" & sourceColumnName & sourceRowEnd)\n    Set dstRange = destSheet.Range(destColumnName & destRowStart)\n\n    srcRange.Copy\n    dstRange.PasteSpecial Paste:=xlPasteValues, Operation:=xlNone, _\n                          SkipBlanks:=False, Transpose:=False\n    Application.CutCopyMode = False\n\n    Set srcRange = Nothing\n    Set dstRange = Nothing\nEnd Function\n\n'--------------------------------------------------\n' 函式：CopyRangeByFile\n' 用途：將來源活頁簿（依檔名）的指定範圍，以「僅貼值」方式\n'       複製到目的活頁簿（依檔名）的指定範圍\n'       ＊兩個活頁簿必須都已開啟\n' 參數：sourceFileName    - 來源活頁簿檔名（含副檔名）\n'       sourceSheetName   - 來源工作表名稱\n'       sourceRangeDisplay - 來源範圍位址字串（例如 \"A1:C10\"）\n'       destFileName      - 目的活頁簿檔名（含副檔名）\n'       destSheetName     - 目的工作表名稱\n'       destRangeDisplay  - 目的起始範圍位址字串\n'--------------------------------------------------\nFunction CopyRangeByFile(ByVal sourceFileName As String, ByVal sourceSheetName As String _\n                        , ByVal sourceRangeDisplay As String _\n                        , ByVal destFileName As String, ByVal destSheetName As String _\n                        , ByVal destRangeDisplay As String)\n\n    ' 複製來源範圍到剪貼簿\n    Workbooks(sourceFileName).Worksheets(sourceSheetName).Range(sourceRangeDisplay).Copy\n\n    ' 以僅貼值方式貼到目的範圍\n    Workbooks(destFileName).Worksheets(destSheetName).Range(destRangeDisplay).PasteSpecial _\n        Paste:=xlPasteValues, Operation:=xlNone, SkipBlanks:=False, Transpose:=False\n\n    Application.CutCopyMode = False\nEnd Function\n\n'--------------------------------------------------\n' 函式：CopyRangeFomulaBySheet\n' 用途：將來源工作表物件指定欄的某範圍列，以「僅貼公式」方式\n'       複製到目的工作表物件的指定起始位置\n' 參數：sourceSheet      - 來源工作表物件（Worksheet）\n'       sourceColumnName - 來源欄位英文代號\n'       sourceRowStart   - 來源起始列號\n'       sourceRowEnd     - 來源結束列號\n'       destSheet        - 目的工作表物件（Worksheet）\n'       destColumnName   - 目的欄位英文代號\n'       destRowStart     - 目的起始列號\n'--------------------------------------------------\nFunction CopyRangeFomulaBySheet(ByVal sourceSheet As Worksheet, ByVal sourceColumnName As String _\n                               , ByVal sourceRowStart As Long, ByVal sourceRowEnd As Long _\n                               , ByVal destSheet As Worksheet, ByVal destColumnName As String _\n                               , ByVal destRowStart As Long)\n\n    Dim srcRange As Range\n    Dim dstRange As Range\n    Set srcRange = sourceSheet.Range( _\n        sourceColumnName & sourceRowStart & \":\" & sourceColumnName & sourceRowEnd)\n    Set dstRange = destSheet.Range(destColumnName & destRowStart)\n\n    srcRange.Copy\n    dstRange.PasteSpecial Paste:=xlPasteFormulas, Operation:=xlNone, _\n                          SkipBlanks:=False, Transpose:=False\n    Application.CutCopyMode = False\n\n    Set srcRange = Nothing\n    Set dstRange = Nothing\nEnd Function\n\n'--------------------------------------------------\n' 函式：CopyRangeFormatBySheet\n' 用途：將來源工作表物件指定欄的某範圍列，以「僅貼格式」方式\n'       複製到目的工作表物件的指定起始位置\n' 參數：sourceSheet      - 來源工作表物件（Worksheet）\n'       sourceColumnName - 來源欄位英文代號\n'       sourceRowStart   - 來源起始列號\n'       sourceRowEnd     - 來源結束列號\n'       destSheet        - 目的工作表物件（Worksheet）\n'       destColumnName   - 目的欄位英文代號\n'       destRowStart     - 目的起始列號\n'--------------------------------------------------\nFunction CopyRangeFormatBySheet(ByVal sourceSheet As Worksheet, ByVal sourceColumnName As String _\n                               , ByVal sourceRowStart As Long, ByVal sourceRowEnd As Long _\n                               , ByVal destSheet As Worksheet, ByVal destColumnName As String _\n                               , ByVal destRowStart As Long)\n\n    Dim srcRange As Range\n    Dim dstRange As Range\n    Set srcRange = sourceSheet.Range( _\n        sourceColumnName & sourceRowStart & \":\" & sourceColumnName & sourceRowEnd)\n    Set dstRange = destSheet.Range(destColumnName & destRowStart)\n\n    srcRange.Copy\n    dstRange.PasteSpecial Paste:=xlPasteFormats, Operation:=xlNone, _\n                          SkipBlanks:=False, Transpose:=False\n    Application.CutCopyMode = False\n\n    Set srcRange = Nothing\n    Set dstRange = Nothing\nEnd Function\n\n'--------------------------------------------------\n' 函式：CopyUsedRangeToAnotherSheetWithoutFormatting\n' 用途：將來源工作表的 UsedRange（已使用範圍）以「僅貼值」方式\n'       複製到目的工作表的指定位置（不複製格式）\n' 參數：wsSource         - 來源工作表物件（Worksheet）\n'       wsDest           - 目的工作表物件（Worksheet）\n'       destRangeDisplay - 目的起始範圍位址字串（例如 \"A1\"）\n' 備註：原始版本有 Bug（使用未宣告的 destRange 變數），已修正為 destRangeDisplay\n'--------------------------------------------------\nPrivate Function CopyUsedRangeToAnotherSheetWithoutFormatting( _\n    ByVal wsSource As Worksheet, ByVal wsDest As Worksheet, ByVal destRangeDisplay As String)\n\n    wsSource.UsedRange.Copy\n    wsDest.Range(destRangeDisplay).PasteSpecial _\n        Paste:=xlPasteValues, Operation:=xlNone, SkipBlanks:=False, Transpose:=False\n    Application.CutCopyMode = False\nEnd Function\n\n'--------------------------------------------------\n' 函式：CopySheetFromFile\n' 用途：開啟外部 Excel 檔案，將其第一張工作表複製到目前活頁簿的最後，\n'       並重新命名後關閉來源檔案\n' 參數：fileName        - 來源檔案完整路徑\n'       resultSheetName - 複製後的工作表新名稱\n' 備註：需搭配 FileIOUtility 模組的 GetFileNameWithoutFolder 函式\n'--------------------------------------------------\nFunction CopySheetFromFile(ByVal fileName As String, ByVal resultSheetName As String)\n    Dim windowName As String\n    windowName = FileIOUtility.GetFileNameWithoutFolder(fileName)\n\n    Workbooks.Open fileName:=fileName\n    Windows(windowName).Activate\n\n    ' 將來源第一張工作表複製到目前活頁簿最後\n    Sheets(1).Copy After:=ThisWorkbook.Sheets(ThisWorkbook.Sheets.Count)\n    ThisWorkbook.Sheets(ThisWorkbook.Sheets.Count).Name = resultSheetName\n\n    Windows(windowName).Close SaveChanges:=False\nEnd Function\n\n\n' ══════════════════════════════════════════════════════════════════════\n' 【區段三】搜尋\n' ══════════════════════════════════════════════════════════════════════\n\n'--------------------------------------------------\n' 函式：FindFirstValueRowInRange\n' 用途：在指定範圍內搜尋（完全符合），回傳第一個符合值所在的列號\n' 參數：myRange - 搜尋範圍（Range）\n'       findStr - 要搜尋的字串\n' 回傳：找到時回傳列號（Long）；找不到時回傳 -1\n'--------------------------------------------------\nFunction FindFirstValueRowInRange(ByVal myRange As Range, ByVal findStr As String) As Long\n    Dim findRange As Range\n    With myRange\n        Set findRange = .Find(findStr, After:=.Cells(.Cells.Count), _\n                              LookIn:=xlValues, LookAt:=xlWhole)\n    End With\n\n    If Not findRange Is Nothing Then\n        FindFirstValueRowInRange = findRange.Row\n        Set findRange = Nothing\n    Else\n        FindFirstValueRowInRange = -1\n    End If\nEnd Function\n\n'--------------------------------------------------\n' 函式：FindValueRowsInRange\n' 用途：在指定範圍內搜尋（完全符合），回傳所有符合值所在的列號陣列\n' 參數：myRange - 搜尋範圍（Range）\n'       findStr - 要搜尋的字串\n' 回傳：包含所有符合列號的 Variant 陣列；若無符合則回傳空陣列\n' 備註：原始版本的 firstAddress 未宣告，已修正\n'--------------------------------------------------\nFunction FindValueRowsInRange(ByVal myRange As Range, ByVal findStr As String) As Variant\n    Dim findRange As Range\n    Dim resultArray() As Variant\n    Dim firstAddress As String\n    Dim counter As Long\n\n    ReDim resultArray(65536)\n    counter = 0\n\n    With myRange\n        Set findRange = .Find(findStr, After:=.Cells(.Cells.Count), _\n                              LookIn:=xlValues, LookAt:=xlWhole)\n        If Not findRange Is Nothing Then\n            firstAddress = findRange.Address\n            Do\n                Set findRange = .FindNext(findRange)\n                resultArray(counter) = findRange.Row\n                counter = counter + 1\n            Loop While Not findRange Is Nothing And findRange.Address <> firstAddress\n        End If\n    End With\n\n    If counter > 0 Then\n        counter = counter - 1\n    End If\n\n    ReDim Preserve resultArray(counter)\n    FindValueRowsInRange = resultArray\nEnd Function\n\n'--------------------------------------------------\n' 函式：FindFirstValueColumnInRange\n' 用途：在指定範圍內搜尋（完全符合），回傳第一個符合值所在的欄號\n' 參數：myRange - 搜尋範圍（Range）\n'       findStr - 要搜尋的字串\n' 回傳：找到時回傳欄號（Long）；找不到時回傳 -1\n'--------------------------------------------------\nFunction FindFirstValueColumnInRange(ByVal myRange As Range, ByVal findStr As String) As Long\n    Dim findRange As Range\n    With myRange\n        Set findRange = .Find(findStr, After:=.Cells(.Cells.Count), _\n                              LookIn:=xlValues, LookAt:=xlWhole)\n    End With\n\n    If Not findRange Is Nothing Then\n        FindFirstValueColumnInRange = findRange.Column\n        Set findRange = Nothing\n    Else\n        FindFirstValueColumnInRange = -1\n    End If\nEnd Function\n\n'--------------------------------------------------\n' 函式：FindFirstValueAbsAddressInRange\n' 用途：在指定範圍內搜尋（完全符合），回傳第一個符合值的絕對位址（含 $）\n' 參數：myRange - 搜尋範圍（Range）\n'       findStr - 要搜尋的字串\n' 回傳：找到時回傳絕對位址字串，例如 \"$A$5\"（String）；找不到時回傳 \"\"\n'--------------------------------------------------\nFunction FindFirstValueAbsAddressInRange(ByVal myRange As Range, ByVal findStr As String) As String\n    Dim findRange As Range\n    With myRange\n        Set findRange = .Find(findStr, After:=.Cells(.Cells.Count), _\n                              LookIn:=xlValues, LookAt:=xlWhole)\n    End With\n\n    If Not findRange Is Nothing Then\n        FindFirstValueAbsAddressInRange = findRange.Address\n        Set findRange = Nothing\n    Else\n        FindFirstValueAbsAddressInRange = \"\"\n    End If\nEnd Function\n\n'--------------------------------------------------\n' 函式：FindFirstValueAddressInRangeFullMatch\n' 用途：在指定範圍內搜尋（完全符合），回傳第一個符合值的相對位址（不含 $）\n' 參數：myRange - 搜尋範圍（Range）\n'       findStr - 要搜尋的字串\n' 回傳：找到時回傳相對位址字串，例如 \"A5\"（String）；找不到時回傳 \"\"\n'--------------------------------------------------\nFunction FindFirstValueAddressInRangeFullMatch(ByVal myRange As Range, ByVal findStr As String) As String\n    Dim findRange As Range\n    With myRange\n        Set findRange = .Find(findStr, After:=.Cells(.Cells.Count), _\n                              LookIn:=xlValues, LookAt:=xlWhole)\n    End With\n\n    If Not findRange Is Nothing Then\n        FindFirstValueAddressInRangeFullMatch = Replace(findRange.Address, \"$\", \"\")\n        Set findRange = Nothing\n    Else\n        FindFirstValueAddressInRangeFullMatch = \"\"\n    End If\nEnd Function\n\n'--------------------------------------------------\n' 函式：FindFirstValueAddressInRangePartialMatch\n' 用途：在指定範圍內搜尋（部分符合），回傳第一個符合值的相對位址（不含 $）\n' 參數：myRange - 搜尋範圍（Range）\n'       findStr - 要搜尋的字串（支援部分比對）\n' 回傳：找到時回傳相對位址字串，例如 \"A5\"（String）；找不到時回傳 \"\"\n'--------------------------------------------------\nFunction FindFirstValueAddressInRangePartialMatch(ByVal myRange As Range, ByVal findStr As String) As String\n    Dim findRange As Range\n    With myRange\n        Set findRange = .Find(findStr, After:=.Cells(.Cells.Count), _\n                              LookIn:=xlValues, LookAt:=xlPart)\n    End With\n\n    If Not findRange Is Nothing Then\n        FindFirstValueAddressInRangePartialMatch = Replace(findRange.Address, \"$\", \"\")\n        Set findRange = Nothing\n    Else\n        FindFirstValueAddressInRangePartialMatch = \"\"\n    End If\nEnd Function\n\n\n' ══════════════════════════════════════════════════════════════════════\n' 【區段四】資料清除與取代\n' ══════════════════════════════════════════════════════════════════════\n\n'--------------------------------------------------\n' 函式：ClearContent\n' 用途：清除指定範圍內所有內容（值、公式），保留格式\n' 參數：myRange - 要清除的範圍（Range）\n'--------------------------------------------------\nFunction ClearContent(ByVal myRange As Range)\n    myRange.ClearContents\nEnd Function\n\n'--------------------------------------------------\n' 函式：ClearContentOnlyText\n' 用途：清除指定範圍內的常數內容（文字、數值），保留公式與格式\n' 參數：myRange - 要清除的範圍（Range）\n' 備註：若範圍內無常數儲存格，忽略錯誤並正常結束\n'--------------------------------------------------\nFunction ClearContentOnlyText(ByVal myRange As Range)\n    On Error GoTo NoData\n    myRange.SpecialCells(xlCellTypeConstants, 23).ClearContents\nNoData:\nEnd Function\n\n'--------------------------------------------------\n' 函式：ReplaceValueInRange\n' 用途：在指定範圍內，將所有符合（完全符合）的值以 replaceString 取代\n' 參數：myRange       - 搜尋範圍（Range）\n'       findStr       - 要搜尋的字串\n'       replaceString - 取代後的新值\n' 備註：原始版本的 firstAddress 未宣告，已修正\n'--------------------------------------------------\nFunction ReplaceValueInRange(ByVal myRange As Range, ByVal findStr As String, ByVal replaceString As Variant)\n    Dim findRange As Range\n    Dim firstAddress As String\n\n    With myRange\n        Set findRange = .Find(findStr, After:=.Cells(.Cells.Count), _\n                              LookIn:=xlValues, LookAt:=xlWhole)\n        If Not findRange Is Nothing Then\n            firstAddress = findRange.Address\n            Do\n                findRange.Value = replaceString\n                Set findRange = .FindNext(findRange)\n            Loop While Not findRange Is Nothing And findRange.Address <> firstAddress\n        End If\n    End With\n\n    Set findRange = Nothing\nEnd Function\n\n\n' ══════════════════════════════════════════════════════════════════════\n' 【區段五】活頁簿連結與其他工具\n' ══════════════════════════════════════════════════════════════════════\n\n'--------------------------------------------------\n' 函式：BreakAllLinks\n' 用途：中斷目前活頁簿內所有外部 Excel 連結（xlLinkTypeExcelLinks）\n' 備註：若活頁簿中沒有任何外部連結，函式安全地結束\n'--------------------------------------------------\nFunction BreakAllLinks()\n    Dim links As Variant\n    Dim i As Integer\n\n    links = ThisWorkbook.LinkSources(Type:=xlLinkTypeExcelLinks)\n    On Error GoTo leave\n\n    For i = 1 To UBound(links)\n        ThisWorkbook.BreakLink Name:=links(i), Type:=xlLinkTypeExcelLinks\n    Next i\nleave:\n    Exit Function\nEnd Function\n\n'--------------------------------------------------\n' 函式：CheckValueFromFile\n' 用途：開啟外部 Excel 檔案，檢查其第一張工作表指定儲存格的值\n'       是否包含指定字串，然後關閉檔案\n' 參數：fileName   - 外部檔案完整路徑\n'       rangeValue - 要檢查的儲存格位址（例如 \"A1\"）\n'       findText   - 要搜尋的字串\n' 回傳：True 表示找到，False 表示未找到（Boolean）\n' 備註：需搭配 FileIOUtility 模組的 GetFileNameWithoutFolder 函式\n'--------------------------------------------------\nFunction CheckValueFromFile(ByVal fileName As String, ByVal rangeValue As String, ByVal findText As String) As Boolean\n    Dim windowName As String\n    Dim isFind As Boolean\n    windowName = FileIOUtility.GetFileNameWithoutFolder(fileName)\n\n    Workbooks.Open fileName:=fileName\n    Windows(windowName).Activate\n\n    isFind = (InStr(1, Sheets(1).Range(rangeValue).Value, findText) > 0)\n\n    Windows(windowName).Close SaveChanges:=False\n    CheckValueFromFile = isFind\nEnd Function", "content_b64": ""}, {"name": "SheetUtil.bas", "path": "模組/Others/SheetUtil.bas", "content": "Attribute VB_Name = \"SheetUtil\"\n\n\nOption Explicit\n\n\n'工作頁常用功能\n\n\n''''''''''''''''''\n\n\n\n\n\n'調整欄寬\n\n\nSub AutoFitAllColumns()\n\n\n ActiveSheet.UsedRange.Columns.AutoFit\n\n\nEnd Sub\n\n\n'調整欄高\n\n\nSub AutoFitAllRows()\n\n\n ActiveSheet.UsedRange.Rows.AutoFit\n\n\nEnd Sub\n\n\n'產生工作表索引超連結\n\n\nSub ShtAdd()\n\n\n    Dim mySht As Worksheet\n\n\n    Dim ShtName As String\n\n\n    Dim myRng As Range\n\n\n    Dim i, j As Integer\n\n\n    Dim myWb As Workbook\n\n\n    Set myWb = ActiveWorkbook\n\n\n    Set mySht = myWb.Worksheets.Add(Count:=1, Before:=Sheets(1))\n\n\n    \n\n\n    On Error Resume Next\n\n\n   \n\n\n    mySht.Name = \"總表索引\"\n\n\n    Columns(2).Clear                            '儲存格的清除\n\n\n    Set myRng = Range(\"A1\")\n\n\n    Range(\"A1\").Value = \"總表索引\"            '標題的設定\n\n\n    \n\n\n    For Each mySht In Worksheets\n\n\n        ShtName = mySht.Name\n\n\n        If mySht.Name = \"總表索引\" Then\n\n\n            Sheets(\"總表索引\").Activate\n\n\n            Columns(2).Clear                          '儲存格的清除\n\n\n            Set myRng = Range(\"A1\")\n\n\n            Range(\"A1\").Value = \"總表索引\"            '標題的設定\n\n\n\n\n\n        Else\n\n\n        \n\n\n        'Cells(Rows.Count, 2).End(xlUp).Offset(1).Value = mySht.Name     '參考 說明()\n\n\n    '    MsgBox mySht.Name\n\n\n        Set myRng = myRng.Offset(1)\n\n\n        myRng.Activate\n\n\n        ActiveCell.Hyperlinks.Add Anchor:=Selection, SubAddress:=ShtName & \"!A1\", Address:=\"\", TextToDisplay:=ShtName\n\n\n    \n\n\n        End If\n\n\n    Next\n\n\n    'MsgBox Rows.Count\n\n\n    Set mySht = Nothing\n\n\n\n\n\nEnd Sub\n\n\n\n\n\n'ProtectSheet\n\n\n'使用保護修改的地方\n\n\nSub ProtectSheet()\n\n\n\n\n\n     ' Loop through all sheets in the workbook.\n\n\n     For i = 1 To Sheets.Count\n\n\n        Sheets(i).Protect\n\n\n     Next i\n\n\n\n\n\nEnd Sub\n\n\nSub UnprotectSheet()\n\n\n'\n\n\n' UnprotectSheet Macro\n\n\n' CR3-31 在 2011/6/7 錄製的巨集\n\n\n'\n\n\n\n\n\n'\n\n\n     For i = 1 To Sheets.Count\n\n\n          Sheets(i).Unprotect\n\n\n       Next i\n\n\nEnd Sub\n\n\n\n\n\n\n\n\nSub BatchRenameSheets()\n\n\nDim my_name, pre_name As String\n\n\nDim i, j As Byte\n\n\nDim my_range As Range\n\n\nSheets(1).Name = \"namelist\"\n\n\nSheets(\"namelist\").Activate\n\n\nRange(\"A1\").Activate\n\n\nmy_name = \"\"\n\n\npre_name = \"\"\n\n\nmy_name = ActiveCell.Text\n\n\nSet my_range = ActiveCell\n\n\n\n\n\nDo While my_name <> pre_name\n\n\n    my_name = my_name\n\n\n    Sheets(\"namelist\").Activate\n\n\n    my_range.Offset(1, 0).Activate\n\n\n    Set my_range = ActiveCell\n\n\n    my_name = ActiveCell.Text\n\n\nOn Error Resume Next\n\n\nj = i + 2\n\n\n    If my_name <> \"\" Then\n\n\n    Sheets.Add After:=Sheets(Sheets.Count)\n\n\n    Sheets(j).Name = my_name\n\n\n    End If\n\n\ni = i + 1\n\n\n'MsgBox my_name & my_name\n\n\nLoop\n\n\nSheets(1).Name = \"namelist\"\n\n\nSheets(\"namelist\").Activate\n\n\nRange(\"A1\").Activate\n\n\n\n\n\nEnd Sub\n\n\n\n\n\n\n\n\nSub DeleteAllNames()\n\n\n        Dim nm As Name\n\n\n        For Each nm In ThisWorkbook.Names\n\n\n            nm.Delete\n\n\n        Next nm\n\n\nEnd Sub\n\n\n\n\n\n'取得最後一列數號\n\n\nFunction GetLastRowNum(ByVal sheetName As String, ByVal columnAlpha As String)\n\n\n    Dim lastRowNum As Integer\n\n\n    On Error GoTo xls\n\n\n    'xlsx\n\n\n    lastRowNum = ThisWorkbook.Sheets(sheetName).Range(columnAlpha & \"1048576\").End(xlUp).Row\n\n\n    GetLastRowNum = lastRowNum\n\n\n    Exit Function\n\n\nxls:\n\n\n    lastRowNum = ThisWorkbook.Sheets(sheetName).Range(columnAlpha & \"65536\").End(xlUp).Row\n\n\n    GetLastRowNum = lastRowNum\n\n\nEnd Function\n\n\n\n\n\n'複製指定工作頁的範圍到目的工作頁\n\n\nFunction CopyRange(ByVal sourceSheetName As String, ByVal sourceColumnName As String _\n\n\n                                                    , ByVal sourceRawStart As Integer, ByVal sourceRawEnd As Integer _\n\n\n                                                                                       , ByVal destSheetName As String, ByVal destColumnName As String _\n\n\n                                                                                                                        , ByVal destRawStart As Integer)\n\n\n\n\n\n    ThisWorkbook.Sheets(sourceSheetName).Select\n\n\n    ThisWorkbook.Sheets(sourceSheetName).Range(sourceColumnName & CStr(sourceRawStart) _\n\n\n                                               & \":\" & sourceColumnName & CStr(sourceRawEnd)).Select\n\n\n    Selection.Copy\n\n\n    ThisWorkbook.Sheets(destSheetName).Select\n\n\n    ThisWorkbook.Sheets(destSheetName).Range(destColumnName & CStr(destRawStart)).Select\n\n\n    Selection.PasteSpecial Paste:=xlPasteValues, Operation:=xlNone, SkipBlanks _\n\n\n                                                                    :=False, Transpose:=False\n\n\n\n\n\nEnd Function\n\n\n\n\n\n\n\n\n\n\n\n", "content_b64": ""}, {"name": "ShellExecTool.bas", "path": "模組/Others/ShellExecTool.bas", "content": "Attribute VB_Name = \"ShellExecTool\"\nOption Explicit\n'*************************************************************************************\n'專案名稱: 底層元件\n'功能描述: 執行wsh shell函式\n'\n'版權所有: Dunk\n'程式撰寫: Dunk\n'撰寫日期：2017/9/20\n'\n'改版日期:\n'改版備註:\n'\n'*************************************************************************************\n\n' Windows API function declarations.\n#If VBA7 Then\n    Private Declare PtrSafe Function OpenProcess Lib \"kernel32.dll\" (ByVal dwDesiredAccessas As Long, _\n                                                                     ByVal bInheritHandle As Long, ByVal dwProcId As Long) As Long\n    Private Declare PtrSafe Function CloseHandle Lib \"kernel32.dll\" (ByVal hObject As Long) As Long\n    Private Declare PtrSafe Function WaitForSingleObject Lib \"kernel32.dll\" (ByVal hHandle As Long, _\n                                                                             ByVal dwMilliseconds As Long) As Long\n    Private Declare PtrSafe Function GetExitCodeProcess Lib \"kernel32.dll\" (ByVal hProcess As Long, _\n                                                                            ByRef lpExitCodeOut As Long) As Integer\n#Else\n    Private Declare Function OpenProcess Lib \"kernel32.dll\" (ByVal dwDesiredAccessas As Long, _\n                                                             ByVal bInheritHandle As Long, ByVal dwProcId As Long) As Long\n    Private Declare Function CloseHandle Lib \"kernel32.dll\" (ByVal hObject As Long) As Long\n    Private Declare Function WaitForSingleObject Lib \"kernel32.dll\" (ByVal hHandle As Long, _\n                                                                     ByVal dwMilliseconds As Long) As Long\n    Private Declare Function GetExitCodeProcess Lib \"kernel32.dll\" (ByVal hProcess As Long, _\n                                                                    ByRef lpExitCodeOut As Long) As Integer\n#End If\n\n'執行wsh\nFunction RunWshShell(ByVal cmd As String)\n\n    Dim wsh As Object\n    Set wsh = VBA.CreateObject(\"WScript.Shell\")\n    Dim waitOnReturn As Boolean: waitOnReturn = True\n    Dim windowStyle As Integer: windowStyle = 1\n    Dim errorCode As Long\n    errorCode = wsh.Run(cmd, windowStyle, waitOnReturn)\n    Set wsh = Nothing\n    RunWshShell = errorCode\nEnd Function\n\n'執行wsh\nFunction RunWshShellHidden(ByVal cmd As String)\n\n    Dim wsh As Object\n    Set wsh = VBA.CreateObject(\"WScript.Shell\")\n    Dim waitOnReturn As Boolean: waitOnReturn = True\n    Dim windowStyle As Integer: windowStyle = 0\n    Dim errorCode As Long\n    errorCode = wsh.Run(cmd, windowStyle, waitOnReturn)\n    Set wsh = Nothing\n    RunWshShellHidden = errorCode\nEnd Function\n\n' Synchronously executes the specified command and returns its exit code.\n' Waits indefinitely for the command to finish, unless you pass a\n' timeout value in seconds for `timeoutInSecs`.\nPrivate Function SyncShell(ByVal cmd As String, _\n                           Optional ByVal windowStyle As VbAppWinStyle = vbMinimizedFocus, _\n                           Optional ByVal timeoutInSecs As Double = -1) As Long\n    Dim pid As Long    ' PID (process ID) as returned by Shell().\n    Dim h As Long    ' Process handle\n    Dim sts As Long    ' WinAPI return value\n    Dim timeoutMs As Long    ' WINAPI timeout value\n    Dim exitCode As Long\n    ' Invoke the command (invariably asynchronously) and store the PID returned.\n    ' Note that this invocation may raise an error.\n    pid = Shell(cmd, windowStyle)\n    ' Translate the PIP into a process *handle* with the\n    ' SYNCHRONIZE and PROCESS_QUERY_LIMITED_INFORMATION access rights,\n    ' so we can wait for the process to terminate and query its exit code.\n    ' &H100000 == SYNCHRONIZE, &H1000 == PROCESS_QUERY_LIMITED_INFORMATION\n    h = OpenProcess(&H100000 Or &H1000, 0, pid)\n    If h = 0 Then\n        Err.Raise vbObjectError + 1024, , _\n                  \"Failed to obtain process handle for process with ID \" & pid & \".\"\n    End If\n    ' Now wait for the process to terminate.\n    If timeoutInSecs = -1 Then\n        timeoutMs = &HFFFF    ' INFINITE\n    Else\n        timeoutMs = timeoutInSecs * 1000\n    End If\n    sts = WaitForSingleObject(h, timeoutMs)\n    If sts <> 0 Then\n        Err.Raise vbObjectError + 1025, , _\n                  \"Waiting for process with ID \" & pid & _\n                  \" to terminate timed out, or an unexpected error occurred.\"\n    End If\n    ' Obtain the process's exit code.\n    sts = GetExitCodeProcess(h, exitCode)    ' Return value is a BOOL: 1 for true, 0 for false\n    If sts <> 1 Then\n        Err.Raise vbObjectError + 1026, , _\n                  \"Failed to obtain exit code for process ID \" & pid & \".\"\n    End If\n    CloseHandle h\n    ' Return the exit code.\n    SyncShell = exitCode\nEnd Function\n", "content_b64": ""}, {"name": "SortUtility.bas", "path": "模組/Others/SortUtility.bas", "content": "Attribute VB_Name = \"SortUtility\"\n\n\nOption Explicit\n\n\nSub SortByModifiedDateDesc()\n\n\nAttribute SortByModifiedDateDesc.VB_ProcData.VB_Invoke_Func = \" \\n14\"\n\n\n'檔案清單\n\n\n    ActiveWorkbook.Worksheets(\"檔案清單\").ListObjects(\"檔案清單_表格\").Sort.SortFields.Clear\n\n\n    ActiveWorkbook.Worksheets(\"檔案清單\").ListObjects(\"檔案清單_表格\").Sort.SortFields.Add _\n\n\n        Key:=Range(\"檔案清單_表格[[#All],[修改時間]]\"), SortOn:=xlSortOnValues, Order:= _\n\n\n        xlDescending, DataOption:=xlSortNormal\n\n\n    With ActiveWorkbook.Worksheets(\"檔案清單\").ListObjects(\"檔案清單_表格\").Sort\n\n\n        .Header = xlYes\n\n\n        .MatchCase = False\n\n\n        .Orientation = xlTopToBottom\n\n\n        .SortMethod = xlPinYin\n\n\n        .Apply\n\n\n    End With\n\n\n'子目錄清單\n\n\n    ActiveWorkbook.Worksheets(\"子目錄清單\").ListObjects(\"檔案清單_目錄\").Sort.SortFields.Clear\n\n\n    ActiveWorkbook.Worksheets(\"子目錄清單\").ListObjects(\"檔案清單_目錄\").Sort.SortFields.Add _\n\n\n        Key:=Range(\"檔案清單_目錄[[#All],[修改時間]]\"), SortOn:=xlSortOnValues, Order:= _\n\n\n        xlDescending, DataOption:=xlSortNormal\n\n\n    With ActiveWorkbook.Worksheets(\"子目錄清單\").ListObjects(\"檔案清單_目錄\").Sort\n\n\n        .Header = xlYes\n\n\n        .MatchCase = False\n\n\n        .Orientation = xlTopToBottom\n\n\n        .SortMethod = xlPinYin\n\n\n        .Apply\n\n\n    End With\n\n\nEnd Sub\n\n\n", "content_b64": ""}, {"name": "SqlStatement.bas", "path": "模組/Others/SqlStatement.bas", "content": "Attribute VB_Name = \"SqlStatement\"\n\nOption Explicit\n\n'*************************************************************************************\n\n'專案名稱: VBA專案\n\n'功能描述: SQL指令彙整\n\n'\n\n'版權所有: Dunk\n\n'程式撰寫: Dunk\n\n'撰寫日期：2015/7/30\n\n'\n\n'改版日期:\n\n'改版備註:\n\n'*************************************************************************************\n\nFunction GetDbTableCompareFormat(ByVal tableName As String) As Variant\n\n    GetDbTableCompareFormat = \"SELECT   a.TABLE_NAME as [Table ID],a.COLUMN_NAME as [Column name],\" & Chr(13) & \"\" & Chr(10) & \"case a.DATA_TYPE \" & Chr(13) & \"\" & Chr(10) & \"when 'char' then a.DATA_TYP\" _\n\n        & \"E +'(' +cast(a.CHARACTER_MAXIMUM_LENGTH as varchar)+ ')'\" & Chr(13) & \"\" & Chr(10) & \"when 'varchar' then a.DATA_TYPE +'(' +cast(a.CHARACTER_MA\" _\n\n        & \"XIMUM_LENGTH as varchar)+ ')'\" & Chr(13) & \"\" & Chr(10) & \"when 'decimal' then a.DATA_TYPE +'(' +cast(a.NUMERIC_PRECISION as varchar)+','+cast(\" _\n\n        & \"a.NUMERIC_SCALE AS varchar)+ ')'\" & Chr(13) & \"\" & Chr(10) & \"ELSE a.DATA_TYPE\" & Chr(13) & \"\" & Chr(10) & \"end as [Data type],\" & Chr(13) & \"\" & Chr(10) & \"N'N' as [New column(Y/N)],\" & Chr(13) & \"\" & Chr(10) & \"N'N' as [Data \" _\n\n        & \"type changed\" & Chr(13) & \"\" & Chr(10) & \"N: no change\" & Chr(13) & \"\" & Chr(10) & \"Data type],\" & Chr(13) & \"\" & Chr(10) & \"N'' as [Default value],\" & Chr(13) & \"\" & Chr(10) & \"N'unchanged' as [transporting type],\" & Chr(13) & \"\" & Chr(10) & \"a.ORDINAL_P\" _\n\n        & \"OSITION as [New column id],\" & Chr(13) & \"\" & Chr(10) & \"a.ORDINAL_POSITION as [Original column id]\" & Chr(13) & \"\" & Chr(10) & \"FROM INFORMATION_SCHEMA.COLUMNS a \" & Chr(13) & \"\" & Chr(10) & \"inner \" _\n\n        & \"join INFORMATION_SCHEMA.TABLES b on\" & Chr(13) & \"\" & Chr(10) & \"a.TABLE_NAME = b.TABLE_NAME\" & Chr(13) & \"\" & Chr(10) & \"where b.TABLE_TYPE='BASE TABLE' and a.TABLE_NAME \" _\n\n        & \"='\" & tableName & \"'\" & Chr(13) & \"\" & Chr(10) & \"order by b.TABLE_NAME,a.ORDINAL_POSITION\"\n\nEnd Function\n\n\n\nFunction GetTableData(ByVal tableName As String) As Variant\n\n    GetTableData = \"select * from \" & tableName\n\nEnd Function\n\n", "content_b64": ""}, {"name": "SqlStatementDB2.bas", "path": "模組/Others/SqlStatementDB2.bas", "content": "Attribute VB_Name = \"SqlStatementDB2\"\n\nOption Explicit\n\n'*************************************************************************************\n\n'專案名稱: 雪梨分行集中\n\n'功能描述: SQL指令彙整\n\n'\n\n'版權所有: Dunk\n\n'程式撰寫: Dunk\n\n'撰寫日期：2015/10/26\n\n'\n\n'改版日期:\n\n'改版備註:\n\n'*************************************************************************************\n\n\n\nFunction GetTableData(ByVal tableName As String, ByVal schemaName As String) As Variant\n\n    GetTableData = \"select * from \" & schemaName & \".\" & tableName\n\nEnd Function\n\n\n\nFunction GetTableSchema(ByVal tableName As String, ByVal schemaName As String) As Variant\n\n    GetTableSchema = \"   SELECT TABNAME AS TABLEID, COLNAME AS COLUMNNAME,     CASE TYPENAME \" & _\n\n      \"WHEN 'CHARACTER' THEN LOWER('CHAR') || '(' || LENGTH || ')' \" & _\n\n      \"WHEN 'VARCHAR' THEN LOWER(TYPENAME) || '(' || LENGTH || ')' \" & _\n\n      \"WHEN 'DECIMAL' THEN LOWER(TYPENAME) || '(' || LENGTH || ',' || SCALE || ')'\" & _\n\n      \"Else LOWER (TypeName) \" & _\n\n    \"END AS DATATYPEDESC, COLNO + 1 AS ORIGINALCOLUMNID \" & _\n\n  \"FROM SYSCAT.Columns \" & _\n\n  \"WHERE TABSCHEMA = '\" & schemaName & \"' AND TABNAME = '\" & tableName & \"' \" & _\n\n  \"ORDER BY TABLEID, COLNO;\"\n\nEnd Function\n\n", "content_b64": ""}, {"name": "StringUtility.bas", "path": "模組/Others/StringUtility.bas", "content": "Attribute VB_Name = \"StringUtility\"\n\nOption Explicit\n\n''字串處理模組\n\n''作者：Guan Jhih Liao\n\n\n\n'顯示今日日期(民國年YYYMMDD)\n\nPublic Function Today() As String\n\n  Today = Format(Date, \"yyyymmdd\")\n\n  Today = Today - 19110000\n\n  TodayTw = Format(TodayTw, \"0######\")\n\nEnd Function\n\n\n\n'將字串轉成數字\n\nPublic Function Str2Val(ByVal sNum As String) As Double\n\n   sNum = Format(sNum, \"#\")\n\n   Str2Val = Val(sNum)\n\nEnd Function\n\n\n\n'切割字串根據字元長度(Byte Length)\n\n'長度超過時會補空白\n\n'mode=\"L\":左補空白\n\n'mode=\"M\":置中(兩側擺空白)\n\n'未指定為右補空白\n\nPublic Function FixStr(ByVal iStr As String, ByVal fixlen As Integer, ByVal mode As String) As String\n\n   Dim strlen   As Integer\n\n   Dim strTemp  As String\n\n   Dim x        As Integer\n\n   Dim i        As Integer\n\n   Dim C        As String\n\n   Dim newStr   As String\n\n   Dim nowlen   As Integer\n\n   \n\n'   iStr = Trim(iStr)\n\n   strlen = 0\n\n   strTemp = iStr\n\n   newStr = \"\"\n\n   \n\n   Do While Len(strTemp) > 0\n\n      C = Left(strTemp, 1)\n\n      If Asc(C) < 0 Then\n\n         nowlen = 2\n\n      Else\n\n         nowlen = 1\n\n      End If\n\n      \n\n      If (strlen + nowlen) > fixlen Then\n\n         Exit Do\n\n      Else\n\n         strlen = strlen + nowlen\n\n      End If\n\n      newStr = newStr + C\n\n      \n\n      strTemp = Right(strTemp, Len(strTemp) - 1)\n\n   Loop\n\n   \n\n   x = fixlen - strlen\n\n   If x > 0 Then\n\n      If mode = \"L\" Then\n\n         FixStr = Space(x) + newStr\n\n      Else\n\n         If mode = \"M\" Then\n\n            i = x Mod 2\n\n            If i = 0 Then\n\n               FixStr = Space(x / 2) + newStr + Space(x / 2)\n\n            Else\n\n               i = x / 2\n\n               FixStr = Space(i) + newStr + Space(x - i)\n\n            End If\n\n         Else\n\n            FixStr = newStr + Space(x)\n\n         End If\n\n      End If\n\n   Else\n\n      FixStr = newStr\n\n   End If\n\nEnd Function\n\n\n\n'擷取字串根據指定開始位置及字元長度(Byte Length)\n\nPublic Function MidMbcs(ByVal str As String, start As Integer, Optional length As Integer) As String\n\n   Dim strlen   As Integer\n\n   Dim strTemp  As String\n\n   Dim i        As Integer\n\n   Dim C        As String\n\n   Dim newStr   As String\n\n   Dim nowlen   As Integer\n\n   \n\n   strlen = 0\n\n   strTemp = str\n\n   newStr = \"\"\n\n   \n\n   \n\n   If start < 1 Then start = 1\n\n   i = 0\n\n   Do While i < (start - 1)\n\n      If Len(strTemp) <= 0 Then Exit Do\n\n      \n\n      C = Left(strTemp, 1)\n\n      If Asc(C) < 0 Then\n\n         nowlen = 2\n\n      Else\n\n         nowlen = 1\n\n      End If\n\n      \n\n      If (i + nowlen) >= start Then\n\n         Exit Do\n\n      Else\n\n         i = i + nowlen\n\n         strTemp = Right(strTemp, Len(strTemp) - 1)\n\n      End If\n\n      \n\n      If strTemp = \"\" Then\n\n         Exit Do\n\n      End If\n\n   Loop\n\n    \n\n   Do While Len(strTemp) > 0\n\n      C = Left(strTemp, 1)\n\n      If Asc(C) < 0 Then\n\n         nowlen = 2\n\n      Else\n\n         nowlen = 1\n\n      End If\n\n      \n\n      If (strlen + nowlen) > length And length <> 0 Then\n\n         Exit Do\n\n      Else\n\n         strlen = strlen + nowlen\n\n      End If\n\n      newStr = newStr + C\n\n      \n\n      strTemp = Right(strTemp, Len(strTemp) - 1)\n\n   Loop\n\n   MidMbcs = newStr\n\nEnd Function\n\n\n\n'擷取字串根據字元長度(Byte Length)\n\n'不足指定長度會去除最後一個byte\n\nPublic Function cutchar(dataString As String, limit As Integer) As String\n\n    Dim i As Integer\n\n    Dim s As String\n\n    Dim sql As String\n\n  \n\n    sql = \"\"\n\n    s = \"\"\n\n    i = 0\n\n    Do While Len(dataString) <> 0\n\n       s = Left(dataString, 1)\n\n       \n\n       If Asc(s) < 0 Then\n\n          i = i + 2\n\n       Else\n\n          i = i + 1\n\n       End If\n\n       \n\n       If i <= limit Then\n\n          sql = sql + s\n\n          dataString = Right(dataString, Len(dataString) - 1)\n\n          If Asc(s) = 13 Then\n\n             Exit Do\n\n          End If\n\n       Else\n\n          Exit Do\n\n       End If\n\n   Loop\n\n   cutchar = sql\n\n   \n\nEnd Function\n\n\n\n\n\n'將來源字串移除指定的文字\n\nPublic Function InStrDel(ByVal strData As String, ByVal strDelStr As String) As String\n\n    Dim i As Integer\n\n    Dim s As String\n\n    Dim sql As String\n\n\n\n    sql = \"\"\n\n    s = \"\"\n\n    i = 0\n\n    strData = Trim(strData)\n\n\n\n    Do While Len(strData) <> 0\n\n       s = Left(strData, 1)\n\n       Debug.Print Asc(s)\n\n       Debug.Print Asc(strDelStr)\n\n\n\n       If Asc(s) = Asc(strDelStr) Then\n\n       Else\n\n          sql = sql + s\n\n       End If\n\n       strData = Right(strData, Len(strData) - 1)\n\n\n\n   Loop\n\n   InStrDel = sql\n\n\n\n   \n\n'   If Len(strData) = 0 Then Exit Function\n\n'   Do\n\n'      W = InStr(strData, Asc(strDelStr))\n\n'      If W = 0 Then Exit Do\n\n'      strData = Left(strData, W - 1) & Right(strData, Len(strData) - W)\n\n'   Loop\n\n'   InStrDel = strData\n\nEnd Function\n\n\n\n", "content_b64": ""}, {"name": "WebHtmlFetch.bas", "path": "模組/Others/WebHtmlFetch.bas", "content": "Attribute VB_Name = \"WebHtmlFetch\"\nOption Explicit\n'*************************************************************************************\n'專案名稱: 網頁處理底層工具\n'功能描述:\n'https://stackoverflow.com/questions/4998715/does-vba-have-any-built-in-url-decoding\n'版權所有: Dunk\n'程式撰寫: Dunk\n'撰寫日期：2024/8/5\n'\n'改版日期:\n'改版備註:\n'*************************************************************************************\n'Microsoft Internet Controls設定引用項目\n'Microsoft HTML Object Library設定引用項目\nPublic Function FetUrlsFromPage(ByVal mySiteUrl As String)\n    Dim myIE      As InternetExplorer\n    Dim myDoc     As MSHTML.HTMLDocument\n    Dim myLnk     As MSHTML.HTMLAnchorElement\n    Dim myErr     As Long\n    Dim i         As Long\n    Dim counter   As Integer\n    counter = 0\n    Dim myTempList(65536) As String\n    Dim myLinkList() As String\n    \n    Set myIE = New InternetExplorer\n    With myIE\n        .Navigate mySiteUrl\n        .Visible = True\n        Do While .Busy\n        Loop\n        Do Until .ReadyState = READYSTATE_COMPLETE\n        Loop\n        Set myDoc = .Document\n    End With\n    With myDoc\n        If .frames.Length > 0 Then\n            For i = 0 To .frames.Length _\n            - 1\n                On Error Resume Next\n                myErr = Err.Number\n                On Error GoTo 0\n                Err.Clear\n                If myErr = 0 Then\n                    For Each myLnk In .frames(i).Document.Links\n                        myTempList(counter) = myLnk.href\n                        counter = counter + 1\n                    Next\n                End If\n            Next\n        Else\n            For Each myLnk In .Links\n                myTempList(counter) = myLnk.href\n                counter = counter + 1\n            Next\n        End If\n    End With\n    myIE.Quit\n    Set myIE = Nothing                   '釋放物件\n    Set myDoc = Nothing\n    ReDim myLinkList(counter)\n    For i = 0 To counter\n        myLinkList(i) = myTempList(i)\n    Next\n    FetUrlsFromPage = myLinkList\nEnd Function\n\nPublic Function FetUrlTitlesFromPage(ByVal mySiteUrl As String)\n    Dim myIE      As InternetExplorer\n    Dim myDoc     As MSHTML.HTMLDocument\n    Dim myLnk     As MSHTML.HTMLAnchorElement\n    Dim myErr     As Long\n    Dim i         As Long\n    Dim counter   As Integer\n    counter = 0\n    Dim myTempList(65536) As String\n    Dim myLinkList() As String\n    Set myIE = New InternetExplorer 'CreateObject(\"InternetExplorer.Application\")\n    With myIE\n        .Navigate mySiteUrl\n        .Visible = True\n        Do While .Busy\n        Loop\n        Do Until .ReadyState = READYSTATE_COMPLETE\n        Loop\n        Set myDoc = .Document\n    End With\n    With myDoc\n        If .frames.Length > 0 Then\n            For i = 0 To .frames.Length - 1\n                On Error Resume Next\n                myErr = Err.Number\n                On Error GoTo 0\n                Err.Clear\n                If myErr = 0 Then\n                    For Each myLnk In .frames(i).Document.Links\n                        myTempList(counter) = myLnk.innerText\n                        counter = counter + 1\n                    Next\n                End If\n            Next\n        Else\n            For Each myLnk In .Links\n                myTempList(counter) = myLnk.innerText\n                counter = counter + 1\n            Next\n        End If\n    End With\n    myIE.Quit\n    Set myIE = Nothing                   '釋放物件\n    Set myDoc = Nothing\n    ReDim myLinkList(counter)\n    For i = 0 To counter\n        myLinkList(i) = myTempList(i)\n    Next\n    FetUrlTitlesFromPage = myLinkList\nEnd Function\n\n'抓取網頁內容\nFunction FetchHtmlContent(ByVal myURL As String, ByVal Worksheet As Worksheet)\n     Dim urlConnection As String\n     urlConnection = \"URL;\" & myURL\n     Worksheet.Columns.Delete\n    '指定讀入表單\n    With Worksheet\n        With .QueryTables.Add(Connection:=urlConnection, Destination:=Range(\"A1\"))\n                         '讀入目標儲存格\n            .WebSelectionType = xlEntirePage\n            .WebFormatting = xlWebFormattingAll\n            .Refresh BackgroundQuery:=False\n        End With\n    .Cells.EntireColumn.AutoFit\n    End With\nEnd Function\n\n'將網址編碼,記得引用Microsoft Internet Controls\nFunction ENCODEURL(varText As Variant, Optional blnEncode = True)\n    Static objHtmlfile As Object\n    If objHtmlfile Is Nothing Then\n        Set objHtmlfile = CreateObject(\"htmlfile\")\n        With objHtmlfile.parentWindow\n            .execScript \"function encode(s) {return encodeURIComponent(s)}\", \"jscript\"\n        End With\n    End If\n    If blnEncode Then\n        ENCODEURL = objHtmlfile.parentWindow.encode(varText)\n    End If\nEnd Function\n\n'將網址解碼\nFunction DECODEURL(varText As Variant, Optional blnEncode = True)\n    Static objHtmlfile As Object\n    If objHtmlfile Is Nothing Then\n        Set objHtmlfile = CreateObject(\"htmlfile\")\n        With objHtmlfile.parentWindow\n            .execScript \"function decode(s) {return decodeURIComponent(s)}\", \"jscript\"\n        End With\n    End If\n    If blnEncode Then\n        DECODEURL = objHtmlfile.parentWindow.decode(varText)\n    End If\nEnd Function\n", "content_b64": ""}, {"name": "活頁簿管理.bas", "path": "模組/Others/活頁簿管理.bas", "content": "Attribute VB_Name = \"活頁簿管理\"\n\nOption Explicit\n\n\n\nSub CreateSheetsWithHyperlinks()\n\n  Application.ScreenUpdating = False\n\n  Call BatchRenameSheets\n\n  Application.DisplayAlerts = False\n\n  Sheets(\"總表\").Delete\n\n  Application.DisplayAlerts = True\n\n  Call CreateSheetIndex\n\n  Application.ScreenUpdating = True\n\nEnd Sub\n\n\n\nSub BatchRenameSheets()\n\n\n\n'刪除現有工作表\n\nDim q  As Integer\n\nApplication.DisplayAlerts = False\n\n    Sheets(\"工作表2\").Select\n\n    ActiveWindow.SelectedSheets.Delete\n\n    Sheets(\"工作表3\").Select\n\n    ActiveWindow.SelectedSheets.Delete\n\nApplication.DisplayAlerts = True\n\n\n\n'增加工作表\n\nDim my_name, pre_name As String\n\nDim i, j As Byte\n\nDim my_range As Range\n\nSheets(1).Name = \"總表\"\n\nSheets(\"總表\").Activate\n\nRange(\"A1\").Activate\n\nmy_name = \"\"\n\npre_name = \"\"\n\nmy_name = ActiveCell.Text\n\nSet my_range = ActiveCell\n\n\n\nDo While my_name <> pre_name\n\n    my_name = my_name\n\n    Sheets(\"總表\").Activate\n\n    my_range.Offset(1, 0).Activate\n\n    Set my_range = ActiveCell\n\n    my_name = ActiveCell.Text\n\nOn Error Resume Next\n\nj = i + 2\n\n    If my_name <> \"\" Then\n\n    Sheets.Add After:=Sheets(Sheets.Count)\n\n    Sheets(j).Name = my_name\n\n    End If\n\ni = i + 1\n\n'MsgBox my_name & my_name\n\nLoop\n\nSheets(1).Name = \"總表\"\n\nSheets(\"總表\").Activate\n\nRange(\"A1\").Activate\n\n\n\nEnd Sub\n\n\n\nSub CreateSheetIndex()\n\n    Dim mySht As Worksheet\n\n    Dim ShtName As String\n\n    Dim myRng As Range\n\n    Dim i, j As Integer\n\n    Dim myWb As Workbook\n\n    Set myWb = ActiveWorkbook\n\n    Set mySht = myWb.Worksheets.Add(Count:=1, Before:=Sheets(1))\n\n    \n\n    On Error Resume Next\n\n   \n\n    mySht.Name = \"工作表索引\"\n\n    Columns(1).Clear                            '儲存格的清除\n\n    Set myRng = Range(\"A1\")\n\n    Range(\"A1\").Value = \"工作表索引\"            '標題的設定\n\n    \n\n    For Each mySht In Worksheets\n\n        ShtName = mySht.Name\n\n        If mySht.Name = \"工作表索引\" Then\n\n            Sheets(\"工作表索引\").Activate\n\n            Columns(1).Clear                            '儲存格的清除\n\n            Set myRng = Range(\"A1\")\n\n            Range(\"A1\").Value = \"工作表索引\"            '標題的設定\n\n\n\n        Else\n\n        \n\n     '   Cells(Rows.Count, 2).End(xlUp).Offset(1).Value = mySht.Name     '參考 說明()\n\n    '    MsgBox mySht.Name\n\n        Set myRng = myRng.Offset(1)\n\n        myRng.Activate\n\n        ActiveCell.Hyperlinks.Add Anchor:=Selection, SubAddress:=\"'\" & ShtName & \"'\" & \"!A1\", Address:=\"\", TextToDisplay:=ShtName\n\n    \n\n        End If\n\n    Next\n\n    'MsgBox Rows.Count\n\n    Set mySht = Nothing\n\n\n\n\n\nEnd Sub\n\n\n\nSub ProtectAllSheets()\n\n\n\n     ' Loop through all sheets in the workbook.\n\n     Dim i As Integer\n\n     For i = 1 To Sheets.Count\n\n        Sheets(i).Protect\n\n     Next i\n\nEnd Sub\n\n\n\nSub UnprotectAllSheets()\n\n     ' Loop through all sheets in the workbook.\n\n     Dim i As Integer\n\n     For i = 1 To Sheets.Count\n\n        Sheets(i).Unprotect\n\n     Next i\n\nEnd Sub\n\nSub ClearContent()\n\n    Selection.Borders(xlDiagonalDown).LineStyle = xlNone\n\n    Selection.Borders(xlDiagonalUp).LineStyle = xlNone\n\n    Selection.Borders(xlEdgeLeft).LineStyle = xlNone\n\n    Selection.Borders(xlEdgeTop).LineStyle = xlNone\n\n    Selection.Borders(xlEdgeBottom).LineStyle = xlNone\n\n    Selection.Borders(xlEdgeRight).LineStyle = xlNone\n\n    Selection.Borders(xlInsideVertical).LineStyle = xlNone\n\n    Selection.Borders(xlInsideHorizontal).LineStyle = xlNone\n\n    Selection.ClearContents\n\n    With Selection.Interior\n\n        .Pattern = xlNone\n\n        .TintAndShade = 0\n\n        .PatternTintAndShade = 0\n\n    End With\n\n    ActiveCell.Select\n\nEnd Sub\n\n\n\nSub AutoFitColumnsToContent()\n\n    ActiveSheet.Columns.AutoFit\n\nEnd Sub\n\n", "content_b64": ""}]}, {"folder": "Outlook", "path": "模組/Outlook", "files": [{"name": "AutoReply.bas", "path": "模組/Outlook/AutoReply.bas", "content": "Attribute VB_Name = \"AutoReply\"\n\nOption Explicit\n\n'*************************************************************************************\n\n'專案名稱: 期信基金帳務處理\n\n'功能描述:\n\n' email自動回覆內容\n\n\n\n'版權所有: Dunk\n\n'程式撰寫: Dunk\n\n'撰寫日期：2017/10/26\n\n'\n\n'改版日期:\n\n'改版備註: 2020/3/12 增加C_Step1_TaishinLongRedBalanceOK\n\n'\n\n'*************************************************************************************\n\nSub C_Step1_ReplyReceiveFAXOK()\n\n    ReplyAllWithSubjectAddMsg (\"_已收到謝謝\")\n\nEnd Sub\n\n\n\nSub C_Step2_ReplyReceiveFAXNotOK()\n\n    ReplyAllWithSubjectAddMsg (\"_未收到請重傳FAX\")\n\nEnd Sub\n\n\n\nSub C_Step1_TaishinLongRedBalanceOK()\n\n    ReplyWithSubjectAddMsgToUser \"_餘額OK\", \"claire.ku@tsit.com.tw]\"\n\nEnd Sub\n\n\n\nFunction ReplyAllWithSubjectAddMsg(ByVal msg As String)\n\n    Dim mail    'object/mail item iterator\n\n    Dim replyall    'object which will represent the reply email\n\n\n\n    For Each mail In Outlook.Application.ActiveExplorer.Selection\n\n        If mail.Class = olMail Then\n\n            Set replyall = mail.replyall\n\n            With replyall\n\n                .Subject = .Subject & msg\n\n                .Send\n\n            End With\n\n        End If\n\n    Next\n\nEnd Function\n\n\n\n\n\nFunction ReplyWithSubjectAddMsgToUser(ByVal msg As String, ByVal ToList As String)\n\n    Dim mail    'object/mail item iterator\n\n    Dim replyall    'object which will represent the reply email\n\n\n\n    For Each mail In Outlook.Application.ActiveExplorer.Selection\n\n        If mail.Class = olMail Then\n\n            Set replyall = mail.replyall\n\n            With replyall\n\n                .Subject = .Subject & msg\n\n                .To = ToList\n\n                .Send\n\n            End With\n\n        End If\n\n    Next\n\nEnd Function\n\n", "content_b64": ""}, {"name": "CreateCalendarAppointment.bas", "path": "模組/Outlook/CreateCalendarAppointment.bas", "content": "Attribute VB_Name = \"CreateCalendarAppointment\"\nOption Explicit\n'*************************************************************************************\n' 專案名稱: 建立行事曆約會範例\n' 功能說明: 透過 Outlook 建立一筆約會並顯示給使用者確認\n'*************************************************************************************\n\nPrivate Const OL_APPOINTMENT_ITEM As Long = 1\nPrivate Const OL_BUSY As Long = 2\n\nPublic Sub CreateCalendarAppointmentExample()\n    On Error GoTo ErrorHandler\n\n    Dim outlookApp As Object\n    Dim appointmentItem As Object\n    Dim subjectText As String\n    Dim startText As String\n    Dim minutesText As String\n    Dim startTime As Date\n    Dim durationMinutes As Long\n\n    subjectText = InputBox(\"請輸入約會主旨\", \"建立約會\", \"例行會議\")\n    If Len(Trim$(subjectText)) = 0 Then\n        Exit Sub\n    End If\n\n    startText = InputBox(\"請輸入開始時間，例如 2026/05/09 14:00\", \"建立約會\", Format$(Now + 1, \"yyyy/mm/dd hh:nn\"))\n    If Not IsDate(startText) Then\n        MsgBox \"開始時間格式不正確。\", vbExclamation, \"建立約會\"\n        Exit Sub\n    End If\n\n    minutesText = InputBox(\"請輸入會議分鐘數\", \"建立約會\", \"60\")\n    If Not IsNumeric(minutesText) Then\n        MsgBox \"分鐘數必須是數字。\", vbExclamation, \"建立約會\"\n        Exit Sub\n    End If\n\n    startTime = CDate(startText)\n    durationMinutes = CLng(minutesText)\n\n    Set outlookApp = GetCreateCalendarAppointmentOutlookApp()\n    Set appointmentItem = outlookApp.CreateItem(OL_APPOINTMENT_ITEM)\n\n    With appointmentItem\n        .Subject = subjectText\n        .Start = startTime\n        .Duration = durationMinutes\n        .BusyStatus = OL_BUSY\n        .ReminderSet = True\n        .ReminderMinutesBeforeStart = 15\n        .Body = \"此約會由 VBA 範例建立，請確認內容後儲存。\"\n        .Display\n    End With\n\nCleanExit:\n    Set appointmentItem = Nothing\n    Set outlookApp = Nothing\n    Exit Sub\n\nErrorHandler:\n    MsgBox \"建立約會時發生錯誤：\" & Err.Description, vbExclamation, \"建立約會\"\n    Resume CleanExit\nEnd Sub\n\nPrivate Function GetCreateCalendarAppointmentOutlookApp() As Object\n    On Error Resume Next\n\n    Set GetCreateCalendarAppointmentOutlookApp = GetObject(, \"Outlook.Application\")\n    If GetCreateCalendarAppointmentOutlookApp Is Nothing Then\n        Set GetCreateCalendarAppointmentOutlookApp = CreateObject(\"Outlook.Application\")\n    End If\nEnd Function", "content_b64": ""}, {"name": "CreateContactsFromExcelRows.bas", "path": "模組/Outlook/CreateContactsFromExcelRows.bas", "content": "Attribute VB_Name = \"CreateContactsFromExcelRows\"\nOption Explicit\n'*************************************************************************************\n' 專案名稱: 由 Excel 建立 Outlook 聯絡人範例\n' 功能說明: 讀取目前工作表 A:C 欄，建立 Outlook 聯絡人\n'*************************************************************************************\n\nPrivate Const OL_CONTACT_ITEM As Long = 2\n\nPublic Sub CreateContactsFromExcelRowsExample()\n    On Error GoTo ErrorHandler\n\n    Dim outlookApp As Object\n    Dim contactItem As Object\n    Dim worksheetObject As Object\n    Dim lastRow As Long\n    Dim rowIndex As Long\n    Dim createdCount As Long\n    Dim fullName As String\n    Dim emailAddress As String\n    Dim phoneNumber As String\n\n    Set worksheetObject = ActiveSheet\n    lastRow = worksheetObject.Cells(worksheetObject.Rows.Count, \"A\").End(-4162).Row\n\n    If lastRow < 2 Then\n        MsgBox \"目前工作表沒有可建立的聯絡人資料。\", vbInformation, \"建立聯絡人\"\n        Exit Sub\n    End If\n\n    Set outlookApp = GetCreateContactsFromRowsOutlookApp()\n\n    For rowIndex = 2 To lastRow\n        fullName = Trim$(CStr(worksheetObject.Cells(rowIndex, \"A\").Value))\n        emailAddress = Trim$(CStr(worksheetObject.Cells(rowIndex, \"B\").Value))\n        phoneNumber = Trim$(CStr(worksheetObject.Cells(rowIndex, \"C\").Value))\n\n        If Len(fullName) > 0 And Len(emailAddress) > 0 Then\n            Set contactItem = outlookApp.CreateItem(OL_CONTACT_ITEM)\n            With contactItem\n                .FullName = fullName\n                .Email1Address = emailAddress\n                .BusinessTelephoneNumber = phoneNumber\n                .Save\n            End With\n            createdCount = createdCount + 1\n        End If\n    Next rowIndex\n\n    MsgBox \"聯絡人建立完成，共建立 \" & CStr(createdCount) & \" 筆。\", vbInformation, \"建立聯絡人\"\n\nCleanExit:\n    Set contactItem = Nothing\n    Set worksheetObject = Nothing\n    Set outlookApp = Nothing\n    Exit Sub\n\nErrorHandler:\n    MsgBox \"建立聯絡人時發生錯誤：\" & Err.Description, vbExclamation, \"建立聯絡人\"\n    Resume CleanExit\nEnd Sub\n\nPrivate Function GetCreateContactsFromRowsOutlookApp() As Object\n    On Error Resume Next\n\n    Set GetCreateContactsFromRowsOutlookApp = GetObject(, \"Outlook.Application\")\n    If GetCreateContactsFromRowsOutlookApp Is Nothing Then\n        Set GetCreateContactsFromRowsOutlookApp = CreateObject(\"Outlook.Application\")\n    End If\nEnd Function", "content_b64": ""}, {"name": "DealOilFunAttachment.bas", "path": "模組/Outlook/DealOilFunAttachment.bas", "content": "Attribute VB_Name = \"DealOilFunAttachment\"\n\nOption Explicit\n\n'*************************************************************************************\n\n'專案名稱: 期信基金處理\n\n'功能描述:\n\n' email 收件自動下載列印(華頓石油)\n\n\n\n'版權所有: Dunk\n\n'程式撰寫: Dunk\n\n'撰寫日期：2018/3/7\n\n'\n\n'改版日期:\n\n'改版備註:\n\n'\n\n'*************************************************************************************\n\n\n\n\n\n'將基金代理收件匣未讀取信件的所有附件檔另存\n\nSub ProcessOilFundAttachment()\n\n    Dim myNameSpace As Outlook.NameSpace\n\n    Dim myFolder As Outlook.MAPIFolder\n\n    Dim myAttachments As Outlook.Attachments\n\n    Dim myItems As Outlook.Items\n\n    Dim TargetFolder As String, SFName As String, NSFName As String\n\n    Dim resultFolder As String\n\n    Dim i As Integer\n\n    Dim fs As Variant\n\n    Dim mail, att, ReturnVal As Variant\n\n\n\n    '重建資料夾，執行前先清除有可能造成鎖定的檔案\n\n    TargetFolder = \"Z:\\全委組帳務\\帳務--新制轉檔報表\\蘭錦\\華頓石油\"\n\n    Sleep (2000)\n\n    MakeDirOil (TargetFolder)\n\n\n\n    Set fs = CreateObject(\"Scripting.FileSystemObject\")\n\n    Set myNameSpace = Application.GetNamespace(\"MAPI\")\n\n    Set myFolder = myNameSpace.Folders(\"個人資料夾\").Folders(\"01.工作\").Folders(\"01.基金代理\")\n\n    'myFolder 代表 \"收件匣 Inbox\"\n\n    Set myItems = myFolder.Items\n\n    'myItems 代表 \"收件匣\" 中所有信件 (的集合)\n\n    For Each mail In myItems   '檢查每一封信\n\n        If mail.UnRead = True Then\n\n            resultFolder = TargetFolder\n\n            Set myAttachments = mail.Attachments\n\n            'myAttachments 代表這封信件裡所有附件檔 (的集合)\n\n            For Each att In myAttachments\n\n                SFName = resultFolder & \"\\\" & att.fileName\n\n                If fs.FileExists(SFName) Then    '若檔案已存在, 就加上 (數字)\n\n                    i = 0\n\n                    Do\n\n                        NSFName = TargetFolder & \"\\\" & fs.GetBaseName(SFName) _\n\n                                  & \"(\" & i & \").\" & fs.GetExtensionName(SFName)\n\n                        i = i + 1\n\n                    Loop While fs.FileExists(NSFName)\n\n                    att.SaveAsFile NSFName    '用加了數字的檔名儲存\n\n                Else\n\n                    att.SaveAsFile SFName  ''若檔案不存在, 就用原來的檔名儲存\n\n                End If\n\n            Next att\n\n            mail.UnRead = False\n\n        End If\n\n    Next mail\n\n    'att.PrintOut\n\n    OpenFolder2 (TargetFolder)\n\nEnd Sub\n\n\n\n'排除建立資料夾時的特殊字元\n\nFunction GetFolderName(ByVal fileName As String)\n\n    Dim strname As String\n\n    strname = fileName\n\n    strname = Replace(strname, \"*\", \"_\")\n\n    strname = Replace(strname, \"\\\", \"_\")\n\n    strname = Replace(strname, \"/\", \"_\")\n\n    strname = Replace(strname, \"$\", \"_\")\n\n    strname = Replace(strname, \"%\", \"_\")\n\n    strname = Replace(strname, \"!\", \"_\")\n\n    strname = Replace(strname, \"~\", \"_\")\n\n    strname = Replace(strname, \"(\", \"_\")\n\n    strname = Replace(strname, \")\", \"_\")\n\n    strname = Replace(strname, \"+\", \"_\")\n\n    strname = Replace(strname, \":\", \"_\")\n\n    strname = Replace(strname, \"<\", \"_\")\n\n    strname = Replace(strname, \">\", \"_\")\n\n    strname = Replace(strname, \"|\", \"_\")\n\n    strname = Replace(strname, \"?\", \"_\")\n\n    strname = Replace(strname, \"\"\"\", \"_\")\n\n    strname = Replace(strname, \" \", \"_\")\n\n    strname = Replace(strname, \".\", \"_\")\n\n    GetFolderName = strname\n\nEnd Function\n\n\n\n'建立資料夾(如果已經存在會先刪除)\n\nFunction MakeDirOil(ByVal folderName As String)\n\n    Dim fso As Scripting.FileSystemObject\n\n    Set fso = New Scripting.FileSystemObject\n\n    If fso.FolderExists(folderName) = True Then\n\n        fso.DeleteFolder folderName, force:=True\n\n        fso.CreateFolder folderName\n\n    Else\n\n        fso.CreateFolder folderName\n\n    End If\n\nEnd Function\n\n\n\n'開啟資料夾,另一種比較簡單的方式\n\nFunction OpenFolder2(strPath As String, Optional bnRoot As Boolean = False)\n\n    Dim strRoot As String\n\n\n\n    If bnRoot = True Then\n\n        strRoot = \"/root,\"\n\n    Else\n\n        strRoot = \"\"\n\n    End If\n\n\n\n    Call Shell(\"explorer.exe\" & \" \" & strRoot & strPath, vbNormalFocus)\n\nEnd Function\n\n", "content_b64": ""}, {"name": "DraftMeetingFromSelectedMail.bas", "path": "模組/Outlook/DraftMeetingFromSelectedMail.bas", "content": "Attribute VB_Name = \"DraftMeetingFromSelectedMail\"\nOption Explicit\n'*************************************************************************************\n' 專案名稱: 由所選郵件建立會議邀請草稿範例\n' 功能說明: 讀取所選郵件的寄件者與主旨，建立一封會議邀請草稿\n'*************************************************************************************\n\nPrivate Const OL_MAIL_ITEM As Long = 43\nPrivate Const OL_APPOINTMENT_ITEM As Long = 1\nPrivate Const OL_MEETING As Long = 1\nPrivate Const OL_REQUIRED As Long = 1\n\nPublic Sub DraftMeetingFromSelectedMailExample()\n    On Error GoTo ErrorHandler\n\n    Dim outlookApp As Object\n    Dim selectionItems As Object\n    Dim sourceMail As Object\n    Dim meetingItem As Object\n    Dim recipientItem As Object\n    Dim startText As String\n    Dim startTime As Date\n\n    startText = InputBox(\"請輸入會議開始時間，例如 2026/05/09 15:00\", \"建立會議草稿\", Format$(Now + 1, \"yyyy/mm/dd 10:00\"))\n    If Not IsDate(startText) Then\n        MsgBox \"會議開始時間格式不正確。\", vbExclamation, \"建立會議草稿\"\n        Exit Sub\n    End If\n    startTime = CDate(startText)\n\n    Set outlookApp = GetDraftMeetingFromMailOutlookApp()\n    Set selectionItems = outlookApp.ActiveExplorer.Selection\n\n    If selectionItems.Count = 0 Then\n        MsgBox \"請先選取一封郵件。\", vbInformation, \"建立會議草稿\"\n        GoTo CleanExit\n    End If\n\n    Set sourceMail = selectionItems.Item(1)\n    If sourceMail.Class <> OL_MAIL_ITEM Then\n        MsgBox \"選取項目不是郵件。\", vbInformation, \"建立會議草稿\"\n        GoTo CleanExit\n    End If\n\n    Set meetingItem = outlookApp.CreateItem(OL_APPOINTMENT_ITEM)\n    With meetingItem\n        .MeetingStatus = OL_MEETING\n        .Subject = \"討論：\" & sourceMail.Subject\n        .Start = startTime\n        .Duration = 30\n        .Location = \"請填寫會議地點\"\n        .Body = \"此會議草稿依所選郵件建立。\" & vbCrLf & vbCrLf & sourceMail.Subject\n        Set recipientItem = .Recipients.Add(GetDraftMeetingFromMailAddress(sourceMail))\n        recipientItem.Type = OL_REQUIRED\n        .Display\n    End With\n\nCleanExit:\n    Set recipientItem = Nothing\n    Set meetingItem = Nothing\n    Set sourceMail = Nothing\n    Set selectionItems = Nothing\n    Set outlookApp = Nothing\n    Exit Sub\n\nErrorHandler:\n    MsgBox \"建立會議草稿時發生錯誤：\" & Err.Description, vbExclamation, \"建立會議草稿\"\n    Resume CleanExit\nEnd Sub\n\nPrivate Function GetDraftMeetingFromMailOutlookApp() As Object\n    On Error Resume Next\n\n    Set GetDraftMeetingFromMailOutlookApp = GetObject(, \"Outlook.Application\")\n    If GetDraftMeetingFromMailOutlookApp Is Nothing Then\n        Set GetDraftMeetingFromMailOutlookApp = CreateObject(\"Outlook.Application\")\n    End If\nEnd Function\n\nPrivate Function GetDraftMeetingFromMailAddress(ByVal mailItem As Object) As String\n    On Error Resume Next\n\n    GetDraftMeetingFromMailAddress = mailItem.SenderEmailAddress\n    If Len(GetDraftMeetingFromMailAddress) = 0 Then\n        GetDraftMeetingFromMailAddress = mailItem.SenderName\n    End If\nEnd Function", "content_b64": ""}, {"name": "ExportSelectedMailsToCsv.bas", "path": "模組/Outlook/ExportSelectedMailsToCsv.bas", "content": "Attribute VB_Name = \"ExportSelectedMailsToCsv\"\nOption Explicit\n'*************************************************************************************\n' 專案名稱: 匯出所選郵件清單範例\n' 功能說明: 將 Outlook 目前選取郵件的寄件者、主旨、時間匯出為 CSV\n'*************************************************************************************\n\nPrivate Const OL_MAIL_ITEM As Long = 43\n\nPublic Sub ExportSelectedMailsToCsvExample()\n    On Error GoTo ErrorHandler\n\n    Dim outputFile As String\n    Dim outlookApp As Object\n    Dim selectionItems As Object\n    Dim mailItem As Object\n    Dim fileNumber As Integer\n    Dim exportedCount As Long\n\n    outputFile = InputBox(\"請輸入 CSV 輸出路徑\", \"匯出郵件清單\", \"C:\\Temp\\SelectedMails.csv\")\n    If Len(Trim$(outputFile)) = 0 Then\n        Exit Sub\n    End If\n\n    EnsureExportSelectedMailsFolder GetExportSelectedMailsFolder(outputFile)\n\n    Set outlookApp = GetExportSelectedMailsOutlookApp()\n    Set selectionItems = outlookApp.ActiveExplorer.Selection\n\n    fileNumber = FreeFile\n    Open outputFile For Output As #fileNumber\n    Print #fileNumber, \"寄件者,寄件信箱,主旨,收件時間,附件數\"\n\n    For Each mailItem In selectionItems\n        If mailItem.Class = OL_MAIL_ITEM Then\n            Print #fileNumber, CsvExportSelectedMailsText(mailItem.SenderName) & \",\" & _\n                CsvExportSelectedMailsText(GetExportSelectedMailsSenderAddress(mailItem)) & \",\" & _\n                CsvExportSelectedMailsText(mailItem.Subject) & \",\" & _\n                CsvExportSelectedMailsText(Format$(mailItem.ReceivedTime, \"yyyy/mm/dd hh:nn:ss\")) & \",\" & _\n                CStr(mailItem.Attachments.Count)\n            exportedCount = exportedCount + 1\n        End If\n    Next mailItem\n\n    Close #fileNumber\n    MsgBox \"匯出完成，共匯出 \" & CStr(exportedCount) & \" 封郵件。\", vbInformation, \"匯出郵件清單\"\n\nCleanExit:\n    On Error Resume Next\n    If fileNumber <> 0 Then\n        Close #fileNumber\n    End If\n    Set mailItem = Nothing\n    Set selectionItems = Nothing\n    Set outlookApp = Nothing\n    Exit Sub\n\nErrorHandler:\n    MsgBox \"匯出郵件清單時發生錯誤：\" & Err.Description, vbExclamation, \"匯出郵件清單\"\n    Resume CleanExit\nEnd Sub\n\nPrivate Function GetExportSelectedMailsOutlookApp() As Object\n    On Error Resume Next\n\n    Set GetExportSelectedMailsOutlookApp = GetObject(, \"Outlook.Application\")\n    If GetExportSelectedMailsOutlookApp Is Nothing Then\n        Set GetExportSelectedMailsOutlookApp = CreateObject(\"Outlook.Application\")\n    End If\nEnd Function\n\nPrivate Function GetExportSelectedMailsSenderAddress(ByVal mailItem As Object) As String\n    On Error Resume Next\n\n    GetExportSelectedMailsSenderAddress = mailItem.SenderEmailAddress\nEnd Function\n\nPrivate Function CsvExportSelectedMailsText(ByVal value As String) As String\n    CsvExportSelectedMailsText = \"\"\"\" & Replace$(value, \"\"\"\", \"\"\"\"\"\") & \"\"\"\"\nEnd Function\n\nPrivate Function GetExportSelectedMailsFolder(ByVal filePath As String) As String\n    Dim fso As Object\n\n    Set fso = CreateObject(\"Scripting.FileSystemObject\")\n    GetExportSelectedMailsFolder = fso.GetParentFolderName(filePath)\n    Set fso = Nothing\nEnd Function\n\nPrivate Sub EnsureExportSelectedMailsFolder(ByVal folderPath As String)\n    Dim fso As Object\n\n    If Len(folderPath) = 0 Then\n        Exit Sub\n    End If\n\n    Set fso = CreateObject(\"Scripting.FileSystemObject\")\n    If Not fso.FolderExists(folderPath) Then\n        fso.CreateFolder folderPath\n    End If\n    Set fso = Nothing\nEnd Sub", "content_b64": ""}, {"name": "FlagSelectedMailsForFollowUp.bas", "path": "模組/Outlook/FlagSelectedMailsForFollowUp.bas", "content": "Attribute VB_Name = \"FlagSelectedMailsForFollowUp\"\nOption Explicit\n'*************************************************************************************\n' 專案名稱: 標記所選郵件後續追蹤範例\n' 功能說明: 對 Outlook 目前選取郵件加上追蹤旗標與提醒時間\n'*************************************************************************************\n\nPrivate Const OL_MAIL_ITEM As Long = 43\nPrivate Const OL_MARK_TODAY As Long = 0\n\nPublic Sub FlagSelectedMailsForFollowUpExample()\n    On Error GoTo ErrorHandler\n\n    Dim outlookApp As Object\n    Dim selectionItems As Object\n    Dim mailItem As Object\n    Dim reminderText As String\n    Dim reminderTime As Date\n    Dim flaggedCount As Long\n\n    reminderText = InputBox(\"請輸入提醒時間，例如 2026/05/09 17:00\", \"郵件追蹤\", Format$(Now + 1, \"yyyy/mm/dd 09:00\"))\n    If Not IsDate(reminderText) Then\n        MsgBox \"提醒時間格式不正確。\", vbExclamation, \"郵件追蹤\"\n        Exit Sub\n    End If\n\n    reminderTime = CDate(reminderText)\n\n    Set outlookApp = GetFlagSelectedMailsOutlookApp()\n    Set selectionItems = outlookApp.ActiveExplorer.Selection\n\n    For Each mailItem In selectionItems\n        If mailItem.Class = OL_MAIL_ITEM Then\n            mailItem.MarkAsTask OL_MARK_TODAY\n            mailItem.TaskSubject = \"追蹤：\" & mailItem.Subject\n            mailItem.ReminderSet = True\n            mailItem.ReminderTime = reminderTime\n            mailItem.Save\n            flaggedCount = flaggedCount + 1\n        End If\n    Next mailItem\n\n    MsgBox \"已標記 \" & CStr(flaggedCount) & \" 封郵件。\", vbInformation, \"郵件追蹤\"\n\nCleanExit:\n    Set mailItem = Nothing\n    Set selectionItems = Nothing\n    Set outlookApp = Nothing\n    Exit Sub\n\nErrorHandler:\n    MsgBox \"標記郵件時發生錯誤：\" & Err.Description, vbExclamation, \"郵件追蹤\"\n    Resume CleanExit\nEnd Sub\n\nPrivate Function GetFlagSelectedMailsOutlookApp() As Object\n    On Error Resume Next\n\n    Set GetFlagSelectedMailsOutlookApp = GetObject(, \"Outlook.Application\")\n    If GetFlagSelectedMailsOutlookApp Is Nothing Then\n        Set GetFlagSelectedMailsOutlookApp = CreateObject(\"Outlook.Application\")\n    End If\nEnd Function", "content_b64": ""}, {"name": "ListUnreadMailsToImmediate.bas", "path": "模組/Outlook/ListUnreadMailsToImmediate.bas", "content": "Attribute VB_Name = \"ListUnreadMailsToImmediate\"\nOption Explicit\n'*************************************************************************************\n' 專案名稱: 列出未讀郵件範例\n' 功能說明: 將目前 Outlook 資料夾中的未讀郵件資訊輸出到立即視窗\n'*************************************************************************************\n\nPrivate Const OL_MAIL_ITEM As Long = 43\n\nPublic Sub ListUnreadMailsToImmediateExample()\n    On Error GoTo ErrorHandler\n\n    Dim outlookApp As Object\n    Dim currentFolder As Object\n    Dim mailItem As Object\n    Dim index As Long\n    Dim unreadCount As Long\n\n    Set outlookApp = GetListUnreadMailsOutlookApp()\n    Set currentFolder = outlookApp.ActiveExplorer.CurrentFolder\n\n    Debug.Print String$(60, \"-\")\n    Debug.Print \"未讀郵件清單：\" & currentFolder.Name\n    Debug.Print String$(60, \"-\")\n\n    For index = 1 To currentFolder.Items.Count\n        Set mailItem = currentFolder.Items.Item(index)\n        If mailItem.Class = OL_MAIL_ITEM Then\n            If mailItem.UnRead = True Then\n                Debug.Print Format$(mailItem.ReceivedTime, \"yyyy/mm/dd hh:nn\") & \" | \" & mailItem.SenderName & \" | \" & mailItem.Subject\n                unreadCount = unreadCount + 1\n            End If\n        End If\n    Next index\n\n    MsgBox \"已列出 \" & CStr(unreadCount) & \" 封未讀郵件，請查看 VBA 立即視窗。\", vbInformation, \"未讀郵件\"\n\nCleanExit:\n    Set mailItem = Nothing\n    Set currentFolder = Nothing\n    Set outlookApp = Nothing\n    Exit Sub\n\nErrorHandler:\n    MsgBox \"列出未讀郵件時發生錯誤：\" & Err.Description, vbExclamation, \"未讀郵件\"\n    Resume CleanExit\nEnd Sub\n\nPrivate Function GetListUnreadMailsOutlookApp() As Object\n    On Error Resume Next\n\n    Set GetListUnreadMailsOutlookApp = GetObject(, \"Outlook.Application\")\n    If GetListUnreadMailsOutlookApp Is Nothing Then\n        Set GetListUnreadMailsOutlookApp = CreateObject(\"Outlook.Application\")\n    End If\nEnd Function", "content_b64": ""}, {"name": "MoveMailsBySubjectKeyword.bas", "path": "模組/Outlook/MoveMailsBySubjectKeyword.bas", "content": "Attribute VB_Name = \"MoveMailsBySubjectKeyword\"\nOption Explicit\n'*************************************************************************************\n' 專案名稱: 依主旨關鍵字移動郵件範例\n' 功能說明: 將目前資料夾中主旨含指定關鍵字的郵件移到子資料夾\n'*************************************************************************************\n\nPrivate Const OL_MAIL_ITEM As Long = 43\n\nPublic Sub MoveMailsBySubjectKeywordExample()\n    On Error GoTo ErrorHandler\n\n    Dim keyword As String\n    Dim targetFolderName As String\n    Dim outlookApp As Object\n    Dim sourceFolder As Object\n    Dim targetFolder As Object\n    Dim mailItem As Object\n    Dim index As Long\n    Dim movedCount As Long\n\n    keyword = InputBox(\"請輸入主旨關鍵字\", \"移動郵件\")\n    If Len(Trim$(keyword)) = 0 Then\n        Exit Sub\n    End If\n\n    targetFolderName = InputBox(\"請輸入目的子資料夾名稱\", \"移動郵件\", \"已分類\")\n    If Len(Trim$(targetFolderName)) = 0 Then\n        Exit Sub\n    End If\n\n    Set outlookApp = GetMoveMailsBySubjectOutlookApp()\n    Set sourceFolder = outlookApp.ActiveExplorer.CurrentFolder\n    Set targetFolder = GetMoveMailsBySubjectSubFolder(sourceFolder, targetFolderName)\n\n    For index = sourceFolder.Items.Count To 1 Step -1\n        Set mailItem = sourceFolder.Items.Item(index)\n        If mailItem.Class = OL_MAIL_ITEM Then\n            If InStr(1, mailItem.Subject, keyword, vbTextCompare) > 0 Then\n                mailItem.Move targetFolder\n                movedCount = movedCount + 1\n            End If\n        End If\n    Next index\n\n    MsgBox \"移動完成，共移動 \" & CStr(movedCount) & \" 封郵件。\", vbInformation, \"移動郵件\"\n\nCleanExit:\n    Set mailItem = Nothing\n    Set targetFolder = Nothing\n    Set sourceFolder = Nothing\n    Set outlookApp = Nothing\n    Exit Sub\n\nErrorHandler:\n    MsgBox \"移動郵件時發生錯誤：\" & Err.Description, vbExclamation, \"移動郵件\"\n    Resume CleanExit\nEnd Sub\n\nPrivate Function GetMoveMailsBySubjectOutlookApp() As Object\n    On Error Resume Next\n\n    Set GetMoveMailsBySubjectOutlookApp = GetObject(, \"Outlook.Application\")\n    If GetMoveMailsBySubjectOutlookApp Is Nothing Then\n        Set GetMoveMailsBySubjectOutlookApp = CreateObject(\"Outlook.Application\")\n    End If\nEnd Function\n\nPrivate Function GetMoveMailsBySubjectSubFolder(ByVal parentFolder As Object, ByVal folderName As String) As Object\n    On Error Resume Next\n\n    Set GetMoveMailsBySubjectSubFolder = parentFolder.Folders.Item(folderName)\n    On Error GoTo 0\n\n    If GetMoveMailsBySubjectSubFolder Is Nothing Then\n        Set GetMoveMailsBySubjectSubFolder = parentFolder.Folders.Add(folderName)\n    End If\nEnd Function", "content_b64": ""}, {"name": "PrintAttachment.bas", "path": "模組/Outlook/PrintAttachment.bas", "content": "Attribute VB_Name = \"PrintAttachment\"\nOption Explicit\n'*************************************************************************************\n'專案名稱: 全委帳務處理\n'功能描述:\n' email 收件自動下載列印\n\n'版權所有: Dunk\n'程式撰寫: Dunk\n'撰寫日期：2017/6/8\n'\n'改版日期:\n'改版備註: 2017/6/13 增加關閉Excel,RAR及adobe檔案功能(因為會與重建資料夾功能衝突，先關閉後再執行)\n'                 2017/6/14 調整關閉Excel,RAR及adobe檔案功能執行順序及執行不顯示視窗\n'                 2017/6/26 調整排除建立資料夾時的特殊字元\n'                 2017/12/27 增加全委代理設定\n'                 2018/1/19 增加保德信檔案處理\n'                 2018/2/7 增加儲存基金對帳單檔案及安聯檔案\n'                 2018/2/13 調整代理部份\n'                 2018/3/1 調整過濾郵件列印部份\n'                 2018/8/28 增加判斷小寫檔名\n'*************************************************************************************\n\n\n\n#If VBA7 Then\n    Declare PtrSafe  Sub Sleep Lib \"kernel32\" (ByVal dwMilliseconds As Long)    'For 64 Bit Systems\n    Declare PtrSafe  Function ShellExecute Lib \"shell32.dll\" _\n            Alias \"ShellExecuteA\" (ByVal hwnd As Long, ByVal lpOperation As String, _\n                                   ByVal lpFile As String, ByVal lpParameters As String, _\n                                   ByVal lpDirectory As String, ByVal nShowCmd As Long) As Long\n#Else\n    Declare Sub Sleep Lib \"kernel32\" (ByVal dwMilliseconds As Long)    'For 32 Bit Systems\n    Declare Function ShellExecute Lib \"shell32.dll\" _\n                                  Alias \"ShellExecuteA\" (ByVal hwnd As Long, ByVal lpOperation As String, _\n                                                         ByVal lpFile As String, ByVal lpParameters As String, _\n                                                         ByVal lpDirectory As String, ByVal nShowCmd As Long) As Long\n#End If\n\nSub A_Test()\n    Sleep (3000)\n    MsgBox (\"!!\")\nEnd Sub\n\n'將收件匣未讀取信件的所有附件檔另存\nSub A_Step1_SaveAttachments()\n    Dim myNameSpace As Outlook.NameSpace\n    Dim myFolder As Outlook.MAPIFolder\n    Dim myAttachments As Outlook.Attachments\n    Dim myItems As Outlook.Items\n    Dim TargetFolder As String, SFName As String, NSFName As String\n    Dim resultFolder As String\n    Dim i As Integer\n    Dim fs As Variant\n    Dim mail, att, ReturnVal As Variant\n\n    '重建資料夾，執行前先清除有可能造成鎖定的檔案\n    TargetFolder = \"D:\\來信的附件檔\"\n    A_Step2_CloseImgFiles\n    Sleep (2000)\n    MakeDir (TargetFolder)\n\n    Set fs = CreateObject(\"Scripting.FileSystemObject\")\n    Set myNameSpace = Application.GetNamespace(\"MAPI\")\n    Set myFolder = myNameSpace.GetDefaultFolder(olFolderInbox)\n    'myFolder 代表 \"收件匣 Inbox\"\n    Set myItems = myFolder.Items\n    'myItems 代表 \"收件匣\" 中所有信件 (的集合)\n    For Each mail In myItems   '檢查每一封信\n        If mail.UnRead = True Then\n            resultFolder = TargetFolder & \"\\\" & GetFolderName(mail.Subject)\n            MakeDir (resultFolder)\n            Set myAttachments = mail.Attachments\n            'myAttachments 代表這封信件裡所有附件檔 (的集合)\n            For Each att In myAttachments\n                SFName = resultFolder & \"\\\" & att.fileName\n                If fs.FileExists(SFName) Then    '若檔案已存在, 就加上 (數字)\n                    i = 0\n                    Do\n                        NSFName = TargetFolder & \"\\\" & fs.GetBaseName(SFName) _\n                                  & \"(\" & i & \").\" & fs.GetExtensionName(SFName)\n                        i = i + 1\n                    Loop While fs.FileExists(NSFName)\n                    If checkname(NSFName) = True Then\n                        att.SaveAsFile NSFName    '用加了數字的檔名儲存\n                    End If\n                Else\n                    If checkname(SFName) = True Then\n                        att.SaveAsFile SFName  ''若檔案不存在, 就用原來的檔名儲存\n\n                        If ValidPrintAbleFile(SFName, mail.SenderEmailAddress) = True Then\n                            ReturnVal = ShellExecute(0&, \"print\", SFName, 0&, 0&, 0&)\n                        Else\n                            '處理加密的zip檔案\n                            DealWithZipCryFiles Subject:=mail.Subject, SFName:=SFName, _\n                                                sender:=mail.SenderEmailAddress\n                        End If\n                    End If\n                End If\n            Next att\n            mail.UnRead = False\n        End If\n    Next mail\n    'att.PrintOut\n    OpenFolder2 (TargetFolder)\nEnd Sub\n'處理加密的zip檔案\nFunction DealWithZipCryFiles(ByVal Subject As String, ByVal SFName As String, ByVal sender As String)\n'處理保德信\n    If (InStr(1, Subject, \"保德信\") > 0 Or InStr(1, sender, \"pru.com.tw\") > 0) _\n       And (InStr(1, SFName, \".zip\") > 0 Or InStr(1, SFName, \".rar\") > 0) Then\n        If InStr(1, Subject, \"103-1\") > 0 Then\n            UnzipFile.DealWithEncryFilePGIM SFName, \"Aa1234\", sender\n        Else\n            UnzipFile.DealWithEncryFilePGIM SFName, \"Aa1234\", sender\n        End If\n    End If\n    '處理安聯\n    If (InStr(1, Subject, \"安聯\") > 0 Or InStr(1, sender, \"allianzgi.com\") > 0) _\n       And (InStr(1, SFName, \".zip\") > 0 Or InStr(1, SFName, \".rar\") > 0) Then\n        If InStr(1, Subject, \"報表\") > 0 Then\n            '檔案\n            UnzipFile.DealWithEncryFilePGIM SFName, \"A0036\", sender\n        Else\n            '檔案\n            UnzipFile.DealWithEncryFilePGIM SFName, \"Allianz18\", sender\n        End If\n        If InStr(1, sender, \"Kim.Wang@allianzgi.com\") > 0 Then\n            '檔案\n            UnzipFile.DealWithEncryFilePGIM SFName, \"kimw9516\", sender\n        End If\n    End If\nEnd Function\n\nSub A_Step2_AgentBenZhi()\n    A_Step1_SavePlaceAttachments (\"01.秉志\")\nEnd Sub\nSub A_Step2_AgentLanJin()\n    A_Step1_SavePlaceAttachments (\"02.蘭錦\")\nEnd Sub\nSub A_Step2_AgentZhenFu()\n    A_Step1_SavePlaceAttachments (\"03.振富\")\nEnd Sub\n\n\n'將全委代理收件匣未讀取信件的所有附件檔另存\nFunction A_Step1_SavePlaceAttachments(ByVal userName As String)\n    Dim myNameSpace As Outlook.NameSpace\n    Dim myFolder As Outlook.MAPIFolder\n    Dim myAttachments As Outlook.Attachments\n    Dim myItems As Outlook.Items\n    Dim TargetFolder As String, SFName As String, NSFName As String\n    Dim resultFolder As String\n    Dim i As Integer\n    Dim fs As Variant\n    Dim mail, att, ReturnVal As Variant\n\n    '重建資料夾，執行前先清除有可能造成鎖定的檔案\n    TargetFolder = \"D:\\來信的附件檔\"\n    A_Step2_CloseImgFiles\n    Sleep (2000)\n    MakeDir (TargetFolder)\n\n    Set fs = CreateObject(\"Scripting.FileSystemObject\")\n    Set myNameSpace = Application.GetNamespace(\"MAPI\")\n    Set myFolder = myNameSpace.GetDefaultFolder(olFolderInbox).Folders(\"代理\").Folders(userName)\n    'myFolder 代表 \"收件匣 Inbox\"\n    Set myItems = myFolder.Items\n    'myItems 代表 \"收件匣\" 中所有信件 (的集合)\n    For Each mail In myItems   '檢查每一封信\n        If mail.UnRead = True Then\n            resultFolder = TargetFolder & \"\\\" & GetFolderName(mail.Subject)\n            MakeDir (resultFolder)\n            Set myAttachments = mail.Attachments\n            'myAttachments 代表這封信件裡所有附件檔 (的集合)\n            For Each att In myAttachments\n                SFName = resultFolder & \"\\\" & att.fileName\n                If fs.FileExists(SFName) Then    '若檔案已存在, 就加上 (數字)\n                    i = 0\n                    Do\n                        NSFName = TargetFolder & \"\\\" & fs.GetBaseName(SFName) _\n                                  & \"(\" & i & \").\" & fs.GetExtensionName(SFName)\n                        i = i + 1\n                    Loop While fs.FileExists(NSFName)\n                    If checkname(NSFName) = True Then\n                        att.SaveAsFile NSFName    '用加了數字的檔名儲存\n                    End If\n                Else\n                    If checkname(SFName) = True Then\n                        att.SaveAsFile SFName  ''若檔案不存在, 就用原來的檔名儲存\n                        If ValidPrintAbleFile(SFName, mail.SenderEmailAddress) = True Then\n                            ReturnVal = ShellExecute(0&, \"print\", SFName, 0&, 0&, 0&)\n                        Else\n                            '處理加密的zip檔案\n                            DealWithZipCryFiles Subject:=mail.Subject, SFName:=SFName, _\n                                                sender:=mail.SenderEmailAddress\n                        End If\n                    End If\n                End If\n            Next att\n            mail.UnRead = False\n        End If\n    Next mail\n    'att.PrintOut\n    OpenFolder2 (TargetFolder)\nEnd Function\n\n'將基金收件匣未讀取信件的所有附件檔另存\nSub A_Step1_SaveFundAttachments()\n    Dim myNameSpace As Outlook.NameSpace\n    Dim myFolder As Outlook.MAPIFolder\n    Dim myAttachments As Outlook.Attachments\n    Dim myItems As Outlook.Items\n    Dim TargetFolder As String, SFName As String, NSFName As String\n    Dim resultFolder As String\n    Dim i As Integer\n    Dim fs As Variant\n    Dim mail, att, ReturnVal As Variant\n\n    '重建資料夾，執行前先清除有可能造成鎖定的檔案\n    TargetFolder = \"D:\\來信的附件檔\"\n    A_Step2_CloseImgFiles\n    Sleep (2000)\n    MakeDir (TargetFolder)\n\n    Set fs = CreateObject(\"Scripting.FileSystemObject\")\n    Set myNameSpace = Application.GetNamespace(\"MAPI\")\n    Set myFolder = myNameSpace.Folders(\"個人資料夾\").Folders(\"01.工作\").Folders(\"01.基金\")\n    'myFolder 代表 \"收件匣 Inbox\"\n    Set myItems = myFolder.Items\n    'myItems 代表 \"收件匣\" 中所有信件 (的集合)\n    For Each mail In myItems   '檢查每一封信\n        If mail.UnRead = True Then\n            resultFolder = TargetFolder & \"\\\" & GetFolderName(mail.Subject)\n            MakeDir (resultFolder)\n            Set myAttachments = mail.Attachments\n            'myAttachments 代表這封信件裡所有附件檔 (的集合)\n            For Each att In myAttachments\n                SFName = resultFolder & \"\\\" & att.fileName\n                If fs.FileExists(SFName) Then    '若檔案已存在, 就加上 (數字)\n                    i = 0\n                    Do\n                        NSFName = TargetFolder & \"\\\" & fs.GetBaseName(SFName) _\n                                  & \"(\" & i & \").\" & fs.GetExtensionName(SFName)\n                        i = i + 1\n                    Loop While fs.FileExists(NSFName)\n                    If checkname(NSFName) = True Then\n                        att.SaveAsFile NSFName    '用加了數字的檔名儲存\n                    End If\n                Else\n                    If checkname(SFName) = True Then\n                        att.SaveAsFile SFName  ''若檔案不存在, 就用原來的檔名儲存\n                        If ValidPrintAbleFileFund(SFName) = True Then\n                            '儲存基金對帳單檔案\n                            SaveFundFiles.SaveFundFile (SFName)\n                            '取消列印\n                            'ReturnVal = ShellExecute(0&, \"print\", SFName, 0&, 0&, 0&)\n                        End If\n                    End If\n                End If\n            Next att\n            mail.UnRead = False\n        End If\n    Next mail\n    'att.PrintOut\n    OpenFolder2 (TargetFolder)\nEnd Sub\n\n'將基金代理收件匣未讀取信件的所有附件檔另存\nSub A_Step1_SaveFundRepMgrAttachments()\n    Dim myNameSpace As Outlook.NameSpace\n    Dim myFolder As Outlook.MAPIFolder\n    Dim myAttachments As Outlook.Attachments\n    Dim myItems As Outlook.Items\n    Dim TargetFolder As String, SFName As String, NSFName As String\n    Dim resultFolder As String\n    Dim i As Integer\n    Dim fs As Variant\n    Dim mail, att, ReturnVal As Variant\n\n    '重建資料夾，執行前先清除有可能造成鎖定的檔案\n    TargetFolder = \"D:\\來信的附件檔\"\n    A_Step2_CloseImgFiles\n    Sleep (2000)\n    MakeDir (TargetFolder)\n\n    Set fs = CreateObject(\"Scripting.FileSystemObject\")\n    Set myNameSpace = Application.GetNamespace(\"MAPI\")\n    Set myFolder = myNameSpace.Folders(\"個人資料夾\").Folders(\"01.工作\").Folders(\"01.基金代理\")\n    'myFolder 代表 \"收件匣 Inbox\"\n    Set myItems = myFolder.Items\n    'myItems 代表 \"收件匣\" 中所有信件 (的集合)\n    For Each mail In myItems   '檢查每一封信\n        If mail.UnRead = True Then\n            resultFolder = TargetFolder & \"\\\" & GetFolderName(mail.Subject)\n            MakeDir (resultFolder)\n            Set myAttachments = mail.Attachments\n            'myAttachments 代表這封信件裡所有附件檔 (的集合)\n            For Each att In myAttachments\n                SFName = resultFolder & \"\\\" & att.fileName\n                If fs.FileExists(SFName) Then    '若檔案已存在, 就加上 (數字)\n                    i = 0\n                    Do\n                        NSFName = TargetFolder & \"\\\" & fs.GetBaseName(SFName) _\n                                  & \"(\" & i & \").\" & fs.GetExtensionName(SFName)\n                        i = i + 1\n                    Loop While fs.FileExists(NSFName)\n                    If checkname(NSFName) = True Then\n                        att.SaveAsFile NSFName    '用加了數字的檔名儲存\n                    End If\n                Else\n                    If checkname(SFName) = True Then\n                        att.SaveAsFile SFName  ''若檔案不存在, 就用原來的檔名儲存\n                        If ValidPrintAbleFileFund(SFName) = True Then\n                            ReturnVal = ShellExecute(0&, \"print\", SFName, 0&, 0&, 0&)\n                        End If\n                    End If\n                End If\n            Next att\n            mail.UnRead = False\n        End If\n    Next mail\n    'att.PrintOut\n    OpenFolder2 (TargetFolder)\nEnd Sub\n\n'關閉多開的檔案\nSub A_Step2_CloseImgFiles()\n'關閉多開的Excel檔案\n    CallTaskKill (\"EXCEL.EXE\")\n    '關閉多開的Rar檔案\n    CallTaskKill (\"WinRAR.exe\")\n    '關閉多開的Adobe檔案\n    CallTaskKill (\"Acrobat.exe\")\nEnd Sub\n\nFunction checkname(ByVal fileName As String)\n    checkname = True\nEnd Function\n\n'排除建立資料夾時的特殊字元\nFunction GetFolderName(ByVal fileName As String)\n    Dim strname As String\n    strname = fileName\n    strname = Replace(strname, \"*\", \"_\")\n    strname = Replace(strname, \"\\\", \"_\")\n    strname = Replace(strname, \"/\", \"_\")\n    strname = Replace(strname, \"$\", \"_\")\n    strname = Replace(strname, \"%\", \"_\")\n    strname = Replace(strname, \"!\", \"_\")\n    strname = Replace(strname, \"~\", \"_\")\n    strname = Replace(strname, \"(\", \"_\")\n    strname = Replace(strname, \")\", \"_\")\n    strname = Replace(strname, \"+\", \"_\")\n    strname = Replace(strname, \":\", \"_\")\n    strname = Replace(strname, \"<\", \"_\")\n    strname = Replace(strname, \">\", \"_\")\n    strname = Replace(strname, \"|\", \"_\")\n    strname = Replace(strname, \"?\", \"_\")\n    strname = Replace(strname, \"\"\"\", \"_\")\n    strname = Replace(strname, \" \", \"_\")\n    strname = Replace(strname, \".\", \"_\")\n    GetFolderName = strname\nEnd Function\n\n'建立資料夾(如果已經存在會先刪除)\nFunction MakeDir(ByVal folderName As String)\n    Dim fso As Scripting.FileSystemObject\n    Set fso = New Scripting.FileSystemObject\n    If fso.FolderExists(folderName) = True Then\n        fso.DeleteFolder folderName, force:=True\n        fso.CreateFolder folderName\n    Else\n        fso.CreateFolder folderName\n    End If\nEnd Function\n\n'區分可以列印的檔案名稱與種類\nFunction ValidPrintAbleFile(ByVal fileName As String, ByVal sender As String) '\n' for 保德信\n    If InStr(1, sender, \"pru.com.tw\") > 0 Then\n        If InStr(1, fileName, \"短期投資未到期明細表\") > 0 Then\n            ValidPrintAbleFile = False\n            Exit Function\n        End If\n        If InStr(1, fileName, \"資產投資組合表\") > 0 Then\n            ValidPrintAbleFile = False\n            Exit Function\n        End If\n    End If\n    'for 安聯\n    If InStr(1, sender, \"allianzgi.com\") > 0 Then\n        If InStr(1, fileName, \"短期票券應收利息明細表\") > 0 Then\n            ValidPrintAbleFile = False\n            Exit Function\n        End If\n    End If\n    'for 台新\n    If InStr(1, sender, \"tsit.com.tw\") > 0 Then\n        If InStr(1, fileName, \"附買回債券票券應計利息明細表\") > 0 Then\n            ValidPrintAbleFile = False\n            Exit Function\n        End If\n    End If\n    Dim fileNameLow As String\n    '判斷小寫檔名\n    fileNameLow = LCase(fileName)\n    If InStr(1, fileNameLow, \"doc\") > 0 Or InStr(1, fileNameLow, \"docx\") > 0 Or InStr(1, fileNameLow, \"rtf\") > 0 _\n       Or InStr(1, fileNameLow, \"pdf\") > 0 Then\n        ValidPrintAbleFile = True\n    Else\n        ValidPrintAbleFile = False\n    End If\n\nEnd Function\n\n'區分可以列印的檔案名稱與種類(基金檔案)\nFunction ValidPrintAbleFileFund(ByVal fileName As String) '\n' for 元大期貨\n    If InStr(1, fileName, \"2449158C\") > 0 Or _\n       InStr(1, fileName, \"2518539C\") > 0 Or _\n       InStr(1, fileName, \"2533187C\") > 0 Or _\n       InStr(1, fileName, \"9756162C\") > 0 Then\n        ValidPrintAbleFileFund = False\n        Exit Function\n    End If\n\n    Dim fileNameLow As String\n    '判斷小寫檔名\n    fileNameLow = LCase(fileName)\n    If InStr(1, fileNameLow, \"doc\") > 0 Or InStr(1, fileNameLow, \"docx\") > 0 Or InStr(1, fileNameLow, \"rtf\") > 0 _\n       Or InStr(1, fileNameLow, \"pdf\") > 0 Then\n        ValidPrintAbleFileFund = True\n    Else\n        ValidPrintAbleFileFund = False\n    End If\n\nEnd Function\n\n'開啟資料夾,另一種比較簡單的方式\nFunction OpenFolder2(strPath As String, Optional bnRoot As Boolean = False)\n    Dim strRoot As String\n\n    If bnRoot = True Then\n        strRoot = \"/root,\"\n    Else\n        strRoot = \"\"\n    End If\n\n    Call Shell(\"explorer.exe\" & \" \" & strRoot & strPath, vbNormalFocus)\nEnd Function\n\n\nFunction CallTaskKill(ByVal imgName As String)\n    Call Shell(\"cmd.exe /C \"\"taskkill /F /IM \" & imgName & \"\"\"\", vbHide)\nEnd Function\n\n", "content_b64": ""}, {"name": "RemoveMail.bas", "path": "模組/Outlook/RemoveMail.bas", "content": "Attribute VB_Name = \"RemoveMail\"\nOption Explicit\n'*************************************************************************************\n'專案名稱: 期信基金帳務處理\n'功能描述:\n' 將基金收件匣未讀取信件的轉寄email刪除\n\n'版權所有: Dunk\n'程式撰寫: Dunk\n'撰寫日期：2017/11/8\n'\n'改版日期:\n'改版備註:\n'\n'\n'*************************************************************************************\n\n'將基金收件匣未讀取信件的轉寄email刪除\nSub A_Step9_RemoveFundEmail()\n    Dim myNameSpace As Outlook.NameSpace\n    Dim myFolder As Outlook.MAPIFolder\n    Dim myAttachments As Outlook.Attachments\n    Dim myItems As Outlook.Items\n    Dim TargetFolder As String, SFName As String, NSFName As String\n    Dim resultFolder As String\n    Dim i As Integer\n    Dim fs As Variant\n    Dim mail, att, ReturnVal As Variant\n\n    '重建資料夾，執行前先清除有可能造成鎖定的檔案\n    TargetFolder = \"D:\\來信的附件檔\"\n    A_Step2_CloseImgFiles\n    Sleep (2000)\n    MakeDir (TargetFolder)\n\n    Set fs = CreateObject(\"Scripting.FileSystemObject\")\n    Set myNameSpace = Application.GetNamespace(\"MAPI\")\n    Set myFolder = myNameSpace.Folders(\"個人資料夾\").Folders(\"01.工作\").Folders(\"01.基金\")\n    'myFolder 代表 \"收件匣 Inbox\"\n    Set myItems = myFolder.Items\n    'myItems 代表 \"收件匣\" 中所有信件 (的集合)\n    For Each mail In myItems   '檢查每一封信\n        If mail.UnRead = True Then\n            If InStr(1, CStr(mail.Subject), \"FW: \") > 0 Then\n                mail.Delete\n            End If\n        End If\n    Next mail\nEnd Sub\n\n", "content_b64": ""}, {"name": "SaveFundFiles.bas", "path": "模組/Outlook/SaveFundFiles.bas", "content": "Attribute VB_Name = \"SaveFundFiles\"\nOption Explicit\n'*************************************************************************************\n'專案名稱: 期信基金\n'功能描述: 儲存期貨對帳單檔案\n'\n'版權所有: Dunk\n'程式撰寫: Dunk\n'撰寫日期：2018/2/7\n'\n'改版日期:\n'改版備註:\n'\n'*************************************************************************************\n'儲存期貨對帳單\nFunction SaveFundFile(ByVal sourceFileName As String)\n    Dim sourceFolder, destFolder, destFileName As String\n    '目的資料夾\n    destFolder = \"Z:\\全委組帳務\\帳務--新制轉檔報表\\期信基金\\對帳單\"\n    destFileName = destFolder & \"\\\" & GetFileNameWithoutFolder(sourceFileName)\n    If InStr(1, sourceFileName, \".pdf\") > 0 Then\n        CopyFile fileNameSource:=sourceFileName, fileNameDest:=destFileName\n    End If\nEnd Function\n\n'複製檔案\nFunction CopyFile(ByVal fileNameSource As String, ByVal fileNameDest As String)\n    Dim existFile As Boolean\n    Dim fso As Scripting.FileSystemObject\n    Set fso = New Scripting.FileSystemObject\n\n\n    existFile = fso.FileExists(fileNameSource)\n    If existFile = False Then\n        MsgBox \"來源檔案不存在!\"\n        Set fso = Nothing\n        Exit Function\n    End If\n\n    fso.CopyFile fileNameSource, fileNameDest, True\n    Set fso = Nothing\nEnd Function\n\n'取得檔案所在資料夾\nFunction GetFileFolder(ByVal fileName As String)\n    Dim fName As String\n    Dim existFile As Boolean\n    Dim fso As Scripting.FileSystemObject\n    Dim myFile As File\n\n    Set fso = New Scripting.FileSystemObject\n    existFile = fso.FileExists(fileName)\n    If existFile = False Then\n        GetFileFolder = \"\"\n        Set myFile = Nothing\n        Set fso = Nothing\n        Exit Function\n    End If\n\n    Set myFile = fso.GetFile(fileName)\n    GetFileFolder = fso.GetParentFolderName(fileName)\n    Set myFile = Nothing\n    Set fso = Nothing\nEnd Function\n\n'取得檔案名稱(不含資料夾路徑)\nFunction GetFileNameWithoutFolder(ByVal fileName As String)\n    Dim fName As String\n    Dim existFile As Boolean\n    Dim fso As Scripting.FileSystemObject\n    Dim myFile As File\n\n    Set fso = New Scripting.FileSystemObject\n    existFile = fso.FileExists(fileName)\n    If existFile = False Then\n        GetFileNameWithoutFolder = \"\"\n        Set myFile = Nothing\n        Set fso = Nothing\n        Exit Function\n    End If\n\n    Set myFile = fso.GetFile(fileName)\n    GetFileNameWithoutFolder = fso.GetFileName(fileName)\n    Set myFile = Nothing\n    Set fso = Nothing\nEnd Function\n", "content_b64": ""}, {"name": "SaveSelectedMailAttachments.bas", "path": "模組/Outlook/SaveSelectedMailAttachments.bas", "content": "Attribute VB_Name = \"SaveSelectedMailAttachments\"\nOption Explicit\n'*************************************************************************************\n' 專案名稱: 儲存所選郵件附件範例\n' 功能說明: 將 Outlook 目前選取郵件的所有附件存到指定資料夾\n'*************************************************************************************\n\nPrivate Const OL_MAIL_ITEM As Long = 43\n\nPublic Sub SaveSelectedMailAttachmentsExample()\n    On Error GoTo ErrorHandler\n\n    Dim targetFolder As String\n    Dim outlookApp As Object\n    Dim selectionItems As Object\n    Dim mailItem As Object\n    Dim attachmentItem As Object\n    Dim savedCount As Long\n    Dim filePath As String\n\n    targetFolder = InputBox(\"請輸入附件儲存資料夾路徑\", \"儲存附件\", \"C:\\Temp\\OutlookAttachments\")\n    If Len(Trim$(targetFolder)) = 0 Then\n        Exit Sub\n    End If\n\n    If Right$(targetFolder, 1) <> \"\\\" Then\n        targetFolder = targetFolder & \"\\\"\n    End If\n\n    EnsureSaveSelectedAttachmentsFolder targetFolder\n\n    Set outlookApp = GetSaveSelectedAttachmentsOutlookApp()\n    Set selectionItems = outlookApp.ActiveExplorer.Selection\n\n    For Each mailItem In selectionItems\n        If mailItem.Class = OL_MAIL_ITEM Then\n            For Each attachmentItem In mailItem.Attachments\n                filePath = targetFolder & Format$(Now, \"yyyymmdd_hhnnss_\") & CleanSaveSelectedAttachmentsFileName(attachmentItem.FileName)\n                attachmentItem.SaveAsFile filePath\n                savedCount = savedCount + 1\n            Next attachmentItem\n        End If\n    Next mailItem\n\n    MsgBox \"附件儲存完成，共儲存 \" & CStr(savedCount) & \" 個檔案。\", vbInformation, \"儲存附件\"\n\nCleanExit:\n    Set attachmentItem = Nothing\n    Set mailItem = Nothing\n    Set selectionItems = Nothing\n    Set outlookApp = Nothing\n    Exit Sub\n\nErrorHandler:\n    MsgBox \"儲存附件時發生錯誤：\" & Err.Description, vbExclamation, \"儲存附件\"\n    Resume CleanExit\nEnd Sub\n\nPrivate Function GetSaveSelectedAttachmentsOutlookApp() As Object\n    On Error Resume Next\n\n    Set GetSaveSelectedAttachmentsOutlookApp = GetObject(, \"Outlook.Application\")\n    If GetSaveSelectedAttachmentsOutlookApp Is Nothing Then\n        Set GetSaveSelectedAttachmentsOutlookApp = CreateObject(\"Outlook.Application\")\n    End If\nEnd Function\n\nPrivate Sub EnsureSaveSelectedAttachmentsFolder(ByVal folderPath As String)\n    Dim fso As Object\n\n    Set fso = CreateObject(\"Scripting.FileSystemObject\")\n    If Not fso.FolderExists(folderPath) Then\n        fso.CreateFolder folderPath\n    End If\n    Set fso = Nothing\nEnd Sub\n\nPrivate Function CleanSaveSelectedAttachmentsFileName(ByVal fileName As String) As String\n    Dim invalidChars As Variant\n    Dim item As Variant\n\n    invalidChars = Array(\"\\\", \"/\", \":\", \"*\", \"?\", \"\"\"\", \"<\", \">\", \"|\")\n    CleanSaveSelectedAttachmentsFileName = fileName\n\n    For Each item In invalidChars\n        CleanSaveSelectedAttachmentsFileName = Replace$(CleanSaveSelectedAttachmentsFileName, CStr(item), \"_\")\n    Next item\nEnd Function", "content_b64": ""}, {"name": "SaveSelectedMailsAsMsg.bas", "path": "模組/Outlook/SaveSelectedMailsAsMsg.bas", "content": "Attribute VB_Name = \"SaveSelectedMailsAsMsg\"\nOption Explicit\n'*************************************************************************************\n' 專案名稱: 將所選郵件另存為 MSG 範例\n' 功能說明: 將 Outlook 目前選取郵件逐一另存成 .msg 檔\n'*************************************************************************************\n\nPrivate Const OL_MAIL_ITEM As Long = 43\nPrivate Const OL_MSG As Long = 3\n\nPublic Sub SaveSelectedMailsAsMsgExample()\n    On Error GoTo ErrorHandler\n\n    Dim targetFolder As String\n    Dim outlookApp As Object\n    Dim selectionItems As Object\n    Dim mailItem As Object\n    Dim savedCount As Long\n    Dim fileName As String\n\n    targetFolder = InputBox(\"請輸入 MSG 儲存資料夾路徑\", \"另存郵件\", \"C:\\Temp\\OutlookMsg\")\n    If Len(Trim$(targetFolder)) = 0 Then\n        Exit Sub\n    End If\n\n    If Right$(targetFolder, 1) <> \"\\\" Then\n        targetFolder = targetFolder & \"\\\"\n    End If\n\n    EnsureSaveSelectedMsgFolder targetFolder\n\n    Set outlookApp = GetSaveSelectedMsgOutlookApp()\n    Set selectionItems = outlookApp.ActiveExplorer.Selection\n\n    For Each mailItem In selectionItems\n        If mailItem.Class = OL_MAIL_ITEM Then\n            fileName = targetFolder & Format$(mailItem.ReceivedTime, \"yyyymmdd_hhnnss_\") & CleanSaveSelectedMsgFileName(mailItem.Subject) & \".msg\"\n            mailItem.SaveAs fileName, OL_MSG\n            savedCount = savedCount + 1\n        End If\n    Next mailItem\n\n    MsgBox \"郵件另存完成，共儲存 \" & CStr(savedCount) & \" 封。\", vbInformation, \"另存郵件\"\n\nCleanExit:\n    Set mailItem = Nothing\n    Set selectionItems = Nothing\n    Set outlookApp = Nothing\n    Exit Sub\n\nErrorHandler:\n    MsgBox \"另存郵件時發生錯誤：\" & Err.Description, vbExclamation, \"另存郵件\"\n    Resume CleanExit\nEnd Sub\n\nPrivate Function GetSaveSelectedMsgOutlookApp() As Object\n    On Error Resume Next\n\n    Set GetSaveSelectedMsgOutlookApp = GetObject(, \"Outlook.Application\")\n    If GetSaveSelectedMsgOutlookApp Is Nothing Then\n        Set GetSaveSelectedMsgOutlookApp = CreateObject(\"Outlook.Application\")\n    End If\nEnd Function\n\nPrivate Sub EnsureSaveSelectedMsgFolder(ByVal folderPath As String)\n    Dim fso As Object\n\n    Set fso = CreateObject(\"Scripting.FileSystemObject\")\n    If Not fso.FolderExists(folderPath) Then\n        fso.CreateFolder folderPath\n    End If\n    Set fso = Nothing\nEnd Sub\n\nPrivate Function CleanSaveSelectedMsgFileName(ByVal fileName As String) As String\n    Dim invalidChars As Variant\n    Dim item As Variant\n\n    invalidChars = Array(\"\\\", \"/\", \":\", \"*\", \"?\", \"\"\"\", \"<\", \">\", \"|\")\n    CleanSaveSelectedMsgFileName = Left$(fileName, 80)\n\n    For Each item In invalidChars\n        CleanSaveSelectedMsgFileName = Replace$(CleanSaveSelectedMsgFileName, CStr(item), \"_\")\n    Next item\n\n    If Len(Trim$(CleanSaveSelectedMsgFileName)) = 0 Then\n        CleanSaveSelectedMsgFileName = \"NoSubject\"\n    End If\nEnd Function", "content_b64": ""}, {"name": "SendMail.bas", "path": "模組/Outlook/SendMail.bas", "content": "Attribute VB_Name = \"SendMail\"\nOption Explicit\n'*************************************************************************************\n'專案名稱: 全委帳務處理\n'功能描述: 寄送股款信件\n'\n'版權所有: Dunk\n'程式撰寫: Dunk\n'撰寫日期：2017/6/13\n'\n'改版日期:\n'改版備註:\n'\n'*************************************************************************************\nSub B_Step1_SendMailToStock()\n    Dim tradeDay, sender As String\n    tradeDay = \"\"\n    tradeDay = InputBox(\"請輸入股款年月日\", \"股款設定\")\n    If tradeDay = \"\" Then\n        MsgBox \"請輸入股款年月日!\"\n        Exit Sub\n    End If\n\n    sender = \"abc@def.com\"\n\n    SendMailToStock tradeDay:=tradeDay, sender:=sender\nEnd Sub\n\n'寄送股款信件\nFunction SendMailToStock(ByVal tradeDay As String, ByVal sender As String)\n    Dim wbStr As String\n    Dim OutlookApp As Outlook.Application\n    Dim newMail As Outlook.MailItem\n    Dim myAttachments As Outlook.Attachments\n    Set OutlookApp = New Outlook.Application\n    Set newMail = OutlookApp.CreateItem(olMailItem)\n    With newMail\n        .Subject = tradeDay & \"股款\"\n        .To = sender\n        Set myAttachments = newMail.Attachments\n        myAttachments.Add \"D:\\\" & tradeDay & \"取款.zip\"\n        myAttachments.Add \"D:\\\" & tradeDay & \"匯款.zip\"\n        .Send\n    End With\n    MsgBox \"郵件發送成功!\"\n    Set newMail = Nothing\n    Set myAttachments = Nothing\n    Set OutlookApp = Nothing\nEnd Function\n", "content_b64": ""}, {"name": "SendWorkbookAsAttachment.bas", "path": "模組/Outlook/SendWorkbookAsAttachment.bas", "content": "Attribute VB_Name = \"SendWorkbookAsAttachment\"\nOption Explicit\n'*************************************************************************************\n' 專案名稱: 寄送目前活頁簿範例\n' 功能說明: 從 Excel 將目前活頁簿存檔後附加到 Outlook 郵件\n'*************************************************************************************\n\nPrivate Const OL_MAIL_ITEM As Long = 0\n\nPublic Sub SendWorkbookAsAttachmentExample()\n    On Error GoTo ErrorHandler\n\n    Dim outlookApp As Object\n    Dim mailItem As Object\n    Dim workbookPath As String\n    Dim recipientText As String\n\n    recipientText = InputBox(\"請輸入收件者信箱，多人請用分號分隔\", \"寄送活頁簿\")\n    If Len(Trim$(recipientText)) = 0 Then\n        Exit Sub\n    End If\n\n    workbookPath = ActiveWorkbook.FullName\n    If Len(workbookPath) = 0 Then\n        MsgBox \"請先儲存目前活頁簿，再執行此範例。\", vbExclamation, \"寄送活頁簿\"\n        Exit Sub\n    End If\n\n    ActiveWorkbook.Save\n\n    Set outlookApp = GetSendWorkbookAttachmentOutlookApp()\n    Set mailItem = outlookApp.CreateItem(OL_MAIL_ITEM)\n\n    With mailItem\n        .To = recipientText\n        .Subject = \"活頁簿附件 - \" & ActiveWorkbook.Name\n        .Body = \"您好，請參考附件活頁簿。\" & vbCrLf & vbCrLf & \"此郵件由 VBA 範例建立，請確認後再寄出。\"\n        .Attachments.Add workbookPath\n        .Display\n    End With\n\nCleanExit:\n    Set mailItem = Nothing\n    Set outlookApp = Nothing\n    Exit Sub\n\nErrorHandler:\n    MsgBox \"建立郵件時發生錯誤：\" & Err.Description, vbExclamation, \"寄送活頁簿\"\n    Resume CleanExit\nEnd Sub\n\nPrivate Function GetSendWorkbookAttachmentOutlookApp() As Object\n    On Error Resume Next\n\n    Set GetSendWorkbookAttachmentOutlookApp = GetObject(, \"Outlook.Application\")\n    If GetSendWorkbookAttachmentOutlookApp Is Nothing Then\n        Set GetSendWorkbookAttachmentOutlookApp = CreateObject(\"Outlook.Application\")\n    End If\nEnd Function", "content_b64": ""}, {"name": "UnzipFile.bas", "path": "模組/Outlook/UnzipFile.bas", "content": "Attribute VB_Name = \"UnzipFile\"\nOption Explicit\n'*************************************************************************************\n'專案名稱: 全權委託\n'功能描述: 將郵件檔案解壓縮\n'\n'版權所有: Dunk\n'程式撰寫: Dunk\n'撰寫日期：2018/1/19\n'\n'改版日期:\n'改版備註: 2018/3/1 調整過濾郵件列印部份\n'\n'*************************************************************************************\n'with full path\n'\"C:\\Program Files\\7-Zip\\7z.exe\" x -aoa D:\\0118日報.rar -oD:\\test_extract\\*.* -r -pAa1234\n'\"C:\\Program Files\\7-Zip\\7z.exe\" x -aoa D:\\新98-1續2-20180118.zip -oD:\\test_extract\\*.* -r -pAa1234\n\n'no full path (used)\n'\"C:\\Program Files\\7-Zip\\7z.exe\" x -aoa D:\\0118日報.rar -oD:\\test_extract -r -pAa1234\n'\"C:\\Program Files\\7-Zip\\7z.exe\" x -aoa D:\\新98-1續2-20180118.zip -oD:\\test_extract -r -pAa1234\n#If VBA7 Then\n    Declare PtrSafe  Sub Sleep Lib \"kernel32\" (ByVal dwMilliseconds As Long)    'For 64 Bit Systems\n    Declare PtrSafe  Function ShellExecute Lib \"shell32.dll\" _\n            Alias \"ShellExecuteA\" (ByVal hwnd As Long, ByVal lpOperation As String, _\n                                   ByVal lpFile As String, ByVal lpParameters As String, _\n                                   ByVal lpDirectory As String, ByVal nShowCmd As Long) As Long\n#Else\n    Declare Sub Sleep Lib \"kernel32\" (ByVal dwMilliseconds As Long)    'For 32 Bit Systems\n    Declare Function ShellExecute Lib \"shell32.dll\" _\n                                  Alias \"ShellExecuteA\" (ByVal hwnd As Long, ByVal lpOperation As String, _\n                                                         ByVal lpFile As String, ByVal lpParameters As String, _\n                                                         ByVal lpDirectory As String, ByVal nShowCmd As Long) As Long\n#End If\n\n'處理保德信加密檔案\nFunction DealWithEncryFilePGIM(ByVal zipFileName As String, ByVal pwd As String, ByVal sender As String)\n    Dim unzipFolder As String\n    'zipFileName = \"D:\\test_extract\\0118日報.rar\"\n    unzipFolder = GetFileFolder(zipFileName)\n    StartExtractFileForPGIM zipFileName, pwd\n    StartPrinting unzipFolder, sender\nEnd Function\n\n' 開始解壓縮檔案(for 保德信)\nFunction StartExtractFileForPGIM(ByVal inZipFileName As String, ByVal pwd As String)\n    Dim zipFileName, destFolder, destFileName, resultFileName As String\n    Dim pureZipFileName As String\n    'pwd\n    'pwd = \"Aa1234\"\n    'ZIP檔案位置\n    zipFileName = inZipFileName\n    '解壓縮後的資料夾\n    destFolder = GetFileFolder(zipFileName)\n    '檔案名稱\n    'destFileName = \"\\*.*\"\n    destFileName = \"\"\n\n    '開始解壓縮\n    ExtractFileToFolder zipFileName:=zipFileName, pwd:=pwd, destFolder:=destFolder, destFileName:=destFileName\n\nEnd Function\n'開始列印檔案\nFunction StartPrinting(ByVal folderName As String, ByVal sender As String)\n    Dim fileList(), fileName, ReturnVal As Variant\n    fileList = RetrivalFileListToArrary(folderName, 0)\n    For Each fileName In fileList\n        If PrintAttachment.ValidPrintAbleFile(fileName, sender) = True Then\n            ReturnVal = ShellExecute(0&, \"print\", fileName, 0&, 0&, 0&)\n        End If\n    Next\nEnd Function\n\n'取得檔案資料夾\nFunction GetFileFolder(ByVal fileName As String)\n    Dim fName As String\n    Dim existFile As Boolean\n    Dim fso As Scripting.FileSystemObject\n    Dim myFile As File\n\n    Set fso = New Scripting.FileSystemObject\n    existFile = fso.FileExists(fileName)\n    If existFile = False Then\n        GetFileFolder = \"\"\n        Set myFile = Nothing\n        Set fso = Nothing\n        Exit Function\n    End If\n\n    Set myFile = fso.GetFile(fileName)\n    GetFileFolder = myFile.ParentFolder\n    Set myFile = Nothing\n    Set fso = Nothing\nEnd Function\n'解壓縮檔案\nFunction ExtractFileToFolder(ByVal zipFileName As String, ByVal pwd As String, ByVal destFolder As String, ByVal destFileName As String)\n    Dim zipExePath, cmdLine As String\n    Dim wsh As Object\n    Set wsh = VBA.CreateObject(\"WScript.Shell\")\n    Dim waitOnReturn As Boolean: waitOnReturn = True\n    Dim windowStyle As Integer: windowStyle = 0\n    '7zip執行檔位置\n    zipExePath = \"C:\\Program Files\\7-Zip\\7z.exe\"\n    cmdLine = \"\"\"\" & zipExePath & \"\"\"  x -aoa \" & zipFileName & \" -o\" & destFolder & destFileName & \" -r -p\" & pwd\n    'Debug.Print cmdLine\n    wsh.Run cmdLine, windowStyle, waitOnReturn\nEnd Function\n\n'列出檔案清單\n'depth=0\nFunction RetrivalFileListToArrary(ByVal strDir As String, ByRef depth As Integer)\n    Dim thePath As String\n    Dim strSdir As String\n    Dim theDirs As Scripting.Folders\n    Dim theDir As Scripting.Folder\n    Dim theFile As Scripting.File\n    Dim myFSO As Scripting.FileSystemObject\n    Dim subFolderCount As Integer\n    Dim fileList() As Variant\n    Dim counter As Long\n\n    ReDim fileList(65536)\n    counter = 0\n\n    Set myFSO = New Scripting.FileSystemObject\n    If Right(strDir, 1) <> \"\" Then strDir = strDir & \"\"\n    thePath = thePath & strDir\n\n    '列出第一層根目錄的檔案\n    If depth = 0 Then\n        For Each theFile In myFSO.GetFolder(strDir).Files\n            fileList(counter) = theFile.Path\n            counter = counter + 1\n        Next\n        depth = 1\n    End If\n\n    '尋找所有子目錄的檔案\n    Set theDirs = myFSO.GetFolder(strDir).SubFolders\n    For Each theDir In theDirs\n        For Each theFile In theDir.Files\n            fileList(counter) = theFile.Path\n            counter = counter + 1\n        Next\n        RetrivalFileListToArrary strDir:=theDir.Path, depth:=depth\n    Next\n\n    Set myFSO = Nothing\n    If counter > 0 Then\n        counter = counter - 1\n    End If\n    ReDim Preserve fileList(counter)\n\n    RetrivalFileListToArrary = fileList\nEnd Function\n", "content_b64": ""}]}, {"folder": "PivotCharts", "path": "模組/PivotCharts", "files": [{"name": "PivotAreaChartExample.bas", "path": "模組/PivotCharts/PivotAreaChartExample.bas", "content": "Attribute VB_Name = \"PivotAreaChartExample\"\n\nOption Explicit\n\n'*************************************************************************************\n\n'模組名稱: PivotAreaChartExample\n\n'功能說明: 建立樞紐分析區域圖，展示各月份銷售趨勢\n\n'\n\n'作者版權所有: Dunk\n\n'程式設計: Dunk\n\n'撰寫日期: 2026/5/9\n\n'\n\n'*************************************************************************************\n\n\n\nSub TestPivotAreaChart()\n\n    Call CreatePivotAreaChart\n\nEnd Sub\n\n\n\nSub CreatePivotAreaChart()\n\n    Dim wsData  As Worksheet\n\n    Dim wsPivot As Worksheet\n\n    Dim pc      As PivotCache\n\n    Dim pt      As PivotTable\n\n    Dim chtObj  As ChartObject\n\n    Dim cht     As Chart\n\n\n\n    On Error GoTo ErrHandler\n\n\n\n    Set wsData  = AreaGetOrCreateWs(\"月份銷售資料\")\n\n    Set wsPivot = AreaGetOrCreateWs(\"區域圖樞紐\")\n\n\n\n    Call FillMonthlyAreaData(wsData)\n\n\n\n    Set pc = ThisWorkbook.PivotCaches.Create( _\n\n        SourceType:=xlDatabase, _\n\n        SourceData:=wsData.Range(\"A1\").CurrentRegion)\n\n\n\n    Set pt = pc.CreatePivotTable( _\n\n        TableDestination:=wsPivot.Range(\"A3\"), _\n\n        TableName:=\"月份銷售樞紐\")\n\n\n\n    With pt\n\n        .PivotFields(\"月份\").Orientation = xlRowField\n\n        .PivotFields(\"月份\").Position = 1\n\n        .AddDataField .PivotFields(\"銷售額\"), \"銷售額合計\", xlSum\n\n    End With\n\n\n\n    Set chtObj = wsPivot.ChartObjects.Add( _\n\n        Left:=wsPivot.Range(\"E3\").Left, _\n\n        Top:=wsPivot.Range(\"E3\").Top, _\n\n        Width:=450, Height:=300)\n\n\n\n    Set cht = chtObj.Chart\n\n    cht.SetSourceData Source:=pt.TableRange1\n\n    cht.ChartType = xlArea\n\n    cht.HasTitle = True\n\n    cht.ChartTitle.Text = \"各月份銷售趨勢區域圖\"\n\n    cht.HasLegend = True\n\n    cht.Legend.Position = xlLegendPositionBottom\n\n\n\n    wsPivot.Activate\n\n    MsgBox \"區域圖已建立完成！\", vbInformation, \"完成\"\n\n    Exit Sub\n\n\n\nErrHandler:\n\n    MsgBox \"建立區域圖失敗：\" & Err.Description, vbCritical, \"錯誤\"\n\nEnd Sub\n\n\n\nPrivate Sub FillMonthlyAreaData(ByVal ws As Worksheet)\n\n    ws.Cells.Clear\n\n    ws.Range(\"A1\").Value = \"月份\"\n\n    ws.Range(\"B1\").Value = \"銷售額\"\n\n    ws.Range(\"A2\").Value = \"一月\"\n\n    ws.Range(\"B2\").Value = 85000\n\n    ws.Range(\"A3\").Value = \"二月\"\n\n    ws.Range(\"B3\").Value = 92000\n\n    ws.Range(\"A4\").Value = \"三月\"\n\n    ws.Range(\"B4\").Value = 110000\n\n    ws.Range(\"A5\").Value = \"四月\"\n\n    ws.Range(\"B5\").Value = 103000\n\n    ws.Range(\"A6\").Value = \"五月\"\n\n    ws.Range(\"B6\").Value = 128000\n\n    ws.Range(\"A7\").Value = \"六月\"\n\n    ws.Range(\"B7\").Value = 145000\n\n    ws.Columns(\"A:B\").AutoFit\n\nEnd Sub\n\n\n\nPrivate Function AreaGetOrCreateWs(ByVal sheetName As String) As Worksheet\n\n    Dim ws As Worksheet\n\n    On Error Resume Next\n\n    Set ws = ThisWorkbook.Worksheets(sheetName)\n\n    On Error GoTo 0\n\n    If ws Is Nothing Then\n\n        Set ws = ThisWorkbook.Worksheets.Add\n\n        ws.Name = sheetName\n\n    End If\n\n    ws.Cells.Clear\n\n    Set AreaGetOrCreateWs = ws\n\nEnd Function\n\n", "content_b64": ""}, {"name": "PivotBarChartExample.bas", "path": "模組/PivotCharts/PivotBarChartExample.bas", "content": "Attribute VB_Name = \"PivotBarChartExample\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: PivotBarChartExample\n'功能說明: 建立以樞紐分析表為資料來源的長條樞紐分析圖\n'\n'著作權所有: Dunk\n'程式設計: Dunk\n'撰寫日期: 2026/5/7\n'\n'*************************************************************************************\n\n' 測試用入口\nSub TestPivotBarChart()\n    Call CreatePivotBarChart\nEnd Sub\n\n' 建立樞紐分析圖（橫條圖）\nSub CreatePivotBarChart()\n    Dim wsData As Worksheet\n    Dim wsPivot As Worksheet\n    Dim pc As PivotCache\n    Dim pt As PivotTable\n    Dim chartObj As ChartObject\n    Dim cht As Chart\n\n    Set wsData = GetOrCreateSheet(ThisWorkbook, \"銷售資料\")\n    Call FillSalesData(wsData)\n\n    Set wsPivot = GetOrCreateSheet(ThisWorkbook, \"樞紐分析圖\")\n\n    Set pc = ThisWorkbook.PivotCaches.Create( _\n        SourceType:=xlDatabase, _\n        SourceData:=wsData.Range(\"A1\").CurrentRegion)\n\n    Set pt = pc.CreatePivotTable( _\n        TableDestination:=wsPivot.Range(\"A3\"), _\n        TableName:=\"銷售樞紐\")\n\n    With pt.PivotFields(\"地區\")\n        .Orientation = xlRowField\n        .Position = 1\n    End With\n\n    pt.AddDataField pt.PivotFields(\"銷售額\"), \"銷售額合計\", xlSum\n\n    Set chartObj = wsPivot.ChartObjects.Add( _\n        Left:=wsPivot.Range(\"E3\").Left, _\n        Top:=wsPivot.Range(\"E3\").Top, _\n        Width:=400, _\n        Height:=280)\n\n    Set cht = chartObj.Chart\n    cht.SetSourceData Source:=pt.TableRange1\n    cht.ChartType = xlBarClustered\n    cht.HasTitle = True\n    cht.ChartTitle.Text = \"各地區銷售額樞紐分析圖\"\n    cht.ChartStyle = 5\n    cht.SeriesCollection(1).HasDataLabels = True\n\n    wsPivot.Activate\n    MsgBox \"樞紐分析圖已建立完成！\", vbInformation, \"完成\"\nEnd Sub\n\n' 填入銷售資料\nPrivate Sub FillSalesData(ByVal ws As Worksheet)\n    ws.Range(\"A1\").Value = \"地區\"\n    ws.Range(\"B1\").Value = \"產品\"\n    ws.Range(\"C1\").Value = \"銷售額\"\n    ws.Range(\"A2\").Value = \"北區\"\n    ws.Range(\"B2\").Value = \"產品A\"\n    ws.Range(\"C2\").Value = 120000\n    ws.Range(\"A3\").Value = \"南區\"\n    ws.Range(\"B3\").Value = \"產品A\"\n    ws.Range(\"C3\").Value = 95000\n    ws.Range(\"A4\").Value = \"東區\"\n    ws.Range(\"B4\").Value = \"產品B\"\n    ws.Range(\"C4\").Value = 108000\n    ws.Range(\"A5\").Value = \"西區\"\n    ws.Range(\"B5\").Value = \"產品B\"\n    ws.Range(\"C5\").Value = 87000\n    ws.Range(\"A6\").Value = \"北區\"\n    ws.Range(\"B6\").Value = \"產品B\"\n    ws.Range(\"C6\").Value = 135000\n    ws.Range(\"A7\").Value = \"南區\"\n    ws.Range(\"B7\").Value = \"產品A\"\n    ws.Range(\"C7\").Value = 78000\n    ws.Columns(\"A:C\").AutoFit\nEnd Sub\n\n' 取得或建立工作表，並清除內容\nPrivate Function GetOrCreateSheet(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add\n        ws.Name = sheetName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreateSheet = ws\nEnd Function\n", "content_b64": ""}, {"name": "PivotColumnChartExample.bas", "path": "模組/PivotCharts/PivotColumnChartExample.bas", "content": "Attribute VB_Name = \"PivotColumnChartExample\"\n\nOption Explicit\n\n'*************************************************************************************\n\n'模組名稱: PivotColumnChartExample\n\n'功能說明: 建立樞紐分析群組直條圖，比較各月份不同產品銷售量\n\n'\n\n'作者版權所有: Dunk\n\n'程式設計: Dunk\n\n'撰寫日期: 2026/5/9\n\n'\n\n'*************************************************************************************\n\n\n\nSub TestPivotColumnChart()\n\n    Call CreatePivotColumnChart\n\nEnd Sub\n\n\n\nSub CreatePivotColumnChart()\n\n    Dim wsData  As Worksheet\n\n    Dim wsPivot As Worksheet\n\n    Dim pc      As PivotCache\n\n    Dim pt      As PivotTable\n\n    Dim chtObj  As ChartObject\n\n    Dim cht     As Chart\n\n\n\n    On Error GoTo ErrHandler\n\n\n\n    Set wsData  = ColGetOrCreateWs(\"月份產品銷售\")\n\n    Set wsPivot = ColGetOrCreateWs(\"群組直條樞紐\")\n\n\n\n    Call FillColumnData(wsData)\n\n\n\n    Set pc = ThisWorkbook.PivotCaches.Create( _\n\n        SourceType:=xlDatabase, _\n\n        SourceData:=wsData.Range(\"A1\").CurrentRegion)\n\n\n\n    Set pt = pc.CreatePivotTable( _\n\n        TableDestination:=wsPivot.Range(\"A3\"), _\n\n        TableName:=\"月份產品樞紐\")\n\n\n\n    With pt\n\n        .PivotFields(\"月份\").Orientation = xlRowField\n\n        .PivotFields(\"月份\").Position = 1\n\n        .PivotFields(\"產品\").Orientation = xlColumnField\n\n        .PivotFields(\"產品\").Position = 1\n\n        .AddDataField .PivotFields(\"銷售量\"), \"銷售量合計\", xlSum\n\n    End With\n\n\n\n    Set chtObj = wsPivot.ChartObjects.Add( _\n\n        Left:=wsPivot.Range(\"F3\").Left, _\n\n        Top:=wsPivot.Range(\"F3\").Top, _\n\n        Width:=480, Height:=320)\n\n\n\n    Set cht = chtObj.Chart\n\n    cht.SetSourceData Source:=pt.TableRange1\n\n    cht.ChartType = xlColumnClustered\n\n    cht.HasTitle = True\n\n    cht.ChartTitle.Text = \"各月份產品銷售量群組直條圖\"\n\n    cht.HasLegend = True\n\n    cht.Legend.Position = xlLegendPositionBottom\n\n    cht.ChartStyle = 6\n\n    cht.SeriesCollection(1).HasDataLabels = True\n\n\n\n    wsPivot.Activate\n\n    MsgBox \"群組直條圖已建立完成！\", vbInformation, \"完成\"\n\n    Exit Sub\n\n\n\nErrHandler:\n\n    MsgBox \"建立群組直條圖失敗：\" & Err.Description, vbCritical, \"錯誤\"\n\nEnd Sub\n\n\n\nPrivate Sub FillColumnData(ByVal ws As Worksheet)\n\n    ws.Cells.Clear\n\n    ws.Range(\"A1\").Value = \"月份\"\n\n    ws.Range(\"B1\").Value = \"產品\"\n\n    ws.Range(\"C1\").Value = \"銷售量\"\n\n    ws.Range(\"A2\").Value = \"一月\"\n\n    ws.Range(\"B2\").Value = \"手機\"\n\n    ws.Range(\"C2\").Value = 320\n\n    ws.Range(\"A3\").Value = \"一月\"\n\n    ws.Range(\"B3\").Value = \"平板\"\n\n    ws.Range(\"C3\").Value = 185\n\n    ws.Range(\"A4\").Value = \"二月\"\n\n    ws.Range(\"B4\").Value = \"手機\"\n\n    ws.Range(\"C4\").Value = 295\n\n    ws.Range(\"A5\").Value = \"二月\"\n\n    ws.Range(\"B5\").Value = \"平板\"\n\n    ws.Range(\"C5\").Value = 210\n\n    ws.Range(\"A6\").Value = \"三月\"\n\n    ws.Range(\"B6\").Value = \"手機\"\n\n    ws.Range(\"C6\").Value = 410\n\n    ws.Range(\"A7\").Value = \"三月\"\n\n    ws.Range(\"B7\").Value = \"平板\"\n\n    ws.Range(\"C7\").Value = 240\n\n    ws.Range(\"A8\").Value = \"四月\"\n\n    ws.Range(\"B8\").Value = \"手機\"\n\n    ws.Range(\"C8\").Value = 380\n\n    ws.Range(\"A9\").Value = \"四月\"\n\n    ws.Range(\"B9\").Value = \"平板\"\n\n    ws.Range(\"C9\").Value = 195\n\n    ws.Columns(\"A:C\").AutoFit\n\nEnd Sub\n\n\n\nPrivate Function ColGetOrCreateWs(ByVal sheetName As String) As Worksheet\n\n    Dim ws As Worksheet\n\n    On Error Resume Next\n\n    Set ws = ThisWorkbook.Worksheets(sheetName)\n\n    On Error GoTo 0\n\n    If ws Is Nothing Then\n\n        Set ws = ThisWorkbook.Worksheets.Add\n\n        ws.Name = sheetName\n\n    End If\n\n    ws.Cells.Clear\n\n    Set ColGetOrCreateWs = ws\n\nEnd Function\n\n", "content_b64": ""}, {"name": "PivotComboChartExample.bas", "path": "模組/PivotCharts/PivotComboChartExample.bas", "content": "Attribute VB_Name = \"PivotComboChartExample\"\n\nOption Explicit\n\n'*************************************************************************************\n\n'模組名稱: PivotComboChartExample\n\n'功能說明: 建立樞紐分析組合圖（直條圖+折線圖），呈現銷售額與達成率對比\n\n'\n\n'作者版權所有: Dunk\n\n'程式設計: Dunk\n\n'撰寫日期: 2026/5/9\n\n'\n\n'*************************************************************************************\n\n\n\nSub TestPivotComboChart()\n\n    Call CreatePivotComboChart\n\nEnd Sub\n\n\n\nSub CreatePivotComboChart()\n\n    Dim wsData  As Worksheet\n\n    Dim wsPivot As Worksheet\n\n    Dim pc      As PivotCache\n\n    Dim pt      As PivotTable\n\n    Dim chtObj  As ChartObject\n\n    Dim cht     As Chart\n\n    Dim ser     As Series\n\n\n\n    On Error GoTo ErrHandler\n\n\n\n    Set wsData  = ComboGetOrCreateWs(\"銷售達成資料\")\n\n    Set wsPivot = ComboGetOrCreateWs(\"組合圖樞紐\")\n\n\n\n    Call FillComboData(wsData)\n\n\n\n    Set pc = ThisWorkbook.PivotCaches.Create( _\n\n        SourceType:=xlDatabase, _\n\n        SourceData:=wsData.Range(\"A1\").CurrentRegion)\n\n\n\n    Set pt = pc.CreatePivotTable( _\n\n        TableDestination:=wsPivot.Range(\"A3\"), _\n\n        TableName:=\"銷售達成樞紐\")\n\n\n\n    With pt\n\n        .PivotFields(\"業務員\").Orientation = xlRowField\n\n        .PivotFields(\"業務員\").Position = 1\n\n        .AddDataField .PivotFields(\"銷售額\"), \"銷售額合計\", xlSum\n\n        .AddDataField .PivotFields(\"達成率\"), \"平均達成率\", xlAverage\n\n        .DataFields(1).NumberFormat = \"#,##0\"\n\n        .DataFields(2).NumberFormat = \"0.0%\"\n\n    End With\n\n\n\n    Set chtObj = wsPivot.ChartObjects.Add( _\n\n        Left:=wsPivot.Range(\"F3\").Left, _\n\n        Top:=wsPivot.Range(\"F3\").Top, _\n\n        Width:=480, Height:=320)\n\n\n\n    Set cht = chtObj.Chart\n\n    cht.SetSourceData Source:=pt.TableRange1\n\n    cht.ChartType = xlColumnClustered\n\n\n\n    '將第二數列改為折線圖並置於副座標軸\n\n    If cht.SeriesCollection.Count >= 2 Then\n\n        Set ser = cht.SeriesCollection(2)\n\n        ser.ChartType = xlLine\n\n        ser.AxisGroup = xlSecondary\n\n    End If\n\n\n\n    cht.HasTitle = True\n\n    cht.ChartTitle.Text = \"業務員銷售額與達成率組合圖\"\n\n    cht.HasLegend = True\n\n    cht.Legend.Position = xlLegendPositionBottom\n\n\n\n    wsPivot.Activate\n\n    MsgBox \"組合圖已建立完成！\", vbInformation, \"完成\"\n\n    Exit Sub\n\n\n\nErrHandler:\n\n    MsgBox \"建立組合圖失敗：\" & Err.Description, vbCritical, \"錯誤\"\n\nEnd Sub\n\n\n\nPrivate Sub FillComboData(ByVal ws As Worksheet)\n\n    ws.Cells.Clear\n\n    ws.Range(\"A1\").Value = \"業務員\"\n\n    ws.Range(\"B1\").Value = \"銷售額\"\n\n    ws.Range(\"C1\").Value = \"達成率\"\n\n    ws.Range(\"A2\").Value = \"陳大明\"\n\n    ws.Range(\"B2\").Value = 285000\n\n    ws.Range(\"C2\").Value = 0.95\n\n    ws.Range(\"A3\").Value = \"林小華\"\n\n    ws.Range(\"B3\").Value = 320000\n\n    ws.Range(\"C3\").Value = 1.07\n\n    ws.Range(\"A4\").Value = \"王志遠\"\n\n    ws.Range(\"B4\").Value = 198000\n\n    ws.Range(\"C4\").Value = 0.66\n\n    ws.Range(\"A5\").Value = \"張美玲\"\n\n    ws.Range(\"B5\").Value = 410000\n\n    ws.Range(\"C5\").Value = 1.37\n\n    ws.Range(\"A6\").Value = \"李俊賢\"\n\n    ws.Range(\"B6\").Value = 250000\n\n    ws.Range(\"C6\").Value = 0.83\n\n    ws.Columns(\"A:C\").AutoFit\n\nEnd Sub\n\n\n\nPrivate Function ComboGetOrCreateWs(ByVal sheetName As String) As Worksheet\n\n    Dim ws As Worksheet\n\n    On Error Resume Next\n\n    Set ws = ThisWorkbook.Worksheets(sheetName)\n\n    On Error GoTo 0\n\n    If ws Is Nothing Then\n\n        Set ws = ThisWorkbook.Worksheets.Add\n\n        ws.Name = sheetName\n\n    End If\n\n    ws.Cells.Clear\n\n    Set ComboGetOrCreateWs = ws\n\nEnd Function\n\n", "content_b64": ""}, {"name": "PivotDoughnutChartExample.bas", "path": "模組/PivotCharts/PivotDoughnutChartExample.bas", "content": "Attribute VB_Name = \"PivotDoughnutChartExample\"\n\nOption Explicit\n\n'*************************************************************************************\n\n'模組名稱: PivotDoughnutChartExample\n\n'功能說明: 建立樞紐分析環形圖，展示各產品類別市佔率\n\n'\n\n'作者版權所有: Dunk\n\n'程式設計: Dunk\n\n'撰寫日期: 2026/5/9\n\n'\n\n'*************************************************************************************\n\n\n\nSub TestPivotDoughnutChart()\n\n    Call CreatePivotDoughnutChart\n\nEnd Sub\n\n\n\nSub CreatePivotDoughnutChart()\n\n    Dim wsData  As Worksheet\n\n    Dim wsPivot As Worksheet\n\n    Dim pc      As PivotCache\n\n    Dim pt      As PivotTable\n\n    Dim chtObj  As ChartObject\n\n    Dim cht     As Chart\n\n\n\n    On Error GoTo ErrHandler\n\n\n\n    Set wsData  = DoughnutGetOrCreateWs(\"產品市佔資料\")\n\n    Set wsPivot = DoughnutGetOrCreateWs(\"環形圖樞紐\")\n\n\n\n    Call FillDoughnutData(wsData)\n\n\n\n    Set pc = ThisWorkbook.PivotCaches.Create( _\n\n        SourceType:=xlDatabase, _\n\n        SourceData:=wsData.Range(\"A1\").CurrentRegion)\n\n\n\n    Set pt = pc.CreatePivotTable( _\n\n        TableDestination:=wsPivot.Range(\"A3\"), _\n\n        TableName:=\"產品市佔樞紐\")\n\n\n\n    With pt\n\n        .PivotFields(\"產品類別\").Orientation = xlRowField\n\n        .PivotFields(\"產品類別\").Position = 1\n\n        .AddDataField .PivotFields(\"銷售額\"), \"銷售額合計\", xlSum\n\n        .DataFields(1).NumberFormat = \"#,##0\"\n\n    End With\n\n\n\n    Set chtObj = wsPivot.ChartObjects.Add( _\n\n        Left:=wsPivot.Range(\"D3\").Left, _\n\n        Top:=wsPivot.Range(\"D3\").Top, _\n\n        Width:=420, Height:=300)\n\n\n\n    Set cht = chtObj.Chart\n\n    cht.SetSourceData Source:=pt.TableRange1\n\n    cht.ChartType = xlDoughnut\n\n    cht.HasTitle = True\n\n    cht.ChartTitle.Text = \"各產品類別市佔率環形圖\"\n\n    cht.SeriesCollection(1).ApplyDataLabels\n\n    cht.SeriesCollection(1).DataLabels.ShowPercentage = True\n\n    cht.SeriesCollection(1).DataLabels.ShowValue = False\n\n    cht.HasLegend = True\n\n    cht.Legend.Position = xlLegendPositionRight\n\n\n\n    wsPivot.Activate\n\n    MsgBox \"環形圖已建立完成！\", vbInformation, \"完成\"\n\n    Exit Sub\n\n\n\nErrHandler:\n\n    MsgBox \"建立環形圖失敗：\" & Err.Description, vbCritical, \"錯誤\"\n\nEnd Sub\n\n\n\nPrivate Sub FillDoughnutData(ByVal ws As Worksheet)\n\n    ws.Cells.Clear\n\n    ws.Range(\"A1\").Value = \"產品類別\"\n\n    ws.Range(\"B1\").Value = \"銷售額\"\n\n    ws.Range(\"A2\").Value = \"電子產品\"\n\n    ws.Range(\"B2\").Value = 350000\n\n    ws.Range(\"A3\").Value = \"服飾配件\"\n\n    ws.Range(\"B3\").Value = 210000\n\n    ws.Range(\"A4\").Value = \"食品飲料\"\n\n    ws.Range(\"B4\").Value = 180000\n\n    ws.Range(\"A5\").Value = \"家居用品\"\n\n    ws.Range(\"B5\").Value = 145000\n\n    ws.Range(\"A6\").Value = \"運動休閒\"\n\n    ws.Range(\"B6\").Value = 125000\n\n    ws.Range(\"A7\").Value = \"書籍文具\"\n\n    ws.Range(\"B7\").Value = 90000\n\n    ws.Columns(\"A:B\").AutoFit\n\nEnd Sub\n\n\n\nPrivate Function DoughnutGetOrCreateWs(ByVal sheetName As String) As Worksheet\n\n    Dim ws As Worksheet\n\n    On Error Resume Next\n\n    Set ws = ThisWorkbook.Worksheets(sheetName)\n\n    On Error GoTo 0\n\n    If ws Is Nothing Then\n\n        Set ws = ThisWorkbook.Worksheets.Add\n\n        ws.Name = sheetName\n\n    End If\n\n    ws.Cells.Clear\n\n    Set DoughnutGetOrCreateWs = ws\n\nEnd Function\n\n", "content_b64": ""}, {"name": "PivotLineChartExample.bas", "path": "模組/PivotCharts/PivotLineChartExample.bas", "content": "Attribute VB_Name = \"PivotLineChartExample\"\n\nOption Explicit\n\n\n\n' ============================================================\n\n' 範例：以 VBA 建立樞紐折線圖（PivotChart - Line）\n\n' 功能：基於現有樞紐分析表建立折線樞紐圖，並設定標題\n\n' ============================================================\n\nSub CreatePivotLineChart()\n\n    Dim ws      As Worksheet\n\n    Dim pt      As PivotTable\n\n    Dim chObj   As ChartObject\n\n    Dim ch      As Chart\n\n\n\n    On Error GoTo ErrHandler\n\n\n\n    ' --- 確認作用中工作表有樞紐分析表 ---\n\n    Set ws = ActiveSheet\n\n    If ws.PivotTables.Count = 0 Then\n\n        MsgBox \"作用中工作表沒有樞紐分析表，請先切換至含樞紐分析表的工作表。\", vbExclamation\n\n        Exit Sub\n\n    End If\n\n\n\n    Set pt = ws.PivotTables(1)\n\n\n\n    ' --- 插入樞紐折線圖 ---\n\n    Set chObj = ws.ChartObjects.Add(Left:=20, Top:=200, Width:=450, Height:=280)\n\n    Set ch = chObj.Chart\n\n\n\n    ch.SetSourceData Source:=pt.TableRange1\n\n    ch.ChartType = xlLine\n\n\n\n    ' --- 設定標題 ---\n\n    ch.HasTitle = True\n\n    ch.ChartTitle.Text = pt.Name & \" 趨勢折線圖\"\n\n\n\n    ' --- 設定圖例 ---\n\n    ch.HasLegend = True\n\n    ch.Legend.Position = xlLegendPositionBottom\n\n\n\n    MsgBox \"樞紐折線圖已建立於工作表：\" & ws.Name, vbInformation\n\n    Exit Sub\n\n\n\nErrHandler:\n\n    MsgBox \"發生錯誤：\" & Err.Description, vbCritical\n\nEnd Sub\n\n", "content_b64": ""}, {"name": "PivotMultiFieldChartExample.bas", "path": "模組/PivotCharts/PivotMultiFieldChartExample.bas", "content": "Attribute VB_Name = \"PivotMultiFieldChartExample\"\n\nOption Explicit\n\n'*************************************************************************************\n\n'模組名稱: PivotMultiFieldChartExample\n\n'功能說明: 建立多欄位樞紐分析圖，進行地區與產品線交叉分析\n\n'\n\n'作者版權所有: Dunk\n\n'程式設計: Dunk\n\n'撰寫日期: 2026/5/9\n\n'\n\n'*************************************************************************************\n\n\n\nSub TestPivotMultiFieldChart()\n\n    Call CreatePivotMultiFieldChart\n\nEnd Sub\n\n\n\nSub CreatePivotMultiFieldChart()\n\n    Dim wsData  As Worksheet\n\n    Dim wsPivot As Worksheet\n\n    Dim pc      As PivotCache\n\n    Dim pt      As PivotTable\n\n    Dim chtObj  As ChartObject\n\n    Dim cht     As Chart\n\n\n\n    On Error GoTo ErrHandler\n\n\n\n    Set wsData  = MultiGetOrCreateWs(\"地區產品資料\")\n\n    Set wsPivot = MultiGetOrCreateWs(\"多欄位樞紐\")\n\n\n\n    Call FillMultiFieldData(wsData)\n\n\n\n    Set pc = ThisWorkbook.PivotCaches.Create( _\n\n        SourceType:=xlDatabase, _\n\n        SourceData:=wsData.Range(\"A1\").CurrentRegion)\n\n\n\n    Set pt = pc.CreatePivotTable( _\n\n        TableDestination:=wsPivot.Range(\"A3\"), _\n\n        TableName:=\"地區產品樞紐\")\n\n\n\n    With pt\n\n        .PivotFields(\"地區\").Orientation = xlRowField\n\n        .PivotFields(\"地區\").Position = 1\n\n        .PivotFields(\"產品線\").Orientation = xlColumnField\n\n        .PivotFields(\"產品線\").Position = 1\n\n        .AddDataField .PivotFields(\"銷售量\"), \"銷售量合計\", xlSum\n\n    End With\n\n\n\n    Set chtObj = wsPivot.ChartObjects.Add( _\n\n        Left:=wsPivot.Range(\"F3\").Left, _\n\n        Top:=wsPivot.Range(\"F3\").Top, _\n\n        Width:=480, Height:=320)\n\n\n\n    Set cht = chtObj.Chart\n\n    cht.SetSourceData Source:=pt.TableRange1\n\n    cht.ChartType = xlColumnClustered\n\n    cht.HasTitle = True\n\n    cht.ChartTitle.Text = \"各地區產品線銷售量交叉分析圖\"\n\n    cht.HasLegend = True\n\n    cht.Legend.Position = xlLegendPositionBottom\n\n    cht.ChartStyle = 10\n\n\n\n    wsPivot.Activate\n\n    MsgBox \"多欄位樞紐圖已建立完成！\", vbInformation, \"完成\"\n\n    Exit Sub\n\n\n\nErrHandler:\n\n    MsgBox \"建立多欄位樞紐圖失敗：\" & Err.Description, vbCritical, \"錯誤\"\n\nEnd Sub\n\n\n\nPrivate Sub FillMultiFieldData(ByVal ws As Worksheet)\n\n    ws.Cells.Clear\n\n    ws.Range(\"A1\").Value = \"地區\"\n\n    ws.Range(\"B1\").Value = \"產品線\"\n\n    ws.Range(\"C1\").Value = \"銷售量\"\n\n    ws.Range(\"A2\").Value = \"北部\"\n\n    ws.Range(\"B2\").Value = \"家電\"\n\n    ws.Range(\"C2\").Value = 520\n\n    ws.Range(\"A3\").Value = \"北部\"\n\n    ws.Range(\"B3\").Value = \"3C\"\n\n    ws.Range(\"C3\").Value = 880\n\n    ws.Range(\"A4\").Value = \"北部\"\n\n    ws.Range(\"B4\").Value = \"服飾\"\n\n    ws.Range(\"C4\").Value = 430\n\n    ws.Range(\"A5\").Value = \"中部\"\n\n    ws.Range(\"B5\").Value = \"家電\"\n\n    ws.Range(\"C5\").Value = 380\n\n    ws.Range(\"A6\").Value = \"中部\"\n\n    ws.Range(\"B6\").Value = \"3C\"\n\n    ws.Range(\"C6\").Value = 620\n\n    ws.Range(\"A7\").Value = \"中部\"\n\n    ws.Range(\"B7\").Value = \"服飾\"\n\n    ws.Range(\"C7\").Value = 350\n\n    ws.Range(\"A8\").Value = \"南部\"\n\n    ws.Range(\"B8\").Value = \"家電\"\n\n    ws.Range(\"C8\").Value = 410\n\n    ws.Range(\"A9\").Value = \"南部\"\n\n    ws.Range(\"B9\").Value = \"3C\"\n\n    ws.Range(\"C9\").Value = 550\n\n    ws.Range(\"A10\").Value = \"南部\"\n\n    ws.Range(\"B10\").Value = \"服飾\"\n\n    ws.Range(\"C10\").Value = 480\n\n    ws.Columns(\"A:C\").AutoFit\n\nEnd Sub\n\n\n\nPrivate Function MultiGetOrCreateWs(ByVal sheetName As String) As Worksheet\n\n    Dim ws As Worksheet\n\n    On Error Resume Next\n\n    Set ws = ThisWorkbook.Worksheets(sheetName)\n\n    On Error GoTo 0\n\n    If ws Is Nothing Then\n\n        Set ws = ThisWorkbook.Worksheets.Add\n\n        ws.Name = sheetName\n\n    End If\n\n    ws.Cells.Clear\n\n    Set MultiGetOrCreateWs = ws\n\nEnd Function\n\n", "content_b64": ""}, {"name": "PivotPageFieldChartExample.bas", "path": "模組/PivotCharts/PivotPageFieldChartExample.bas", "content": "Attribute VB_Name = \"PivotPageFieldChartExample\"\n\nOption Explicit\n\n'*************************************************************************************\n\n'模組名稱: PivotPageFieldChartExample\n\n'功能說明: 建立含頁面欄位（報表篩選）的樞紐分析圖，可依業務員切換檢視\n\n'\n\n'作者版權所有: Dunk\n\n'程式設計: Dunk\n\n'撰寫日期: 2026/5/9\n\n'\n\n'*************************************************************************************\n\n\n\nSub TestPivotPageFieldChart()\n\n    Call CreatePivotPageFieldChart\n\nEnd Sub\n\n\n\nSub CreatePivotPageFieldChart()\n\n    Dim wsData  As Worksheet\n\n    Dim wsPivot As Worksheet\n\n    Dim pc      As PivotCache\n\n    Dim pt      As PivotTable\n\n    Dim chtObj  As ChartObject\n\n    Dim cht     As Chart\n\n\n\n    On Error GoTo ErrHandler\n\n\n\n    Set wsData  = PageGetOrCreateWs(\"業務銷售明細\")\n\n    Set wsPivot = PageGetOrCreateWs(\"頁面篩選樞紐\")\n\n\n\n    Call FillPageFieldData(wsData)\n\n\n\n    Set pc = ThisWorkbook.PivotCaches.Create( _\n\n        SourceType:=xlDatabase, _\n\n        SourceData:=wsData.Range(\"A1\").CurrentRegion)\n\n\n\n    Set pt = pc.CreatePivotTable( _\n\n        TableDestination:=wsPivot.Range(\"A3\"), _\n\n        TableName:=\"業務銷售樞紐\")\n\n\n\n    With pt\n\n        '業務員設為頁面欄位（報表篩選）\n\n        .PivotFields(\"業務員\").Orientation = xlPageField\n\n        .PivotFields(\"業務員\").Position = 1\n\n        '月份設為列欄位\n\n        .PivotFields(\"月份\").Orientation = xlRowField\n\n        .PivotFields(\"月份\").Position = 1\n\n        .AddDataField .PivotFields(\"銷售額\"), \"銷售額合計\", xlSum\n\n        .DataFields(1).NumberFormat = \"#,##0\"\n\n    End With\n\n\n\n    Set chtObj = wsPivot.ChartObjects.Add( _\n\n        Left:=wsPivot.Range(\"E5\").Left, _\n\n        Top:=wsPivot.Range(\"E5\").Top, _\n\n        Width:=450, Height:=300)\n\n\n\n    Set cht = chtObj.Chart\n\n    cht.SetSourceData Source:=pt.TableRange1\n\n    cht.ChartType = xlBarClustered\n\n    cht.HasTitle = True\n\n    cht.ChartTitle.Text = \"業務員月份銷售額（可依頁面篩選切換）\"\n\n    cht.HasLegend = False\n\n\n\n    wsPivot.Activate\n\n    MsgBox \"含頁面篩選欄位的樞紐圖已建立！\" & vbCrLf & _\n\n           \"請在 A1 下拉選單切換業務員以更新圖表。\", vbInformation, \"完成\"\n\n    Exit Sub\n\n\n\nErrHandler:\n\n    MsgBox \"建立頁面篩選樞紐圖失敗：\" & Err.Description, vbCritical, \"錯誤\"\n\nEnd Sub\n\n\n\nPrivate Sub FillPageFieldData(ByVal ws As Worksheet)\n\n    ws.Cells.Clear\n\n    ws.Range(\"A1\").Value = \"業務員\"\n\n    ws.Range(\"B1\").Value = \"月份\"\n\n    ws.Range(\"C1\").Value = \"銷售額\"\n\n    ws.Range(\"A2\").Value = \"陳大明\"\n\n    ws.Range(\"B2\").Value = \"一月\"\n\n    ws.Range(\"C2\").Value = 85000\n\n    ws.Range(\"A3\").Value = \"陳大明\"\n\n    ws.Range(\"B3\").Value = \"二月\"\n\n    ws.Range(\"C3\").Value = 92000\n\n    ws.Range(\"A4\").Value = \"陳大明\"\n\n    ws.Range(\"B4\").Value = \"三月\"\n\n    ws.Range(\"C4\").Value = 108000\n\n    ws.Range(\"A5\").Value = \"林小華\"\n\n    ws.Range(\"B5\").Value = \"一月\"\n\n    ws.Range(\"C5\").Value = 110000\n\n    ws.Range(\"A6\").Value = \"林小華\"\n\n    ws.Range(\"B6\").Value = \"二月\"\n\n    ws.Range(\"C6\").Value = 125000\n\n    ws.Range(\"A7\").Value = \"林小華\"\n\n    ws.Range(\"B7\").Value = \"三月\"\n\n    ws.Range(\"C7\").Value = 140000\n\n    ws.Range(\"A8\").Value = \"王志遠\"\n\n    ws.Range(\"B8\").Value = \"一月\"\n\n    ws.Range(\"C8\").Value = 65000\n\n    ws.Range(\"A9\").Value = \"王志遠\"\n\n    ws.Range(\"B9\").Value = \"二月\"\n\n    ws.Range(\"C9\").Value = 72000\n\n    ws.Range(\"A10\").Value = \"王志遠\"\n\n    ws.Range(\"B10\").Value = \"三月\"\n\n    ws.Range(\"C10\").Value = 80000\n\n    ws.Columns(\"A:C\").AutoFit\n\nEnd Sub\n\n\n\nPrivate Function PageGetOrCreateWs(ByVal sheetName As String) As Worksheet\n\n    Dim ws As Worksheet\n\n    On Error Resume Next\n\n    Set ws = ThisWorkbook.Worksheets(sheetName)\n\n    On Error GoTo 0\n\n    If ws Is Nothing Then\n\n        Set ws = ThisWorkbook.Worksheets.Add\n\n        ws.Name = sheetName\n\n    End If\n\n    ws.Cells.Clear\n\n    Set PageGetOrCreateWs = ws\n\nEnd Function\n\n", "content_b64": ""}, {"name": "PivotPieChartExample.bas", "path": "模組/PivotCharts/PivotPieChartExample.bas", "content": "Option Explicit\n\n' 建立樞紐分析圓形圖，呈現各區銷售金額占比。\nPublic Sub CreatePivotPieChartExample()\n    On Error GoTo ErrHandler\n\n    Dim dataWs As Worksheet\n    Dim pivotWs As Worksheet\n    Dim pivotCache As PivotCache\n    Dim pivotTable As PivotTable\n    Dim chartObj As ChartObject\n\n    Set dataWs = GetOrCreatePivotChartWorksheet(\"圓形樞紐資料\")\n    Set pivotWs = GetOrCreatePivotChartWorksheet(\"圓形樞紐圖\")\n    dataWs.Cells.Clear\n    pivotWs.Cells.Clear\n\n    Call FillPivotPieData(dataWs)\n    Set pivotCache = ThisWorkbook.PivotCaches.Create(SourceType:=xlDatabase, SourceData:=dataWs.Range(\"A1\").CurrentRegion)\n    Set pivotTable = pivotCache.CreatePivotTable(TableDestination:=pivotWs.Range(\"A3\"), TableName:=\"PiePivotTable\")\n\n    With pivotTable\n        .PivotFields(\"區域\").Orientation = xlRowField\n        .AddDataField .PivotFields(\"金額\"), \"金額合計\", xlSum\n        .DataFields(1).NumberFormat = \"#,##0\"\n    End With\n\n    Set chartObj = pivotWs.ChartObjects.Add(Left:=pivotWs.Range(\"D3\").Left, Top:=pivotWs.Range(\"D3\").Top, Width:=420, Height:=300)\n    With chartObj.Chart\n        .SetSourceData Source:=pivotTable.TableRange1\n        .ChartType = xlPie\n        .HasTitle = True\n        .ChartTitle.Text = \"各區銷售占比\"\n        .SeriesCollection(1).ApplyDataLabels\n    End With\n\n    pivotWs.Columns.AutoFit\n    MsgBox \"樞紐分析圓形圖已建立完成。\", vbInformation, \"完成\"\n    Exit Sub\n\nErrHandler:\n    MsgBox \"建立樞紐分析圖失敗：\" & Err.Description, vbExclamation, \"錯誤\"\nEnd Sub\n\nPrivate Sub FillPivotPieData(ByVal ws As Worksheet)\n    ws.Range(\"A1:C1\").Value = Array(\"區域\", \"產品\", \"金額\")\n    ws.Range(\"A2:C2\").Value = Array(\"北區\", \"A\", 22000)\n    ws.Range(\"A3:C3\").Value = Array(\"北區\", \"B\", 18000)\n    ws.Range(\"A4:C4\").Value = Array(\"中區\", \"A\", 26000)\n    ws.Range(\"A5:C5\").Value = Array(\"中區\", \"B\", 21000)\n    ws.Range(\"A6:C6\").Value = Array(\"南區\", \"A\", 24000)\n    ws.Range(\"A7:C7\").Value = Array(\"南區\", \"B\", 19500)\nEnd Sub\n\nPrivate Function GetOrCreatePivotChartWorksheet(ByVal sheetName As String) As Worksheet\n    On Error Resume Next\n    Set GetOrCreatePivotChartWorksheet = ThisWorkbook.Worksheets(sheetName)\n    On Error GoTo 0\n\n    If GetOrCreatePivotChartWorksheet Is Nothing Then\n        Set GetOrCreatePivotChartWorksheet = ThisWorkbook.Worksheets.Add\n        GetOrCreatePivotChartWorksheet.Name = sheetName\n    End If\nEnd Function", "content_b64": ""}, {"name": "PivotRadarChartExample.bas", "path": "模組/PivotCharts/PivotRadarChartExample.bas", "content": "Attribute VB_Name = \"PivotRadarChartExample\"\n\nOption Explicit\n\n'*************************************************************************************\n\n'模組名稱: PivotRadarChartExample\n\n'功能說明: 建立樞紐分析雷達圖，展示各部門績效多維評估\n\n'\n\n'作者版權所有: Dunk\n\n'程式設計: Dunk\n\n'撰寫日期: 2026/5/9\n\n'\n\n'*************************************************************************************\n\n\n\nSub TestPivotRadarChart()\n\n    Call CreatePivotRadarChart\n\nEnd Sub\n\n\n\nSub CreatePivotRadarChart()\n\n    Dim wsData  As Worksheet\n\n    Dim wsPivot As Worksheet\n\n    Dim pc      As PivotCache\n\n    Dim pt      As PivotTable\n\n    Dim chtObj  As ChartObject\n\n    Dim cht     As Chart\n\n\n\n    On Error GoTo ErrHandler\n\n\n\n    Set wsData  = RadarGetOrCreateWs(\"部門績效資料\")\n\n    Set wsPivot = RadarGetOrCreateWs(\"雷達圖樞紐\")\n\n\n\n    Call FillRadarData(wsData)\n\n\n\n    Set pc = ThisWorkbook.PivotCaches.Create( _\n\n        SourceType:=xlDatabase, _\n\n        SourceData:=wsData.Range(\"A1\").CurrentRegion)\n\n\n\n    Set pt = pc.CreatePivotTable( _\n\n        TableDestination:=wsPivot.Range(\"A3\"), _\n\n        TableName:=\"部門績效樞紐\")\n\n\n\n    With pt\n\n        .PivotFields(\"評估項目\").Orientation = xlRowField\n\n        .PivotFields(\"評估項目\").Position = 1\n\n        .PivotFields(\"部門\").Orientation = xlColumnField\n\n        .PivotFields(\"部門\").Position = 1\n\n        .AddDataField .PivotFields(\"分數\"), \"平均分數\", xlAverage\n\n        .DataFields(1).NumberFormat = \"0.0\"\n\n    End With\n\n\n\n    Set chtObj = wsPivot.ChartObjects.Add( _\n\n        Left:=wsPivot.Range(\"F3\").Left, _\n\n        Top:=wsPivot.Range(\"F3\").Top, _\n\n        Width:=420, Height:=320)\n\n\n\n    Set cht = chtObj.Chart\n\n    cht.SetSourceData Source:=pt.TableRange1\n\n    cht.ChartType = xlRadar\n\n    cht.HasTitle = True\n\n    cht.ChartTitle.Text = \"各部門績效雷達圖\"\n\n    cht.HasLegend = True\n\n    cht.Legend.Position = xlLegendPositionBottom\n\n\n\n    wsPivot.Activate\n\n    MsgBox \"雷達圖已建立完成！\", vbInformation, \"完成\"\n\n    Exit Sub\n\n\n\nErrHandler:\n\n    MsgBox \"建立雷達圖失敗：\" & Err.Description, vbCritical, \"錯誤\"\n\nEnd Sub\n\n\n\nPrivate Sub FillRadarData(ByVal ws As Worksheet)\n\n    ws.Cells.Clear\n\n    ws.Range(\"A1\").Value = \"評估項目\"\n\n    ws.Range(\"B1\").Value = \"部門\"\n\n    ws.Range(\"C1\").Value = \"分數\"\n\n    ws.Range(\"A2\").Value = \"工作效率\"\n\n    ws.Range(\"B2\").Value = \"業務部\"\n\n    ws.Range(\"C2\").Value = 85\n\n    ws.Range(\"A3\").Value = \"團隊合作\"\n\n    ws.Range(\"B3\").Value = \"業務部\"\n\n    ws.Range(\"C3\").Value = 78\n\n    ws.Range(\"A4\").Value = \"創新能力\"\n\n    ws.Range(\"B4\").Value = \"業務部\"\n\n    ws.Range(\"C4\").Value = 72\n\n    ws.Range(\"A5\").Value = \"客戶服務\"\n\n    ws.Range(\"B5\").Value = \"業務部\"\n\n    ws.Range(\"C5\").Value = 91\n\n    ws.Range(\"A6\").Value = \"問題解決\"\n\n    ws.Range(\"B6\").Value = \"業務部\"\n\n    ws.Range(\"C6\").Value = 80\n\n    ws.Range(\"A7\").Value = \"工作效率\"\n\n    ws.Range(\"B7\").Value = \"技術部\"\n\n    ws.Range(\"C7\").Value = 90\n\n    ws.Range(\"A8\").Value = \"團隊合作\"\n\n    ws.Range(\"B8\").Value = \"技術部\"\n\n    ws.Range(\"C8\").Value = 82\n\n    ws.Range(\"A9\").Value = \"創新能力\"\n\n    ws.Range(\"B9\").Value = \"技術部\"\n\n    ws.Range(\"C9\").Value = 95\n\n    ws.Range(\"A10\").Value = \"客戶服務\"\n\n    ws.Range(\"B10\").Value = \"技術部\"\n\n    ws.Range(\"C10\").Value = 70\n\n    ws.Range(\"A11\").Value = \"問題解決\"\n\n    ws.Range(\"B11\").Value = \"技術部\"\n\n    ws.Range(\"C11\").Value = 88\n\n    ws.Columns(\"A:C\").AutoFit\n\nEnd Sub\n\n\n\nPrivate Function RadarGetOrCreateWs(ByVal sheetName As String) As Worksheet\n\n    Dim ws As Worksheet\n\n    On Error Resume Next\n\n    Set ws = ThisWorkbook.Worksheets(sheetName)\n\n    On Error GoTo 0\n\n    If ws Is Nothing Then\n\n        Set ws = ThisWorkbook.Worksheets.Add\n\n        ws.Name = sheetName\n\n    End If\n\n    ws.Cells.Clear\n\n    Set RadarGetOrCreateWs = ws\n\nEnd Function\n\n", "content_b64": ""}, {"name": "PivotStackedBarChartExample.bas", "path": "模組/PivotCharts/PivotStackedBarChartExample.bas", "content": "Attribute VB_Name = \"PivotStackedBarChartExample\"\n\nOption Explicit\n\n'*************************************************************************************\n\n'模組名稱: PivotStackedBarChartExample\n\n'功能說明: 建立樞紐分析堆疊橫條圖，分析各部門費用結構\n\n'\n\n'作者版權所有: Dunk\n\n'程式設計: Dunk\n\n'撰寫日期: 2026/5/9\n\n'\n\n'*************************************************************************************\n\n\n\nSub TestPivotStackedBarChart()\n\n    Call CreatePivotStackedBarChart\n\nEnd Sub\n\n\n\nSub CreatePivotStackedBarChart()\n\n    Dim wsData  As Worksheet\n\n    Dim wsPivot As Worksheet\n\n    Dim pc      As PivotCache\n\n    Dim pt      As PivotTable\n\n    Dim chtObj  As ChartObject\n\n    Dim cht     As Chart\n\n\n\n    On Error GoTo ErrHandler\n\n\n\n    Set wsData  = StkBarGetOrCreateWs(\"部門費用資料\")\n\n    Set wsPivot = StkBarGetOrCreateWs(\"堆疊橫條樞紐\")\n\n\n\n    Call FillStackedBarData(wsData)\n\n\n\n    Set pc = ThisWorkbook.PivotCaches.Create( _\n\n        SourceType:=xlDatabase, _\n\n        SourceData:=wsData.Range(\"A1\").CurrentRegion)\n\n\n\n    Set pt = pc.CreatePivotTable( _\n\n        TableDestination:=wsPivot.Range(\"A3\"), _\n\n        TableName:=\"部門費用樞紐\")\n\n\n\n    With pt\n\n        .PivotFields(\"部門\").Orientation = xlRowField\n\n        .PivotFields(\"部門\").Position = 1\n\n        .PivotFields(\"費用類型\").Orientation = xlColumnField\n\n        .PivotFields(\"費用類型\").Position = 1\n\n        .AddDataField .PivotFields(\"費用金額\"), \"費用合計\", xlSum\n\n        .DataFields(1).NumberFormat = \"#,##0\"\n\n    End With\n\n\n\n    Set chtObj = wsPivot.ChartObjects.Add( _\n\n        Left:=wsPivot.Range(\"F3\").Left, _\n\n        Top:=wsPivot.Range(\"F3\").Top, _\n\n        Width:=450, Height:=300)\n\n\n\n    Set cht = chtObj.Chart\n\n    cht.SetSourceData Source:=pt.TableRange1\n\n    cht.ChartType = xlBarStacked\n\n    cht.HasTitle = True\n\n    cht.ChartTitle.Text = \"各部門費用結構堆疊橫條圖\"\n\n    cht.HasLegend = True\n\n    cht.Legend.Position = xlLegendPositionBottom\n\n\n\n    wsPivot.Activate\n\n    MsgBox \"堆疊橫條圖已建立完成！\", vbInformation, \"完成\"\n\n    Exit Sub\n\n\n\nErrHandler:\n\n    MsgBox \"建立堆疊橫條圖失敗：\" & Err.Description, vbCritical, \"錯誤\"\n\nEnd Sub\n\n\n\nPrivate Sub FillStackedBarData(ByVal ws As Worksheet)\n\n    ws.Cells.Clear\n\n    ws.Range(\"A1\").Value = \"部門\"\n\n    ws.Range(\"B1\").Value = \"費用類型\"\n\n    ws.Range(\"C1\").Value = \"費用金額\"\n\n    ws.Range(\"A2\").Value = \"業務部\"\n\n    ws.Range(\"B2\").Value = \"人事費用\"\n\n    ws.Range(\"C2\").Value = 320000\n\n    ws.Range(\"A3\").Value = \"業務部\"\n\n    ws.Range(\"B3\").Value = \"差旅費用\"\n\n    ws.Range(\"C3\").Value = 85000\n\n    ws.Range(\"A4\").Value = \"業務部\"\n\n    ws.Range(\"B4\").Value = \"行銷費用\"\n\n    ws.Range(\"C4\").Value = 120000\n\n    ws.Range(\"A5\").Value = \"技術部\"\n\n    ws.Range(\"B5\").Value = \"人事費用\"\n\n    ws.Range(\"C5\").Value = 450000\n\n    ws.Range(\"A6\").Value = \"技術部\"\n\n    ws.Range(\"B6\").Value = \"差旅費用\"\n\n    ws.Range(\"C6\").Value = 30000\n\n    ws.Range(\"A7\").Value = \"技術部\"\n\n    ws.Range(\"B7\").Value = \"行銷費用\"\n\n    ws.Range(\"C7\").Value = 20000\n\n    ws.Range(\"A8\").Value = \"管理部\"\n\n    ws.Range(\"B8\").Value = \"人事費用\"\n\n    ws.Range(\"C8\").Value = 280000\n\n    ws.Range(\"A9\").Value = \"管理部\"\n\n    ws.Range(\"B9\").Value = \"差旅費用\"\n\n    ws.Range(\"C9\").Value = 45000\n\n    ws.Range(\"A10\").Value = \"管理部\"\n\n    ws.Range(\"B10\").Value = \"行銷費用\"\n\n    ws.Range(\"C10\").Value = 60000\n\n    ws.Columns(\"A:C\").AutoFit\n\nEnd Sub\n\n\n\nPrivate Function StkBarGetOrCreateWs(ByVal sheetName As String) As Worksheet\n\n    Dim ws As Worksheet\n\n    On Error Resume Next\n\n    Set ws = ThisWorkbook.Worksheets(sheetName)\n\n    On Error GoTo 0\n\n    If ws Is Nothing Then\n\n        Set ws = ThisWorkbook.Worksheets.Add\n\n        ws.Name = sheetName\n\n    End If\n\n    ws.Cells.Clear\n\n    Set StkBarGetOrCreateWs = ws\n\nEnd Function\n\n", "content_b64": ""}, {"name": "PivotStackedColumnChartExample.bas", "path": "模組/PivotCharts/PivotStackedColumnChartExample.bas", "content": "Attribute VB_Name = \"PivotStackedColumnChartExample\"\n\nOption Explicit\n\n'*************************************************************************************\n\n'模組名稱: PivotStackedColumnChartExample\n\n'功能說明: 建立樞紐分析堆疊直條圖，展示各季度產品銷售組成\n\n'\n\n'作者版權所有: Dunk\n\n'程式設計: Dunk\n\n'撰寫日期: 2026/5/9\n\n'\n\n'*************************************************************************************\n\n\n\nSub TestPivotStackedColumnChart()\n\n    Call CreatePivotStackedColumnChart\n\nEnd Sub\n\n\n\nSub CreatePivotStackedColumnChart()\n\n    Dim wsData  As Worksheet\n\n    Dim wsPivot As Worksheet\n\n    Dim pc      As PivotCache\n\n    Dim pt      As PivotTable\n\n    Dim chtObj  As ChartObject\n\n    Dim cht     As Chart\n\n\n\n    On Error GoTo ErrHandler\n\n\n\n    Set wsData  = StkColGetOrCreateWs(\"季度銷售資料\")\n\n    Set wsPivot = StkColGetOrCreateWs(\"堆疊直條樞紐\")\n\n\n\n    Call FillStackedColumnData(wsData)\n\n\n\n    Set pc = ThisWorkbook.PivotCaches.Create( _\n\n        SourceType:=xlDatabase, _\n\n        SourceData:=wsData.Range(\"A1\").CurrentRegion)\n\n\n\n    Set pt = pc.CreatePivotTable( _\n\n        TableDestination:=wsPivot.Range(\"A3\"), _\n\n        TableName:=\"季度銷售樞紐\")\n\n\n\n    With pt\n\n        .PivotFields(\"季度\").Orientation = xlRowField\n\n        .PivotFields(\"季度\").Position = 1\n\n        .PivotFields(\"產品\").Orientation = xlColumnField\n\n        .PivotFields(\"產品\").Position = 1\n\n        .AddDataField .PivotFields(\"銷售額\"), \"銷售額合計\", xlSum\n\n        .DataFields(1).NumberFormat = \"#,##0\"\n\n    End With\n\n\n\n    Set chtObj = wsPivot.ChartObjects.Add( _\n\n        Left:=wsPivot.Range(\"F3\").Left, _\n\n        Top:=wsPivot.Range(\"F3\").Top, _\n\n        Width:=450, Height:=300)\n\n\n\n    Set cht = chtObj.Chart\n\n    cht.SetSourceData Source:=pt.TableRange1\n\n    cht.ChartType = xlColumnStacked\n\n    cht.HasTitle = True\n\n    cht.ChartTitle.Text = \"各季度產品銷售組成堆疊直條圖\"\n\n    cht.HasLegend = True\n\n    cht.Legend.Position = xlLegendPositionBottom\n\n\n\n    wsPivot.Activate\n\n    MsgBox \"堆疊直條圖已建立完成！\", vbInformation, \"完成\"\n\n    Exit Sub\n\n\n\nErrHandler:\n\n    MsgBox \"建立堆疊直條圖失敗：\" & Err.Description, vbCritical, \"錯誤\"\n\nEnd Sub\n\n\n\nPrivate Sub FillStackedColumnData(ByVal ws As Worksheet)\n\n    ws.Cells.Clear\n\n    ws.Range(\"A1\").Value = \"季度\"\n\n    ws.Range(\"B1\").Value = \"產品\"\n\n    ws.Range(\"C1\").Value = \"銷售額\"\n\n    ws.Range(\"A2\").Value = \"Q1\"\n\n    ws.Range(\"B2\").Value = \"產品A\"\n\n    ws.Range(\"C2\").Value = 150000\n\n    ws.Range(\"A3\").Value = \"Q1\"\n\n    ws.Range(\"B3\").Value = \"產品B\"\n\n    ws.Range(\"C3\").Value = 120000\n\n    ws.Range(\"A4\").Value = \"Q1\"\n\n    ws.Range(\"B4\").Value = \"產品C\"\n\n    ws.Range(\"C4\").Value = 90000\n\n    ws.Range(\"A5\").Value = \"Q2\"\n\n    ws.Range(\"B5\").Value = \"產品A\"\n\n    ws.Range(\"C5\").Value = 175000\n\n    ws.Range(\"A6\").Value = \"Q2\"\n\n    ws.Range(\"B6\").Value = \"產品B\"\n\n    ws.Range(\"C6\").Value = 135000\n\n    ws.Range(\"A7\").Value = \"Q2\"\n\n    ws.Range(\"B7\").Value = \"產品C\"\n\n    ws.Range(\"C7\").Value = 105000\n\n    ws.Range(\"A8\").Value = \"Q3\"\n\n    ws.Range(\"B8\").Value = \"產品A\"\n\n    ws.Range(\"C8\").Value = 200000\n\n    ws.Range(\"A9\").Value = \"Q3\"\n\n    ws.Range(\"B9\").Value = \"產品B\"\n\n    ws.Range(\"C9\").Value = 155000\n\n    ws.Range(\"A10\").Value = \"Q3\"\n\n    ws.Range(\"B10\").Value = \"產品C\"\n\n    ws.Range(\"C10\").Value = 120000\n\n    ws.Range(\"A11\").Value = \"Q4\"\n\n    ws.Range(\"B11\").Value = \"產品A\"\n\n    ws.Range(\"C11\").Value = 230000\n\n    ws.Range(\"A12\").Value = \"Q4\"\n\n    ws.Range(\"B12\").Value = \"產品B\"\n\n    ws.Range(\"C12\").Value = 180000\n\n    ws.Range(\"A13\").Value = \"Q4\"\n\n    ws.Range(\"B13\").Value = \"產品C\"\n\n    ws.Range(\"C13\").Value = 145000\n\n    ws.Columns(\"A:C\").AutoFit\n\nEnd Sub\n\n\n\nPrivate Function StkColGetOrCreateWs(ByVal sheetName As String) As Worksheet\n\n    Dim ws As Worksheet\n\n    On Error Resume Next\n\n    Set ws = ThisWorkbook.Worksheets(sheetName)\n\n    On Error GoTo 0\n\n    If ws Is Nothing Then\n\n        Set ws = ThisWorkbook.Worksheets.Add\n\n        ws.Name = sheetName\n\n    End If\n\n    ws.Cells.Clear\n\n    Set StkColGetOrCreateWs = ws\n\nEnd Function\n\n", "content_b64": ""}, {"name": "PivotTop5ChartExample.bas", "path": "模組/PivotCharts/PivotTop5ChartExample.bas", "content": "Attribute VB_Name = \"PivotTop5ChartExample\"\n\nOption Explicit\n\n'*************************************************************************************\n\n'模組名稱: PivotTop5ChartExample\n\n'功能說明: 建立顯示銷售前五名客戶的樞紐分析圖，使用值篩選功能\n\n'\n\n'作者版權所有: Dunk\n\n'程式設計: Dunk\n\n'撰寫日期: 2026/5/9\n\n'\n\n'*************************************************************************************\n\n\n\nSub TestPivotTop5Chart()\n\n    Call CreatePivotTop5Chart\n\nEnd Sub\n\n\n\nSub CreatePivotTop5Chart()\n\n    Dim wsData  As Worksheet\n\n    Dim wsPivot As Worksheet\n\n    Dim pc      As PivotCache\n\n    Dim pt      As PivotTable\n\n    Dim pf      As PivotField\n\n    Dim chtObj  As ChartObject\n\n    Dim cht     As Chart\n\n\n\n    On Error GoTo ErrHandler\n\n\n\n    Set wsData  = Top5GetOrCreateWs(\"客戶銷售資料\")\n\n    Set wsPivot = Top5GetOrCreateWs(\"前五名樞紐\")\n\n\n\n    Call FillTop5Data(wsData)\n\n\n\n    Set pc = ThisWorkbook.PivotCaches.Create( _\n\n        SourceType:=xlDatabase, _\n\n        SourceData:=wsData.Range(\"A1\").CurrentRegion)\n\n\n\n    Set pt = pc.CreatePivotTable( _\n\n        TableDestination:=wsPivot.Range(\"A3\"), _\n\n        TableName:=\"客戶銷售樞紐\")\n\n\n\n    With pt\n\n        Set pf = .PivotFields(\"客戶名稱\")\n\n        pf.Orientation = xlRowField\n\n        pf.Position = 1\n\n        .AddDataField .PivotFields(\"購買金額\"), \"購買金額合計\", xlSum\n\n        .DataFields(1).NumberFormat = \"#,##0\"\n\n    End With\n\n\n\n    '套用前五名值篩選\n\n    pt.PivotFields(\"客戶名稱\").PivotFilters.Add2 _\n\n        Type:=xlTopCount, _\n\n        DataField:=pt.DataFields(1), _\n\n        Value1:=5\n\n\n\n    '依金額降冪排序\n\n    pt.PivotFields(\"客戶名稱\").AutoSort xlDescending, \"購買金額合計\"\n\n\n\n    Set chtObj = wsPivot.ChartObjects.Add( _\n\n        Left:=wsPivot.Range(\"D3\").Left, _\n\n        Top:=wsPivot.Range(\"D3\").Top, _\n\n        Width:=420, Height:=280)\n\n\n\n    Set cht = chtObj.Chart\n\n    cht.SetSourceData Source:=pt.TableRange1\n\n    cht.ChartType = xlBarClustered\n\n    cht.HasTitle = True\n\n    cht.ChartTitle.Text = \"銷售前五名客戶排行圖\"\n\n    cht.HasLegend = False\n\n    cht.SeriesCollection(1).HasDataLabels = True\n\n    cht.SeriesCollection(1).DataLabels.NumberFormat = \"#,##0\"\n\n\n\n    wsPivot.Activate\n\n    MsgBox \"前五名客戶樞紐圖已建立完成！\", vbInformation, \"完成\"\n\n    Exit Sub\n\n\n\nErrHandler:\n\n    MsgBox \"建立前五名樞紐圖失敗：\" & Err.Description, vbCritical, \"錯誤\"\n\nEnd Sub\n\n\n\nPrivate Sub FillTop5Data(ByVal ws As Worksheet)\n\n    ws.Cells.Clear\n\n    ws.Range(\"A1\").Value = \"客戶名稱\"\n\n    ws.Range(\"B1\").Value = \"購買金額\"\n\n    ws.Range(\"A2\").Value = \"台灣科技股份有限公司\"\n\n    ws.Range(\"B2\").Value = 580000\n\n    ws.Range(\"A3\").Value = \"創新電子有限公司\"\n\n    ws.Range(\"B3\").Value = 420000\n\n    ws.Range(\"A4\").Value = \"全球貿易股份有限公司\"\n\n    ws.Range(\"B4\").Value = 750000\n\n    ws.Range(\"A5\").Value = \"信義實業有限公司\"\n\n    ws.Range(\"B5\").Value = 310000\n\n    ws.Range(\"A6\").Value = \"大安科技股份有限公司\"\n\n    ws.Range(\"B6\").Value = 890000\n\n    ws.Range(\"A7\").Value = \"中山商貿有限公司\"\n\n    ws.Range(\"B7\").Value = 225000\n\n    ws.Range(\"A8\").Value = \"松山企業股份有限公司\"\n\n    ws.Range(\"B8\").Value = 640000\n\n    ws.Range(\"A9\").Value = \"內湖科學園區有限公司\"\n\n    ws.Range(\"B9\").Value = 480000\n\n    ws.Range(\"A10\").Value = \"南港電子股份有限公司\"\n\n    ws.Range(\"B10\").Value = 390000\n\n    ws.Range(\"A11\").Value = \"士林國際有限公司\"\n\n    ws.Range(\"B11\").Value = 175000\n\n    ws.Columns(\"A:B\").AutoFit\n\nEnd Sub\n\n\n\nPrivate Function Top5GetOrCreateWs(ByVal sheetName As String) As Worksheet\n\n    Dim ws As Worksheet\n\n    On Error Resume Next\n\n    Set ws = ThisWorkbook.Worksheets(sheetName)\n\n    On Error GoTo 0\n\n    If ws Is Nothing Then\n\n        Set ws = ThisWorkbook.Worksheets.Add\n\n        ws.Name = sheetName\n\n    End If\n\n    ws.Cells.Clear\n\n    Set Top5GetOrCreateWs = ws\n\nEnd Function\n\n", "content_b64": ""}]}, {"folder": "PivotTableAnalysis", "path": "模組/PivotTableAnalysis", "files": [{"name": "BasicPivotTable.bas", "path": "模組/PivotTableAnalysis/BasicPivotTable.bas", "content": "Attribute VB_Name = \"BasicPivotTable\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: BasicPivotTable\n'功能說明: 建立基本樞紐分析表（地區 X 產品，加總銷售額）\n'\n'版權所有: Dunk\n'程式設計: Dunk\n'撰寫日期: 2026/5/3\n'\n'*************************************************************************************\n\n' 測試入口\nSub TestBasicPivotTable()\n    Call CreateBasicPivotTable\nEnd Sub\n\n' 建立基本樞紐分析表\n' 列欄位: 地區 / 欄欄位: 產品 / 值: 銷售額加總\nSub CreateBasicPivotTable()\n    Dim wsData As Worksheet\n    Dim wsPivot As Worksheet\n    Dim pc As PivotCache\n    Dim pt As PivotTable\n    Dim dataRange As Range\n\n    ' 準備資料工作表\n    Set wsData = GetOrCreateSheet(ThisWorkbook, \"銷售資料\")\n    Call FillSalesData(wsData)\n\n    ' 準備樞紐工作表\n    Set wsPivot = GetOrCreateSheet(ThisWorkbook, \"基本樞紐\")\n\n    ' 取得資料範圍\n    Set dataRange = wsData.Range(\"A1\").CurrentRegion\n\n    ' 建立 PivotCache\n    Set pc = ThisWorkbook.PivotCaches.Create( _\n        SourceType:=xlDatabase, _\n        SourceData:=dataRange)\n\n    ' 建立樞紐分析表\n    Set pt = pc.CreatePivotTable( _\n        TableDestination:=wsPivot.Range(\"A3\"), _\n        TableName:=\"基本樞紐分析表\")\n\n    ' 設定列欄位：地區\n    With pt.PivotFields(\"地區\")\n        .Orientation = xlRowField\n        .Position = 1\n    End With\n\n    ' 設定欄欄位：產品\n    With pt.PivotFields(\"產品\")\n        .Orientation = xlColumnField\n        .Position = 1\n    End With\n\n    ' 設定值欄位：銷售額（加總）\n    pt.AddDataField pt.PivotFields(\"銷售額\"), \"銷售額加總\", xlSum\n\n    wsPivot.Activate\n    MsgBox \"基本樞紐分析表已建立完成！\", vbInformation, \"完成\"\nEnd Sub\n\n' 填入範例銷售資料（共 8 筆：日期、地區、產品、數量、單價、銷售額）\nPrivate Sub FillSalesData(ByVal ws As Worksheet)\n    ws.Range(\"A1\").Value = \"日期\"\n    ws.Range(\"B1\").Value = \"地區\"\n    ws.Range(\"C1\").Value = \"產品\"\n    ws.Range(\"D1\").Value = \"數量\"\n    ws.Range(\"E1\").Value = \"單價\"\n    ws.Range(\"F1\").Value = \"銷售額\"\n\n    ws.Range(\"A2\").Value = DateSerial(2026, 1, 5)\n    ws.Range(\"B2\").Value = \"北部\"\n    ws.Range(\"C2\").Value = \"產品A\"\n    ws.Range(\"D2\").Value = 100\n    ws.Range(\"E2\").Value = 50\n    ws.Range(\"F2\").Value = 5000\n\n    ws.Range(\"A3\").Value = DateSerial(2026, 1, 10)\n    ws.Range(\"B3\").Value = \"南部\"\n    ws.Range(\"C3\").Value = \"產品B\"\n    ws.Range(\"D3\").Value = 80\n    ws.Range(\"E3\").Value = 75\n    ws.Range(\"F3\").Value = 6000\n\n    ws.Range(\"A4\").Value = DateSerial(2026, 2, 5)\n    ws.Range(\"B4\").Value = \"北部\"\n    ws.Range(\"C4\").Value = \"產品B\"\n    ws.Range(\"D4\").Value = 60\n    ws.Range(\"E4\").Value = 75\n    ws.Range(\"F4\").Value = 4500\n\n    ws.Range(\"A5\").Value = DateSerial(2026, 2, 15)\n    ws.Range(\"B5\").Value = \"中部\"\n    ws.Range(\"C5\").Value = \"產品A\"\n    ws.Range(\"D5\").Value = 120\n    ws.Range(\"E5\").Value = 50\n    ws.Range(\"F5\").Value = 6000\n\n    ws.Range(\"A6\").Value = DateSerial(2026, 3, 1)\n    ws.Range(\"B6\").Value = \"南部\"\n    ws.Range(\"C6\").Value = \"產品A\"\n    ws.Range(\"D6\").Value = 90\n    ws.Range(\"E6\").Value = 50\n    ws.Range(\"F6\").Value = 4500\n\n    ws.Range(\"A7\").Value = DateSerial(2026, 3, 20)\n    ws.Range(\"B7\").Value = \"中部\"\n    ws.Range(\"C7\").Value = \"產品B\"\n    ws.Range(\"D7\").Value = 150\n    ws.Range(\"E7\").Value = 75\n    ws.Range(\"F7\").Value = 11250\n\n    ws.Range(\"A8\").Value = DateSerial(2026, 4, 5)\n    ws.Range(\"B8\").Value = \"北部\"\n    ws.Range(\"C8\").Value = \"產品A\"\n    ws.Range(\"D8\").Value = 200\n    ws.Range(\"E8\").Value = 50\n    ws.Range(\"F8\").Value = 10000\n\n    ws.Range(\"A9\").Value = DateSerial(2026, 4, 18)\n    ws.Range(\"B9\").Value = \"南部\"\n    ws.Range(\"C9\").Value = \"產品B\"\n    ws.Range(\"D9\").Value = 110\n    ws.Range(\"E9\").Value = 75\n    ws.Range(\"F9\").Value = 8250\n\n    ws.Columns(\"A\").NumberFormat = \"yyyy/m/d\"\n    ws.Columns(\"A:F\").AutoFit\nEnd Sub\n\n' 取得或建立工作表，並清除內容\nPrivate Function GetOrCreateSheet(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add\n        ws.Name = sheetName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreateSheet = ws\nEnd Function\n", "content_b64": ""}, {"name": "CalculatedFieldPivot.bas", "path": "模組/PivotTableAnalysis/CalculatedFieldPivot.bas", "content": "Attribute VB_Name = \"CalculatedFieldPivot\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: CalculatedFieldPivot\n'功能說明: 樞紐分析表計算欄位（自訂公式：平均單價 = 銷售額 / 數量）\n'\n'版權所有: Dunk\n'程式設計: Dunk\n'撰寫日期: 2026/5/3\n'\n'*************************************************************************************\n\n' 測試入口\nSub TestCalculatedFieldPivot()\n    Call CreateCalculatedFieldPivot\nEnd Sub\n\n' 建立含計算欄位的樞紐分析表\n' 計算欄位公式：平均單價 = 銷售額 / 數量\nSub CreateCalculatedFieldPivot()\n    Dim wsData As Worksheet\n    Dim wsPivot As Worksheet\n    Dim pc As PivotCache\n    Dim pt As PivotTable\n    Dim dataRange As Range\n\n    ' 準備工作表\n    Set wsData = GetOrCreateSheet(ThisWorkbook, \"銷售資料\")\n    Call FillSalesData(wsData)\n    Set wsPivot = GetOrCreateSheet(ThisWorkbook, \"計算欄位樞紐\")\n\n    Set dataRange = wsData.Range(\"A1\").CurrentRegion\n\n    Set pc = ThisWorkbook.PivotCaches.Create( _\n        SourceType:=xlDatabase, _\n        SourceData:=dataRange)\n    Set pt = pc.CreatePivotTable( _\n        TableDestination:=wsPivot.Range(\"A3\"), _\n        TableName:=\"計算欄位樞紐分析表\")\n\n    ' 列欄位：地區\n    With pt.PivotFields(\"地區\")\n        .Orientation = xlRowField\n        .Position = 1\n    End With\n\n    ' 欄欄位：產品\n    With pt.PivotFields(\"產品\")\n        .Orientation = xlColumnField\n        .Position = 1\n    End With\n\n    ' 值欄位：銷售額加總\n    pt.AddDataField pt.PivotFields(\"銷售額\"), \"銷售額加總\", xlSum\n\n    ' 值欄位：數量加總\n    pt.AddDataField pt.PivotFields(\"數量\"), \"數量加總\", xlSum\n\n    ' 新增計算欄位：平均單價 = 銷售額 / 數量\n    On Error Resume Next\n    pt.CalculatedFields.Add \"平均單價\", \"=銷售額/數量\"\n    On Error GoTo 0\n\n    ' 將計算欄位加入為資料欄位\n    On Error Resume Next\n    Dim pfCalc As PivotField\n    Set pfCalc = pt.PivotFields(\"平均單價\")\n    If Not pfCalc Is Nothing Then\n        pfCalc.Orientation = xlDataField\n        pfCalc.Name = \"平均單價計算\"\n        pfCalc.NumberFormat = \"#,##0.00\"\n    End If\n    On Error GoTo 0\n\n    wsPivot.Activate\n    MsgBox \"計算欄位樞紐分析表已建立完成！（含平均單價 = 銷售額 / 數量）\", vbInformation, \"完成\"\nEnd Sub\n\n' 填入範例銷售資料（共 8 筆：日期、地區、產品、數量、單價、銷售額）\nPrivate Sub FillSalesData(ByVal ws As Worksheet)\n    ws.Range(\"A1\").Value = \"日期\"\n    ws.Range(\"B1\").Value = \"地區\"\n    ws.Range(\"C1\").Value = \"產品\"\n    ws.Range(\"D1\").Value = \"數量\"\n    ws.Range(\"E1\").Value = \"單價\"\n    ws.Range(\"F1\").Value = \"銷售額\"\n\n    ws.Range(\"A2\").Value = DateSerial(2026, 1, 5)\n    ws.Range(\"B2\").Value = \"北部\"\n    ws.Range(\"C2\").Value = \"產品A\"\n    ws.Range(\"D2\").Value = 100\n    ws.Range(\"E2\").Value = 50\n    ws.Range(\"F2\").Value = 5000\n\n    ws.Range(\"A3\").Value = DateSerial(2026, 1, 10)\n    ws.Range(\"B3\").Value = \"南部\"\n    ws.Range(\"C3\").Value = \"產品B\"\n    ws.Range(\"D3\").Value = 80\n    ws.Range(\"E3\").Value = 75\n    ws.Range(\"F3\").Value = 6000\n\n    ws.Range(\"A4\").Value = DateSerial(2026, 2, 5)\n    ws.Range(\"B4\").Value = \"北部\"\n    ws.Range(\"C4\").Value = \"產品B\"\n    ws.Range(\"D4\").Value = 60\n    ws.Range(\"E4\").Value = 75\n    ws.Range(\"F4\").Value = 4500\n\n    ws.Range(\"A5\").Value = DateSerial(2026, 2, 15)\n    ws.Range(\"B5\").Value = \"中部\"\n    ws.Range(\"C5\").Value = \"產品A\"\n    ws.Range(\"D5\").Value = 120\n    ws.Range(\"E5\").Value = 50\n    ws.Range(\"F5\").Value = 6000\n\n    ws.Range(\"A6\").Value = DateSerial(2026, 3, 1)\n    ws.Range(\"B6\").Value = \"南部\"\n    ws.Range(\"C6\").Value = \"產品A\"\n    ws.Range(\"D6\").Value = 90\n    ws.Range(\"E6\").Value = 50\n    ws.Range(\"F6\").Value = 4500\n\n    ws.Range(\"A7\").Value = DateSerial(2026, 3, 20)\n    ws.Range(\"B7\").Value = \"中部\"\n    ws.Range(\"C7\").Value = \"產品B\"\n    ws.Range(\"D7\").Value = 150\n    ws.Range(\"E7\").Value = 75\n    ws.Range(\"F7\").Value = 11250\n\n    ws.Range(\"A8\").Value = DateSerial(2026, 4, 5)\n    ws.Range(\"B8\").Value = \"北部\"\n    ws.Range(\"C8\").Value = \"產品A\"\n    ws.Range(\"D8\").Value = 200\n    ws.Range(\"E8\").Value = 50\n    ws.Range(\"F8\").Value = 10000\n\n    ws.Range(\"A9\").Value = DateSerial(2026, 4, 18)\n    ws.Range(\"B9\").Value = \"南部\"\n    ws.Range(\"C9\").Value = \"產品B\"\n    ws.Range(\"D9\").Value = 110\n    ws.Range(\"E9\").Value = 75\n    ws.Range(\"F9\").Value = 8250\n\n    ws.Columns(\"A\").NumberFormat = \"yyyy/m/d\"\n    ws.Columns(\"A:F\").AutoFit\nEnd Sub\n\n' 取得或建立工作表，並清除內容\nPrivate Function GetOrCreateSheet(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add\n        ws.Name = sheetName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreateSheet = ws\nEnd Function\n", "content_b64": ""}, {"name": "ConditionalFormatPivot.bas", "path": "模組/PivotTableAnalysis/ConditionalFormatPivot.bas", "content": "Attribute VB_Name = \"ConditionalFormatPivot\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: ConditionalFormatPivot\n'功能說明: 在樞紐分析表的值區域套用條件式格式（資料橫條），\n'          以視覺化方式呈現銷售額的大小比較\n'\n'版權所有: Dunk\n'程式設計: Dunk\n'撰寫日期: 2026/5/4\n'\n'*************************************************************************************\n\n' 測試入口\nSub TestConditionalFormatPivot()\n    Call CreateConditionalFormatPivot\nEnd Sub\n\n' 建立含條件式格式的樞紐分析表\n' 功能: 在值區域套用資料橫條，突顯高低銷售額\nSub CreateConditionalFormatPivot()\n    Dim wsData   As Worksheet\n    Dim wsPivot  As Worksheet\n    Dim pc       As PivotCache\n    Dim pt       As PivotTable\n    Dim dataRange As Range\n    Dim ptRange  As Range\n\n    ' 準備資料工作表\n    Set wsData = GetOrCreateSheet(ThisWorkbook, \"銷售資料\")\n    Call FillSalesData(wsData)\n\n    ' 準備樞紐工作表\n    Set wsPivot = GetOrCreateSheet(ThisWorkbook, \"條件格式樞紐\")\n\n    Set dataRange = wsData.Range(\"A1\").CurrentRegion\n\n    ' 建立 PivotCache 與樞紐分析表\n    Set pc = ThisWorkbook.PivotCaches.Create( _\n        SourceType:=xlDatabase, _\n        SourceData:=dataRange)\n    Set pt = pc.CreatePivotTable( _\n        TableDestination:=wsPivot.Range(\"A3\"), _\n        TableName:=\"條件格式樞紐\")\n\n    ' 列欄位: 地區\n    With pt.PivotFields(\"地區\")\n        .Orientation = xlRowField\n        .Position = 1\n    End With\n\n    ' 欄欄位: 產品\n    With pt.PivotFields(\"產品\")\n        .Orientation = xlColumnField\n        .Position = 1\n    End With\n\n    ' 值欄位: 銷售額加總\n    pt.AddDataField pt.PivotFields(\"銷售額\"), \"銷售額加總\", xlSum\n\n    ' 取得值區域並套用資料橫條條件式格式\n    Set ptRange = pt.DataBodyRange\n    If Not ptRange Is Nothing Then\n        ptRange.FormatConditions.Delete\n        ptRange.FormatConditions.AddDatabar\n        With ptRange.FormatConditions(1)\n            .BarColor.Color = RGB(99, 142, 198)\n            .BarFillType = xlDataBarFillSolid\n            .ShowValue = True\n        End With\n    End If\n\n    wsPivot.Activate\n    MsgBox \"含條件式格式的樞紐分析表已建立完成！\" & Chr(13) & _\n           \"值區域已套用資料橫條以視覺化比較銷售額。\", _\n           vbInformation, \"完成\"\nEnd Sub\n\n' 填入範例銷售資料（8筆：日期、地區、產品、數量、單價、銷售額）\nPrivate Sub FillSalesData(ByVal ws As Worksheet)\n    ws.Range(\"A1\").Value = \"日期\"\n    ws.Range(\"B1\").Value = \"地區\"\n    ws.Range(\"C1\").Value = \"產品\"\n    ws.Range(\"D1\").Value = \"數量\"\n    ws.Range(\"E1\").Value = \"單價\"\n    ws.Range(\"F1\").Value = \"銷售額\"\n\n    ws.Range(\"A2\").Value = DateSerial(2026, 1, 5)\n    ws.Range(\"B2\").Value = \"北區\"\n    ws.Range(\"C2\").Value = \"產品A\"\n    ws.Range(\"D2\").Value = 100\n    ws.Range(\"E2\").Value = 50\n    ws.Range(\"F2\").Value = 5000\n\n    ws.Range(\"A3\").Value = DateSerial(2026, 1, 10)\n    ws.Range(\"B3\").Value = \"南區\"\n    ws.Range(\"C3\").Value = \"產品B\"\n    ws.Range(\"D3\").Value = 80\n    ws.Range(\"E3\").Value = 75\n    ws.Range(\"F3\").Value = 6000\n\n    ws.Range(\"A4\").Value = DateSerial(2026, 2, 5)\n    ws.Range(\"B4\").Value = \"北區\"\n    ws.Range(\"C4\").Value = \"產品B\"\n    ws.Range(\"D4\").Value = 60\n    ws.Range(\"E4\").Value = 75\n    ws.Range(\"F4\").Value = 4500\n\n    ws.Range(\"A5\").Value = DateSerial(2026, 2, 15)\n    ws.Range(\"B5\").Value = \"中區\"\n    ws.Range(\"C5\").Value = \"產品A\"\n    ws.Range(\"D5\").Value = 120\n    ws.Range(\"E5\").Value = 50\n    ws.Range(\"F5\").Value = 6000\n\n    ws.Range(\"A6\").Value = DateSerial(2026, 3, 1)\n    ws.Range(\"B6\").Value = \"南區\"\n    ws.Range(\"C6\").Value = \"產品A\"\n    ws.Range(\"D6\").Value = 90\n    ws.Range(\"E6\").Value = 50\n    ws.Range(\"F6\").Value = 4500\n\n    ws.Range(\"A7\").Value = DateSerial(2026, 3, 20)\n    ws.Range(\"B7\").Value = \"中區\"\n    ws.Range(\"C7\").Value = \"產品B\"\n    ws.Range(\"D7\").Value = 150\n    ws.Range(\"E7\").Value = 75\n    ws.Range(\"F7\").Value = 11250\n\n    ws.Range(\"A8\").Value = DateSerial(2026, 4, 5)\n    ws.Range(\"B8\").Value = \"北區\"\n    ws.Range(\"C8\").Value = \"產品A\"\n    ws.Range(\"D8\").Value = 200\n    ws.Range(\"E8\").Value = 50\n    ws.Range(\"F8\").Value = 10000\n\n    ws.Range(\"A9\").Value = DateSerial(2026, 4, 18)\n    ws.Range(\"B9\").Value = \"南區\"\n    ws.Range(\"C9\").Value = \"產品B\"\n    ws.Range(\"D9\").Value = 110\n    ws.Range(\"E9\").Value = 75\n    ws.Range(\"F9\").Value = 8250\n\n    ws.Columns(\"A\").NumberFormat = \"yyyy/m/d\"\n    ws.Columns(\"A:F\").AutoFit\nEnd Sub\n\n' 取得或建立工作表，並清除現有內容\nPrivate Function GetOrCreateSheet(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add\n        ws.Name = sheetName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreateSheet = ws\nEnd Function\n", "content_b64": ""}, {"name": "CopyPivotAsValues.bas", "path": "模組/PivotTableAnalysis/CopyPivotAsValues.bas", "content": "Attribute VB_Name = \"CopyPivotAsValues\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: CopyPivotAsValues\n'功能說明: 將樞紐分析表結果複製為純值到新工作表，\n'          避免樞紐分析表連結，方便獨立使用或列印\n'\n'版權所有: Dunk\n'程式設計: Dunk\n'撰寫日期: 2026/5/4\n'\n'*************************************************************************************\n\n' 測試入口\nSub TestCopyPivotAsValues()\n    Call CreateAndCopyPivotAsValues\nEnd Sub\n\n' 建立樞紐分析表並將結果複製為純值到新工作表\nSub CreateAndCopyPivotAsValues()\n    Dim wsData      As Worksheet\n    Dim wsPivot     As Worksheet\n    Dim wsCopy      As Worksheet\n    Dim pc          As PivotCache\n    Dim pt          As PivotTable\n    Dim dataRange   As Range\n    Dim ptFullRange As Range\n\n    ' 準備資料工作表\n    Set wsData = GetOrCreateSheet(ThisWorkbook, \"銷售資料\")\n    Call FillSalesData(wsData)\n\n    ' 準備樞紐工作表\n    Set wsPivot = GetOrCreateSheet(ThisWorkbook, \"原始樞紐\")\n\n    Set dataRange = wsData.Range(\"A1\").CurrentRegion\n\n    Set pc = ThisWorkbook.PivotCaches.Create( _\n        SourceType:=xlDatabase, _\n        SourceData:=dataRange)\n    Set pt = pc.CreatePivotTable( _\n        TableDestination:=wsPivot.Range(\"A3\"), _\n        TableName:=\"複製來源樞紐\")\n\n    ' 列欄位: 地區\n    With pt.PivotFields(\"地區\")\n        .Orientation = xlRowField\n        .Position = 1\n    End With\n\n    ' 欄欄位: 產品\n    With pt.PivotFields(\"產品\")\n        .Orientation = xlColumnField\n        .Position = 1\n    End With\n\n    ' 值欄位: 銷售額加總\n    pt.AddDataField pt.PivotFields(\"銷售額\"), \"銷售額加總\", xlSum\n    ' 值欄位: 數量加總\n    pt.AddDataField pt.PivotFields(\"數量\"), \"數量加總\", xlSum\n\n    ' 複製樞紐完整範圍\n    Set ptFullRange = pt.TableRange2\n    ptFullRange.Copy\n\n    ' 準備目標工作表（純值）\n    Set wsCopy = GetOrCreateSheet(ThisWorkbook, \"純值結果\")\n    wsCopy.Range(\"A1\").PasteSpecial Paste:=xlPasteValues\n    wsCopy.Range(\"A1\").PasteSpecial Paste:=xlPasteFormats\n    Application.CutCopyMode = False\n\n    ' 自動調整欄寬\n    wsCopy.Columns.AutoFit\n\n    wsCopy.Activate\n    MsgBox \"樞紐分析表已複製為純值到「純值結果」工作表！\" & Chr(13) & _\n           \"此工作表無樞紐連結，可獨立編輯或列印。\", _\n           vbInformation, \"完成\"\nEnd Sub\n\n' 填入範例銷售資料（8筆：日期、地區、產品、數量、單價、銷售額）\nPrivate Sub FillSalesData(ByVal ws As Worksheet)\n    ws.Range(\"A1\").Value = \"日期\"\n    ws.Range(\"B1\").Value = \"地區\"\n    ws.Range(\"C1\").Value = \"產品\"\n    ws.Range(\"D1\").Value = \"數量\"\n    ws.Range(\"E1\").Value = \"單價\"\n    ws.Range(\"F1\").Value = \"銷售額\"\n\n    ws.Range(\"A2\").Value = DateSerial(2026, 1, 5)\n    ws.Range(\"B2\").Value = \"北區\"\n    ws.Range(\"C2\").Value = \"產品A\"\n    ws.Range(\"D2\").Value = 100\n    ws.Range(\"E2\").Value = 50\n    ws.Range(\"F2\").Value = 5000\n\n    ws.Range(\"A3\").Value = DateSerial(2026, 1, 10)\n    ws.Range(\"B3\").Value = \"南區\"\n    ws.Range(\"C3\").Value = \"產品B\"\n    ws.Range(\"D3\").Value = 80\n    ws.Range(\"E3\").Value = 75\n    ws.Range(\"F3\").Value = 6000\n\n    ws.Range(\"A4\").Value = DateSerial(2026, 2, 5)\n    ws.Range(\"B4\").Value = \"北區\"\n    ws.Range(\"C4\").Value = \"產品B\"\n    ws.Range(\"D4\").Value = 60\n    ws.Range(\"E4\").Value = 75\n    ws.Range(\"F4\").Value = 4500\n\n    ws.Range(\"A5\").Value = DateSerial(2026, 2, 15)\n    ws.Range(\"B5\").Value = \"中區\"\n    ws.Range(\"C5\").Value = \"產品A\"\n    ws.Range(\"D5\").Value = 120\n    ws.Range(\"E5\").Value = 50\n    ws.Range(\"F5\").Value = 6000\n\n    ws.Range(\"A6\").Value = DateSerial(2026, 3, 1)\n    ws.Range(\"B6\").Value = \"南區\"\n    ws.Range(\"C6\").Value = \"產品A\"\n    ws.Range(\"D6\").Value = 90\n    ws.Range(\"E6\").Value = 50\n    ws.Range(\"F6\").Value = 4500\n\n    ws.Range(\"A7\").Value = DateSerial(2026, 3, 20)\n    ws.Range(\"B7\").Value = \"中區\"\n    ws.Range(\"C7\").Value = \"產品B\"\n    ws.Range(\"D7\").Value = 150\n    ws.Range(\"E7\").Value = 75\n    ws.Range(\"F7\").Value = 11250\n\n    ws.Range(\"A8\").Value = DateSerial(2026, 4, 5)\n    ws.Range(\"B8\").Value = \"北區\"\n    ws.Range(\"C8\").Value = \"產品A\"\n    ws.Range(\"D8\").Value = 200\n    ws.Range(\"E8\").Value = 50\n    ws.Range(\"F8\").Value = 10000\n\n    ws.Range(\"A9\").Value = DateSerial(2026, 4, 18)\n    ws.Range(\"B9\").Value = \"南區\"\n    ws.Range(\"C9\").Value = \"產品B\"\n    ws.Range(\"D9\").Value = 110\n    ws.Range(\"E9\").Value = 75\n    ws.Range(\"F9\").Value = 8250\n\n    ws.Columns(\"A\").NumberFormat = \"yyyy/m/d\"\n    ws.Columns(\"A:F\").AutoFit\nEnd Sub\n\n' 取得或建立工作表，並清除現有內容\nPrivate Function GetOrCreateSheet(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add\n        ws.Name = sheetName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreateSheet = ws\nEnd Function\n", "content_b64": ""}, {"name": "DateGroupPivotTable.bas", "path": "模組/PivotTableAnalysis/DateGroupPivotTable.bas", "content": "Attribute VB_Name = \"DateGroupPivotTable\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: DateGroupPivotTable\n'功能說明: 樞紐分析表日期群組（依月份與年份分組）\n'\n'版權所有: Dunk\n'程式設計: Dunk\n'撰寫日期: 2026/5/3\n'\n'*************************************************************************************\n\n' 測試入口\nSub TestDateGroupPivotTable()\n    Call CreateDateGroupPivotTable\nEnd Sub\n\n' 建立日期群組樞紐分析表\n' 將日期欄位依年份與月份分組，觀察各月銷售趨勢\nSub CreateDateGroupPivotTable()\n    Dim wsData As Worksheet\n    Dim wsPivot As Worksheet\n    Dim pc As PivotCache\n    Dim pt As PivotTable\n    Dim dataRange As Range\n\n    ' 準備工作表\n    Set wsData = GetOrCreateSheet(ThisWorkbook, \"銷售資料\")\n    Call FillSalesData(wsData)\n    Set wsPivot = GetOrCreateSheet(ThisWorkbook, \"日期群組樞紐\")\n\n    Set dataRange = wsData.Range(\"A1\").CurrentRegion\n\n    Set pc = ThisWorkbook.PivotCaches.Create( _\n        SourceType:=xlDatabase, _\n        SourceData:=dataRange)\n    Set pt = pc.CreatePivotTable( _\n        TableDestination:=wsPivot.Range(\"A3\"), _\n        TableName:=\"日期群組樞紐分析表\")\n\n    ' 列欄位：日期\n    With pt.PivotFields(\"日期\")\n        .Orientation = xlRowField\n        .Position = 1\n    End With\n\n    ' 欄欄位：地區\n    With pt.PivotFields(\"地區\")\n        .Orientation = xlColumnField\n        .Position = 1\n    End With\n\n    ' 值欄位：銷售額\n    pt.AddDataField pt.PivotFields(\"銷售額\"), \"銷售額加總\", xlSum\n\n    ' 對日期欄位進行分組（月份 + 年份）\n    ' Periods 陣列：Seconds, Minutes, Hours, Days, Months, Quarters, Years\n    On Error Resume Next\n    pt.PivotFields(\"日期\").DataRange.Group _\n        Start:=True, End:=True, _\n        Periods:=Array(False, False, False, False, True, False, True)\n    On Error GoTo 0\n\n    wsPivot.Activate\n    MsgBox \"日期群組樞紐分析表已建立完成！（依年份與月份分組）\", vbInformation, \"完成\"\nEnd Sub\n\n' 填入範例銷售資料（共 8 筆：日期、地區、產品、數量、單價、銷售額）\nPrivate Sub FillSalesData(ByVal ws As Worksheet)\n    ws.Range(\"A1\").Value = \"日期\"\n    ws.Range(\"B1\").Value = \"地區\"\n    ws.Range(\"C1\").Value = \"產品\"\n    ws.Range(\"D1\").Value = \"數量\"\n    ws.Range(\"E1\").Value = \"單價\"\n    ws.Range(\"F1\").Value = \"銷售額\"\n\n    ws.Range(\"A2\").Value = DateSerial(2026, 1, 5)\n    ws.Range(\"B2\").Value = \"北部\"\n    ws.Range(\"C2\").Value = \"產品A\"\n    ws.Range(\"D2\").Value = 100\n    ws.Range(\"E2\").Value = 50\n    ws.Range(\"F2\").Value = 5000\n\n    ws.Range(\"A3\").Value = DateSerial(2026, 1, 10)\n    ws.Range(\"B3\").Value = \"南部\"\n    ws.Range(\"C3\").Value = \"產品B\"\n    ws.Range(\"D3\").Value = 80\n    ws.Range(\"E3\").Value = 75\n    ws.Range(\"F3\").Value = 6000\n\n    ws.Range(\"A4\").Value = DateSerial(2026, 2, 5)\n    ws.Range(\"B4\").Value = \"北部\"\n    ws.Range(\"C4\").Value = \"產品B\"\n    ws.Range(\"D4\").Value = 60\n    ws.Range(\"E4\").Value = 75\n    ws.Range(\"F4\").Value = 4500\n\n    ws.Range(\"A5\").Value = DateSerial(2026, 2, 15)\n    ws.Range(\"B5\").Value = \"中部\"\n    ws.Range(\"C5\").Value = \"產品A\"\n    ws.Range(\"D5\").Value = 120\n    ws.Range(\"E5\").Value = 50\n    ws.Range(\"F5\").Value = 6000\n\n    ws.Range(\"A6\").Value = DateSerial(2026, 3, 1)\n    ws.Range(\"B6\").Value = \"南部\"\n    ws.Range(\"C6\").Value = \"產品A\"\n    ws.Range(\"D6\").Value = 90\n    ws.Range(\"E6\").Value = 50\n    ws.Range(\"F6\").Value = 4500\n\n    ws.Range(\"A7\").Value = DateSerial(2026, 3, 20)\n    ws.Range(\"B7\").Value = \"中部\"\n    ws.Range(\"C7\").Value = \"產品B\"\n    ws.Range(\"D7\").Value = 150\n    ws.Range(\"E7\").Value = 75\n    ws.Range(\"F7\").Value = 11250\n\n    ws.Range(\"A8\").Value = DateSerial(2026, 4, 5)\n    ws.Range(\"B8\").Value = \"北部\"\n    ws.Range(\"C8\").Value = \"產品A\"\n    ws.Range(\"D8\").Value = 200\n    ws.Range(\"E8\").Value = 50\n    ws.Range(\"F8\").Value = 10000\n\n    ws.Range(\"A9\").Value = DateSerial(2026, 4, 18)\n    ws.Range(\"B9\").Value = \"南部\"\n    ws.Range(\"C9\").Value = \"產品B\"\n    ws.Range(\"D9\").Value = 110\n    ws.Range(\"E9\").Value = 75\n    ws.Range(\"F9\").Value = 8250\n\n    ws.Columns(\"A\").NumberFormat = \"yyyy/m/d\"\n    ws.Columns(\"A:F\").AutoFit\nEnd Sub\n\n' 取得或建立工作表，並清除內容\nPrivate Function GetOrCreateSheet(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add\n        ws.Name = sheetName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreateSheet = ws\nEnd Function\n", "content_b64": ""}, {"name": "DeferUpdatePivot.bas", "path": "模組/PivotTableAnalysis/DeferUpdatePivot.bas", "content": "Attribute VB_Name = \"DeferUpdatePivot\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: DeferUpdatePivot\n'功能說明: 延遲版面配置更新模式示範（ManualUpdate）\n'          在大量欄位操作時，先關閉自動更新以提升效能\n'          完成所有欄位設定後再統一刷新樞紐分析表\n'\n'版權所有: Dunk\n'程式設計: Dunk\n'撰寫日期: 2026/5/6\n'\n'*************************************************************************************\n\n' 程式進入點\nSub TestDeferUpdatePivot()\n    Call CreateDeferUpdatePivot\nEnd Sub\n\n' 建立樞紐分析表並示範 ManualUpdate 延遲更新模式\nSub CreateDeferUpdatePivot()\n    Dim wsData As Worksheet\n    Dim wsPivot As Worksheet\n    Dim pc As PivotCache\n    Dim pt As PivotTable\n    Dim dataRange As Range\n    Dim startTime As Double\n    Dim endTime As Double\n\n    Set wsData = GetOrCreateSheet(ThisWorkbook, \"大量欄位資料\")\n    Call FillLargeFieldData(wsData)\n    Set wsPivot = GetOrCreateSheet(ThisWorkbook, \"延遲更新樞紐\")\n\n    Set dataRange = wsData.Range(\"A1\").CurrentRegion\n\n    Set pc = ThisWorkbook.PivotCaches.Create( _\n        SourceType:=xlDatabase, _\n        SourceData:=dataRange)\n    Set pt = pc.CreatePivotTable( _\n        TableDestination:=wsPivot.Range(\"A3\"), _\n        TableName:=\"延遲更新樞紐分析表\")\n\n    startTime = Timer\n\n    ' ── 開啟延遲更新模式（ManualUpdate = True）──\n    ' 此後所有欄位設定均不觸發重算，直到 ManualUpdate = False\n    pt.ManualUpdate = True\n\n    ' 批次設定多個欄位（不觸發重算）\n    With pt.PivotFields(\"部門\")\n        .Orientation = xlRowField\n        .Position = 1\n    End With\n\n    With pt.PivotFields(\"月份\")\n        .Orientation = xlColumnField\n        .Position = 1\n    End With\n\n    pt.AddDataField pt.PivotFields(\"薪資\"), \"薪資合計\", xlSum\n    pt.AddDataField pt.PivotFields(\"獎金\"), \"獎金合計\", xlSum\n\n    pt.RowAxisLayout xlTabularRow\n    pt.TableStyle2 = \"PivotStyleMedium4\"\n\n    ' ── 關閉延遲更新，觸發一次性重算 ──\n    pt.ManualUpdate = False\n\n    endTime = Timer\n\n    wsPivot.Columns(\"A:I\").AutoFit\n    wsPivot.Activate\n    MsgBox \"延遲更新模式示範完成！\" & Chr(13) & _\n           \"所有欄位設定完畢後才進行一次重算。\" & Chr(13) & _\n           \"耗時：\" & Format(endTime - startTime, \"0.000\") & \" 秒\", _\n           vbInformation, \"完成\"\nEnd Sub\n\n' 填入大量欄位測試資料\nPrivate Sub FillLargeFieldData(ByVal ws As Worksheet)\n    ws.Range(\"A1\").Value = \"部門\"\n    ws.Range(\"B1\").Value = \"月份\"\n    ws.Range(\"C1\").Value = \"薪資\"\n    ws.Range(\"D1\").Value = \"獎金\"\n\n    Dim depts As Variant\n    Dim months As Variant\n    depts = Array(\"業務部\", \"研發部\", \"管理部\", \"財務部\")\n    months = Array(\"一月\", \"二月\", \"三月\", \"四月\", \"五月\", \"六月\")\n\n    Dim row As Integer\n    Dim d As Integer\n    Dim m As Integer\n    row = 2\n    For d = 0 To UBound(depts)\n        For m = 0 To UBound(months)\n            ws.Cells(row, 1).Value = depts(d)\n            ws.Cells(row, 2).Value = months(m)\n            ws.Cells(row, 3).Value = 30000 + (d * 5000) + (m * 1000)\n            ws.Cells(row, 4).Value = 5000 + (d * 1000) + (m * 500)\n            row = row + 1\n        Next m\n    Next d\n\n    ws.Columns(\"A:D\").AutoFit\nEnd Sub\n\n' 取得或建立工作表，並清除內容\nPrivate Function GetOrCreateSheet(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add\n        ws.Name = sheetName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreateSheet = ws\nEnd Function\n", "content_b64": ""}, {"name": "DisplayModePivot.bas", "path": "模組/PivotTableAnalysis/DisplayModePivot.bas", "content": "Attribute VB_Name = \"DisplayModePivot\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: DisplayModePivot\n'功能說明: 樞紐顯示模式切換示範\n'          示範三種版面配置模式：\n'          xlCompactRow（精簡）、xlOutlineRow（大綱）、xlTabularRow（表格）\n'          以及小計與總計的顯示控制\n'\n'版權所有: Dunk\n'程式設計: Dunk\n'撰寫日期: 2026/5/6\n'\n'*************************************************************************************\n\n' 程式進入點\nSub TestDisplayModePivot()\n    Call CreateDisplayModePivot\nEnd Sub\n\n' 建立樞紐分析表並示範三種版面配置模式\nSub CreateDisplayModePivot()\n    Dim wsData As Worksheet\n    Dim pc As PivotCache\n    Dim dataRange As Range\n\n    Set wsData = GetOrCreateSheet(ThisWorkbook, \"組織銷售\")\n    Call FillOrgData(wsData)\n\n    Set dataRange = wsData.Range(\"A1\").CurrentRegion\n\n    Set pc = ThisWorkbook.PivotCaches.Create( _\n        SourceType:=xlDatabase, _\n        SourceData:=dataRange)\n\n    ' 建立三個工作表，各套用一種顯示模式\n    Call BuildModeSheet(pc, dataRange, \"精簡模式樞紐\", \"精簡模式樞紐分析表\", xlCompactRow)\n    Call BuildModeSheet(pc, dataRange, \"大綱模式樞紐\", \"大綱模式樞紐分析表\", xlOutlineRow)\n    Call BuildModeSheet(pc, dataRange, \"表格模式樞紐\", \"表格模式樞紐分析表\", xlTabularRow)\n\n    ThisWorkbook.Worksheets(\"精簡模式樞紐\").Activate\n    MsgBox \"三種版面配置模式示範完成！\" & Chr(13) & _\n           \"‧ 精簡模式樞紐：多欄位合併顯示在同一欄\" & Chr(13) & _\n           \"‧ 大綱模式樞紐：多欄位依層級縮排顯示\" & Chr(13) & _\n           \"‧ 表格模式樞紐：多欄位各自獨立欄顯示\", vbInformation, \"完成\"\nEnd Sub\n\n' 依指定版面模式建立單一樞紐分析表工作表\nPrivate Sub BuildModeSheet( _\n    ByVal pc As PivotCache, _\n    ByVal dataRange As Range, _\n    ByVal sheetName As String, _\n    ByVal tableName As String, _\n    ByVal layoutMode As Long)\n\n    Dim wsPivot As Worksheet\n    Dim pt As PivotTable\n\n    Set wsPivot = GetOrCreateSheet(ThisWorkbook, sheetName)\n\n    Set pt = pc.CreatePivotTable( _\n        TableDestination:=wsPivot.Range(\"A3\"), _\n        TableName:=tableName)\n\n    ' 多層列欄位：部門 → 組別\n    With pt.PivotFields(\"部門\")\n        .Orientation = xlRowField\n        .Position = 1\n    End With\n\n    With pt.PivotFields(\"組別\")\n        .Orientation = xlRowField\n        .Position = 2\n    End With\n\n    ' 欄欄位：季度\n    With pt.PivotFields(\"季度\")\n        .Orientation = xlColumnField\n        .Position = 1\n    End With\n\n    ' 值欄位：業績\n    Dim df As PivotField\n    Set df = pt.AddDataField(pt.PivotFields(\"業績\"), \"業績合計\", xlSum)\n    df.NumberFormat = \"#,##0\"\n\n    ' 套用版面配置模式\n    pt.RowAxisLayout layoutMode\n\n    ' 控制小計顯示（大綱/表格模式下可見）\n    pt.PivotFields(\"部門\").Subtotals(1) = True  ' 顯示自動小計\n\n    ' 控制總計顯示\n    pt.ColumnGrand = True\n    pt.RowGrand = True\n\n    wsPivot.Columns(\"A:G\").AutoFit\nEnd Sub\n\n' 填入組織業績資料\nPrivate Sub FillOrgData(ByVal ws As Worksheet)\n    ws.Range(\"A1\").Value = \"部門\"\n    ws.Range(\"B1\").Value = \"組別\"\n    ws.Range(\"C1\").Value = \"季度\"\n    ws.Range(\"D1\").Value = \"業績\"\n\n    ws.Range(\"A2\").Value = \"業務部\" : ws.Range(\"B2\").Value = \"一組\" : ws.Range(\"C2\").Value = \"Q1\" : ws.Range(\"D2\").Value = 250000\n    ws.Range(\"A3\").Value = \"業務部\" : ws.Range(\"B3\").Value = \"一組\" : ws.Range(\"C3\").Value = \"Q2\" : ws.Range(\"D3\").Value = 310000\n    ws.Range(\"A4\").Value = \"業務部\" : ws.Range(\"B4\").Value = \"二組\" : ws.Range(\"C4\").Value = \"Q1\" : ws.Range(\"D4\").Value = 190000\n    ws.Range(\"A5\").Value = \"業務部\" : ws.Range(\"B5\").Value = \"二組\" : ws.Range(\"C5\").Value = \"Q2\" : ws.Range(\"D5\").Value = 225000\n    ws.Range(\"A6\").Value = \"研發部\" : ws.Range(\"B6\").Value = \"前端組\" : ws.Range(\"C6\").Value = \"Q1\" : ws.Range(\"D6\").Value = 120000\n    ws.Range(\"A7\").Value = \"研發部\" : ws.Range(\"B7\").Value = \"前端組\" : ws.Range(\"C7\").Value = \"Q2\" : ws.Range(\"D7\").Value = 145000\n    ws.Range(\"A8\").Value = \"研發部\" : ws.Range(\"B8\").Value = \"後端組\" : ws.Range(\"C8\").Value = \"Q1\" : ws.Range(\"D8\").Value = 160000\n    ws.Range(\"A9\").Value = \"研發部\" : ws.Range(\"B9\").Value = \"後端組\" : ws.Range(\"C9\").Value = \"Q2\" : ws.Range(\"D9\").Value = 175000\n\n    ws.Columns(\"A:D\").AutoFit\nEnd Sub\n\n' 取得或建立工作表，並清除內容\nPrivate Function GetOrCreateSheet(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add\n        ws.Name = sheetName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreateSheet = ws\nEnd Function\n", "content_b64": ""}, {"name": "DrillDownPivotTable.bas", "path": "模組/PivotTableAnalysis/DrillDownPivotTable.bas", "content": "Attribute VB_Name = \"DrillDownPivotTable\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: DrillDownPivotTable\n'功能說明: 示範樞紐分析表的下鑽功能（ShowDetail），\n'          對指定儲存格自動產生明細工作表\n'\n'版權所有: Dunk\n'程式設計: Dunk\n'撰寫日期: 2026/5/4\n'\n'*************************************************************************************\n\n' 測試入口\nSub TestDrillDownPivotTable()\n    Call CreateDrillDownPivotTable\nEnd Sub\n\n' 建立樞紐分析表並示範下鑽明細功能\nSub CreateDrillDownPivotTable()\n    Dim wsData    As Worksheet\n    Dim wsPivot   As Worksheet\n    Dim pc        As PivotCache\n    Dim pt        As PivotTable\n    Dim dataRange As Range\n    Dim ptCell    As Range\n\n    ' 準備資料工作表\n    Set wsData = GetOrCreateSheet(ThisWorkbook, \"銷售資料\")\n    Call FillSalesData(wsData)\n\n    ' 準備樞紐工作表\n    Set wsPivot = GetOrCreateSheet(ThisWorkbook, \"下鑽樞紐\")\n\n    Set dataRange = wsData.Range(\"A1\").CurrentRegion\n\n    Set pc = ThisWorkbook.PivotCaches.Create( _\n        SourceType:=xlDatabase, _\n        SourceData:=dataRange)\n    Set pt = pc.CreatePivotTable( _\n        TableDestination:=wsPivot.Range(\"A3\"), _\n        TableName:=\"下鑽樞紐\")\n\n    ' 列欄位: 地區\n    With pt.PivotFields(\"地區\")\n        .Orientation = xlRowField\n        .Position = 1\n    End With\n\n    ' 欄欄位: 產品\n    With pt.PivotFields(\"產品\")\n        .Orientation = xlColumnField\n        .Position = 1\n    End With\n\n    ' 值欄位: 銷售額加總\n    pt.AddDataField pt.PivotFields(\"銷售額\"), \"銷售額加總\", xlSum\n\n    wsPivot.Activate\n\n    ' 取得資料本體第一個儲存格並執行下鑽\n    Set ptCell = pt.DataBodyRange.Cells(1, 1)\n    If Not ptCell Is Nothing Then\n        On Error Resume Next\n        ptCell.ShowDetail = True\n        On Error GoTo 0\n    End If\n\n    MsgBox \"下鑽功能示範完成！\" & Chr(13) & _\n           \"已對第一個值儲存格執行下鑽，\" & Chr(13) & _\n           \"Excel 將自動產生明細工作表。\", _\n           vbInformation, \"完成\"\nEnd Sub\n\n' 填入範例銷售資料（8筆：日期、地區、產品、數量、單價、銷售額）\nPrivate Sub FillSalesData(ByVal ws As Worksheet)\n    ws.Range(\"A1\").Value = \"日期\"\n    ws.Range(\"B1\").Value = \"地區\"\n    ws.Range(\"C1\").Value = \"產品\"\n    ws.Range(\"D1\").Value = \"數量\"\n    ws.Range(\"E1\").Value = \"單價\"\n    ws.Range(\"F1\").Value = \"銷售額\"\n\n    ws.Range(\"A2\").Value = DateSerial(2026, 1, 5)\n    ws.Range(\"B2\").Value = \"北區\"\n    ws.Range(\"C2\").Value = \"產品A\"\n    ws.Range(\"D2\").Value = 100\n    ws.Range(\"E2\").Value = 50\n    ws.Range(\"F2\").Value = 5000\n\n    ws.Range(\"A3\").Value = DateSerial(2026, 1, 10)\n    ws.Range(\"B3\").Value = \"南區\"\n    ws.Range(\"C3\").Value = \"產品B\"\n    ws.Range(\"D3\").Value = 80\n    ws.Range(\"E3\").Value = 75\n    ws.Range(\"F3\").Value = 6000\n\n    ws.Range(\"A4\").Value = DateSerial(2026, 2, 5)\n    ws.Range(\"B4\").Value = \"北區\"\n    ws.Range(\"C4\").Value = \"產品B\"\n    ws.Range(\"D4\").Value = 60\n    ws.Range(\"E4\").Value = 75\n    ws.Range(\"F4\").Value = 4500\n\n    ws.Range(\"A5\").Value = DateSerial(2026, 2, 15)\n    ws.Range(\"B5\").Value = \"中區\"\n    ws.Range(\"C5\").Value = \"產品A\"\n    ws.Range(\"D5\").Value = 120\n    ws.Range(\"E5\").Value = 50\n    ws.Range(\"F5\").Value = 6000\n\n    ws.Range(\"A6\").Value = DateSerial(2026, 3, 1)\n    ws.Range(\"B6\").Value = \"南區\"\n    ws.Range(\"C6\").Value = \"產品A\"\n    ws.Range(\"D6\").Value = 90\n    ws.Range(\"E6\").Value = 50\n    ws.Range(\"F6\").Value = 4500\n\n    ws.Range(\"A7\").Value = DateSerial(2026, 3, 20)\n    ws.Range(\"B7\").Value = \"中區\"\n    ws.Range(\"C7\").Value = \"產品B\"\n    ws.Range(\"D7\").Value = 150\n    ws.Range(\"E7\").Value = 75\n    ws.Range(\"F7\").Value = 11250\n\n    ws.Range(\"A8\").Value = DateSerial(2026, 4, 5)\n    ws.Range(\"B8\").Value = \"北區\"\n    ws.Range(\"C8\").Value = \"產品A\"\n    ws.Range(\"D8\").Value = 200\n    ws.Range(\"E8\").Value = 50\n    ws.Range(\"F8\").Value = 10000\n\n    ws.Range(\"A9\").Value = DateSerial(2026, 4, 18)\n    ws.Range(\"B9\").Value = \"南區\"\n    ws.Range(\"C9\").Value = \"產品B\"\n    ws.Range(\"D9\").Value = 110\n    ws.Range(\"E9\").Value = 75\n    ws.Range(\"F9\").Value = 8250\n\n    ws.Columns(\"A\").NumberFormat = \"yyyy/m/d\"\n    ws.Columns(\"A:F\").AutoFit\nEnd Sub\n\n' 取得或建立工作表，並清除現有內容\nPrivate Function GetOrCreateSheet(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add\n        ws.Name = sheetName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreateSheet = ws\nEnd Function\n", "content_b64": ""}, {"name": "ErrorEmptyCellPivot.bas", "path": "模組/PivotTableAnalysis/ErrorEmptyCellPivot.bas", "content": "Attribute VB_Name = \"ErrorEmptyCellPivot\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: ErrorEmptyCellPivot\n'功能說明: 空白及錯誤儲存格顯示設定示範\n'          設定樞紐分析表在遇到空白資料時顯示指定文字\n'          以及當計算發生錯誤時的替代顯示文字\n'\n'版權所有: Dunk\n'程式設計: Dunk\n'撰寫日期: 2026/5/6\n'\n'*************************************************************************************\n\n' 程式進入點\nSub TestErrorEmptyCellPivot()\n    Call CreateErrorEmptyCellPivot\nEnd Sub\n\n' 建立含空白及錯誤顯示設定的樞紐分析表\nSub CreateErrorEmptyCellPivot()\n    Dim wsData As Worksheet\n    Dim wsPivot As Worksheet\n    Dim pc As PivotCache\n    Dim pt As PivotTable\n    Dim dataRange As Range\n\n    Set wsData = GetOrCreateSheet(ThisWorkbook, \"含空值銷售\")\n    Call FillSparseData(wsData)\n    Set wsPivot = GetOrCreateSheet(ThisWorkbook, \"空白錯誤樞紐\")\n\n    Set dataRange = wsData.Range(\"A1\").CurrentRegion\n\n    Set pc = ThisWorkbook.PivotCaches.Create( _\n        SourceType:=xlDatabase, _\n        SourceData:=dataRange)\n    Set pt = pc.CreatePivotTable( _\n        TableDestination:=wsPivot.Range(\"A3\"), _\n        TableName:=\"空白錯誤樞紐分析表\")\n\n    ' 列欄位：地區\n    With pt.PivotFields(\"地區\")\n        .Orientation = xlRowField\n        .Position = 1\n    End With\n\n    ' 欄欄位：產品\n    With pt.PivotFields(\"產品\")\n        .Orientation = xlColumnField\n        .Position = 1\n    End With\n\n    ' 值欄位：銷售額\n    pt.AddDataField pt.PivotFields(\"銷售額\"), \"銷售額合計\", xlSum\n\n    ' 設定空白儲存格顯示文字\n    pt.NullString = \"－\"\n\n    ' 設定錯誤值顯示文字\n    pt.ErrorString = \"錯誤\"\n    pt.DisplayErrorString = True\n\n    ' 開啟空白顯示\n    pt.DisplayNullString = True\n\n    wsPivot.Columns(\"A:E\").AutoFit\n    wsPivot.Activate\n    MsgBox \"空白/錯誤顯示樞紐分析表已建立！\" & Chr(13) & _\n           \"空白儲存格顯示：『－』\" & Chr(13) & _\n           \"錯誤值顯示：『錯誤』\", vbInformation, \"完成\"\nEnd Sub\n\n' 填入含稀疏（空值）的銷售資料\nPrivate Sub FillSparseData(ByVal ws As Worksheet)\n    ws.Range(\"A1\").Value = \"地區\"\n    ws.Range(\"B1\").Value = \"產品\"\n    ws.Range(\"C1\").Value = \"銷售額\"\n\n    ' 刻意讓部分地區/產品組合缺少資料（產生空白格）\n    ws.Range(\"A2\").Value = \"北部\" : ws.Range(\"B2\").Value = \"產品A\" : ws.Range(\"C2\").Value = 50000\n    ws.Range(\"A3\").Value = \"北部\" : ws.Range(\"B3\").Value = \"產品B\" : ws.Range(\"C3\").Value = 32000\n    ws.Range(\"A4\").Value = \"南部\" : ws.Range(\"B4\").Value = \"產品A\" : ws.Range(\"C4\").Value = 41000\n    ' 南部 產品B 刻意省略（樞紐會顯示空白）\n    ws.Range(\"A5\").Value = \"東部\" : ws.Range(\"B5\").Value = \"產品C\" : ws.Range(\"C5\").Value = 28000\n    ws.Range(\"A6\").Value = \"北部\" : ws.Range(\"B6\").Value = \"產品C\" : ws.Range(\"C6\").Value = 19000\n    ' 東部 產品A、產品B 刻意省略\n\n    ws.Columns(\"A:C\").AutoFit\nEnd Sub\n\n' 取得或建立工作表，並清除內容\nPrivate Function GetOrCreateSheet(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add\n        ws.Name = sheetName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreateSheet = ws\nEnd Function\n", "content_b64": ""}, {"name": "ExportPivotToNewSheet.bas", "path": "模組/PivotTableAnalysis/ExportPivotToNewSheet.bas", "content": "Attribute VB_Name = \"ExportPivotToNewSheet\"\n\nOption Explicit\n\n\n\n' ============================================================\n\n' 範例：將樞紐分析表的數值結果複製貼上至新工作表（去除公式）\n\n' 功能：選取作用中樞紐分析表，以「只貼值」方式匯出至新工作表\n\n' ============================================================\n\nSub ExportPivotToNewSheet()\n\n    Dim ws          As Worksheet\n\n    Dim wsNew       As Worksheet\n\n    Dim pt          As PivotTable\n\n    Dim rngPivot    As Range\n\n\n\n    On Error GoTo ErrHandler\n\n\n\n    ' --- 確認作用中工作表有樞紐分析表 ---\n\n    Set ws = ActiveSheet\n\n    If ws.PivotTables.Count = 0 Then\n\n        MsgBox \"作用中工作表沒有樞紐分析表，請先切換至含樞紐分析表的工作表。\", vbExclamation\n\n        Exit Sub\n\n    End If\n\n\n\n    Set pt = ws.PivotTables(1)\n\n    Set rngPivot = pt.TableRange2\n\n\n\n    ' --- 建立新工作表並貼上純值 ---\n\n    Set wsNew = ThisWorkbook.Worksheets.Add( _\n\n        After:=ThisWorkbook.Sheets(ThisWorkbook.Sheets.Count))\n\n    wsNew.Name = \"樞紐匯出_\" & Format(Now(), \"mmddHHmm\")\n\n\n\n    rngPivot.Copy\n\n    wsNew.Range(\"A1\").PasteSpecial Paste:=xlPasteValues\n\n    wsNew.Range(\"A1\").PasteSpecial Paste:=xlPasteFormats\n\n    Application.CutCopyMode = False\n\n\n\n    wsNew.Columns.AutoFit\n\n    MsgBox \"樞紐分析表已匯出至工作表：\" & wsNew.Name, vbInformation\n\n    Exit Sub\n\n\n\nErrHandler:\n\n    MsgBox \"發生錯誤：\" & Err.Description, vbCritical\n\nEnd Sub\n\n", "content_b64": ""}, {"name": "FilterPivotTable.bas", "path": "模組/PivotTableAnalysis/FilterPivotTable.bas", "content": "Attribute VB_Name = \"FilterPivotTable\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: FilterPivotTable\n'功能說明: 樞紐分析表頁面篩選（報表篩選），示範篩選特定地區\n'\n'版權所有: Dunk\n'程式設計: Dunk\n'撰寫日期: 2026/5/3\n'\n'*************************************************************************************\n\n' 測試入口：建立樞紐並篩選「北部」\nSub TestFilterPivotTable()\n    Call CreateFilterPivotTable(\"北部\")\nEnd Sub\n\n' 建立含報表篩選的樞紐分析表\n' filterValue: 要篩選的地區（傳入空字串則顯示全部）\nSub CreateFilterPivotTable(ByVal filterValue As String)\n    Dim wsData As Worksheet\n    Dim wsPivot As Worksheet\n    Dim pc As PivotCache\n    Dim pt As PivotTable\n    Dim dataRange As Range\n    Dim pfPage As PivotField\n\n    ' 準備工作表\n    Set wsData = GetOrCreateSheet(ThisWorkbook, \"銷售資料\")\n    Call FillSalesData(wsData)\n    Set wsPivot = GetOrCreateSheet(ThisWorkbook, \"篩選樞紐\")\n\n    Set dataRange = wsData.Range(\"A1\").CurrentRegion\n\n    Set pc = ThisWorkbook.PivotCaches.Create( _\n        SourceType:=xlDatabase, _\n        SourceData:=dataRange)\n    Set pt = pc.CreatePivotTable( _\n        TableDestination:=wsPivot.Range(\"A3\"), _\n        TableName:=\"篩選樞紐分析表\")\n\n    ' 報表篩選欄位：地區\n    With pt.PivotFields(\"地區\")\n        .Orientation = xlPageField\n        .Position = 1\n    End With\n\n    ' 列欄位：產品\n    With pt.PivotFields(\"產品\")\n        .Orientation = xlRowField\n        .Position = 1\n    End With\n\n    ' 值欄位：銷售額\n    pt.AddDataField pt.PivotFields(\"銷售額\"), \"銷售額加總\", xlSum\n\n    ' 套用篩選條件\n    Set pfPage = pt.PivotFields(\"地區\")\n    If filterValue <> \"\" Then\n        pfPage.CurrentPage = filterValue\n        MsgBox \"已篩選地區：\" & filterValue, vbInformation, \"完成\"\n    Else\n        pfPage.CurrentPage = \"(全部)\"\n        MsgBox \"顯示全部地區\", vbInformation, \"完成\"\n    End If\n\n    wsPivot.Activate\nEnd Sub\n\n' 填入範例銷售資料（共 8 筆：日期、地區、產品、數量、單價、銷售額）\nPrivate Sub FillSalesData(ByVal ws As Worksheet)\n    ws.Range(\"A1\").Value = \"日期\"\n    ws.Range(\"B1\").Value = \"地區\"\n    ws.Range(\"C1\").Value = \"產品\"\n    ws.Range(\"D1\").Value = \"數量\"\n    ws.Range(\"E1\").Value = \"單價\"\n    ws.Range(\"F1\").Value = \"銷售額\"\n\n    ws.Range(\"A2\").Value = DateSerial(2026, 1, 5)\n    ws.Range(\"B2\").Value = \"北部\"\n    ws.Range(\"C2\").Value = \"產品A\"\n    ws.Range(\"D2\").Value = 100\n    ws.Range(\"E2\").Value = 50\n    ws.Range(\"F2\").Value = 5000\n\n    ws.Range(\"A3\").Value = DateSerial(2026, 1, 10)\n    ws.Range(\"B3\").Value = \"南部\"\n    ws.Range(\"C3\").Value = \"產品B\"\n    ws.Range(\"D3\").Value = 80\n    ws.Range(\"E3\").Value = 75\n    ws.Range(\"F3\").Value = 6000\n\n    ws.Range(\"A4\").Value = DateSerial(2026, 2, 5)\n    ws.Range(\"B4\").Value = \"北部\"\n    ws.Range(\"C4\").Value = \"產品B\"\n    ws.Range(\"D4\").Value = 60\n    ws.Range(\"E4\").Value = 75\n    ws.Range(\"F4\").Value = 4500\n\n    ws.Range(\"A5\").Value = DateSerial(2026, 2, 15)\n    ws.Range(\"B5\").Value = \"中部\"\n    ws.Range(\"C5\").Value = \"產品A\"\n    ws.Range(\"D5\").Value = 120\n    ws.Range(\"E5\").Value = 50\n    ws.Range(\"F5\").Value = 6000\n\n    ws.Range(\"A6\").Value = DateSerial(2026, 3, 1)\n    ws.Range(\"B6\").Value = \"南部\"\n    ws.Range(\"C6\").Value = \"產品A\"\n    ws.Range(\"D6\").Value = 90\n    ws.Range(\"E6\").Value = 50\n    ws.Range(\"F6\").Value = 4500\n\n    ws.Range(\"A7\").Value = DateSerial(2026, 3, 20)\n    ws.Range(\"B7\").Value = \"中部\"\n    ws.Range(\"C7\").Value = \"產品B\"\n    ws.Range(\"D7\").Value = 150\n    ws.Range(\"E7\").Value = 75\n    ws.Range(\"F7\").Value = 11250\n\n    ws.Range(\"A8\").Value = DateSerial(2026, 4, 5)\n    ws.Range(\"B8\").Value = \"北部\"\n    ws.Range(\"C8\").Value = \"產品A\"\n    ws.Range(\"D8\").Value = 200\n    ws.Range(\"E8\").Value = 50\n    ws.Range(\"F8\").Value = 10000\n\n    ws.Range(\"A9\").Value = DateSerial(2026, 4, 18)\n    ws.Range(\"B9\").Value = \"南部\"\n    ws.Range(\"C9\").Value = \"產品B\"\n    ws.Range(\"D9\").Value = 110\n    ws.Range(\"E9\").Value = 75\n    ws.Range(\"F9\").Value = 8250\n\n    ws.Columns(\"A\").NumberFormat = \"yyyy/m/d\"\n    ws.Columns(\"A:F\").AutoFit\nEnd Sub\n\n' 取得或建立工作表，並清除內容\nPrivate Function GetOrCreateSheet(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add\n        ws.Name = sheetName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreateSheet = ws\nEnd Function\n", "content_b64": ""}, {"name": "GetPivotDataFunc.bas", "path": "模組/PivotTableAnalysis/GetPivotDataFunc.bas", "content": "Attribute VB_Name = \"GetPivotDataFunc\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: GetPivotDataFunc\n'功能說明: 使用 GetPivotData 函數從樞紐分析表取得特定值\n'          示範以 VBA 呼叫 PivotTable.GetPivotData 讀取指定交叉值\n'          並將結果輸出至摘要工作表\n'\n'版權所有: Dunk\n'程式設計: Dunk\n'撰寫日期: 2026/5/6\n'\n'*************************************************************************************\n\n' 程式進入點\nSub TestGetPivotDataFunc()\n    Call DemoGetPivotData\nEnd Sub\n\n' 建立樞紐分析表並示範 GetPivotData 取值\nSub DemoGetPivotData()\n    Dim wsData As Worksheet\n    Dim wsPivot As Worksheet\n    Dim wsSummary As Worksheet\n    Dim pc As PivotCache\n    Dim pt As PivotTable\n    Dim dataRange As Range\n    Dim extractVal As Double\n\n    Set wsData = GetOrCreateSheet(ThisWorkbook, \"季度銷售\")\n    Call FillQuarterData(wsData)\n    Set wsPivot = GetOrCreateSheet(ThisWorkbook, \"季度樞紐\")\n    Set wsSummary = GetOrCreateSheet(ThisWorkbook, \"GetPivotData摘要\")\n\n    Set dataRange = wsData.Range(\"A1\").CurrentRegion\n\n    Set pc = ThisWorkbook.PivotCaches.Create( _\n        SourceType:=xlDatabase, _\n        SourceData:=dataRange)\n    Set pt = pc.CreatePivotTable( _\n        TableDestination:=wsPivot.Range(\"A3\"), _\n        TableName:=\"季度樞紐分析表\")\n\n    ' 列欄位：地區\n    With pt.PivotFields(\"地區\")\n        .Orientation = xlRowField\n        .Position = 1\n    End With\n\n    ' 欄欄位：季度\n    With pt.PivotFields(\"季度\")\n        .Orientation = xlColumnField\n        .Position = 1\n    End With\n\n    ' 值欄位：銷售額\n    pt.AddDataField pt.PivotFields(\"銷售額\"), \"銷售額合計\", xlSum\n\n    ' 建立摘要工作表標題\n    wsSummary.Range(\"A1\").Value = \"GetPivotData 取值示範\"\n    wsSummary.Range(\"A1\").Font.Bold = True\n    wsSummary.Range(\"A3\").Value = \"查詢項目\"\n    wsSummary.Range(\"B3\").Value = \"取得值\"\n    wsSummary.Range(\"A3:B3\").Font.Bold = True\n\n    ' 以 GetPivotData 取出特定交叉值\n    On Error Resume Next\n    extractVal = pt.GetPivotData(\"銷售額合計\", \"地區\", \"北部\", \"季度\", \"Q1\")\n    wsSummary.Range(\"A4\").Value = \"北部 Q1 銷售額\"\n    wsSummary.Range(\"B4\").Value = extractVal\n\n    extractVal = pt.GetPivotData(\"銷售額合計\", \"地區\", \"南部\", \"季度\", \"Q2\")\n    wsSummary.Range(\"A5\").Value = \"南部 Q2 銷售額\"\n    wsSummary.Range(\"B5\").Value = extractVal\n\n    extractVal = pt.GetPivotData(\"銷售額合計\", \"地區\", \"東部\", \"季度\", \"Q3\")\n    wsSummary.Range(\"A6\").Value = \"東部 Q3 銷售額\"\n    wsSummary.Range(\"B6\").Value = extractVal\n    On Error GoTo 0\n\n    wsSummary.Columns(\"A:B\").AutoFit\n    wsSummary.Activate\n    MsgBox \"GetPivotData 示範完成！\" & Chr(13) & _\n           \"已在『GetPivotData摘要』工作表輸出指定交叉值。\", vbInformation, \"完成\"\nEnd Sub\n\n' 填入季度銷售資料\nPrivate Sub FillQuarterData(ByVal ws As Worksheet)\n    ws.Range(\"A1\").Value = \"地區\"\n    ws.Range(\"B1\").Value = \"季度\"\n    ws.Range(\"C1\").Value = \"銷售額\"\n\n    ws.Range(\"A2\").Value = \"北部\" : ws.Range(\"B2\").Value = \"Q1\" : ws.Range(\"C2\").Value = 88000\n    ws.Range(\"A3\").Value = \"北部\" : ws.Range(\"B3\").Value = \"Q2\" : ws.Range(\"C3\").Value = 92000\n    ws.Range(\"A4\").Value = \"北部\" : ws.Range(\"B4\").Value = \"Q3\" : ws.Range(\"C4\").Value = 76000\n    ws.Range(\"A5\").Value = \"北部\" : ws.Range(\"B5\").Value = \"Q4\" : ws.Range(\"C5\").Value = 105000\n    ws.Range(\"A6\").Value = \"南部\" : ws.Range(\"B6\").Value = \"Q1\" : ws.Range(\"C6\").Value = 65000\n    ws.Range(\"A7\").Value = \"南部\" : ws.Range(\"B7\").Value = \"Q2\" : ws.Range(\"C7\").Value = 78000\n    ws.Range(\"A8\").Value = \"南部\" : ws.Range(\"B8\").Value = \"Q3\" : ws.Range(\"C8\").Value = 83000\n    ws.Range(\"A9\").Value = \"南部\" : ws.Range(\"B9\").Value = \"Q4\" : ws.Range(\"C9\").Value = 91000\n    ws.Range(\"A10\").Value = \"東部\" : ws.Range(\"B10\").Value = \"Q1\" : ws.Range(\"C10\").Value = 42000\n    ws.Range(\"A11\").Value = \"東部\" : ws.Range(\"B11\").Value = \"Q2\" : ws.Range(\"C11\").Value = 55000\n    ws.Range(\"A12\").Value = \"東部\" : ws.Range(\"B12\").Value = \"Q3\" : ws.Range(\"C12\").Value = 61000\n    ws.Range(\"A13\").Value = \"東部\" : ws.Range(\"B13\").Value = \"Q4\" : ws.Range(\"C13\").Value = 48000\n\n    ws.Columns(\"A:C\").AutoFit\nEnd Sub\n\n' 取得或建立工作表，並清除內容\nPrivate Function GetOrCreateSheet(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add\n        ws.Name = sheetName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreateSheet = ws\nEnd Function\n", "content_b64": ""}, {"name": "GroupByTextPivot.bas", "path": "模組/PivotTableAnalysis/GroupByTextPivot.bas", "content": "Attribute VB_Name = \"GroupByTextPivot\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: GroupByTextPivot\n'功能說明: 手動文字群組示範\n'          將樞紐分析表中多個列項目合併為自訂群組\n'          例如：台北+基隆 → 北部地區、高雄+台南 → 南部地區\n'\n'版權所有: Dunk\n'程式設計: Dunk\n'撰寫日期: 2026/5/6\n'\n'*************************************************************************************\n\n' 程式進入點\nSub TestGroupByTextPivot()\n    Call CreateGroupByTextPivot\nEnd Sub\n\n' 建立含手動文字群組的樞紐分析表\nSub CreateGroupByTextPivot()\n    Dim wsData As Worksheet\n    Dim wsPivot As Worksheet\n    Dim pc As PivotCache\n    Dim pt As PivotTable\n    Dim pf As PivotField\n    Dim dataRange As Range\n\n    Set wsData = GetOrCreateSheet(ThisWorkbook, \"城市銷售\")\n    Call FillCityData(wsData)\n    Set wsPivot = GetOrCreateSheet(ThisWorkbook, \"文字群組樞紐\")\n\n    Set dataRange = wsData.Range(\"A1\").CurrentRegion\n\n    Set pc = ThisWorkbook.PivotCaches.Create( _\n        SourceType:=xlDatabase, _\n        SourceData:=dataRange)\n    Set pt = pc.CreatePivotTable( _\n        TableDestination:=wsPivot.Range(\"A3\"), _\n        TableName:=\"文字群組樞紐分析表\")\n\n    ' 列欄位：城市\n    With pt.PivotFields(\"城市\")\n        .Orientation = xlRowField\n        .Position = 1\n    End With\n\n    ' 值欄位：銷售額\n    pt.AddDataField pt.PivotFields(\"銷售額\"), \"銷售額合計\", xlSum\n\n    ' 手動群組：台北+基隆 → 北部地區\n    Set pf = pt.PivotFields(\"城市\")\n    pf.PivotItems(\"台北\").Selected = True\n    pf.PivotItems(\"基隆\").Selected = True\n\n    On Error Resume Next\n    pf.CreatePivotItemList(Array(\"台北\", \"基隆\")).Group\n    pt.PivotFields(\"城市2\").PivotItems(\"群組1\").Caption = \"北部地區\"\n\n    ' 手動群組：高雄+台南 → 南部地區\n    pf.PivotItems(\"高雄\").Selected = True\n    pf.PivotItems(\"台南\").Selected = True\n    pf.CreatePivotItemList(Array(\"高雄\", \"台南\")).Group\n    pt.PivotFields(\"城市2\").PivotItems(\"群組2\").Caption = \"南部地區\"\n    On Error GoTo 0\n\n    wsPivot.Columns(\"A:D\").AutoFit\n    wsPivot.Activate\n    MsgBox \"手動文字群組樞紐分析表已建立！\" & Chr(13) & _\n           \"城市已依地區分組顯示。\", vbInformation, \"完成\"\nEnd Sub\n\n' 填入城市銷售資料\nPrivate Sub FillCityData(ByVal ws As Worksheet)\n    ws.Range(\"A1\").Value = \"城市\"\n    ws.Range(\"B1\").Value = \"類別\"\n    ws.Range(\"C1\").Value = \"銷售額\"\n\n    ws.Range(\"A2\").Value = \"台北\" : ws.Range(\"B2\").Value = \"電子\" : ws.Range(\"C2\").Value = 12000\n    ws.Range(\"A3\").Value = \"基隆\" : ws.Range(\"B3\").Value = \"服飾\" : ws.Range(\"C3\").Value = 8000\n    ws.Range(\"A4\").Value = \"高雄\" : ws.Range(\"B4\").Value = \"電子\" : ws.Range(\"C4\").Value = 15000\n    ws.Range(\"A5\").Value = \"台南\" : ws.Range(\"B5\").Value = \"服飾\" : ws.Range(\"C5\").Value = 9500\n    ws.Range(\"A6\").Value = \"台北\" : ws.Range(\"B6\").Value = \"食品\" : ws.Range(\"C6\").Value = 7000\n    ws.Range(\"A7\").Value = \"高雄\" : ws.Range(\"B7\").Value = \"食品\" : ws.Range(\"C7\").Value = 11000\n    ws.Range(\"A8\").Value = \"基隆\" : ws.Range(\"B8\").Value = \"電子\" : ws.Range(\"C8\").Value = 6500\n    ws.Range(\"A9\").Value = \"台南\" : ws.Range(\"B9\").Value = \"電子\" : ws.Range(\"C9\").Value = 13000\n\n    ws.Columns(\"A:C\").AutoFit\nEnd Sub\n\n' 取得或建立工作表，並清除內容\nPrivate Function GetOrCreateSheet(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add\n        ws.Name = sheetName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreateSheet = ws\nEnd Function\n", "content_b64": ""}, {"name": "HideItemPivot.bas", "path": "模組/PivotTableAnalysis/HideItemPivot.bas", "content": "Attribute VB_Name = \"HideItemPivot\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: HideItemPivot\n'功能說明: 示範如何隱藏/顯示樞紐分析表中的特定項目，\n'          透過 PivotItem.Visible 控制個別項目的顯示\n'\n'版權所有: Dunk\n'程式設計: Dunk\n'撰寫日期: 2026/5/4\n'\n'*************************************************************************************\n\n' 測試入口\nSub TestHideItemPivot()\n    Call CreateHideItemPivot\nEnd Sub\n\n' 建立樞紐分析表並隱藏指定項目\n' 功能: 建立地區x產品的樞紐後，隱藏「中區」列\nSub CreateHideItemPivot()\n    Dim wsData    As Worksheet\n    Dim wsPivot   As Worksheet\n    Dim pc        As PivotCache\n    Dim pt        As PivotTable\n    Dim dataRange As Range\n    Dim pfRegion  As PivotField\n    Dim pi        As PivotItem\n\n    ' 準備資料工作表\n    Set wsData = GetOrCreateSheet(ThisWorkbook, \"銷售資料\")\n    Call FillSalesData(wsData)\n\n    ' 準備樞紐工作表\n    Set wsPivot = GetOrCreateSheet(ThisWorkbook, \"隱藏項目樞紐\")\n\n    Set dataRange = wsData.Range(\"A1\").CurrentRegion\n\n    Set pc = ThisWorkbook.PivotCaches.Create( _\n        SourceType:=xlDatabase, _\n        SourceData:=dataRange)\n    Set pt = pc.CreatePivotTable( _\n        TableDestination:=wsPivot.Range(\"A3\"), _\n        TableName:=\"隱藏項目樞紐\")\n\n    ' 列欄位: 地區\n    Set pfRegion = pt.PivotFields(\"地區\")\n    pfRegion.Orientation = xlRowField\n    pfRegion.Position = 1\n\n    ' 欄欄位: 產品\n    With pt.PivotFields(\"產品\")\n        .Orientation = xlColumnField\n        .Position = 1\n    End With\n\n    ' 值欄位: 銷售額加總\n    pt.AddDataField pt.PivotFields(\"銷售額\"), \"銷售額加總\", xlSum\n\n    ' 隱藏「中區」項目（至少需保留一個項目可見）\n    On Error Resume Next\n    For Each pi In pfRegion.PivotItems\n        If pi.Name = \"中區\" Then\n            pi.Visible = False\n        End If\n    Next pi\n    On Error GoTo 0\n\n    wsPivot.Activate\n    MsgBox \"隱藏項目樞紐分析表已建立完成！\" & Chr(13) & _\n           \"「中區」已被隱藏，只顯示北區與南區。\" & Chr(13) & _\n           \"可修改 PivotItem.Visible = True 還原顯示。\", _\n           vbInformation, \"完成\"\nEnd Sub\n\n' 填入範例銷售資料（8筆：日期、地區、產品、數量、單價、銷售額）\nPrivate Sub FillSalesData(ByVal ws As Worksheet)\n    ws.Range(\"A1\").Value = \"日期\"\n    ws.Range(\"B1\").Value = \"地區\"\n    ws.Range(\"C1\").Value = \"產品\"\n    ws.Range(\"D1\").Value = \"數量\"\n    ws.Range(\"E1\").Value = \"單價\"\n    ws.Range(\"F1\").Value = \"銷售額\"\n\n    ws.Range(\"A2\").Value = DateSerial(2026, 1, 5)\n    ws.Range(\"B2\").Value = \"北區\"\n    ws.Range(\"C2\").Value = \"產品A\"\n    ws.Range(\"D2\").Value = 100\n    ws.Range(\"E2\").Value = 50\n    ws.Range(\"F2\").Value = 5000\n\n    ws.Range(\"A3\").Value = DateSerial(2026, 1, 10)\n    ws.Range(\"B3\").Value = \"南區\"\n    ws.Range(\"C3\").Value = \"產品B\"\n    ws.Range(\"D3\").Value = 80\n    ws.Range(\"E3\").Value = 75\n    ws.Range(\"F3\").Value = 6000\n\n    ws.Range(\"A4\").Value = DateSerial(2026, 2, 5)\n    ws.Range(\"B4\").Value = \"北區\"\n    ws.Range(\"C4\").Value = \"產品B\"\n    ws.Range(\"D4\").Value = 60\n    ws.Range(\"E4\").Value = 75\n    ws.Range(\"F4\").Value = 4500\n\n    ws.Range(\"A5\").Value = DateSerial(2026, 2, 15)\n    ws.Range(\"B5\").Value = \"中區\"\n    ws.Range(\"C5\").Value = \"產品A\"\n    ws.Range(\"D5\").Value = 120\n    ws.Range(\"E5\").Value = 50\n    ws.Range(\"F5\").Value = 6000\n\n    ws.Range(\"A6\").Value = DateSerial(2026, 3, 1)\n    ws.Range(\"B6\").Value = \"南區\"\n    ws.Range(\"C6\").Value = \"產品A\"\n    ws.Range(\"D6\").Value = 90\n    ws.Range(\"E6\").Value = 50\n    ws.Range(\"F6\").Value = 4500\n\n    ws.Range(\"A7\").Value = DateSerial(2026, 3, 20)\n    ws.Range(\"B7\").Value = \"中區\"\n    ws.Range(\"C7\").Value = \"產品B\"\n    ws.Range(\"D7\").Value = 150\n    ws.Range(\"E7\").Value = 75\n    ws.Range(\"F7\").Value = 11250\n\n    ws.Range(\"A8\").Value = DateSerial(2026, 4, 5)\n    ws.Range(\"B8\").Value = \"北區\"\n    ws.Range(\"C8\").Value = \"產品A\"\n    ws.Range(\"D8\").Value = 200\n    ws.Range(\"E8\").Value = 50\n    ws.Range(\"F8\").Value = 10000\n\n    ws.Range(\"A9\").Value = DateSerial(2026, 4, 18)\n    ws.Range(\"B9\").Value = \"南區\"\n    ws.Range(\"C9\").Value = \"產品B\"\n    ws.Range(\"D9\").Value = 110\n    ws.Range(\"E9\").Value = 75\n    ws.Range(\"F9\").Value = 8250\n\n    ws.Columns(\"A\").NumberFormat = \"yyyy/m/d\"\n    ws.Columns(\"A:F\").AutoFit\nEnd Sub\n\n' 取得或建立工作表，並清除現有內容\nPrivate Function GetOrCreateSheet(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add\n        ws.Name = sheetName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreateSheet = ws\nEnd Function\n", "content_b64": ""}, {"name": "LayoutPivotTable.bas", "path": "模組/PivotTableAnalysis/LayoutPivotTable.bas", "content": "Attribute VB_Name = \"LayoutPivotTable\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: LayoutPivotTable\n'功能說明: 示範樞紐分析表三種版面配置切換：\n'          1. 壓縮模式 (Compact)\n'          2. 大綱模式 (Outline)\n'          3. 表格模式 (Tabular)\n'\n'版權所有: Dunk\n'程式設計: Dunk\n'撰寫日期: 2026/5/4\n'\n'*************************************************************************************\n\n' 測試入口\nSub TestLayoutPivotTable()\n    Call CreateLayoutPivotTable\nEnd Sub\n\n' 建立樞紐分析表並示範三種版面配置\nSub CreateLayoutPivotTable()\n    Dim wsData    As Worksheet\n    Dim wsPivot   As Worksheet\n    Dim pc        As PivotCache\n    Dim pt        As PivotTable\n    Dim dataRange As Range\n    Dim answer    As Integer\n\n    ' 準備資料工作表\n    Set wsData = GetOrCreateSheet(ThisWorkbook, \"銷售資料\")\n    Call FillSalesData(wsData)\n\n    ' 準備樞紐工作表\n    Set wsPivot = GetOrCreateSheet(ThisWorkbook, \"版面配置樞紐\")\n\n    Set dataRange = wsData.Range(\"A1\").CurrentRegion\n\n    Set pc = ThisWorkbook.PivotCaches.Create( _\n        SourceType:=xlDatabase, _\n        SourceData:=dataRange)\n    Set pt = pc.CreatePivotTable( _\n        TableDestination:=wsPivot.Range(\"A3\"), _\n        TableName:=\"版面配置樞紐\")\n\n    ' 第一層列欄位: 地區\n    With pt.PivotFields(\"地區\")\n        .Orientation = xlRowField\n        .Position = 1\n    End With\n\n    ' 第二層列欄位: 產品\n    With pt.PivotFields(\"產品\")\n        .Orientation = xlRowField\n        .Position = 2\n    End With\n\n    ' 值欄位: 銷售額加總\n    pt.AddDataField pt.PivotFields(\"銷售額\"), \"銷售額加總\", xlSum\n\n    ' 詢問使用者選擇版面配置\n    answer = MsgBox( _\n        \"請選擇版面配置模式：\" & Chr(13) & _\n        \"是(Y) = 壓縮模式\" & Chr(13) & _\n        \"否(N) = 大綱模式\" & Chr(13) & _\n        \"取消 = 表格模式\", _\n        vbYesNoCancel + vbQuestion, \"選擇版面配置\")\n\n    Select Case answer\n        Case vbYes\n            ' 壓縮模式：所有列欄位壓縮在同一欄\n            pt.RowAxisLayout xlCompactRow\n            MsgBox \"已切換為壓縮模式（Compact Layout）。\", vbInformation, \"完成\"\n        Case vbNo\n            ' 大綱模式：各列欄位分欄但保留縮排\n            pt.RowAxisLayout xlOutlineRow\n            MsgBox \"已切換為大綱模式（Outline Layout）。\", vbInformation, \"完成\"\n        Case vbCancel\n            ' 表格模式：各列欄位完全分欄，無縮排\n            pt.RowAxisLayout xlTabularRow\n            MsgBox \"已切換為表格模式（Tabular Layout）。\", vbInformation, \"完成\"\n    End Select\n\n    wsPivot.Activate\nEnd Sub\n\n' 填入範例銷售資料（8筆：日期、地區、產品、數量、單價、銷售額）\nPrivate Sub FillSalesData(ByVal ws As Worksheet)\n    ws.Range(\"A1\").Value = \"日期\"\n    ws.Range(\"B1\").Value = \"地區\"\n    ws.Range(\"C1\").Value = \"產品\"\n    ws.Range(\"D1\").Value = \"數量\"\n    ws.Range(\"E1\").Value = \"單價\"\n    ws.Range(\"F1\").Value = \"銷售額\"\n\n    ws.Range(\"A2\").Value = DateSerial(2026, 1, 5)\n    ws.Range(\"B2\").Value = \"北區\"\n    ws.Range(\"C2\").Value = \"產品A\"\n    ws.Range(\"D2\").Value = 100\n    ws.Range(\"E2\").Value = 50\n    ws.Range(\"F2\").Value = 5000\n\n    ws.Range(\"A3\").Value = DateSerial(2026, 1, 10)\n    ws.Range(\"B3\").Value = \"南區\"\n    ws.Range(\"C3\").Value = \"產品B\"\n    ws.Range(\"D3\").Value = 80\n    ws.Range(\"E3\").Value = 75\n    ws.Range(\"F3\").Value = 6000\n\n    ws.Range(\"A4\").Value = DateSerial(2026, 2, 5)\n    ws.Range(\"B4\").Value = \"北區\"\n    ws.Range(\"C4\").Value = \"產品B\"\n    ws.Range(\"D4\").Value = 60\n    ws.Range(\"E4\").Value = 75\n    ws.Range(\"F4\").Value = 4500\n\n    ws.Range(\"A5\").Value = DateSerial(2026, 2, 15)\n    ws.Range(\"B5\").Value = \"中區\"\n    ws.Range(\"C5\").Value = \"產品A\"\n    ws.Range(\"D5\").Value = 120\n    ws.Range(\"E5\").Value = 50\n    ws.Range(\"F5\").Value = 6000\n\n    ws.Range(\"A6\").Value = DateSerial(2026, 3, 1)\n    ws.Range(\"B6\").Value = \"南區\"\n    ws.Range(\"C6\").Value = \"產品A\"\n    ws.Range(\"D6\").Value = 90\n    ws.Range(\"E6\").Value = 50\n    ws.Range(\"F6\").Value = 4500\n\n    ws.Range(\"A7\").Value = DateSerial(2026, 3, 20)\n    ws.Range(\"B7\").Value = \"中區\"\n    ws.Range(\"C7\").Value = \"產品B\"\n    ws.Range(\"D7\").Value = 150\n    ws.Range(\"E7\").Value = 75\n    ws.Range(\"F7\").Value = 11250\n\n    ws.Range(\"A8\").Value = DateSerial(2026, 4, 5)\n    ws.Range(\"B8\").Value = \"北區\"\n    ws.Range(\"C8\").Value = \"產品A\"\n    ws.Range(\"D8\").Value = 200\n    ws.Range(\"E8\").Value = 50\n    ws.Range(\"F8\").Value = 10000\n\n    ws.Range(\"A9\").Value = DateSerial(2026, 4, 18)\n    ws.Range(\"B9\").Value = \"南區\"\n    ws.Range(\"C9\").Value = \"產品B\"\n    ws.Range(\"D9\").Value = 110\n    ws.Range(\"E9\").Value = 75\n    ws.Range(\"F9\").Value = 8250\n\n    ws.Columns(\"A\").NumberFormat = \"yyyy/m/d\"\n    ws.Columns(\"A:F\").AutoFit\nEnd Sub\n\n' 取得或建立工作表，並清除現有內容\nPrivate Function GetOrCreateSheet(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add\n        ws.Name = sheetName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreateSheet = ws\nEnd Function\n", "content_b64": ""}, {"name": "MultiFieldPivotTable.bas", "path": "模組/PivotTableAnalysis/MultiFieldPivotTable.bas", "content": "Attribute VB_Name = \"MultiFieldPivotTable\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: MultiFieldPivotTable\n'功能說明: 多欄位列/欄分組樞紐分析表（列: 地區+產品，值: 銷售額+數量）\n'\n'版權所有: Dunk\n'程式設計: Dunk\n'撰寫日期: 2026/5/3\n'\n'*************************************************************************************\n\n' 測試入口\nSub TestMultiFieldPivotTable()\n    Call CreateMultiFieldPivotTable\nEnd Sub\n\n' 建立多欄位樞紐分析表\n' 列欄位: 地區、產品（兩層）/ 值: 銷售額加總、數量加總\nSub CreateMultiFieldPivotTable()\n    Dim wsData As Worksheet\n    Dim wsPivot As Worksheet\n    Dim pc As PivotCache\n    Dim pt As PivotTable\n    Dim dataRange As Range\n\n    ' 準備工作表\n    Set wsData = GetOrCreateSheet(ThisWorkbook, \"銷售資料\")\n    Call FillSalesData(wsData)\n    Set wsPivot = GetOrCreateSheet(ThisWorkbook, \"多欄位樞紐\")\n\n    Set dataRange = wsData.Range(\"A1\").CurrentRegion\n\n    ' 建立 PivotCache 與樞紐分析表\n    Set pc = ThisWorkbook.PivotCaches.Create( _\n        SourceType:=xlDatabase, _\n        SourceData:=dataRange)\n    Set pt = pc.CreatePivotTable( _\n        TableDestination:=wsPivot.Range(\"A3\"), _\n        TableName:=\"多欄位樞紐分析表\")\n\n    ' 第一層列欄位：地區\n    With pt.PivotFields(\"地區\")\n        .Orientation = xlRowField\n        .Position = 1\n    End With\n\n    ' 第二層列欄位：產品\n    With pt.PivotFields(\"產品\")\n        .Orientation = xlRowField\n        .Position = 2\n    End With\n\n    ' 值欄位 1：銷售額加總\n    pt.AddDataField pt.PivotFields(\"銷售額\"), \"銷售額加總\", xlSum\n\n    ' 值欄位 2：數量加總\n    pt.AddDataField pt.PivotFields(\"數量\"), \"數量加總\", xlSum\n\n    ' 設定多欄位佈局（壓縮模式）\n    pt.RowAxisLayout xlCompactRow\n\n    wsPivot.Activate\n    MsgBox \"多欄位樞紐分析表已建立完成！\", vbInformation, \"完成\"\nEnd Sub\n\n' 填入範例銷售資料（共 8 筆：日期、地區、產品、數量、單價、銷售額）\nPrivate Sub FillSalesData(ByVal ws As Worksheet)\n    ws.Range(\"A1\").Value = \"日期\"\n    ws.Range(\"B1\").Value = \"地區\"\n    ws.Range(\"C1\").Value = \"產品\"\n    ws.Range(\"D1\").Value = \"數量\"\n    ws.Range(\"E1\").Value = \"單價\"\n    ws.Range(\"F1\").Value = \"銷售額\"\n\n    ws.Range(\"A2\").Value = DateSerial(2026, 1, 5)\n    ws.Range(\"B2\").Value = \"北部\"\n    ws.Range(\"C2\").Value = \"產品A\"\n    ws.Range(\"D2\").Value = 100\n    ws.Range(\"E2\").Value = 50\n    ws.Range(\"F2\").Value = 5000\n\n    ws.Range(\"A3\").Value = DateSerial(2026, 1, 10)\n    ws.Range(\"B3\").Value = \"南部\"\n    ws.Range(\"C3\").Value = \"產品B\"\n    ws.Range(\"D3\").Value = 80\n    ws.Range(\"E3\").Value = 75\n    ws.Range(\"F3\").Value = 6000\n\n    ws.Range(\"A4\").Value = DateSerial(2026, 2, 5)\n    ws.Range(\"B4\").Value = \"北部\"\n    ws.Range(\"C4\").Value = \"產品B\"\n    ws.Range(\"D4\").Value = 60\n    ws.Range(\"E4\").Value = 75\n    ws.Range(\"F4\").Value = 4500\n\n    ws.Range(\"A5\").Value = DateSerial(2026, 2, 15)\n    ws.Range(\"B5\").Value = \"中部\"\n    ws.Range(\"C5\").Value = \"產品A\"\n    ws.Range(\"D5\").Value = 120\n    ws.Range(\"E5\").Value = 50\n    ws.Range(\"F5\").Value = 6000\n\n    ws.Range(\"A6\").Value = DateSerial(2026, 3, 1)\n    ws.Range(\"B6\").Value = \"南部\"\n    ws.Range(\"C6\").Value = \"產品A\"\n    ws.Range(\"D6\").Value = 90\n    ws.Range(\"E6\").Value = 50\n    ws.Range(\"F6\").Value = 4500\n\n    ws.Range(\"A7\").Value = DateSerial(2026, 3, 20)\n    ws.Range(\"B7\").Value = \"中部\"\n    ws.Range(\"C7\").Value = \"產品B\"\n    ws.Range(\"D7\").Value = 150\n    ws.Range(\"E7\").Value = 75\n    ws.Range(\"F7\").Value = 11250\n\n    ws.Range(\"A8\").Value = DateSerial(2026, 4, 5)\n    ws.Range(\"B8\").Value = \"北部\"\n    ws.Range(\"C8\").Value = \"產品A\"\n    ws.Range(\"D8\").Value = 200\n    ws.Range(\"E8\").Value = 50\n    ws.Range(\"F8\").Value = 10000\n\n    ws.Range(\"A9\").Value = DateSerial(2026, 4, 18)\n    ws.Range(\"B9\").Value = \"南部\"\n    ws.Range(\"C9\").Value = \"產品B\"\n    ws.Range(\"D9\").Value = 110\n    ws.Range(\"E9\").Value = 75\n    ws.Range(\"F9\").Value = 8250\n\n    ws.Columns(\"A\").NumberFormat = \"yyyy/m/d\"\n    ws.Columns(\"A:F\").AutoFit\nEnd Sub\n\n' 取得或建立工作表，並清除內容\nPrivate Function GetOrCreateSheet(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add\n        ws.Name = sheetName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreateSheet = ws\nEnd Function\n", "content_b64": ""}, {"name": "MultipleConsolidationPivot.bas", "path": "模組/PivotTableAnalysis/MultipleConsolidationPivot.bas", "content": "Attribute VB_Name = \"MultipleConsolidationPivot\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: MultipleConsolidationPivot\n'功能說明: 將多個來源工作表資料合併後建立樞紐分析表\n'\n'著作權所有: Dunk\n'程式設計: Dunk\n'撰寫日期: 2026/5/7\n'\n'*************************************************************************************\n\n' 測試用入口\nSub TestMultipleConsolidationPivot()\n    Call CreateMultipleConsolidationPivot\nEnd Sub\n\n' 建立多重來源資料彙整後的樞紐分析表\nSub CreateMultipleConsolidationPivot()\n    Dim wsQ1 As Worksheet\n    Dim wsQ2 As Worksheet\n    Dim wsCombined As Worksheet\n    Dim wsPivot As Worksheet\n    Dim pc As PivotCache\n    Dim pt As PivotTable\n\n    Set wsQ1 = GetOrCreateSheet(ThisWorkbook, \"Q1銷售\")\n    Set wsQ2 = GetOrCreateSheet(ThisWorkbook, \"Q2銷售\")\n    Call FillQ1Data(wsQ1)\n    Call FillQ2Data(wsQ2)\n\n    Set wsCombined = GetOrCreateSheet(ThisWorkbook, \"合併資料來源\")\n    Call CombineSourceData(wsQ1, wsQ2, wsCombined)\n\n    Set wsPivot = GetOrCreateSheet(ThisWorkbook, \"多重彙總樞紐\")\n\n    Set pc = ThisWorkbook.PivotCaches.Create( _\n        SourceType:=xlDatabase, _\n        SourceData:=wsCombined.Range(\"A1\").CurrentRegion)\n\n    Set pt = pc.CreatePivotTable( _\n        TableDestination:=wsPivot.Range(\"A3\"), _\n        TableName:=\"多重彙總樞紐\")\n\n    With pt.PivotFields(\"季度\")\n        .Orientation = xlRowField\n        .Position = 1\n    End With\n\n    With pt.PivotFields(\"地區\")\n        .Orientation = xlColumnField\n        .Position = 1\n    End With\n\n    pt.AddDataField pt.PivotFields(\"銷售額\"), \"銷售額合計\", xlSum\n\n    wsPivot.Activate\n    MsgBox \"多重彙總樞紐分析表已建立完成！\", vbInformation, \"完成\"\nEnd Sub\n\n' 合併兩個來源工作表的資料\nPrivate Sub CombineSourceData(ByVal ws1 As Worksheet, ByVal ws2 As Worksheet, _\n                               ByVal wsOut As Worksheet)\n    Dim lastRow1 As Long\n    Dim lastRow2 As Long\n\n    lastRow1 = ws1.Cells(ws1.Rows.Count, 1).End(xlUp).Row\n    ws1.Range(\"A1\").Resize(lastRow1, 3).Copy Destination:=wsOut.Cells(1, 1)\n\n    lastRow2 = ws2.Cells(ws2.Rows.Count, 1).End(xlUp).Row\n    If lastRow2 >= 2 Then\n        ws2.Range(\"A2\").Resize(lastRow2 - 1, 3).Copy Destination:=wsOut.Cells(lastRow1 + 1, 1)\n    End If\n\n    wsOut.Columns(\"A:C\").AutoFit\nEnd Sub\n\n' 填入 Q1 銷售資料\nPrivate Sub FillQ1Data(ByVal ws As Worksheet)\n    ws.Range(\"A1\").Value = \"季度\"\n    ws.Range(\"B1\").Value = \"地區\"\n    ws.Range(\"C1\").Value = \"銷售額\"\n    ws.Range(\"A2\").Value = \"Q1\"\n    ws.Range(\"B2\").Value = \"北區\"\n    ws.Range(\"C2\").Value = 80000\n    ws.Range(\"A3\").Value = \"Q1\"\n    ws.Range(\"B3\").Value = \"南區\"\n    ws.Range(\"C3\").Value = 65000\n    ws.Range(\"A4\").Value = \"Q1\"\n    ws.Range(\"B4\").Value = \"東區\"\n    ws.Range(\"C4\").Value = 72000\n    ws.Columns(\"A:C\").AutoFit\nEnd Sub\n\n' 填入 Q2 銷售資料\nPrivate Sub FillQ2Data(ByVal ws As Worksheet)\n    ws.Range(\"A1\").Value = \"季度\"\n    ws.Range(\"B1\").Value = \"地區\"\n    ws.Range(\"C1\").Value = \"銷售額\"\n    ws.Range(\"A2\").Value = \"Q2\"\n    ws.Range(\"B2\").Value = \"北區\"\n    ws.Range(\"C2\").Value = 95000\n    ws.Range(\"A3\").Value = \"Q2\"\n    ws.Range(\"B3\").Value = \"南區\"\n    ws.Range(\"C3\").Value = 78000\n    ws.Range(\"A4\").Value = \"Q2\"\n    ws.Range(\"B4\").Value = \"東區\"\n    ws.Range(\"C4\").Value = 88000\n    ws.Columns(\"A:C\").AutoFit\nEnd Sub\n\n' 取得或建立工作表，並清除內容\nPrivate Function GetOrCreateSheet(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add\n        ws.Name = sheetName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreateSheet = ws\nEnd Function\n", "content_b64": ""}, {"name": "NumberFormatPivot.bas", "path": "模組/PivotTableAnalysis/NumberFormatPivot.bas", "content": "Attribute VB_Name = \"NumberFormatPivot\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: NumberFormatPivot\n'功能說明: 數值欄位格式設定示範\n'          對樞紐分析表的值欄位套用\n'          千分位、小數位數、百分比、貨幣符號等數字格式\n'\n'版權所有: Dunk\n'程式設計: Dunk\n'撰寫日期: 2026/5/6\n'\n'*************************************************************************************\n\n' 程式進入點\nSub TestNumberFormatPivot()\n    Call CreateNumberFormatPivot\nEnd Sub\n\n' 建立多格式值欄位樞紐分析表\nSub CreateNumberFormatPivot()\n    Dim wsData As Worksheet\n    Dim wsPivot As Worksheet\n    Dim pc As PivotCache\n    Dim pt As PivotTable\n    Dim dataRange As Range\n    Dim dfSales As PivotField\n    Dim dfQty As PivotField\n    Dim dfRate As PivotField\n\n    Set wsData = GetOrCreateSheet(ThisWorkbook, \"產品銷售\")\n    Call FillProductData(wsData)\n    Set wsPivot = GetOrCreateSheet(ThisWorkbook, \"數字格式樞紐\")\n\n    Set dataRange = wsData.Range(\"A1\").CurrentRegion\n\n    Set pc = ThisWorkbook.PivotCaches.Create( _\n        SourceType:=xlDatabase, _\n        SourceData:=dataRange)\n    Set pt = pc.CreatePivotTable( _\n        TableDestination:=wsPivot.Range(\"A3\"), _\n        TableName:=\"數字格式樞紐分析表\")\n\n    ' 列欄位：產品\n    With pt.PivotFields(\"產品\")\n        .Orientation = xlRowField\n        .Position = 1\n    End With\n\n    ' 值欄位 1：銷售額（貨幣格式）\n    Set dfSales = pt.AddDataField(pt.PivotFields(\"銷售額\"), \"銷售額\", xlSum)\n    dfSales.NumberFormat = \"NT$#,##0\"\n\n    ' 值欄位 2：數量（整數千分位）\n    Set dfQty = pt.AddDataField(pt.PivotFields(\"數量\"), \"銷售數量\", xlSum)\n    dfQty.NumberFormat = \"#,##0 件\"\n\n    ' 值欄位 3：退貨率（百分比）\n    Set dfRate = pt.AddDataField(pt.PivotFields(\"退貨率\"), \"平均退貨率\", xlAverage)\n    dfRate.NumberFormat = \"0.00%\"\n\n    ' 值欄位排列為欄方向\n    pt.DataPivotField.Orientation = xlColumnField\n\n    wsPivot.Columns(\"A:E\").AutoFit\n    wsPivot.Activate\n    MsgBox \"數字格式樞紐分析表已建立！\" & Chr(13) & _\n           \"分別套用貨幣、千分位計數、百分比格式。\", vbInformation, \"完成\"\nEnd Sub\n\n' 填入產品銷售資料（含退貨率）\nPrivate Sub FillProductData(ByVal ws As Worksheet)\n    ws.Range(\"A1\").Value = \"產品\"\n    ws.Range(\"B1\").Value = \"銷售額\"\n    ws.Range(\"C1\").Value = \"數量\"\n    ws.Range(\"D1\").Value = \"退貨率\"\n\n    ws.Range(\"A2\").Value = \"筆記型電腦\" : ws.Range(\"B2\").Value = 120000 : ws.Range(\"C2\").Value = 10 : ws.Range(\"D2\").Value = 0.02\n    ws.Range(\"A3\").Value = \"智慧型手機\" : ws.Range(\"B3\").Value = 85000  : ws.Range(\"C3\").Value = 17 : ws.Range(\"D3\").Value = 0.035\n    ws.Range(\"A4\").Value = \"平板電腦\"   : ws.Range(\"B4\").Value = 63000  : ws.Range(\"C4\").Value = 9  : ws.Range(\"D4\").Value = 0.015\n    ws.Range(\"A5\").Value = \"筆記型電腦\" : ws.Range(\"B5\").Value = 95000  : ws.Range(\"C5\").Value = 8  : ws.Range(\"D5\").Value = 0.025\n    ws.Range(\"A6\").Value = \"智慧型手機\" : ws.Range(\"B6\").Value = 110000 : ws.Range(\"C6\").Value = 22 : ws.Range(\"D6\").Value = 0.04\n    ws.Range(\"A7\").Value = \"耳機\"       : ws.Range(\"B7\").Value = 28000  : ws.Range(\"C7\").Value = 35 : ws.Range(\"D7\").Value = 0.05\n    ws.Range(\"A8\").Value = \"耳機\"       : ws.Range(\"B8\").Value = 31000  : ws.Range(\"C8\").Value = 40 : ws.Range(\"D8\").Value = 0.045\n    ws.Range(\"A9\").Value = \"平板電腦\"   : ws.Range(\"B9\").Value = 72000  : ws.Range(\"C9\").Value = 12 : ws.Range(\"D9\").Value = 0.02\n\n    ws.Columns(\"A:D\").AutoFit\nEnd Sub\n\n' 取得或建立工作表，並清除內容\nPrivate Function GetOrCreateSheet(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add\n        ws.Name = sheetName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreateSheet = ws\nEnd Function\n", "content_b64": ""}, {"name": "NumberRangeGroupPivot.bas", "path": "模組/PivotTableAnalysis/NumberRangeGroupPivot.bas", "content": "Attribute VB_Name = \"NumberRangeGroupPivot\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: NumberRangeGroupPivot\n'功能說明: 數值欄位自動區間分組示範\n'          將數值欄位（如：單價）依指定區間自動分組\n'          例如：0~999、1000~1999、2000~2999 等\n'\n'版權所有: Dunk\n'程式設計: Dunk\n'撰寫日期: 2026/5/6\n'\n'*************************************************************************************\n\n' 程式進入點\nSub TestNumberRangeGroupPivot()\n    Call CreateNumberRangeGroupPivot\nEnd Sub\n\n' 建立數值區間分組樞紐分析表\nSub CreateNumberRangeGroupPivot()\n    Dim wsData As Worksheet\n    Dim wsPivot As Worksheet\n    Dim pc As PivotCache\n    Dim pt As PivotTable\n    Dim dataRange As Range\n    Dim pf As PivotField\n\n    Set wsData = GetOrCreateSheet(ThisWorkbook, \"訂單明細\")\n    Call FillOrderData(wsData)\n    Set wsPivot = GetOrCreateSheet(ThisWorkbook, \"數值區間群組樞紐\")\n\n    Set dataRange = wsData.Range(\"A1\").CurrentRegion\n\n    Set pc = ThisWorkbook.PivotCaches.Create( _\n        SourceType:=xlDatabase, _\n        SourceData:=dataRange)\n    Set pt = pc.CreatePivotTable( _\n        TableDestination:=wsPivot.Range(\"A3\"), _\n        TableName:=\"數值區間群組樞紐分析表\")\n\n    ' 列欄位：單價（數值，後續群組）\n    With pt.PivotFields(\"單價\")\n        .Orientation = xlRowField\n        .Position = 1\n    End With\n\n    ' 值欄位：訂單數\n    pt.AddDataField pt.PivotFields(\"訂單數\"), \"訂單數合計\", xlSum\n\n    ' 對「單價」欄位進行數值區間自動分組\n    ' 起始值 0、結束值 5000、每段 1000\n    Set pf = pt.PivotFields(\"單價\")\n    pf.AutoGroup\n\n    ' 或使用手動指定區間\n    ' pf.DataRange.Group Start:=0, End:=5000, By:=1000\n\n    wsPivot.Columns(\"A:C\").AutoFit\n    wsPivot.Activate\n    MsgBox \"數值區間群組樞紐分析表已建立！\" & Chr(13) & _\n           \"單價欄位已依數值範圍自動分組。\", vbInformation, \"完成\"\nEnd Sub\n\n' 填入訂單明細資料\nPrivate Sub FillOrderData(ByVal ws As Worksheet)\n    ws.Range(\"A1\").Value = \"訂單編號\"\n    ws.Range(\"B1\").Value = \"單價\"\n    ws.Range(\"C1\").Value = \"訂單數\"\n\n    ws.Range(\"A2\").Value = \"ORD001\" : ws.Range(\"B2\").Value = 250   : ws.Range(\"C2\").Value = 5\n    ws.Range(\"A3\").Value = \"ORD002\" : ws.Range(\"B3\").Value = 1200  : ws.Range(\"C3\").Value = 3\n    ws.Range(\"A4\").Value = \"ORD003\" : ws.Range(\"B4\").Value = 850   : ws.Range(\"C4\").Value = 8\n    ws.Range(\"A5\").Value = \"ORD004\" : ws.Range(\"B5\").Value = 3500  : ws.Range(\"C5\").Value = 2\n    ws.Range(\"A6\").Value = \"ORD005\" : ws.Range(\"B6\").Value = 480   : ws.Range(\"C6\").Value = 12\n    ws.Range(\"A7\").Value = \"ORD006\" : ws.Range(\"B7\").Value = 2200  : ws.Range(\"C7\").Value = 4\n    ws.Range(\"A8\").Value = \"ORD007\" : ws.Range(\"B8\").Value = 990   : ws.Range(\"C8\").Value = 6\n    ws.Range(\"A9\").Value = \"ORD008\" : ws.Range(\"B9\").Value = 4800  : ws.Range(\"C9\").Value = 1\n    ws.Range(\"A10\").Value = \"ORD009\" : ws.Range(\"B10\").Value = 1750 : ws.Range(\"C10\").Value = 9\n    ws.Range(\"A11\").Value = \"ORD010\" : ws.Range(\"B11\").Value = 320  : ws.Range(\"C11\").Value = 15\n\n    ws.Columns(\"A:C\").AutoFit\nEnd Sub\n\n' 取得或建立工作表，並清除內容\nPrivate Function GetOrCreateSheet(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add\n        ws.Name = sheetName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreateSheet = ws\nEnd Function\n", "content_b64": ""}, {"name": "PageFieldPivot.bas", "path": "模組/PivotTableAnalysis/PageFieldPivot.bas", "content": "Attribute VB_Name = \"PageFieldPivot\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: PageFieldPivot\n'功能說明: 頁面欄位（報表篩選）操作示範\n'          設定報表篩選欄位，並示範以 VBA 逐一切換篩選值\n'          以及使用 ShowPages 依篩選值自動產生各頁工作表\n'\n'版權所有: Dunk\n'程式設計: Dunk\n'撰寫日期: 2026/5/6\n'\n'*************************************************************************************\n\n' 程式進入點\nSub TestPageFieldPivot()\n    Call CreatePageFieldPivot\nEnd Sub\n\n' 建立含頁面欄位的樞紐分析表，並示範切換篩選值\nSub CreatePageFieldPivot()\n    Dim wsData As Worksheet\n    Dim wsPivot As Worksheet\n    Dim pc As PivotCache\n    Dim pt As PivotTable\n    Dim dataRange As Range\n    Dim pf As PivotField\n    Dim pi As PivotItem\n\n    Set wsData = GetOrCreateSheet(ThisWorkbook, \"年度銷售\")\n    Call FillYearData(wsData)\n    Set wsPivot = GetOrCreateSheet(ThisWorkbook, \"頁面欄位樞紐\")\n\n    Set dataRange = wsData.Range(\"A1\").CurrentRegion\n\n    Set pc = ThisWorkbook.PivotCaches.Create( _\n        SourceType:=xlDatabase, _\n        SourceData:=dataRange)\n    Set pt = pc.CreatePivotTable( _\n        TableDestination:=wsPivot.Range(\"A3\"), _\n        TableName:=\"頁面欄位樞紐分析表\")\n\n    ' 頁面欄位（報表篩選）：年度\n    With pt.PivotFields(\"年度\")\n        .Orientation = xlPageField\n        .Position = 1\n    End With\n\n    ' 列欄位：地區\n    With pt.PivotFields(\"地區\")\n        .Orientation = xlRowField\n        .Position = 1\n    End With\n\n    ' 欄欄位：產品\n    With pt.PivotFields(\"產品\")\n        .Orientation = xlColumnField\n        .Position = 1\n    End With\n\n    ' 值欄位：銷售額\n    pt.AddDataField pt.PivotFields(\"銷售額\"), \"銷售額合計\", xlSum\n\n    ' 示範以 VBA 切換頁面篩選值為「2025」\n    Set pf = pt.PivotFields(\"年度\")\n    pf.CurrentPage = \"2025\"\n\n    wsPivot.Columns(\"A:F\").AutoFit\n    wsPivot.Activate\n\n    ' 提示：ShowPages 示範（會產生新工作表，已備註）\n    ' pt.ShowPages FieldName:=\"年度\"\n\n    MsgBox \"頁面欄位樞紐分析表已建立！\" & Chr(13) & _\n           \"目前篩選年度：2025\" & Chr(13) & _\n           \"可修改 CurrentPage 屬性切換其他年度。\", vbInformation, \"完成\"\nEnd Sub\n\n' 填入年度銷售資料\nPrivate Sub FillYearData(ByVal ws As Worksheet)\n    ws.Range(\"A1\").Value = \"年度\"\n    ws.Range(\"B1\").Value = \"地區\"\n    ws.Range(\"C1\").Value = \"產品\"\n    ws.Range(\"D1\").Value = \"銷售額\"\n\n    ws.Range(\"A2\").Value = \"2024\"  : ws.Range(\"B2\").Value = \"北部\" : ws.Range(\"C2\").Value = \"A產品\" : ws.Range(\"D2\").Value = 80000\n    ws.Range(\"A3\").Value = \"2024\"  : ws.Range(\"B3\").Value = \"南部\" : ws.Range(\"C3\").Value = \"A產品\" : ws.Range(\"D3\").Value = 65000\n    ws.Range(\"A4\").Value = \"2024\"  : ws.Range(\"B4\").Value = \"北部\" : ws.Range(\"C4\").Value = \"B產品\" : ws.Range(\"D4\").Value = 72000\n    ws.Range(\"A5\").Value = \"2024\"  : ws.Range(\"B5\").Value = \"南部\" : ws.Range(\"C5\").Value = \"B產品\" : ws.Range(\"D5\").Value = 55000\n    ws.Range(\"A6\").Value = \"2025\"  : ws.Range(\"B6\").Value = \"北部\" : ws.Range(\"C6\").Value = \"A產品\" : ws.Range(\"D6\").Value = 95000\n    ws.Range(\"A7\").Value = \"2025\"  : ws.Range(\"B7\").Value = \"南部\" : ws.Range(\"C7\").Value = \"A產品\" : ws.Range(\"D7\").Value = 78000\n    ws.Range(\"A8\").Value = \"2025\"  : ws.Range(\"B8\").Value = \"北部\" : ws.Range(\"C8\").Value = \"B產品\" : ws.Range(\"D8\").Value = 88000\n    ws.Range(\"A9\").Value = \"2025\"  : ws.Range(\"B9\").Value = \"南部\" : ws.Range(\"C9\").Value = \"B產品\" : ws.Range(\"D9\").Value = 69000\n\n    ws.Columns(\"A:D\").AutoFit\nEnd Sub\n\n' 取得或建立工作表，並清除內容\nPrivate Function GetOrCreateSheet(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add\n        ws.Name = sheetName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreateSheet = ws\nEnd Function\n", "content_b64": ""}, {"name": "PercentagePivotTable.bas", "path": "模組/PivotTableAnalysis/PercentagePivotTable.bas", "content": "Attribute VB_Name = \"PercentagePivotTable\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: PercentagePivotTable\n'功能說明: 樞紐分析表值欄位顯示方式：佔總計百分比\n'\n'版權所有: Dunk\n'程式設計: Dunk\n'撰寫日期: 2026/5/3\n'\n'*************************************************************************************\n\n' 測試入口\nSub TestPercentagePivotTable()\n    Call CreatePercentagePivotTable\nEnd Sub\n\n' 建立百分比顯示的樞紐分析表\n' 加入銷售額加總及佔總計百分比兩個值欄位\nSub CreatePercentagePivotTable()\n    Dim wsData As Worksheet\n    Dim wsPivot As Worksheet\n    Dim pc As PivotCache\n    Dim pt As PivotTable\n    Dim dataRange As Range\n    Dim pfSum As PivotField\n    Dim pfPct As PivotField\n\n    ' 準備工作表\n    Set wsData = GetOrCreateSheet(ThisWorkbook, \"銷售資料\")\n    Call FillSalesData(wsData)\n    Set wsPivot = GetOrCreateSheet(ThisWorkbook, \"百分比樞紐\")\n\n    Set dataRange = wsData.Range(\"A1\").CurrentRegion\n\n    Set pc = ThisWorkbook.PivotCaches.Create( _\n        SourceType:=xlDatabase, _\n        SourceData:=dataRange)\n    Set pt = pc.CreatePivotTable( _\n        TableDestination:=wsPivot.Range(\"A3\"), _\n        TableName:=\"百分比樞紐分析表\")\n\n    ' 列欄位：地區\n    With pt.PivotFields(\"地區\")\n        .Orientation = xlRowField\n        .Position = 1\n    End With\n\n    ' 欄欄位：產品\n    With pt.PivotFields(\"產品\")\n        .Orientation = xlColumnField\n        .Position = 1\n    End With\n\n    ' 值欄位 1：銷售額加總（原始金額）\n    Set pfSum = pt.AddDataField(pt.PivotFields(\"銷售額\"), \"銷售額加總\", xlSum)\n    pfSum.NumberFormat = \"#,##0\"\n\n    ' 值欄位 2：銷售額佔總計百分比\n    Set pfPct = pt.AddDataField(pt.PivotFields(\"銷售額\"), \"銷售額佔比\", xlSum)\n    pfPct.Calculation = xlPercentOfTotal\n    pfPct.NumberFormat = \"0.00%\"\n\n    wsPivot.Activate\n    MsgBox \"百分比樞紐分析表已建立完成！右側欄位顯示佔總計百分比。\", vbInformation, \"完成\"\nEnd Sub\n\n' 填入範例銷售資料（共 8 筆：日期、地區、產品、數量、單價、銷售額）\nPrivate Sub FillSalesData(ByVal ws As Worksheet)\n    ws.Range(\"A1\").Value = \"日期\"\n    ws.Range(\"B1\").Value = \"地區\"\n    ws.Range(\"C1\").Value = \"產品\"\n    ws.Range(\"D1\").Value = \"數量\"\n    ws.Range(\"E1\").Value = \"單價\"\n    ws.Range(\"F1\").Value = \"銷售額\"\n\n    ws.Range(\"A2\").Value = DateSerial(2026, 1, 5)\n    ws.Range(\"B2\").Value = \"北部\"\n    ws.Range(\"C2\").Value = \"產品A\"\n    ws.Range(\"D2\").Value = 100\n    ws.Range(\"E2\").Value = 50\n    ws.Range(\"F2\").Value = 5000\n\n    ws.Range(\"A3\").Value = DateSerial(2026, 1, 10)\n    ws.Range(\"B3\").Value = \"南部\"\n    ws.Range(\"C3\").Value = \"產品B\"\n    ws.Range(\"D3\").Value = 80\n    ws.Range(\"E3\").Value = 75\n    ws.Range(\"F3\").Value = 6000\n\n    ws.Range(\"A4\").Value = DateSerial(2026, 2, 5)\n    ws.Range(\"B4\").Value = \"北部\"\n    ws.Range(\"C4\").Value = \"產品B\"\n    ws.Range(\"D4\").Value = 60\n    ws.Range(\"E4\").Value = 75\n    ws.Range(\"F4\").Value = 4500\n\n    ws.Range(\"A5\").Value = DateSerial(2026, 2, 15)\n    ws.Range(\"B5\").Value = \"中部\"\n    ws.Range(\"C5\").Value = \"產品A\"\n    ws.Range(\"D5\").Value = 120\n    ws.Range(\"E5\").Value = 50\n    ws.Range(\"F5\").Value = 6000\n\n    ws.Range(\"A6\").Value = DateSerial(2026, 3, 1)\n    ws.Range(\"B6\").Value = \"南部\"\n    ws.Range(\"C6\").Value = \"產品A\"\n    ws.Range(\"D6\").Value = 90\n    ws.Range(\"E6\").Value = 50\n    ws.Range(\"F6\").Value = 4500\n\n    ws.Range(\"A7\").Value = DateSerial(2026, 3, 20)\n    ws.Range(\"B7\").Value = \"中部\"\n    ws.Range(\"C7\").Value = \"產品B\"\n    ws.Range(\"D7\").Value = 150\n    ws.Range(\"E7\").Value = 75\n    ws.Range(\"F7\").Value = 11250\n\n    ws.Range(\"A8\").Value = DateSerial(2026, 4, 5)\n    ws.Range(\"B8\").Value = \"北部\"\n    ws.Range(\"C8\").Value = \"產品A\"\n    ws.Range(\"D8\").Value = 200\n    ws.Range(\"E8\").Value = 50\n    ws.Range(\"F8\").Value = 10000\n\n    ws.Range(\"A9\").Value = DateSerial(2026, 4, 18)\n    ws.Range(\"B9\").Value = \"南部\"\n    ws.Range(\"C9\").Value = \"產品B\"\n    ws.Range(\"D9\").Value = 110\n    ws.Range(\"E9\").Value = 75\n    ws.Range(\"F9\").Value = 8250\n\n    ws.Columns(\"A\").NumberFormat = \"yyyy/m/d\"\n    ws.Columns(\"A:F\").AutoFit\nEnd Sub\n\n' 取得或建立工作表，並清除內容\nPrivate Function GetOrCreateSheet(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add\n        ws.Name = sheetName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreateSheet = ws\nEnd Function\n", "content_b64": ""}, {"name": "PivotChartCreate.bas", "path": "模組/PivotTableAnalysis/PivotChartCreate.bas", "content": "Attribute VB_Name = \"PivotChartCreate\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: PivotChartCreate\n'功能說明: 從樞紐分析表建立樞紐分析圖（PivotChart），\n'          圖表類型為群組直條圖，並設定標題\n'\n'版權所有: Dunk\n'程式設計: Dunk\n'撰寫日期: 2026/5/4\n'\n'*************************************************************************************\n\n' 測試入口\nSub TestPivotChartCreate()\n    Call CreatePivotChart\nEnd Sub\n\n' 建立樞紐分析表並同步產生樞紐分析圖\nSub CreatePivotChart()\n    Dim wsData    As Worksheet\n    Dim wsPivot   As Worksheet\n    Dim pc        As PivotCache\n    Dim pt        As PivotTable\n    Dim dataRange As Range\n    Dim chtObj    As ChartObject\n    Dim cht       As Chart\n\n    ' 準備資料工作表\n    Set wsData = GetOrCreateSheet(ThisWorkbook, \"銷售資料\")\n    Call FillSalesData(wsData)\n\n    ' 準備樞紐工作表\n    Set wsPivot = GetOrCreateSheet(ThisWorkbook, \"樞紐分析圖\")\n\n    Set dataRange = wsData.Range(\"A1\").CurrentRegion\n\n    Set pc = ThisWorkbook.PivotCaches.Create( _\n        SourceType:=xlDatabase, _\n        SourceData:=dataRange)\n    Set pt = pc.CreatePivotTable( _\n        TableDestination:=wsPivot.Range(\"A3\"), _\n        TableName:=\"樞紐分析圖表\")\n\n    ' 列欄位: 地區\n    With pt.PivotFields(\"地區\")\n        .Orientation = xlRowField\n        .Position = 1\n    End With\n\n    ' 欄欄位: 產品\n    With pt.PivotFields(\"產品\")\n        .Orientation = xlColumnField\n        .Position = 1\n    End With\n\n    ' 值欄位: 銷售額加總\n    pt.AddDataField pt.PivotFields(\"銷售額\"), \"銷售額加總\", xlSum\n\n    ' 在工作表上插入圖表物件\n    Set chtObj = wsPivot.ChartObjects.Add( _\n        Left:=300, Top:=50, Width:=400, Height:=250)\n    Set cht = chtObj.Chart\n\n    ' 將圖表資料來源設定為樞紐分析表\n    cht.SetSourceData Source:=pt.TableRange1\n    cht.ChartType = xlColumnClustered\n\n    ' 設定圖表標題\n    cht.HasTitle = True\n    cht.ChartTitle.Text = \"各地區產品銷售額樞紐分析圖\"\n\n    ' 設定座標軸標題\n    With cht.Axes(xlCategory)\n        .HasTitle = True\n        .AxisTitle.Text = \"地區\"\n    End With\n    With cht.Axes(xlValue)\n        .HasTitle = True\n        .AxisTitle.Text = \"銷售額\"\n    End With\n\n    ' 顯示圖例\n    cht.HasLegend = True\n    cht.Legend.Position = xlLegendPositionBottom\n\n    wsPivot.Activate\n    MsgBox \"樞紐分析圖已建立完成！\" & Chr(13) & _\n           \"圖表類型：群組直條圖。\", _\n           vbInformation, \"完成\"\nEnd Sub\n\n' 填入範例銷售資料（8筆：日期、地區、產品、數量、單價、銷售額）\nPrivate Sub FillSalesData(ByVal ws As Worksheet)\n    ws.Range(\"A1\").Value = \"日期\"\n    ws.Range(\"B1\").Value = \"地區\"\n    ws.Range(\"C1\").Value = \"產品\"\n    ws.Range(\"D1\").Value = \"數量\"\n    ws.Range(\"E1\").Value = \"單價\"\n    ws.Range(\"F1\").Value = \"銷售額\"\n\n    ws.Range(\"A2\").Value = DateSerial(2026, 1, 5)\n    ws.Range(\"B2\").Value = \"北區\"\n    ws.Range(\"C2\").Value = \"產品A\"\n    ws.Range(\"D2\").Value = 100\n    ws.Range(\"E2\").Value = 50\n    ws.Range(\"F2\").Value = 5000\n\n    ws.Range(\"A3\").Value = DateSerial(2026, 1, 10)\n    ws.Range(\"B3\").Value = \"南區\"\n    ws.Range(\"C3\").Value = \"產品B\"\n    ws.Range(\"D3\").Value = 80\n    ws.Range(\"E3\").Value = 75\n    ws.Range(\"F3\").Value = 6000\n\n    ws.Range(\"A4\").Value = DateSerial(2026, 2, 5)\n    ws.Range(\"B4\").Value = \"北區\"\n    ws.Range(\"C4\").Value = \"產品B\"\n    ws.Range(\"D4\").Value = 60\n    ws.Range(\"E4\").Value = 75\n    ws.Range(\"F4\").Value = 4500\n\n    ws.Range(\"A5\").Value = DateSerial(2026, 2, 15)\n    ws.Range(\"B5\").Value = \"中區\"\n    ws.Range(\"C5\").Value = \"產品A\"\n    ws.Range(\"D5\").Value = 120\n    ws.Range(\"E5\").Value = 50\n    ws.Range(\"F5\").Value = 6000\n\n    ws.Range(\"A6\").Value = DateSerial(2026, 3, 1)\n    ws.Range(\"B6\").Value = \"南區\"\n    ws.Range(\"C6\").Value = \"產品A\"\n    ws.Range(\"D6\").Value = 90\n    ws.Range(\"E6\").Value = 50\n    ws.Range(\"F6\").Value = 4500\n\n    ws.Range(\"A7\").Value = DateSerial(2026, 3, 20)\n    ws.Range(\"B7\").Value = \"中區\"\n    ws.Range(\"C7\").Value = \"產品B\"\n    ws.Range(\"D7\").Value = 150\n    ws.Range(\"E7\").Value = 75\n    ws.Range(\"F7\").Value = 11250\n\n    ws.Range(\"A8\").Value = DateSerial(2026, 4, 5)\n    ws.Range(\"B8\").Value = \"北區\"\n    ws.Range(\"C8\").Value = \"產品A\"\n    ws.Range(\"D8\").Value = 200\n    ws.Range(\"E8\").Value = 50\n    ws.Range(\"F8\").Value = 10000\n\n    ws.Range(\"A9\").Value = DateSerial(2026, 4, 18)\n    ws.Range(\"B9\").Value = \"南區\"\n    ws.Range(\"C9\").Value = \"產品B\"\n    ws.Range(\"D9\").Value = 110\n    ws.Range(\"E9\").Value = 75\n    ws.Range(\"F9\").Value = 8250\n\n    ws.Columns(\"A\").NumberFormat = \"yyyy/m/d\"\n    ws.Columns(\"A:F\").AutoFit\nEnd Sub\n\n' 取得或建立工作表，並清除現有內容\nPrivate Function GetOrCreateSheet(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add\n        ws.Name = sheetName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreateSheet = ws\nEnd Function\n", "content_b64": ""}, {"name": "PivotFromNamedRange.bas", "path": "模組/PivotTableAnalysis/PivotFromNamedRange.bas", "content": "Option Explicit\n\n' 使用命名範圍建立樞紐分析表，示範來源範圍命名與彙總欄位設定。\nPublic Sub CreatePivotFromNamedRangeExample()\n    On Error GoTo ErrHandler\n\n    Dim dataWs As Worksheet\n    Dim pivotWs As Worksheet\n    Dim sourceRange As Range\n    Dim pivotCache As PivotCache\n    Dim pivotTable As PivotTable\n\n    Set dataWs = GetOrCreatePivotWorksheet(\"命名範圍資料\")\n    Set pivotWs = GetOrCreatePivotWorksheet(\"命名範圍樞紐\")\n    dataWs.Cells.Clear\n    pivotWs.Cells.Clear\n\n    Call FillPivotNamedRangeData(dataWs)\n    Set sourceRange = dataWs.Range(\"A1\").CurrentRegion\n    ThisWorkbook.Names.Add Name:=\"SalesNamedRange\", RefersTo:=sourceRange\n\n    Set pivotCache = ThisWorkbook.PivotCaches.Create(SourceType:=xlDatabase, SourceData:=\"SalesNamedRange\")\n    Set pivotTable = pivotCache.CreatePivotTable(TableDestination:=pivotWs.Range(\"A3\"), TableName:=\"NamedRangePivot\")\n\n    With pivotTable\n        .PivotFields(\"區域\").Orientation = xlRowField\n        .PivotFields(\"產品\").Orientation = xlColumnField\n        .AddDataField .PivotFields(\"金額\"), \"金額合計\", xlSum\n        .DataFields(1).NumberFormat = \"#,##0\"\n        .RowAxisLayout xlTabularRow\n    End With\n\n    pivotWs.Columns.AutoFit\n    MsgBox \"命名範圍樞紐分析表已建立完成。\", vbInformation, \"完成\"\n    Exit Sub\n\nErrHandler:\n    MsgBox \"建立樞紐分析表失敗：\" & Err.Description, vbExclamation, \"錯誤\"\nEnd Sub\n\nPrivate Sub FillPivotNamedRangeData(ByVal ws As Worksheet)\n    ws.Range(\"A1:D1\").Value = Array(\"區域\", \"產品\", \"業務\", \"金額\")\n    ws.Range(\"A2:D2\").Value = Array(\"北區\", \"A\", \"王小明\", 12000)\n    ws.Range(\"A3:D3\").Value = Array(\"北區\", \"B\", \"王小明\", 9500)\n    ws.Range(\"A4:D4\").Value = Array(\"中區\", \"A\", \"陳美華\", 13800)\n    ws.Range(\"A5:D5\").Value = Array(\"中區\", \"B\", \"陳美華\", 11200)\n    ws.Range(\"A6:D6\").Value = Array(\"南區\", \"A\", \"林志強\", 15600)\n    ws.Range(\"A7:D7\").Value = Array(\"南區\", \"B\", \"林志強\", 10100)\nEnd Sub\n\nPrivate Function GetOrCreatePivotWorksheet(ByVal sheetName As String) As Worksheet\n    On Error Resume Next\n    Set GetOrCreatePivotWorksheet = ThisWorkbook.Worksheets(sheetName)\n    On Error GoTo 0\n\n    If GetOrCreatePivotWorksheet Is Nothing Then\n        Set GetOrCreatePivotWorksheet = ThisWorkbook.Worksheets.Add\n        GetOrCreatePivotWorksheet.Name = sheetName\n    End If\nEnd Function", "content_b64": ""}, {"name": "PivotStylePivot.bas", "path": "模組/PivotTableAnalysis/PivotStylePivot.bas", "content": "Attribute VB_Name = \"PivotStylePivot\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: PivotStylePivot\n'功能說明: 樞紐分析表樣式套用示範\n'          示範套用 Excel 內建 PivotTable 樣式\n'          包含 Light / Medium / Dark 系列\n'          並開啟帶狀列與標題列格式\n'\n'版權所有: Dunk\n'程式設計: Dunk\n'撰寫日期: 2026/5/6\n'\n'*************************************************************************************\n\n' 程式進入點\nSub TestPivotStylePivot()\n    Call CreatePivotWithStyles\nEnd Sub\n\n' 建立樞紐分析表並套用內建樣式\nSub CreatePivotWithStyles()\n    Dim wsData As Worksheet\n    Dim wsPivot As Worksheet\n    Dim pc As PivotCache\n    Dim pt As PivotTable\n    Dim dataRange As Range\n    Dim df As PivotField\n\n    Set wsData = GetOrCreateSheet(ThisWorkbook, \"部門費用\")\n    Call FillDeptData(wsData)\n    Set wsPivot = GetOrCreateSheet(ThisWorkbook, \"樣式樞紐\")\n\n    Set dataRange = wsData.Range(\"A1\").CurrentRegion\n\n    Set pc = ThisWorkbook.PivotCaches.Create( _\n        SourceType:=xlDatabase, _\n        SourceData:=dataRange)\n    Set pt = pc.CreatePivotTable( _\n        TableDestination:=wsPivot.Range(\"A3\"), _\n        TableName:=\"樣式樞紐分析表\")\n\n    ' 列欄位：部門\n    With pt.PivotFields(\"部門\")\n        .Orientation = xlRowField\n        .Position = 1\n    End With\n\n    ' 欄欄位：費用類型\n    With pt.PivotFields(\"費用類型\")\n        .Orientation = xlColumnField\n        .Position = 1\n    End With\n\n    ' 值欄位：金額\n    Set df = pt.AddDataField(pt.PivotFields(\"金額\"), \"金額合計\", xlSum)\n    df.NumberFormat = \"#,##0\"\n\n    ' 套用內建樣式（Medium 藍色系）\n    pt.TableStyle2 = \"PivotStyleMedium2\"\n\n    ' 顯示帶狀列\n    pt.ShowTableStyleColumnHeaders = True\n    pt.ShowTableStyleRowHeaders = True\n    pt.ShowTableStyleRowStripes = True\n\n    ' 其他可用樣式（取消下方註解即可切換）\n    ' pt.TableStyle2 = \"PivotStyleLight16\"   ' 淺色\n    ' pt.TableStyle2 = \"PivotStyleDark1\"     ' 深色\n    ' pt.TableStyle2 = \"PivotStyleMedium9\"   ' 橘色\n\n    wsPivot.Columns(\"A:F\").AutoFit\n    wsPivot.Activate\n    MsgBox \"樣式樞紐分析表已建立！\" & Chr(13) & _\n           \"目前套用：PivotStyleMedium2\" & Chr(13) & _\n           \"可修改 TableStyle2 屬性切換其他樣式。\", vbInformation, \"完成\"\nEnd Sub\n\n' 填入部門費用資料\nPrivate Sub FillDeptData(ByVal ws As Worksheet)\n    ws.Range(\"A1\").Value = \"部門\"\n    ws.Range(\"B1\").Value = \"費用類型\"\n    ws.Range(\"C1\").Value = \"金額\"\n\n    ws.Range(\"A2\").Value = \"業務部\" : ws.Range(\"B2\").Value = \"差旅費\" : ws.Range(\"C2\").Value = 25000\n    ws.Range(\"A3\").Value = \"業務部\" : ws.Range(\"B3\").Value = \"交際費\" : ws.Range(\"C3\").Value = 18000\n    ws.Range(\"A4\").Value = \"業務部\" : ws.Range(\"B4\").Value = \"辦公費\" : ws.Range(\"C4\").Value = 5000\n    ws.Range(\"A5\").Value = \"研發部\" : ws.Range(\"B5\").Value = \"差旅費\" : ws.Range(\"C5\").Value = 12000\n    ws.Range(\"A6\").Value = \"研發部\" : ws.Range(\"B6\").Value = \"辦公費\" : ws.Range(\"C6\").Value = 15000\n    ws.Range(\"A7\").Value = \"研發部\" : ws.Range(\"B7\").Value = \"設備費\" : ws.Range(\"C7\").Value = 45000\n    ws.Range(\"A8\").Value = \"管理部\" : ws.Range(\"B8\").Value = \"差旅費\" : ws.Range(\"C8\").Value = 8000\n    ws.Range(\"A9\").Value = \"管理部\" : ws.Range(\"B9\").Value = \"交際費\" : ws.Range(\"C9\").Value = 6000\n    ws.Range(\"A10\").Value = \"管理部\" : ws.Range(\"B10\").Value = \"辦公費\" : ws.Range(\"C10\").Value = 9000\n\n    ws.Columns(\"A:C\").AutoFit\nEnd Sub\n\n' 取得或建立工作表，並清除內容\nPrivate Function GetOrCreateSheet(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add\n        ws.Name = sheetName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreateSheet = ws\nEnd Function\n", "content_b64": ""}, {"name": "RankPivotTable.bas", "path": "模組/PivotTableAnalysis/RankPivotTable.bas", "content": "Attribute VB_Name = \"RankPivotTable\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: RankPivotTable\n'功能說明: 樞紐分析表排名顯示（xlRankAscending，排名 1 = 最小值）\n'\n'版權所有: Dunk\n'程式設計: Dunk\n'撰寫日期: 2026/5/3\n'\n'*************************************************************************************\n\n' 測試入口\nSub TestRankPivotTable()\n    Call CreateRankPivotTable\nEnd Sub\n\n' 建立排名樞紐分析表\n' 同時顯示銷售額加總與排名（由小到大）\nSub CreateRankPivotTable()\n    Dim wsData As Worksheet\n    Dim wsPivot As Worksheet\n    Dim pc As PivotCache\n    Dim pt As PivotTable\n    Dim dataRange As Range\n    Dim pfSum As PivotField\n    Dim pfRank As PivotField\n\n    ' 準備工作表\n    Set wsData = GetOrCreateSheet(ThisWorkbook, \"銷售資料\")\n    Call FillSalesData(wsData)\n    Set wsPivot = GetOrCreateSheet(ThisWorkbook, \"排名樞紐\")\n\n    Set dataRange = wsData.Range(\"A1\").CurrentRegion\n\n    Set pc = ThisWorkbook.PivotCaches.Create( _\n        SourceType:=xlDatabase, _\n        SourceData:=dataRange)\n    Set pt = pc.CreatePivotTable( _\n        TableDestination:=wsPivot.Range(\"A3\"), _\n        TableName:=\"排名樞紐分析表\")\n\n    ' 列欄位：地區\n    With pt.PivotFields(\"地區\")\n        .Orientation = xlRowField\n        .Position = 1\n    End With\n\n    ' 欄欄位：產品\n    With pt.PivotFields(\"產品\")\n        .Orientation = xlColumnField\n        .Position = 1\n    End With\n\n    ' 值欄位 1：銷售額加總（原始金額）\n    Set pfSum = pt.AddDataField(pt.PivotFields(\"銷售額\"), \"銷售額加總\", xlSum)\n    pfSum.NumberFormat = \"#,##0\"\n\n    ' 值欄位 2：銷售額排名（由小到大，排名 1 = 最小值）\n    ' xlRankAscending = 14\n    Set pfRank = pt.AddDataField(pt.PivotFields(\"銷售額\"), \"銷售額排名\", xlSum)\n    pfRank.Calculation = xlRankAscending\n    pfRank.NumberFormat = \"#,##0\"\n\n    wsPivot.Activate\n    MsgBox \"排名樞紐分析表已建立完成！（排名 1 = 最小銷售額）\", vbInformation, \"完成\"\nEnd Sub\n\n' 填入範例銷售資料（共 8 筆：日期、地區、產品、數量、單價、銷售額）\nPrivate Sub FillSalesData(ByVal ws As Worksheet)\n    ws.Range(\"A1\").Value = \"日期\"\n    ws.Range(\"B1\").Value = \"地區\"\n    ws.Range(\"C1\").Value = \"產品\"\n    ws.Range(\"D1\").Value = \"數量\"\n    ws.Range(\"E1\").Value = \"單價\"\n    ws.Range(\"F1\").Value = \"銷售額\"\n\n    ws.Range(\"A2\").Value = DateSerial(2026, 1, 5)\n    ws.Range(\"B2\").Value = \"北部\"\n    ws.Range(\"C2\").Value = \"產品A\"\n    ws.Range(\"D2\").Value = 100\n    ws.Range(\"E2\").Value = 50\n    ws.Range(\"F2\").Value = 5000\n\n    ws.Range(\"A3\").Value = DateSerial(2026, 1, 10)\n    ws.Range(\"B3\").Value = \"南部\"\n    ws.Range(\"C3\").Value = \"產品B\"\n    ws.Range(\"D3\").Value = 80\n    ws.Range(\"E3\").Value = 75\n    ws.Range(\"F3\").Value = 6000\n\n    ws.Range(\"A4\").Value = DateSerial(2026, 2, 5)\n    ws.Range(\"B4\").Value = \"北部\"\n    ws.Range(\"C4\").Value = \"產品B\"\n    ws.Range(\"D4\").Value = 60\n    ws.Range(\"E4\").Value = 75\n    ws.Range(\"F4\").Value = 4500\n\n    ws.Range(\"A5\").Value = DateSerial(2026, 2, 15)\n    ws.Range(\"B5\").Value = \"中部\"\n    ws.Range(\"C5\").Value = \"產品A\"\n    ws.Range(\"D5\").Value = 120\n    ws.Range(\"E5\").Value = 50\n    ws.Range(\"F5\").Value = 6000\n\n    ws.Range(\"A6\").Value = DateSerial(2026, 3, 1)\n    ws.Range(\"B6\").Value = \"南部\"\n    ws.Range(\"C6\").Value = \"產品A\"\n    ws.Range(\"D6\").Value = 90\n    ws.Range(\"E6\").Value = 50\n    ws.Range(\"F6\").Value = 4500\n\n    ws.Range(\"A7\").Value = DateSerial(2026, 3, 20)\n    ws.Range(\"B7\").Value = \"中部\"\n    ws.Range(\"C7\").Value = \"產品B\"\n    ws.Range(\"D7\").Value = 150\n    ws.Range(\"E7\").Value = 75\n    ws.Range(\"F7\").Value = 11250\n\n    ws.Range(\"A8\").Value = DateSerial(2026, 4, 5)\n    ws.Range(\"B8\").Value = \"北部\"\n    ws.Range(\"C8\").Value = \"產品A\"\n    ws.Range(\"D8\").Value = 200\n    ws.Range(\"E8\").Value = 50\n    ws.Range(\"F8\").Value = 10000\n\n    ws.Range(\"A9\").Value = DateSerial(2026, 4, 18)\n    ws.Range(\"B9\").Value = \"南部\"\n    ws.Range(\"C9\").Value = \"產品B\"\n    ws.Range(\"D9\").Value = 110\n    ws.Range(\"E9\").Value = 75\n    ws.Range(\"F9\").Value = 8250\n\n    ws.Columns(\"A\").NumberFormat = \"yyyy/m/d\"\n    ws.Columns(\"A:F\").AutoFit\nEnd Sub\n\n' 取得或建立工作表，並清除內容\nPrivate Function GetOrCreateSheet(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add\n        ws.Name = sheetName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreateSheet = ws\nEnd Function\n", "content_b64": ""}, {"name": "RefreshPivotTable.bas", "path": "模組/PivotTableAnalysis/RefreshPivotTable.bas", "content": "Attribute VB_Name = \"RefreshPivotTable\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: RefreshPivotTable\n'功能說明: 重新整理樞紐分析表（重新整理單一或活頁簿中所有樞紐分析表）\n'\n'版權所有: Dunk\n'程式設計: Dunk\n'撰寫日期: 2026/5/3\n'\n'*************************************************************************************\n\n' 測試入口：建立基礎樞紐後更新資料並重新整理\nSub TestRefreshPivotTable()\n    Call SetupAndRefreshPivotTable\nEnd Sub\n\n' 建立樞紐、更新來源資料，再重新整理\nSub SetupAndRefreshPivotTable()\n    Dim wsData As Worksheet\n    Dim wsPivot As Worksheet\n    Dim pc As PivotCache\n    Dim pt As PivotTable\n    Dim dataRange As Range\n\n    ' 準備資料工作表\n    Set wsData = GetOrCreateSheet(ThisWorkbook, \"銷售資料\")\n    Call FillSalesData(wsData)\n    Set wsPivot = GetOrCreateSheet(ThisWorkbook, \"重整樞紐\")\n\n    Set dataRange = wsData.Range(\"A1\").CurrentRegion\n\n    Set pc = ThisWorkbook.PivotCaches.Create( _\n        SourceType:=xlDatabase, _\n        SourceData:=dataRange)\n    Set pt = pc.CreatePivotTable( _\n        TableDestination:=wsPivot.Range(\"A3\"), _\n        TableName:=\"重整樞紐分析表\")\n\n    With pt.PivotFields(\"地區\")\n        .Orientation = xlRowField\n        .Position = 1\n    End With\n    With pt.PivotFields(\"產品\")\n        .Orientation = xlColumnField\n        .Position = 1\n    End With\n    pt.AddDataField pt.PivotFields(\"銷售額\"), \"銷售額加總\", xlSum\n\n    ' 模擬新增一筆資料到來源\n    Dim lastRow As Long\n    lastRow = wsData.Cells(wsData.Rows.Count, \"A\").End(xlUp).Row + 1\n    wsData.Cells(lastRow, 1).Value = DateSerial(2026, 5, 1)\n    wsData.Cells(lastRow, 2).Value = \"北部\"\n    wsData.Cells(lastRow, 3).Value = \"產品A\"\n    wsData.Cells(lastRow, 4).Value = 300\n    wsData.Cells(lastRow, 5).Value = 50\n    wsData.Cells(lastRow, 6).Value = 15000\n\n    MsgBox \"已新增一筆資料，即將重新整理樞紐分析表...\", vbInformation, \"提示\"\n\n    ' 更新 PivotCache 資料範圍並重新整理\n    Call RefreshAllPivotTables(ThisWorkbook)\n\n    wsPivot.Activate\n    MsgBox \"所有樞紐分析表已重新整理完成！\", vbInformation, \"完成\"\nEnd Sub\n\n' 重新整理指定活頁簿中所有樞紐分析表\n' wb: 目標活頁簿\nSub RefreshAllPivotTables(ByVal wb As Workbook)\n    Dim ws As Worksheet\n    Dim pt As PivotTable\n    Dim refreshCount As Integer\n\n    refreshCount = 0\n    For Each ws In wb.Worksheets\n        For Each pt In ws.PivotTables\n            pt.PivotCache.Refresh\n            refreshCount = refreshCount + 1\n        Next pt\n    Next ws\n\n    Debug.Print \"共重新整理 \" & refreshCount & \" 個樞紐分析表\"\nEnd Sub\n\n' 重新整理指定工作表中的單一樞紐分析表（依名稱）\n' ws: 目標工作表 / ptName: 樞紐分析表名稱\nSub RefreshSinglePivotTable(ByVal ws As Worksheet, ByVal ptName As String)\n    Dim pt As PivotTable\n    On Error Resume Next\n    Set pt = ws.PivotTables(ptName)\n    On Error GoTo 0\n    If pt Is Nothing Then\n        MsgBox \"找不到樞紐分析表：\" & ptName, vbExclamation, \"錯誤\"\n        Exit Sub\n    End If\n    pt.PivotCache.Refresh\n    MsgBox \"樞紐分析表「\" & ptName & \"」已重新整理。\", vbInformation, \"完成\"\nEnd Sub\n\n' 填入範例銷售資料（共 8 筆：日期、地區、產品、數量、單價、銷售額）\nPrivate Sub FillSalesData(ByVal ws As Worksheet)\n    ws.Range(\"A1\").Value = \"日期\"\n    ws.Range(\"B1\").Value = \"地區\"\n    ws.Range(\"C1\").Value = \"產品\"\n    ws.Range(\"D1\").Value = \"數量\"\n    ws.Range(\"E1\").Value = \"單價\"\n    ws.Range(\"F1\").Value = \"銷售額\"\n\n    ws.Range(\"A2\").Value = DateSerial(2026, 1, 5)\n    ws.Range(\"B2\").Value = \"北部\"\n    ws.Range(\"C2\").Value = \"產品A\"\n    ws.Range(\"D2\").Value = 100\n    ws.Range(\"E2\").Value = 50\n    ws.Range(\"F2\").Value = 5000\n\n    ws.Range(\"A3\").Value = DateSerial(2026, 1, 10)\n    ws.Range(\"B3\").Value = \"南部\"\n    ws.Range(\"C3\").Value = \"產品B\"\n    ws.Range(\"D3\").Value = 80\n    ws.Range(\"E3\").Value = 75\n    ws.Range(\"F3\").Value = 6000\n\n    ws.Range(\"A4\").Value = DateSerial(2026, 2, 5)\n    ws.Range(\"B4\").Value = \"北部\"\n    ws.Range(\"C4\").Value = \"產品B\"\n    ws.Range(\"D4\").Value = 60\n    ws.Range(\"E4\").Value = 75\n    ws.Range(\"F4\").Value = 4500\n\n    ws.Range(\"A5\").Value = DateSerial(2026, 2, 15)\n    ws.Range(\"B5\").Value = \"中部\"\n    ws.Range(\"C5\").Value = \"產品A\"\n    ws.Range(\"D5\").Value = 120\n    ws.Range(\"E5\").Value = 50\n    ws.Range(\"F5\").Value = 6000\n\n    ws.Range(\"A6\").Value = DateSerial(2026, 3, 1)\n    ws.Range(\"B6\").Value = \"南部\"\n    ws.Range(\"C6\").Value = \"產品A\"\n    ws.Range(\"D6\").Value = 90\n    ws.Range(\"E6\").Value = 50\n    ws.Range(\"F6\").Value = 4500\n\n    ws.Range(\"A7\").Value = DateSerial(2026, 3, 20)\n    ws.Range(\"B7\").Value = \"中部\"\n    ws.Range(\"C7\").Value = \"產品B\"\n    ws.Range(\"D7\").Value = 150\n    ws.Range(\"E7\").Value = 75\n    ws.Range(\"F7\").Value = 11250\n\n    ws.Range(\"A8\").Value = DateSerial(2026, 4, 5)\n    ws.Range(\"B8\").Value = \"北部\"\n    ws.Range(\"C8\").Value = \"產品A\"\n    ws.Range(\"D8\").Value = 200\n    ws.Range(\"E8\").Value = 50\n    ws.Range(\"F8\").Value = 10000\n\n    ws.Range(\"A9\").Value = DateSerial(2026, 4, 18)\n    ws.Range(\"B9\").Value = \"南部\"\n    ws.Range(\"C9\").Value = \"產品B\"\n    ws.Range(\"D9\").Value = 110\n    ws.Range(\"E9\").Value = 75\n    ws.Range(\"F9\").Value = 8250\n\n    ws.Columns(\"A\").NumberFormat = \"yyyy/m/d\"\n    ws.Columns(\"A:F\").AutoFit\nEnd Sub\n\n' 取得或建立工作表，並清除內容\nPrivate Function GetOrCreateSheet(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add\n        ws.Name = sheetName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreateSheet = ws\nEnd Function\n", "content_b64": ""}, {"name": "RunningTotalPivot.bas", "path": "模組/PivotTableAnalysis/RunningTotalPivot.bas", "content": "Attribute VB_Name = \"RunningTotalPivot\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: RunningTotalPivot\n'功能說明: 樞紐分析表顯示累計值（Running Total），\n'          以地區為基底欄位，依序累計各產品的銷售額\n'\n'版權所有: Dunk\n'程式設計: Dunk\n'撰寫日期: 2026/5/4\n'\n'*************************************************************************************\n\n' 測試入口\nSub TestRunningTotalPivot()\n    Call CreateRunningTotalPivot\nEnd Sub\n\n' 建立累計值樞紐分析表\n' 功能: 加入原始加總與累計值兩個值欄位\nSub CreateRunningTotalPivot()\n    Dim wsData    As Worksheet\n    Dim wsPivot   As Worksheet\n    Dim pc        As PivotCache\n    Dim pt        As PivotTable\n    Dim dataRange As Range\n    Dim pfSum     As PivotField\n    Dim pfRunning As PivotField\n\n    ' 準備資料工作表\n    Set wsData = GetOrCreateSheet(ThisWorkbook, \"銷售資料\")\n    Call FillSalesData(wsData)\n\n    ' 準備樞紐工作表\n    Set wsPivot = GetOrCreateSheet(ThisWorkbook, \"累計值樞紐\")\n\n    Set dataRange = wsData.Range(\"A1\").CurrentRegion\n\n    Set pc = ThisWorkbook.PivotCaches.Create( _\n        SourceType:=xlDatabase, _\n        SourceData:=dataRange)\n    Set pt = pc.CreatePivotTable( _\n        TableDestination:=wsPivot.Range(\"A3\"), _\n        TableName:=\"累計值樞紐\")\n\n    ' 列欄位: 地區\n    With pt.PivotFields(\"地區\")\n        .Orientation = xlRowField\n        .Position = 1\n    End With\n\n    ' 欄欄位: 產品\n    With pt.PivotFields(\"產品\")\n        .Orientation = xlColumnField\n        .Position = 1\n    End With\n\n    ' 值欄位 1: 銷售額加總（原始值）\n    Set pfSum = pt.AddDataField(pt.PivotFields(\"銷售額\"), \"銷售額加總\", xlSum)\n\n    ' 值欄位 2: 銷售額累計（Running Total）\n    Set pfRunning = pt.AddDataField(pt.PivotFields(\"銷售額\"), \"銷售額累計\", xlSum)\n\n    ' 設定顯示方式為累計（依地區欄位）\n    With pfRunning\n        .Calculation = xlRunningTotal\n        .BaseField = \"地區\"\n    End With\n\n    ' 格式化數值\n    pfSum.NumberFormat = \"#,##0\"\n    pfRunning.NumberFormat = \"#,##0\"\n\n    wsPivot.Activate\n    MsgBox \"累計值樞紐分析表已建立完成！\" & Chr(13) & _\n           \"「銷售額加總」顯示各地區原始值。\" & Chr(13) & _\n           \"「銷售額累計」顯示依地區順序的累計值。\", _\n           vbInformation, \"完成\"\nEnd Sub\n\n' 填入範例銷售資料（8筆：日期、地區、產品、數量、單價、銷售額）\nPrivate Sub FillSalesData(ByVal ws As Worksheet)\n    ws.Range(\"A1\").Value = \"日期\"\n    ws.Range(\"B1\").Value = \"地區\"\n    ws.Range(\"C1\").Value = \"產品\"\n    ws.Range(\"D1\").Value = \"數量\"\n    ws.Range(\"E1\").Value = \"單價\"\n    ws.Range(\"F1\").Value = \"銷售額\"\n\n    ws.Range(\"A2\").Value = DateSerial(2026, 1, 5)\n    ws.Range(\"B2\").Value = \"北區\"\n    ws.Range(\"C2\").Value = \"產品A\"\n    ws.Range(\"D2\").Value = 100\n    ws.Range(\"E2\").Value = 50\n    ws.Range(\"F2\").Value = 5000\n\n    ws.Range(\"A3\").Value = DateSerial(2026, 1, 10)\n    ws.Range(\"B3\").Value = \"南區\"\n    ws.Range(\"C3\").Value = \"產品B\"\n    ws.Range(\"D3\").Value = 80\n    ws.Range(\"E3\").Value = 75\n    ws.Range(\"F3\").Value = 6000\n\n    ws.Range(\"A4\").Value = DateSerial(2026, 2, 5)\n    ws.Range(\"B4\").Value = \"北區\"\n    ws.Range(\"C4\").Value = \"產品B\"\n    ws.Range(\"D4\").Value = 60\n    ws.Range(\"E4\").Value = 75\n    ws.Range(\"F4\").Value = 4500\n\n    ws.Range(\"A5\").Value = DateSerial(2026, 2, 15)\n    ws.Range(\"B5\").Value = \"中區\"\n    ws.Range(\"C5\").Value = \"產品A\"\n    ws.Range(\"D5\").Value = 120\n    ws.Range(\"E5\").Value = 50\n    ws.Range(\"F5\").Value = 6000\n\n    ws.Range(\"A6\").Value = DateSerial(2026, 3, 1)\n    ws.Range(\"B6\").Value = \"南區\"\n    ws.Range(\"C6\").Value = \"產品A\"\n    ws.Range(\"D6\").Value = 90\n    ws.Range(\"E6\").Value = 50\n    ws.Range(\"F6\").Value = 4500\n\n    ws.Range(\"A7\").Value = DateSerial(2026, 3, 20)\n    ws.Range(\"B7\").Value = \"中區\"\n    ws.Range(\"C7\").Value = \"產品B\"\n    ws.Range(\"D7\").Value = 150\n    ws.Range(\"E7\").Value = 75\n    ws.Range(\"F7\").Value = 11250\n\n    ws.Range(\"A8\").Value = DateSerial(2026, 4, 5)\n    ws.Range(\"B8\").Value = \"北區\"\n    ws.Range(\"C8\").Value = \"產品A\"\n    ws.Range(\"D8\").Value = 200\n    ws.Range(\"E8\").Value = 50\n    ws.Range(\"F8\").Value = 10000\n\n    ws.Range(\"A9\").Value = DateSerial(2026, 4, 18)\n    ws.Range(\"B9\").Value = \"南區\"\n    ws.Range(\"C9\").Value = \"產品B\"\n    ws.Range(\"D9\").Value = 110\n    ws.Range(\"E9\").Value = 75\n    ws.Range(\"F9\").Value = 8250\n\n    ws.Columns(\"A\").NumberFormat = \"yyyy/m/d\"\n    ws.Columns(\"A:F\").AutoFit\nEnd Sub\n\n' 取得或建立工作表，並清除現有內容\nPrivate Function GetOrCreateSheet(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add\n        ws.Name = sheetName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreateSheet = ws\nEnd Function\n", "content_b64": ""}, {"name": "SlicerPivotTable.bas", "path": "模組/PivotTableAnalysis/SlicerPivotTable.bas", "content": "Attribute VB_Name = \"SlicerPivotTable\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: SlicerPivotTable\n'功能說明: 為樞紐分析表加入交叉分析篩選器（Slicer）\n'          需要 Excel 2010 以上版本\n'\n'版權所有: Dunk\n'程式設計: Dunk\n'撰寫日期: 2026/5/3\n'\n'*************************************************************************************\n\n' 測試入口\nSub TestSlicerPivotTable()\n    Call CreateSlicerPivotTable\nEnd Sub\n\n' 建立含 Slicer 的樞紐分析表\nSub CreateSlicerPivotTable()\n    Dim wsData As Worksheet\n    Dim wsPivot As Worksheet\n    Dim pc As PivotCache\n    Dim pt As PivotTable\n    Dim dataRange As Range\n    Dim sc As SlicerCache\n    Dim slc As Slicer\n\n    ' 準備工作表\n    Set wsData = GetOrCreateSheet(ThisWorkbook, \"銷售資料\")\n    Call FillSalesData(wsData)\n    Set wsPivot = GetOrCreateSheet(ThisWorkbook, \"Slicer樞紐\")\n\n    ' 先移除既有 SlicerCache（避免重複）\n    Dim existSc As SlicerCache\n    For Each existSc In ThisWorkbook.SlicerCaches\n        If existSc.SourcePivotTable.Name = \"Slicer樞紐分析表\" Then\n            existSc.Delete\n            Exit For\n        End If\n    Next existSc\n\n    Set dataRange = wsData.Range(\"A1\").CurrentRegion\n\n    Set pc = ThisWorkbook.PivotCaches.Create( _\n        SourceType:=xlDatabase, _\n        SourceData:=dataRange)\n    Set pt = pc.CreatePivotTable( _\n        TableDestination:=wsPivot.Range(\"A3\"), _\n        TableName:=\"Slicer樞紐分析表\")\n\n    ' 列欄位：產品\n    With pt.PivotFields(\"產品\")\n        .Orientation = xlRowField\n        .Position = 1\n    End With\n\n    ' 值欄位：銷售額\n    pt.AddDataField pt.PivotFields(\"銷售額\"), \"銷售額加總\", xlSum\n\n    ' 新增地區 Slicer（交叉分析篩選器）\n    On Error Resume Next\n    Set sc = ThisWorkbook.SlicerCaches.Add2(pt, \"地區\")\n    If Not sc Is Nothing Then\n        Set slc = sc.Slicers.Add( _\n            SlicerDestination:=wsPivot, _\n            Name:=\"地區篩選器\", _\n            Caption:=\"地區\", _\n            Top:=50, Left:=300, Width:=150, Height:=200)\n    End If\n    On Error GoTo 0\n\n    wsPivot.Activate\n    MsgBox \"Slicer 樞紐分析表已建立完成！請點選右側交叉分析篩選器進行篩選。\", vbInformation, \"完成\"\nEnd Sub\n\n' 填入範例銷售資料（共 8 筆：日期、地區、產品、數量、單價、銷售額）\nPrivate Sub FillSalesData(ByVal ws As Worksheet)\n    ws.Range(\"A1\").Value = \"日期\"\n    ws.Range(\"B1\").Value = \"地區\"\n    ws.Range(\"C1\").Value = \"產品\"\n    ws.Range(\"D1\").Value = \"數量\"\n    ws.Range(\"E1\").Value = \"單價\"\n    ws.Range(\"F1\").Value = \"銷售額\"\n\n    ws.Range(\"A2\").Value = DateSerial(2026, 1, 5)\n    ws.Range(\"B2\").Value = \"北部\"\n    ws.Range(\"C2\").Value = \"產品A\"\n    ws.Range(\"D2\").Value = 100\n    ws.Range(\"E2\").Value = 50\n    ws.Range(\"F2\").Value = 5000\n\n    ws.Range(\"A3\").Value = DateSerial(2026, 1, 10)\n    ws.Range(\"B3\").Value = \"南部\"\n    ws.Range(\"C3\").Value = \"產品B\"\n    ws.Range(\"D3\").Value = 80\n    ws.Range(\"E3\").Value = 75\n    ws.Range(\"F3\").Value = 6000\n\n    ws.Range(\"A4\").Value = DateSerial(2026, 2, 5)\n    ws.Range(\"B4\").Value = \"北部\"\n    ws.Range(\"C4\").Value = \"產品B\"\n    ws.Range(\"D4\").Value = 60\n    ws.Range(\"E4\").Value = 75\n    ws.Range(\"F4\").Value = 4500\n\n    ws.Range(\"A5\").Value = DateSerial(2026, 2, 15)\n    ws.Range(\"B5\").Value = \"中部\"\n    ws.Range(\"C5\").Value = \"產品A\"\n    ws.Range(\"D5\").Value = 120\n    ws.Range(\"E5\").Value = 50\n    ws.Range(\"F5\").Value = 6000\n\n    ws.Range(\"A6\").Value = DateSerial(2026, 3, 1)\n    ws.Range(\"B6\").Value = \"南部\"\n    ws.Range(\"C6\").Value = \"產品A\"\n    ws.Range(\"D6\").Value = 90\n    ws.Range(\"E6\").Value = 50\n    ws.Range(\"F6\").Value = 4500\n\n    ws.Range(\"A7\").Value = DateSerial(2026, 3, 20)\n    ws.Range(\"B7\").Value = \"中部\"\n    ws.Range(\"C7\").Value = \"產品B\"\n    ws.Range(\"D7\").Value = 150\n    ws.Range(\"E7\").Value = 75\n    ws.Range(\"F7\").Value = 11250\n\n    ws.Range(\"A8\").Value = DateSerial(2026, 4, 5)\n    ws.Range(\"B8\").Value = \"北部\"\n    ws.Range(\"C8\").Value = \"產品A\"\n    ws.Range(\"D8\").Value = 200\n    ws.Range(\"E8\").Value = 50\n    ws.Range(\"F8\").Value = 10000\n\n    ws.Range(\"A9\").Value = DateSerial(2026, 4, 18)\n    ws.Range(\"B9\").Value = \"南部\"\n    ws.Range(\"C9\").Value = \"產品B\"\n    ws.Range(\"D9\").Value = 110\n    ws.Range(\"E9\").Value = 75\n    ws.Range(\"F9\").Value = 8250\n\n    ws.Columns(\"A\").NumberFormat = \"yyyy/m/d\"\n    ws.Columns(\"A:F\").AutoFit\nEnd Sub\n\n' 取得或建立工作表，並清除內容\nPrivate Function GetOrCreateSheet(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add\n        ws.Name = sheetName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreateSheet = ws\nEnd Function\n", "content_b64": ""}, {"name": "SortPivotTable.bas", "path": "模組/PivotTableAnalysis/SortPivotTable.bas", "content": "Attribute VB_Name = \"SortPivotTable\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: SortPivotTable\n'功能說明: 樞紐分析表排序（依銷售額升冪 / 降冪排序列欄位）\n'\n'版權所有: Dunk\n'程式設計: Dunk\n'撰寫日期: 2026/5/3\n'\n'*************************************************************************************\n\n' 測試入口（降冪）\nSub TestSortPivotTableDesc()\n    Call CreateSortPivotTable(xlDescending)\nEnd Sub\n\n' 測試入口（升冪）\nSub TestSortPivotTableAsc()\n    Call CreateSortPivotTable(xlAscending)\nEnd Sub\n\n' 建立排序樞紐分析表\n' sortOrder: xlAscending（升冪）或 xlDescending（降冪）\nSub CreateSortPivotTable(ByVal sortOrder As XlSortOrder)\n    Dim wsData As Worksheet\n    Dim wsPivot As Worksheet\n    Dim pc As PivotCache\n    Dim pt As PivotTable\n    Dim dataRange As Range\n    Dim sortLabel As String\n\n    If sortOrder = xlAscending Then\n        sortLabel = \"升冪\"\n    Else\n        sortLabel = \"降冪\"\n    End If\n\n    ' 準備工作表\n    Set wsData = GetOrCreateSheet(ThisWorkbook, \"銷售資料\")\n    Call FillSalesData(wsData)\n    Set wsPivot = GetOrCreateSheet(ThisWorkbook, \"排序樞紐\")\n\n    Set dataRange = wsData.Range(\"A1\").CurrentRegion\n\n    Set pc = ThisWorkbook.PivotCaches.Create( _\n        SourceType:=xlDatabase, _\n        SourceData:=dataRange)\n    Set pt = pc.CreatePivotTable( _\n        TableDestination:=wsPivot.Range(\"A3\"), _\n        TableName:=\"排序樞紐分析表\")\n\n    ' 列欄位：地區\n    With pt.PivotFields(\"地區\")\n        .Orientation = xlRowField\n        .Position = 1\n    End With\n\n    ' 欄欄位：產品\n    With pt.PivotFields(\"產品\")\n        .Orientation = xlColumnField\n        .Position = 1\n    End With\n\n    ' 值欄位：銷售額加總\n    pt.AddDataField pt.PivotFields(\"銷售額\"), \"銷售額加總\", xlSum\n\n    ' 對列欄位「地區」依「銷售額加總」排序\n    pt.PivotFields(\"地區\").AutoSort sortOrder, \"銷售額加總\"\n\n    wsPivot.Activate\n    MsgBox \"排序樞紐分析表已建立完成！地區依銷售額\" & sortLabel & \"排序。\", vbInformation, \"完成\"\nEnd Sub\n\n' 填入範例銷售資料（共 8 筆：日期、地區、產品、數量、單價、銷售額）\nPrivate Sub FillSalesData(ByVal ws As Worksheet)\n    ws.Range(\"A1\").Value = \"日期\"\n    ws.Range(\"B1\").Value = \"地區\"\n    ws.Range(\"C1\").Value = \"產品\"\n    ws.Range(\"D1\").Value = \"數量\"\n    ws.Range(\"E1\").Value = \"單價\"\n    ws.Range(\"F1\").Value = \"銷售額\"\n\n    ws.Range(\"A2\").Value = DateSerial(2026, 1, 5)\n    ws.Range(\"B2\").Value = \"北部\"\n    ws.Range(\"C2\").Value = \"產品A\"\n    ws.Range(\"D2\").Value = 100\n    ws.Range(\"E2\").Value = 50\n    ws.Range(\"F2\").Value = 5000\n\n    ws.Range(\"A3\").Value = DateSerial(2026, 1, 10)\n    ws.Range(\"B3\").Value = \"南部\"\n    ws.Range(\"C3\").Value = \"產品B\"\n    ws.Range(\"D3\").Value = 80\n    ws.Range(\"E3\").Value = 75\n    ws.Range(\"F3\").Value = 6000\n\n    ws.Range(\"A4\").Value = DateSerial(2026, 2, 5)\n    ws.Range(\"B4\").Value = \"北部\"\n    ws.Range(\"C4\").Value = \"產品B\"\n    ws.Range(\"D4\").Value = 60\n    ws.Range(\"E4\").Value = 75\n    ws.Range(\"F4\").Value = 4500\n\n    ws.Range(\"A5\").Value = DateSerial(2026, 2, 15)\n    ws.Range(\"B5\").Value = \"中部\"\n    ws.Range(\"C5\").Value = \"產品A\"\n    ws.Range(\"D5\").Value = 120\n    ws.Range(\"E5\").Value = 50\n    ws.Range(\"F5\").Value = 6000\n\n    ws.Range(\"A6\").Value = DateSerial(2026, 3, 1)\n    ws.Range(\"B6\").Value = \"南部\"\n    ws.Range(\"C6\").Value = \"產品A\"\n    ws.Range(\"D6\").Value = 90\n    ws.Range(\"E6\").Value = 50\n    ws.Range(\"F6\").Value = 4500\n\n    ws.Range(\"A7\").Value = DateSerial(2026, 3, 20)\n    ws.Range(\"B7\").Value = \"中部\"\n    ws.Range(\"C7\").Value = \"產品B\"\n    ws.Range(\"D7\").Value = 150\n    ws.Range(\"E7\").Value = 75\n    ws.Range(\"F7\").Value = 11250\n\n    ws.Range(\"A8\").Value = DateSerial(2026, 4, 5)\n    ws.Range(\"B8\").Value = \"北部\"\n    ws.Range(\"C8\").Value = \"產品A\"\n    ws.Range(\"D8\").Value = 200\n    ws.Range(\"E8\").Value = 50\n    ws.Range(\"F8\").Value = 10000\n\n    ws.Range(\"A9\").Value = DateSerial(2026, 4, 18)\n    ws.Range(\"B9\").Value = \"南部\"\n    ws.Range(\"C9\").Value = \"產品B\"\n    ws.Range(\"D9\").Value = 110\n    ws.Range(\"E9\").Value = 75\n    ws.Range(\"F9\").Value = 8250\n\n    ws.Columns(\"A\").NumberFormat = \"yyyy/m/d\"\n    ws.Columns(\"A:F\").AutoFit\nEnd Sub\n\n' 取得或建立工作表，並清除內容\nPrivate Function GetOrCreateSheet(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add\n        ws.Name = sheetName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreateSheet = ws\nEnd Function\n", "content_b64": ""}, {"name": "SubtotalControlPivot.bas", "path": "模組/PivotTableAnalysis/SubtotalControlPivot.bas", "content": "Attribute VB_Name = \"SubtotalControlPivot\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: SubtotalControlPivot\n'功能說明: 示範樞紐分析表小計控制，\n'          包含顯示/隱藏各層級欄位小計，以及關閉所有小計\n'\n'版權所有: Dunk\n'程式設計: Dunk\n'撰寫日期: 2026/5/4\n'\n'*************************************************************************************\n\n' 測試入口\nSub TestSubtotalControlPivot()\n    Call CreateSubtotalControlPivot\nEnd Sub\n\n' 建立樞紐分析表並示範小計控制\n' 功能: 多層列欄位（地區+產品），示範小計顯示/隱藏\nSub CreateSubtotalControlPivot()\n    Dim wsData    As Worksheet\n    Dim wsPivot   As Worksheet\n    Dim pc        As PivotCache\n    Dim pt        As PivotTable\n    Dim dataRange As Range\n    Dim pfRegion  As PivotField\n    Dim pfProduct As PivotField\n\n    ' 準備資料工作表\n    Set wsData = GetOrCreateSheet(ThisWorkbook, \"銷售資料\")\n    Call FillSalesData(wsData)\n\n    ' 準備樞紐工作表\n    Set wsPivot = GetOrCreateSheet(ThisWorkbook, \"小計控制樞紐\")\n\n    Set dataRange = wsData.Range(\"A1\").CurrentRegion\n\n    Set pc = ThisWorkbook.PivotCaches.Create( _\n        SourceType:=xlDatabase, _\n        SourceData:=dataRange)\n    Set pt = pc.CreatePivotTable( _\n        TableDestination:=wsPivot.Range(\"A3\"), _\n        TableName:=\"小計控制樞紐\")\n\n    ' 第一層列欄位: 地區\n    Set pfRegion = pt.PivotFields(\"地區\")\n    pfRegion.Orientation = xlRowField\n    pfRegion.Position = 1\n\n    ' 第二層列欄位: 產品\n    Set pfProduct = pt.PivotFields(\"產品\")\n    pfProduct.Orientation = xlRowField\n    pfProduct.Position = 2\n\n    ' 值欄位: 銷售額加總\n    pt.AddDataField pt.PivotFields(\"銷售額\"), \"銷售額加總\", xlSum\n    ' 值欄位: 數量加總\n    pt.AddDataField pt.PivotFields(\"數量\"), \"數量加總\", xlSum\n\n    ' 顯示地區小計（第一層顯示加總小計）\n    pfRegion.Subtotals(1) = True\n\n    ' 隱藏產品的小計（最內層不顯示小計）\n    pfProduct.Subtotals(1) = False\n\n    ' 在最後顯示總計列\n    pt.RowGrand = True\n    pt.ColumnGrand = True\n\n    wsPivot.Activate\n    MsgBox \"小計控制樞紐分析表已建立完成！\" & Chr(13) & _\n           \"地區欄位顯示加總小計，產品欄位隱藏小計。\", _\n           vbInformation, \"完成\"\nEnd Sub\n\n' 填入範例銷售資料（8筆：日期、地區、產品、數量、單價、銷售額）\nPrivate Sub FillSalesData(ByVal ws As Worksheet)\n    ws.Range(\"A1\").Value = \"日期\"\n    ws.Range(\"B1\").Value = \"地區\"\n    ws.Range(\"C1\").Value = \"產品\"\n    ws.Range(\"D1\").Value = \"數量\"\n    ws.Range(\"E1\").Value = \"單價\"\n    ws.Range(\"F1\").Value = \"銷售額\"\n\n    ws.Range(\"A2\").Value = DateSerial(2026, 1, 5)\n    ws.Range(\"B2\").Value = \"北區\"\n    ws.Range(\"C2\").Value = \"產品A\"\n    ws.Range(\"D2\").Value = 100\n    ws.Range(\"E2\").Value = 50\n    ws.Range(\"F2\").Value = 5000\n\n    ws.Range(\"A3\").Value = DateSerial(2026, 1, 10)\n    ws.Range(\"B3\").Value = \"南區\"\n    ws.Range(\"C3\").Value = \"產品B\"\n    ws.Range(\"D3\").Value = 80\n    ws.Range(\"E3\").Value = 75\n    ws.Range(\"F3\").Value = 6000\n\n    ws.Range(\"A4\").Value = DateSerial(2026, 2, 5)\n    ws.Range(\"B4\").Value = \"北區\"\n    ws.Range(\"C4\").Value = \"產品B\"\n    ws.Range(\"D4\").Value = 60\n    ws.Range(\"E4\").Value = 75\n    ws.Range(\"F4\").Value = 4500\n\n    ws.Range(\"A5\").Value = DateSerial(2026, 2, 15)\n    ws.Range(\"B5\").Value = \"中區\"\n    ws.Range(\"C5\").Value = \"產品A\"\n    ws.Range(\"D5\").Value = 120\n    ws.Range(\"E5\").Value = 50\n    ws.Range(\"F5\").Value = 6000\n\n    ws.Range(\"A6\").Value = DateSerial(2026, 3, 1)\n    ws.Range(\"B6\").Value = \"南區\"\n    ws.Range(\"C6\").Value = \"產品A\"\n    ws.Range(\"D6\").Value = 90\n    ws.Range(\"E6\").Value = 50\n    ws.Range(\"F6\").Value = 4500\n\n    ws.Range(\"A7\").Value = DateSerial(2026, 3, 20)\n    ws.Range(\"B7\").Value = \"中區\"\n    ws.Range(\"C7\").Value = \"產品B\"\n    ws.Range(\"D7\").Value = 150\n    ws.Range(\"E7\").Value = 75\n    ws.Range(\"F7\").Value = 11250\n\n    ws.Range(\"A8\").Value = DateSerial(2026, 4, 5)\n    ws.Range(\"B8\").Value = \"北區\"\n    ws.Range(\"C8\").Value = \"產品A\"\n    ws.Range(\"D8\").Value = 200\n    ws.Range(\"E8\").Value = 50\n    ws.Range(\"F8\").Value = 10000\n\n    ws.Range(\"A9\").Value = DateSerial(2026, 4, 18)\n    ws.Range(\"B9\").Value = \"南區\"\n    ws.Range(\"C9\").Value = \"產品B\"\n    ws.Range(\"D9\").Value = 110\n    ws.Range(\"E9\").Value = 75\n    ws.Range(\"F9\").Value = 8250\n\n    ws.Columns(\"A\").NumberFormat = \"yyyy/m/d\"\n    ws.Columns(\"A:F\").AutoFit\nEnd Sub\n\n' 取得或建立工作表，並清除現有內容\nPrivate Function GetOrCreateSheet(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add\n        ws.Name = sheetName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreateSheet = ws\nEnd Function\n", "content_b64": ""}, {"name": "TimelinePivot.bas", "path": "模組/PivotTableAnalysis/TimelinePivot.bas", "content": "Attribute VB_Name = \"TimelinePivot\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: TimelinePivot\n'功能說明: 在樞紐分析表加入時間軸篩選器（Timeline），\n'          需要 Excel 2013 以上版本\n'\n'版權所有: Dunk\n'程式設計: Dunk\n'撰寫日期: 2026/5/4\n'\n'*************************************************************************************\n\n' 測試入口\nSub TestTimelinePivot()\n    Call CreateTimelinePivot\nEnd Sub\n\n' 建立含時間軸篩選器的樞紐分析表\n' 功能: 以地區為列欄位，銷售額為值，插入日期時間軸\nSub CreateTimelinePivot()\n    Dim wsData    As Worksheet\n    Dim wsPivot   As Worksheet\n    Dim pc        As PivotCache\n    Dim pt        As PivotTable\n    Dim dataRange As Range\n    Dim sc        As SlicerCache\n    Dim tl        As Slicer\n\n    ' 準備資料工作表\n    Set wsData = GetOrCreateSheet(ThisWorkbook, \"銷售資料\")\n    Call FillSalesData(wsData)\n\n    ' 準備樞紐工作表\n    Set wsPivot = GetOrCreateSheet(ThisWorkbook, \"時間軸樞紐\")\n\n    Set dataRange = wsData.Range(\"A1\").CurrentRegion\n\n    Set pc = ThisWorkbook.PivotCaches.Create( _\n        SourceType:=xlDatabase, _\n        SourceData:=dataRange)\n    Set pt = pc.CreatePivotTable( _\n        TableDestination:=wsPivot.Range(\"A3\"), _\n        TableName:=\"時間軸樞紐\")\n\n    ' 列欄位: 地區\n    With pt.PivotFields(\"地區\")\n        .Orientation = xlRowField\n        .Position = 1\n    End With\n\n    ' 值欄位: 銷售額加總\n    pt.AddDataField pt.PivotFields(\"銷售額\"), \"銷售額加總\", xlSum\n\n    ' 插入時間軸篩選器（需 Excel 2013 以上）\n    On Error GoTo ErrHandler\n    Set sc = ThisWorkbook.SlicerCaches.Add2(pt, \"日期\", , xlTimeline)\n    Set tl = sc.Slicers.Add( _\n        SlicerDestination:=wsPivot, _\n        Top:=50, Left:=300, Width:=400, Height:=100)\n\n    wsPivot.Activate\n    MsgBox \"時間軸篩選器已建立完成！\" & Chr(13) & _\n           \"可點選時間軸選取特定月份或季度進行篩選。\", _\n           vbInformation, \"完成\"\n    Exit Sub\n\nErrHandler:\n    wsPivot.Activate\n    MsgBox \"時間軸篩選器建立失敗。\" & Chr(13) & _\n           \"請確認 Excel 版本為 2013 以上，且日期欄位格式正確。\" & Chr(13) & _\n           \"錯誤：\" & Err.Description, _\n           vbExclamation, \"警告\"\nEnd Sub\n\n' 填入範例銷售資料（8筆：日期、地區、產品、數量、單價、銷售額）\nPrivate Sub FillSalesData(ByVal ws As Worksheet)\n    ws.Range(\"A1\").Value = \"日期\"\n    ws.Range(\"B1\").Value = \"地區\"\n    ws.Range(\"C1\").Value = \"產品\"\n    ws.Range(\"D1\").Value = \"數量\"\n    ws.Range(\"E1\").Value = \"單價\"\n    ws.Range(\"F1\").Value = \"銷售額\"\n\n    ws.Range(\"A2\").Value = DateSerial(2026, 1, 5)\n    ws.Range(\"B2\").Value = \"北區\"\n    ws.Range(\"C2\").Value = \"產品A\"\n    ws.Range(\"D2\").Value = 100\n    ws.Range(\"E2\").Value = 50\n    ws.Range(\"F2\").Value = 5000\n\n    ws.Range(\"A3\").Value = DateSerial(2026, 1, 10)\n    ws.Range(\"B3\").Value = \"南區\"\n    ws.Range(\"C3\").Value = \"產品B\"\n    ws.Range(\"D3\").Value = 80\n    ws.Range(\"E3\").Value = 75\n    ws.Range(\"F3\").Value = 6000\n\n    ws.Range(\"A4\").Value = DateSerial(2026, 2, 5)\n    ws.Range(\"B4\").Value = \"北區\"\n    ws.Range(\"C4\").Value = \"產品B\"\n    ws.Range(\"D4\").Value = 60\n    ws.Range(\"E4\").Value = 75\n    ws.Range(\"F4\").Value = 4500\n\n    ws.Range(\"A5\").Value = DateSerial(2026, 2, 15)\n    ws.Range(\"B5\").Value = \"中區\"\n    ws.Range(\"C5\").Value = \"產品A\"\n    ws.Range(\"D5\").Value = 120\n    ws.Range(\"E5\").Value = 50\n    ws.Range(\"F5\").Value = 6000\n\n    ws.Range(\"A6\").Value = DateSerial(2026, 3, 1)\n    ws.Range(\"B6\").Value = \"南區\"\n    ws.Range(\"C6\").Value = \"產品A\"\n    ws.Range(\"D6\").Value = 90\n    ws.Range(\"E6\").Value = 50\n    ws.Range(\"F6\").Value = 4500\n\n    ws.Range(\"A7\").Value = DateSerial(2026, 3, 20)\n    ws.Range(\"B7\").Value = \"中區\"\n    ws.Range(\"C7\").Value = \"產品B\"\n    ws.Range(\"D7\").Value = 150\n    ws.Range(\"E7\").Value = 75\n    ws.Range(\"F7\").Value = 11250\n\n    ws.Range(\"A8\").Value = DateSerial(2026, 4, 5)\n    ws.Range(\"B8\").Value = \"北區\"\n    ws.Range(\"C8\").Value = \"產品A\"\n    ws.Range(\"D8\").Value = 200\n    ws.Range(\"E8\").Value = 50\n    ws.Range(\"F8\").Value = 10000\n\n    ws.Range(\"A9\").Value = DateSerial(2026, 4, 18)\n    ws.Range(\"B9\").Value = \"南區\"\n    ws.Range(\"C9\").Value = \"產品B\"\n    ws.Range(\"D9\").Value = 110\n    ws.Range(\"E9\").Value = 75\n    ws.Range(\"F9\").Value = 8250\n\n    ws.Columns(\"A\").NumberFormat = \"yyyy/m/d\"\n    ws.Columns(\"A:F\").AutoFit\nEnd Sub\n\n' 取得或建立工作表，並清除現有內容\nPrivate Function GetOrCreateSheet(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add\n        ws.Name = sheetName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreateSheet = ws\nEnd Function\n", "content_b64": ""}, {"name": "TopNFilterPivot.bas", "path": "模組/PivotTableAnalysis/TopNFilterPivot.bas", "content": "Attribute VB_Name = \"TopNFilterPivot\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: TopNFilterPivot\n'功能說明: 樞紐分析表前N名篩選功能，\n'          使用 PivotFilters 篩選出銷售額前3名的地區\n'\n'版權所有: Dunk\n'程式設計: Dunk\n'撰寫日期: 2026/5/4\n'\n'*************************************************************************************\n\n' 測試入口\nSub TestTopNFilterPivot()\n    Call CreateTopNFilterPivot\nEnd Sub\n\n' 建立含前N名篩選的樞紐分析表\nSub CreateTopNFilterPivot()\n    Dim wsData    As Worksheet\n    Dim wsPivot   As Worksheet\n    Dim pc        As PivotCache\n    Dim pt        As PivotTable\n    Dim dataRange As Range\n    Dim pfRegion  As PivotField\n    Dim pfSales   As PivotField\n\n    ' 準備資料工作表\n    Set wsData = GetOrCreateSheet(ThisWorkbook, \"銷售資料\")\n    Call FillSalesData(wsData)\n\n    ' 準備樞紐工作表\n    Set wsPivot = GetOrCreateSheet(ThisWorkbook, \"前N名篩選樞紐\")\n\n    Set dataRange = wsData.Range(\"A1\").CurrentRegion\n\n    Set pc = ThisWorkbook.PivotCaches.Create( _\n        SourceType:=xlDatabase, _\n        SourceData:=dataRange)\n    Set pt = pc.CreatePivotTable( _\n        TableDestination:=wsPivot.Range(\"A3\"), _\n        TableName:=\"前N名篩選樞紐\")\n\n    ' 列欄位: 地區\n    Set pfRegion = pt.PivotFields(\"地區\")\n    pfRegion.Orientation = xlRowField\n    pfRegion.Position = 1\n\n    ' 值欄位: 銷售額加總\n    Set pfSales = pt.AddDataField(pt.PivotFields(\"銷售額\"), \"銷售額加總\", xlSum)\n\n    ' 套用前3名篩選（依銷售額加總排序取前3名）\n    On Error Resume Next\n    pfRegion.PivotFilters.Add2 _\n        Type:=xlTopCount, _\n        DataField:=pfSales, _\n        Value1:=3\n    On Error GoTo 0\n\n    wsPivot.Activate\n    MsgBox \"前N名篩選樞紐分析表已建立完成！\" & Chr(13) & _\n           \"已篩選出銷售額加總前3名的地區。\", _\n           vbInformation, \"完成\"\nEnd Sub\n\n' 填入範例銷售資料（8筆：日期、地區、產品、數量、單價、銷售額）\nPrivate Sub FillSalesData(ByVal ws As Worksheet)\n    ws.Range(\"A1\").Value = \"日期\"\n    ws.Range(\"B1\").Value = \"地區\"\n    ws.Range(\"C1\").Value = \"產品\"\n    ws.Range(\"D1\").Value = \"數量\"\n    ws.Range(\"E1\").Value = \"單價\"\n    ws.Range(\"F1\").Value = \"銷售額\"\n\n    ws.Range(\"A2\").Value = DateSerial(2026, 1, 5)\n    ws.Range(\"B2\").Value = \"北區\"\n    ws.Range(\"C2\").Value = \"產品A\"\n    ws.Range(\"D2\").Value = 100\n    ws.Range(\"E2\").Value = 50\n    ws.Range(\"F2\").Value = 5000\n\n    ws.Range(\"A3\").Value = DateSerial(2026, 1, 10)\n    ws.Range(\"B3\").Value = \"南區\"\n    ws.Range(\"C3\").Value = \"產品B\"\n    ws.Range(\"D3\").Value = 80\n    ws.Range(\"E3\").Value = 75\n    ws.Range(\"F3\").Value = 6000\n\n    ws.Range(\"A4\").Value = DateSerial(2026, 2, 5)\n    ws.Range(\"B4\").Value = \"北區\"\n    ws.Range(\"C4\").Value = \"產品B\"\n    ws.Range(\"D4\").Value = 60\n    ws.Range(\"E4\").Value = 75\n    ws.Range(\"F4\").Value = 4500\n\n    ws.Range(\"A5\").Value = DateSerial(2026, 2, 15)\n    ws.Range(\"B5\").Value = \"中區\"\n    ws.Range(\"C5\").Value = \"產品A\"\n    ws.Range(\"D5\").Value = 120\n    ws.Range(\"E5\").Value = 50\n    ws.Range(\"F5\").Value = 6000\n\n    ws.Range(\"A6\").Value = DateSerial(2026, 3, 1)\n    ws.Range(\"B6\").Value = \"南區\"\n    ws.Range(\"C6\").Value = \"產品A\"\n    ws.Range(\"D6\").Value = 90\n    ws.Range(\"E6\").Value = 50\n    ws.Range(\"F6\").Value = 4500\n\n    ws.Range(\"A7\").Value = DateSerial(2026, 3, 20)\n    ws.Range(\"B7\").Value = \"中區\"\n    ws.Range(\"C7\").Value = \"產品B\"\n    ws.Range(\"D7\").Value = 150\n    ws.Range(\"E7\").Value = 75\n    ws.Range(\"F7\").Value = 11250\n\n    ws.Range(\"A8\").Value = DateSerial(2026, 4, 5)\n    ws.Range(\"B8\").Value = \"北區\"\n    ws.Range(\"C8\").Value = \"產品A\"\n    ws.Range(\"D8\").Value = 200\n    ws.Range(\"E8\").Value = 50\n    ws.Range(\"F8\").Value = 10000\n\n    ws.Range(\"A9\").Value = DateSerial(2026, 4, 18)\n    ws.Range(\"B9\").Value = \"南區\"\n    ws.Range(\"C9\").Value = \"產品B\"\n    ws.Range(\"D9\").Value = 110\n    ws.Range(\"E9\").Value = 75\n    ws.Range(\"F9\").Value = 8250\n\n    ws.Columns(\"A\").NumberFormat = \"yyyy/m/d\"\n    ws.Columns(\"A:F\").AutoFit\nEnd Sub\n\n' 取得或建立工作表，並清除現有內容\nPrivate Function GetOrCreateSheet(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add\n        ws.Name = sheetName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreateSheet = ws\nEnd Function\n", "content_b64": ""}, {"name": "ValueStatsPivot.bas", "path": "模組/PivotTableAnalysis/ValueStatsPivot.bas", "content": "Attribute VB_Name = \"ValueStatsPivot\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: ValueStatsPivot\n'功能說明: 多種統計值示範\n'          在同一樞紐分析表中，對同一資料欄同時顯示\n'          加總、平均、最大值、最小值、計數\n'\n'版權所有: Dunk\n'程式設計: Dunk\n'撰寫日期: 2026/5/6\n'\n'*************************************************************************************\n\n' 程式進入點\nSub TestValueStatsPivot()\n    Call CreateValueStatsPivot\nEnd Sub\n\n' 建立多統計值樞紐分析表\nSub CreateValueStatsPivot()\n    Dim wsData As Worksheet\n    Dim wsPivot As Worksheet\n    Dim pc As PivotCache\n    Dim pt As PivotTable\n    Dim dataRange As Range\n    Dim dfSum As PivotField\n    Dim dfAvg As PivotField\n    Dim dfMax As PivotField\n    Dim dfMin As PivotField\n    Dim dfCnt As PivotField\n\n    Set wsData = GetOrCreateSheet(ThisWorkbook, \"業務銷售\")\n    Call FillSalesDetail(wsData)\n    Set wsPivot = GetOrCreateSheet(ThisWorkbook, \"多統計值樞紐\")\n\n    Set dataRange = wsData.Range(\"A1\").CurrentRegion\n\n    Set pc = ThisWorkbook.PivotCaches.Create( _\n        SourceType:=xlDatabase, _\n        SourceData:=dataRange)\n    Set pt = pc.CreatePivotTable( _\n        TableDestination:=wsPivot.Range(\"A3\"), _\n        TableName:=\"多統計值樞紐分析表\")\n\n    ' 列欄位：業務員\n    With pt.PivotFields(\"業務員\")\n        .Orientation = xlRowField\n        .Position = 1\n    End With\n\n    ' 加總\n    Set dfSum = pt.AddDataField(pt.PivotFields(\"金額\"), \"金額加總\", xlSum)\n    dfSum.NumberFormat = \"#,##0\"\n\n    ' 平均\n    Set dfAvg = pt.AddDataField(pt.PivotFields(\"金額\"), \"金額平均\", xlAverage)\n    dfAvg.NumberFormat = \"#,##0.00\"\n\n    ' 最大值\n    Set dfMax = pt.AddDataField(pt.PivotFields(\"金額\"), \"金額最大\", xlMax)\n    dfMax.NumberFormat = \"#,##0\"\n\n    ' 最小值\n    Set dfMin = pt.AddDataField(pt.PivotFields(\"金額\"), \"金額最小\", xlMin)\n    dfMin.NumberFormat = \"#,##0\"\n\n    ' 計數\n    Set dfCnt = pt.AddDataField(pt.PivotFields(\"金額\"), \"筆數\", xlCount)\n\n    ' 值欄位排列為欄方向\n    pt.DataPivotField.Orientation = xlColumnField\n\n    wsPivot.Columns(\"A:G\").AutoFit\n    wsPivot.Activate\n    MsgBox \"多統計值樞紐分析表已建立！\" & Chr(13) & _\n           \"同時顯示加總、平均、最大、最小、計數。\", vbInformation, \"完成\"\nEnd Sub\n\n' 填入業務銷售明細\nPrivate Sub FillSalesDetail(ByVal ws As Worksheet)\n    ws.Range(\"A1\").Value = \"業務員\"\n    ws.Range(\"B1\").Value = \"月份\"\n    ws.Range(\"C1\").Value = \"金額\"\n\n    ws.Range(\"A2\").Value = \"王小明\" : ws.Range(\"B2\").Value = \"一月\" : ws.Range(\"C2\").Value = 32000\n    ws.Range(\"A3\").Value = \"王小明\" : ws.Range(\"B3\").Value = \"二月\" : ws.Range(\"C3\").Value = 45000\n    ws.Range(\"A4\").Value = \"王小明\" : ws.Range(\"B4\").Value = \"三月\" : ws.Range(\"C4\").Value = 28000\n    ws.Range(\"A5\").Value = \"李美華\" : ws.Range(\"B5\").Value = \"一月\" : ws.Range(\"C5\").Value = 51000\n    ws.Range(\"A6\").Value = \"李美華\" : ws.Range(\"B6\").Value = \"二月\" : ws.Range(\"C6\").Value = 39000\n    ws.Range(\"A7\").Value = \"李美華\" : ws.Range(\"B7\").Value = \"三月\" : ws.Range(\"C7\").Value = 62000\n    ws.Range(\"A8\").Value = \"張志偉\" : ws.Range(\"B8\").Value = \"一月\" : ws.Range(\"C8\").Value = 18000\n    ws.Range(\"A9\").Value = \"張志偉\" : ws.Range(\"B9\").Value = \"二月\" : ws.Range(\"C9\").Value = 27000\n    ws.Range(\"A10\").Value = \"張志偉\" : ws.Range(\"B10\").Value = \"三月\" : ws.Range(\"C10\").Value = 33000\n\n    ws.Columns(\"A:C\").AutoFit\nEnd Sub\n\n' 取得或建立工作表，並清除內容\nPrivate Function GetOrCreateSheet(ByVal wb As Workbook, ByVal sheetName As String) As Worksheet\n    Dim ws As Worksheet\n    On Error Resume Next\n    Set ws = wb.Worksheets(sheetName)\n    On Error GoTo 0\n    If ws Is Nothing Then\n        Set ws = wb.Worksheets.Add\n        ws.Name = sheetName\n    End If\n    ws.Cells.Clear\n    Set GetOrCreateSheet = ws\nEnd Function\n", "content_b64": ""}]}, {"folder": "Word", "path": "模組/Word", "files": [{"name": "AddHeaderFooterToWord.bas", "path": "模組/Word/AddHeaderFooterToWord.bas", "content": "Attribute VB_Name = \"AddHeaderFooterToWord\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: AddHeaderFooterToWord\n'功能說明: 批次為資料夾內所有 Word 文件加入頁首與頁尾\n'\n'版權所有: Dunk\n'程式撰寫: Dunk\n'撰寫日期: 2026/05/10\n'\n'使用方式:\n'  1. 執行 BatchAddHeaderFooter\n'  2. 輸入頁首文字（留空則略過頁首）\n'  3. 輸入頁尾文字，可使用 {page}/{pages} 代表頁碼/總頁數\n'  4. 選擇目標資料夾，程式自動處理所有 .docx\n'\n'注意事項:\n'  - 將覆蓋原有頁首頁尾設定\n'  - {page} 與 {pages} 為特殊標記，會替換為 Word 域\n'*************************************************************************************\n\n'批次加入頁首頁尾\nSub BatchAddHeaderFooter()\n    Dim wdApp        As Object\n    Dim wdDoc        As Object\n    Dim wdSec        As Object\n    Dim strFolder    As String\n    Dim strFile      As String\n    Dim strHeader    As String\n    Dim strFooter    As String\n    Dim lngCount     As Long\n\n    On Error GoTo ErrHandler\n\n    strHeader = InputBox(\"請輸入頁首文字（留空略過）：\", \"設定頁首\", \"機密文件\")\n    strFooter = InputBox(\"請輸入頁尾文字（{page}=頁碼, {pages}=總頁數）：\", _\n                         \"設定頁尾\", \"第 {page} 頁，共 {pages} 頁\")\n\n    If strHeader = \"\" And strFooter = \"\" Then\n        MsgBox \"頁首與頁尾均為空白，操作取消。\", vbInformation, \"提示\"\n        Exit Sub\n    End If\n\n    With Application.FileDialog(4)\n        .Title = \"請選擇 Word 文件資料夾\"\n        If .Show <> -1 Then Exit Sub\n        strFolder = .SelectedItems(1)\n    End With\n    If Right(strFolder, 1) <> \"\\\" Then strFolder = strFolder & \"\\\"\n\n    Set wdApp = CreateObject(\"Word.Application\")\n    wdApp.Visible = False\n\n    lngCount = 0\n    strFile = Dir(strFolder & \"*.docx\")\n\n    Do While strFile <> \"\"\n        Set wdDoc = wdApp.Documents.Open(strFolder & strFile)\n\n        For Each wdSec In wdDoc.Sections\n            '設定頁首\n            If strHeader <> \"\" Then\n                wdSec.Headers(1).LinkToPrevious = False\n                wdSec.Headers(1).Range.Text = strHeader\n            End If\n\n            '設定頁尾（處理 {page} 與 {pages} 標記）\n            If strFooter <> \"\" Then\n                wdSec.Footers(1).LinkToPrevious = False\n\n                Dim rng As Object\n                Set rng = wdSec.Footers(1).Range\n\n                '清空頁尾\n                rng.Text = \"\"\n\n                '依標記分段插入一般文字或域\n                Dim strParts() As String\n                Dim strFull    As String\n                Dim k          As Long\n                strFull = strFooter\n\n                '用臨時符號替換 {page} 與 {pages}\n                strFull = Replace(strFull, \"{pages}\", Chr(2))\n                strFull = Replace(strFull, \"{page}\", Chr(1))\n                strParts = Split(strFull, \"\")\n\n                Dim partRng As Object\n                Set partRng = wdSec.Footers(1).Range\n                partRng.Collapse 0   'wdCollapseEnd\n\n                Dim c As Long\n                For c = 1 To Len(strFull)\n                    Dim ch As String\n                    ch = Mid(strFull, c, 1)\n                    Select Case Asc(ch)\n                        Case 1  '{page}\n                            partRng.InsertAfter \"\"\n                            partRng.Collapse 0\n                            wdDoc.Fields.Add Range:=partRng, Type:=33  'wdFieldPage=33\n                            partRng.Collapse 0\n                        Case 2  '{pages}\n                            partRng.InsertAfter \"\"\n                            partRng.Collapse 0\n                            wdDoc.Fields.Add Range:=partRng, Type:=26  'wdFieldNumPages=26\n                            partRng.Collapse 0\n                        Case Else\n                            partRng.InsertAfter ch\n                            partRng.Collapse 0\n                    End Select\n                Next c\n                Set partRng = Nothing\n                Set rng = Nothing\n            End If\n        Next wdSec\n\n        wdDoc.Save\n        wdDoc.Close False\n        Set wdDoc = Nothing\n        lngCount = lngCount + 1\n        strFile = Dir()\n    Loop\n\n    wdApp.Quit\n    Set wdApp = Nothing\n\n    MsgBox \"頁首頁尾設定完成！\" & vbCrLf & _\n           \"共處理 \" & lngCount & \" 個文件。\", vbInformation, \"完成\"\n    Exit Sub\n\nErrHandler:\n    MsgBox \"發生錯誤：\" & Err.Number & \" - \" & Err.Description, vbCritical, \"錯誤\"\n    If Not wdDoc Is Nothing Then wdDoc.Close False\n    If Not wdApp Is Nothing Then wdApp.Quit\n    Set wdDoc = Nothing\n    Set wdApp = Nothing\nEnd Sub\n", "content_b64": ""}, {"name": "AddWatermarkToWord.bas", "path": "模組/Word/AddWatermarkToWord.bas", "content": "Attribute VB_Name = \"AddWatermarkToWord\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: AddWatermarkToWord\n'功能說明: 批次為資料夾內所有 Word 文件加入文字浮水印\n'\n'版權所有: Dunk\n'程式撰寫: Dunk\n'撰寫日期: 2026/05/10\n'\n'使用方式:\n'  1. 執行 BatchAddWatermark\n'  2. 輸入浮水印文字（例如：機密、DRAFT）\n'  3. 選擇目標資料夾，程式自動為所有 .docx 加上浮水印\n'\n'注意事項:\n'  - 浮水印以 WordArt 文字方塊置於頁首實現\n'  - 將覆蓋原有頁首中的浮水印形狀\n'*************************************************************************************\n\n'批次加入文字浮水印\nSub BatchAddWatermark()\n    Dim wdApp        As Object\n    Dim wdDoc        As Object\n    Dim wdShape      As Object\n    Dim wdHdr        As Object\n    Dim strFolder    As String\n    Dim strFile      As String\n    Dim strWmText    As String\n    Dim lngCount     As Long\n\n    On Error GoTo ErrHandler\n\n    strWmText = InputBox(\"請輸入浮水印文字：\", \"浮水印設定\", \"機密文件\")\n    If strWmText = \"\" Then\n        MsgBox \"浮水印文字為空，操作取消。\", vbInformation, \"提示\"\n        Exit Sub\n    End If\n\n    With Application.FileDialog(4)\n        .Title = \"請選擇 Word 文件資料夾\"\n        If .Show <> -1 Then Exit Sub\n        strFolder = .SelectedItems(1)\n    End With\n    If Right(strFolder, 1) <> \"\\\" Then strFolder = strFolder & \"\\\"\n\n    Set wdApp = CreateObject(\"Word.Application\")\n    wdApp.Visible = False\n\n    lngCount = 0\n    strFile = Dir(strFolder & \"*.docx\")\n\n    Do While strFile <> \"\"\n        Set wdDoc = wdApp.Documents.Open(strFolder & strFile)\n\n        '在第一節頁首中插入浮水印\n        Set wdHdr = wdDoc.Sections(1).Headers(1)\n        wdHdr.LinkToPrevious = False\n\n        '移除頁首中既有的形狀\n        Dim s As Long\n        For s = wdHdr.Shapes.Count To 1 Step -1\n            wdHdr.Shapes(s).Delete\n        Next s\n\n        '新增文字方塊作為浮水印\n        Set wdShape = wdHdr.Shapes.AddTextbox( _\n            Orientation:=1, _\n            Left:=100, Top:=200, Width:=350, Height:=150)\n\n        With wdShape\n            .Line.Visible = False\n            .Fill.Visible = False\n            .Rotation = 315\n            .TextFrame.TextRange.Text = strWmText\n            With .TextFrame.TextRange.Font\n                .Size = 72\n                .Bold = True\n                .Color = RGB(192, 192, 192)\n            End With\n            .TextFrame.WordWrap = False\n        End With\n\n        Set wdShape = Nothing\n        Set wdHdr = Nothing\n\n        wdDoc.Save\n        wdDoc.Close False\n        Set wdDoc = Nothing\n        lngCount = lngCount + 1\n        strFile = Dir()\n    Loop\n\n    wdApp.Quit\n    Set wdApp = Nothing\n\n    MsgBox \"浮水印加入完成！\" & vbCrLf & _\n           \"共處理 \" & lngCount & \" 個文件。\", vbInformation, \"完成\"\n    Exit Sub\n\nErrHandler:\n    MsgBox \"發生錯誤：\" & Err.Number & \" - \" & Err.Description, vbCritical, \"錯誤\"\n    If Not wdDoc Is Nothing Then wdDoc.Close False\n    If Not wdApp Is Nothing Then wdApp.Quit\n    Set wdShape = Nothing\n    Set wdDoc = Nothing\n    Set wdApp = Nothing\nEnd Sub\n", "content_b64": ""}, {"name": "BatchProtectWordDocs.bas", "path": "模組/Word/BatchProtectWordDocs.bas", "content": "Attribute VB_Name = \"BatchProtectWordDocs\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: BatchProtectWordDocs\n'功能說明: 批次為資料夾內所有 Word 文件設定或解除密碼保護\n'\n'版權所有: Dunk\n'程式撰寫: Dunk\n'撰寫日期: 2026/05/10\n'\n'使用方式:\n'  1. 執行 BatchProtectWordDocuments 套用保護\n'     或執行 BatchUnprotectWordDocuments 解除保護\n'  2. 輸入密碼\n'  3. 選擇目標資料夾，程式自動處理所有 .docx\n'\n'注意事項:\n'  - 保護類型為「僅允許填寫表單」（wdAllowOnlyFormFields = 2）\n'  - 解除保護時若密碼錯誤，該文件將略過並記錄於結果訊息\n'*************************************************************************************\n\n'批次保護 Word 文件（鎖定編輯）\nSub BatchProtectWordDocuments()\n    Dim wdApp     As Object\n    Dim wdDoc     As Object\n    Dim strFolder As String\n    Dim strFile   As String\n    Dim strPwd    As String\n    Dim lngOK     As Long\n    Dim lngFail   As Long\n    Dim strFailed As String\n\n    On Error GoTo ErrHandler\n\n    strPwd = InputBox(\"請輸入要設定的保護密碼：\", \"設定文件保護\")\n    If strPwd = \"\" Then\n        MsgBox \"密碼為空，操作取消。\", vbInformation, \"提示\"\n        Exit Sub\n    End If\n\n    With Application.FileDialog(4)\n        .Title = \"請選擇 Word 文件資料夾\"\n        If .Show <> -1 Then Exit Sub\n        strFolder = .SelectedItems(1)\n    End With\n    If Right(strFolder, 1) <> \"\\\" Then strFolder = strFolder & \"\\\"\n\n    Set wdApp = CreateObject(\"Word.Application\")\n    wdApp.Visible = False\n    lngOK = 0\n    lngFail = 0\n\n    strFile = Dir(strFolder & \"*.docx\")\n    Do While strFile <> \"\"\n        On Error Resume Next\n        Set wdDoc = wdApp.Documents.Open(strFolder & strFile)\n\n        If Err.Number = 0 Then\n            '套用保護（wdAllowOnlyFormFields = 2）\n            wdDoc.Protect Type:=2, Password:=strPwd, NoReset:=True\n            wdDoc.Save\n            wdDoc.Close False\n            Set wdDoc = Nothing\n            lngOK = lngOK + 1\n        Else\n            lngFail = lngFail + 1\n            strFailed = strFailed & strFile & vbCrLf\n            Err.Clear\n        End If\n        On Error GoTo ErrHandler\n\n        strFile = Dir()\n    Loop\n\n    wdApp.Quit\n    Set wdApp = Nothing\n\n    Dim strMsg As String\n    strMsg = \"保護設定完成！\" & vbCrLf & _\n             \"成功：\" & lngOK & \" 個\" & vbCrLf & _\n             \"失敗：\" & lngFail & \" 個\"\n    If strFailed <> \"\" Then strMsg = strMsg & vbCrLf & \"失敗清單：\" & vbCrLf & strFailed\n    MsgBox strMsg, vbInformation, \"完成\"\n    Exit Sub\n\nErrHandler:\n    MsgBox \"發生錯誤：\" & Err.Number & \" - \" & Err.Description, vbCritical, \"錯誤\"\n    If Not wdDoc Is Nothing Then wdDoc.Close False\n    If Not wdApp Is Nothing Then wdApp.Quit\n    Set wdDoc = Nothing\n    Set wdApp = Nothing\nEnd Sub\n\n'批次解除 Word 文件保護\nSub BatchUnprotectWordDocuments()\n    Dim wdApp     As Object\n    Dim wdDoc     As Object\n    Dim strFolder As String\n    Dim strFile   As String\n    Dim strPwd    As String\n    Dim lngOK     As Long\n    Dim lngFail   As Long\n    Dim strFailed As String\n\n    On Error GoTo ErrHandler\n\n    strPwd = InputBox(\"請輸入現有保護密碼：\", \"解除文件保護\")\n    If strPwd = \"\" Then\n        MsgBox \"密碼為空，操作取消。\", vbInformation, \"提示\"\n        Exit Sub\n    End If\n\n    With Application.FileDialog(4)\n        .Title = \"請選擇 Word 文件資料夾\"\n        If .Show <> -1 Then Exit Sub\n        strFolder = .SelectedItems(1)\n    End With\n    If Right(strFolder, 1) <> \"\\\" Then strFolder = strFolder & \"\\\"\n\n    Set wdApp = CreateObject(\"Word.Application\")\n    wdApp.Visible = False\n    lngOK = 0\n    lngFail = 0\n\n    strFile = Dir(strFolder & \"*.docx\")\n    Do While strFile <> \"\"\n        On Error Resume Next\n        Set wdDoc = wdApp.Documents.Open(strFolder & strFile)\n\n        If Err.Number = 0 Then\n            If wdDoc.ProtectionType <> -1 Then   'wdNoProtection = -1\n                wdDoc.Unprotect Password:=strPwd\n                If Err.Number = 0 Then\n                    wdDoc.Save\n                    lngOK = lngOK + 1\n                Else\n                    lngFail = lngFail + 1\n                    strFailed = strFailed & strFile & \"（密碼錯誤）\" & vbCrLf\n                    Err.Clear\n                End If\n            Else\n                lngOK = lngOK + 1  '未保護，直接計數\n            End If\n            wdDoc.Close False\n            Set wdDoc = Nothing\n        Else\n            lngFail = lngFail + 1\n            strFailed = strFailed & strFile & vbCrLf\n            Err.Clear\n        End If\n        On Error GoTo ErrHandler\n\n        strFile = Dir()\n    Loop\n\n    wdApp.Quit\n    Set wdApp = Nothing\n\n    Dim strMsg As String\n    strMsg = \"解除保護完成！\" & vbCrLf & _\n             \"成功：\" & lngOK & \" 個\" & vbCrLf & _\n             \"失敗：\" & lngFail & \" 個\"\n    If strFailed <> \"\" Then strMsg = strMsg & vbCrLf & \"失敗清單：\" & vbCrLf & strFailed\n    MsgBox strMsg, vbInformation, \"完成\"\n    Exit Sub\n\nErrHandler:\n    MsgBox \"發生錯誤：\" & Err.Number & \" - \" & Err.Description, vbCritical, \"錯誤\"\n    If Not wdDoc Is Nothing Then wdDoc.Close False\n    If Not wdApp Is Nothing Then wdApp.Quit\n    Set wdDoc = Nothing\n    Set wdApp = Nothing\nEnd Sub\n", "content_b64": ""}, {"name": "BatchReplaceInWord.bas", "path": "模組/Word/BatchReplaceInWord.bas", "content": "Attribute VB_Name = \"BatchReplaceInWord\"\n\nOption Explicit\n\n'*************************************************************************************\n\n'模組名稱: BatchReplaceInWord\n\n'功能說明: 批次取代指定資料夾內所有 Word 文件中的特定文字\n\n'\n\n'版權所有: Dunk\n\n'程式撰寫: Dunk\n\n'撰寫日期: 2026/05/10\n\n'\n\n'使用方式:\n\n'  1. 在 Excel 工作表 A 欄填入「尋找文字」，B 欄填入「取代文字」\n\n'  2. 執行 BatchReplaceTextInWordFiles\n\n'  3. 選擇要處理的 Word 文件資料夾\n\n'  4. 程式將自動逐一開啟、取代並儲存所有 .docx 檔案\n\n'\n\n'注意事項:\n\n'  - 工作表第一列為標題，資料從第二列開始\n\n'  - 取代後原始檔案將被覆蓋，請先備份\n\n'*************************************************************************************\n\n\n\n'批次取代資料夾內 Word 文件文字\n\nSub BatchReplaceTextInWordFiles()\n\n    Dim wsRule       As Worksheet\n\n    Dim wdApp        As Object\n\n    Dim wdDoc        As Object\n\n    Dim strFolder    As String\n\n    Dim strFile      As String\n\n    Dim lngRow       As Long\n\n    Dim lngLastRow   As Long\n\n    Dim lngCount     As Long\n\n    Dim lngFileCount As Long\n\n    Dim arrFind()    As String\n\n    Dim arrReplace() As String\n\n    Dim i            As Long\n\n\n\n    On Error GoTo ErrHandler\n\n\n\n    Set wsRule = ActiveSheet\n\n\n\n    '讀取取代規則（A欄=尋找，B欄=取代）\n\n    lngLastRow = wsRule.Cells(wsRule.Rows.Count, 1).End(xlUp).Row\n\n    If lngLastRow < 2 Then\n\n        MsgBox \"請在 A 欄填入尋找文字，B 欄填入取代文字（第二列起）！\", vbExclamation, \"提示\"\n\n        Exit Sub\n\n    End If\n\n\n\n    lngCount = lngLastRow - 1\n\n    ReDim arrFind(1 To lngCount)\n\n    ReDim arrReplace(1 To lngCount)\n\n\n\n    For lngRow = 2 To lngLastRow\n\n        arrFind(lngRow - 1) = CStr(wsRule.Cells(lngRow, 1).Value)\n\n        arrReplace(lngRow - 1) = CStr(wsRule.Cells(lngRow, 2).Value)\n\n    Next lngRow\n\n\n\n    '選擇目標資料夾（msoFileDialogFolderPicker = 4）\n\n    With Application.FileDialog(4)\n\n        .Title = \"請選擇含有 Word 文件的資料夾\"\n\n        If .Show <> -1 Then\n\n            MsgBox \"已取消操作。\", vbInformation, \"提示\"\n\n            Exit Sub\n\n        End If\n\n        strFolder = .SelectedItems(1)\n\n    End With\n\n\n\n    If Right(strFolder, 1) <> \"\\\" Then strFolder = strFolder & \"\\\"\n\n\n\n    '建立 Word 物件（背景執行）\n\n    Set wdApp = CreateObject(\"Word.Application\")\n\n    wdApp.Visible = False\n\n\n\n    '逐一處理 .docx 檔案\n\n    lngFileCount = 0\n\n    strFile = Dir(strFolder & \"*.docx\")\n\n\n\n    Do While strFile <> \"\"\n\n        Set wdDoc = wdApp.Documents.Open(strFolder & strFile)\n\n\n\n        '套用所有取代規則\n\n        For i = 1 To lngCount\n\n            If arrFind(i) <> \"\" Then\n\n                With wdDoc.Content.Find\n\n                    .ClearFormatting\n\n                    .Replacement.ClearFormatting\n\n                    .Text = arrFind(i)\n\n                    .Replacement.Text = arrReplace(i)\n\n                    .Forward = True\n\n                    .Wrap = 1           'wdFindContinue = 1\n\n                    .MatchCase = False\n\n                    .Execute Replace:=2  'wdReplaceAll = 2\n\n                End With\n\n            End If\n\n        Next i\n\n\n\n        wdDoc.Save\n\n        wdDoc.Close False\n\n        Set wdDoc = Nothing\n\n        lngFileCount = lngFileCount + 1\n\n        strFile = Dir()\n\n    Loop\n\n\n\n    wdApp.Quit\n\n    Set wdApp = Nothing\n\n\n\n    MsgBox \"批次取代完成！\" & vbCrLf & _\n\n           \"共處理 \" & lngFileCount & \" 個 Word 文件。\", _\n\n           vbInformation, \"完成\"\n\n\n\n    Set wsRule = Nothing\n\n    Exit Sub\n\n\n\nErrHandler:\n\n    MsgBox \"發生錯誤：\" & Err.Number & \" - \" & Err.Description, vbCritical, \"錯誤\"\n\n    If Not wdDoc Is Nothing Then wdDoc.Close False\n\n    If Not wdApp Is Nothing Then wdApp.Quit\n\n    Set wdDoc = Nothing\n\n    Set wdApp = Nothing\n\nEnd Sub\n\n", "content_b64": ""}, {"name": "ExportExcelToWord.bas", "path": "模組/Word/ExportExcelToWord.bas", "content": "Attribute VB_Name = \"ExportExcelToWord\"\n\nOption Explicit\n\n'*************************************************************************************\n\n'模組名稱: ExportExcelToWord\n\n'功能說明: 將 Excel 工作表資料匯出為 Word 文件表格\n\n'\n\n'版權所有: Dunk\n\n'程式撰寫: Dunk\n\n'撰寫日期: 2026/05/10\n\n'\n\n'使用方式:\n\n'  1. 在 Excel 工作表中準備資料（第一列為標題）\n\n'  2. 執行 ExportSheetDataToWord\n\n'  3. Word 文件將自動開啟並插入完整表格\n\n'\n\n'注意事項:\n\n'  - 需啟用 Microsoft Word Object Library 參考\n\n'  - 資料範圍以 UsedRange 自動偵測\n\n'*************************************************************************************\n\n\n\n'將當前工作表資料匯出至新 Word 文件\n\nSub ExportSheetDataToWord()\n\n    Dim wsData      As Worksheet\n\n    Dim rngData     As Range\n\n    Dim wdApp       As Object\n\n    Dim wdDoc       As Object\n\n    Dim wdTable     As Object\n\n    Dim lngRows     As Long\n\n    Dim lngCols     As Long\n\n    Dim i           As Long\n\n    Dim j           As Long\n\n    Dim strSavePath As String\n\n\n\n    On Error GoTo ErrHandler\n\n\n\n    Set wsData = ActiveSheet\n\n\n\n    '確認工作表有資料\n\n    If wsData.UsedRange.Cells.Count <= 1 Then\n\n        MsgBox \"工作表無資料可匯出！\", vbExclamation, \"提示\"\n\n        Exit Sub\n\n    End If\n\n\n\n    Set rngData = wsData.UsedRange\n\n    lngRows = rngData.Rows.Count\n\n    lngCols = rngData.Columns.Count\n\n\n\n    '建立 Word 應用程式物件\n\n    Set wdApp = CreateObject(\"Word.Application\")\n\n    wdApp.Visible = True\n\n\n\n    '建立新文件\n\n    Set wdDoc = wdApp.Documents.Add\n\n\n\n    '插入標題\n\n    With wdDoc.Content\n\n        .InsertAfter wsData.Name & \" 資料報表\"\n\n        .InsertParagraphAfter\n\n    End With\n\n\n\n    '設定標題格式\n\n    With wdDoc.Paragraphs(1).Range\n\n        .Style = \"Heading 1\"\n\n        .Bold = True\n\n    End With\n\n\n\n    '在文件末端插入段落後建立表格\n\n    wdDoc.Content.InsertParagraphAfter\n\n    Set wdTable = wdDoc.Tables.Add( _\n\n        Range:=wdDoc.Paragraphs(wdDoc.Paragraphs.Count).Range, _\n\n        NumRows:=lngRows, _\n\n        NumColumns:=lngCols)\n\n\n\n    '填入資料至 Word 表格\n\n    For i = 1 To lngRows\n\n        For j = 1 To lngCols\n\n            wdTable.Cell(i, j).Range.Text = _\n\n                CStr(rngData.Cells(i, j).Value)\n\n        Next j\n\n    Next i\n\n\n\n    '設定表格樣式：標題列粗體並加底色\n\n    With wdTable.Rows(1)\n\n        .Range.Bold = True\n\n        .Shading.BackgroundPatternColor = RGB(180, 198, 231)\n\n    End With\n\n\n\n    '自動調整欄寬（wdAutoFitContent = 1）\n\n    wdTable.AutoFitBehavior 1\n\n\n\n    '套用表格框線\n\n    wdTable.Borders.Enable = True\n\n\n\n    '提示儲存路徑\n\n    strSavePath = Application.GetSaveAsFilename( _\n\n        InitialFileName:=wsData.Name & \"_報表.docx\", _\n\n        FileFilter:=\"Word 文件 (*.docx), *.docx\")\n\n\n\n    If strSavePath <> \"False\" Then\n\n        wdDoc.SaveAs2 strSavePath, 16\n\n        MsgBox \"匯出成功！\" & vbCrLf & \"已儲存至：\" & vbCrLf & strSavePath, vbInformation, \"完成\"\n\n    Else\n\n        MsgBox \"已取消儲存，文件仍開啟中。\", vbInformation, \"提示\"\n\n    End If\n\n\n\n    Set wdTable = Nothing\n\n    Set wdDoc = Nothing\n\n    Set wdApp = Nothing\n\n    Set rngData = Nothing\n\n    Set wsData = Nothing\n\n    Exit Sub\n\n\n\nErrHandler:\n\n    MsgBox \"發生錯誤：\" & Err.Number & \" - \" & Err.Description, vbCritical, \"錯誤\"\n\n    If Not wdDoc Is Nothing Then wdDoc.Close False\n\n    If Not wdApp Is Nothing Then wdApp.Quit\n\n    Set wdTable = Nothing\n\n    Set wdDoc = Nothing\n\n    Set wdApp = Nothing\n\nEnd Sub\n\n", "content_b64": ""}, {"name": "ExtractWordTextToExcel.bas", "path": "模組/Word/ExtractWordTextToExcel.bas", "content": "Attribute VB_Name = \"ExtractWordTextToExcel\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: ExtractWordTextToExcel\n'功能說明: 擷取資料夾內所有 Word 文件的段落文字，彙整至 Excel 工作表\n'\n'版權所有: Dunk\n'程式撰寫: Dunk\n'撰寫日期: 2026/05/10\n'\n'使用方式:\n'  1. 執行 ExtractAllWordTextToSheet\n'  2. 選擇含有 .docx 文件的資料夾\n'  3. 結果寫入新工作表「WordText」，欄位：檔名 | 段落序號 | 段落文字\n'\n'注意事項:\n'  - 空白段落將略過\n'  - 大量文件時處理時間較長，請耐心等待\n'*************************************************************************************\n\n'擷取所有 Word 文件段落文字至 Excel\nSub ExtractAllWordTextToSheet()\n    Dim wdApp       As Object\n    Dim wdDoc       As Object\n    Dim wdPara      As Object\n    Dim strFolder   As String\n    Dim strFile     As String\n    Dim wsOut       As Worksheet\n    Dim lngOutRow   As Long\n    Dim lngParaIdx  As Long\n    Dim strParaText As String\n\n    On Error GoTo ErrHandler\n\n    With Application.FileDialog(4)\n        .Title = \"請選擇含有 Word 文件的資料夾\"\n        If .Show <> -1 Then Exit Sub\n        strFolder = .SelectedItems(1)\n    End With\n    If Right(strFolder, 1) <> \"\\\" Then strFolder = strFolder & \"\\\"\n\n    '建立輸出工作表\n    Application.DisplayAlerts = False\n    On Error Resume Next\n    ThisWorkbook.Sheets(\"WordText\").Delete\n    On Error GoTo ErrHandler\n    Application.DisplayAlerts = True\n\n    Set wsOut = ThisWorkbook.Sheets.Add(After:=ThisWorkbook.Sheets(ThisWorkbook.Sheets.Count))\n    wsOut.Name = \"WordText\"\n\n    '寫入標題\n    With wsOut\n        .Cells(1, 1).Value = \"檔案名稱\"\n        .Cells(1, 2).Value = \"段落序號\"\n        .Cells(1, 3).Value = \"段落文字\"\n        .Rows(1).Font.Bold = True\n    End With\n    lngOutRow = 2\n\n    Set wdApp = CreateObject(\"Word.Application\")\n    wdApp.Visible = False\n\n    strFile = Dir(strFolder & \"*.docx\")\n\n    Do While strFile <> \"\"\n        Set wdDoc = wdApp.Documents.Open(strFolder & strFile)\n        lngParaIdx = 0\n\n        For Each wdPara In wdDoc.Paragraphs\n            strParaText = Trim(wdPara.Range.Text)\n            '移除段落結尾特殊字元\n            If Len(strParaText) > 0 Then\n                strParaText = Left(strParaText, Len(strParaText) - 1)\n            End If\n\n            If strParaText <> \"\" Then\n                lngParaIdx = lngParaIdx + 1\n                wsOut.Cells(lngOutRow, 1).Value = strFile\n                wsOut.Cells(lngOutRow, 2).Value = lngParaIdx\n                wsOut.Cells(lngOutRow, 3).Value = strParaText\n                lngOutRow = lngOutRow + 1\n            End If\n        Next wdPara\n\n        wdDoc.Close False\n        Set wdDoc = Nothing\n        strFile = Dir()\n    Loop\n\n    wdApp.Quit\n    Set wdApp = Nothing\n\n    wsOut.Columns.AutoFit\n    MsgBox \"擷取完成！共寫入 \" & lngOutRow - 2 & \" 筆段落資料。\", _\n           vbInformation, \"完成\"\n    Set wsOut = Nothing\n    Exit Sub\n\nErrHandler:\n    MsgBox \"發生錯誤：\" & Err.Number & \" - \" & Err.Description, vbCritical, \"錯誤\"\n    If Not wdDoc Is Nothing Then wdDoc.Close False\n    If Not wdApp Is Nothing Then wdApp.Quit\n    Set wdDoc = Nothing\n    Set wdApp = Nothing\nEnd Sub\n", "content_b64": ""}, {"name": "FillWordBookmarks.bas", "path": "模組/Word/FillWordBookmarks.bas", "content": "Attribute VB_Name = \"FillWordBookmarks\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: FillWordBookmarks\n'功能說明: 以 Excel 工作表每列資料填入 Word 範本書籤，批次產生個人化文件\n'\n'版權所有: Dunk\n'程式撰寫: Dunk\n'撰寫日期: 2026/05/10\n'\n'使用方式:\n'  1. 在 Word 範本中設定書籤（Bookmark），名稱需與 Excel 標題列相同\n'  2. Excel 第一列為欄位名稱（對應書籤名稱），第二列起為資料\n'  3. 執行 FillBookmarksFromExcel\n'  4. 選擇 Word 範本檔案，再選擇輸出資料夾\n'  5. 程式為每列資料產生一份獨立的 Word 文件\n'\n'注意事項:\n'  - 書籤名稱不可含有空格，建議使用英文\n'  - 輸出檔名為「列序號_欄A值.docx」\n'*************************************************************************************\n\n'以 Excel 資料填入 Word 書籤並批次輸出\nSub FillBookmarksFromExcel()\n    Dim wsData       As Worksheet\n    Dim wdApp        As Object\n    Dim wdDoc        As Object\n    Dim strTemplate  As String\n    Dim strOutFolder As String\n    Dim strOutFile   As String\n    Dim lngLastRow   As Long\n    Dim lngLastCol   As Long\n    Dim lngRow       As Long\n    Dim lngCol       As Long\n    Dim strBmkName   As String\n    Dim strValue     As String\n    Dim lngCount     As Long\n\n    On Error GoTo ErrHandler\n\n    Set wsData = ActiveSheet\n\n    lngLastRow = wsData.Cells(wsData.Rows.Count, 1).End(xlUp).Row\n    lngLastCol = wsData.Cells(1, wsData.Columns.Count).End(xlToLeft).Column\n\n    If lngLastRow < 2 Then\n        MsgBox \"工作表無資料列！\", vbExclamation, \"提示\"\n        Exit Sub\n    End If\n\n    '選擇 Word 範本\n    strTemplate = Application.GetOpenFilename( _\n        FileFilter:=\"Word 文件 (*.docx), *.docx\", _\n        Title:=\"請選擇 Word 書籤範本\")\n    If strTemplate = \"False\" Then Exit Sub\n\n    '選擇輸出資料夾\n    With Application.FileDialog(4)\n        .Title = \"請選擇輸出資料夾\"\n        If .Show <> -1 Then Exit Sub\n        strOutFolder = .SelectedItems(1)\n    End With\n    If Right(strOutFolder, 1) <> \"\\\" Then strOutFolder = strOutFolder & \"\\\"\n\n    Set wdApp = CreateObject(\"Word.Application\")\n    wdApp.Visible = False\n    lngCount = 0\n\n    '逐列處理資料\n    For lngRow = 2 To lngLastRow\n        '開啟範本副本\n        Set wdDoc = wdApp.Documents.Open(strTemplate)\n\n        '逐欄對應書籤並填入資料\n        For lngCol = 1 To lngLastCol\n            strBmkName = Trim(CStr(wsData.Cells(1, lngCol).Value))\n            strValue = CStr(wsData.Cells(lngRow, lngCol).Value)\n\n            If strBmkName <> \"\" Then\n                If wdDoc.Bookmarks.Exists(strBmkName) Then\n                    wdDoc.Bookmarks(strBmkName).Range.Text = strValue\n                End If\n            End If\n        Next lngCol\n\n        '輸出檔案\n        strOutFile = strOutFolder & lngRow - 1 & \"_\" & _\n            CStr(wsData.Cells(lngRow, 1).Value) & \".docx\"\n        wdDoc.SaveAs2 strOutFile, 16\n        wdDoc.Close False\n        Set wdDoc = Nothing\n        lngCount = lngCount + 1\n    Next lngRow\n\n    wdApp.Quit\n    Set wdApp = Nothing\n    Set wsData = Nothing\n\n    MsgBox \"批次產生完成！\" & vbCrLf & _\n           \"共產生 \" & lngCount & \" 份文件。\" & vbCrLf & _\n           \"輸出位置：\" & strOutFolder, vbInformation, \"完成\"\n    Exit Sub\n\nErrHandler:\n    MsgBox \"發生錯誤：\" & Err.Number & \" - \" & Err.Description, vbCritical, \"錯誤\"\n    If Not wdDoc Is Nothing Then wdDoc.Close False\n    If Not wdApp Is Nothing Then wdApp.Quit\n    Set wdDoc = Nothing\n    Set wdApp = Nothing\nEnd Sub\n", "content_b64": ""}, {"name": "InsertExcelChartToWord.bas", "path": "模組/Word/InsertExcelChartToWord.bas", "content": "Attribute VB_Name = \"InsertExcelChartToWord\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: InsertExcelChartToWord\n'功能說明: 將 Excel 活頁簿中所有圖表依序插入新 Word 文件\n'\n'版權所有: Dunk\n'程式撰寫: Dunk\n'撰寫日期: 2026/05/10\n'\n'使用方式:\n'  1. 確認 Excel 活頁簿含有至少一張圖表（內嵌或圖表工作表）\n'  2. 執行 ExportAllChartsToWord\n'  3. 選擇 Word 文件儲存路徑\n'  4. 程式將所有圖表以圖片貼入 Word，每張圖後分頁\n'\n'注意事項:\n'  - 圖表以 Enhanced Metafile (EMF) 格式插入，保持向量品質\n'  - 圖表工作表與內嵌圖表均支援\n'*************************************************************************************\n\n'將 Excel 圖表全部匯出至 Word 文件\nSub ExportAllChartsToWord()\n    Dim wdApp       As Object\n    Dim wdDoc       As Object\n    Dim wdRng       As Object\n    Dim ws          As Worksheet\n    Dim chtObj      As ChartObject\n    Dim cht         As Chart\n    Dim strSavePath As String\n    Dim lngCount    As Long\n    Dim strTmpImg   As String\n\n    On Error GoTo ErrHandler\n\n    '確認活頁簿有圖表\n    lngCount = 0\n    For Each ws In ThisWorkbook.Worksheets\n        lngCount = lngCount + ws.ChartObjects.Count\n    Next ws\n    For Each cht In ThisWorkbook.Charts\n        lngCount = lngCount + 1\n    Next cht\n\n    If lngCount = 0 Then\n        MsgBox \"活頁簿中找不到任何圖表！\", vbExclamation, \"提示\"\n        Exit Sub\n    End If\n\n    '選擇儲存路徑\n    strSavePath = Application.GetSaveAsFilename( _\n        InitialFileName:=\"圖表報告.docx\", _\n        FileFilter:=\"Word 文件 (*.docx), *.docx\")\n    If strSavePath = \"False\" Then Exit Sub\n\n    Set wdApp = CreateObject(\"Word.Application\")\n    wdApp.Visible = False\n    Set wdDoc = wdApp.Documents.Add\n\n    '臨時圖片路徑\n    strTmpImg = Environ(\"TEMP\") & \"\\~chart_tmp.emf\"\n\n    lngCount = 0\n\n    '處理內嵌圖表\n    For Each ws In ThisWorkbook.Worksheets\n        For Each chtObj In ws.ChartObjects\n            chtObj.Chart.Export strTmpImg, \"EMF\"\n            Set wdRng = wdDoc.Bookmarks(\"\\EndOfDoc\").Range\n\n            '插入圖表標題\n            wdRng.InsertAfter ws.Name & \" - \" & chtObj.Name\n            wdRng.InsertParagraphAfter\n            wdRng.Collapse 0\n\n            '插入圖片\n            wdDoc.InlineShapes.AddPicture _\n                FileName:=strTmpImg, _\n                LinkToFile:=False, _\n                SaveWithDocument:=True, _\n                Range:=wdRng\n\n            lngCount = lngCount + 1\n            If lngCount < ThisWorkbook.Sheets.Count Then\n                Set wdRng = wdDoc.Bookmarks(\"\\EndOfDoc\").Range\n                wdRng.InsertBreak 7\n            End If\n        Next chtObj\n    Next ws\n\n    '處理圖表工作表\n    For Each cht In ThisWorkbook.Charts\n        cht.Export strTmpImg, \"EMF\"\n        Set wdRng = wdDoc.Bookmarks(\"\\EndOfDoc\").Range\n        wdRng.InsertAfter cht.Name\n        wdRng.InsertParagraphAfter\n        wdRng.Collapse 0\n\n        wdDoc.InlineShapes.AddPicture _\n            FileName:=strTmpImg, _\n            LinkToFile:=False, _\n            SaveWithDocument:=True, _\n            Range:=wdRng\n\n        lngCount = lngCount + 1\n    Next cht\n\n    '刪除臨時檔案\n    On Error Resume Next\n    Kill strTmpImg\n    On Error GoTo ErrHandler\n\n    wdDoc.SaveAs2 strSavePath, 16\n    wdApp.Visible = True\n\n    MsgBox \"圖表匯出完成！\" & vbCrLf & _\n           \"共插入 \" & lngCount & \" 張圖表。\" & vbCrLf & _\n           \"已儲存至：\" & strSavePath, vbInformation, \"完成\"\n\n    Set wdRng = Nothing\n    Set wdDoc = Nothing\n    Set wdApp = Nothing\n    Exit Sub\n\nErrHandler:\n    MsgBox \"發生錯誤：\" & Err.Number & \" - \" & Err.Description, vbCritical, \"錯誤\"\n    If Not wdDoc Is Nothing Then wdDoc.Close False\n    If Not wdApp Is Nothing Then wdApp.Quit\n    Set wdRng = Nothing\n    Set wdDoc = Nothing\n    Set wdApp = Nothing\nEnd Sub\n", "content_b64": ""}, {"name": "MergeWordDocuments.bas", "path": "模組/Word/MergeWordDocuments.bas", "content": "Attribute VB_Name = \"MergeWordDocuments\"\n\nOption Explicit\n\n'*************************************************************************************\n\n'模組名稱: MergeWordDocuments\n\n'功能說明: 將指定資料夾內的所有 Word 文件合併為單一文件\n\n'\n\n'版權所有: Dunk\n\n'程式撰寫: Dunk\n\n'撰寫日期: 2026/05/10\n\n'\n\n'使用方式:\n\n'  1. 執行 MergeAllWordDocumentsInFolder\n\n'  2. 選擇包含多個 .docx 文件的資料夾\n\n'  3. 程式依檔名排序後逐一合併，每份文件後自動插入分頁符號\n\n'  4. 完成後提示儲存合併後文件\n\n'\n\n'注意事項:\n\n'  - 合併後的文件為全新文件，原始文件不受影響\n\n'  - 需啟用 Microsoft Word Object Library 參考\n\n'*************************************************************************************\n\n\n\n'合併資料夾內所有 Word 文件\n\nSub MergeAllWordDocumentsInFolder()\n\n    Dim wdApp       As Object\n\n    Dim wdMerged    As Object\n\n    Dim wdSrc       As Object\n\n    Dim strFolder   As String\n\n    Dim strFile     As String\n\n    Dim strSavePath As String\n\n    Dim strTemp     As String\n\n    Dim colFiles    As Collection\n\n    Dim varFile     As Variant\n\n    Dim lngCount    As Long\n\n    Dim arrFiles()  As String\n\n    Dim k           As Long\n\n    Dim m           As Long\n\n\n\n    On Error GoTo ErrHandler\n\n\n\n    '選擇目標資料夾（msoFileDialogFolderPicker = 4）\n\n    With Application.FileDialog(4)\n\n        .Title = \"請選擇要合併的 Word 文件資料夾\"\n\n        If .Show <> -1 Then\n\n            MsgBox \"已取消操作。\", vbInformation, \"提示\"\n\n            Exit Sub\n\n        End If\n\n        strFolder = .SelectedItems(1)\n\n    End With\n\n\n\n    If Right(strFolder, 1) <> \"\\\" Then strFolder = strFolder & \"\\\"\n\n\n\n    '收集所有 .docx 檔案\n\n    Set colFiles = New Collection\n\n    strFile = Dir(strFolder & \"*.docx\")\n\n    Do While strFile <> \"\"\n\n        colFiles.Add strFolder & strFile\n\n        strFile = Dir()\n\n    Loop\n\n\n\n    If colFiles.Count = 0 Then\n\n        MsgBox \"所選資料夾中找不到 .docx 文件！\", vbExclamation, \"提示\"\n\n        Exit Sub\n\n    End If\n\n\n\n    '將 Collection 轉為陣列以便排序\n\n    ReDim arrFiles(1 To colFiles.Count)\n\n    k = 1\n\n    For Each varFile In colFiles\n\n        arrFiles(k) = CStr(varFile)\n\n        k = k + 1\n\n    Next varFile\n\n\n\n    '氣泡排序（依檔名升冪）\n\n    For k = 1 To UBound(arrFiles) - 1\n\n        For m = 1 To UBound(arrFiles) - k\n\n            If arrFiles(m) > arrFiles(m + 1) Then\n\n                strTemp = arrFiles(m)\n\n                arrFiles(m) = arrFiles(m + 1)\n\n                arrFiles(m + 1) = strTemp\n\n            End If\n\n        Next m\n\n    Next k\n\n\n\n    '建立 Word 物件\n\n    Set wdApp = CreateObject(\"Word.Application\")\n\n    wdApp.Visible = False\n\n\n\n    '建立合併目標文件\n\n    Set wdMerged = wdApp.Documents.Add\n\n    lngCount = 0\n\n\n\n    '逐一插入各文件內容\n\n    For k = 1 To UBound(arrFiles)\n\n        Set wdSrc = wdApp.Documents.Open(arrFiles(k))\n\n\n\n        '複製全文內容至合併文件末端\n\n        wdSrc.Content.Copy\n\n        wdMerged.Bookmarks(\"\\EndOfDoc\").Range.Paste\n\n\n\n        '插入分頁符號（最後一份除外，wdPageBreak = 7）\n\n        If k < UBound(arrFiles) Then\n\n            wdMerged.Bookmarks(\"\\EndOfDoc\").Range.InsertBreak 7\n\n        End If\n\n\n\n        wdSrc.Close False\n\n        Set wdSrc = Nothing\n\n        lngCount = lngCount + 1\n\n    Next k\n\n\n\n    '顯示合併文件\n\n    wdApp.Visible = True\n\n\n\n    '提示儲存路徑\n\n    strSavePath = Application.GetSaveAsFilename( _\n\n        InitialFileName:=\"合併文件.docx\", _\n\n        FileFilter:=\"Word 文件 (*.docx), *.docx\")\n\n\n\n    If strSavePath <> \"False\" Then\n\n        wdMerged.SaveAs2 strSavePath, 16\n\n        MsgBox \"合併完成！\" & vbCrLf & _\n\n               \"共合併 \" & lngCount & \" 個文件。\" & vbCrLf & _\n\n               \"已儲存至：\" & strSavePath, vbInformation, \"完成\"\n\n    Else\n\n        MsgBox \"已取消儲存，合併文件仍開啟中。\", vbInformation, \"提示\"\n\n    End If\n\n\n\n    Set wdMerged = Nothing\n\n    Set wdApp = Nothing\n\n    Set colFiles = Nothing\n\n    Exit Sub\n\n\n\nErrHandler:\n\n    MsgBox \"發生錯誤：\" & Err.Number & \" - \" & Err.Description, vbCritical, \"錯誤\"\n\n    If Not wdSrc Is Nothing Then wdSrc.Close False\n\n    If Not wdMerged Is Nothing Then wdMerged.Close False\n\n    If Not wdApp Is Nothing Then wdApp.Quit\n\n    Set wdSrc = Nothing\n\n    Set wdMerged = Nothing\n\n    Set wdApp = Nothing\n\nEnd Sub\n\n", "content_b64": ""}, {"name": "SetWordPageLayout.bas", "path": "模組/Word/SetWordPageLayout.bas", "content": "Attribute VB_Name = \"SetWordPageLayout\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: SetWordPageLayout\n'功能說明: 批次設定資料夾內所有 Word 文件的頁面版面配置\n'          （紙張大小、方向、邊界）\n'\n'版權所有: Dunk\n'程式撰寫: Dunk\n'撰寫日期: 2026/05/10\n'\n'使用方式:\n'  1. 執行 BatchSetWordPageLayout\n'  2. 選擇紙張大小（A4 / A3 / Letter）\n'  3. 選擇方向（直向 / 橫向）\n'  4. 輸入上下左右邊界（公分）\n'  5. 選擇目標資料夾，程式自動套用\n'\n'注意事項:\n'  - 1 公分 = 567 twips（Word 內部單位）\n'  - 預設值以 A4 直向、2.54cm 邊界為基準\n'*************************************************************************************\n\n'批次設定 Word 頁面版面\nSub BatchSetWordPageLayout()\n    Const CM_TO_TWIPS As Double = 567\n\n    Dim wdApp        As Object\n    Dim wdDoc        As Object\n    Dim wdSec        As Object\n    Dim strFolder    As String\n    Dim strFile      As String\n    Dim lngPaperSize As Long\n    Dim lngOrient    As Long\n    Dim dblTop       As Double\n    Dim dblBottom    As Double\n    Dim dblLeft      As Double\n    Dim dblRight     As Double\n    Dim lngCount     As Long\n    Dim strChoice    As String\n\n    On Error GoTo ErrHandler\n\n    '選擇紙張大小\n    strChoice = InputBox(\"請輸入紙張大小：\" & vbCrLf & _\n                         \"1 = A4\" & vbCrLf & _\n                         \"2 = A3\" & vbCrLf & _\n                         \"3 = Letter\", \"紙張大小\", \"1\")\n    Select Case strChoice\n        Case \"1\": lngPaperSize = 9    'wdPaperA4 = 9\n        Case \"2\": lngPaperSize = 8    'wdPaperA3 = 8\n        Case \"3\": lngPaperSize = 1    'wdPaperLetter = 1\n        Case Else\n            MsgBox \"無效選擇，操作取消。\", vbExclamation, \"提示\"\n            Exit Sub\n    End Select\n\n    '選擇方向\n    strChoice = InputBox(\"請輸入頁面方向：\" & vbCrLf & _\n                         \"0 = 直向\" & vbCrLf & _\n                         \"1 = 橫向\", \"頁面方向\", \"0\")\n    Select Case strChoice\n        Case \"0\": lngOrient = 0   'wdOrientPortrait = 0\n        Case \"1\": lngOrient = 1   'wdOrientLandscape = 1\n        Case Else\n            MsgBox \"無效選擇，操作取消。\", vbExclamation, \"提示\"\n            Exit Sub\n    End Select\n\n    '輸入邊界（公分）\n    dblTop = CDbl(InputBox(\"上邊界（公分）：\", \"邊界設定\", \"2.54\"))\n    dblBottom = CDbl(InputBox(\"下邊界（公分）：\", \"邊界設定\", \"2.54\"))\n    dblLeft = CDbl(InputBox(\"左邊界（公分）：\", \"邊界設定\", \"3.17\"))\n    dblRight = CDbl(InputBox(\"右邊界（公分）：\", \"邊界設定\", \"3.17\"))\n\n    '選擇目標資料夾\n    With Application.FileDialog(4)\n        .Title = \"請選擇 Word 文件資料夾\"\n        If .Show <> -1 Then Exit Sub\n        strFolder = .SelectedItems(1)\n    End With\n    If Right(strFolder, 1) <> \"\\\" Then strFolder = strFolder & \"\\\"\n\n    Set wdApp = CreateObject(\"Word.Application\")\n    wdApp.Visible = False\n\n    lngCount = 0\n    strFile = Dir(strFolder & \"*.docx\")\n\n    Do While strFile <> \"\"\n        Set wdDoc = wdApp.Documents.Open(strFolder & strFile)\n\n        For Each wdSec In wdDoc.Sections\n            With wdSec.PageSetup\n                .PaperSize = lngPaperSize\n                .Orientation = lngOrient\n                .TopMargin = dblTop * CM_TO_TWIPS\n                .BottomMargin = dblBottom * CM_TO_TWIPS\n                .LeftMargin = dblLeft * CM_TO_TWIPS\n                .RightMargin = dblRight * CM_TO_TWIPS\n            End With\n        Next wdSec\n\n        wdDoc.Save\n        wdDoc.Close False\n        Set wdDoc = Nothing\n        lngCount = lngCount + 1\n        strFile = Dir()\n    Loop\n\n    wdApp.Quit\n    Set wdApp = Nothing\n\n    MsgBox \"版面設定完成！\" & vbCrLf & _\n           \"共處理 \" & lngCount & \" 個文件。\", vbInformation, \"完成\"\n    Exit Sub\n\nErrHandler:\n    MsgBox \"發生錯誤：\" & Err.Number & \" - \" & Err.Description, vbCritical, \"錯誤\"\n    If Not wdDoc Is Nothing Then wdDoc.Close False\n    If Not wdApp Is Nothing Then wdApp.Quit\n    Set wdDoc = Nothing\n    Set wdApp = Nothing\nEnd Sub\n", "content_b64": ""}, {"name": "WordCommentExtractToExcel.bas", "path": "模組/Word/WordCommentExtractToExcel.bas", "content": "Attribute VB_Name = \"WordCommentExtractToExcel\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: WordCommentExtractToExcel\n'功能說明: 擷取 Word 文件中的所有批注（Comments）並彙整至 Excel\n'\n'版權所有: Dunk\n'程式撰寫: Dunk\n'撰寫日期: 2026/05/10\n'\n'使用方式:\n'  1. 執行 ExtractWordCommentsToExcel\n'  2. 選擇目標 Word 文件（支援單一檔案）\n'  3. 批注清單寫入新工作表「WordComments」\n'     欄位：序號 | 批注者 | 批注日期 | 被批注文字 | 批注內容\n'\n'注意事項:\n'  - 適用於程式碼審查、文件校對等場景\n'  - 若文件無批注，將顯示提示訊息\n'*************************************************************************************\n\n'擷取 Word 文件批注至 Excel\nSub ExtractWordCommentsToExcel()\n    Dim wdApp       As Object\n    Dim wdDoc       As Object\n    Dim wdCmt       As Object\n    Dim strFilePath As String\n    Dim wsOut       As Worksheet\n    Dim lngRow      As Long\n    Dim lngIdx      As Long\n\n    On Error GoTo ErrHandler\n\n    strFilePath = Application.GetOpenFilename( _\n        FileFilter:=\"Word 文件 (*.docx;*.doc), *.docx;*.doc\", _\n        Title:=\"請選擇含有批注的 Word 文件\")\n    If strFilePath = \"False\" Then Exit Sub\n\n    Set wdApp = CreateObject(\"Word.Application\")\n    wdApp.Visible = False\n    Set wdDoc = wdApp.Documents.Open(strFilePath)\n\n    If wdDoc.Comments.Count = 0 Then\n        MsgBox \"此文件中找不到任何批注！\", vbExclamation, \"提示\"\n        wdDoc.Close False\n        wdApp.Quit\n        Exit Sub\n    End If\n\n    '建立輸出工作表\n    Application.DisplayAlerts = False\n    On Error Resume Next\n    ThisWorkbook.Sheets(\"WordComments\").Delete\n    On Error GoTo ErrHandler\n    Application.DisplayAlerts = True\n\n    Set wsOut = ThisWorkbook.Sheets.Add(After:=ThisWorkbook.Sheets(ThisWorkbook.Sheets.Count))\n    wsOut.Name = \"WordComments\"\n\n    '標題列\n    With wsOut\n        .Cells(1, 1).Value = \"序號\"\n        .Cells(1, 2).Value = \"批注者\"\n        .Cells(1, 3).Value = \"批注日期\"\n        .Cells(1, 4).Value = \"被批注文字\"\n        .Cells(1, 5).Value = \"批注內容\"\n        .Rows(1).Font.Bold = True\n        .Rows(1).Interior.Color = RGB(180, 198, 231)\n    End With\n    lngRow = 2\n\n    '逐一讀取批注\n    lngIdx = 1\n    For Each wdCmt In wdDoc.Comments\n        wsOut.Cells(lngRow, 1).Value = lngIdx\n        wsOut.Cells(lngRow, 2).Value = wdCmt.Author\n        wsOut.Cells(lngRow, 3).Value = Format(wdCmt.Date, \"yyyy/mm/dd hh:mm\")\n        wsOut.Cells(lngRow, 4).Value = Trim(wdCmt.Scope.Text)\n        wsOut.Cells(lngRow, 5).Value = Trim(wdCmt.Range.Text)\n        lngRow = lngRow + 1\n        lngIdx = lngIdx + 1\n    Next wdCmt\n\n    wdDoc.Close False\n    wdApp.Quit\n    Set wdCmt = Nothing\n    Set wdDoc = Nothing\n    Set wdApp = Nothing\n\n    wsOut.Columns.AutoFit\n    MsgBox \"批注擷取完成！共擷取 \" & lngIdx - 1 & \" 筆批注。\", _\n           vbInformation, \"完成\"\n    Set wsOut = Nothing\n    Exit Sub\n\nErrHandler:\n    MsgBox \"發生錯誤：\" & Err.Number & \" - \" & Err.Description, vbCritical, \"錯誤\"\n    If Not wdDoc Is Nothing Then wdDoc.Close False\n    If Not wdApp Is Nothing Then wdApp.Quit\n    Set wdDoc = Nothing\n    Set wdApp = Nothing\nEnd Sub\n", "content_b64": ""}, {"name": "WordTableToExcel.bas", "path": "模組/Word/WordTableToExcel.bas", "content": "Attribute VB_Name = \"WordTableToExcel\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: WordTableToExcel\n'功能說明: 將指定 Word 文件中的所有表格資料匯入 Excel 工作表\n'\n'版權所有: Dunk\n'程式撰寫: Dunk\n'撰寫日期: 2026/05/10\n'\n'使用方式:\n'  1. 執行 ImportWordTablesToExcel\n'  2. 選擇目標 Word 文件\n'  3. 每張表格將匯入至新工作表，工作表名稱為「Table_N」\n'\n'注意事項:\n'  - 若 Word 表格有合併儲存格，內容取自左上格\n'  - 需啟用 Microsoft Word Object Library 參考\n'*************************************************************************************\n\n'匯入 Word 文件內所有表格至 Excel\nSub ImportWordTablesToExcel()\n    Dim wdApp       As Object\n    Dim wdDoc       As Object\n    Dim wdTable     As Object\n    Dim strFilePath As String\n    Dim wsNew       As Worksheet\n    Dim i           As Long\n    Dim j           As Long\n    Dim tbl         As Long\n    Dim strSheetName As String\n\n    On Error GoTo ErrHandler\n\n    '選擇 Word 文件\n    strFilePath = Application.GetOpenFilename( _\n        FileFilter:=\"Word 文件 (*.docx;*.doc), *.docx;*.doc\", _\n        Title:=\"請選擇要匯入的 Word 文件\")\n\n    If strFilePath = \"False\" Then\n        MsgBox \"已取消操作。\", vbInformation, \"提示\"\n        Exit Sub\n    End If\n\n    Set wdApp = CreateObject(\"Word.Application\")\n    wdApp.Visible = False\n    Set wdDoc = wdApp.Documents.Open(strFilePath)\n\n    If wdDoc.Tables.Count = 0 Then\n        MsgBox \"此文件中找不到任何表格！\", vbExclamation, \"提示\"\n        wdDoc.Close False\n        wdApp.Quit\n        Exit Sub\n    End If\n\n    '逐一處理每張表格\n    For tbl = 1 To wdDoc.Tables.Count\n        Set wdTable = wdDoc.Tables(tbl)\n\n        '建立新工作表\n        strSheetName = \"Table_\" & tbl\n        On Error Resume Next\n        Application.DisplayAlerts = False\n        ThisWorkbook.Sheets(strSheetName).Delete\n        Application.DisplayAlerts = True\n        On Error GoTo ErrHandler\n\n        Set wsNew = ThisWorkbook.Sheets.Add(After:=ThisWorkbook.Sheets(ThisWorkbook.Sheets.Count))\n        wsNew.Name = strSheetName\n\n        '逐列逐欄寫入資料\n        For i = 1 To wdTable.Rows.Count\n            For j = 1 To wdTable.Columns.Count\n                On Error Resume Next\n                wsNew.Cells(i, j).Value = Trim(wdTable.Cell(i, j).Range.Text)\n                '移除 Word 儲存格結尾的特殊字元\n                wsNew.Cells(i, j).Value = Left(wsNew.Cells(i, j).Value, _\n                    Len(wsNew.Cells(i, j).Value) - 2)\n                On Error GoTo ErrHandler\n            Next j\n        Next i\n\n        '自動調整欄寬\n        wsNew.Columns.AutoFit\n    Next tbl\n\n    wdDoc.Close False\n    wdApp.Quit\n    Set wdTable = Nothing\n    Set wdDoc = Nothing\n    Set wdApp = Nothing\n\n    MsgBox \"匯入完成！\" & vbCrLf & _\n           \"共匯入 \" & tbl - 1 & \" 張表格。\", vbInformation, \"完成\"\n    Exit Sub\n\nErrHandler:\n    MsgBox \"發生錯誤：\" & Err.Number & \" - \" & Err.Description, vbCritical, \"錯誤\"\n    If Not wdDoc Is Nothing Then wdDoc.Close False\n    If Not wdApp Is Nothing Then wdApp.Quit\n    Set wdTable = Nothing\n    Set wdDoc = Nothing\n    Set wdApp = Nothing\nEnd Sub\n", "content_b64": ""}, {"name": "WordToPdfBatch.bas", "path": "模組/Word/WordToPdfBatch.bas", "content": "Attribute VB_Name = \"WordToPdfBatch\"\nOption Explicit\n'*************************************************************************************\n'模組名稱: WordToPdfBatch\n'功能說明: 批次將指定資料夾內的所有 Word 文件轉存為 PDF 檔案\n'\n'版權所有: Dunk\n'程式撰寫: Dunk\n'撰寫日期: 2026/05/10\n'\n'使用方式:\n'  1. 執行 BatchConvertWordToPdf\n'  2. 選擇含有 .docx 文件的資料夾\n'  3. PDF 將輸出至相同資料夾，檔名與原檔相同\n'\n'注意事項:\n'  - 需安裝 Word 並支援 PDF 匯出（Office 2010+）\n'  - 原始 Word 文件不受影響\n'*************************************************************************************\n\n'批次轉換 Word 為 PDF\nSub BatchConvertWordToPdf()\n    Dim wdApp        As Object\n    Dim wdDoc        As Object\n    Dim strFolder    As String\n    Dim strFile      As String\n    Dim strPdfPath   As String\n    Dim lngCount     As Long\n\n    On Error GoTo ErrHandler\n\n    '選擇來源資料夾\n    With Application.FileDialog(4)\n        .Title = \"請選擇含有 Word 文件的資料夾\"\n        If .Show <> -1 Then\n            MsgBox \"已取消操作。\", vbInformation, \"提示\"\n            Exit Sub\n        End If\n        strFolder = .SelectedItems(1)\n    End With\n\n    If Right(strFolder, 1) <> \"\\\" Then strFolder = strFolder & \"\\\"\n\n    Set wdApp = CreateObject(\"Word.Application\")\n    wdApp.Visible = False\n\n    lngCount = 0\n    strFile = Dir(strFolder & \"*.docx\")\n\n    Do While strFile <> \"\"\n        Set wdDoc = wdApp.Documents.Open(strFolder & strFile)\n\n        '輸出 PDF 至相同資料夾（wdExportFormatPDF = 17）\n        strPdfPath = strFolder & Left(strFile, Len(strFile) - 5) & \".pdf\"\n        wdDoc.ExportAsFixedFormat OutputFileName:=strPdfPath, _\n            ExportFormat:=17, _\n            OpenAfterExport:=False, _\n            OptimizeFor:=0\n\n        wdDoc.Close False\n        Set wdDoc = Nothing\n        lngCount = lngCount + 1\n        strFile = Dir()\n    Loop\n\n    wdApp.Quit\n    Set wdApp = Nothing\n\n    MsgBox \"PDF 轉換完成！\" & vbCrLf & _\n           \"共轉換 \" & lngCount & \" 個文件。\" & vbCrLf & _\n           \"輸出位置：\" & strFolder, vbInformation, \"完成\"\n    Exit Sub\n\nErrHandler:\n    MsgBox \"發生錯誤：\" & Err.Number & \" - \" & Err.Description, vbCritical, \"錯誤\"\n    If Not wdDoc Is Nothing Then wdDoc.Close False\n    If Not wdApp Is Nothing Then wdApp.Quit\n    Set wdDoc = Nothing\n    Set wdApp = Nothing\nEnd Sub\n", "content_b64": ""}]}]};
